insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid, '{"es-MX":"Iniciador","ar-AE":"مبادر","es-ES":"Iniciador","ja-JP":"イニシエーター","it-IT":"Demolitore","de-DE":"Initiator","id-ID":"Initiator","ko-KR":"척후대","fr-FR":"Initiateur","en-US":"Initiator","pl-PL":"Inicjator","pt-BR":"Iniciador","ru-RU":"Зачинщик","th-TH":"Initiator","tr-TR":"Öncü","vi-VN":"Khởi tranh","zh-CN":"先锋","zh-TW":"先鋒"}'::jsonb, '{"es-MX":"Los iniciadores crean oportunidades para que el equipo pueda despejar ángulos, entrar a zonas en disputa y alejar a los defensores.","ar-AE":"يواجه المبادرون الأركان بتسهيل دخول فرقهم إلى المناطق المتنازع عليها وطرد المدافعين منها.","es-ES":"Los iniciadores se centran en servirse de ángulos inusuales para ayudar a su equipo a adentrarse en territorios clave y alejar a los defensores.","ja-JP":"戦闘エリアで交戦するメンバーをサポートすることで様々な戦局に対処していく。","it-IT":"I Demolitori creano occasioni utili per permettere alla squadra di entrare in territori contesi e respingere i difensori.","de-DE":"Initiatoren eröffnen neue Perspektiven und ermöglichen ihrem Team, umkämpftes Gelände zu betreten und die Verteidiger zu verdrängen.","id-ID":"Initiator mengancam sudut dengan mengatur tim memasuki medan yang diperebutkan dan mendorong mundur defender.","ko-KR":"척후대는 팀이 전투 지역에 침입할 수 있도록 다각도로 진입로를 확보하고 적 팀에 틈을 만들어냅니다.","fr-FR":"Les initiateurs sont là pour aider leur équipe à entrer dans des zones contestées et à repousser les défenseurs.","en-US":"Initiators challenge angles by setting up their team to enter contested ground and push defenders away.","pl-PL":"Inicjatorzy obserwują teren i przygotowują swoją drużynę, by ta mogła wejść do akcji i odepchnąć obrońców.","pt-BR":"Iniciadores desafiam situações arriscadas, preparando a equipe para entrar em terreno contestado e rechaçar defensores.","ru-RU":"Зачинщики отрабатывают опасные углы, проводя таким образом подготовку для захвата территории командой и оттесняя обороняющихся.","th-TH":"Initiator โดดเด่นในการช่วยเคลียร์พื้นที่เพื่อให้ทีมสามารถบุกเข้าไปในสนามรบและผลักดันฝ่ายป้องกันออกไป ","tr-TR":"Öncüler, ilerlemesi tehlikeli köşeleri aşabilmeleri için takımlarına olanaklar yaratır.","vi-VN":"Người Khởi tranh có nhiệm vụ tạo cơ hội cho đồng đội đẩy lùi hàng phòng ngự của đối thủ để đánh chiếm những vị trí quan trọng.","zh-CN":"先锋能够为队伍打开局面，帮助队友进入交战区域并驱逐敌方防守力量。","zh-TW":"先鋒能從不同角度切入且擊退守備方，替隊伍在詭譎多變的戰場中製造優勢。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/1b47567f-8f7b-444b-aae3-b0c634622d10/displayicon.png') on conflict do nothing;
insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('5fc02f99-4091-4486-a531-98459a3e95e9'::uuid, '{"es-MX":"Centinela","ar-AE":"حارس","es-ES":"Centinela","ja-JP":"センチネル","it-IT":"Guardiano","de-DE":"Wächter","id-ID":"Sentinel","ko-KR":"감시자","fr-FR":"Sentinelle","en-US":"Sentinel","pl-PL":"Strażnik","pt-BR":"Sentinela","ru-RU":"Страж","th-TH":"Sentinel","tr-TR":"Gözcü","vi-VN":"Hộ vệ","zh-CN":"哨卫","zh-TW":"守衛"}'::jsonb, '{"es-MX":"Los centinelas son expertos en defensa que aseguran áreas del mapa y vigilan los flancos, tanto en las rondas de defensa como de ataque.","ar-AE":"الحراس خبراء دفاعيون قادرون على تأمين المناطق ومراقبة الأجنحة في جولات الدفاع والهجوم على حد سواء.","es-ES":"Los centinelas son expertos en defensa que se centran en bloquear áreas y vigilar los flancos tanto durante las rondas de ataque como en las de defensa.","ja-JP":"あらゆる局面において、エリアの封鎖や側面における防衛に力を発揮する守りのエキスパート。","it-IT":"I Guardiani sono esperti nella difesa e possono chiudere aree e coprire i fianchi, sia in attacco che in difesa.","de-DE":"Wächter sind Verteidigungsexperten, die sowohl in Angriffs- als auch in Verteidigungsrunden Bereiche absperren und Flanken bewachen können.","id-ID":"Sentinel adalah ahli pertahanan yang bisa mengunci area dan mengawasi sisi sayap, baik di ronde attacker dan defender.","ko-KR":"감시자들은 공격팀이나 수비팀에 상관없이 지역을 점유하고 팀 엄호를 담당하는 수비 전문가입니다.","fr-FR":"Les sentinelles sont des experts de la défense qui verrouillent l''accès aux zones et surveillent les flancs, tant en attaque qu''en défense.","en-US":"Sentinels are defensive experts who can lock down areas and watch flanks, both on attacker and defender rounds.","pl-PL":"Strażnicy to eksperci od obrony, którzy potrafią zamknąć dany obszar i pilnować flank, zarówno w rundzie atakujących, jak i obrońców.","pt-BR":"Sentinelas são especialistas em defesa que podem bloquear áreas e vigiar flancos, tanto nas rodadas de ataque, quanto nas de defesa.","ru-RU":"Стражи – эксперты по обороне, способные обеспечить прикрытие участков на поле боя и флангов как в защите, так и в нападении.","th-TH":"Sentinel คือผู้เชี่ยวชาญด้านการตั้งรับ โดยสามารถทำการปิดกั้นพื้นที่และคอยระวังหลังให้กับสมาชิกในทีม ทั้งในรอบการโจมตีและการตั้งรับ","tr-TR":"Gözcüler hem saldıran hem savunan turlarında bölgeleri kapatabilen ve kanatları kolaçan eden savunma uzmanlarıdır.","vi-VN":"Hộ vệ là những chuyên gia phòng thủ, những người có thể cầm chân đối thủ trên diện rộng và canh gác bên sườn cho đồng đội cả trong vòng đấu tấn công cũng như phòng thủ.","zh-CN":"哨卫是防守的专家，为队伍封锁区域或盯防包夹，无论攻守回合均能发挥重要作用。","zh-TW":"守衛顧名思義就是守備專家。無論是攻擊或守備回合，都能夠為隊伍封鎖區域以及掩護側翼。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/5fc02f99-4091-4486-a531-98459a3e95e9/displayicon.png') on conflict do nothing;
insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid, '{"es-MX":"Duelista","ar-AE":"مبارز","es-ES":"Duelista","ja-JP":"デュエリスト","it-IT":"Assassino","de-DE":"Duellant","id-ID":"Duelist","ko-KR":"타격대","fr-FR":"Duelliste","en-US":"Duelist","pl-PL":"Szturmowiec","pt-BR":"Duelista","ru-RU":"Дуэлянт","th-TH":"Duelist","tr-TR":"Düellocu","vi-VN":"Đối đầu","zh-CN":"决斗","zh-TW":"決鬥者"}'::jsonb, '{"es-MX":"Los duelistas son asesinos autosuficientes con destrezas y habilidades que les permiten detonar los enfrentamientos y conseguir un gran número de asesinatos.","ar-AE":"المبارزون هم قتلة يعتمدون على أنفسهم وتتوقع منهم فرقهم تنفيذ عمليات قتل كبرى والسعي إلى الالتحام دائمًا بفضل ما يتمتعون به من قدرات ومهارات.","es-ES":"Los duelistas son asesinos autosuficientes que, gracias a sus habilidades y destrezas, suelen conseguir iniciar enfrentamientos y anotarse muchos asesinatos.","ja-JP":"アビリティーやスキルを駆使しながら、敵と素早く交戦して次々とキルを重ねていく、頼れる自己完結型アタッカー。","it-IT":"Gli Assassini sono combattenti autonomi. La loro squadra conta su di loro per uccidere gli avversari con abilità e tecniche, e ottenere un alto numero di uccisioni durante gli scontri.","de-DE":"Duellanten sind unabhängige Fragger, die durch ihre Fähigkeiten und Fertigkeiten die ersten in ihrem Team sind, die auf Konfrontationskurs gehen und ordentlich austeilen.","id-ID":"Duelist adalah pembunuh mandiri dengan kemampuan dan keahlian yang diandalkan oleh tim untuk menghasilkan angka pembunuhan tinggi dan melakukan serangan pertama.","ko-KR":"타격대는 자급자족이 가능하며 팀에서 공격을 담당합니다. 스킬과 실력을 통해 먼저 교전을 시작하고 적을 처치합니다.","fr-FR":"Les duellistes sont des combattants indépendants. Leur équipe compte sur eux pour tuer un maximum d''adversaires et provoquer des combats.","en-US":"Duelists are self-sufficient fraggers who their team expects, through abilities and skills, to get high frags and seek out engagements first.","pl-PL":"Szturmowcy to samowystarczalni zabójcy, którzy za sprawą swych umiejętności powinni zdobywać jak najwięcej zabójstw dla swojej drużyny i jako pierwsi nawiązywać kontakt ogniowy z wrogiem.","pt-BR":"Duelistas são abatedores independentes que estão sempre prontos para o confronto. Eles usam habilidades e perícia para conseguir vários abates.","ru-RU":"Дуэлянты – самодостаточные убийцы, от которых товарищи по команде ожидают высокой результативности и агрессивной игры. Добиться в этом успеха им позволяют их умения и навыки.","th-TH":"Duelist คือหน่วยกล้าตายที่ไม่ต้องพึ่งพาใคร\nซึ่งเพื่อนร่วมทีมคาดหวังว่าด้วยสกิลและความสามารถ\nที่มีจะสามารถสร้างความเสียหายได้อย่างมาก \nและเข้าไปปะทะก่อนใครเพื่อน","tr-TR":"Düellocular yetenek ve becerilerini kullanarak takımları için rakibe hasar yağdıran ve çatışma başlatan, kendi kendilerine yeten, etkili savaşçılardır.","vi-VN":"Đối đầu là vai trò của người chơi đủ khả năng tự lực cánh sinh, có kỹ năng để hạ gục nhiều đối thủ và luôn lao lên chiến đấu trước.","zh-CN":"决斗者是独当一面的战斗力，可利用其技能为队伍输出伤害，并主动寻找与对手交战的机会。","zh-TW":"決鬥者是獨當一面的殺手，隊伍皆仰賴其高超技巧，尋找開戰的契機、殲滅敵方。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/dbe8757e-9e92-4ed4-b39f-9dfc589691d4/displayicon.png') on conflict do nothing;
insert into public.valo_agent_roles (uuid, display_name, description, display_icon) values ('4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid, '{"es-MX":"Controlador","ar-AE":"متحكم","es-ES":"Controlador","ja-JP":"コントローラー","it-IT":"Stratega","de-DE":"Taktiker","id-ID":"Controller","ko-KR":"전략가","fr-FR":"Contrôleur","en-US":"Controller","pl-PL":"Kontroler","pt-BR":"Controlador","ru-RU":"Специалист","th-TH":"Controller","tr-TR":"Kontrol Uzmanı","vi-VN":"Kiểm soát","zh-CN":"控场","zh-TW":"控場者"}'::jsonb, '{"es-MX":"Los controladores son expertos en dividir y preparar el terreno para darle una ventaja a su equipo","ar-AE":"المتحكمون يجيدون تقسيم المناطق الخطرة لتوزيع فرقهم بشكل يضمن تحقيق النجاح.","es-ES":"Los controladores se especializan en dividir terrenos peligrosos en varias zonas para que su equipo pueda encargarse del resto.","ja-JP":"危険なエリアを特定し、チームを勝利に導く戦略のエキスパート。","it-IT":"Gli Strateghi sono esperti nella preparazione dei territori pericolosi per consentire alla loro squadra di vincere le battaglie.","de-DE":"Taktiker analysieren das Schlachtfeld und finden so für ihr Team den besten Weg zum Ziel.","id-ID":"Controller adalah ahli pembagian wilayah berbahaya untuk mempersiapkan keberhasilan tim.","ko-KR":"전략가들은 위험 지역을 분석하여 팀을 승리로 이끄는 데 탁월합니다.","fr-FR":"Les contrôleurs excellent à diviser les zones dangereuses pour permettre à leur équipe de remporter la victoire.","en-US":"Controllers are experts in slicing up dangerous territory to set their team up for success.","pl-PL":"Kontrolerzy to eksperci w rozpracowywaniu niebezpiecznych obszarów, dzięki czemu mogą przygotować swoją drużynę do zwycięstwa.","pt-BR":"Controladores se dedicam a dissecar territórios perigosos e pavimentar o caminho do sucesso para a equipe.","ru-RU":"Специалисты по контролю мастерски справляются с угрозами на местности, чтобы обеспечить команде победу.","th-TH":"Controller เชี่ยวชาญในการจัดการกับพื้นที่อันตราย เพื่อนำทีมของพวกเขาไปสู่ความสำเร็จ","tr-TR":"Kontrol uzmanları takımlarını başarıya götürmek için tehlikeli bölgeleri ayrıştırmakta uzmandır.","vi-VN":"Người Kiểm soát là bậc thầy trong việc phân tích những địa thế nguy hiểm và tìm con đường tới chiến thắng cho đội mình.","zh-CN":"控场者是改变和利用战场地形的专家，为队伍的胜利创造有利条件。","zh-TW":"控場者擅長分割地帶，阻隔危險，替隊伍作好迎接勝利的準備。"}'::jsonb, 'https://media.valorant-api.com/agents/roles/4ee40330-ecdd-4f2f-98a8-eb1243428373/displayicon.png') on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('e370fa57-4757-3604-3648-499e1f642d3f'::uuid, '{"es-MX":"Gekko","ar-AE":"غيكو","es-ES":"Gekko","ja-JP":"ゲッコー","it-IT":"Gekko","de-DE":"Gekko","id-ID":"Gekko","ko-KR":"게코","fr-FR":"Gekko","en-US":"Gekko","pl-PL":"Gekko","pt-BR":"Gekko","ru-RU":"Gekko","th-TH":"Gekko","tr-TR":"GEKKO","vi-VN":"Gekko","zh-CN":"盖可","zh-TW":"蓋克"}'::jsonb, '{"es-MX":"Gekko, el nativo de Los Ángeles, lidera un grupo de criaturas revoltosas, y son como uña y mugre. Sus amiguitos avanzan a toda velocidad, dispersando a los enemigos, y Gekko los persigue para reagruparlos y lanzarlos de nuevo.","ar-AE":"جاء غيكو من لوس أنجلوس، وهو يتزعم عصبة من المخلوقات الفوضوية التي تجمع بينها روابط وثيقة. وينطلق رفاقه إلى الأمام لتفريق الأعداء وفتح الطريق، ويمضي غيكو خلفهم لجمعهم وإعادة الكرّة.","es-ES":"Gekko, de Los Ángeles, lidera una pequeña pandilla de calamitosas criaturas. Sus colegas toman la delantera para dispersar a los enemigos, mientras que Gekko los persigue para luego reagruparse y repetir el proceso.","ja-JP":"ロサンゼルス出身のゲッコーは、固い絆で結ばれた暴れん坊のクリーチャーたちを率いている。敵を蹴散らしながら進むクリーチャーをゲッコーが追い、集め、力を合わせて戦い続ける。","it-IT":"Gekko, originario di Los Angeles, guida un''affiatata cricca di turbolente creature. I suoi amichetti irrompono in territorio ostile, disperdendo i nemici sulla loro strada, con Gekko alle loro calcagna, pronto a recuperarli e ripartire da capo.","de-DE":"Gekko der Angeleno führt eine eingeschworene Truppe verrückter Kreaturen. Seine Freunde springen voran und vertreiben Gegner, während Gekko ihnen folgt, um sie einzusammeln und von vorne anzufangen.","id-ID":"Gekko the Angeleno memimpin pasukan kompak yang terdiri dari makhluk-mahkluk berbahaya. Usai pasukannya bergerak maju dan menyingkirkan musuh, Gekko mengejar dan mengambil mereka kembali lalu beranjak lagi.","ko-KR":"로스앤젤레스 출신 게코는 무시무시한 봇 생명체들을 이끕니다. 봇들이 돌진해 적들을 분산시키면 게코가 따라가 전열을 재정비한 후 다시 공격을 개시합니다.","fr-FR":"Originaire de Los Angeles, Gekko dirige une bande de créatures chaotiques, mais très soudées. Ses amis s''occupent de disperser les ennemis, puis Gekko rassemble sa petite troupe pour recommencer.","en-US":"Gekko the Angeleno leads a tight-knit crew of calamitous creatures. His buddies bound forward, scattering enemies out of the way, with Gekko chasing them down to regroup and go again.","pl-PL":"Gekko Angeleno przewodzi zgranej ekipie groźnych stworzeń. Jego kumple szarżują przed siebie, odrzucając wrogów z drogi, a Gekko ściga ich, by przegrupowali się i ponownie ruszyli do akcji.","pt-BR":"Gekko, de Los Angeles, lidera um grupo muito unido de criaturas caóticas. Seus amigos atropelam tudo, tirando os inimigos do caminho. Depois, Gekko corre atrás deles para reagrupá-los e reiniciar o processo.","ru-RU":"Gekko из Лос-Анджелеса заправляет дружной командой безбашенных существ. Его верные зверята смело бросаются в драку, разнося врагов в пух и прах. А когда Gekko подбирает питомцев с поля боя, можно перевести дух и повторить!","th-TH":"Gekko เอเจนท์จากลอสแอนเจลิสจะนำพากลุ่มสิ่งมีชีวิตอภิมหาตัวป่วนมารวมตัวกัน เหล่าสหายของเขาจะพุ่งไปด้านหน้า ขับไล่ศัตรูออกไปให้พ้นทาง พร้อมกับ Gekko ที่จะคอยตามเก็บพวกมันเพื่อมารวมกลุ่มกันและจัดการลุยกันอีกครั้ง","tr-TR":"Los Angeles çocuğu Gekko yaratıklardan oluşan belalı tayfasına liderlik etmekte. Gekko''nun tayfası ileri atılarak düşmanların başına bela olur. Sonrasında Gekko onları toplar ve birlikte tekrar bela olacak düşman aramaya koyulurlar.","vi-VN":"Gekko - gã trai phố thị L.A. - là người dẫn đầu biệt đội toàn những sinh vật \"lắm chiêu\" và rất thân thiết. Gekko đuổi theo những đồng đội đang mải miết lao tới hất tung tất cả kẻ thù đang ngáng đường, ráng sức tập hợp chúng lại để có thể tiếp tục ra chiêu.","zh-CN":"西海岸小伙“盖可”随身带着一群调皮捣蛋的小怪兽。这些小跟班们负责冲在战斗的最前方，给敌人制造各种麻烦。等到盖可追上来后，它们还能回到他身边，然后再次出击。","zh-TW":"洛杉磯人蓋克帶領了一群親密無間的小怪物。他的好夥伴總是一馬當先，打亂敵人陣腳，等蓋克追上後再重整隊伍，再次出擊。"}'::jsonb, 'Aggrobot', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/displayicon.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/displayicon.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/fullportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/fullportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/fullportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/killfeedportrait.png', 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/minimapportrait.png', null, 'https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/background.png', array['371c5cff', '0f1923ff', '3a2656ff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('e370fa57-4757-3604-3648-499e1f642d3f'::uuid, 'Ability1', '{"es-MX":"Carnalito","ar-AE":"وينغمان","es-ES":"Wingman","ja-JP":"ウィングマン","it-IT":"Wingman","de-DE":"Wingman","id-ID":"Wingman","ko-KR":"지원봇","fr-FR":"Altego","en-US":"Wingman","pl-PL":"Wingman","pt-BR":"Wingman","ru-RU":"Бегун","th-TH":"Wingman","tr-TR":"KANKUŞ","vi-VN":"Wingman","zh-CN":"顽皮搭档","zh-TW":"震翼鳥人"}'::jsonb, '{"es-MX":"EQUIPA a Carnalito. DISPARA para enviar a Carnalito hacia adelante en busca de enemigos; Carnalito libera una explosión conmocionante hacia el primer enemigo que ve. Usa DISPARO SECUNDARIO al apuntar a un sitio de Spike o a una Spike plantada para que Carnalito plante o desactive la Spike, respectivamente. Para plantarla, Gekko debe tener la Spike en su inventario. Cuando Carnalito se agota, regresa a su forma de glóbulo en reposo; INTERACTÚA para recuperar el glóbulo y obtener otra carga de Carnalito tras un breve enfriamiento.","ar-AE":"تجهّز بـ وينغمان. أطلق لإرسال وينغمان إلى الأمام بحثًا عن الأعداء. يطلق وينغمان صدمة ارتجاجية باتجاه أول عدو يراه. استخدم الإطلاق البديل عند استهداف موقع سبايك أو السبايك المزروعة لجعل وينغمان يعطل السبايك أو يزرعها. للزرع، يجب أن يكون غيكو حائزًا على السبايك في مخزونه. عند انتهاء وقت وينغمان، يعود إلى هيئة الكريّة النائمة. تفاعل لاستعادة الكريّة واكسب شحنة وينغمان أخرى بعد فترة تبريد قصيرة.","es-ES":"EQUIPA a Wingman. DISPARA para mandarlo hacia delante en busca de enemigos. Wingman libera una explosión aturdidora en dirección al primero que ve. Utiliza el DISPARO ALTERNATIVO mientras apuntas a una zona de la Spike o a una Spike colocada para que la coloque o la desarme. Para colocarla, Gekko debe tenerla en su inventario. Cuando Wingman desaparece, vuelve a su estado en reposo. INTERACTÚA para recuperar el glóbulo y obtener otra carga tras un breve enfriamiento.","ja-JP":"ウィングマンを構える。「発射」でウィングマンを前方に送り出し索敵させる。ウィングマンは最初に視認した敵に向かってスタンを与える爆風を放つ。スパイク設置サイトまたは設置されたスパイクに照準を合わせた状態で「オルト射撃」で、ウィングマンがスパイクの設置または解除をする。スパイクを設置させるには、ゲッコーがスパイクを所持している必要がある。ウィングマンは一定時間が経過すると、球体になって活動を停止する。「インタラクト」で球体を回収でき、短時間のクールダウン後に再使用可能になる。","it-IT":"EQUIPAGGIA Wingman. Usa il FUOCO per inviare Wingman alla ricerca di nemici. Non appena Wingman vede un nemico, sprigiona contro di esso un''esplosione stordente. Usa il FUOCO ALTERNATIVO mentre indichi un Punto di piazzamento o la Spike piazzata per ordinare a Wingman di disinnescare o piazzare la Spike. Per piazzare la Spike, Gekko deve averla nell''inventario. Quando il potere di Wingman si esaurisce, torna in forma di globulo dormiente. INTERAGISCI con il globulo per raccoglierlo, ottenendo un''altra carica di Wingman dopo una breve ricarica.","de-DE":"RÜSTE Wingman AUS. FEUERE, um Wingman loszuschicken. Wingman entfesselt eine erschütternde Explosion gegen den ersten erkannten Gegner. ALT. FEUERMODUS auf ein Spike-Areal oder einen platzierten Spike, damit Wingman den Spike entschärft oder platziert. Zum Platzieren muss Gekko der Spiketräger sein. Wenn Wingman abläuft, wird er zu einer ruhenden Kugel. INTERAGIERE, um die Kugel einzusammeln und nach einer Abklingzeit einen weiteren Wingman zu erhalten.","id-ID":"EQUIP Wingman. Tekan FIRE untuk mengirim Wingman mencari musuh. Wingman melepaskan ledakan berutilitas Concussive ke musuh pertama yang dilihatnya. Tekan ALT FIRE agar Wingman menjinakkan atau menempatkan Spike. Untuk menempatkan, Gekko harus memiliki Spike. Saat Wingman menghilang, dia kembali ke globule yang tidak aktif. INTERAKSIKAN untuk mengambil globule dan memperoleh charge Wingman lagi setelah cooldown.","ko-KR":"지원봇을 장착합니다. 발사하면 지원봇을 앞으로 보내 적을 찾습니다. 지원봇은 처음 본 적에게 뇌진탕을 유발합니다. 스파이크 지점이나 설치된 스파이크를 겨눈 상태에서 보조 공격 시 지원봇에게 스파이크 설치나 해체를 명령할 수 있습니다. 설치하려면 게코가 스파이크를 소지하고 있어야 합니다. 지원봇은 지속시간이 끝나면 작은 구체로 되돌아갑니다. 상호작용하면 구체를 회수하며, 짧은 재사용 대기시간 이후 지원봇을 다시 사용할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''Altego. TIREZ pour l''envoyer chercher des ennemis. Il provoque une explosion désorientante en direction du premier ennemi qu''il voit. En visant un site de pose du spike ou un spike posé, utilisez le TIR SECONDAIRE pour l''envoyer poser ou désamorcer le spike. Pour poser le spike, Gekko doit l''avoir dans son inventaire. Quand Altego arrive à expiration, il redevient un globule dormant. INTERAGISSEZ avec lui pour récupérer le globule et, après un court délai, pouvoir le réutiliser.","en-US":"EQUIP Wingman. FIRE to send Wingman forward seeking enemies. Wingman unleashes a concussive blast toward the first enemy he sees. ALT FIRE when targeting a Spike site or planted Spike to have Wingman defuse or plant the Spike. To plant, Gekko must have the Spike in his inventory. When Wingman expires he reverts into a dormant globule. INTERACT to reclaim the globule and gain another Wingman charge after a short cooldown.","pl-PL":"WYPOSAŻ Wingmana. STRZAŁ wysyła Wingmana, by szukał wrogów. Wingman posyła ogłuszający wybuch w kierunku pierwszego wroga, którego zobaczy. ALT. STRZAŁ podczas celowania w punkt podłożenia lub podłożonego Spike’a sprawi, że Wingman rozbroi lub podłoży Spike’a. Aby podłożyć, Gekko musi mieć Spike’a w ekwipunku. Gdy czas działania Wingmana upłynie, zamienia się w kulkę w stanie uśpienia. Naciśnij przycisk INTERAKCJI, by ją podnieść i otrzymać kolejny ładunek Wingmana po krótkim czasie odnowienia.","pt-BR":"EQUIPE Wingman. DISPARE para enviá-lo para encontrar inimigos. Wingman lança uma forte explosão na direção do primeiro inimigo que vê. Use o DISPARO ALTERNATIVO na direção de um ponto ou Spike plantada para que Wingman plante ou desarme a Spike. Para plantar, Gekko deve estar com a Spike no inventário. Quando Wingman expira, ele se transforma em um glóbulo inativo. INTERAJA para recuperar o glóbulo e ganhar outra carga de Wingman após um curto período.","ru-RU":"Выбирает Бегуна. Нажмите кнопку ОГОНЬ, чтобы отправить Бегуна вперед искать противников. Бегун высвобождает энергию в сторону первого увиденного врага, совершая оглушающий взрыв. Нажмите АЛЬТ. ОГОНЬ, нацелившись на точку установки Spike или на установленный Spike, чтобы Бегун установил или обезвредил его. Spike должен быть в инвентаре Gekko, чтобы Бегун мог его установить. Когда энергия заканчивается, Бегун превращается в шарик и бездействует. Взаимодействуйте с шариком, чтобы забрать его, и спустя короткое время Бегун получит новый заряд энергии.","th-TH":"ติดตั้ง Wingman กดยิงเพื่อปล่อย Wingman ออกไปด้านหน้า เพื่อคอยตามล่าศัตรู Wingman จะปล่อยคลื่นสะเทือนเข้าใส่ศัตรูตัวแรกที่เขาพบ กดโหมดยิงเสริมขณะเล็งจุดติดตั้ง Spike หรือ Spike ที่ถูกติดตั้งไว้แล้วเพื่อให้ Wingman ปลดชนวน Spike หรือติดตั้ง Spike ในการติดตั้ง Spike นั้น Gekko จะต้องมี Spike อยู่กับตัวด้วย เมื่อสิ้นสุดระยะเวลา Wingman จะเปลี่ยนไปเป็นก้อนกลมที่ไม่สามารถเคลื่อนที่ได้ กดโต้ตอบเพื่อเก็บก้อนกลมกลับมาและจะได้รับชาร์จของ Wingman คืนมาหนึ่งชาร์จหลังจากติดคูลดาวน์ชั่วขณะ","tr-TR":"Kankuş''u KUŞAN. Kankuş''u düşman aramaya göndermek için ATEŞ ET. Kankuş gördüğü ilk düşmana doğru Sersemletici bir patlama oluşturur. Kankuş''un Spike''ı yerleştirmesi veya imha etmesi için Spike bölgesine veya yerleştirilmiş Spike''a nişan al ve ALT. ATIŞ kullan. Yerleştirmek için Spike Gekko''da olmalıdır. Kankuş süresi dolduğunda pasif bir küreye dönüşür. Onu geri almak ve kısa bir bekleme süresinin ardından bir Kankuş yükü daha edinmek için küreyle ETKİLEŞİME GİR.","vi-VN":"TRANG BỊ Wingman. BẮN để phóng Wingman ra phía trước tìm kẻ địch. Wingman phát ra xung chấn làm choáng kẻ địch đầu tiên nhìn thấy. BẮN PHỤ khi chỉ tâm ngắm vào khu vực đặt Spike hoặc Spike đã được đặt để Wingman đặt hoặc gỡ Spike. Để đặt Spike, Gekko phải có Spike trong kho đồ. Khi Wingman hết thời gian hiệu lực, cậu sẽ tiêu biến thành một tiểu thể không hoạt động. TƯƠNG TÁC để thu hồi tiểu thể và nhận thêm 1 lượt dùng Wingman sau khoảng thời gian hồi chiêu ngắn.","zh-CN":"装备宠物“皮蛋”。按【射击】派皮蛋去前方搜寻敌人。发现首名敌人后，皮蛋将对其发射震荡冲击。瞄准爆能器部署区域或已部署的爆能器后，按下【辅助射击】可以派皮蛋前去部署或拆除爆能器。盖可的物品栏中必须拥有爆能器才能进行部署。技能失效后，皮蛋将变回一颗休眠的球体。与球体【互动】即可将其回收，在短暂的冷却时间后可再次获得顽皮搭档充能。","zh-TW":"裝備鳥人。點擊「攻擊」即可向前放出鳥人搜敵。鳥人會炸出震波暈眩第一位看見的敵人。瞄準據點或輻能核心時點擊「輔助攻擊」，即可讓鳥人安裝或拆除輻能核心。蓋克的物品欄中必須有輻能核心才能安裝。鳥人的時間一到就會回復成休眠的球體。點擊「互動」即可回收球體，經過短暫的冷卻時間後便可獲得另一次鳥人充能。"}'::jsonb, '"https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('e370fa57-4757-3604-3648-499e1f642d3f'::uuid, 'Ability2', '{"es-MX":"Vértigo","ar-AE":"ديزي","es-ES":"Dizzy","ja-JP":"ディジー","it-IT":"Dizzy","de-DE":"Dizzy","id-ID":"Dizzy","ko-KR":"기절봇","fr-FR":"Verti","en-US":"Dizzy","pl-PL":"Dizzy","pt-BR":"Dizzy","ru-RU":"Клякса","th-TH":"Dizzy","tr-TR":"ŞAŞKIN","vi-VN":"Dizzy","zh-CN":"炫晕光波","zh-TW":"頭暈目眩"}'::jsonb, '{"es-MX":"EQUIPA a Vértigo. DISPARA para enviar a Vértigo volando hacia adelante. Vértigo carga y luego libera explosiones de plasma contra los enemigos en su campo de visión; los enemigos alcanzados por su plasma quedan cegados. Cuando Vértigo se agota, regresa a su forma de glóbulo en reposo; INTERACTÚA para recuperar el glóbulo y obtener otra carga de Vértigo tras un breve enfriamiento.","ar-AE":"تجهّز بـ ديزي. أطلق لإرسال ديزي محلّقة إلى الأمام في الهواء. تشحن ديزي نفسها ثم تطلق دفقات من البلازما على الأعداء في خط الرؤية. يقع الأعداء المصابون بدفقات البلازما تحت تأثير العمى. عند انتهاء وقت ديزي، تعود إلى هيئة الكريّة النائمة. تفاعل لاستعادة الكريّة واكسب شحنة ديزي أخرى بعد فترة تبريد قصيرة.","es-ES":"EQUIPA a Dizzy. DISPARA para lanzar a Dizzy volando hacia delante. Dizzy carga y libera explosiones de plasma hacia los enemigos en su campo de visión. El plasma ciega a los enemigos alcanzados. Cuando Dizzy desaparece, vuelve a su estado de glóbulo en reposo. INTERACTÚA para recuperar el glóbulo y obtener otra carga de Dizzy tras un breve enfriamiento.","ja-JP":"ディジーを構える。「発射」でディジーを前方に放る。 ディジーはチャージ後、視認した敵に向かってプラズマブラストを放ち、 命中した敵の視界を奪う。 ディジーは一定時間が経過すると、球体になって活動を停止する。「インタラクト」で球体を回収でき、短時間のクールダウン後に再使用可能になる。","it-IT":"EQUIPAGGIA Dizzy. Usa il FUOCO per far volare Dizzy in avanti. Dopo una breve preparazione, Dizzy spara getti di plasma ai nemici nel suo campo visivo. I nemici colpiti dal suo plasma vengono ACCECATI. Quando il potere di Dizzy si esaurisce, torna in forma di globulo dormiente. INTERAGISCI con il globulo per raccoglierlo, ottenendo un''altra carica di Dizzy dopo un breve periodo di ricarica.","de-DE":"RÜSTE Dizzy AUS. FEUERE, um Dizzy vorwärts durch die Luft zu schicken. Dizzy fliegt vorwärts und feuert dann Plasmaschüsse auf Gegner in Sichtweite. Von ihrem Plasma getroffene Gegner werden geblendet. Wenn Dizzy abläuft, wird sie zu einer ruhenden Kugel. INTERAGIERE, um die Kugel einzusammeln und nach einer kurzen Abklingzeit eine weitere Dizzy zu erhalten.","id-ID":"EQUIP Dizzy. Tekan FIRE untuk mengirim Dizzy melesat ke udara. Dizzy memperoleh charge dan melepaskan ledakan plasma ke musuh yang ada di garis pandang. Musuh yang tersentuh oleh plasmanya akan terkena utilitas Blind. Saat Dizzy menghilang, dia kembali ke globule yang tidak aktif. INTERAKSIKAN untuk mengambil globule dan memperoleh charge Dizzy lagi setelah cooldown.","ko-KR":"기절봇을 장착합니다. 발사하면 기절봇이 공중으로 솟아오릅니다. 기절봇은 충전한 뒤 시야에 들어온 적을 향해 플라즈마 폭발을 일으킵니다. 플라즈마에 맞은 적은 실명합니다. 기절봇은 지속시간이 끝나면 작은 구체로 되돌아갑니다. 상호작용하면 구체를 회수하며, 짧은 재사용 대기시간 이후 기절봇을 다시 사용할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous de Verti. TIREZ pour envoyer Verti dans les airs. Verti charge son attaque, puis tire des projectiles de plasma sur les ennemis dans son champ de vision. Les ennemis touchés par le plasma sont aveuglés. Quand Verti arrive à expiration, elle redevient un globule dormant. INTERAGISSEZ avec elle pour récupérer le globule et, après un court délai, pouvoir réutiliser Verti.","en-US":"EQUIP Dizzy. FIRE to send Dizzy soaring forward through the air. Dizzy charges then unleashes plasma blasts at enemies in line of sight. Enemies hit by her plasma are Blinded. When Dizzy expires she reverts into a dormant globule. INTERACT to reclaim the globule and gain another Dizzy charge after a short cooldown.","pl-PL":"WYPOSAŻ Dizzy. STRZAŁ posyła Dizzy w powietrze. Dizzy ładuje i wypuszcza plazmowe wybuchy w kierunku wrogów w polu widzenia. Wrogowie trafieni plazmą zostają oślepieni. Gdy czas działania Dizzy upłynie, zamienia się w kulkę w stanie uśpienia. Naciśnij przycisk INTERAKCJI, by podnieść kulkę i otrzymać kolejny ładunek Dizzy po krótkim czasie odnowienia.","pt-BR":"EQUIPE Dizzy. DISPARE para enviá-la voando pelo ar. Dizzy avança e solta explosões de plasma nos inimigos em sua linha de visão. Os inimigos atingidos pelo plasma ficam Cegos. Ao expirar, Dizzy se transforma em um glóbulo inativo. INTERAJA para recuperar o glóbulo e ganhar outra carga de Dizzy após um curto período.","ru-RU":"Выбирает Кляксу. Нажмите кнопку ОГОНЬ, чтобы запустить Кляксу высоко в воздух и послать ее вперед. Клякса запускает взрывающиеся сгустки плазмы в сторону противников в зоне видимости. Плазма ослепляет врагов, попавших в зону действия. Когда энергия заканчивается, Клякса превращается в шарик и бездействует. Взаимодействуйте с шариком, чтобы забрать его, и спустя короткое время Клякса получит новый заряд энергии.","th-TH":"ติดตั้ง Dizzy กดยิงเพื่อปล่อย Dizzy พุ่งออกไปกลางอากาศทางด้านหน้า Dizzy จะชาร์จและปลดปล่อยคลื่นพลาสมาใส่ศัตรูในระยะมองเห็น ศัตรูที่โดนพลาสมาของเธอจะถูกทำให้สูญเสียการมองเห็น เมื่อสิ้นสุดระยะเวลา Dizzy จะเปลี่ยนไปเป็นก้อนกลมที่ไม่สามารถเคลื่อนที่ได้ กดโต้ตอบเพื่อเก็บก้อนกลมกลับมาและได้รับชาร์จของ Dizzy คืนมาหนึ่งชาร์จหลังจากติดคูลดาวน์ชั่วขณะ","tr-TR":"Şaşkın''ı KUŞAN. Şaşkın''ı havada süzülecek şekilde fırlatmak için ATEŞ ET. Şaşkın enerji topladıktan sonra görüşüne giren düşmanlara plazma atar. Plazmanın isabet ettiği düşmanlar Kör olur. Şaşkın süresi dolduğunda pasif bir küreye dönüşür. Onu geri almak ve kısa bir bekleme süresinin ardından bir Şaşkın yükü daha edinmek için küreyle ETKİLEŞİME GİR.","vi-VN":"TRANG BỊ Dizzy. BẮN để cử Dizzy bay vút thẳng lên không trung. Dizzy vận sức, sau đó phóng ra tia plasma lên những kẻ địch trong tầm nhìn. Kẻ địch trúng tia plasma sẽ bị Mù. Khi Dizzy hết thời gian hiệu lực, cô sẽ tiêu biến thành một tiểu thể không hoạt động. TƯƠNG TÁC để thu hồi tiểu thể và nhận thêm 1 lượt dùng Dizzy sau khoảng thời gian hồi chiêu ngắn.","zh-CN":"装备宠物“丢丢”。按【射击】派它飞向天空。丢丢会对视线范围内的敌人使用电浆冲击。被电浆命中的敌人将被【致盲】。技能失效后，丢丢将变回一颗休眠的球体。与球体【互动】即可将其回收，在短暂的冷却时间后可再次获得炫晕光波充能。","zh-TW":"裝備眩眩。點擊「攻擊」即可讓眩眩向前飛。眩眩蓄力後對視野內的敵人發射電漿砲，被電漿砲擊中的敵人會遭到「致盲」。眩眩的時間一到就會回復成休眠的球體。點擊「互動」即可回收球體，經過短暫的冷卻時間後便可獲得另一次眩眩充能。"}'::jsonb, '"https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('e370fa57-4757-3604-3648-499e1f642d3f'::uuid, 'Grenade', '{"es-MX":"Pogo Brutal","ar-AE":"جحيم موش","es-ES":"Mosh","ja-JP":"モッシュピット","it-IT":"Moshpit","de-DE":"Mosh-Pit","id-ID":"Mosh Pit","ko-KR":"폭파봇 지옥","fr-FR":"Pogo","en-US":"Mosh Pit","pl-PL":"A Mosh!","pt-BR":"Mosh Pit","ru-RU":"Тыдыщ","th-TH":"Mosh Pit","tr-TR":"POFUDUK TARLASI","vi-VN":"Bãi Mìn Của Mosh","zh-CN":"嗨爆全场","zh-TW":"爆爆領域"}'::jsonb, '{"es-MX":"EQUIPA a Pogo. DISPARA para lanzar a Pogo como una granada. Usa el DISPARO SECUNDARIO para lanzarlo por debajo. Al aterrizar, Pogo se duplica en una zona amplia que inflige un poco de daño prolongado y luego explota después de un corto lapso de tiempo. INTERACTÚA para recuperar el glóbulo y obtener otra carga de Pogo tras un breve enfriamiento.","ar-AE":"تجهّز بـ موش. أطلق لرمي موش على شكل قنبلة يدوية. استخدم الإطلاق البديل للإلقاء المقوس. عند هبوطه، تتولد نسخٌ جديدة عن موش في منطقة واسعة تُلحق قدرًا طفيفًا من الضرر بمرور الوقت، ثم تنفجر النسخ بعد فترة قصيرة. تفاعل لاستعادة الكريّة واكسب شحنة موش أخرى بعد فترة تبريد قصيرة.","es-ES":"EQUIPA a Mosh. DISPARA para lanzar a Mosh como una granada. Utiliza el DISPARO ALTERNATIVO para tirarlo. Al caer, Mosh se divide en varias copias en un área grande, que inflige una pequeña cantidad de daño prolongado y, tras un breve lapso, explota. INTERACTÚA para recuperar el glóbulo y obtener otra carga de Mosh tras un breve enfriamiento.","ja-JP":"モッシュを構える。「発射」でモッシュをグレネードのように投げる。「オルト射撃」で軽く放る。モッシュは地面に触れると広範囲に分裂し、時間経過により少量のダメージを与える地帯を作り出し、少ししてから爆発する。「インタラクト」で球体を回収でき、短時間のクールダウン後に再使用可能になる。","it-IT":"EQUIPAGGIA Mosh. Usa il FUOCO per lanciare Mosh come una granata. Usa il FUOCO ALTERNATIVO per lanciarlo dal basso verso l''alto. All''impatto, Mosh si duplica coprendo un''ampia area, formando una zona che infligge una piccola quantità di danni nel tempo, per poi esplodere dopo qualche istante. INTERAGISCI con il globulo per raccoglierlo, ottenendo un''altra carica di Mosh dopo un breve periodo di ricarica.","de-DE":"RÜSTE Mosh AUS. FEUERE, um Mosh wie eine Granate zu werfen. ALT. FEUERMODUS für einen Unterhandwurf. Nach der Landung verteilt sich Mosh über einen großen Bereich, der geringen Schaden über Zeit verursacht, und explodiert nach einer kurzen Verzögerung. INTERAGIERE, um die Kugel einzusammeln und nach einer kurzen Abklingzeit einen weiteren Mosh zu erhalten.","id-ID":"EQUIP Mosh. Tekan FIRE untuk melempar Mosh seperti granat. Tekan ALT FIRE untuk melempar tinggi. Setelah mendarat, Mosh menjadi banyak di area yang luas, menghasilkan sedikit damage berkelanjutan, lalu sesaat kemudian meledak. INTERAKSIKAN untuk mengambil kembali globul dan memperoleh charge Mosh lagi setelah cooldown singkat.","ko-KR":"폭파봇을 장착합니다. 발사하면 폭파봇을 수류탄처럼 투척합니다. 보조 공격 시 가깝게 투척합니다. 폭파봇은 땅에 닿으면 넓은 구역에 복제되며 소규모의 피해량을 시간에 걸쳐 입힌 뒤 잠시 후 폭발합니다. 상호작용하면 구체를 회수하며, 짧은 재사용 대기시간 이후 폭파봇을 다시 사용할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous de Pogo. TIREZ pour lancer Pogo comme une grenade. Utilisez le TIR SECONDAIRE pour le lancer en cloche. À l''atterrissage, Pogo se multiplie dans une large zone qui inflige des dégâts mineurs sur la durée, puis il explose après un court délai. INTERAGISSEZ avec lui pour récupérer le globule et, après un court délai, pouvoir réutiliser Pogo.","en-US":"EQUIP Mosh. FIRE to throw Mosh like a grenade. ALT FIRE to lob. Upon landing Mosh duplicates across a large area that deals a small amount of damage over time then after a short delay explodes. INTERACT to reclaim the globule and gain another Mosh charge after a short cooldown.","pl-PL":"WYPOSAŻ Mosha. STRZEL, by rzucić Moshem jak granatem. Naciśnij ALT. STRZAŁ, by cisnąć. Po wylądowaniu Mosh duplikuje się na dużym obszarze i zadaje niewielkie obrażenia rozłożone w czasie, a po krótkim opóźnieniu eksploduje. Naciśnij przycisk INTERAKCJI, by podnieść kulkę i otrzymać kolejny ładunek Mosha po krótkim czasie odnowienia.","pt-BR":"EQUIPE Mosh. DISPARE para lançá-lo como uma granada. Use o DISPARO ALTERNATIVO para arremessar a curta distância. Ao atingir uma superfície, Mosh se multiplica em uma grande área, o que causa uma pequena quantidade de dano ao longo do tempo, e, depois de uns instantes, explode. INTERAJA para recuperar o glóbulo e ganhar outra carga de Mosh após um curto período.","ru-RU":"Выбирает Тыдыща. Нажмите ОГОНЬ, чтобы бросить Тыдыща, как гранату. Нажмите АЛЬТ. ОГОНЬ для броска снизу. Коснувшись поверхности, Тыдыщ разделяется, покрывая большую площадь, которая наносит немного урона с течением времени, и после небольшой задержки взрывается. Взаимодействуйте с шариком, чтобы забрать его и спустя короткое время получить еще один заряд Тыдыща.","th-TH":"ติดตั้ง Mosh กดยิงเพื่อขว้าง Mosh ออกไปเหมือนลูกระเบิด กดโหมดยิงเสริมเพื่อโยนออกไปในระยะสั้น ๆ เมื่อตกถึงพื้น Mosh จะเพิ่มจำนวนขึ้นในพื้นที่กว้าง ซึ่งจะสร้างความเสียหายเล็กน้อยตลอดระยะเวลา แล้วจะระเบิดหลังจากผ่านไปช่วงเวลาหนึ่ง กดโต้ตอบเพื่อเก็บก้อนกลมกลับมาและจะได้รับชาร์จของ Mosh คืนมาหนึ่งชาร์จหลังจากติดคูลดาวน์ชั่วขณะ","tr-TR":"Pofu''yu KUŞAN. Pofu''yu bomba gibi fırlatmak için ATEŞ ET. Yavaşça fırlatmak için ALT. ATIŞ kullan. Pofu indiği yerde büyük bir alana yayılır, bu alandaki düşmanlara her saniye düşük miktarda hasar verir ve kısa bir gecikmenin ardından patlar. Onu geri almak ve kısa bir bekleme süresinin ardından bir Pofu yükü daha edinmek için küreyle ETKİLEŞİME GİR.","vi-VN":"TRANG BỊ Mosh. BẮN để quăng Mosh như trái lựu đạn. BẮN PHỤ để ném cao. Sau khi đáp đất, Mosh phân tách bản thân ra một khu vực rộng hơn và gây lượng sát thương nhỏ theo thời gian, rồi phát nổ sau khoảng chờ ngắn. TƯƠNG TÁC để thu hồi tiểu thể và nhận thêm 1 lượt dùng Mosh sau khoảng thời gian hồi chiêu ngắn.","zh-CN":"装备宠物“嗨宝”。按【射击】即可将其掷出。按【辅助射击】可轻抛。落地后，嗨宝会在一大片区域内复制自己，持续造成少量伤害，并在短暂延迟后爆炸。与球体【互动】即可将其回收，在短暂的冷却时间后可再次获得嗨爆全场充能。","zh-TW":"裝備爆爆。點按「攻擊」即可將爆爆當成手榴彈投出。點按「輔助攻擊」，則可低手拋出。爆爆落地後會在大範圍內複製增生，持續造成少量傷害，並在短暫延遲後爆炸。點按「互動」即可回收球體，經過短暫的冷卻時間後便可獲得另一次爆爆充能。"}'::jsonb, '"https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('e370fa57-4757-3604-3648-499e1f642d3f'::uuid, 'Ultimate', '{"es-MX":"Paliza","ar-AE":"ثراش","es-ES":"Thrash","ja-JP":"スラッシュ","it-IT":"Thrash","de-DE":"Thrash","id-ID":"Thrash","ko-KR":"요동봇","fr-FR":"Mordicus","en-US":"Thrash","pl-PL":"Thrash","pt-BR":"Thrash","ru-RU":"Бабах","th-TH":"Thrash","tr-TR":"ZORBA","vi-VN":"Thrash","zh-CN":"无敌超鲨","zh-TW":"鯊無赦"}'::jsonb, '{"es-MX":"EQUIPA a Paliza. DISPARA para vincularte con la mente de Paliza y dirigirla a través del territorio enemigo; ACTIVA para embestir hacia adelante y explotar, lo que inmoviliza a los enemigos en un pequeño radio. Cuando Paliza se agota, regresa a su forma de glóbulo en reposo; INTERACTÚA para recuperar el glóbulo y obtener otra carga de Paliza tras un breve enfriamiento. Solo se puede recuperar a Paliza una vez.","ar-AE":"تجهّز بـ ثراش. أطلق للارتباط بعقل ثراش وقم بتوجيهها عبر أرض العدو. قم بالتفعيل للاندفاع إلى الأمام والانفجار، مع احتجاز أي لاعب ضمن نطاق محدود. عند انتهاء وقت ثراش، تعود إلى هيئة الكريّة النائمة. تفاعل لاستعادة الكريّة واكسب شحنة ثراش أخرى بعد فترة تبريد قصيرة. يمكن استعادة ثراش مرة وحيدة.","es-ES":"EQUIPA a Thrash. DISPARA para vincular tu mente con la de Thrash y manejarla a través del territorio enemigo. ACTÍVALA para embestir hacia delante y explotar, lo que detendrá a cualquier jugador en un pequeño radio. Cuando Thrash desaparece, vuelve a su estado de glóbulo en reposo. INTERACTÚA para recuperar el glóbulo y obtener otra carga de Thrash tras un breve enfriamiento. Thrash se puede recuperar una vez.","ja-JP":"スラッシュを構える。「発射」でスラッシュの精神とリンクし、スラッシュを操作して敵陣で動き回ることができる。「発動」で前方に飛んで爆発し、小範囲内のプレイヤーをすべて拘束する。スラッシュは一定時間が経過すると球体になって活動を停止する。「インタラクト」で球体を回収でき、短時間のクールダウン後に再使用可能になる。スラッシュは一度だけ回収できる。","it-IT":"EQUIPAGGIA Thrash. Usa il FUOCO per connetterti alla mente di Thrash e guidarla in territorio nemico. ATTIVA per balzare in avanti ed esplodere, OSTACOLANDO i nemici entro un''area ridotta. Quando il potere di Thrash si esaurisce, torna in forma di globulo dormiente. INTERAGISCI con il globulo per raccoglierlo, ottenendo un''altra carica di Thrash dopo un breve periodo di ricarica. Thrash può essere recuperata una volta sola.","de-DE":"RÜSTE Thrash AUS. FEUERE, um dich mit Thrashs Geist zu verbinden und sie durch feindliches Gebiet zu lenken. AKTIVIERE, um nach vorne zu springen und zu explodieren, um Spieler in einem kleinen Bereich zu hindern. Wenn Thrash abläuft, wird sie zu einer ruhenden Kugel. INTERAGIERE, um die Kugel aufzuheben und nach einer kurzen Abklingzeit eine weitere Thrash zu erhalten. Thrash kann einmal aufgesammelt werden.","id-ID":"EQUIP Thrash. Tekan FIRE untuk terhubung dengan pikiran Thrash dan mengarahkannya ke wilayah musuh. AKTIFKAN untuk menerjang ke depan dan menghasilkan ledakan, serta menahan pemain dalam radius kecil. Saat Thrash menghilang, dia kembali ke globule yang tidak aktif. INTERAKSIKAN untuk mengambil globule dan memperoleh charge Thrash lagi setelah cooldown. Thrash bisa diambil kembali satu kali.","ko-KR":"요동봇을 장착합니다. 발사하면 요동봇의 정신과 연결되어 요동봇을 적 진영으로 조종합니다. 활성화하면 앞으로 돌진해 폭발하며 좁은 범위 안에 있는 플레이어를 모두 구속합니다. 요동봇은 지속시간이 끝나면 작은 구체로 되돌아갑니다. 상호작용하면 구체를 회수하며, 짧은 재사용 대기시간 이후 요동봇을 다시 사용할 수 있습니다. 요동봇은 한 번만 회수할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous de Mordicus. TIREZ pour vous lier mentalement avec Mordicus et la diriger en territoire ennemi. ACTIVEZ pour bondir vers l''avant et exploser, ce qui retient tous les joueurs dans un petit rayon. Quand Mordicus arrive à expiration, elle redevient un globule dormant. INTERAGISSEZ avec elle pour récupérer le globule et, après un court délai, pouvoir réutiliser Mordicus. Mordicus peut être récupérée une fois.","en-US":"EQUIP Thrash. FIRE to link with Thrash’s mind and steer her through enemy territory. ACTIVATE to lunge forward and explode, Detaining any players in a small radius. When Thrash expires she reverts into a dormant globule. INTERACT to reclaim the globule and gain another Thrash charge after a short cooldown. Thrash can be reclaimed once.","pl-PL":"WYPOSAŻ Thrash. STRZEL, by połączyć się z umysłem Thrash i sterować nią na obszarze wroga. AKTYWUJ, by wyskoczyć wprzód i eksplodować, zatrzymując graczy na niewielkim obszarze. Gdy czas działania Thrash upłynie, zamienia się w kulkę w stanie uśpienia. Naciśnij przycisk INTERAKCJI, by podnieść kulkę i otrzymać kolejny ładunek Thrash po krótkim czasie odnowienia. Thrash można odzyskać jednokrotnie.","pt-BR":"EQUIPE Thrash. DISPARE para se conectar à mente dela e guiá-la pelo território inimigo. ATIVE para avançar e explodir, Detendo qualquer jogador em um pequeno raio. Ao expirar, Thrash se transforma em um glóbulo inativo. INTERAJA para recuperar o glóbulo e ganhar outra carga de Thrash após um curto período. Thrash pode ser recuperada uma vez.","ru-RU":"Выбирает Бабах. Нажмите кнопку ОГОНЬ, чтобы установить мысленную связь с Бабах и управлять ее передвижением по вражеской территории. Нажмите кнопку АКТИВАЦИИ, чтобы Бабах сделала рывок вперед и устроила взрыв, задержала врагов на небольшом расстоянии от себя. Когда энергия заканчивается, Бабах превращается в шарик и бездействует. Взаимодействуйте с шариком, чтобы забрать его, и спустя короткое время Бабах получит новый заряд энергии. Повторный заряд Бабах можно использовать только один раз.","th-TH":"ติดตั้ง Thrash กดยิงเพื่อเชื่อมต่อจิตใจกับ Thrash และควบคุมเธอผ่านเข้าไปในเขตแดนของศัตรู กดใช้เพื่อพุ่งตัวไปด้านหน้าและระเบิดออก กักขังศัตรูทุกคนในระยะสั้น ๆ เมื่อสิ้นสุดระยะเวลา Thrash จะเปลี่ยนไปเป็นก้อนกลม ๆ ที่ไม่สามารถเคลื่อนที่ได้ กดโต้ตอบเพื่อเก็บก้อนกลม ๆ กลับมาและได้รับชาร์จของ Thrash คืนมาหนึ่งชาร์จหลังจากติดคูลดาวน์ชั่วขณะ Thrash จะสามารถเก็บกลับมาได้เพียงครั้งเดียว","tr-TR":"Zorba''yı KUŞAN. Zorba''nın zihnine girerek onunla düşman bölgesinde gezinmek için ATEŞ ET. Zorba''nın ileri atılıp patlayarak küçük bir alandaki tüm oyuncuları Alıkoyması için ETKİNLEŞTİR. Zorba süresi dolduğunda pasif bir küreye dönüşür. Onu geri almak ve kısa bir bekleme süresinin ardından bir Zorba yükü daha edinmek için küreyle ETKİLEŞİME GİR. Zorba yalnızca bir kere geri alınabilir.","vi-VN":"TRANG BỊ Thrash. BẮN để kết nối với tâm trí của Thrash và điều khiển nó xuyên qua lãnh địa của kẻ thù. KÍCH HOẠT để lao về phía trước và phát nổ, Giam Cầm mọi kẻ địch trong một phạm vi nhỏ. Khi Thrash hết thời gian hiệu lực, nó sẽ tiêu biến thành một tiểu thể không hoạt động. TƯƠNG TÁC để thu hồi tiểu thể và nhận thêm 1 lượt dùng Thrash sau khoảng thời gian hồi chiêu ngắn. Có thể thu hồi Thrash một lần.","zh-CN":"装备宠物“鲨鲨”。按【射击】与鲨鲨的意识进行相连，控制她穿越敌人领地。按【激活】即可让鲨鲨向前冲刺并爆炸，【束缚】小范围内的所有玩家。技能失效后，鲨鲨将变回一颗休眠的球体。与球体【互动】即可将其回收，在短暂的冷却时间后可再次获得无敌超鲨充能。鲨鲨仅可被回收一次。","zh-TW":"裝備鯊鯊。點擊「攻擊」即可與其心智連結，操控她穿越敵軍陣地。按下「啟動」可使鯊鯊向前衝並爆炸，「拘束」小範圍內所有玩家。鯊鯊的時間一到就會回復成休眠的球體。點擊「互動」即可回收球體，經過短暫的冷卻時間後便可獲得另一次鯊鯊充能。鯊鯊只能回收一次。"}'::jsonb, '"https://media.valorant-api.com/agents/e370fa57-4757-3604-3648-499e1f642d3f/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('dade69b4-4f5a-8528-247b-219e5a1facd6'::uuid, '{"es-MX":"Fade","ar-AE":"فايد","es-ES":"Fade","ja-JP":"フェイド","it-IT":"Fade","de-DE":"Fade","id-ID":"Fade","ko-KR":"페이드","fr-FR":"Fade","en-US":"Fade","pl-PL":"Fade","pt-BR":"Fade","ru-RU":"Fade","th-TH":"Fade","tr-TR":"FADE","vi-VN":"Fade","zh-CN":"黑梦","zh-TW":"菲德"}'::jsonb, '{"es-MX":"Fade, la cazarrecompensas turca, desata el poder de las pesadillas para apoderarse de los secretos del enemigo. En armonía con el terror puro, acecha a sus objetivos y revela sus miedos más profundos, antes de aplastarlos en la oscuridad.","ar-AE":"تطلق فايد، صيادة الجوائز التركية، عنان قوة الكابوس الخالصة لانتزاع أسرار الأعداء. وبفضل انسجامها مع الرعب ذاته، تطارد الأهداف وتكشف عن أسوأ مخاوفهم، قبل سحقهم في الظلام.","es-ES":"Fade, la cazarrecompensas turca, controla el poder de las pesadillas para poner al descubierto los secretos de los enemigos. Ataviada con el propio terror, da caza a sus objetivos y revela sus miedos más profundos, para después acabar con ellos en la oscuridad.","ja-JP":"トルコ出身の賞金稼ぎのフェイドは、むき出しの悪夢の力を解き放ち、敵の秘密を掴む。恐怖そのものと同調している彼女は、追い詰めたターゲットの心の奥底にある恐怖を掘り起こし、そして闇に葬る。","it-IT":"Fade, la cacciatrice di taglie turca, scatena il potere degli incubi per impossessarsi dei segreti nemici. In sintonia con il terrore, dà la caccia ai bersagli e rivela le loro paure più recondite, per poi trascinarli via nel buio.","de-DE":"Die türkische Kopfgeldjägerin Fade entlockt Gegnern mit der Macht der Albträume ihre Geheimnisse. Sie arbeitet mit dem Schrecken selbst zusammen, jagt ihre Ziele und enthüllt deren Ängste – bevor sie sie in der Dunkelheit zermalmt.","id-ID":"Pemburu bayaran asal Turki, Fade, menggunakan mimpi buruk yang nyata sebagai kekuatannya untuk merebut rahasia musuh. Dia memburu target dan menyingkap ketakutan terdalam dari musuhnya-sebelum mereka dihancurkan di dalam kegelapan.","ko-KR":"튀르키예 출신 현상금 사냥꾼 페이드는 악몽의 힘을 이용해 적의 비밀을 캐냅니다. 공포와 하나가 되어 표적을 쫓고 마음속 가장 깊은 곳에 숨겨진 공포를 파헤친 뒤, 어둠 속에서 짓밟습니다.","fr-FR":"Originaire de Türkiye, la chasseuse de primes Fade utilise le pouvoir des cauchemars pour s''emparer des secrets ennemis. Elle traque ses cibles et révèle leurs plus grandes peurs pour mieux les briser dans l''obscurité.","en-US":"Turkish bounty hunter Fade unleashes the power of raw nightmare to seize enemy secrets. Attuned with terror itself, she hunts down targets and reveals their deepest fears - before crushing them in the dark.","pl-PL":"Turecka łowczyni nagród Fade czerpie z czystej mocy koszmarów, aby odkryć tajemnice wroga. Dzięki swojemu zestrojeniu z przerażeniem dopada swoje cele i ujawnia najgłębiej skrywane przez nich lęki, zanim zmiażdży ich w mroku.","pt-BR":"Fade, uma caçadora de recompensas turca, usa o poder dos pesadelos para capturar os segredos dos inimigos. Personificando o próprio terror, ela persegue os alvos e revela seus medos mais profundos para, depois, destruí-los na escuridão.","ru-RU":"Турчанка Fade, охотница за головами, связала свою жизнь с Кошмаром и научилась читать врагов как открытые книги с помощью силы этого существа. Впустив в свое сердце кромешную тьму, она получила способность раскрывать чужие страхи и сводить жертву с ума.","th-TH":"Fade นักล่าค่าหัวชาวตุรกีจะมาปลดปล่อยพลังแห่งฝันร้ายอันทรงพลังเพื่อช่วงชิงความลับของศัตรู เอเจนท์ที่หลอมรวมเข้ากับความหวาดกลัวผู้นี้จะไล่ล่าเป้าหมายของเธอและดึงเอาความกลัวที่ฝังลึกในใจของพวกเขาออกมา ก่อนที่จะจัดการพวกเขาภายใต้เงามืด","tr-TR":"Türk kelle avcısı Fade, düşmanların sırlarını gasp etmek için saf kâbus gücünü kullanır. Korkuyla uyum içinde çalışarak hedeflerini avlar ve hedeflerinin işini bitirmeden önce en büyük korkularını açığa çıkarır.","vi-VN":"Fade - thợ săn tiền thường tới từ Thổ Nhĩ Kỳ, người điều khiển sức mạnh ác mộng để chiếm đoạt những bí mật của kẻ thù. Là hiện thân của sự sợ hãi, cô ấy săn đuổi và khai thác những nỗi sợ sâu thẳm nhất của mục tiêu - trước khi nghiền nát chúng trong bóng tối.","zh-CN":"“黑梦”是来自小亚细亚地区的赏金猎人，她能够操纵纯粹的噩梦能量，揭开他人心底潜藏的恐惧和秘密。她会如梦魇般对敌人穷追不舍，然后在黑暗中将其摧毁殆尽。","zh-TW":"來自土耳其的賞金獵人菲德能釋放純粹的惡夢能量來攫取敵人的祕密。她是恐懼的化身，能追獵目標，揭開他們最深層的恐懼，然後用黑暗將其摧毀殆盡。"}'::jsonb, 'BountyHunter', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/displayicon.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/displayicon.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/fullportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/fullportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/fullportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/killfeedportrait.png', 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/minimapportrait.png', null, 'https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/background.png', array['1d2846ff', '0f1923ff', '18344cff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('dade69b4-4f5a-8528-247b-219e5a1facd6'::uuid, 'Ability1', '{"es-MX":"Capturar","ar-AE":"تقييد","es-ES":"Apresar","ja-JP":"シーズ","it-IT":"Cattura","de-DE":"Ergreifen","id-ID":"Seize","ko-KR":"포박","fr-FR":"Capture","en-US":"Seize","pl-PL":"Przejęcie","pt-BR":"Clausura","ru-RU":"Захват","th-TH":"Seize","tr-TR":"MIHLA","vi-VN":"Bẫy Ác Mộng","zh-CN":"幽爪","zh-TW":"咒縛夢魘"}'::jsonb, '{"es-MX":"EQUIPA un núcleo de miedo puro. DISPARA para lanzarlo. El núcleo cae después de un tiempo determinado. VUELVE A USAR para hacer caer el núcleo anticipadamente. El núcleo se rompe al impactar, lo que inmoviliza a los enemigos cercanos. Los enemigos inmovilizados son ensordecidos y debilitados.","ar-AE":"تجهّز بعقدة من الخوف الخالص. أطلق لرميها. تسقط العقدة على الأرض بعد فترة معينة. أعد الاستخدام لإسقاط العقدة قبل الأوان. تتمزق العقدة لدى الاصطدام، فتثبّت الأعداء المجاورين في أماكنهم. يصاب الأعداء المثبّتون بتأثيري الصمم وتدهور الصحة.","es-ES":"EQUIPA un Nódulo de terror puro. DISPARA para lanzarlo. El Nódulo cae tras un periodo de tiempo determinado. VUELVE A USAR la habilidad para que el Nódulo caiga antes. El Nódulo estalla al impactar y retiene a los enemigos cercanos. Ensordece y aplica declive a los enemigos retenidos.","ja-JP":"むき出しの恐怖の塊を構える。「発射」で投げる。塊は一定時間経過すると落下する。アビリティーを「再使用」すると、塊を早く落下させることができる。塊は地面に当たると破裂し、周囲の敵を拘束する。拘束された敵は聴覚を奪われ「衰弱」効果を受ける。","it-IT":"EQUIPAGGIA un nodo di puro terrore. Usa il FUOCO per lanciarlo. Il nodo piomba a terra in picchiata dopo un determinato lasso di tempo. USA DI NUOVO l''abilità per farlo cadere prima. Il nodo si rompe all''impatto, impedendo ai nemici nei paraggi di allontanarsi. I nemici coinvolti vengono ASSORDATI e DETERIORATI.","de-DE":"LEGE einen Knoten purer Furcht AN. FEUERE, um zu werfen. Der Knoten fällt nach einer festgelegten Zeit zu Boden. VERWENDE die Fähigkeit ERNEUT, um den Knoten vorzeitig auf den Boden fallen zu lassen. Der Knoten explodiert beim Aufprall und hält Gegner in der Nähe fest. Festgehaltenen Gegnern werden Taubheit und Verfall zugefügt.","id-ID":"EQUIP segenggam bola yang berisikan rasa takut. Tekan FIRE untuk melempar. Bola akan jatuh sesuai waktu yang ditetapkan. GUNAKAN LAGI untuk menjatuhkan benda tersebut sesuai perintah. Bola akan pecah saat membentur tanah, lalu menahan musuh yang ada di sekitar untuk tetap di tempatnya. Musuh yang ditahan akan terkena utilitas Deafen dan Decay.","ko-KR":"공포의 매듭을 장착합니다. 발사하면 던집니다. 매듭은 일정 시간이 지난 후 땅에 떨어집니다. 다시 사용하면 매듭을 일찍 떨어뜨립니다. 매듭이 땅에 닿으면 폭발해 주변의 적을 그 자리에 붙잡습니다. 붙잡힌 적의 청력을 약화시키고 부패 효과를 적용합니다.","fr-FR":"ÉQUIPEZ-vous d''un nœud de peur brute. TIREZ pour le lancer. Le nœud tombe au bout d''un certain temps. RÉUTILISEZ la compétence pour faire tomber le nœud plus tôt. À l''impact, le nœud éclate et retient les ennemis proches. Les ennemis retenus sont assourdis et leurs PV se désagrègent.","en-US":"EQUIP a knot of raw fear. FIRE to throw. The knot drops down after a set time. RE-USE to drop the knot early. The knot ruptures on impact, holding nearby enemies in place. Held enemies are Deafened, and Decayed.","pl-PL":"WYPOSAŻ węzeł czystego strachu. STRZEL, by rzucić. Węzeł opadnie po określonym czasie. UŻYJ PONOWNIE, aby węzeł opadł wcześniej. Węzeł pęka po zderzeniu, usidlając pobliskich wrogów. Usidleni wrogowie zostają ogłuszeni i ulegają rozpadowi.","pt-BR":"EQUIPE um nódulo de puro temor. DISPARE para arremessá-lo. O nódulo cairá depois de um determinado tempo. REPITA a habilidade para soltá-lo antecipadamente. Esse nódulo se rompe ao impacto, enclausurando inimigos próximos. Inimigos enclausurados sofrem Surdez e Deterioração.","ru-RU":"Выбирает сгусток страха. Нажмите кнопку ОГОНЬ для броска. Через некоторое время сгусток опустится на землю. Используйте умение повторно, чтобы он опустился сразу. При столкновении с целью сгусток взрывается, удерживая ближайших противников, лишая их слуха и нанося им периодический урон.","th-TH":"ติดตั้งกลุ่มก้อนแห่งความหวาดกลัว กดยิงเพื่อขว้าง กลุ่มก้อนจะตกลงบนพื้นหลังจากผ่านไปช่วงเวลาหนึ่ง กดใช้อีกครั้งเพื่อปล่อยกลุ่มก้อนลงพื้นก่อนเวลาที่กำหนด กลุ่มก้อนจะระเบิดออกเมื่อตกกระทบพื้นผิว และยึดศัตรูใกล้เคียงให้อยู่กับที่ ศัตรูที่ถูกยึดอยู่กับที่จะถูกจำกัดการได้ยินและติดสถานะเสื่อมสลาย","tr-TR":"Bir saf korku yumağı KUŞAN. Fırlatmak için ATEŞ ET. Yumak belli bir süre sonra yere iner. Yumağı yere erken indirmek için TEKRAR KULLAN. Yumak yere indiğinde açılarak yakındaki düşmanları olduğu yere sabitler. Sabitlenmiş düşmanlar Sağır olur ve Çürüme hasarı almaya başlar.","vi-VN":"TRANG BỊ 1 nút thắt chứa đầy ác mộng kinh hoàng. BẮN để ném. Nút thắt sẽ rơi xuống sau 1 khoảng thời gian cố định. TÁI SỬ DỤNG để thả sớm. Nút thắt sẽ đứt ra khi va chạm, giam giữ những kẻ địch gần bên. Những kẻ địch bị giam giữ sẽ mất đi Thính Giác và chịu Phân Rã.","zh-CN":"将恐惧之力具象化为一根套索，按【射击】将其掷出。套索会在一段时间后下落，【再次按技能键】可使它提前下落。套索会在碰触到地面后炸裂，将附近的敌人束缚在原地，并对其施加【致聋】和【腐坏】效果。","zh-TW":"裝備充滿純粹恐懼的球體，點擊「攻擊」即可拋出。球體會在經過一定時間後落下，「重施技能」即可使球體提早落下。球體會在接觸時破裂，束縛附近的敵人，被束縛的目標會遭到「致聾和侵蝕」。"}'::jsonb, '"https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('dade69b4-4f5a-8528-247b-219e5a1facd6'::uuid, 'Ability2', '{"es-MX":"Atormentar","ar-AE":"الشبح","es-ES":"Tormento","ja-JP":"ホウント","it-IT":"Tormento","de-DE":"Nachtalb","id-ID":"Haunt","ko-KR":"귀체","fr-FR":"Hanteur","en-US":"Haunt","pl-PL":"Prześladowca","pt-BR":"Assombrar","ru-RU":"Призрак","th-TH":"Haunt","tr-TR":"MUSALLAT","vi-VN":"Mắt Quỷ","zh-CN":"诡眼","zh-TW":"惡夢幽魂"}'::jsonb, '{"es-MX":"EQUIPA un tormento. DISPARA para lanzarlo. El tormento cae después de un tiempo determinado. VUELVE A USAR para hacerlo caer anticipadamente. El tormento se activa al impactar, revela a los enemigos en su línea de visión y crea rastros de terror hacia ellos. Los enemigos pueden destruir al tormento.","ar-AE":"تجهّز بمراقب شبح. أطلق لرميه. يسقط المراقِب على الأرض بعد فترة معينة. أعد الاستخدام لإسقاط المراقِب قبل الأوان. يندفع المراقِب عند الاصطدام، فيكشف الأعداء ضمن خط رؤيته ويكوّن آثار رعب تؤدي إليهم. يستطيع الأعداء تدمير المراقِب.","es-ES":"EQUIPA un Vigía aterrador. DISPARA para lanzarlo. El Vigía cae tras un periodo de tiempo determinado. VUELVE A USAR la habilidad para que el Vigía caiga antes. El Vigía ataca al caer, lo que revela a los enemigos que estén en su campo de visión y crea rastros de terror que llevan hasta ellos. Los enemigos pueden destruir al Vigía.","ja-JP":"奇怪なウォッチャーを呼び出す。「発射」で投げる。ウォッチャーは一定時間経過すると落下する。アビリティーを「再使用」すると、ウォッチャーを早く落下させることができる。ウォッチャーは地面に当たると暴れ、視界に入った敵の位置を特定して、その敵へと続くテラートレイルを作り出す。敵はウォッチャーを破壊することができる。","it-IT":"EQUIPAGGIA un tormentatore. Usa il FUOCO per lanciarlo. Il tormentatore piomba a terra in picchiata dopo un determinato lasso di tempo. USA DI NUOVO l''abilità per farlo cadere prima. Il tormentatore si scatena all''impatto, RIVELANDO i nemici che si trovano nel suo campo visivo e creando scie di terrore che portano a loro. I nemici possono distruggere il tormentatore.","de-DE":"RÜSTE einen Nachtalb AUS. FEUERE, um zu werfen. Der Nachtalb fällt nach einer festgelegten Zeit zu Boden. VERWENDE die Fähigkeit ERNEUT, um den Nachtalb vorzeitig auf den Boden fallen zu lassen. Der Nachtalb schlägt beim Aufprall um sich, enthüllt Gegner in seiner Sichtlinie und erschafft Furchtfährten zu ihnen. Gegner können den Nachtalb zerstören.","id-ID":"EQUIP pengintai yang memata-matai musuh. Tekan FIRE untuk melempar. Pengintai akan jatuh sesuai waktu yang ditetapkan. GUNAKAN LAGI untuk menjatuhkan benda tersebut sesuai perintah. Pengintai menyerang saat membentur tanah, mengungkap keberadaan musuh yang ada di dalam garis pandangnya dan menciptakan Terror Trail pada mereka. Musuh bisa menghancurkan pengintai ini.","ko-KR":"감시귀를 장착합니다. 발사하면 던집니다. 감시귀는 일정 시간이 지난 후 땅에 떨어집니다. 다시 사용하면 감시귀를 일찍 떨어뜨립니다. 감시귀는 땅에 닿으면 시야에 들어온 적의 위치를 드러내고 공포의 흔적을 남깁니다. 적은 감시귀를 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un observateur terrifiant. TIREZ pour le lancer. L''observateur tombe au bout d''un certain temps. RÉUTILISEZ la compétence pour faire tomber l''observateur plus tôt. L''observateur se déchaîne à l''impact, révélant les ennemis dans son champ de vision et créant des pistes de terreur qui mènent à eux. Les ennemis peuvent détruire l''observateur.","en-US":"EQUIP a haunting watcher. FIRE to throw. The watcher drops down after a set time. RE-USE to drop the watcher early. The watcher lashes out on impact, Revealing enemies in its line of sight and creating terror trails to them. Enemies can destroy the watcher.","pl-PL":"WYPOSAŻ dręczącego obserwatora. STRZEL, by rzucić. Obserwator opadnie po określonym czasie. UŻYJ PONOWNIE, aby obserwator opadł wcześniej. Obserwator atakuje po zderzeniu, ujawniając wrogów w swoim polu widzenia i tworząc prowadzące do nich szlaki przerażenia. Wrogowie mogą go zniszczyć.","pt-BR":"EQUIPE uma assombração. DISPARE para arremessá-la. Ela cairá depois de um determinado tempo. REPITA a habilidade para soltá-la antecipadamente. Essa assombração ataca ao contato, Revelando inimigos em sua linha de visão e criando rastros sinistros até eles. Ela pode ser destruída pelos inimigos.","ru-RU":"Выбирает призрака-дозорного. Нажмите кнопку ОГОНЬ для броска. Через некоторое время призрак опустится на землю. Используйте умение повторно, чтобы он опустился сразу. При столкновении с целью призрак нападает, показывая местоположение противников в зоне видимости и прокладывая ведущий к ним след ужаса. Враги могут уничтожить призрака-дозорного.","th-TH":"ติดตั้งตัวสังเกตการณ์ฝันร้าย กดยิงเพื่อขว้าง ตัวสังเกตการณ์จะตกลงบนพื้นหลังจากผ่านไปช่วงเวลาหนึ่ง กดใช้อีกครั้งเพื่อปล่อยตัวสังเกตการณ์ลงพื้นก่อนเวลาที่กำหนด ตัวสังเกตการณ์จะกระจายตัวออกเมื่อกระทบพื้นผิว เปิดเผยตำแหน่งศัตรูทั้งหมดในระยะการมองเห็นของมันและสร้างร่องรอยความกลัวตามตัวพวกเขา ศัตรูสามารถทำลายตัวสังเกตการณ์นี้ได้","tr-TR":"Musallat olan bir gözcü KUŞAN. Fırlatmak için ATEŞ ET. Gözcü belli bir süre sonra yere iner. Gözcüyü yere erken indirmek için TEKRAR KULLAN. Gözcü yere indiğinde etkinleşerek görüş menzili içinde kalan düşmanları Açığa Çıkarır ve hepsine dehşet izi uygular. Düşmanlar gözcüyü yok edebilir.","vi-VN":"TRANG BỊ 1 mắt quỷ. BẮN để ném. Mắt quỷ sẽ rơi xuống sau 1 khoảng thời gian cố định. TÁI SỬ DỤNG để thả mắt quỷ sớm. Mắt quỷ sẽ kích hoạt khi va chạm, làm Lộ Diện những kẻ địch trong tầm nhìn của nó và tạo dấu vết kinh hoàng tới vị trí của chúng. Kẻ địch có thể phá hủy mắt quỷ.","zh-CN":"装备一颗诡眼。按【射击】将其掷出。诡眼会在一段时间后下落，【再次按技能键】可使它提前下落。诡眼会在碰触到地面后爆裂，【揭露】其视线范围内的所有敌人，并使他们留下恐惧轨迹。诡眼可被敌人摧毁。","zh-TW":"裝備一個偵察幽魂，點擊「攻擊」即可拋出。幽魂會在經過一定時間後落下，「重施技能」即可使幽魂提早落下。幽魂會在接觸時爆炸，「揭露」視野範圍內的敵人，並製造出通往目標的恐懼軌跡。敵軍可破壞此幽魂。"}'::jsonb, '"https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('dade69b4-4f5a-8528-247b-219e5a1facd6'::uuid, 'Grenade', '{"es-MX":"Acechadora","ar-AE":"المتصيّد","es-ES":"Acechador","ja-JP":"プラウラー","it-IT":"Predatore","de-DE":"Nachtschatten","id-ID":"Prowler","ko-KR":"추적귀","fr-FR":"Rôdeur","en-US":"Prowler","pl-PL":"Grasant","pt-BR":"Espreitador","ru-RU":"Хищник","th-TH":"Prowler","tr-TR":"ECEL","vi-VN":"Dạ Quỷ","zh-CN":"黯兽","zh-TW":"潛行夢魔"}'::jsonb, '{"es-MX":"EQUIPA una acechadora. DISPARA para enviar a la acechadora hacia adelante. MANTÉN PRESIONADO EL DISPARO para guiar a la acechadora hacia tu retícula. La acechadora perseguirá al primer enemigo o rastro de terror que vea y ofuscará al enemigo al impactar.","ar-AE":"تجهّز بمتصيّد. أطلق لإرسال المتصيّد إلى الأمام. تابع الضغط على زر الإطلاق لتوجيه المتصيّد باتجاه مؤشر تصويب سلاحك. سيلاحق المتصيّد أول عدو أو أثر رعب يرصده، وسيصاب العدو بتأثير قصر النظر عند الاصطدام به.","es-ES":"EQUIPA un Acechador. DISPARA para lanzarlo hacia adelante. MANTÉN PULSADO DISPARAR para dirigir al Acechador en la dirección de la mira. El Acechador seguirá al primer enemigo o rastro que vea y reducirá el campo de visión del enemigo al impactar.","ja-JP":"プラウラーを呼び出す。「発射」でプラウラーを前方へ送り出す。「発射長押し」でプラウラーをクロスヘアの方へ方向転換させる。プラウラーは最初に見つけた敵またはテラートレイル（恐怖の爪痕）を追い、接触した敵の視界を悪化させる。","it-IT":"EQUIPAGGIA un predatore. Usa il FUOCO per mandare il predatore in avanti. TIENI PREMUTO il FUOCO per far virare il predatore verso il tuo reticolo. Non appena un nemico o una scia di terrore entrano nella visuale del predatore, questo li insegue, ANNEBBIANDO il bersaglio all''impatto.","de-DE":"RÜSTE einen Nachtschatten AUS. FEUERE, um den Nachtschatten auszusenden. HALTE FEUERN, um den Nachtschatten in Richtung deines Fadenkreuzes zu steuern. Der Nachtschatten jagt dem ersten erblickten Gegner oder der ersten Furchtfährte nach und schränkt die Sicht des Gegners ein, wenn er ihn erreicht.","id-ID":"EQUIP pemburu musuh. Tekan FIRE untuk melempar pemburu ke depan, HOLD FIRE untuk mengarahkan benda tersebut ke arah crosshair. Pemburu akan mengejar musuh atau Terror Trail pertama yang dilihatnya, lalu memberikan utilitas Nearsight pada musuh yang dikenainya.","ko-KR":"추적귀를 장착합니다. 발사하면 전방으로 추적귀를 내보냅니다. 발사 버튼을 길게 누르면 추적귀를 조준점 방향으로 움직일 수 있습니다. 추적귀는 처음으로 본 적이나 공포의 흔적을 추적하며, 닿으면 적의 시야를 제한합니다.","fr-FR":"ÉQUIPEZ-vous d''un rôdeur. TIREZ pour lancer le rôdeur devant vous. MAINTENEZ LE TIR pour guider le rôdeur dans la direction de votre réticule. Le rôdeur pourchasse le premier ennemi ou suit la première piste de terreur qu''il voit. S''il atteint un ennemi, il le rend myope.","en-US":"EQUIP a prowler. FIRE to send the prowler forward. HOLD FIRE to steer the prowler towards your crosshair. The prowler will chase down the first enemy or terror trail it sees, and Nearsight the enemy on impact.","pl-PL":"WYPOSAŻ grasanta. STRZEL, aby wysłać go naprzód. PRZYTRZYMAJ STRZAŁ, aby sterować grasantem przy użyciu celownika. Grasant ruszy śladem pierwszego wroga lub szlakiem przerażenia i wywoła u wroga krótkowzroczność po zderzeniu.","pt-BR":"EQUIPE um Espreitador. DISPARE para enviá-lo à frente. SEGURE O DISPARO para mover o Espreitador na direção da sua retícula. Ele perseguirá o primeiro rastro sinistro ou inimigo que encontrar e afetará o alvo com Visão Turva ao alcançá-lo.","ru-RU":"Выбирает хищника. Нажмите кнопку ОГОНЬ, чтобы послать хищника вперед. Удерживайте кнопку ОГОНЬ, чтобы хищник двигался в направлении вашего прицела. Хищник будет следовать за первым увиденным противником или идти по первому увиденному следу ужаса, ограничивая обзор пойманных врагов.","th-TH":"ติดตั้ง Prowler กดยิงเพื่อปล่อย Prowler ออกไปข้างหน้า กดยิงค้างไว้เพื่อควบคุม Prowler ตามตำแหน่งเป้าเล็งของคุณ Prowler จะไล่ตามศัตรูตัวแรกหรือร่องรอยความกลัวที่มันพบเห็น และจำกัดการมองเห็นของศัตรูเมื่อถึงตัว","tr-TR":"Bir Ecel KUŞAN. Ecel''i ileri göndermek için ATEŞ ET. Ecel''i nişangâhının baktığı tarafa doğru yönlendirmek için ATEŞ DÜĞMESİNİ BASILI TUT. Ecel gördüğü ilk düşmanın veya dehşet izinin peşine takılır ve yakaladığı düşmanın Görüşünü Kısıtlar.","vi-VN":"TRANG BỊ một dạ quỷ. BẮN để giải phóng dạ quỷ về phía trước. GIỮ BẮN để điều khiển hướng di chuyển của dạ quỷ theo tâm ngắm của bạn. Dạ quỷ sẽ đuổi theo kẻ địch hoặc dấu vết kinh hoàng đầu tiên nó nhìn thấy và gây Hạn Chế Tầm Nhìn của kẻ địch khi chạm vào chúng.","zh-CN":"装备一只黯兽。按【射击】使其向前扑出，【按住射击】可引导黯兽朝准星前进。黯兽将追击它所看到的第一个敌人或追踪恐惧轨迹，并在碰触到敌人时使其【视野收缩】。","zh-TW":"裝備一個夢魔，點擊「攻擊」，即可向前放出夢魔。長按「攻擊」能操控夢魔，依照十字準星的方向轉彎。夢魔會追蹤第一位目擊的敵人或恐懼軌跡，並在觸碰到敵方時「限制其視野」。"}'::jsonb, '"https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('dade69b4-4f5a-8528-247b-219e5a1facd6'::uuid, 'Ultimate', '{"es-MX":"Anochecer","ar-AE":"حلول الليل","es-ES":"Ocaso","ja-JP":"ナイトフォール","it-IT":"Crepuscolo","de-DE":"Einbruch der Nacht","id-ID":"Nightfall","ko-KR":"황혼","fr-FR":"Nuit tombante","en-US":"Nightfall","pl-PL":"Zmrok","pt-BR":"Véu da Noite","ru-RU":"Тьма","th-TH":"Nightfall","tr-TR":"GECE KARANLIĞI","vi-VN":"Bóng Đêm Bao Trùm","zh-CN":"夜临","zh-TW":"夜幕降臨"}'::jsonb, '{"es-MX":"EQUIPA el poder de la pesadilla misma. DISPARA para desatar una ola imparable de energía de pesadilla. Los enemigos atrapados en la ola quedan marcados por rastros de terror, ensordecidos y debilitados.","ar-AE":"تجهّز بقوة الكابوس ذاته. أطلق لتحرير موجة من طاقة الكابوس غير القابلة للصد. يتم وسم الأعداء العالقين في الموجة بآثار الرعب، كما يصابون بتأثيري الصمم وتدهور الصحة.","es-ES":"EQUIPA el poder de las pesadillas. DISPARA para desatar una ola imparable de energía de pesadillas. Marca con rastros de terror, ensordece y aplica declive a los enemigos golpeados por la ola.","ja-JP":"悪夢そのものの力を利用する。「発射」により強力な悪夢のエネルギー波を放つ。この波に巻き込まれた敵はテラートレイルでマークされ、聴覚を奪われ「衰弱」効果を受ける。","it-IT":"EQUIPAGGIA il potere dell''incubo. Usa il FUOCO per sprigionare un''onda di energia da incubo inarrestabile. I nemici investiti dall''onda vengono ASSORDATI, DETERIORATI e MARCATI con scie di terrore.","de-DE":"RÜSTE die Macht des Albtraums AUS. FEUERE, um eine Welle unaufhaltbarer Albtraumenergie zu entfesseln. Von der Welle ergriffene Gegner werden von Furchtfährten markiert und sie erleiden Taubheit und Verfall.","id-ID":"EQUIP kekuatan mimpi buruk. Tekan FIRE untuk melepaskan gelombang energi mimpi buruk yang sangat kuat. Musuh yang tertangkap di dalam gelombang akan Ditandai oleh Terror Trail, lalu terkena utilitas Deafen dan Decay.","ko-KR":"악몽의 힘을 장착합니다. 발사하면 멈출 수 없는 악몽의 에너지 파동을 보냅니다. 파동이 적에게 닿으면 공포의 흔적을 남기며 청력을 약화시키고 부패 효과를 적용합니다.","fr-FR":"ÉQUIPEZ-vous du pouvoir du Cauchemar. TIREZ pour envoyer une vague d''énergie cauchemardesque inarrêtable. Les ennemis pris dans la vague laissent une piste de terreur derrière eux, sont assourdis et leurs PV se désagrègent.","en-US":"EQUIP the power of nightmare itself. FIRE to unleash a wave of unstoppable nightmare energy. Enemies caught in the wave are Marked by terror trails, Deafened, and Decayed.","pl-PL":"WYPOSAŻ moc koszmaru. WYSTRZEL, aby uwolnić falę niepowstrzymanej energii koszmaru. Wrogowie dotknięci przez falę zostają oznaczeni szlakami przerażenia, ogłuszeni i ulegają rozpadowi.","pt-BR":"EQUIPE o poder dos pesadelos. DISPARE para liberar uma onda implacável de energia aterrorizante. Inimigos atingidos pela onda são Marcados por rastros sinistros e sofrem Surdez e Deterioração.","ru-RU":"Выбирает силу Кошмара. Нажмите кнопку ОГОНЬ, чтобы создать волну неудержимой энергии Кошмара. Эта энергия лишает противников слуха и наносит им периодический урон, а также прокладывает к ним след ужаса.","th-TH":"ติดตั้งมวลพลังแห่งฝันร้าย กดยิงเพื่อปลดปล่อยคลื่นพลังงานฝันร้ายที่ไม่สามารถหยุดได้ ศัตรูที่โดนคลื่นพลังจะถูกทำเครื่องหมายร่องรอยแห่งความกลัว ถูกจำกัดการได้ยิน และติดสถานะเสื่อมสลาย","tr-TR":"Kâbusun gücünü KUŞAN. Durdurulamaz bir kâbus enerjisi göndermek için ATEŞ ET. Dalgaya maruz kalan düşmanlar dehşet izleriyle İşaretlenir, Sağır olur ve Çürüme hasarı almaya başlar.","vi-VN":"TRANG BỊ nguồn sức mạnh ác mộng. BẮN để phóng ra một đợt sóng năng lượng ác mộng không thể cản phá. Những kẻ địch bị sóng bắn trúng sẽ bị Đánh Dấu bởi dấu vết kinh hoàng, mất đi Thính Giác và chịu Phân Rã.","zh-CN":"引导噩梦本源的力量，按【射击】释放出排山倒海般的噩梦能量。被波及的敌人会被恐惧轨迹【标记】、并受到【致聋】和【腐坏】效果。","zh-TW":"裝備惡夢之力，點擊「攻擊」即可釋放一波勢不可擋的惡夢能量，遭到波及的敵人會被「致聾和侵蝕」，並會產生恐懼軌跡。"}'::jsonb, '"https://media.valorant-api.com/agents/dade69b4-4f5a-8528-247b-219e5a1facd6/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('5f8d3a7f-467b-97f3-062c-13acf203c006'::uuid, '{"es-MX":"Breach","ar-AE":"بريتش","es-ES":"Breach","ja-JP":"ブリーチ","it-IT":"Breach","de-DE":"Breach","id-ID":"Breach","ko-KR":"브리치","fr-FR":"Breach","en-US":"Breach","pl-PL":"Breach","pt-BR":"Breach","ru-RU":"Breach","th-TH":"Breach","tr-TR":"BREACH","vi-VN":"Breach","zh-CN":"铁臂","zh-TW":"叛奇"}'::jsonb, '{"es-MX":"El sueco biónico Breach lanza poderosas ráfagas cinéticas para abrirse paso a la fuerza a través del territorio enemigo. El daño y la disrupción que inflige garantizan que ninguna pelea sea justa.","ar-AE":"يطلق بريتش، الرجل نصف الآلي القادم من السويد، دفقات من الطاقة الحركية القوية والموجهة لكي يخلي الطريق بكل شراسة في منطقة الأعداء. كم الضرر والتشويش الذي يسببه يضمن ألا يكون القتال عادلًا أبدًا.","es-ES":"Breach, el sueco biónico, dispara una serie de explosiones cinéticas controladas para abrirse paso por el territorio enemigo. Su capacidad para infligir daño y sembrar el caos garantiza que los combates siempre estén de su parte.","ja-JP":"生体工学を駆使した義肢を操るスウェーデン人のブリーチは、強力な衝撃波を放つことで、敵陣地への突破口を切り開く。敵にダメージや撹乱を与えることで、戦いを有利に進めることが可能だ。","it-IT":"Breach, lo svedese bionico, spara potenti scariche cinetiche mirate ad aprire un varco in modo aggressivo in territorio nemico. I danni e la distruzione che infligge conferiscono un enorme vantaggio in ogni scontro.","de-DE":"Der bionisch augmentierte Schwede Breach verursacht gezielt mächtige, kinetische Explosionen, die ohne Rücksicht auf Verluste den Weg frei räumen. Der Schaden und die Massenkontrolle stellen sicher, dass kein Kampf je fair ist.","id-ID":"Breach, bionik dari Swedia ini menembakkan ledakan kuat untuk mengosongkan jalan menembus wilayah musuh. Damage dan gangguan yang dia timbulkan memastikan pertarungan tidak pernah adil.","ko-KR":"스웨덴 출신의 생체병기 브리치는 강력한 역학적 폭발을 이용해 적진을 돌파합니다. 브리치의 강력한 피해량과 교란술은 아군이 굳이 ''공정한'' 전투를 할 필요가 없게 만들죠.","fr-FR":"Breach, le Suédois bionique, tire de puissantes décharges cinétiques pour ouvrir un chemin en territoire ennemi. Grâce aux dégâts et aux diversions ainsi provoqués, jamais un combat n''est en sa défaveur.","en-US":"The bionic Swede Breach fires powerful, targeted kinetic blasts to aggressively clear a path through enemy ground. The damage and disruption he inflicts ensures no fight is ever fair.","pl-PL":"Breach, bioniczny reprezentant Szwecji, wystrzeliwuje potężne namierzane wybuchy kinetyczne, które pozwalają przebić się przez szeregi wroga. Zadawane przez niego obrażenia i zakłócenie sprawiają, że żadna walka nie jest wyrównana.","pt-BR":"Breach, o homem-biônico sueco, dispara poderosos jatos cinéticos para forçar a abertura de um caminho pelo território inimigo. O dano e a interrupção que ele causa garantem que nenhuma luta seja justa.","ru-RU":"Использующий бионические усиления швед Breach полагается на мощные направленные взрывы, чтобы расчистить путь от агентов противника. Разрушительная сила его умений позволяет получить решающее преимущество в любом бою.","th-TH":"Breach ไบโอนิคชาวสวีเดนสามารถยิงพลังระเบิดอันรุนแรง เป้าหมายของเขาคือการเคลียร์เส้นทางในสนามรบของศัตรู ทุกความเสียหายและการก่อกวนที่เขาสร้างนั้นรุนแรง จนมั่นใจได้เลยว่าเกมจะไม่ยุติธรรมกับคู่แข่งแน่นอน","tr-TR":"İnsanüstü güçlere sahip İsveçli Breach, düşman zemininde sert bir şekilde yolu açan, hedeflenebilir kinetik dalgalar gönderir. Sebep olduğu hasar ve darbeler, savaşın dengelerini değiştirecek niteliktedir.","vi-VN":"Breach, gã Thụy Điển với thân hình đầy máy móc, có thể bắn ra các luồng năng lượng động học mạnh mẽ tới mục tiêu và mở đường xuyên qua lãnh địa của đối phương. Với sát thương đáng kể cùng khả năng gây rối, Breach luôn đảm bảo đồng đội chiếm được thế thượng phong khi giao chiến.","zh-CN":"生化改造人“铁臂”来自北欧波罗的海西岸，他能够使用定向爆破和动能冲击从敌阵中强行打开一条通道。他从来不跟敌人讲道理，火力和爆破就是硬道理。","zh-TW":"瑞典生化人叛奇，能發射強大且精準的雷射震擊，通過火力壓制開闢前往敵區的道路。能夠阻斷敵方，又能造成傷害的他，絕對是確保敵我雙方實力懸殊的不二人選。"}'::jsonb, 'Breach', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/displayicon.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/displayicon.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/fullportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/fullportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/fullportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/killfeedportrait.png', 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/minimapportrait.png', null, 'https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/background.png', array['81331aff', '0f1923ff', '523a23ff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('5f8d3a7f-467b-97f3-062c-13acf203c006'::uuid, 'Ability1', '{"es-MX":"Fulgor","ar-AE":"نقطة الوميض","es-ES":"Explosión cegadora","ja-JP":"フラッシュポイント","it-IT":"Esplosione abbagliante","de-DE":"Blitzladung","id-ID":"Flashpoint","ko-KR":"섬광 폭발","fr-FR":"Point d''ignition","en-US":"Flashpoint","pl-PL":"Rozbłysk","pt-BR":"Estopim","ru-RU":"Ослепляющий заряд","th-TH":"Flashpoint","tr-TR":"GÖZ KAMAŞTIRAN","vi-VN":"Điểm Sáng","zh-CN":"闪点爆破","zh-TW":"致盲閃光"}'::jsonb, '{"es-MX":"EQUIPA una carga cegadora y DISPARA para lanzar una ráfaga de acción rápida a través de la pared. La carga detonará y cegará a todos los jugadores que la vean.","ar-AE":"تجهّز بشحنة مسببة للعمى. أطلق الشحنة لتحرير دفقة سريعة المفعول عبر الجدار. تنفجر الشحنة لتصيب جميع اللاعبين الذين ينظرون إليها بتأثير العمى.","es-ES":"EQUIPA una carga explosiva cegadora. DISPARA la carga para liberar una rápida explosión que atraviesa la pared. Cuando detona, la carga ciega a todos los jugadores que la estén mirando.","ja-JP":"視界を奪う攻撃を装填する。「発射」することで素早く展開する爆発を巻き起こし、視線を向けていたプレイヤー全員の視界を奪う。この爆発は壁を貫通する。","it-IT":"EQUIPAGGIA una carica ACCECANTE. Usa il FUOCO per innescare un''esplosione che si propaga rapidamente attraverso il muro. La carica esplode ACCECANDO tutti i giocatori che la guardano.","de-DE":"RÜSTE eine Blendladung AUS. FEUERE eine Ladung, um eine schnelle Explosion durch eine Wand zu schicken. Die Ladung detoniert und blendet alle Spieler, die sie sehen.","id-ID":"EQUIP charge dengan utilitas Blind. Tekan FIRE untuk melakukan charge dan mempersiapkan ledakan cepat menembus dinding. Charge terdetonasi untuk memberikan utilitas Blind pada semua pemain yang melihatnya.","ko-KR":"실명탄을 장착합니다. 발사하면 벽을 통과하고 빠르게 효과가 발생하는 폭발을 일으켜 섬광을 본 모든 플레이어를 실명시킵니다.","fr-FR":"ÉQUIPEZ-vous d''une charge aveuglante. TIREZ pour provoquer une explosion rapide à travers le mur. La charge explose en aveuglant tous les joueurs qui la regardent.","en-US":"EQUIP a Blinding charge. FIRE the charge to set a fast-acting burst through the wall. The charge detonates to Blind all players looking at it.","pl-PL":"WYPOSAŻ ładunek oślepiający. STRZEL, by wypuścić szybki ładunek przez ścianę. Ładunek wybuchnie i oślepi wszystkich patrzących w jego stronę graczy.","pt-BR":"EQUIPE uma carga Cegante. DISPARE a carga para armar um jato de ação rápida pela parede. A carga é detonada, Cegando todos os jogadores que estiverem olhando para ela.","ru-RU":"Выбирает ослепляющий заряд. Нажмите кнопку ОГОНЬ, чтобы запустить его через стену. Заряд взрывается и ослепляет всех смотрящих в его сторону игроков.","th-TH":"ติดตั้งปืนลำแสง กดยิงเพื่อปล่อยระเบิดทะลุผ่านกำแพงอย่างรวดเร็ว ระเบิดลำแสงจะทำให้ผู้เล่นทุกคนที่มองเห็นสูญเสียการมองเห็น","tr-TR":"Kör Edici bir yük KUŞAN. Duvarın içinden geçtikten sonra art arda hızla gerçekleşen patlamalar oluşturmak için ATEŞ ET. Patlayan yük, ona bakan herkesi Kör eder.","vi-VN":"TRANG BỊ một đạn Mù. BẮN để phóng một viên đạn siêu tốc xuyên qua tường. Khi phát nổ sẽ làm Mù tất cả người chơi trong phạm vi tầm nhìn của viên đạn.","zh-CN":"装备【致盲】炸药。按【射击】即可在墙壁的另一侧引发一次爆破，【致盲】所有目击爆破点的玩家。","zh-TW":"裝備一顆「致盲彈」。點擊「攻擊」發射彈體，穿牆後在另一面快速爆炸。爆炸後將「致盲」所有未移開視線的玩家。"}'::jsonb, '"https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('5f8d3a7f-467b-97f3-062c-13acf203c006'::uuid, 'Ability2', '{"es-MX":"Falla Sísmica","ar-AE":"الصدع المزلزل","es-ES":"Falla","ja-JP":"フォールトライン","it-IT":"Fenditura","de-DE":"Verwerfungslinie","id-ID":"Fault Line","ko-KR":"균열","fr-FR":"Ligne de fracture","en-US":"Fault Line","pl-PL":"Uskok","pt-BR":"Falha Tectônica","ru-RU":"Трещина","th-TH":"Fault Line","tr-TR":"FAY HATTI","vi-VN":"Địa Chấn","zh-CN":"山崩地陷","zh-TW":"震動斷層"}'::jsonb, '{"es-MX":"EQUIPA una Carga Sísmica. MANTÉN PRESIONADO EL DISPARO para aumentar la distancia. SUELTA para iniciar el temblor y conmocionar a todos los jugadores que estén en su alcance.","ar-AE":"تجهّز بمفجر زلزالي. تابع الضغط على زر الإطلاق لزيادة المسافة. حرر الزر لتطلق الزلزال الذي يسبب الارتجاج لجميع اللاعبين المتواجدين في نطاقه وفي خط يصل إلى المنطقة.","es-ES":"EQUIPA una bomba sísmica. MANTÉN PULSADO DISPARAR para aumentar la distancia. SUELTA para liberar un seísmo que conmocionará a todos los jugadores dentro de la zona y en una línea hasta ella.","ja-JP":"大地を揺るがす強力な衝撃波を構える。「発射長押し」で飛距離を伸ばすことができる。発射すると揺れが発生し、範囲内および範囲に至る直線上のすべてのプレイヤーをスタン状態にする。","it-IT":"EQUIPAGGIA una Carica Sismica. TIENI PREMUTO il FUOCO per aumentare la distanza. RILASCIA per innescare il terremoto, STORDENDO tutti i giocatori nel raggio d''azione e in linea retta fino all''epicentro.","de-DE":"RÜSTE eine seismische Druckwelle AUS. HALTE FEUERN, um die Distanz zu erhöhen. LOSLASSEN, um das Beben zu entfesseln, das alle Spieler im Wirkbereich in einer Linie betäubt.","id-ID":"EQUIP Ledakan Seismik. HOLD FIRE untuk menambah jarak. LEPAS untuk memulai gempa, terapkan Concuss pada semua pemain dalam zonanya dan dalam jalur menuju zona tersebut.","ko-KR":"지진파를 장착합니다. 발사를 길게 누르면 사거리가 늘어납니다. 버튼을 떼면 지진파를 날려 경로상에 있는 적과 대상 범위 내의 모든 적에게 뇌진탕을 일으킵니다.","fr-FR":"ÉQUIPEZ-vous d''un explosif sismique. MAINTENEZ LE TIR pour augmenter la distance. RELÂCHEZ pour provoquer un séisme qui désoriente tous les joueurs dans la zone et sur une ligne menant à la zone.","en-US":"EQUIP a Seismic Blast. HOLD FIRE to increase the distance. RELEASE to set off the quake, Concussing all players in its zone and in a line up to the zone.","pl-PL":"WYPOSAŻ Wybuch Sejsmiczny. PRZYTRZYMAJ STRZAŁ, by zwiększyć jego zasięg. PUŚĆ, by wywołać wstrząs ogłuszający wszystkich graczy na obszarze jego działania oraz stojących na drodze do tej strefy.","pt-BR":"EQUIPE um impacto sísmico. SEGURE O DISPARO para aumentar a distância. SOLTE para iniciar o terremoto, causando Concussão em todos os jogadores na zona e numa linha reta até a zona.","ru-RU":"Выбирает сейсмический заряд. Удерживайте кнопку ОГОНЬ, чтобы увеличить дальность разлома. Отпустите, чтобы создать разлом, оглушающий всех игроков в зоне поражения.","th-TH":"ติดตั้งคลื่นระเบิดสั่นสะเทือน กดยิงค้างไว้เพื่อเพิ่มระยะทาง ปล่อยเพื่อสร้างแรงสั่นสะเทือน สร้างสถานะกระทบกระเทือนแก่ผู้เล่นทั้งหมดในพื้นที่และในแนวของการสั่นสะเทือน","tr-TR":"Sismik bir darbe KUŞAN. Darbenin etkili olacağı mesafeyi arttırmak için BASILI TUT. Bir sarsıntı oluşturarak etki alanında ve alan hattı üzerinde kalan tüm oyuncuları Sersemletmek için SERBEST BIRAK.","vi-VN":"TRANG BỊ một Đạn Xung Chấn. GIỮ BẮN để tăng khoảng cách. THẢ RA để giải phóng một cơn địa chấn, Làm Choáng tất cả người chơi trong phạm vi ảnh hưởng và trên đường thẳng từ vị trí bắn đến cơn địa chấn.","zh-CN":"装备震波冲击器。【按住射击】可增加射程。【松开】便可引发震荡，使直线范围内的玩家受到【震荡】。","zh-TW":"裝備一道撼地雷射。長按「攻擊」可增加攻擊距離。放開「攻擊」，將引發地震，「暈眩」範圍內以及發射路徑上的所有玩家。"}'::jsonb, '"https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('5f8d3a7f-467b-97f3-062c-13acf203c006'::uuid, 'Grenade', '{"es-MX":"Réplica","ar-AE":"الصدمة الارتدادية","es-ES":"Réplica","ja-JP":"アフターショック","it-IT":"Scossa di assestamento","de-DE":"Nachbeben","id-ID":"Aftershock","ko-KR":"여진","fr-FR":"Réplique","en-US":"Aftershock","pl-PL":"Wstrząs Wtórny","pt-BR":"Pós-choque","ru-RU":"Пробивной удар","th-TH":"Aftershock","tr-TR":"ARTÇI SARSINTI","vi-VN":"Dư Chấn","zh-CN":"剧震余波","zh-TW":"餘震打擊"}'::jsonb, '{"es-MX":"EQUIPA una carga de fusión y DISPARA para lanzar una ráfaga de acción lenta a través de la pared. La ráfaga infligirá mucho daño a todos los que estén en su alcance.","ar-AE":"تجهّز بشحنة اندماجية. أطلق الشحنة لتحرر دفقة بطيئة المفعول عبر الجدار. تلحق الشحنة ضررًا كبيرًا لكل من يتواجد في نطاقها.","es-ES":"EQUIPA una carga explosiva de fusión. DISPARA la carga para liberar una explosión que atraviesa la pared tras un retardo. La explosión inflige mucho daño a cualquiera que esté dentro del área afectada.","ja-JP":"核融合エネルギーをチャージする。「発射」することでゆっくりと展開する爆発を巻き起こし、範囲内のプレイヤーすべてに大ダメージを与える。この爆発は壁を貫通する。","it-IT":"EQUIPAGGIA una carica a fusione. Usa il FUOCO per innescare un''esplosione che si propaga lentamente attraverso il muro. L''esplosione infligge danni ingenti a chiunque si trovi nel relativo raggio d''azione.","de-DE":"RÜSTE eine Fusionsladung AUS. SPRENGE die Ladung, um eine langsame Explosion durch eine Wand zu schicken. Diese fügt allen getroffenen Spielern schweren Schaden zu.","id-ID":"EQUIP charge fusi. Tekan FIRE untuk melakukan charge dan mempersiapkan ledakan lambat menembus dinding. Ledakan memberikan damage besar pada semua yang berada di area tersebut.","ko-KR":"융합 에너지탄을 장착합니다. 발사하면 벽을 통과하고 느리게 효과가 발생하는 폭발을 일으켜 대상 범위 내의 모든 적에게 큰 피해를 입힙니다.","fr-FR":"ÉQUIPEZ-vous d''une charge à fusion. TIREZ pour provoquer une explosion lente à travers le mur. L''explosion inflige d''importants dégâts à tous ceux dans la zone.","en-US":"EQUIP a fusion charge. FIRE the charge to set a slow-acting burst through the wall. The burst does heavy damage to anyone caught in its area.","pl-PL":"WYPOSAŻ ładunek fuzyjny. STRZEL, by wypuścić powolny ładunek przez ścianę. Zada on duże obrażenia każdemu, kto znajdzie się na obszarze jego działania.","pt-BR":"EQUIPE uma carga de fusão. DISPARE a carga para armar um jato de ação lenta pela parede, que causa alto dano a todos que estiverem na área de efeito.","ru-RU":"Выбирает взрывной заряд. Нажмите кнопку ОГОНЬ, чтобы запустить заряд через стену и создать взрыв на другой стороне. Взрыв наносит серьезный урон всем, кто попадает в зону поражения.","th-TH":"ติดตั้ง Fusion Charge กดยิงเพื่อปล่อยระเบิดที่จะหน่วงเวลาในการยิงทะลุผ่านกำแพง ระเบิดจะสร้างความเสียหายอันรุนแรงแก่ผู้เล่นที่อยู่ในพื้นที่นั้น","tr-TR":"Termonükleer bir yük KUŞAN. Duvarın içinden geçtikten sonra zamanla gerçekleşen patlamalar için ATEŞ ET. Patlayan yük, etki alanında kalan herkese ağır hasar verir.","vi-VN":"TRANG BỊ 1 đạn nhiệt hạch. BẮN để phóng 1 viên đạn nổ chậm xuyên qua tường. Khi phát nổ sẽ gây sát thương lớn lên bất cứ ai trong phạm vi ảnh hưởng.","zh-CN":"装备聚变炸药。按【射击】即可透过墙壁引发一次延时生效的爆破。该冲击会对作用范围内的所有人造成严重伤害。","zh-TW":"裝備一枚核融彈。點擊「攻擊」發射彈體，穿牆後在另一面緩速爆炸。在範圍內的所有人將受到重度傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('5f8d3a7f-467b-97f3-062c-13acf203c006'::uuid, 'Ultimate', '{"es-MX":"Trueno Rodante","ar-AE":"الرعد الهادر","es-ES":"Fragor imparable","ja-JP":"ローリングサンダー","it-IT":"Esplosione sismica","de-DE":"Thors Hammer","id-ID":"Rolling Thunder","ko-KR":"지진 강타","fr-FR":"Onde sismique","en-US":"Rolling Thunder","pl-PL":"Kaskadowe Tąpnięcie","pt-BR":"Onda Trovejante","ru-RU":"Раскат грома","th-TH":"Rolling Thunder","tr-TR":"ZELZELE","vi-VN":"Đại Địa Chấn","zh-CN":"惊雷卷地","zh-TW":"撼地轟雷"}'::jsonb, '{"es-MX":"EQUIPA una carga sísmica y DISPARA para enviar un temblor en cascada por una gran zona. El temblor conmociona y lanza por el aire a todos los que impacte.","ar-AE":"تجهّز بشحنة مزلزلة. أطلق لترسل موجة زلزالية متعاقبة عبر جميع التضاريس في منطقة واسعة. تسبب الموجة الزلزالية الارتجاج وتطيح بجميع المتعرضين لها إلى الخلف.","es-ES":"EQUIPA una carga explosiva sísmica. DISPARA para liberar un seísmo que se extenderá por una gran zona. El seísmo aturde y lanza por los aires a todos los jugadores que estén en el interior de la zona.","ja-JP":"大地を揺るがす強力な衝撃波を溜め、「発射」で扇状の広範囲に次々と揺れを発生させて、命中した者すべてをスタン状態にし、ノックアップさせる。","it-IT":"EQUIPAGGIA una carica sismica. Usa il FUOCO per innescare un terremoto a cascata che si propaga lungo tutto il terreno in un''ampia area. Il terremoto STORDISCE e scaglia in aria chiunque venga travolto.","de-DE":"RÜSTE eine seismische Ladung AUS. FEUERE, um ein großflächiges Beben durch sämtliches Terrain zu schicken. Das Beben betäubt alle getroffenen Spieler und schleudert sie in die Luft.","id-ID":"EQUIP Charge Seismik. Tekan FIRE untuk mengirimkan gempa beruntun melalui semua medan dalam zona besar. Gempa akan menerapkan utilitas Concuss dan menjatuhkan semua yang terperangkap di dalamnya.","ko-KR":"지진탄을 장착합니다. 발사하면 모든 지형을 통과하는 지진 파동을 날려 경로상에 있는 모든 적에게 뇌진탕을 일으키고 공중으로 띄웁니다.","fr-FR":"ÉQUIPEZ-vous d''une charge sismique. TIREZ pour envoyer un séisme déferlant à travers tous les obstacles dans une large zone. Le séisme désoriente et projette en l''air tous ceux qu''il touche.","en-US":"EQUIP a Seismic Charge. FIRE to send a cascading quake through all terrain in a large zone. The quake Concusses and knocks up anyone caught in it.","pl-PL":"WYPOSAŻ ładunek sejsmiczny. STRZEL, by posłać wielki kaskadowy wstrząs na obszarze. Wstrząs ogłusza i wyrzuca w powietrze każdego na swojej drodze.","pt-BR":"EQUIPE uma Carga Sísmica. DISPARE para lançar um terremoto em cascata por todo o terreno numa grande área. O terremoto causa Concussão e lança ao ar quem estiver na área de efeito.","ru-RU":"Выбирает сейсмическую волну. Нажмите кнопку ОГОНЬ, чтобы запустить цепочку взрывов в обширной области перед собой. Эти взрывы оглушают и подбрасывают в воздух всех на своем пути.","th-TH":"ติดตั้งปืนระเบิดสั่นสะเทือน กดยิงเพื่อส่งแรงสั่นสะเทือนที่ทะลุผ่านพื้นที่ได้ทุกแบบเป็นบริเวณกว้าง แรงสั่นสะเทือนจะทำให้ทุกคนที่อยู่ในพื้นที่ติดสถานะกระทบกระเทือนและถูกกระแทกให้ลอยขึ้น","tr-TR":"Sismik bir yük KUŞAN. Geniş bir alanın içinde kalan zemini dalga dalga etkileyen bir deprem tetiklemek için ATEŞ ET. Depreme yakalanan herkes Sersemler ve havaya savrulur.","vi-VN":"TRANG BỊ một Đầu Đạn Đại Xung Chấn. BẮN để giải phóng một trận động đất qua mọi địa hình trong phạm vi lớn. Cơn địa chấn Làm Choáng và hất tung bất cứ ai trong phạm vi ảnh hưởng.","zh-CN":"装备震波炸药。按【射击】在巨大的锥形范围内发出一道穿越地形、层层递进的地震波。该地震会击飞任何受波及的玩家并震晕他们。","zh-TW":"裝備一顆撼地彈。點擊「攻擊」，釋放可穿透所有地形的大範圍連鎖地震。範圍內所有人將受到暈眩且遭到擊飛。"}'::jsonb, '"https://media.valorant-api.com/agents/5f8d3a7f-467b-97f3-062c-13acf203c006/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, '{"es-MX":"Deadlock","ar-AE":"ديدلوك","es-ES":"Deadlock","ja-JP":"デッドロック","it-IT":"Deadlock","de-DE":"Deadlock","id-ID":"Deadlock","ko-KR":"데드록","fr-FR":"Deadlock","en-US":"Deadlock","pl-PL":"Deadlock","pt-BR":"Deadlock","ru-RU":"Deadlock","th-TH":"Deadlock","tr-TR":"DEADLOCK","vi-VN":"Deadlock","zh-CN":"钢锁","zh-TW":"蒂羅"}'::jsonb, '{"es-MX":"La agente noruega Deadlock despliega una variedad de nanocables de alta tecnología para asegurar el campo de batalla, incluso en los asaltos más letales. Nadie escapa de su ojo vigilante ni sobrevive a su ferocidad inquebrantable.","ar-AE":"تنشر العميلة النرويجية ديدلوك مجموعة من أسلاك النانو المتطورة لتأمين ميدان المعركة حتى من أكثر الهجمات فتكًا. ولا أحد يفلت من مراقبتها اليقظة، ولا ينجو أحد من ضراوتها التي لا تلين.","es-ES":"Deadlock, la agente noruega, despliega un surtido de avanzados nanocables para defender el campo de batalla de cualquier asalto, por letal que sea. Nadie escapa a su atenta mirada ni sobrevive a su implacable ferocidad.","ja-JP":"ノルウェー出身の工作員、デッドロックは最先端のナノワイヤー技術を駆使し、危険な襲撃の最中においても戦場の要所を確保する。その油断のない監視、そして不屈の獰猛さから逃れられる者はいない。","it-IT":"L''agente norvegese Deadlock si serve di una rivoluzionaria varietà di nanofilo per difendere il campo di battaglia dagli assalti più letali. Nessuno può eludere la sua vigile sorveglianza, né sopravvivere alla sua irriducibile ferocia.","de-DE":"Die norwegische Elitesoldatin Deadlock bedient sich verschiedener High-Tech-Nanodrahtgeräte, um das Schlachtfeld vor den tödlichsten Angriffen zu schützen. Nichts und niemand entgeht ihren Argusaugen und ihre Entschlossenheit hat noch jeden Gegner zur Strecke gebracht.","id-ID":"Detektif Norwegia, Deadlock, mengerahkan nanowire mutakhir untuk mengamankan battlefield dari serangan yang paling mematikan sekalipun. Tidak ada yang bisa lolos dari pengawasan ketatnya, ataupun bertahan dari kebengisannya.","ko-KR":"노르웨이 출신 요원 데드록은 최첨단 나노와이어를 배치해 전장의 위협적인 공격을 막아냅니다. 누구도 데드록의 감시를 피할 수도, 집요한 공격에서 살아남을 수도 없습니다.","fr-FR":"Deadlock, l''agent spécial norvégien, déploie un éventail de nanocâbles ultra-modernes pour défendre sa position contre le plus violent des assauts. Nul n''échappe à sa vigilance ni ne survit à sa cruelle ténacité.","en-US":"Norwegian operative Deadlock deploys an array of cutting-edge nanowire to secure the battlefield from even the most lethal assault. No one escapes her vigilant watch, nor survives her unyielding ferocity.","pl-PL":"Norweska agentka Deadlock korzysta z nowatorskich nanoobwodów, aby zabezpieczyć pole walki przed nawet najbardziej zabójczym atakiem. Nic jej nie umknie i nikt nie przetrwa jej bezwzględnej zaciekłości.","pt-BR":"A agente norueguesa Deadlock posiciona uma gama de nanofios de alta tecnologia para proteger o campo de batalha até mesmo do ataque mais letal. Ninguém escapa do seu olhar vigilante. Ninguém sobrevive à sua ferocidade implacável.","ru-RU":"Уроженка Норвегии Deadlock известна своим упорством и суровостью. Она контролирует ситуацию на поле боя с помощью наноустройств, и никто не может ускользнуть от ее зоркого взгляда.","th-TH":"Deadlock สายลับชาวนอร์เวย์ ผู้เชี่ยวชาญการใช้เส้นลวดนาโนล้ำยุคเพื่อควบคุมสถานการณ์ในสนามรบ และพร้อมรับมือแม้กระทั่งการบุกโจมตีที่หนักหน่วงที่สุด ไม่มีใครเล็ดลอดไปจากสายตาที่จับจ้องของเธอได้ และไม่เคยมีผู้ใดรอดชีวิตจากความดุร้ายไร้ปราณีของเธอ","tr-TR":"Norveçli ajan Deadlock, savaş esnasında en ölümcül saldırıları bile savuşturabilecek son teknoloji bir nanobağ ağı kullanır. Keskin gözlerinden kaçan, vahşetinden kurtulan olmamıştır.","vi-VN":"Đặc Vụ người Na-uy: Deadlock, sử dụng hàng loạt sợi dây nano tân tiến nhằm bảo vệ chiến trường khỏi những đợt công kích nguy hiểm nhất. Chẳng ai có thể thoát khỏi sự truy sát gắt gao, cũng như không thể sống sót trước sự hung dữ ngoan cường của cô ấy.","zh-CN":"来自北欧的特工“钢锁”配备着多种尖端纳米纤维武器，她擅长监听战场动态和阻碍对手移动。一旦敌人遭到锁定，将面对她凌厉无情的攻势并难逃一劫。","zh-TW":"挪威籍特務蒂羅佈下大量尖端科技奈米線守住陣地，就連最致命的攻擊也難越雷池一步。在她的警戒下，誰都逃不過她的法眼。她對敵人從不手下留情，遇上她絕對九死而無一生。"}'::jsonb, 'Cable', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/displayicon.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/displayicon.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/fullportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/fullportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/fullportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/killfeedportrait.png', 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/minimapportrait.png', null, 'https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/background.png', array['425495ff', '0f1923ff', '221c3dff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, 'Ability1', '{"es-MX":"Sensor Sónico","ar-AE":"لاقط الصوت","es-ES":"Sensor sónico","ja-JP":"ソニックセンサー","it-IT":"Sensore sonico","de-DE":"Geräuschsensor","id-ID":"Sonic Sensor","ko-KR":"음향 센서","fr-FR":"Radar ultrason","en-US":"Sonic Sensor","pl-PL":"Wykrywacz Dźwięku","pt-BR":"Sensor Sônico","ru-RU":"Звуковой сенсор","th-TH":"Sonic Sensor","tr-TR":"SONİK SENSÖR","vi-VN":"Cảm Biến Siêu Thanh","zh-CN":"声感陷阱","zh-TW":"聲波感測器"}'::jsonb, '{"es-MX":"EQUIPA un Sensor Sónico. DISPARA para desplegarlo. El sensor vigila una zona en busca de enemigos que emitan sonidos. Conmociona la zona si detecta pisadas, disparos o una cantidad de ruido significativa. Puedes recogerla para VOLVER A COLOCARLA en otro lugar.","ar-AE":"تجهز بلاقط صوت. أطلق لنشره. يرصد اللاقط أصوات الأعداء في منطقة معينة. يصيب تلك المنطقة بصدمة ارتجاجية إذا رصدَ صوت خطوات أقدام أو نيران أسلحة أو ضوضاء عالية بما يكفي. يمكن التقاط هذه القدرة لإعادة تثبيتها مرة أخرى.","es-ES":"EQUIPA un sensor sónico. DISPARA para desplegarlo. El sensor rastrea la zona en busca de enemigos que hagan ruido. Si detecta sonidos de pisadas, disparos o cualquier otro ruido considerable, aturde en área. Se puede recoger para VOLVER A COLOCARLO.","ja-JP":"ソニックセンサーを構える。「発射」で設置する。センサーは範囲内で敵が発生させる音をモニターする。足音、射撃音、その他大きな音が検知された場合、範囲内にスタンを発生させる。このアビリティーは回収して再設置可能。","it-IT":"EQUIPAGGIA un sensore sonico. Usa il FUOCO per piazzarlo. Il sensore monitora un''area in attesa di rumori emessi dai nemici, investendola con un effetto stordente se rileva rumore di passi, spari o altri rumori significativi. Questa abilità può essere raccolta per essere RIUTILIZZATA.","de-DE":"RÜSTE einen Geräuschsensor AUS. FEUERE, um den Sensor aufzustellen. Der Sensor überwacht einen Bereich auf Gegner, die Geräusche machen. Er macht Gegner im Bereich kampfunfähig, wenn er Schritte, Waffenfeuer oder signifikante Geräusche erkennt. Du kannst diese Fähigkeit aufheben, um sie ERNEUT EINZUSETZEN.","id-ID":"EQUIP Sonic Sensor. Tekan FIRE untuk mengerahkan benda tersebut. Sensor memantau area untuk mendeteksi musuh yang mengeluarkan suara. Area itu akan terkena utilitas Concuss jika langkah kaki, tembakan senjata, atau suara bising terdeteksi. Ability ini bisa diambil untuk DIKERAHKAN LAGI.","ko-KR":"음향 센서를 장착합니다. 발사하면 음향 센서를 설치합니다. 센서는 지역에서 적이 내는 소리를 탐지합니다. 발걸음 소리, 사격음, 큰 소음이 탐지되면 지역에 뇌진탕을 일으킵니다. 이 스킬은 회수하여 다시 설치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous du Radar ultrason. TIREZ pour le déployer. Le radar détecte tous les sons générés par les ennemis dans une zone. Il inflige une désorientation dans cette zone dès qu''il repère des bruits de pas, de tir ou tout autre son remarquable. Le radar peut être ramassé pour être REDÉPLOYÉ.","en-US":"EQUIP a Sonic Sensor. FIRE to deploy. The sensor monitors an area for enemies making sound. It concusses that area if footsteps, weapons fire, or significant noise are detected. This ability can be picked up to be REDEPLOYED.","pl-PL":"WYPOSAŻ Wykrywacz Dźwięku. STRZEL, by ustawić urządzenie. Wykrywacz monitoruje obszar na obecność wrogów wydających dźwięki. Jeśli wykryte zostaną odgłosy kroków, wystrzału lub znaczący hałas, cały obszar podlega ogłuszeniu. Można go podnieść i UŻYĆ PONOWNIE.","pt-BR":"EQUIPE um Sensor Sônico. DISPARE para posicionar. O sensor monitora os sons dos inimigos em uma área. Causa Concussão na área se sons de passos, disparos ou qualquer barulho significativo forem detectados. O sensor pode ser recuperado e REPOSICIONADO.","ru-RU":"Выбирает звуковой сенсор. Нажмите ОГОНЬ, чтобы разместить его. Сенсор оглушает всех противников в области действия, если обнаруживает издаваемые ими звуки – например, шаги или стрельбу. Сенсор можно подобрать и разместить заново.","th-TH":"ติดตั้ง Sonic Sensor กดยิงเพื่อใช้งาน เซ็นเซอร์จะคอยตรวจจับเสียงของศัตรูภายในพื้นที่ และจะสั่นกระเทือนพื้นที่ดังกล่าวเมื่อตรวจพบเสียงฝีเท้า เสียงยิงอาวุธ หรือเสียงดังอื่น ๆ อุปกรณ์นี้สามารถเก็บขึ้นมาได้เพื่อติดตั้งใหม่","tr-TR":"Bir Sonik Sensör KUŞAN. Sensörü yerleştirmek için ATEŞ ET. Sensör, düşman seslerini algılamak üzere bölgeyi tarar. Eğer taradığı bölgede ayak sesi, silah sesi veya yüksek ses tespit ederse bölgeye sersemletme uygular. Bu yeteneği TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin.","vi-VN":"TRANG BỊ 1 Cảm Biến Siêu Thanh. BẮN để sử dụng. Cảm biến có thể giám sát khu vực và phát hiện kẻ địch gây tiếng động. Nó sẽ gây ra xung chấn tới khu vực đó nếu phát hiện thấy tiếng bước chân, tiếng súng hoặc tiếng ồn. Kỹ năng này cho phép bạn nhặt bẫy dây lên và ĐẶT LẠI.","zh-CN":"装备声感陷阱。按【射击】进行部署。声感陷阱将在一定范围内监听敌方动态，一旦探测到脚步声、枪声或其它明显噪音，便会自动激活，对区域内所有目标造成【震荡】。此装置可被回收并【重新部署】。","zh-TW":"裝備一個聲波偵測器。點擊「攻擊」部署。感測器會偵測範圍內敵人發出的聲音，只要偵測到腳步聲、槍聲或是明顯聲響，就會暈眩範圍內的敵人。可撿起偵測器，然後「重新部署」。"}'::jsonb, '"https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, 'Grenade', '{"es-MX":"Malla Protectora","ar-AE":"شبكة الحاجز","es-ES":"Malla barrera","ja-JP":"バリアメッシュ","it-IT":"Rete di protezione","de-DE":"Gitterbarriere","id-ID":"Barrier Mesh (E)","ko-KR":"장벽망","fr-FR":"Disque barrière","en-US":"Barrier Mesh","pl-PL":"Siatka Bariery","pt-BR":"Barreira de Contenção","ru-RU":"Барьерная сеть","th-TH":"Barrier Mesh","tr-TR":"BARİYER AĞI","vi-VN":"Lưới Chướng Ngại","zh-CN":"阻域屏障","zh-TW":"天羅地網"}'::jsonb, '{"es-MX":"EQUIPA un disco de Malla Protectora. DISPARA para lanzarlo hacia adelante. Al caer, el disco genera barreras desde el punto de origen que bloquean el movimiento de los enemigos.","ar-AE":"تجهّز بقرص شبكة حاجز. أطلق لرميه للأمام. عند ارتطامه بالأرض، يولّد القرص حواجز من الموضع الأصلي تعيق حركة العملاء.","es-ES":"EQUIPA un disco de Malla barrera. DISPARA para lanzarlo hacia delante. Al aterrizar, el disco genera barreras a partir de su punto de origen que detienen el movimiento de los personajes.","ja-JP":"バリアメッシュを発生させるディスクを構える。「発射」で前方に投げる。地面に触れると、ディスクを中心として移動を遮るバリアが発生する。","it-IT":"EQUIPAGGIA un disco contenente la rete di protezione. Usa il FUOCO per lanciarlo in avanti. All''atterraggio, il disco genera una serie di barriere a raggiera che bloccano il movimento dei personaggi.","de-DE":"RÜSTE eine Gitterbarrierenscheibe AUS. FEUERE, um sie nach vorne zu werfen. Bei der Landung erzeugt die Scheibe vom Ursprungspunkt aus Barrieren, die Charakterbewegungen blockieren.","id-ID":"EQUIP cakram Barrier Mesh. Tekan FIRE untuk melempar ke depan. Saat mendarat, cakram menghasilkan penghalang yang membentang dari titik asal. Penghalang tersebut memblokir pergerakan agen.","ko-KR":"장벽망 디스크를 장착합니다. 발사하면 디스크를 앞으로 던집니다. 디스크가 지면에 닿으면 해당 지점에서 장벽이 생성되어 캐릭터가 움직이지 못하도록 억제합니다.","fr-FR":"ÉQUIPEZ-vous du Disque barrière. TIREZ pour le lancer vers l''avant. À l''atterrissage, le disque déploie à partir du point d''origine une barrière bloquant l''avancée des agents.","en-US":"EQUIP a Barrier Mesh disc. FIRE to throw forward. Upon landing, the disc generates barriers from the origin point that block character movement.","pl-PL":"WYPOSAŻ dysk Siatki Bariery. STRZEL, by rzucić nim naprzód. Po wylądowaniu dysk stawia barierę wzdłuż trasy lotu, która blokuje ruch postaci.","pt-BR":"EQUIPE um disco de Barreira de Contenção. DISPARE para lançar à frente. Ao atingir o chão, o disco gera barreiras a partir do ponto de origem, que bloqueiam a movimentação de personagens.","ru-RU":"Выбирает диск с барьерной сетью. Нажмите кнопку ОГОНЬ, чтобы бросить диск вперед. После приземления диск создает барьеры, через которые агенты не могут пройти.","th-TH":"ติดตั้ง Barrier Mesh Disc กดยิงเพื่อขว้างไปด้านหน้า เมื่อตกพื้น Disc จะสร้างบาเรียระหว่างจุดที่เริ่มขว้างจนถึงจุดที่ตกพื้น ซึ่งจะขวางไม่ให้ตัวละครสามารถเคลื่อนที่ผ่านได้","tr-TR":"Bir Bariyer Ağı diski KUŞAN. Diski ileri fırlatmak için ATEŞ ET. Diskin indiği noktada yanlara doğru açılan ve karakterlerin hareketini engelleyen bariyerler oluşur.","vi-VN":"TRANG BỊ 1 đĩa phóng Lưới Chướng Ngại. BẮN để ném về phía trước. Khi chạm đất, đĩa sẽ tạo ra rào chắn từ xuất phát điểm và chặn đường di chuyển.","zh-CN":"装备屏障网生成器。按【射击】向前掷出。该装置会在落地点周围生成屏障网，阻挡所有角色移动。","zh-TW":"裝備一個天羅地網圓盤。點擊「攻擊」向前投出。圓盤落地時會在原點到落點之間生成屏障，阻隔角色移動。"}'::jsonb, '"https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, 'Ability2', '{"es-MX":"GravNet","ar-AE":"شبكة الجاذبية","es-ES":"Red de gravedad","ja-JP":"グラヴィネット","it-IT":"GravNet","de-DE":"GravNet","id-ID":"GravNet","ko-KR":"중력그물","fr-FR":"GravNet","en-US":"GravNet","pl-PL":"GravNet","pt-BR":"GravNet","ru-RU":"Гравинет","th-TH":"GravNet","tr-TR":"NANOÇEKİM","vi-VN":"Lưới Trọng Lực","zh-CN":"重力捕网","zh-TW":"重力網"}'::jsonb, '{"es-MX":"EQUIPA una granada GravNet. DISPARA para lanzarla. Usa el DISPARO SECUNDARIO para lanzarla por debajo. La granada GravNet explota al caer y fuerza a los agentes que se encuentren en la zona a agacharse y moverse con lentitud.","ar-AE":"تجهّز بقنبلة شبكة الجاذبية. أطلق لرميها. استخدم الإطلاق البديل للإلقاء المقوس. تنفجر شبكة الجاذبية عند ارتطامها بالأرض، مما يجبر أي شخصيات موجودة في نطاقها على الانحناء والتحرك ببطء.","es-ES":"EQUIPA una granada de Red de gravedad. DISPARA para lanzarla. Utiliza el DISPARO ALTERNATIVO para tirarla. La Red de gravedad explota al aterrizar, lo que fuerza a los agentes alcanzados a agacharse y moverse lentamente.","ja-JP":"グラヴィネットグレネードを構える。「発射」で投げる。「オルト射撃」では軽く放る。グラヴィネットは着弾すると起爆し、範囲内のプレイヤーは強制的にしゃがみ状態になり、移動速度が低下する。","it-IT":"EQUIPAGGIA una granata GravNet. Usa il FUOCO per lanciarla. Usa il FUOCO ALTERNATIVO per lanciarla dal basso verso l''alto. La GravNet esplode all''atterraggio, costringendo chiunque venga investito dall''esplosione ad accovacciarsi e a muoversi lentamente.","de-DE":"RÜSTE eine GravNet-Granate AUS. FEUERE, um sie zu werfen. ALT. FEUERMODUS für einen Unterhandwurf. Die GravNet-Granate detoniert beim Landen und zwingt alle Charaktere in Reichweite dazu, sich zu ducken und langsam zu bewegen.","id-ID":"EQUIP granat GravNet. Tekan FIRE untuk melempar. Tekan ALT FIRE untuk melempar tinggi. GravNet meledak saat mendarat, memaksa agen mana pun yang terjebak di dalamnya untuk merunduk dan bergerak perlahan.","ko-KR":"중력그물 수류탄을 장착합니다. 발사하면 수류탄을 투척합니다. 보조 공격 시 가깝게 투척합니다. 중력그물 수류탄은 지면에 닿으면 폭발해 범위 내에 있는 모든 캐릭터를 앉아서 천천히 움직이게 합니다.","fr-FR":"ÉQUIPEZ-vous d''une grenade GravNet. TIREZ pour la lancer. Utilisez le TIR SECONDAIRE pour la lancer en cloche. La GravNet explose à l''atterrissage, forçant tous les personnages dans son rayon d''action à s''accroupir et à se déplacer au ralenti.","en-US":"EQUIP a GravNet grenade. FIRE to throw. ALT FIRE to lob. The GravNet detonates upon landing, forcing any characters caught within to crouch and move slowly.","pl-PL":"WYPOSAŻ granat GravNet. STRZEL, by rzucić. Naciśnij ALT. STRZAŁ, by cisnąć. GravNet detonuje się po wylądowaniu, a postacie znajdujące się w zasięgu jego rażenia są zmuszone przykucnąć i poruszać się powoli.","pt-BR":"EQUIPE uma granada GravNet. DISPARE para lançar. Use o DISPARO ALTERNATIVO para arremessar a curta distância. A GravNet detona ao atingir o chão, o que força personagens pegos por ela a agacharem e moverem-se lentamente.","ru-RU":"Выбирает гранату \"Гравинет\". Нажмите ОГОНЬ для обычного броска. Нажмите АЛЬТ. ОГОНЬ для броска снизу. Столкнувшись с поверхностью, граната создает гравитационное поле, внутри которого все персонажи приседают, и их скорость передвижения снижается.","th-TH":"ติดตั้งระเบิดมือ GravNet กดยิงเพื่อขว้าง กดโหมดยิงเสริมเพื่อโยนออกไปในระยะสั้น ๆ GravNet จะระเบิดทันทีที่ตกถึงพื้น ส่งผลให้ตัวละครที่อยู่ในรัศมีต้องย่อลงและเคลื่อนที่อย่างเชื่องช้า","tr-TR":"Bir NanoÇekim bombası KUŞAN. Fırlatmak için ATEŞ ET. Yavaşça fırlatmak için ALT. ATIŞ kullan. NanoÇekim bombası yere temas ettiğinde patlayarak etki alanında kalanların çömelmelerine neden olur ve onları yavaşlatır.","vi-VN":"TRANG BỊ một quả lựu đạn Lưới Trọng Lực. BẮN để ném. BẮN PHỤ để ném cao. Lưới Trọng Lực sẽ phát nổ khi chạm đất, khiến mọi nhân vật nào trong tầm ảnh hưởng phải cúi xuống và di chuyển chậm.","zh-CN":"装备重力捕网手雷。按【射击】投掷，按【辅助射击】可轻抛。手雷会在落地后引爆，迫使范围内的角色蹲下，并减慢其移动速度。","zh-TW":"裝備一枚重力網手榴彈。點擊「攻擊」即可投出。點擊「輔助攻擊」可低手拋出。重力網一落地就會引爆，迫使所有被網住的角色蹲下並緩速。"}'::jsonb, '"https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, 'Ultimate', '{"es-MX":"Aniquilación","ar-AE":"الإبادة","es-ES":"Aniquilación","ja-JP":"アナイアレーション","it-IT":"Annientamento","de-DE":"Annihilation","id-ID":"Annihilation","ko-KR":"소멸","fr-FR":"Annihilation","en-US":"Annihilation","pl-PL":"Anihilacja","pt-BR":"Aniquilação","ru-RU":"Аннигиляция","th-TH":"Annihilation","tr-TR":"KISKIVRAK","vi-VN":"Tuyệt Diệt","zh-CN":"断魂索道","zh-TW":"在繭難逃"}'::jsonb, '{"es-MX":"EQUIPA un Acelerador de Nanocables. DISPARA para liberar un pulso de nanocables que capturan al primer enemigo con el que entren en contacto. El enemigo atrapado es arrastrado por un sendero de nanocables y morirá, a menos que se libere antes. El capullo de nanocables puede ser destruido.","ar-AE":"تجهّز بمُسرّع أسلاك نانو. أطلق لتحرير موجة من أسلاك النانو التي تحتجز أول عدو تلامسه. يتم سحب العدو المحتجز على طول مسار أسلاك النانو ويموت ما لم يتم تحريره. شرنقة أسلاك النانو قابلة للتدمير.","es-ES":"EQUIPA un acelerador de nanocables. DISPARA para emitir un pulso de nanocables que capturan al primer enemigo con el que entran en contacto. El enemigo atrapado se ve arrastrado y muere, a menos que sea liberado. La envoltura de los nanocables se puede destruir.","ja-JP":"ナノワイヤーアクセラレーターを構える。「発射」でナノワイヤーを放ち、最初に命中した敵を捕らえる。コクーン化された敵はナノワイヤーを伝って手繰り寄せられ、解放されなければデスに至る。ナノワイヤーのコクーンは破壊可能。","it-IT":"EQUIPAGGIA un acceleratore di nanofilo. Usa il FUOCO per emettere un impulso di nanofili che intrappola in un bozzolo il primo nemico con cui entra a contatto. Il nemico intrappolato viene trascinato lungo un tracciato di nanofili e muore, a meno che non venga liberato in tempo. Il bozzolo di nanofilo è distruttibile.","de-DE":"RÜSTE einen Nanodrahtbeschleuniger AUS. FEUERE, um einen Impuls aus Nanodrähten auszulösen, der den ersten Gegner, der ihn berührt, einfängt. Der gefangene Gegner wird entlang eines Nanodraht-Pfades gezogen und stirbt, es sei denn, er wird befreit. Der Nanodraht-Kokon ist zerstörbar.","id-ID":"EQUIP Nanowire Accelerator. Tekan FIRE untuk melepaskan gelombang nanowire yang menangkap musuh pertama yang bersinggungan. Musuh yang terlilit ditarik sepanjang jalur nanowire dan akan mati, kecuali mereka dibebaskan. Lilitan nanowire dapat dihancurkan.","ko-KR":"나노와이어 가속기를 장착합니다. 발사하면 처음 적중한 적을 생포하는 나노와이어 펄스를 발사합니다. 생포된 적은 나노와이어의 경로를 따라 끌려가며, 풀려나지 않으면 사망합니다. 나노와이어 고치는 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous de l''Accélérateur de nanocâbles. TIREZ pour envoyer une salve de nanocâbles qui captureront le premier ennemi touché. L''ennemi ainsi emmailloté sera attiré en ligne droite et mourra à moins d''être libéré. Le cocon de nanocâbles est destructible.","en-US":"EQUIP a Nanowire Accelerator. FIRE to unleash a pulse of nanowires that captures the first enemy contacted. The cocooned enemy is pulled along a nanowire path and will die unless they are freed. The nanowire cocoon is destructible.","pl-PL":"WYPOSAŻ akcelerator nanoobwodów. STRZEL, aby uwolnić impuls nanoobwodów łapiący pierwszego wroga, z którym wejdzie w kontakt. Wróg zostaje otoczony kokonem i jest ciągnięty wzdłuż ścieżki nanoobwodów. Zginie, chyba że zostanie wcześniej uwolniony. Kokon nanoobwodów można zniszczyć.","pt-BR":"EQUIPE um Acelerador de Nanofios. DISPARE para liberar um pulso de nanofios que captura o primeiro inimigo que encontrar. O inimigo encasulado é puxado por uma trilha de nanofios e abatido, a não ser que seja libertado. O casulo de nanofios é destrutível.","ru-RU":"Выбирает нанопроводниковый ускоритель. Нажмите ОГОНЬ, чтобы выпустить нанопроводники и захватить первого противника, с которым они столкнутся. Кокон с захваченным агентом перемещается по нанопроводникам. Если его не разрушить, противник умрет.","th-TH":"ติดตั้ง Nanowire Accelerator กดยิงเพื่อปล่อยกลุ่มเส้นลวดนาโนที่จะพันรัดตัวศัตรูคนแรกที่สัมผัสถูก ศัตรูที่ถูกเส้นลวดนาโนมัดรอบตัวจะถูกลากไปตามทางของเส้นลวดนาโน และจะตายเว้นแต่ว่าจะได้รับการช่วยเหลือ เส้นลวดนาโนที่พันรอบตัวศัตรูถูกทำลายได้","tr-TR":"Bir Nanobağ Hızlandırıcı KUŞAN. Yakaladığı ilk düşmanı sarıp kıskıvrak yakalayan bir nanobağ dalgası göndermek için ATEŞ ET. Kozaya yakalanan düşman, oluşan nanobağ yolu boyunca çekilir. Düşman, nanobağ kozasından kurtarılmazsa ölür. Nanobağ kozası yok edilebilir.","vi-VN":"TRANG BỊ 1 Máy Bắn Dây Nano Siêu Tốc. Nhấn BẮN để phóng ra một loạt dây nano và trói kẻ địch đầu tiên chạm vào. Kẻ địch bị trói sẽ bị kéo về hướng dây nano phóng ra và sẽ bị hạ gục nếu không được giải thoát. Kén trói bằng dây nano có thể bị phá hủy.","zh-CN":"装备纳米纤维加速器。按【射击】发出一道纳米纤维脉冲波，把命中的首个敌人包裹在茧里，并拖拽目标沿一条索道移动。如果敌人未获得解救，则直接被击败。纳米纤维茧可被摧毁。","zh-TW":"裝備一個奈米線加速器。點擊「攻擊」射出大量奈米線，捕捉第一位碰到的敵人。敵人被困住後會沿著奈米線路徑被拖行，如不設法脫困就會死亡。奈米繭可被破壞。"}'::jsonb, '"https://media.valorant-api.com/agents/cc8b64c8-4b25-4ff9-6e7f-37b4da43d235/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('cc8b64c8-4b25-4ff9-6e7f-37b4da43d235'::uuid, 200000, '2023-06-27T00:00:00Z'::timestamp with time zone, '2023-07-25T21:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, '{"es-MX":"Tejo","ar-AE":"تيهو","es-ES":"Tejo","ja-JP":"テホ","it-IT":"Tejo","de-DE":"Tejo","id-ID":"Tejo","ko-KR":"테호","fr-FR":"Tejo","en-US":"Tejo","pl-PL":"Tejo","pt-BR":"Tejo","ru-RU":"Tejo","th-TH":"Tejo","tr-TR":"TEJO","vi-VN":"Tejo","zh-CN":"钛狐","zh-TW":"戴侯"}'::jsonb, '{"es-MX":"Tejo es un consultor de inteligencia veterano proveniente de Colombia. Su sistema de guía balística presiona al enemigo para que renuncie a su territorio... o a su vida. Sus ataques dirigidos mantienen a sus oponentes fuera de balance y bajo control.","ar-AE":"تيهو مستشار استخبارات مخضرم من كولومبيا، يستخدم نظام التوجيه الباليستي للضغط على العدو كي يتخلى عن مواقعه، وإلا فالموت مصيره. كما تبقي ضرباته الموجهة الخصومَ في حالة من عدم التوازن وتحت سيطرته.","es-ES":"Tejo, un consultor de inteligencia veterano de Colombia, controla un sistema de guiado balístico que obliga a sus enemigos a decidir entre renunciar a su posición... o a sus vidas. Sus ataques dirigidos pondrán en jaque a sus contrincantes y los dejará a su merced.","ja-JP":"テホはコロンビア出身の退役軍人であり、諜報コンサルタントだ。彼の弾道誘導システムは敵に陣地を明け渡すか、または命を差し出すかの選択を迫る。その精密な攻撃は敵を揺るがし、彼の狙いのもとに押さえ込む。","it-IT":"Esperto consulente di intelligence proveniente dalla Colombia, Tejo sfrutta un sistema missilistico guidato per costringere i nemici a cedere terreno... o a cedere le proprie vite. I suoi bombardamenti mirati non danno tregua agli avversari e gli permettono di tenerli in pugno.","de-DE":"Tejo ist ein kolumbianischer Aufklärungsveteran und besitzt ein ballistisches Leitsystem, mit dem er Gegner dazu zwingt, ihre Stellung aufzugeben … oder sie mit ihrem Leben zu verteidigen. Seine zielgenauen Angriffe bringen Gegner ständig aus dem Konzept und lassen sie nicht zur Ruhe kommen.","id-ID":"Seorang konsultan intelijen veteran dari Kolombia, Tejo, bersama sistem pemandu balistiknya menekan musuh untuk menyerahkan wilayah mereka—atau nyawa mereka. Serangannya yang terarah terus membuat lawannya kocar-kacir dan berada di bawah kendalinya.","ko-KR":"콜롬비아 출신의 베테랑 정보 자문가인 테호는 탄도 유도 시스템을 이용해 적이 위치나 목숨을 포기하도록 압박합니다. 테호의 표적 공격은 상대의 균형을 무너뜨리고 완전히 통제합니다.","fr-FR":"Originaire de Colombie, Tejo est un conseiller vétéran dans le domaine du renseignement. Son système de guidage balistique force les ennemis à perdre du terrain, voire la vie. Ses frappes chirurgicales lui permettent de garder les ennemis sous son emprise.","en-US":"A veteran intelligence consultant from Colombia, Tejo’s ballistic guidance system pressures the enemy to relinquish their ground - or their lives. His targeted strikes keep opponents off balance and under his heel.","pl-PL":"Tejo, doświadczony konsultant wywiadowczy z Kolumbii, za pomocą swojego balistycznego systemu naprowadzania wymusza na wrogu wycofanie się z zajmowanego terenu, jeśli ten ceni sobie swoje życie. Jego namierzane ataki zaburzają szyk przeciwnika, zapewniając mu przewagę.","pt-BR":"Consultor de inteligência veterano da Colômbia, Tejo conta com um sistema de orientação balística que força o inimigo a abrir mão da posição — ou da própria vida. Os ataques precisos dele mantêm os oponentes desestabilizados e sob seu controle.","ru-RU":"Tejo – бывалый разведчик-эксперт из Колумбии. Используемая им система наведения огня вынуждает врагов сдавать позиции – или прощаться с жизнью. Его прицельные ракетные удары застигают противника врасплох и заставляют пластаться по земле.","th-TH":"Tejo ที่ปรึกษาข่าวกรองมากประสบการณ์จากโคลอมเบีย จะใช้ระบบนำทางขีปนาวุธกดดันให้ศัตรูต้องเลือกว่าจะทิ้งพื้นที่หรือชีวิตของตัวเอง การโจมตีแบบเจาะจงเป้าหมายของเขาจะทำให้คู่ต่อสู้ปั่นป่วนและไม่อาจขัดขืน","tr-TR":"Kolombiyalı deneyimli istihbarat danışmanı Tejo''nun balistik güdüm sistemi düşmanları oldukları yerden çıkmaya veya canlarını vermeye zorlar. İsabetli saldırıları sayesinde Tejo rakiplerinin dengesini bozar ve onlara karşı üstünlük kurar.","vi-VN":"Một nhà tư vấn tình báo kỳ cựu từ Colombia, hệ thống đạn đạo tự tìm đường của Tejo gây áp lực buộc kẻ thù phải từ bỏ vị trí, hoặc mạng sống của chúng. Các đợt công kích nhắm mục tiêu của hắn khiến đối thủ mất cân bằng và bị kiểm soát hoàn toàn.","zh-CN":"“钛狐”是来自南美洲的资深情报顾问。他的弹道制导系统可以向敌人施压，迫使其做出选择——要么放弃阵地，要么放弃生命。受到精准打击后，对手往往会失去平衡，被他轻易击败。","zh-TW":"「戴侯」是來自哥倫比亞的資深情報顧問，他的彈道導引系統能迫使敵人放棄陣地……甚或賠上性命。他的精確打擊能讓對手陷入混亂，臣服於他的掌控之下。"}'::jsonb, 'Cashew', '2025-01-08T22:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/displayicon.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/displayicon.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/fullportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/fullportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/fullportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/killfeedportrait.png', 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/minimapportrait.png', null, 'https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/background.png', array['80451bff', '0f1923ff', 'ffffffff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, 'Ability2', '{"es-MX":"Misiles Crucero","ar-AE":"الوابل الموجّه","es-ES":"Descarga guiada","ja-JP":"誘導サルヴォ","it-IT":"Salva guidata","de-DE":"Gelenkte Salve","id-ID":"Guided Salvo","ko-KR":"유도 일제 사격","fr-FR":"Salve autoguidée","en-US":"Guided Salvo","pl-PL":"Salwa Naprowadzana","pt-BR":"Rajada Guiada","ru-RU":"Управляемый залп","th-TH":"Guided Salvo","tr-TR":"GÜDÜMLÜ SALVO","vi-VN":"Tên Lửa Tìm Đường","zh-CN":"精准投放","zh-TW":"導引轟炸"}'::jsonb, '{"es-MX":"EQUIPA un sistema de apuntado con RA. DISPARA para seleccionar hasta dos ubicaciones de objetivos en el mapa. Usa el DISPARO SECUNDARIO para lanzar misiles que navegan de forma automática hacia ubicaciones objetivo y detonan varias veces al aterrizar e infligen daño.","ar-AE":"تجهّز بنظام استهداف بنمط الواقع المعزز. أطلق لاختيار موقعين مستهدفين على الخريطة كحد أقصى. اضغط على زر الإطلاق البديل لإطلاق الصواريخ التي تتجه بصورة مستقلة إلى المواقع المستهدفة، وتنفجر بشكل متكرر لإلحاق الضرر عند وصولها.","es-ES":"EQUIPA un sistema de rastreo de realidad aumentada. DISPARA para seleccionar hasta dos ubicaciones objetivo en el mapa. Utiliza el DISPARO ALTERNATIVO para lanzar misiles que se dirigirán automáticamente a las ubicaciones seleccionadas y detonarán repetidamente al impactar en el objetivo, infligiéndole daño.","ja-JP":"AR ターゲットシステムを構える。「発射」でマップ上に最大2つの地点を指定し、オルト射撃でミサイルを発射する。ミサイルは指定地点まで自動誘導され、着弾すると複数回爆発してダメージを与える。","it-IT":"EQUIPAGGIA un sistema di puntamento basato sulla realtà aumentata. Usa il FUOCO per selezionare fino a due posizioni sulla mappa. Usa il FUOCO ALTERNATIVO per sparare missili che viaggiano autonomamente verso le posizioni bersaglio ed esplodono ripetutamente all''arrivo infliggendo danni.","de-DE":"RÜSTE ein AR-Zielsystem AUS. FEUERE, um bis zu zwei Ziele auf der Karte auszuwählen. Feuere die Raketen mit ALT. FEUERMODUS ab. Die Raketen fliegen automatisch zum Zielgebiet und fügen bei der Ankunft mit wiederholten Explosionen Schaden zu.","id-ID":"EQUIP sistem penarget dengan bantuan AR. Tekan FIRE untuk memilih hingga dua lokasi target di map. Tekan ALT FIRE untuk meluncurkan misil yang bergerak sendiri ke lokasi target, meledak berulang kali dan menimbulkan damage saat mendarat.","ko-KR":"AR 표적 조준 시스템을 장착합니다. 발사하면 맵에서 위치를 최대 2곳 지정합니다. 보조 공격 시 지정 위치로 자율 비행해 여러 차례 폭발하는 미사일을 발사합니다.","fr-FR":"ÉQUIPEZ-vous d''un système de ciblage en réalité augmentée. TIREZ pour cibler jusqu''à deux positions sur la carte. Utilisez le TIR SECONDAIRE pour lancer des missiles autonomes qui iront jusqu''aux positions ciblées et exploseront de manière répétée pour infliger des dégâts à l''arrivée.","en-US":"EQUIP an AR targeting system. FIRE to select up to two target locations on the map. ALT FIRE to launch missiles that autonomously navigate to target locations, detonating repeatedly for damage on arrival.","pl-PL":"WYPOSAŻ system obierania za cel korzystający z RR. STRZEL, by wybrać do dwóch miejsc docelowych na mapie. ALT. STRZAŁ wystrzeliwuje pociski, które samodzielnie kierują się w stronę miejsc docelowych, a po dotarciu wielokrotnie wybuchają, zadając obrażenia.","pt-BR":"EQUIPE um mapa tático. DISPARE para selecionar até dois locais-alvo no mapa. Use o DISPARO ALTERNATIVO para lançar projéteis que viajam de forma autônoma até os locais-alvo e detonam repetidamente e causam dano.","ru-RU":"Выбирает систему прицеливания на базе дополненной реальности. Нажмите кнопку ОГОНЬ, чтобы выбрать до двух мест на карте. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы запустить снаряды, которые ищут цели в автономном режиме, несколько раз взрываясь и нанося урон по их достижении.","th-TH":"ติดตั้งระบบเล็งเป้าหมาย AR กดยิงเพื่อเลือกพื้นที่ที่ต้องการสูงสุดสองจุดบนแผนที่ กดโหมดยิงเสริมเพื่อปล่อยมิสไซล์ที่จะเคลื่อนที่ไปยังตำแหน่งที่ต้องการโดยอัตโนมัติ และระเบิดซ้ำ ๆ เพื่อสร้างความเสียหายเมื่อไปถึง","tr-TR":"Sanal bir hedefleme sistemi KUŞAN. Harita üzerinden en fazla iki hedef konum seçmek için ATEŞ ET. Otomatik olarak hedef konumlara doğru güdümlenen ve hedefe ulaştığında art arda patlayarak hasar veren füzeler atmak için ALT. ATIŞ kullan.","vi-VN":"TRANG BỊ một hệ thống nhắm mục tiêu thực tế ảo (AR). BẮN để chọn tối đa 2 vị trí mục tiêu trên bản đồ. BẮN PHỤ để phóng tên lửa tự động tìm đường đến vị trí mục tiêu, phát nổ liên tục để gây sát thương khi đến nơi.","zh-CN":"装备一套战术投送系统。按【射击】在地图上最多选择两个目标位置。按【辅助射击】发射导弹，导弹可自动导航至目标位置，到达时多次引爆，造成伤害。","zh-TW":"裝備一個AR瞄準系統。點擊「攻擊」在地圖上選擇最多兩個目標地點。點擊「輔助攻擊」發射自動導向飛彈，飛彈會射到目標地點然後多次引爆造成傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, 'Ability1', '{"es-MX":"Entrega Especial","ar-AE":"طرد خاص","es-ES":"Envío especial","ja-JP":"スペシャルデリバリー","it-IT":"Consegna speciale","de-DE":"Sonderzustellung","id-ID":"Special Delivery","ko-KR":"특별 배송","fr-FR":"Livraison spéciale","en-US":"Special Delivery","pl-PL":"Przesyłka Specjalna","pt-BR":"Entrega Especial","ru-RU":"Спецпоставка","th-TH":"Special Delivery","tr-TR":"ÖZEL TESLİMAT","vi-VN":"Gói Hàng Đặc Biệt","zh-CN":"特快专递","zh-TW":"限時快遞"}'::jsonb, '{"es-MX":"EQUIPA una granada pegajosa. DISPARA para lanzarla. La granada se adhiere a la primera superficie que toca y explota, lo que conmociona y daña a los objetivos atrapados en la explosión. Usa el DISPARO SECUNDARIO para lanzar la granada con un solo rebote.","ar-AE":"تجهّز بقنبلة لاصقة. أطلق لرميها. تلتصق القنبلة بأول سطح تصطدم به وتنفجر، مما يؤدي إلى ارتجاج وإلحاق الضرر بأي هدف يقع في نطاق الانفجار. اضغط على زر الإطلاق البديل لرمي القنبلة بارتداد واحد بدلًا عما سبق.","es-ES":"EQUIPA una granada adherente. DISPARA para lanzarla. La granada se quedará pegada a la primera superficie que golpee y explotará, lo que conmocionará e infligirá daño a cualquier objetivo que se encuentre a su alcance. Utiliza el DISPARO ALTERNATIVO para que la granada rebote una sola vez.","ja-JP":"スティッキーグレネードを構える。「発射」で射出する。グレネードは最初に触れた面に貼りついて爆発し、爆風に巻き込んだすべての敵をスタンさせてダメージを与える。オルト射撃の場合はグレネードが1回バウンドしてから貼りつく。","it-IT":"EQUIPAGGIA una granata appiccicosa. Usa il FUOCO per lanciarla. La granata si appiccica alla prima superficie colpita ed esplode, STORDENDO e danneggiando qualsiasi bersaglio investito dall''esplosione. Usa il FUOCO ALTERNATIVO per lanciare la granata con un rimbalzo singolo.","de-DE":"RÜSTE eine Haftgranate AUS. FEUERE, um zu werfen. Die Granate bleibt an Oberflächen haften und explodiert. Die Explosion betäubt Ziele im Explosionsradius und fügt ihnen Schaden zu. Wirf die Granate mit ALT. FEUERMODUS, damit sie einmal abprallt.","id-ID":"GUNAKAN granat lengket. Tekan FIRE untuk meluncurkan. Granat akan menempel pada permukaan pertama yang terkena kontak. Granat itu kemudian meledak dan memberikan damage pada target yang terjebak dalam ledakan. Tekan ALT FIRE untuk meluncurkan granat dengan satu pantulan.","ko-KR":"점착 유탄을 장착합니다. 발사하면 쏩니다. 유탄은 처음 적중한 표면에 붙어 폭발하며, 폭발 반경 내의 모든 대상에게 피해를 입히고 뇌진탕을 일으킵니다. 보조 공격 시 한 번 튕기는 유탄을 쏩니다.","fr-FR":"ÉQUIPEZ-vous d''une grenade adhésive. TIREZ pour la lancer. La grenade se colle à la première surface touchée et explose, désorientant les cibles touchées et leur infligeant des dégâts. Le TIR SECONDAIRE permet de lancer la grenade en la faisant rebondir une fois.","en-US":"EQUIP a sticky grenade. FIRE to launch. The grenade sticks to the first surface it hits and explodes, Concussing and dealing damage to any targets caught in the blast. ALT FIRE to launch the grenade with a single bounce instead.","pl-PL":"WYPOSAŻ lepki granat. STRZEL, by nim rzucić. Granat przylepia się do pierwszej trafionej powierzchni i eksploduje, ogłuszając każdy cel, który znajdzie się w promieniu wybuchu, i zadając mu obrażenia. ALT. STRZAŁ wyrzuca granat, który odbije się jeden raz.","pt-BR":"EQUIPE uma granada adesiva. DISPARE para lançar. A granada gruda na primeira superfície atingida e explode, causando Concussão e dano a qualquer alvo atingido pela explosão. Use o DISPARO ALTERNATIVO para lançar a granada com um ricochete.","ru-RU":"Выбирает липкую гранату. Нажмите кнопку ОГОНЬ, чтобы запустить ее. Как только граната касается какой-либо поверхности, она прилипает и взрывается, оглушая все цели, задетые взрывом, и нанося им урон. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы запустить гранату с одним отскоком.","th-TH":"ติดตั้งระเบิดเหนียว กดยิงเพื่อปล่อยออกไป ระเบิดจะเกาะติดพื้นผิวแรกที่โดนและระเบิดออก ทำให้เป้าหมายที่โดนระเบิดติดสถานะกระทบกระเทือน กดโหมดยิงเสริมเพื่อปล่อยระเบิดให้เด้งหนึ่งครั้งแทน","tr-TR":"Bir yapışkan bomba KUŞAN. Fırlatmak için ATEŞ ET. Bomba değdiği ilk yüzeye yapışır ve patlar. Patlamadan etkilenen tüm hedefler hasar alır ve Sersemler. Bombayı bir kere sekecek şekilde fırlatmak için ALT. ATIŞ kullan.","vi-VN":"TRANG BỊ 1 lựu đạn bám dính. BẮN để quăng. Lựu đạn sẽ bám dính vào bề mặt đầu tiên chạm vào và phát nổ, Làm Choáng và gây sát thương lên tất cả mục tiêu trúng phải vụ nổ. BẮN PHỤ để quăng lựu đạn với một lần nảy.","zh-CN":"装备一颗粘性榴弹，按【射击】发射。榴弹会粘附击中的首个表面并爆炸，被爆炸波及的所有目标都会受到震荡和伤害。按【辅助射击】发射榴弹时，榴弹会在反弹一次后爆炸。","zh-TW":"裝備一顆黏性手榴彈。點擊「攻擊」發射。手榴彈會吸附在第一個碰到的表面上並爆炸，對爆炸範圍內所有目標造成傷害及暈眩效果。點擊「輔助攻擊」則可發射能彈跳一次的手榴彈。"}'::jsonb, '"https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, 'Ultimate', '{"es-MX":"Armagedón","ar-AE":"المعركة الفاصلة","es-ES":"Armagedón","ja-JP":"アルマゲドン","it-IT":"Armageddon","de-DE":"Der Jüngste Tag","id-ID":"Armageddon","ko-KR":"아마겟돈","fr-FR":"Apocalypse","en-US":"Armageddon","pl-PL":"Armagedon","pt-BR":"Armagedom","ru-RU":"Армагеддон","th-TH":"Armageddon","tr-TR":"KIYAMET","vi-VN":"Đòn Quyết Định","zh-CN":"末日审判","zh-TW":"末日審判"}'::jsonb, '{"es-MX":"EQUIPA un mapa de fijación de objetivo de ataque táctico. DISPARA para seleccionar el punto de origen del ataque. DISPARA de nuevo para fijar el punto final y lanzar el ataque con el fin de liberar una ola de explosiones que infligen daño letal a lo largo de la trayectoria del ataque. Usa el DISPARO SECUNDARIO durante la fijación de objetivo del mapa para cancelar el punto de origen.","ar-AE":"تجهّز بخريطة استهداف ضربات تكتيكية. أطلق لتحديد موقع انطلاق الضربة. أطلق مرة أخرى لتحديد نقطة الهدف ثم ابدأ الهجوم، مما يؤدي إلى إطلاق موجة من انفجارات الضرر الفتاك على طول مسار الضربة. استخدم الإطلاق البديل أثناء الاستهداف على الخريطة لإلغاء مصدر الضربة.","es-ES":"EQUIPA un mapa táctico de objetivos de ataque. DISPARA para seleccionar el punto de origen del ataque. Vuelve a DISPARAR para seleccionar la ubicación final y lanzar el ataque. Una oleada de explosiones de daño letal recorrerá el itinerario establecido. Utiliza el DISPARO ALTERNATIVO mientras estés configurando el ataque para cancelar el punto de origen.","ja-JP":"攻撃エリアを指定するマップを開く。「発射」で攻撃の起点を指定する。再度「発射」すると終点を選択して攻撃を開始し、指定した線上に高威力の爆発が連続して生じる。「オルト射撃」でマップでの起点の指定をキャンセルする。","it-IT":"EQUIPAGGIA una mappa tattica per il bombardamento a tappeto. Usa il FUOCO per selezionare il punto d''origine dell''attacco. Usa di nuovo il FUOCO per stabilire il punto di destinazione e lanciare l''attacco, scatenando un''ondata di esplosioni letali lungo il percorso. Usa il FUOCO ALTERNATIVO durante il puntamento sulla mappa per annullare il punto d''origine.","de-DE":"RÜSTE eine Anvisierungskarte für taktischen Beschuss AUS. FEUERE, um den Ausgangspunkt des Beschusses zu bestimmen. FEUERE erneut, um den Endpunkt zu bestimmen und den Angriff zu starten. Der Angriff verursacht viele Explosionen entlang des Angriffspfads, die tödlichen Schaden verursachen. Mit ALT. FEUERMODUS während des Zielens auf der Karte brichst du die Ausgangspunktauswahl ab.","id-ID":"EQUIP map taktis yang menarget serangan. Tekan FIRE untuk memilih titik awal serangan. Tekan FIRE lagi untuk menetapkan titik akhir dan meluncurkan serangan, melepaskan gelombang ledakan mematikan di sepanjang jalur serangan. Tekan ALT FIRE selama penargetan map untuk membatalkan titik awal.","ko-KR":"전술 타격 위치 지도를 장착합니다. 발사하면 공습의 첫 지점을 선택합니다. 다시 발사하면 끝 지점을 정하고 공격을 시작하여 공습 경로를 따라 일련의 치명적인 피해를 입히는 폭발을 일으킵니다. 위치 지정 중 보조 공격 시 첫 지점을 취소합니다.","fr-FR":"ÉQUIPEZ-vous d''une carte tactique. TIREZ pour sélectionner le point d''origine de la frappe. TIREZ à nouveau pour définir le point d''arrivée et lancer l''attaque, ce qui provoque une série d''explosions aux dégâts mortels sur la ligne ainsi tracée. Utilisez le TIR SECONDAIRE pendant le ciblage pour annuler le point d''origine.","en-US":"EQUIP a tactical strike targeting map. FIRE to select the origin point of the strike. FIRE again to set the end point and launch the attack, unleashing a wave of lethal damaging explosions along the strike path. ALT FIRE during map targeting to cancel the origin point.","pl-PL":"WYPOSAŻ mapę do oznaczania uderzeń taktycznych. STRZEL, aby wybrać punkt początkowy uderzenia. STRZEL ponownie, aby określić punkt końcowy i rozpocząć atak, uwalniając wzdłuż wyznaczonej ścieżki falę eksplozji zadających zabójcze obrażenia. ALT. STRZAŁ podczas oznaczania na mapie anuluje punkt początkowy.","pt-BR":"EQUIPE um mapa tático para selecionar o alvo do ataque. DISPARE para selecionar o ponto de origem do ataque. DISPARE novamente para definir o ponto final e lançar o ataque, que libera uma onda de explosões letais ao longo do trecho determinado. Use o DISPARO ALTERNATIVO durante o mapeamento para cancelar o ponto de origem.","ru-RU":"Выбирает карту целей для тактического удара. Нажмите кнопку ОГОНЬ, чтобы указать точку запуска. Нажмите кнопку ОГОНЬ еще раз, чтобы указать точку поражения и инициировать атаку, запустив цепь смертоносных взрывов по маршруту удара. При нажатии кнопки АЛЬТ. ОГОНЬ в режиме карты целей точка запуска сбрасывается.","th-TH":"ติดตั้งแผนที่เล็งเป้าสกิลสำหรับการโจมตีเชิงยุทธวิธี กดยิงเพื่อเลือกจุดเริ่มต้นของการโจมตี ยิงอีกครั้งเพื่อกำหนดจุดสิ้นสุดและเปิดฉากการโจมตี โดยปล่อยระเบิดที่สร้างความเสียหายถึงตายเป็นระลอกไปตามเส้นทางการโจมตี กดโหมดยิงเสริมขณะใช้แผนที่เล็งเป้าสกิลเพื่อยกเลิกจุดเริ่มต้น","tr-TR":"Bir taktiksel saldırı hedefleme haritası KUŞAN. Saldırının başlangıç noktasını seçmek için ATEŞ ET. Saldırının biteceği noktayı da seçip saldırıyı başlatmak için tekrar ATEŞ ET ve seçilen rota boyunca ilerleyerek ölümcül hasar veren patlama dalgaları gönder. Harita hedeflemesi esnasında başlangıç noktasını iptal etmek için ALT. ATIŞ kullan.","vi-VN":"TRANG BỊ một bản đồ chiến thuật chọn mục tiêu. BẮN để chọn điểm khởi đầu. BẮN lần nữa để chọn điểm cuối và phát động tấn công, giải phóng một đợt sóng chất nổ gây sát thương cao chạy dọc đường công kích. BẮN PHỤ trong khi chọn mục tiêu trên bản đồ để hủy điểm khởi đầu.","zh-CN":"装备战术打击地图。按【射击】选择打击起点。【再次按射击键】设置终点并发动无人机空袭，沿所选路径进行地毯式爆破，造成致命伤害。在地图瞄准期间按【辅助射击】可取消起点设置。","zh-TW":"裝備一個鎖定戰術打擊地點的地圖。點擊「攻擊」選擇攻擊的起始點。再次點擊「攻擊」設定終點並發動攻擊，沿著打擊路徑造成一波致命爆炸傷害。使用地圖鎖定地點時，點擊「輔助攻擊」取消攻擊起始點。"}'::jsonb, '"https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, 'Grenade', '{"es-MX":"Dron Furtivo","ar-AE":"الدرون الشبحية","es-ES":"Dron de sigilo","ja-JP":"ステルスドローン","it-IT":"Drone invisibile","de-DE":"Tarndrohne","id-ID":"Stealth Drone","ko-KR":"잠입 드론","fr-FR":"Drone furtif","en-US":"Stealth Drone","pl-PL":"Skrytodron","pt-BR":"Drone Furtivo","ru-RU":"Стелс-дрон","th-TH":"Stealth Drone","tr-TR":"GİZLİ DRON","vi-VN":"Drone Tàng Hình","zh-CN":"潜袭爬虫","zh-TW":"匿蹤無人機"}'::jsonb, '{"es-MX":"EQUIPA un dron de sigilo. DISPARA para lanzar el dron hacia adelante y asumir el control directo de su movimiento. DISPARA de nuevo para activar un pulso que suprime y revela a los enemigos impactados.","ar-AE":"تجهّز بدرون شبحية. أطلق لرمي الدرون إلى الأمام وسيطر على حركتها مباشرة. أطلق مرة أخرى لتفعيل نبضة تقمع وتكشف الأعداء المصابين.","es-ES":"EQUIPA un dron de sigilo. DISPARA para lanzar el dron hacia delante y controlar sus movimientos. Vuelve a DISPARAR para activar un pulso que suprime y revela a los enemigos alcanzados.","ja-JP":"ステルスドローンを構える。「発射」でドローンを前方に射出し、その動きを直接操作できる。もう一度「発射」を押すとパルスが発動し、命中した敵のアビリティーを抑制して位置を特定する。","it-IT":"EQUIPAGGIA un drone invisibile. Usa il FUOCO per lanciare il drone in avanti, assumendo il controllo diretto dei suoi movimenti. Usa di nuovo il FUOCO per attivare un impulso che SOPPRIME e RIVELA i nemici colpiti.","de-DE":"RÜSTE eine Tarndrohne AUS. FEUERE, um die Drohne vorwärts zuwerfen. Die Drohne steuerst du daraufhin direkt. FEUERE erneut, um einen Impuls auszulösen, der getroffene Gegner unterdrückt und aufdeckt.","id-ID":"EQUIP stealth drone. Tekan FIRE untuk melempar drone ke depan, dan kendalikan gerakannya secara langsung. Tekan FIRE lagi untuk memicu denyutan yang menerapkan utilitas Suppress dan mengungkap musuh yang terkena.","ko-KR":"잠입 드론을 장착합니다. 발사하면 드론을 앞으로 던져 움직임을 제어합니다. 다시 발사하면 적중한 적을 모두 제압하고 위치를 드러내는 파동을 발동합니다.","fr-FR":"ÉQUIPEZ-vous d''un drone furtif. TIREZ pour lancer le drone vers l''avant et en prendre le contrôle. TIREZ à nouveau pour déclencher une impulsion qui neutralise et révèle les ennemis touchés.","en-US":"EQUIP a stealth drone. FIRE to throw the drone forward, assuming direct control of its movement. FIRE again to trigger a pulse that Suppresses and Reveals enemies hit.","pl-PL":"WYPOSAŻ maskującego się drona. STRZEL, by cisnąć dronem w przód i przejąć bezpośrednią kontrolę nad nim. STRZEL ponownie, aby aktywować puls, który tłumi i ujawnia trafionych wrogów.","pt-BR":"EQUIPE um drone furtivo. DISPARE para lançar o drone e assumir o controle dos movimentos dele. DISPARE novamente para acionar um pulso que causa Supressão e Revela os inimigos atingidos.","ru-RU":"Выбирает стелс-дрон. Нажмите кнопку ОГОНЬ, чтобы отправить дрон вперед, взяв на себя управление его перемещениями. Нажмите кнопку ОГОНЬ еще раз, чтобы активировать пульсацию, которая подавляет и обнаруживает пораженных ею врагов.","th-TH":"ติดตั้งโดรนล่องหน กดยิงเพื่อขว้างโดรนไปข้างหน้า และควบคุมการเคลื่อนที่ของโดรนโดยตรง ยิงอีกครั้งเพื่อปลดปล่อยคลื่นพลังที่จะยับยั้งพลังและเปิดเผยตำแหน่งของศัตรูที่โดน","tr-TR":"Gizli bir dron KUŞAN. Dronu ileri doğru fırlatıp hareketlerini kontrol etmeye başlamak için ATEŞ ET. İsabet alan düşmanları Sindiren ve Açığa Çıkaran bir dalga göndermek için tekrar ATEŞ ET.","vi-VN":"TRANG BỊ một chiếc drone tàng hình. BẮN để ném drone về phía trước, trực tiếp điều khiển hướng di chuyển của nó. BẮN lần nữa để kích hoạt xung nhịp gây Áp Chế và Lộ Diện những kẻ địch trúng phải.","zh-CN":"装备一架潜袭爬虫，按【射击】将爬虫抛向前方，直接控制其移动。再次按【射击】可触发脉冲，压制并揭露被击中的敌人。","zh-TW":"裝備一架匿蹤無人機。點擊「攻擊」向前拋出無人機，直接控制它移動。再次點擊「攻擊」觸發能量波，被擊中的敵人會遭到抑制並揭露行蹤。"}'::jsonb, '"https://media.valorant-api.com/agents/b444168c-4e35-8076-db47-ef9bf368f384/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('b444168c-4e35-8076-db47-ef9bf368f384'::uuid, 200000, '2025-01-08T22:00:00Z'::timestamp with time zone, '2025-02-05T22:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('f94c3b30-42be-e959-889c-5aa313dba261'::uuid, '{"es-MX":"Raze","ar-AE":"رايز","es-ES":"Raze","ja-JP":"レイズ","it-IT":"Raze","de-DE":"Raze","id-ID":"Raze","ko-KR":"레이즈","fr-FR":"Raze","en-US":"Raze","pl-PL":"Raze","pt-BR":"Raze","ru-RU":"Raze","th-TH":"Raze","tr-TR":"RAZE","vi-VN":"Raze","zh-CN":"雷兹","zh-TW":"芮茲"}'::jsonb, '{"es-MX":"Raze llega de Brasil con su explosiva personalidad y sus grandes armas. Gracias a su contundente estilo de juego, es muy buena para separar a los enemigos atrincherados y para despejar espacios estrechos con una gran cantidad de ''''bum''''.","ar-AE":"أتت رايز بحيوية متفجرة من البرازيل مع تميزها بشخصية قوية وأسلحة كبيرة. أسلوب لعبها المائل إلى ضرب الأعداء عن قرب يجعلها تتفوق في إجبار الأعداء المتحصنين على الخروج من مكامنهم وكذلك في تطهير المساحات الضيقة باستخدام كميات كبيرة من المفرقعات.","es-ES":"Raze llega desde Brasil con ganas de hacer que todo salte por los aires. Con su estilo de juego basado en la fuerza bruta, destaca a la hora de barrer a grupos de enemigos atrincherados y de despejar áreas estrechas con explosión y sin compasión.","ja-JP":"携えたキャノンと持ち前の個性を爆発させるレイズは故郷ブラジルを飛び出した。衝撃力でダメージを与えるスタイルを好む彼女は、「爆発」を惜しみなく使うことで守りを固めている敵を一掃したり、狭い場所をクリアリングすることに長けている。","it-IT":"La personalità della brasiliana Raze è esplosiva tanto quanto le sue armi. Con il suo stile di gioco brutale, è bravissima ad annientare i nemici trincerati e a liberare spazi angusti con una sana dose di \"boom\".","de-DE":"Die explosive Raze bringt eine laute Persönlichkeit und dicke Knarren aus Brasilien mit. Durch ihre brachiale Spielweise ist sie besonders gut darin, Gegner aufzuscheuchen und beengte Räume mit einer großzügigen Portion „Bumm“ zu säubern.","id-ID":"Raze, si eksplosif dari Brasil ini membawa kepribadian yang mencolok serta senjata besarnya. Dengan playstyle-nya yang brutal, Raze unggul dalam menyapu musuh yang berdiam dan mengosongkan ruang sempit dengan ledakan besar.","ko-KR":"브라질에서 온 레이즈는 화끈한 성격으로 커다란 총기를 휘두릅니다. 그녀의 저돌적인 전투 스타일은 엄폐 중인 적을 몰아내는 데 적합하며 대량의 폭발물로 좁은 지역을 초토화합니다.","fr-FR":"Armée de sa personnalité et de sa grosse artillerie, Raze fait une entrée explosive depuis le Brésil. Grâce à sa force brute, elle excelle à débusquer les ennemis retranchés et à faire le ménage dans les espaces étroits, le tout avec une bonne dose de « boum ».","en-US":"Raze explodes out of Brazil with her big personality and big guns. With her blunt-force-trauma playstyle, she excels at flushing entrenched enemies and clearing tight spaces with a generous dose of \"boom.\"","pl-PL":"Raze z Brazylii wkracza na pole walki ze swą wielką osobowością i wielkim arsenałem. Jej wybuchowy styl sprawia, że doskonale radzi sobie z okopanymi wrogami i czyszczeniem niewielkich przestrzeni za pomocą solidnej dawki eksplozji.","pt-BR":"Raze chega do Brasil com uma explosão de carisma e armas enormes. Com seu estilo de jogo \"porradeiro\", ela é craque em desentocar inimigos entrincheirados e limpar espaços apertados com uma bela dose de BUUUM!","ru-RU":"Raze – мастер взрывного дела из Бразилии, обладательница сильного характера и еще более мощных пушек. Она способна легко справиться с засевшими в обороне противниками или зачистить небольшое помещение. Громко и без лишних церемоний.","th-TH":"Raze ระเบิดออกจากบราซิลด้วยบุคลิกที่เข้ากับคนอื่นได้ง่ายและปืนอันใหญ่โต ด้วยสไตล์การเล่นแบบถึงพริกถึงขิง เธอจึงเก่งกาจในการผลักดันศัตรูให้ออกจากที่มั่นและเคลียร์พื้นที่แคบพร้อมเสียง \"ตู้ม\" แบบหูดับตับไหม้","tr-TR":"Bomba gibi bir kişiliğe ve kocaman silahlara sahip olan Raze, aramıza Brezilya''dan katılıyor. Kafa göz dalan oyun tarzıyla düşmanları saklandıkları deliklerden çıkarmakta ve dar alanları ''''bam bam bam'''' temizlemekte üstüne yoktur.","vi-VN":"Raze là một hiện tượng đến từ Brasil với cá tính nổi bật và những khẩu súng cực bự. Với lối chơi bùng nổ, cô luôn ép đối phương phải ra khỏi nơi ẩn nấp và dọn sạch đối thủ trong những địa hình chật hẹp với một liều thuốc nổ hạng nặng.","zh-CN":"“雷兹”来自亚马逊平原。她轰轰烈烈的性情就跟她手中的武器一样火爆，作战风格也是简单粗暴、爆发力十足。无论是攻坚战还是狭小空间的遭遇战，都是她的拿手好戏。","zh-TW":"來自巴西的芮茲經常使用巨型槍械展現她大剌剌的個性。她擅長用驚天一「砰」，逼出躲在壕溝的埋伏，掃除狹窄空間的敵人，這就是她的暴力破壞風。"}'::jsonb, 'Clay', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/displayicon.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/displayicon.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/fullportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/fullportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/fullportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/killfeedportrait.png', 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/minimapportrait.png', null, 'https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/background.png', array['742e1eff', '0f1923ff', '2c5942ff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('f94c3b30-42be-e959-889c-5aa313dba261'::uuid, 'Ability1', '{"es-MX":"Paquete Explosivo","ar-AE":"العبوة الناسفة","es-ES":"Fardo explosivo","ja-JP":"ブラストパック","it-IT":"Pacco esplosivo","de-DE":"Sprengstoffpack","id-ID":"Blast Pack","ko-KR":"폭발 팩","fr-FR":"Pack explosif","en-US":"Blast Pack","pl-PL":"Bombowa Paka","pt-BR":"Carga de Explosivos","ru-RU":"Взрывной ранец","th-TH":"Blast Pack","tr-TR":"PATLAYICI ÇANTA","vi-VN":"Gói Chất Nổ","zh-CN":"惊喜翻腾","zh-TW":"爆破包"}'::jsonb, '{"es-MX":"Lanza AL INSTANTE un Paquete Explosivo que se adhiere a las superficies. VUELVE A USAR la habilidad después de desplegar el paquete para detonarlo, lo que desplazará todo lo que impacte e infligirá daño al estar totalmente cargada.","ar-AE":"تلقي على الفور عبوة ناسفة تلتصق بالأسطح. أعد استخدام القدرة بعد النشر لتفجير العبوة، مما يحرك أي جسم تصيبه ويتسبب في إلحاق ضرر إذا كانت كاملة التسليح.","es-ES":"Lanza AL INSTANTE un fardo explosivo que se adhiere a las superficies. VUELVE A USAR la habilidad después de que el fardo se adhiera para detonarlo, lo que desplazará a todo aquello que alcance e infligirá daño si está totalmente armado.","ja-JP":"ブラストパックを投げる。このブラストパックは地形の表面に張り付けることができる。設置後にアビリティーを「再使用」すると起爆し、爆風を受けたものを吹き飛ばす。また、設置後に完全に爆発した場合はダメージも与える。","it-IT":"Lancia ALL''ISTANTE un Pacco esplosivo che aderisce alle superfici. Una volta piazzato, USA DI NUOVO l''abilità per farlo esplodere, spostando tutto quello che viene colpito e infliggendo danni se innescato del tutto.","de-DE":"Wirf SOFORT ein Sprengstoffpaket, das an Oberflächen haftet. REAKTIVIERE die Fähigkeit nach dem Wurf, um eine Explosion auszulösen. Bei vollständiger Aufladung werden alle getroffenen Gegner und Gegenstände weggeschleudert und sie erleiden Schaden.","id-ID":"SEKETIKA melempar Blast Pack yang akan menempel ke permukaan. GUNAKAN LAGI ability ini setelah dikerahkan untuk meledakkannya, memindahkan apa pun yang dikenai dan menghasilkan damage jika sepenuhnya siap.","ko-KR":"표면에 부착되는 폭발 팩을 던집니다. 부착 후 다시 사용하면 팩이 폭발하며 적중한 대상을 밀어내고, 완전히 무장되었을 경우에는 피해를 입힙니다.","fr-FR":"Lancez INSTANTANÉMENT un pack explosif qui se colle aux surfaces. RÉUTILISEZ la compétence pour déclencher l''explosion, ce qui déplace tous ceux qui sont touchés et inflige des dégâts s''il était complètement armé.","en-US":"INSTANTLY throw a Blast Pack that will stick to surfaces. RE-USE the ability after deployment to detonate, moving anything hit and dealing damage if fully armed.","pl-PL":"NATYCHMIAST rzuć Bombową Paką, która przyczepia się do powierzchni. UŻYJ PONOWNIE tej umiejętności po rozmieszczeniu ładunku, by go zdetonować, przemieszczając wszystkie trafione cele i zadając obrażenia, jeśli był w pełni uzbrojony.","pt-BR":"INSTANTANEAMENTE lança uma Carga de Explosivos que gruda em superfícies. REPITA a habilidade depois de lançar para detonar. A carga move tudo que for atingido e causa dano se estiver totalmente carregada.","ru-RU":"Мгновенно бросает взрывной ранец, прикрепляющийся к поверхностям. Используйте умение повторно, чтобы взорвать ранец – он оттолкнет находящихся рядом агентов, а также нанесет урон, если полностью готов.","th-TH":"โยน Blast Pack ที่จะยึดติดกับพื้นผิวทันที ใช้สกิลอีกครั้งหลังปาออกไปเพื่อจุดชนวนระเบิด เคลื่อนย้ายทุกสิ่งที่โดนและสร้างความเสียหายหากพร้อมทำงานเต็มที่","tr-TR":"Zemine yapışan bir Patlayıcı Çanta''yı ANINDA fırlat. Elinden çıkan çantayı patlatmak için yeteneği TEKRAR KULLAN. Çanta isabet ettiği her şeyi yerinden oynatır ve tamamen kurulduysa onlara hasar verir.","vi-VN":"NGAY LẬP TỨC tung ra Gói Chất Nổ bám dính trên bề mặt địa hình. TÁI SỬ DỤNG kỹ năng sau khi tung ra để kích nổ, làm dịch chuyển bất cứ thứ gì trúng phải và gây sát thương nếu được kích hoạt hoàn toàn.","zh-CN":"投掷一个可粘在物体表面的炸药包。完成部署后，【再次使用】该技能即可将其引爆，击飞命中的目标。如果炸药包已完全激活，则可造成伤害。","zh-TW":"立即丟出一個會黏在表面的爆破包。部署完成後「重施技能」來引爆，對擊中的東西造成位移，完全武裝則會造成傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('f94c3b30-42be-e959-889c-5aa313dba261'::uuid, 'Ability2', '{"es-MX":"Carcasas de Pintura","ar-AE":"القنابل اللونية","es-ES":"Balas de pintura","ja-JP":"ペイント弾","it-IT":"Granate colorate","de-DE":"Farbbomben","id-ID":"Paint Shells","ko-KR":"페인트탄","fr-FR":"Grenade gigogne","en-US":"Paint Shells","pl-PL":"Farbujący Granat","pt-BR":"Cartuchos de Tinta","ru-RU":"Кассетная граната","th-TH":"Paint Shells","tr-TR":"RENK TESİRLİ BOMBA","vi-VN":"Lựu Đạn Liên Hoàn","zh-CN":"彩雷飞溅","zh-TW":"漆彩榴彈"}'::jsonb, '{"es-MX":"EQUIPA una granada de racimo. DISPARA para lanzarla. La granada infligirá daño por su cuenta y creará submuniciones que también infligirán daño a cualquiera que se encuentre dentro de su alcance. Usa el DISPARO SECUNDARIO para lanzarlo por debajo. Las cargas de Carcasas de Pintura se reinician cada dos asesinatos.","ar-AE":"تجهز بقنبلة عنقودية. أطلق لرمي القنبلة، حيث تلحق الضرر وتكوّن قنابل فرعية صغيرة تلحق كل منها الضرر بكل من يتواجد في نطاقها. استخدم الإطلاق البديل للإلقاء المقوس. تتم إعادة ضبط شحنة القنابل اللونية بعد كل عمليتي قتل.","es-ES":"EQUIPA una granada de racimo. DISPARA para lanzar la granada, lo que causa daño y crea submuniciones que infligen daño a cualquiera que esté dentro del rango. Utiliza el DISPARO ALTERNATIVO para tirarlo. La carga de Balas de pintura se reinicia cada dos asesinatos.","ja-JP":"クラスターグレネードを構える。「発射」でグレネードを投げる。グレネードはダメージを与えると同時に複数の小型爆薬を放出し、それぞれが範囲内の全員にダメージを与える。「オルト射撃」で軽く放る。「ペイント弾」のチャージは 2 キルごとにリセットされる。","it-IT":"EQUIPAGGIA una granata a grappolo. Usa il FUOCO per lanciare la granata, che infligge danni e crea esplosioni secondarie che danneggiano a loro volta chiunque si trovi a portata. Usa il FUOCO ALTERNATIVO per lanciare la granata dal basso verso l''alto. La carica delle Granate colorate si ripristina ogni due uccisioni.","de-DE":"RÜSTE eine Clustergranate AUS. FEUERE, um die Granate zu werfen. Sie verursacht Schaden und erzeugt Streumunition, die jedem in ihrem Umkreis Schaden zufügt. ALT. FEUERMODUS für einen Unterhandwurf. Die Farbbombenaufladung setzt sich alle zwei Kills zurück.","id-ID":"EQUIP granat klaster. Tekan FIRE untuk melempar granat yang menghasilkan damage dan sub-amunisi, masing-masing memberikan damage pada siapa pun yang ada dalam jangkauan. Kemudian, tekan ALT FIRE untuk melempar tinggi. Charge Paint Shells direset tiap dua kill.","ko-KR":"집속탄을 장착합니다. 발사하면 집속탄을 던집니다. 집속탄은 피해를 입히고 여러 개의 자탄을 퍼뜨립니다. 자탄은 각각의 범위 내에 있는 모든 대상에게 피해를 입힙니다. 보조 공격 시 높이 던집니다. 페인트탄 충전량은 2킬마다 초기화됩니다.","fr-FR":"ÉQUIPEZ-vous d''une grenade à sous-munitions. TIREZ pour lancer la grenade. Elle inflige des dégâts et crée des sous-munitions qui blessent tous ceux qui sont à leur portée. Utilisez le TIR SECONDAIRE pour la lancer en cloche. Vous regagnez une charge de Grenade gigogne toutes les deux éliminations.","en-US":"EQUIP a cluster grenade. FIRE to throw the grenade, which does damage and creates sub-munitions, each doing damage to anyone in their range. ALT FIRE to lob. Paint Shells charge resets every two kills.","pl-PL":"WYPOSAŻ granat kasetowy. STRZEL, by rzucić granat zadający obrażenia i tworzący mniejsze ładunki, z których każdy zadaje obrażenia celom w jego zasięgu. Naciśnij ALT. STRZAŁ, by cisnąć. Reset Farbujących Granatów następuje co dwa zabójstwa.","pt-BR":"EQUIPE uma granada múltipla. DISPARE para jogar a granada, que causa dano e cria submunições, cada uma causando dano a qualquer um que estiver no alcance. Use o DISPARO ALTERNATIVO para arremessar a curta distância. A carga dos Cartuchos de Tinta é redefinida a cada dois abates.","ru-RU":"Выбирает кассетную гранату. Нажмите кнопку ОГОНЬ, чтобы бросить гранату, которая взрывается, наносит урон и выпускает гранаты поменьше, наносящие урон любому агенту в радиусе поражения. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы сделать бросок снизу. Каждые два убийства восстанавливают заряд \"Кассетной гранаты\".","th-TH":"ติดตั้งระเบิดมือ กดยิงเพื่อขว้างระเบิดมือ ซึ่งจะสร้างความเสียหายและปล่อยระเบิดลูกย่อย ๆ ออกมา ที่แต่ละลูกก็จะสร้างความเสียหายกับทุกคนที่อยู่ในรัศมี กดโหมดยิงเสริมเพื่อโยนออกไปในระยะสั้น ๆ ชาร์จของ Paint Shells จะรีเซ็ตทุก ๆ สองคิล","tr-TR":"Bir parça tesirli el bombası KUŞAN. Fırlatmak için ATEŞ ET. Bomba patlayıp hasar verdikten sonra her biri menzilindeki herkese hasar veren bombacıklar oluşturur. Yavaşça fırlatmak için ALT. ATIŞ kullan. Renk Tesirli Bomba''nın yükü her iki skorda bir dolar.","vi-VN":"TRANG BỊ 1 quả lựu đạn chùm. BẮN để ném lựu đạn, gây sát thương và tạo ra một loạt các lựu đạn phụ gây thương tích lên bất cứ ai trong tầm ảnh hưởng. BẮN PHỤ để ném cao. Lượt sử dụng Lựu Đạn Liên Hoàn sẽ được làm mới sau mỗi 2 hạ gục.","zh-CN":"装备集束手雷。按【射击】投掷手雷，手雷爆炸后会生成子榴弹，每颗对范围内所有人造成伤害。按【辅助射击】可轻抛。每击败两名敌人，可重置【彩雷飞溅】的充能。","zh-TW":"裝備一枚破片手榴彈。點擊「攻擊」來丟出手榴彈造成傷害，並且射出對範圍內所有目標造成傷害的破片。點擊「輔助攻擊」則可低手拋出。每擊殺兩名敵人可重置漆彩榴彈充能數。"}'::jsonb, '"https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('f94c3b30-42be-e959-889c-5aa313dba261'::uuid, 'Grenade', '{"es-MX":"Bumbot","ar-AE":"الروبوت المتفجر","es-ES":"Bot explosivo","ja-JP":"ブームボット","it-IT":"Bot esplosivo","de-DE":"Boom-Bot","id-ID":"Boom Bot","ko-KR":"폭발 봇","fr-FR":"Boum Bot","en-US":"Boom Bot","pl-PL":"Bum Bot","pt-BR":"Bumba","ru-RU":"Бомботрон","th-TH":"Boom Bot","tr-TR":"BOMBOT","vi-VN":"Robot Bộc Phá","zh-CN":"花车巡游","zh-TW":"爆破機器人"}'::jsonb, '{"es-MX":"EQUIPA un Bumbot y DISPARA para desplegarlo. El bot se moverá en línea recta por el suelo y rebotará en los muros. El Bumbot marcará a cualquier enemigo que se encuentre en un cono frente a él y lo perseguirá. Si lo alcanza, infligirá mucho daño.","ar-AE":"تجهّز بروبوت متفجر. يؤدي الإطلاق إلى رمي روبوت يتحرك في خط مستقيم على الأرض ويرتد عن الجدران. يستهدف الروبوت المتفجر أي عدو متواجد في خط سيره المستقيم ويطارده، حيث ينفجر محدثًا ضررًا كبيرًا إن وصل إليه.","es-ES":"EQUIPA un bot explosivo. DISPARA para desplegar el bot y hacer que se desplace en línea recta por el terreno, rebotando por las paredes. El bot explosivo se fijará a los enemigos que encuentre en un cono frontal y los perseguirá. Si los alcanza, explotará e infligirá una gran cantidad de daño.","ja-JP":"ブームボットを準備する。「発射」でブームボットを展開する。このボットは地表をまっすぐに進み、壁に当たると向きを変える。前方の扇状範囲内に敵を感知するとロックオンして追いかけ、敵に追いつくと爆発して大ダメージを与える。","it-IT":"EQUIPAGGIA un bot esplosivo. Usa il FUOCO per piazzare il bot, che viaggerà in linea retta sul terreno rimbalzando quando tocca i muri. Il bot esplosivo punterà i nemici che si trovano in un''area conica di fronte a sé e li inseguirà; se li raggiunge, esploderà infliggendo ingenti danni.","de-DE":"RÜSTE einen Boom-Bot AUS. FEUERE, um den Bot auszulösen. Dadurch bewegt er sich in einer geraden Linie über den Boden und prallt von Wänden ab. Der Boom-Bot hängt sich an alle Gegner vor ihm und jagt sie. Beim Aufprall explodiert er und verursacht schweren Schaden.","id-ID":"EQUIP Boom bot. Tekan FIRE untuk mengaktifkan bot, serta menggerakkannya dalam garis lurus di tanah dan memantul di dinding. Bagian runcing Boom Bot akan mengunci dan mengejar musuh mana pun, lalu menghasilkan damage besar jika mengenai mereka.","ko-KR":"폭발 봇을 장착합니다. 발사하면 폭발 봇이 지면에서 일직선으로 이동하며 벽을 만나면 튕겨 나옵니다. 폭발 봇의 정면 원뿔형 시야 안에 적이 포착되면 해당 적에게 돌진하며 폭발해 치명적인 피해를 입힙니다.","fr-FR":"ÉQUIPEZ-vous d''un Boum Bot. TIREZ pour déployer le bot, ce qui le propulse en ligne droite sur le sol. Il rebondit contre les murs. Les Boum Bots se verrouillent sur les ennemis situés dans un cône face à eux et les chassent, explosant quand ils les atteignent en infligeant de lourds dégâts.","en-US":"EQUIP a Boom Bot. FIRE will deploy the bot, causing it to travel in a straight line on the ground, bouncing off walls. The Boom Bot will lock on to any enemies in its frontal cone and chase them, exploding for heavy damage if it reaches them.","pl-PL":"WYPOSAŻ Bum Bota. STRZEL, by wypuścić bota, który powędruje w linii prostej po ziemi, odbijając się od ścian. Bum Bot namierzy wrogów widocznych przed nim, po czym popędzi w ich kierunku i eksploduje, zadając duże obrażenia, jeśli uda mu się do nich dotrzeć.","pt-BR":"EQUIPE um Bumba. DISPARE para lançar o robô, que avança em linha reta no chão, ricocheteando nas paredes. O Bumba trava ao detectar inimigos no cone frontal e os persegue, explodindo e causando dano pesado se alcançá-los.","ru-RU":"Выбирает \"Бомботрон\". Нажмите кнопку ОГОНЬ, чтобы выпустить его. \"Бомботрон\" двигается по прямой и отскакивает от стен. При обнаружении цели \"Бомботрон\" мчится к ней по прямой и взрывается, нанося большой урон при столкновении.","th-TH":"ติดตั้ง Boom Bot กดยิงเพื่อปล่อยบอทให้วิ่งไป\nบนพื้นเป็นเส้นตรงและจะกระดอนออกมาเมื่อชน\nกำแพง Boom Bot จะล็อกเป้าหมายบนศัตรู\nที่ตรวจพบและไล่ติดตามไป โดยจะทำการระเบิด\nอย่างรุนแรงเมื่อไปถึงศัตรู","tr-TR":"Bir Bombot KUŞAN. Göndermek için ATEŞ ET; bot yerde düz bir hat halinde ilerler ve duvarlardan seker. Bombot önündeki koni şeklindeki alana giren tüm düşmanlara kilitlenir ve onları kovalar. Yakalayabilirse, ağır hasar vererek patlar.","vi-VN":"TRANG BỊ 1 Robot Bộc Phá. BẮN để thả robot về phía trước theo đường thẳng, nảy ra khi chạm tường. Robot Bộc Phá sẽ khóa mục tiêu trong phạm vi hình nón phía trước và bám theo mục tiêu để gây sát thương lớn khi phát nổ.","zh-CN":"装备爆弹机器人。按【射击】即可部署机器人，它在地上沿直线行进，并会在碰到墙体后弹开。爆弹机器人会锁定任何在其锥形范围内的敌人并追逐他们，一旦追上便会引爆并造成严重伤害。","zh-TW":"裝備一個爆破機器人。點擊「攻擊」來啟動機器人，機器人會在地面沿著直線行進，撞到牆壁會反彈。爆破機器人會鎖定出現在其前方扇形區域的敵人，並朝目標直衝，若成功追上敵人則會爆炸造成大量傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('f94c3b30-42be-e959-889c-5aa313dba261'::uuid, 'Ultimate', '{"es-MX":"Tumbadivas","ar-AE":"قاذفة الصواريخ","es-ES":"Cierratelones","ja-JP":"ショーストッパー","it-IT":"Sensazionale","de-DE":"Volles Rohr","id-ID":"Showstopper","ko-KR":"대미 장식","fr-FR":"Bouquet final","en-US":"Showstopper","pl-PL":"Gwóźdź Programu","pt-BR":"Estraga-prazeres","ru-RU":"Гасим свечи!","th-TH":"Showstopper","tr-TR":"NEFES KESEN","vi-VN":"Tên Lửa Hạ Màn","zh-CN":"晚安焰火","zh-TW":"掃興火炮"}'::jsonb, '{"es-MX":"EQUIPA un lanzamisiles. DISPARA para lanzar un misil que inflige daño de área masivo al entrar en contacto con algo.","ar-AE":"تجهز بقاذفة صواريخ. أطلق لإرسال صاروخ يلحق قدرًا كبيرًا من الضرر المحيطي عند اصطدامه بأي شيء.","es-ES":"EQUIPA un lanzacohetes. DISPARA para lanzar un cohete que inflige un daño en área masivo al entrar en contacto con cualquier cosa.","ja-JP":"ロケットランチャーを構える。「発射」でロケット弾を射出する。ロケット弾は着弾地点の周辺に大ダメージを発生させる。","it-IT":"EQUIPAGGIA un lanciarazzi. Usa il FUOCO per lanciare un razzo che infligge ingenti danni ad area all''impatto.","de-DE":"Einen Raketenwerfer AUSRÜSTEN. FEUERE eine Rakete ab, die schweren Flächenschaden verursacht, wenn sie etwas trifft.","id-ID":"EQUIP pelontar roket. Tekan FIRE untuk meluncurkan roket yang menghasilkan damage area masif saat bersentuhan dengan apa pun.","ko-KR":"로켓 발사기를 장착합니다. 발사하면 충돌 시 대량의 범위 피해를 입히는 로켓을 발사합니다.","fr-FR":"ÉQUIPEZ-vous d''un lance-roquettes. TIREZ pour lancer une roquette qui inflige de lourds dégâts de zone au premier contact.","en-US":"EQUIP a rocket launcher. FIRE to shoot a rocket that does massive area damage on contact with anything.","pl-PL":"WYPOSAŻ wyrzutnię rakiet. STRZEL, by wypuścić rakietę, która w chwili trafienia zada potężne obrażenia obszarowe.","pt-BR":"EQUIPE um lança-mísseis. DISPARE um foguete que causa dano devastador em área ao fazer contato com qualquer coisa.","ru-RU":"Выбирает ракетомет. Нажмите кнопку ОГОНЬ, чтобы выпустить ракету, наносящую огромный урон по большой области при контакте.","th-TH":"ติดตั้งเครื่องยิงจรวด กดยิงเพื่อปล่อยจรวดที่สร้างความเสียหายในวงกว้างเมื่อสัมผัสกับสิ่งใด ๆ","tr-TR":"Bir roketatar KUŞAN. Herhangi bir şeye temas ettiğinde patlayıp muazzam alan hasarı veren bir roket fırlatmak için ATEŞ ET.","vi-VN":"TRANG BỊ 1 máy phóng lựu. BẮN để phóng 1 quả tên lửa gây sát thương trên diện rộng khi chạm vào bất cứ thứ gì.","zh-CN":"装备火箭发射器。按【射击】即可发射一枚在与任何物体接触时造成大范围伤害的火箭。","zh-TW":"裝備一台火箭發射器。點擊「攻擊」發射一枚火箭炮，火箭炮會在擊中區域造成大範圍傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/f94c3b30-42be-e959-889c-5aa313dba261/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('22697a3d-45bf-8dd7-4fec-84a9e28c69d7'::uuid, '{"es-MX":"Chamber","ar-AE":"تشامبر","es-ES":"Chamber","ja-JP":"チェンバー","it-IT":"Chamber","de-DE":"Chamber","id-ID":"Chamber","ko-KR":"체임버","fr-FR":"Chamber","en-US":"Chamber","pl-PL":"Chamber","pt-BR":"Chamber","ru-RU":"Chamber","th-TH":"Chamber","tr-TR":"CHAMBER","vi-VN":"Chamber","zh-CN":"尚勃勒","zh-TW":"錢博爾"}'::jsonb, '{"es-MX":"Vestido y armado para matar, el diseñador de armas francés, Chamber, rechaza toda ofensiva con precisión letal. Aprovecha su arsenal personalizado para mantener a los enemigos a raya y eliminarlos desde lejos. Siempre cuenta con la contingencia perfecta para cada plan.","ar-AE":"مع ملابسه الأنيقة وأسلحته الجاهزة، يطرد مصمم الأسلحة الفرنسي تشامبر المعتدين بدقة فتاكة. وهو يستغل ترسانة أسلحته المخصصة للتمسك بالمواقع واقتناص الأعداء من على بُعد، مع خطة طوارئ مصممة لكل ظرف.","es-ES":"El diseñador de armas francés, siempre bien vestido y bien pertrechado, expulsa a los agresores con precisión letal. Chamber aprovecha su arsenal personalizado para resistir, elimina enemigos a distancia y crea la contingencia perfecta para cada plan.","ja-JP":"装いも武器も一流に。フランスの武器デザイナーであるチェンバーは、致命的な精度で敵を撃ち抜く。特製の武器で相手の侵攻を阻み、遠距離から狙い撃て。完璧な策略は、あらゆる戦略を凌駕する。","it-IT":"Chamber, progettista di armi francese agghindato e armato di tutto punto, è un agente capace di togliere di mezzo gli avversari con precisione letale. Questo Guardiano sfrutta il suo arsenale personalizzato per mantenere la posizione ed eliminare i nemici da lontano, creando la strategia perfetta per ogni occasione.","de-DE":"Gut gekleidet und bewaffnet vertreibt der französische Waffendesigner Chamber Angreifer mit tödlicher Präzision. Mit seinem individuellen Arsenal behält er alles im Blick, schaltet Gegner aus der Ferne aus und hat für jeden Plan einen Plan B.","id-ID":"Berpakaian rapi dan bersenjata lengkap, Chamber, yang juga merupakan desainer senjata dari Prancis, menghalau penyerang dengan presisi yang mematikan. Dia memanfaatkan persenjataan kustomnya untuk mempertahankan barisan dan menembak musuh dari jauh, dengan kontingensi yang tersusun untuk tiap rencana.","ko-KR":"맵시 있는 모습으로 단단히 무장한 프랑스 무기 디자이너 체임버는 치명적인 정확도로 적을 몰아냅니다. 만일의 사태에 대한 모든 계획을 세운 그는 자신만의 커스텀 무기를 사용하여 전선을 사수하고 멀리서 적을 격퇴합니다.","fr-FR":"Aussi classe que bien équipé, le concepteur d''armes français Chamber repousse les assaillants avec une précision mortelle. Il met à profit son arsenal bien particulier pour tenir sa position et éliminer les ennemis de loin en prévoyant une solution aux défis posés par chaque stratégie.","en-US":"Well-dressed and well-armed, French weapons designer Chamber expels aggressors with deadly precision. He leverages his custom arsenal to hold the line and pick off enemies from afar, with a contingency built for every plan.","pl-PL":"Świetnie ubrany i równie dobrze uzbrojony francuski projektant broni Chamber neutralizuje wrogów z zabójczą precyzją. Wykorzystując niestandardowy arsenał, utrzymuje pozycję i z daleka eliminuje wrogów, a na każdą ewentualność ma plan awaryjny.","pt-BR":"Bem-vestido e armado até os dentes, o criador de armas francês Chamber coloca os inimigos para correr com precisão mortal. Use e abuse do arsenal personalizado dele para segurar posições e abater inimigos de longe, criando a defesa perfeita para qualquer plano.","ru-RU":"Одет с иголочки и вооружен до зубов. Chamber, французский конструктор оружия, уничтожает врагов с поразительной точностью. Уникальные умения этого стража позволяют эффективно защищаться, нейтрализовать врагов издалека и продумывать любой план до мельчайших подробностей.","th-TH":"แต่งกายครบชุด อาวุธจัดเต็ม Chamber นักออกแบบอาวุธชาวฝรั่งเศสยับยั้งผู้บุกรุกด้วยความแม่นยำแสนร้ายกาจ เขาใช้คลังแสงสั่งทำพิเศษของเขาเพื่ิอป้องกันพื้นที่ และเด็ดหัวศัตรูจากระยะไกล และมีแผนสำรองสำหรับทุกแผนการ","tr-TR":"Her daim şık ve tam teçhizat dolaşan Fransız silah tasarımcısı Chamber, ölümcül isabetliliğiyle rakipleri ortadan kaldırıyor. Özel yeteneklerini kullanarak görüş mesafesi sağlar, uzaktaki rakipleri avlar ve her plana mükemmel bir şekilde uyum sağlar.","vi-VN":"Với vẻ ngoài lịch lãm và trang bị tối tân, chuyên gia vũ khí Chamber đến từ nước Pháp sẽ truy quét đối thủ bằng sự chính xác tuyệt đối. Anh có thể tận dụng kho vũ khí chuyên biệt của mình để giữ vững chiến tuyến, bắn hạ kẻ địch từ xa với phương án dự phòng hoàn hảo dành cho mọi kế hoạch tác chiến.","zh-CN":"穿着考究、装备精良的西欧武器设计师“尚勃勒”非常擅长防守阵线。他会利用强大的自制武器从远处逼退妄图进犯的敌人，同时也会为自己的撤退和转移准备体面的应急方案。","zh-TW":"錢博爾是來自法國的武器設計師，他一身時尚、滿載武力，用致命的精準武器把侵略者一一驅逐。他的特製武器可以守住戰線，從遠處一一消滅敵人，即便作戰出了亂子，他也能優雅應變，臨危不亂。"}'::jsonb, 'Deadeye', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/displayicon.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/displayicon.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/fullportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/fullportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/fullportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/killfeedportrait.png', 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/minimapportrait.png', null, 'https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/background.png', array['20435bff', '0f1923ff', '372d2bff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('22697a3d-45bf-8dd7-4fec-84a9e28c69d7'::uuid, 'Ability2', '{"es-MX":"Rendezvous","ar-AE":"الموعد","es-ES":"Rendez-vous","ja-JP":"ランデヴー","it-IT":"Rendez-vous","de-DE":"Rendezvous","id-ID":"Rendezvous","ko-KR":"랑데부","fr-FR":"Rendez-vous","en-US":"Rendezvous","pl-PL":"Schadzka","pt-BR":"Rendezvous","ru-RU":"Рандеву","th-TH":"Rendezvous","tr-TR":"BULUŞMA","vi-VN":"Điểm Dịch Chuyển","zh-CN":"闪转自如","zh-TW":"法式轉移"}'::jsonb, '{"es-MX":"EQUIPA un teletransportador. DISPARA para colocarlo en el suelo. Mientras estés en el suelo y dentro de su zona de alcance, podrás REACTIVAR la habilidad para transportarte rápidamente al teletransportador. Puedes recogerlo para VOLVER A COLOCARLO en otro lugar.","ar-AE":"تجهز بمرساة انتقال سريع. أطلق لوضعها على الأرض. أثناء وجودك على الأرض وضمن نطاق المرساة، أعد تفعيل القدرة للانتقال السريع إلى المرساة. يمكن التقاط المرساة لإعادة وضعها.","es-ES":"EQUIPA un anclaje de teleportación. DISPARA para colocarlo en el suelo. Mientras esté en el suelo y al alcance, REACTIVA la habilidad para teleportarte rápidamente al anclaje. El anclaje se puede recoger para VOLVER A COLOCARLO.","ja-JP":"テレポートアンカーを構え、「発射」で地面に設置する。アンカーの範囲内かつ地面上にいる時に再発動すると、アンカーに素早くテレポートする。アンカーは回収して再設置可能。","it-IT":"EQUIPAGGIA un nodo di teletrasporto. Usa il FUOCO per piazzarlo a terra. Quando sei a terra e a portata del nodo, RIATTIVA l''abilità per teletrasportarti velocemente su di esso. Il nodo può essere raccolto per RIUTILIZZARLO.","de-DE":"RÜSTE einen Teleporterausgang AUS. FEUERE, um ihn auf dem Boden zu platzieren. Während du dich auf dem Boden und in Reichweite des Ausgangs befindest, kannst du REAKTIVIEREN, um dich schnell zum Ausgang zu teleportieren. Du kannst den Ausgang aufheben, um ihn ERNEUT EINZUSETZEN.","id-ID":"EQUIP penanda teleportasi. Tekan FIRE untuk menempatkannya di darat. Saat berada di darat dan dalam jangkauan penanda, AKTIFKAN KEMBALI untuk berteleportasi dengan cepat ke penanda itu. Penanda bisa diambil untuk DIKERAHKAN LAGI.","ko-KR":"순간이동 앵커를 장착합니다. 발사하면 지면에 설치합니다. 지면에서 앵커 범위 내에 있을 때 다시 활성화하면 해당 앵커로 빠르게 순간이동합니다. 앵커는 회수하여 재배치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''une balise de téléportation. TIREZ pour la poser sur le sol. Quand vous vous trouvez sur le sol à portée de la balise, RÉACTIVEZ pour vous y téléporter rapidement. La balise peut être ramassée pour être REDÉPLOYÉE.","en-US":"EQUIP a teleport anchor. FIRE to place it on the ground. While on the ground and in range of the anchor, REACTIVATE to quickly teleport to the anchor. The anchor can be picked up to be REDEPLOYED.","pl-PL":"WYPOSAŻ kotwicę teleportującą. STRZEL, aby umieścić ją na ziemi. Gdy znajdujesz się na ziemi i w zasięgu działania kotwicy, REAKTYWUJ, by szybko teleportować się do kotwicy. Kotwicę można podnieść i UŻYĆ JEJ PONOWNIE.","pt-BR":"EQUIPE uma âncora de teleporte. DISPARE para posicioná-la no chão. Enquanto estiver no chão e dentro do alcance da âncora, REATIVE para teleportar rapidamente até a âncora. A âncora pode ser recuperada para ser REPOSICIONADA.","ru-RU":"Выбирает телепорт-якорь. Нажмите кнопку ОГОНЬ, чтобы разместить его на земле. Находясь на земле в зоне действия якоря, нажмите кнопку умения повторно, чтобы телепортироваться к нему. Якорь можно подобрать и разместить заново.","th-TH":"ติดตั้งจุดเทเลพอร์ต กดยิงเพื่อวางบนพื้น เมื่อยืนอยู่บนพื้นและอยู่ในระยะของจุดเทเลพอร์ต กดใช้อีกครั้งเพื่อเทเลพอร์ตอย่างรวดเร็วไปยังจุดเทเลพอร์ต จุดเทเลพอร์ตสามารถเก็บขึ้นมาได้เพื่อติดตั้งใหม่","tr-TR":"Bir ışınlayıcı KUŞAN. Işınlayıcıyı zemine yerleştirmek için ATEŞ ET. Işınlayıcının menzilinde ve yerde dururken hızlıca ışınlayıcıya ışınlanmak için TEKRAR ETKİNLEŞTİR. Işınlayıcıyı TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin.","vi-VN":"TRANG BỊ 1 trạm dịch chuyển. BẮN để đặt trạm dịch chuyển trên mặt đất. Khi đang ở trên mặt đất và trong phạm vi hoạt động của trạm, TÁI KÍCH HOẠT để dịch chuyển nhanh tới trạm. Trạm dịch chuyển này có thể được nhặt lên và ĐẶT LẠI.","zh-CN":"放置一个传送锚点。处于锚点范围内的地面上时，【再次激活】技能即可快速传送到锚点处。锚点可被拾起并【重新部署】。","zh-TW":"裝備一個傳送錨點，點擊「攻擊」可放置在地上，錢博爾在地面上且在錨點範圍內時，「重施技能」可瞬間移動到錨點位置。可撿起錨點，然後「重新部署」。"}'::jsonb, '"https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('22697a3d-45bf-8dd7-4fec-84a9e28c69d7'::uuid, 'Grenade', '{"es-MX":"Marca Registrada","ar-AE":"السمة المميزة","es-ES":"Marca registrada","ja-JP":"トレードマーク","it-IT":"Marchio","de-DE":"Markenzeichen","id-ID":"Trademark","ko-KR":"트레이드마크","fr-FR":"Guet-apens","en-US":"Trademark","pl-PL":"Znak Rozpoznawczy","pt-BR":"Marca Registrada","ru-RU":"Коронный прием","th-TH":"Trademark","tr-TR":"KARTVİZİT","vi-VN":"Điểm Đánh Dấu","zh-CN":"贵宾限行","zh-TW":"慢行特區"}'::jsonb, '{"es-MX":"EQUIPA una trampa que escanea los alrededores en busca de enemigos. DISPARA para colocarlo en el suelo. Cuando un enemigo visible entra en contacto, esta comienza una cuenta regresiva que, al terminar, desestabiliza el terreno a su alrededor y crea un área que permanece en la zona y ralentiza a los enemigos dentro de ella. Puedes recogerla para VOLVER A COLOCARLA en otro lugar.","ar-AE":"تجهز بفخ يمسح المنطقة بحثًا عن الأعداء. أطلق لوضعه على الأرض. عند دخول عدو مرئي ضمن النطاق، يبدأ العد التنازلي للفخ ثم يزعزع الأرض من حوله، وينشئ بذلك حقل تثبيت يبطئ اللاعبين الموجودين بداخله. يمكن التقاط الفخ لإعادة نصبه.","es-ES":"EQUIPA una trampa que escanea en busca de enemigos. DISPARA para colocarla en el suelo. Cuando un enemigo visible entra en el alcance, la trampa inicia una cuenta atrás y, a continuación, desestabiliza el terreno a su alrededor, lo que crea un campo persistente que ralentiza a los jugadores que se encuentren en su interior. La trampa se puede recoger para VOLVER A COLOCARLA.","ja-JP":"敵をスキャンするトラップを構え、「発射」で地面に設置する。視認できる敵が射程内に入るとトラップのカウントダウンが始まり、敵の周囲の地形を不安定にして遅延フィールドを発生させ、範囲内にいるプレイヤーをスロウ状態にする。トラップは回収して再設置可能。","it-IT":"EQUIPAGGIA una trappola che scansiona l''area in cerca di nemici. Usa il FUOCO per piazzarla a terra. Quando un nemico visibile entra nel raggio di rilevazione, la trappola avvia un conto alla rovescia al termine del quale destabilizza il terreno intorno al bersaglio, creando un campo persistente che RALLENTA i giocatori al proprio interno. La trappola può essere raccolta per RIUTILIZZARLA.","de-DE":"RÜSTE eine Falle AUS, die nach Gegnern scannt. FEUERE, um sie auf dem Boden zu platzieren. Wenn ein sichtbarer Gegner in ihre Reichweite kommt, beginnt die Falle herunterzuzählen und destabilisiert dann das Terrain um sich herum, wodurch ein temporäres Feld erzeugt wird, das Spieler in ihm verlangsamt. Du kannst die Falle aufheben, um sie ERNEUT EINZUSETZEN.","id-ID":"EQUIP jebakan yang dapat mendeteksi musuh. Tekan FIRE untuk menempatkannya di darat. Ketika musuh yang terdeteksi masuk ke dalam jangkauan, jebakan akan menghitung mundur lalu membuat medan di sekitar mereka tidak stabil. Medan tahan lama ini memberikan utilitas Slow pada pemain yang terperangkap di dalamnya. Jebakan bisa diambil untuk DIKERAHKAN LAGI.","ko-KR":"적을 스캔하는 함정을 장착합니다. 발사하면 지면에 설치합니다. 시야에 보이는 적이 사거리 안에 들어오면 함정이 카운트다운 후 주변 지형을 불안정하게 만들고 일정 시간 유지되는 둔화 영역을 생성하여 영역에 있는 플레이어의 속도를 늦춥니다. 함정은 회수하여 재배치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un piège qui détecte les ennemis. TIREZ pour le poser sur le sol. Quand un ennemi visible est à portée, le piège déclenche un compte à rebours avant d''ébranler le terrain autour de lui, créant un champ persistant qui ralentit les joueurs qui s''y trouvent. Le piège peut être ramassé pour être REDÉPLOYÉ.","en-US":"EQUIP a trap that scans for enemies. FIRE to place it on the ground. When a visible enemy comes in range, the trap counts down and then destabilizes the terrain around them, creating a lingering field that Slows players caught inside of it. The trap can be picked up to be REDEPLOYED.","pl-PL":"WYPOSAŻ pułapkę, która skanuje otoczenie w poszukiwaniu wrogów. STRZEL, aby umieścić ją na ziemi. Gdy widoczny wróg znajdzie się w jej zasięgu, pułapka zacznie odliczanie, po którym zdestabilizuje teren wokół niego, tworząc tymczasowe pole spowalniające znajdujących się w nim graczy. Pułapkę można podnieść i UŻYĆ JEJ PONOWNIE.","pt-BR":"EQUIPE uma armadilha que busca por inimigos. DISPARE para posicioná-la no chão. Quando um inimigo visível entrar no alcance, a armadilha inicia uma contagem regressiva e desestabiliza o terreno ao redor, criando um campo duradouro que Desacelera os jogadores dentro dele. A armadilha pode ser recuperada para ser REPOSICIONADA.","ru-RU":"Выбирает ловушку. Нажмите ОГОНЬ, чтобы разместить ее на земле. Когда рядом оказывается противник, ловушка срабатывает после короткой задержки и дестабилизирует небольшую область, в которой игроки замедляются. Ловушку можно подобрать и разместить заново.","th-TH":"ติดตั้งกับดักที่จะสแกนศัตรู กดยิงเพื่อวางบนพื้น เมื่อมีศัตรูที่มองเห็นได้เข้ามาในระยะ กับดักจะนับถอยหลัง แล้วจากนั้นจะทำให้พื้นที่รอบ ๆ เกิดความไม่เสถียร สร้างพื้นที่ที่จะสโลว์ผู้เล่นในบริเวณนั้น กับดักสามารถเก็บขึ้นมาได้เพื่อติดตั้งใหม่","tr-TR":"Düşmanlar için etrafı tarayan bir tuzak KUŞAN. Tuzağı zemine yerleştirmek için ATEŞ ET. Görünen düşmanlar tuzağın menzili içine girdiğinde, tuzak geri sayıma başlar. Tuzak devreye girdiğinde etki alanını stabil olmayan bir hale getirerek içinde bulunan düşmanları Yavaşlatır. Tuzağı TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin.","vi-VN":"TRANG BỊ 1 bẫy để phát hiện kẻ địch. BẮN để đặt trạm dịch chuyển trên mặt đất. Khi kẻ địch tiến vào phạm vi của bẫy, bẫy sẽ đếm ngược và sau đó khiến địa hình xung quanh rơi vào trạng thái bất ổn, tạo ra một vùng Làm Chậm những người chơi bên trong. Bẫy này có thể được nhặt lên và ĐẶT LẠI.","zh-CN":"装备一个可以扫描敌人的陷阱。按【射击】将其放置在地面上。非隐形的敌人进入扫描范围时，陷阱将开始倒计时并使周围地面陷入不稳定状态，生成一片持续存在的力场，使范围内所有的玩家【减速】。陷阱可被拾起并【重新部署】。","zh-TW":"裝備一個可偵測敵人的陷阱，點擊「攻擊」可放置在地上，非隱形的敵人進入範圍時，該陷阱倒數後會使周圍空間進入不穩定的狀態，創造一個可維持一段時間的力場，「緩速」範圍內的玩家。可撿起陷阱，然後「重新部署」。"}'::jsonb, '"https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('22697a3d-45bf-8dd7-4fec-84a9e28c69d7'::uuid, 'Ability1', '{"es-MX":"Cazador de Cabezas","ar-AE":"صياد الرؤوس","es-ES":"Cazador de cabezas","ja-JP":"ヘッドハンター","it-IT":"Cacciatore di teste","de-DE":"Kopfjäger","id-ID":"Headhunter","ko-KR":"헤드헌터","fr-FR":"Chasseur de têtes","en-US":"Headhunter","pl-PL":"Łowca Głów","pt-BR":"Caçador de Cabeças","ru-RU":"Охотник за головами","th-TH":"Headhunter","tr-TR":"KELLE AVCISI","vi-VN":"Kẻ Săn Đầu Người","zh-CN":"金牌猎头","zh-TW":"獵頭手槍"}'::jsonb, '{"es-MX":"ACTÍVALA para equipar una pistola pesada. Usa DISPARO SECUNDARIO con la pistola equipada para usar la mira.","ar-AE":"فعّل القدرة لتجهيز مسدس ثقيل. استخدم الإطلاق البديل مع المسدس المجهز للتصويب بالمنظار.","es-ES":"ACTÍVALA para equipar una pistola pesada. Utiliza el DISPARO ALTERNATIVO para apuntar con la mira.","ja-JP":"「発動」でヘヴィーピストルを装備する。装備中に「オルト射撃」で照準状態 (ADS) に切り替える。","it-IT":"ATTIVA per equipaggiare una pistola pesante. Usa il FUOCO ALTERNATIVO con la pistola equipaggiata per prendere la mira.","de-DE":"AKTIVIERE, um eine schwere Pistole anzulegen. ALT. FEUERMODUS mit angelegter Pistole, um über Visier zu zielen.","id-ID":"AKTIFKAN untuk equip pistol heavy. Tekan ALT FIRE untuk membidik dengan pistol tersebut.","ko-KR":"활성화하면 헤비 피스톨을 장착합니다. 장착한 피스톨로 보조 공격하면 조준 사격합니다.","fr-FR":"ACTIVEZ pour vous équiper d''un gros calibre. Utilisez le TIR SECONDAIRE avec le pistolet équipé pour viser.","en-US":"ACTIVATE to equip a heavy pistol. ALT FIRE with the pistol equipped to aim down sights.","pl-PL":"AKTYWUJ, aby wyposażyć ciężki pistolet. Użyj przycisku ALT. STRZAŁU z wyposażonym pistoletem, by spojrzeć przez celownik.","pt-BR":"ATIVE para equipar uma pistola pesada. Use o DISPARO ALTERNATIVO com a pistola equipada para mirar.","ru-RU":"Нажмите кнопку умения, чтобы выбрать тяжелый пистолет. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы прицелиться из этого пистолета.","th-TH":"ใช้งานเพื่อติดตั้งปืนพกหนัก ใช้ปุ่มยิงเสริมเมื่อติดตั้งปืนพกเพื่อเล็งผ่านลำกล้อง","tr-TR":"Ağır bir tabanca kuşanmak için ETKİNLEŞTİR. Tabancanın ALT. ATIŞI nişan almanı sağlar.","vi-VN":"KÍCH HOẠT để trang bị một khẩu súng lục hạng nặng. BẮN PHỤ để ngắm ADS khi trang bị súng lục hạng nặng.","zh-CN":"激活后装备一把重型手枪。可使用【辅助射击】开镜瞄准。","zh-TW":"按下「啟動」可裝備一把重火力手槍。持槍時點擊「輔助攻擊」可開始瞄準射擊。"}'::jsonb, '"https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('22697a3d-45bf-8dd7-4fec-84a9e28c69d7'::uuid, 'Ultimate', '{"es-MX":"Tour de Force","ar-AE":"ضربة معلم","es-ES":"Tour de force","ja-JP":"ツール・ド・フォース","it-IT":"Tour de force","de-DE":"Glanzleistung","id-ID":"Tour De Force","ko-KR":"역작","fr-FR":"Tour de force","en-US":"Tour De Force","pl-PL":"Majstersztyk","pt-BR":"Tour de Force","ru-RU":"Демонстрация силы","th-TH":"Tour De Force","tr-TR":"KESKİN TARZ","vi-VN":"Tour De Force","zh-CN":"孤高火力","zh-TW":"浪漫狙殺"}'::jsonb, '{"es-MX":"ACTIVA para invocar un poderoso rifle de francotirador personalizado que mata a los enemigos con cualquier impacto directo en la parte superior del cuerpo. Presiona el DISPARO SECUNDARIO para usar la mira. Matar a un enemigo crea un área que permanece en la zona y ralentiza a los jugadores que queden dentro de ella.","ar-AE":"فعّل القدرة لاستدعاء بندقية قناص مخصصة وقوية التاثير، حيث تكون قادرة على قتل الأعداء بأي إصابة مباشرة للقسم العلوي من الجسم. استخدم الإطلاق البديل للتصويب بالمنظار. يؤدي قتل أحد الأعداء إلى تكوين حقل تثبيت يبطئ اللاعبين الموجودين ضمنه.","es-ES":"ACTÍVALA para invocar un poderoso rifle de francotirador personalizado que mata a los enemigos con cualquier impacto directo en la parte superior del cuerpo. Utiliza el DISPARO ALTERNATIVO para apuntar con la mira. Matar a un enemigo genera un campo persistente que ralentiza a los jugadores que se encuentren en su interior.","ja-JP":"「発動」でカスタムスナイパーライフルを喚び出す。このライフルの弾丸は、それが上半身に直撃した相手を一撃でキルする。「オルト射撃」で照準状態 (ADS) に切り替える。敵をキルすると遅延フィールドが発生し、範囲内にいるプレイヤーをスロウ状態にする。","it-IT":"ATTIVA per imbracciare un potente fucile di precisione personalizzato che uccide un nemico se lo colpisce direttamente nella parte superiore del corpo. Usa il FUOCO ALTERNATIVO per prendere la mira. Uccidere un nemico crea un campo persistente che RALLENTA i giocatori al proprio interno.","de-DE":"AKTIVIEREN, um ein mächtiges Präzisionsgewehr herbeizurufen, das Gegner bei einem direkten Treffer des Oberkörpers sofort tötet. ALT. FEUERMODUS, um über Visier zu zielen. Wenn du einen Gegner tötest, wird ein temporäres Feld erzeugt, das Spieler verlangsamt.","id-ID":"AKTIFKAN untuk menggunakan sniper rifle kustom yang kuat, yang akan membunuh musuh dengan tembakan langsung ke tubuh bagian atas. Tekan ALT FIRE untuk membidik. Membunuh musuh akan menciptakan medan tahan lama yang menerapkan utilitas Slow pada pemain yang terperangkap di dalamnya.","ko-KR":"활성화하면 상체 직격 시 적을 처치할 수 있는 강력한 커스텀 저격총을 소환합니다. 보조 공격 시 조준합니다. 적을 처치하면 일정 시간 유지되는 둔화 영역을 생성하여 영역에 있는 플레이어의 속도를 늦춥니다.","fr-FR":"ACTIVEZ pour matérialiser un puissant fusil de sniper personnalisé qui tue l''ennemi en un coup s''il est touché au corps. Utilisez le TIR SECONDAIRE pour viser. Tuer un ennemi crée un champ persistant qui ralentit les joueurs qui s''y trouvent.","en-US":"ACTIVATE to summon a powerful, custom sniper rifle that will kill an enemy with any direct hit to the upper body. ALT FIRE to aim down sights. Killing an enemy creates a lingering field that Slows players caught inside of it.","pl-PL":"AKTYWUJ, by przywołać śmiercionośny, niestandardowy karabin snajperski, który zabije wroga każdym bezpośrednim trafieniem w górną część ciała. Wciśnij ALT. STRZAŁ, by spojrzeć przez celownik. Zabicie wroga tworzy długotrwałe pole spowalniające graczy w obszarze jego działania.","pt-BR":"ATIVE para invocar um poderoso fuzil de precisão personalizado que abate um inimigo com qualquer acerto na parte superior do corpo. Use o DISPARO ALTERNATIVO para mirar. Abater um inimigo cria um campo duradouro que Desacelera os jogadores dentro dele.","ru-RU":"Нажмите кнопку умения, чтобы выбрать особо мощную снайперскую винтовку, из которой можно убить врага любым прямым попаданием в верхнюю часть тела. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы прицелиться. На месте гибели противника возникает поле, замедляющее игроков, которые находятся в нем.","th-TH":"กดใช้เพื่อเรียกใช้ปืนสไนเปอร์เฉพาะตัวอันทรงพลัง ซึ่งจะฆ่าศัตรูทันทีหากยิงโดนส่วนบนของร่างกายโดยตรง กดโหมดยิงเสริมเพื่อเล็งผ่านกล้อง การฆ่าศัตรูจะสร้างพื้นที่ที่จะสโลว์ผู้เล่นในบริเวณนั้น","tr-TR":"Gövdeye doğrudan isabet ettiği düşmanları anında öldüren güçlü ve özel bir keskin nişancı tüfeği kuşanmak için ETKİNLEŞTİR. Nişan almak için ALT. ATIŞ kullan. Düşmanı öldürdüğün yerde, içine giren düşmanları Yavaşlatan bir etki alanı oluşur.","vi-VN":"KÍCH HOẠT để triệu hồi 1 khẩu súng bắn tỉa chuyên biệt siêu mạnh có khả năng hạ gục đối thủ ngay khi bắn trúng phần thân trên. BẮN PHỤ để ngắm ADS. Khi hạ gục kẻ địch sẽ tạo ra một khu vực khiến đối phương ở bên trong bị Làm Chậm.","zh-CN":"【激活】技能可召唤一把威力强大的定制狙击枪，命中敌人上半身任何部位均可将其击败。按【辅助射击】可使用瞄准镜。被击败的敌人会留下一片持续存在的力场，使范围内的所有玩家【减速】。","zh-TW":"按下「啟動」可取出一把強大的特製狙擊槍，直接命中上身即可擊殺敵人。點擊「輔助攻擊」即可進入開鏡瞄準模式。擊殺敵人後會創造一個可維持一段時間的力場，「緩速」範圍內的玩家。"}'::jsonb, '"https://media.valorant-api.com/agents/22697a3d-45bf-8dd7-4fec-84a9e28c69d7/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('601dbbe7-43ce-be57-2a40-4abd24953621'::uuid, '{"es-MX":"KAY/O","ar-AE":"كاي/أو","es-ES":"KAY/O","ja-JP":"KAY/O","it-IT":"KAY/O","de-DE":"KAY/O","id-ID":"KAY/O","ko-KR":"케이/오","fr-FR":"KAY/O","en-US":"KAY/O","pl-PL":"KAY/O","pt-BR":"KAY/O","ru-RU":"KAY/O","th-TH":"KAY/O","tr-TR":"KAY/O","vi-VN":"KAY/O","zh-CN":"K/O","zh-TW":"KAY/O"}'::jsonb, '{"es-MX":"KAY/O es una máquina de guerra construida para un único propósito: neutralizar radiantes. Su poder para suprimir las habilidades enemigas neutraliza la capacidad de sus rivales para contraatacar, un aspecto que le da a él y a sus aliados la ventaja definitiva en la batalla.","ar-AE":"كاي/أو هو آلة حربية مصممة لغرض واحد هو القضاء على الراديانتس. تتكفل قوة قَمع الأعداء لديه بتفكيك قدرة خصومه على المقاومة بالقتال، مما يؤمن له ولحلفائه الأفضلية الحاسمة.","es-ES":"KAY/O es una máquina de guerra construida con un único propósito: neutralizar a los radiantes. Su poder para suprimir habilidades enemigas incapacita a sus adversarios, lo que asegura la ventaja para él y sus aliados.","ja-JP":"KAY/O はレディアントの制圧を目的として作られた戦闘兵器だ。その力で敵のアビリティーを封じ込め、反撃の機会を奪うことで、味方の絶対的優位を確保することができる。","it-IT":"KAY/O è una macchina da guerra costruita per un solo scopo: neutralizzare i radianti. La sua capacità di SOPPRIMERE le abilità nemiche compromette le possibilità di risposta degli avversari, dando un enorme vantaggio a lui e ai suoi alleati.","de-DE":"KAY/O ist eine Kriegsmaschine mit nur einem Zweck:  die Neutralisierung von Radiants. Er kann gegnerische Fähigkeiten unterdrücken, womit er Gegenangriffe effektiv verhindert und sich und seinen Verbündeten so den entscheidenden Vorteil verschafft.","id-ID":"KAY/O adalah mesin perang yang dibuat untuk melumpuhkan para radiant. Kekuatannya dalam memberi utilitas Suppress pada ability musuh dapat mencegah mereka untuk melawan balik. Ini memberikan keunggulan besar bagi dirinya dan sekutunya.","ko-KR":"케이/오는 레디언트를 무력화하려는 단 하나의 목적을 위해 만들어진 전쟁 병기입니다. 자신과 아군이 유리하도록 적의 스킬을 억제하여 상대의 반격 능력을 약화시킵니다.","fr-FR":"KAY/O est une machine de guerre conçue dans un but précis : neutraliser les radiants. La neutralisation des compétences ennemies réduit les possibilités de riposte des adversaires, ce qui confère un avantage décisif à son équipe.","en-US":"KAY/O is a machine of war built for a single purpose: neutralizing radiants. His power to Suppress enemy abilities dismantles his opponents'' capacity to fight back, securing him and his allies the ultimate edge.","pl-PL":"KAY/O to maszyna wojenna zbudowana w jednym celu: likwidowanie Promienistych. Jego moc tłumienia wrogich umiejętności ogranicza bojowe możliwości przeciwników, zapewniając KAY/O i jego sojusznikom niesamowitą przewagę.","pt-BR":"KAY/O é uma máquina de guerra construída com um único propósito: neutralizar Radiantes. Ele é capaz de Suprimir habilidades inimigas, anulando a capacidade de contra-ataque dos adversários e dando a si próprio e a seus aliados uma vantagem essencial em combate.","ru-RU":"KAY/O – боевая машина, созданная лишь для одной цели: истребить радиантов. Его способность подавлять умения врага существенно ослабляет команду противника и обеспечивает преимущество союзникам.","th-TH":"KAY/O เป็นจักรกลสงครามที่ถูกสร้างขึ้นเพื่อวัตถุประสงค์เดียว: กำจัด Radiant ความสามารถในการยับยั้งสกิลของศัตรูจะทำลายการตอบโต้จากคู่ต่อสู้ และทำให้เขาและเพื่อนร่วมทีมเอาชนะศึกไปได้ในที่สุด","tr-TR":"KAY/O, Radyantları etkisiz hale getirmek için üretilmiş bir savaş makinesi. Düşmanlarının yeteneklerini Sindirerek karşı koyma yetilerini bastırır. Böylece hem kendisini hem de takım arkadaşlarını korur.","vi-VN":"KAY/O là một cỗ máy chiến tranh được chế tạo vì 1 mục đích duy nhất: vô hiệu hóa kẻ thù. Khả năng Áp Chế kỹ năng của kẻ địch khiến chúng không thể phản kháng chắc chắn sẽ mang đến lợi thế lớn cho KAY/O và đồng đội khi giao chiến.","zh-CN":"K/O是一台战争机器，他被制造出来只有一个目的：消灭源能者。他的能力可以【压制】敌人的技能，为自己与队友制造战术优势。","zh-TW":"KAY/O是一台戰爭機器，其唯一目的是消滅所有輻能者。他可以抑制對手的能力，讓敵人無力還擊，為自身陣營取得絕大優勢。"}'::jsonb, 'Grenadier', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/displayicon.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/displayicon.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/fullportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/fullportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/fullportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/killfeedportrait.png', 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/minimapportrait.png', null, 'https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/background.png', array['1c2a69ff', '0f1923ff', '1a1e4bff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('601dbbe7-43ce-be57-2a40-4abd24953621'::uuid, 'Grenade', '{"es-MX":"FRAG/mentación","ar-AE":"الشظـ/ـية","es-ES":"FRAG/mento","ja-JP":"フラグ/メント","it-IT":"FRAG//ment","de-DE":"FRAG/ment","id-ID":"FRAG/ment","ko-KR":"파편/탄","fr-FR":"FRAG/ment","en-US":"FRAG/ment","pl-PL":"FRAG/ment","pt-BR":"FRAG/mento","ru-RU":"ФРАГ/мент","th-TH":"FRAG/ment","tr-TR":"PARÇA/Tesirli","vi-VN":"LỰU ĐẠN/nổ","zh-CN":"碎片溢出","zh-TW":"碎片/絕殺"}'::jsonb, '{"es-MX":"EQUIPA un fragmento explosivo. DISPARA para lanzarlo. Usa el DISPARO SECUNDARIO para lanzarlo por debajo. El fragmento se pega al piso y explota varias veces, lo que inflige daño casi mortal en el centro con cada explosión.","ar-AE":"تجهز بشظية متفجرة. أطلق لرميها. استخدم الإطلاق البديل للإلقاء المقوس. تنغرز الشظية في الأرض وتنفجر عدة مرات، ملحقة ضررًا يكاد يكون مميتًا في مركز كل انفجار.","es-ES":"EQUIPA un fragmento explosivo. DISPARA para lanzar. Utiliza el DISPARO ALTERNATIVO para tirarlo. El fragmento se adhiere al suelo y explota varias veces, lo que inflige daño casi letal en el centro con cada explosión.","ja-JP":"フラグメントグレネードを構え、「発射」で投げる。「オルト射撃」で軽く放る。地面に吸着したフラグメントは複数回の爆発を起こす。爆発のたび、その中心にいるプレイヤーは致命的なダメージを受ける。","it-IT":"EQUIPAGGIA un frammento esplosivo. Usa il FUOCO per lanciarlo. Usa il FUOCO ALTERNATIVO per lanciare la granata dal basso verso l''alto. Il frammento aderisce al terreno ed esplode più volte, infliggendo danni quasi letali al centro di ogni deflagrazione.","de-DE":"RÜSTE ein Sprengfragment AUS. FEUERE, um zu werfen. ALT. FEUERMODUS zum Fallenlassen. Das Fragment bleibt am Boden haften und explodiert mehrfach. Bei jeder Explosion wird im Zentrum beinahe tödlicher Schaden verursacht.","id-ID":"EQUIP fragmen peledak. Tekan FIRE untuk melempar. Tekan ALT FIRE untuk melempar tinggi. Fragmen ini menancap ke tanah dan meledak beberapa kali, menghasilkan damage yang nyaris mematikan di bagian tengah tiap ledakan.","ko-KR":"폭발하는 파편탄을 장착합니다. 발사하면 투척합니다. 보조 공격 시 높이 던집니다. 파편탄은 바닥에 붙어 여러 차례 폭발하며, 폭발할 때마다 중심부에 있는 적에게 치명적인 피해를 입힙니다.","fr-FR":"ÉQUIPEZ-vous d''un fragment explosif. TIREZ pour le lancer. Utilisez le TIR SECONDAIRE pour le lancer en cloche. Le fragment se colle au sol et explose à plusieurs reprises, infligeant des dégâts quasi mortels au centre de chaque explosion.","en-US":"EQUIP an explosive fragment. FIRE to throw. ALT FIRE to lob. The fragment sticks to the floor and explodes multiple times, dealing near lethal damage at the center with each explosion.","pl-PL":"WYPOSAŻ wybuchowy fragment. STRZEL, by rzucić. Naciśnij ALT. STRZAŁ, by cisnąć. Fragment przyczepia się do ziemi i kilkukrotnie wybucha, zadając niemal śmiertelne obrażenia w centrum każdej z eksplozji.","pt-BR":"EQUIPE um fragmento explosivo. DISPARE para lançar. Use o DISPARO ALTERNATIVO para arremessar a curta distância. O fragmento se fixa ao chão e explode várias vezes, causando dano quase letal no centro de cada explosão.","ru-RU":"Выбирает взрывоопасный фрагмент. Нажмите кнопку ОГОНЬ для броска или АЛЬТ. ОГОНЬ для броска снизу. После приземления фрагмента происходит серия взрывов, каждый из которых наносит практически смертельный урон врагам, находящимся в самом центре.","th-TH":"ติดตั้งเศษชิ้นส่วนระเบิด กดยิงเพื่อขว้าง กดโหมดยิงเสริมเพื่อโยนออกไปในระยะสั้น ๆ เศษชิ้นส่วนจะติดกับพื้นและระเบิดหลายครั้งติดต่อกัน สร้างความเสียหายเกือบถึงตายในพื้นที่ศูนย์กลางหลังการระเบิดแต่ละครั้ง","tr-TR":"Patlayıcı bir şarapnel KUŞAN. Fırlatmak için ATEŞ ET. Yavaşça fırlatmak için ALT. ATIŞ kullan. Şarapnel yere yapışır, sonrasında birden fazla kez patlar ve tam merkezinde bulunanlara neredeyse ölümcül hasar verir.","vi-VN":"TRANG BỊ 1 lựu đạn nổ. BẮN để ném. BẮN PHỤ để ném cao. Lựu đạn nổ khi đáp xuống mặt đất sẽ phát nổ nhiều lần, gây sát thương gần như chí mạng ở trung tâm của mỗi vụ nổ.","zh-CN":"装备一枚碎片手雷。按【射击】将其掷出。按【辅助射击】可轻抛。手雷会粘在地上并多次引爆，每次爆炸对范围中心造成高额伤害。","zh-TW":"裝備一個炸彈碎片。點擊「攻擊」即可拋出，點擊「輔助攻擊」則可低手拋出。附著在地面上後會連續爆炸多次，每次都會在爆炸中心造成幾乎致命性的傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('601dbbe7-43ce-be57-2a40-4abd24953621'::uuid, 'Ability1', '{"es-MX":"Memoria/FLASH","ar-AE":"فلاش/درايف","es-ES":"Unidad/FLASH","ja-JP":"フラッシュ/ドライブ","it-IT":"FLASH//drive","de-DE":"BLEND/granate","id-ID":"FLASH/drive","ko-KR":"플래시/드라이브","fr-FR":"MÉMOIRE/flash","en-US":"FLASH/drive","pl-PL":"dysk/BŁYSK","pt-BR":"GRANADA/clarão","ru-RU":"СВЕТ/овая граната","th-TH":"FLASH/drive","tr-TR":"FLAŞ/Bellek","vi-VN":"LỰU ĐẠN/mù","zh-CN":"闪存过载","zh-TW":"閃光/驅動"}'::jsonb, '{"es-MX":"EQUIPA una granada cegadora. DISPARA para lanzarla por encima. Usa el DISPARO SECUNDARIO para lanzar una versión más débil que explota rápidamente. La granada cegadora explota después de un breve tiempo y ciega a todos en la línea de visión.","ar-AE":"تجهز بقنبلة ضوئية. أطلق لرميها مع رفع ذراعك. استخدم الإطلاق البديل مع تخفيض ذراعك لإلقاء رمية أقل قوة تنفجر بسرعة. تنفجر القنبلة الضوئية بعد انتهاء فتيل قصير، مسببة العمى لكل من يقع في خط الرؤية.","es-ES":"EQUIPA una granada cegadora. DISPARA para lanzar la granada por arriba. Utiliza el DISPARO ALTERNATIVO para lanzar una granada más débil que explota rápidamente. La cegadora explota tras un breve tiempo y ciega a todo el que se encuentre en la línea de visión.","ja-JP":"フラッシュバングレネードを構え、「発射」で投げる。「オルト射撃」は、効果は弱まるが早く爆発するグレネードを軽く放る。グレネードは少ししてから爆発し、視線を向けていたプレイヤー全員の視界を奪う。","it-IT":"EQUIPAGGIA una granata accecante. Usa il FUOCO per lanciarla normalmente. Usa il FUOCO ALTERNATIVO per lanciare dal basso verso l''alto una versione meno potente che esplode più velocemente. La granata esplode dopo un breve istante, ACCECANDO chiunque nel suo campo visivo.","de-DE":"RÜSTE eine Blendgranate AUS. FEUERE, um einen Überhandwurf auszuführen. ALT. FEUERMODUS, um mit einem Unterhandwurf eine schwächere, schnell explodierende Version zu werfen. Die Blendgranate explodiert mit geringer Verzögerung und blendet alle in Sichtweite.","id-ID":"EQUIP granat flash. Tekan FIRE untuk melempar ke atas. Tekan ALT FIRE untuk melempar tinggi granat versi lemah yang meledak lebih cepat. Granat flash meledak setelah beberapa saat, memberikan utilitas Blind pada siapa pun yang melihatnya.","ko-KR":"섬광탄을 장착합니다. 발사하면 멀리 투척합니다. 보조 공격 시 더 일찍 폭발하는 약한 섬광탄을 투척합니다. 섬광탄은 잠시 후 폭발하며 모습이 보이는 대상을 실명시킵니다.","fr-FR":"ÉQUIPEZ-vous d''une grenade aveuglante. TIREZ pour faire un lancer tendu. Utilisez le TIR SECONDAIRE pour la lancer en cloche (plus faible, mais explose plus rapidement). La grenade explose après un court instant et aveugle tous ceux qui voient l''explosion.","en-US":"EQUIP a flash grenade. FIRE to overhand throw. ALT FIRE to lob a weaker version that explodes quickly. The flash grenade explodes after a short fuse, Blinding anyone in line of sight.","pl-PL":"WYPOSAŻ granat błyskowy. STRZEL, by wykonać mocny rzut. Wciśnij ALT. STRZAŁ, aby cisnąć jego słabszą wersję, która szybko wybuchnie. Granat błyskowy eksploduje po krótkiej chwili, oślepiając wszystkich w polu widzenia.","pt-BR":"EQUIPE uma granada de clarão. DISPARE para jogá-la por cima. Use o DISPARO ALTERNATIVO para arremessar a curta distância uma versão mais fraca que explode mais rápido. A granada de clarão explode após um curto período, Cegando qualquer um que estiver na linha de visão.","ru-RU":"Выбирает ослепляющую гранату. Нажмите кнопку ОГОНЬ, чтобы бросить ее навесом. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы сделать бросок снизу менее мощной гранатой, которая быстро сдетонирует. Граната взрывается после небольшой задержки, ослепляя всех в зоне видимости.","th-TH":"ติดตั้งระเบิดแฟลช กดยิงเพื่อขว้าง กดโหมดยิงเสริมเพื่อโยนระเบิดแบบรุนแรงน้อยกว่าที่จะระเบิดอย่างรวดเร็วออกไปในระยะสั้น ๆ ระเบิดแฟลชจะระเบิดหลังจุดชนวนสั้น ๆ ทำให้ผู้เล่นทุกคนที่เห็นมันสูญเสียการมองเห็น","tr-TR":"Bir Kör Edici bomba KUŞAN. Yüksekten fırlatmak için ATEŞ ET. Daha zayıf ama hızlı patlayan bir Kör Edici bomba atmak için ALT. ATIŞ kullan. Kör Edici bomba kısa bir süre sonra patlayarak görüş menzili içinde bulunan herkesi Kör eder.","vi-VN":"TRANG BỊ 1 lựu đạn mù. BẮN để ném tầm cao. BẮN PHỤ để ném lên cao một quả lựu đạn yếu hơn nhưng phát nổ nhanh. Lựu đạn mù sẽ nổ sau một thời gian chờ ngắn, Làm Mù tất cả những ai nhìn thấy nó.","zh-CN":"装备闪光榴弹。按【射击】上手投掷。闪光榴弹会在短暂停留后引爆，将拥有视线的所有人【致盲】。按【辅助射击】可轻抛，掷出一颗效力较弱但引爆更快的闪光弹。","zh-TW":"裝備一個閃光彈，點擊「攻擊」即可高手拋出。點擊「輔助攻擊」則改為低手拋出，爆炸更迅速而威力較弱。引信快速燃盡後爆炸，致盲所有視野內的玩家。"}'::jsonb, '"https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('601dbbe7-43ce-be57-2a40-4abd24953621'::uuid, 'Ability2', '{"es-MX":"Punto/CERO","ar-AE":"نقطة/الصفر","es-ES":"Punto/CERO","ja-JP":"ゼロ/ポイント","it-IT":"ZERO//point","de-DE":"NULL/punkt","id-ID":"ZERO/point","ko-KR":"제로/포인트","fr-FR":"POINT/zéro","en-US":"ZERO/point","pl-PL":"punkt/ZERO","pt-BR":"PONTO/zero","ru-RU":"ЭПИ/центр","th-TH":"ZERO/point","tr-TR":"SIFIR/Noktası","vi-VN":"VÔ/hiệu","zh-CN":"零点嗅探","zh-TW":"歸零/零點"}'::jsonb, '{"es-MX":"EQUIPA una cuchilla de supresión. DISPARA para lanzarla. La cuchilla se pega contra la primera superficie que toca, luego explota y suprime a cualquier oponente que se encuentre en el radio de la explosión. Los enemigos pueden destruir la cuchilla.","ar-AE":"تجهز بسكين قَمع. أطلق لرميها. تنغرز السكين في أول سطح تصيبه، وبعد فترة تقمع كل من هو موجود في نطاق الانفجار. يستطيع الأعداء تدمير هذه السكين.","es-ES":"EQUIPA una cuchilla de supresión. DISPARA para lanzar. La cuchilla se adhiere a la primera superficie a la que golpee, se carga y suprime a cualquiera que se encuentre en el radio de la explosión. Los enemigos pueden destruir la cuchilla.","ja-JP":"サプレッションブレードを構え、「発射」で投げる。ブレードは直撃した場所に突き刺さり、少ししてから爆発する。爆発の範囲内にいた全プレイヤーは抑制状態になる。敵はこのブレードを破壊可能。","it-IT":"EQUIPAGGIA una lama di soppressione. Usa il FUOCO per lanciarla normalmente. La lama aderisce alla prima superficie che colpisce e scoppia dopo un breve tempo di caricamento, SOPPRIMENDO chiunque si trovi nel raggio dell''esplosione. I nemici possono distruggere la lama.","de-DE":"RÜSTE eine Unterdrückungsklinge AUS. FEUERE, um zu werfen. Die Klinge bleibt an der getroffenen Oberfläche stecken, lädt auf und unterdrückt alle im Explosionsradius. Gegner können diese Klinge zerstören.","id-ID":"EQUIP pisau surpression. Tekan FIRE untuk melempar. Pisau menancap ke permukaan pertama yang disentuhnya, lalu mengumpulkan tenaga dan memberikan utilitas Suppress pada siapa pun yang ada di dalam radius ledakannya. Musuh bisa menghancurkan pedang ini.","ko-KR":"제압용 검을 장착합니다. 발사하면 투척합니다. 검은 처음 적중한 표면에 꽂혀 잠시 후 폭발하며, 범위 내에 있는 대상을 모두 제압합니다. 적이 검을 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''une lame neutralisante. TIREZ pour la lancer. La lame se colle à la première surface touchée. Après un délai, elle neutralise tous ceux dans le rayon de l''explosion. Les ennemis peuvent détruire cette lame.","en-US":"EQUIP a suppression blade. FIRE to throw. The blade sticks to the first surface it hits, winds up, and Suppresses anyone in the radius of the explosion. Enemies can destroy this blade.","pl-PL":"WYPOSAŻ tłumiące ostrze. STRZEL, by rzucić. Ostrze wczepia się w pierwszą trafioną powierzchnię, ładuje i tłumi wszystkich przebywających w promieniu eksplozji. Wrogowie mogą je zniszczyć.","pt-BR":"EQUIPE uma lâmina de supressão. DISPARE para lançar. A lâmina se fixa à primeira superfície que atingir e explode, Suprimindo qualquer um que estiver dentro do raio da explosão. Inimigos podem destruir a lâmina.","ru-RU":"Выбирает подавляющий клинок. Нажмите кнопку ОГОНЬ для броска. Клинок взрывается в том месте, куда приземляется, и подавляет всех в радиусе взрыва. Враги могут уничтожить клинок.","th-TH":"ติดตั้งใบมีดยับยั้งพลัง กดยิงเพื่อขว้าง ใบมีดจะติดกับพื้นผิวแรกที่โดน ชาร์จสักครู่ แล้วยับยั้งพลังของทุกคนที่อยู่ในรัศมีระเบิด ศัตรูสามารถทำลายใบมีดนี้ได้","tr-TR":"Düşmanları Sindirmeni sağlayan bir bıçak KUŞAN. Fırlatmak için ATEŞ ET. Bıçak isabet ettiği ilk yüzeye saplanır ve kısa bir süre sonra patlayarak menzili içindeki düşmanları Sindirir. Düşmanlar bu bıçağı yok edebilir.","vi-VN":"TRANG BỊ 1 lưỡi dao áp chế. BẮN để ném. Lưỡi dao sẽ cắm vào bề mặt đầu tiên chạm phải, sau một khoảng thời gian sẽ phát nổ và Áp Chế tất cả những ai trong tầm ảnh hưởng. Đối thủ có thể phá hủy lưỡi dao này.","zh-CN":"装备一把压制匕首。按【射击】将其掷出。匕首将粘附在碰到的首个表面，在一段引导时间后对其范围内的所有人造成【压制】。匕首可被敌人摧毁。","zh-TW":"裝備一把抑制刃。點擊「攻擊」即可拋出，附著在第一個擊中的物體表面上，進行發動，並抑制所有在爆炸範圍內的玩家。敵軍可破壞這把刀。"}'::jsonb, '"https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('601dbbe7-43ce-be57-2a40-4abd24953621'::uuid, 'Ultimate', '{"es-MX":"NULL/cmd","ar-AE":"أمر/الإلغاء","es-ES":"Cmd/ANULAR","ja-JP":"ヌル/コマンド","it-IT":"NULL//cmd","de-DE":"NULL/cmd","id-ID":"NULL/cmd","ko-KR":"무력화/명령","fr-FR":"CMD/null","en-US":"NULL/cmd","pl-PL":"NULL/cmd","pt-BR":"ANULAR/cmd","ru-RU":"NULL/cmd","th-TH":"NULL/cmd","tr-TR":"İPTAL/Komut","vi-VN":"NULL/cmd","zh-CN":"无效命令","zh-TW":"無效/指令"}'::jsonb, '{"es-MX":"Se sobrecarga INSTANTÁNEAMENTE con energía polarizada de radianita que emana de KAY/O en un radio masivo. Los enemigos impactados por las ondas de energía quedan suprimidos durante un breve periodo. Mientras está sobrecargado, KAY/O obtiene Potenciador de combate y, si es derribado, pueden volver a estabilizarlo.","ar-AE":"احصل على شحنة زائدة فورية من طاقة الراديانايت المستقطبة التي تنبض من كاي/أو ضمن نطاق ضخم. يتعرض الأعداء المصابون بالنبضات لتأثير القَمع لفترة قصيرة. في طور الشحن الزائد، يكسب كاي/أو محفز قتال ويمكنه استعادة توازنه في حال سقوطه.","es-ES":"Experimenta una sobrecarga INSTANTÁNEA de energía de radianita polarizada en forma de pulsos de gran radio que se emiten desde KAY/O. Los enemigos que reciban el impacto de pulsos quedan silenciados durante un breve periodo de tiempo. Cuando está sobrecargado, KAY/O se aplica Estimulante de combate y puede volver a estabilizarse si resulta derribado.","ja-JP":"分極化されたレディアナイトエネルギーによる急激な負荷をかけることで KAY/O を中心とした広範囲にエネルギーパルスを発生させる。パルスが命中した敵は短時間、抑制状態になる。オーバーロード中、KAY/O はバトルスティムを獲得し、倒されても再安定化によって復活可能となる。","it-IT":"KAY/O si sovraccarica ISTANTANEAMENTE con energia di radianite polarizzata e inizia a emettere scariche ad ampio raggio. I nemici colpiti dalle scariche vengono SOPPRESSI per un breve periodo. Mentre è in sovraccarico, KAY/O diventa ENERGIZZATO, e può essere ristabilizzato da un compagno se viene abbattuto.","de-DE":"ÜBERLADE sofort mit polarisierter Radianit-Energie, die in einem riesigen Radius aus KAY/O hervorbricht. Von den Impulsen getroffene Gegner werden kurzzeitig unterdrückt. KAY/O erhält Kampf-Stim, solange er überladen ist, und kann restabilisiert werden, wenn er am Boden ist.","id-ID":"SEKETIKA mengeluarkan energi radianite yang meluap bertahap dari tubuh KAY/O dalam radius yang masif. Musuh yang terkena gelombang ini menerima utilitas Suppress dalam waktu singkat. Saat energinya melampaui batas, KAY/O mendapatkan utilitas Combat Stim yang akan menstabilkan energinya kembali jika dia terbunuh.","ko-KR":"케이/오가 즉시 양극화된 레디어나이트 에너지를 과충전하여 넓은 범위에 파동을 방출합니다. 이 파동에 맞은 적은 짧은 시간 동안 제압됩니다. 케이/오는 과충전된 동안 전투 자극제 효과를 얻으며, 쓰러져도 다시 안정화할 수 있습니다.","fr-FR":"Entrez INSTANTANÉMENT en surcharge, ce qui permet à KAY/O d''émettre des vagues d''énergie radianite polarisée dans un très large rayon. Les ennemis touchés par ces vagues sont neutralisés pendant un court instant. Pendant la surcharge, KAY/O gagne l''effet Stimulant de combat et peut être restabilisé s''il est mis à terre.","en-US":"INSTANTLY overload with polarized radianite energy that pulses from KAY/O in a massive radius. Enemies hit with pulses are Suppressed for a short duration. While overloaded, KAY/O gains Combat Stim and can be re-stabilized if downed.","pl-PL":"NATYCHMIAST przeciąża KAY/O spolaryzowaną energią Promienitu, która emituje impulsy o sporym zasięgu z jego pozycji. Wrogowie trafieni impulsami zostają stłumieni na krótki czas. Podczas przeciążenia KAY/O zyskuje stymulant bitewny, a po jego powaleniu można go ponownie ustabilizować.","pt-BR":"INSTANTANEAMENTE sobrecarrega com energia de Radianita polarizada que emite grandes pulsos energéticos em um raio enorme a partir de onde KAY/O estiver. Inimigos atingidos pelos pulsos são Suprimidos por um curto período. Enquanto estiver sobrecarregado, KAY/O recebe Estimulante de Combate e pode ser reestabilizado se for abatido.","ru-RU":"Мгновенно заряжается энергией поляризованного радианита, которая вызывает мощное излучение там, где находится KAY/O. Излучение ненадолго подавляет врагов, попавших в зону действия. На заряженного KAY/O действует эффект боевого стимулятора, и он может восстановиться при получении смертельного урона.","th-TH":"โอเวอร์โหลดทันทีด้วยการปล่อยคลื่นพลังงาน Radianite เปลี่ยนขั้วจาก KAY/O ในรัศมีกว้างมาก ศัตรูที่โดนคลื่นพลังงานจะถูกยับยั้งพลังเป็นระยะเวลาสั้น ๆ ขณะโอเวอร์โหลด KAY/O จะได้บัฟ Combat Stim และเพื่อนร่วมทีมสามารถชุบชีวิตได้เมื่อหยุดทำงาน","tr-TR":"KAY/O, kutuplaşmış radyanit enerjisiyle ANINDA aşırı yüklenir ve bulunduğu konumdan devasa bir etki alanına sahip enerji dalgaları yayar. Enerji dalgalarının isabet ettiği düşmanlar kısa bir süreliğine Sindirilir. Aşırı yükleme durumundayken KAY/O Kuvvetli Savaş kazanır ve çöktüğünde yeniden stabil hale getirilebilir.","vi-VN":"NGAY LẬP TỨC tải đầy năng lượng radianite phân cực để giải phóng các sóng năng lượng trên diện rộng từ KAY/O. Kẻ địch trúng phải sóng năng lượng này sẽ bị Áp Chế trong một thời gian ngắn. Khi tải đầy năng lượng, KAY/O được Khuấy Động Giao Tranh và có thể được hồi sinh.","zh-CN":"立即超载极化源晶能量，从K/O身上发射出大范围的能量脉冲。被脉冲击中的敌人会在短时间内受到【压制】。在超载期间，K/O获得【作战强化】状态，并能在被击倒后重启再战。","zh-TW":"立刻運轉超載，產生大量極化輻能，並釋放大範圍能量波，被能量波擊中的敵人會暫時遭受抑制。運轉超載時，KAY/O會獲得「激發戰意」增益，停機後可重新啟動。"}'::jsonb, '"https://media.valorant-api.com/agents/601dbbe7-43ce-be57-2a40-4abd24953621/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('6f2a04ca-43e0-be17-7f36-b3908627744d'::uuid, '{"es-MX":"Skye","ar-AE":"سكاي","es-ES":"Skye","ja-JP":"スカイ","it-IT":"Skye","de-DE":"Skye","id-ID":"Skye","ko-KR":"스카이","fr-FR":"Skye","en-US":"Skye","pl-PL":"Skye","pt-BR":"Skye","ru-RU":"Skye","th-TH":"Skye","tr-TR":"SKYE","vi-VN":"Skye","zh-CN":"斯凯","zh-TW":"絲凱"}'::jsonb, '{"es-MX":"Procedentes de Australia, Skye y su manada de bestias se abren paso por territorio hostil. Con sus creaciones que obstaculizan al enemigo y su poder para sanar a los demás, los equipos serán más fuertes y seguros al lado de Skye.","ar-AE":"تتولى سكاي، القادمة من أستراليا، بصحبة أصدقائها من الحيوانات فتح الطريق أمام الفريق في أراضي العدو. مع تكفل كائناتها بإعاقة مخططات العدو، وتمتعها بالقدرة على معالجة الآخرين، يبدو أي فريق أقوى وأكثر أمنًا بوجود سكاي في صفوفه.","es-ES":"Skye y su manada de bestias se abren paso desde Australia y a través de territorio hostil. Sus creaciones obstaculizan los avances enemigos y su capacidad para curar a los demás se ocupa de que, a su lado, su equipo esté a salvo.","ja-JP":"オーストラリアからやってきたスカイは、獣たちとともに敵陣への道を切り開く。スカイは敵を妨害する創造物を生み出すほか、味方を回復する力を持っている。彼女と行動をともにすることで、チームは最小のリスクで最大の力を発揮することができる。","it-IT":"L''australiana Skye e il suo branco di animali aprono la strada nel territorio ostile. Con le sue creazioni, che ostacolano il nemico, e le sue capacità curative, la squadra è più forte e più al sicuro al fianco di Skye.","de-DE":"Die Australierin Skye und ihr Rudel bahnen einen Weg durch gegnerisches Gebiet für das Team. Ihre Geschöpfe behindern den Gegner und durch ihre Heilkräfte kann ihrem Team nichts zustoßen, solange es an ihrer Seite ist.","id-ID":"Berasal dari Australia, Skye dan kawanannya yang buas berjalan menyusuri wilayah-wilayah berbahaya. Dia mampu memberikan heal, sementara makhluk ciptaannya dapat menghambat gerak musuh. Ini menjadikan dirinya adalah tempat paling aman dan kuat bagi para anggota timnya.","ko-KR":"호주 출신의 스카이는 야수 떼와 함께 적대적인 영역에서 길을 개척합니다. 자신의 창조물로 적을 방해하고, 치유력으로 아군을 회복시키며 든든하게 팀을 지원합니다.","fr-FR":"Originaire d''Australie, Skye et sa bande de bêtes sauvages ouvrent la voie à travers les territoires hostiles. Grâce à ses créations qui entravent l''ennemi et à sa faculté à soigner les autres, l''équipe est plus forte et plus en sécurité quand elle compte Skye dans ses rangs.","en-US":"Hailing from Australia, Skye and her band of beasts trailblaze the way through hostile territory. With her creations hampering the enemy, and her power to heal others, the team is strongest and safest by Skye''s side.","pl-PL":"Pochodząca z Australii Skye oraz sfora jej bestii utorują drogę przez terytorium wroga. Osłabiające wroga stwory oraz moc leczenia innych sprawią, że Skye wzmocni drużynę i zapewni jej większe bezpieczeństwo.","pt-BR":"Mandando um salve direto da Austrália, Skye e sua equipe de feras desbravam territórios hostis. Com seus poderes de cura e suas criações que partem pra cima dos inimigos, qualquer equipe ficará mais forte e mais segura tendo Skye como aliada.","ru-RU":"Австралийка Skye и ее звериная стая прокладывают путь по враждебной территории. Ее создания затрудняют продвижение врага, а сама Skye может лечить союзников. С ней команда будет в безопасности и станет сильнее, чем когда-либо.","th-TH":"เสียงกู่ร้องแห่งออสเตรเลีย Skye และเหล่าสัตว์ร้ายของเธอ แผดเผาเส้นทางศัตรูให้ลุกโชน ทีมของคุณจะแข็งแกร่งและปลอดภัยที่สุดเมื่ออยู่เคียงข้าง Skye เธอมาพร้อมกับสิ่งประดิษฐ์ที่ใช้ขัดขวางศัตรู และพลังการฮีลผู้อื่น","tr-TR":"Aramıza Avustralya''dan katılan Skye, beraberinde getirdiği vahşi hayvan ordusuyla birlikte çatışmayı iyiden iyiye kızıştırıyor. Düşmana ayak bağı olan hayvanları ve takım arkadaşlarını iyileştirme yetisiyle, takımının gücünü pekiştiriyor ve takımdaki herkesi kolluyor.","vi-VN":"Đến từ nước Úc hoang dã, Skye cùng các tinh linh của mình sẽ mở đường đột phá dũng mãnh trong những lãnh địa nguy hiểm. Với dàn tạo vật phong phú có nhiệm vụ quấy rối kẻ địch cùng khả năng hồi máu, cô sẽ luôn mang đến cho đồng đội sự an toàn và cho phép họ thỏa sức chiến đấu ở phong độ cao nhất.","zh-CN":"“斯凯”来自大洋洲，带着宠物风风火火地穿越敌人领地是她的标志风格。她不仅可以用她的造物牵制敌人，还能治疗队友，是小队中攻守兼备的一员。","zh-TW":"絲凱來自澳洲，她與她的野獸同伴會勇闖敵區為我方開路。除了能召喚生物妨礙敵軍，她還能治療隊友，因此只要有絲凱在側，肯定能展現隊伍的最強實力，避開凶險局面。"}'::jsonb, 'Guide', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/displayicon.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/displayicon.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/fullportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/fullportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/fullportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/killfeedportrait.png', 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/minimapportrait.png', null, 'https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/background.png', array['436a51ff', '0f1923ff', '4f1413ff', '0f192300'], false, false, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('6f2a04ca-43e0-be17-7f36-b3908627744d'::uuid, 'Ability1', '{"es-MX":"Forjacaminos","ar-AE":"فاتح الطريق","es-ES":"Precursor","ja-JP":"トレイルブレイザー","it-IT":"Apripista","de-DE":"Bahnbrecher","id-ID":"Pembuka Jalan","ko-KR":"정찰자","fr-FR":"Éclaireur","en-US":"Trailblazer","pl-PL":"Wilczy Cios","pt-BR":"Predador Explosivo","ru-RU":"Следопыт","th-TH":"Trailblazer","tr-TR":"AV PEŞİNDE","vi-VN":"Theo Dấu","zh-CN":"辟林之虎","zh-TW":"開路狼鋒"}'::jsonb, '{"es-MX":"EQUIPA un artefacto de tigre de Tasmania. DISPARA para enviar y tomar el control del depredador. Mientras lo controlas, DISPARA para saltar hacia adelante, lo que provoca una explosión contusiva e inflige daño a los enemigos alcanzados directamente.","ar-AE":"تجهّز بحلية نمر تسمانيّ. أطلق لتحرير الحيوان المفترس والسيطرة عليه. أثناء التحكم به، أطلق للقفز نحو الأمام، حيث ينفجر لإحداث صدمة ارتجاجية لدى الارتطام وإلحاق الضرر بالأعداء الذين يصيبهم مباشرة.","es-ES":"EQUIPA un amuleto de lobo marsupial. DISPARA para desplegar al depredador y controlarlo. Mientras se está controlando al lobo, DISPARA para hacer que salte hacia delante y explote, lo que aturde e inflige daño a los enemigos que golpee.","ja-JP":"タスマニアタイガーのトリンケットを構える。「発射」で放った猛獣を操作することができる。操作中は「発射」で前方に飛び込み、ぶつかるとスタンを与える爆発を引き起こす。直接命中した敵にはダメージを与える。","it-IT":"EQUIPAGGIA un tilacino cristallizzato. Usa il FUOCO per mandare in missione il predatore e prenderne il controllo. Una volta assunto il controllo, usa il FUOCO per balzare in avanti, provocando un''esplosione STORDENTE all''impatto e danneggiando i nemici colpiti direttamente.","de-DE":"RÜSTE einen „Tasmanischer Wolf“-Anhänger AUS. FEUERE, um das Raubtier zu entsenden und es zu steuern. FEUERE, um nach vorne zu springen. Löse eine erschütternde Explosion beim Aufprall aus und füge direkt getroffenen Gegnern Schaden zu.","id-ID":"EQUIP hiasan harimau Tasmania. Tekan FIRE untuk mengeluarkan dan mengendalikan predator ini. Saat memegang kendali, tekan FIRE untuk melompat maju, menghasilkan ledakan Concuss saat terbentur dan melukai musuh yang terkena langsung.","ko-KR":"태즈매니아 호랑이 장신구를 장착합니다. 발사하면 호랑이를 보내 조종합니다. 조종 중에 발사하면 전방으로 뛰어올라 충돌 시 폭발하며 뇌진탕을 일으키고 직접 타격한 적에게 피해를 입힙니다.","fr-FR":"ÉQUIPEZ-vous d''une breloque Tigre de Tasmanie. TIREZ pour lancer et prendre le contrôle du prédateur. Lorsque vous le contrôlez, TIREZ pour bondir en avant, ce qui provoque une explosion désorientante à l''impact et blesse les ennemis directement touchés.","en-US":"EQUIP a Tasmanian tiger trinket. FIRE to send out and take control of the predator. While in control, FIRE to leap forward, exploding in a Concussive blast on impact and damaging directly hit enemies.","pl-PL":"WYPOSAŻ błyskotkę z tasmańskim tygrysem. STRZEL, aby wypuścić drapieżnika i przejąć nad nim kontrolę. Kontrolując go, STRZEL, aby skoczyć naprzód, wywołując po zderzeniu ogłuszający wybuch i zadając obrażenia bezpośrednio trafionym wrogom.","pt-BR":"EQUIPE um amuleto de lobo-da-tasmânia. DISPARE para enviá-lo e controlar esse predador. Enquanto estiver no controle, DISPARE para saltar para a frente. O lobo gera uma explosão Concussiva no impacto e causa dano aos inimigos diretamente atingidos.","ru-RU":"Выбирает фигурку тасманского волка. Нажмите кнопку ОГОНЬ, чтобы вызвать хищника и управлять им. Нажмите ОГОНЬ, чтобы животное сделало рывок вперед, вызвало оглушающий взрыв при столкновении и нанесло урон пораженным врагам.","th-TH":"ติดตั้งเครื่องประดับเสือแทสเมเนียน กดยิงเพื่อปล่อยและควบคุมการเคลื่อนไหวของเสือ ขณะควบคุมอยู่ กดยิงเพื่อกระโจนไปข้างหน้า ระเบิดสั่นกระเทือนเมื่อชนเป้าหมาย และสร้างความเสียหายแก่ศัตรูที่โดนกระโจนใส่โดยตรง","tr-TR":"Bir Tazmanya kaplanı figürü KUŞAN. Avcıyı gönderip onu kontrol etmek için ATEŞ ET. Hayvanı kontrol ederken birden ileri atılarak çarpma halinde Sersemletici bir patlamaya sebep olmak ve doğrudan isabet alan düşmanlara hasar vermek için ATEŞ ET.","vi-VN":"TRANG BỊ 1 lưu vật hổ Tasmania. BẮN để giải phóng và điều khiển thú săn mồi. Khi đang điều khiển, BẮN để nhảy về phía trước và phát nổ khi va chạm, gây sát thương lên kẻ địch trực tiếp trúng đòn, đồng thời tỏa ra xung chấn Làm Choáng đối thủ.","zh-CN":"装备袋狼雕饰，按【射击】放出并控制一只兽形造物，在控制期间按【射击】可向前扑出。兽形造物会在碰撞后引爆，对直接命中的敌人造成【震荡】和伤害。","zh-TW":"裝備一個袋狼雕飾。點擊「攻擊」，即可放出猛獸並控制其行動。控制時，點擊「攻擊」可命令其朝前方撲擊，命中時炸出震波暈眩並傷害直接命中的敵軍。"}'::jsonb, '"https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('6f2a04ca-43e0-be17-7f36-b3908627744d'::uuid, 'Ability2', '{"es-MX":"Luz Guía","ar-AE":"الضوء المرشد","es-ES":"Luz guía","ja-JP":"ガイディングライト","it-IT":"Luce guida","de-DE":"Polarstern","id-ID":"Guiding Light","ko-KR":"인도하는 빛","fr-FR":"Guide éclatant","en-US":"Guiding Light","pl-PL":"Przewodnie Światło","pt-BR":"Luz Desbravadora","ru-RU":"Путеводный свет","th-TH":"Guiding Light","tr-TR":"KILAVUZ IŞIK","vi-VN":"Ánh Sáng Dẫn Đường","zh-CN":"引路之隼","zh-TW":"引導之鷹"}'::jsonb, '{"es-MX":"EQUIPA un artefacto de halcón. DISPARA para enviarlo hacia adelante. MANTÉN PRESIONADO EL DISPARO para guiar al halcón en la dirección de tu retícula. VUELVE A USAR mientras el halcón está en vuelo para transformarlo en un destello. El destello alcanza su máxima potencia tras un breve periodo de tiempo durante el vuelo del halcón.","ar-AE":"تجهّز بحلية صقر. أطلق لإرسالها نحو الأمام. تابع الضغط على الإطلاق لتحريك الصقر باتجاه مؤشر التصويب لديك. أعد الاستخدام أثناء طيران الصقر لتحويله إلى قنبلة ضوئية. يبلغ التأثير الضوئي أعلى درجات قوته بعد فترة قصيرة أثناء تحليق الصقر.","es-ES":"EQUIPA un amuleto de halcón. DISPARA para lanzarlo hacia adelante. MANTÉN PULSADO DISPARAR para guiar al halcón en la dirección de la mira. VUELVE A ACTIVAR la habilidad cuando el halcón esté en el aire para transformarlo en un destello cegador. La ceguera alcanza su máxima potencia tras un breve periodo de tiempo durante el vuelo del halcón.","ja-JP":"鷹のトリンケットを構え、「発射」で鷹を前方に放つ。「発射長押し」でクロスヘアの方向に鷹を動かす。飛行中に「再使用」することで、鷹を閃光に変身させる。閃光は、鷹が短時間飛行したあと最大効果に達する。","it-IT":"EQUIPAGGIA un falco cristallizzato. Usa il FUOCO per mandarlo in missione. TIENI PREMUTO IL FUOCO per guidare il falco nella direzione del tuo reticolo. ATTIVA DI NUOVO l''abilità mentre il falco è in volo per trasformarlo in un lampo accecante. Il lampo raggiunge la potenza massima qualche istante dopo che il falco ha preso il volo.","de-DE":"RÜSTE einen „Falken“-Anhänger AUS. FEUERE, um den Falken auszusenden. HALTE FEUERN gedrückt, um den Falken in Richtung deines Fadenkreuzes zu lenken. VERWENDE die Fähigkeit ERNEUT, während der Falke fliegt, um Gegner zu blenden. Die Blendung erreicht ihre maximale Wirkung nach einer kurzen Dauer während des Flugs des Falken.","id-ID":"EQUIP hiasan elang. Tekan FIRE untuk menerbangkannya ke depan, HOLD FIRE untuk memandu elang ke arah crosshair. GUNAKAN LAGI saat elang terbang untuk mengubahnya menjadi kilat. Kilat mencapai potensi maksimum setelah durasi singkat selama elang terbang.","ko-KR":"매 장신구를 장착합니다. 발사하면 매를 전방으로 날립니다. 발사를 길게 누르면 조준점 방향으로 매를 유도합니다. 비행 중에 다시 사용하면 매가 섬광으로 변합니다. 섬광은 매가 날아가고 잠시 후 가장 강력해집니다.","fr-FR":"ÉQUIPEZ-vous d''une breloque Faucon. TIREZ pour lancer l''oiseau devant vous. MAINTENEZ LE TIR pour guider le faucon dans la direction de votre réticule. RÉUTILISEZ la compétence pendant que le faucon est dans les airs pour le transformer en lumière. La lumière atteint son intensité maximale après une courte durée de vol.","en-US":"EQUIP a hawk trinket. FIRE to send it forward. HOLD FIRE to guide the hawk in the direction of your crosshair. RE-USE while the hawk is in flight to transform it into a flash. The flash reaches max potency after a short duration during the hawk''s flight.","pl-PL":"WYPOSAŻ błyskotkę z jastrzębiem. STRZEL, aby wysłać go do walki. PRZYTRZYMAJ STRZAŁ, aby skierować jastrzębia w kierunku wskazanym przez twój celownik. UŻYJ PONOWNIE jastrzębia podczas jego lotu, aby zmienił się w błysk. Błysk osiąga pełną moc po krótkim czasie podczas lotu jastrzębia.","pt-BR":"EQUIPE um amuleto de falcão. DISPARE para enviá-lo. SEGURE O DISPARO para guiar o falcão na direção da sua mira. REPITA a habilidade enquanto ele estiver voando para transformá-lo em um clarão que alcança a potência máxima depois de um curto período durante o voo.","ru-RU":"Выбирает фигурку ястреба. Нажмите кнопку ОГОНЬ, чтобы послать ястреба вперед. Удерживайте кнопку ОГОНЬ, чтобы ястреб летел в направлении вашего прицела. Во время полета птицы используйте умение снова, чтобы ястреб превратился в ослепляющую вспышку. Вспышка набирает полную силу вскоре после начала полета ястреба.","th-TH":"ติดตั้งเครื่องประดับเหยี่ยว กดยิงเพื่อปล่อยเหยี่ยวออกไปข้างหน้า กดยิงค้างไว้เพื่อนำทางเหยี่ยวตามรัศมีเป้าเล็งของคุณ กดใช้งานอีกครั้งในขณะที่เหยี่ยวยังคงบินอยู่เพื่อแปลงร่างมันเป็นแฟลช แฟลชจะเพิ่มประสิทธิภาพสูงสุดหลังจากที่เหยี่ยวบินออกไปเป็นเวลาสั้น ๆ","tr-TR":"Bir şahin figürü KUŞAN. Şahini ileri göndermek için ATEŞ ET. Şahini nişangâhının baktığı tarafa yöneltmek için ATEŞ DÜĞMESİNİ BASILI TUT. Şahini havada uçarken Kör Edici bir bombaya çevirmek için yeteneği TEKRAR KULLAN. Şahinin uçuşu başladıktan kısa bir süre sonra Kör Etme maksimum potansiyeline ulaşır.","vi-VN":"TRANG BỊ 1 tinh linh chim ưng. BẮN để phóng nó ra trước. GIỮ BẮN để điều khiển chim ưng theo hướng tâm ngắm. KÍCH HOẠT LẠI khi chim ưng đang bay sẽ biến đổi nó thành một pháo mù. Độ mạnh của pháo mù đạt tối đa sau khi chim ưng đã bay được một khoảng ngắn.","zh-CN":"装备飞鹰雕饰，按【射击】将其放出。【按住射击】可以让飞鹰向准星的方向转弯，【再次按技能键】可以让飞鹰化作闪光弹。闪光弹在飞鹰飞行一小段时间后即可达到最大效能。","zh-TW":"裝備一個飛鷹雕飾。點擊「攻擊」，即可向前放出飛鷹。長按「攻擊」，可讓飛鷹隨著畫面上十字準星的方向轉彎。在飛行時「重施技能」，可將飛鷹化為一道閃光致盲敵人。飛鷹飛行一小段時間後，閃光就會達到最大效果。"}'::jsonb, '"https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('6f2a04ca-43e0-be17-7f36-b3908627744d'::uuid, 'Grenade', '{"es-MX":"Regeneración","ar-AE":"تجدد النمو","es-ES":"Reforestación","ja-JP":"リグロウス","it-IT":"Ricrescita","de-DE":"Gedeihen","id-ID":"Regrowth","ko-KR":"재생","fr-FR":"Revitalisation","en-US":"Regrowth","pl-PL":"Regeneracja","pt-BR":"Reflorescer","ru-RU":"Новая поросль","th-TH":"Regrowth","tr-TR":"DOĞANIN ŞİFASI","vi-VN":"Bừng Sức Sống","zh-CN":"愈生之息","zh-TW":"萌芽重生"}'::jsonb, '{"es-MX":"EQUIPA un artefacto de curación. MANTÉN PRESIONADO EL DISPARO para canalizar, lo que cura aliados dentro del alcance y campo visual. Se puede reutilizar hasta que se agote la energía de curación. Skye no puede curarse a sí misma.","ar-AE":"تجهّز بحلية علاج. تابع الضغط على زر الإطلاق لتوجيه القدرة وعلاج الحلفاء ضمن النطاق ومدى الرؤية. يمكن إعادة استخدامها إلى أن يتم استنزاف كمية علاجها. لا تستطيع سكاي علاج نفسها.","es-ES":"EQUIPA un amuleto de curación. MANTÉN PULSADO para canalizar la habilidad, que cura a los aliados que estén dentro del alcance y del campo de visión. Se puede volver a utilizar hasta que se quede sin curación disponible. Skye no se puede curar a sí misma.","ja-JP":"ヒーリングトリンケットを構える。「発射長押し」で詠唱を行い、可視範囲内にいる味方を回復する。回復可能量を使い切るまで再使用できる。自分自身を回復することはできない。","it-IT":"EQUIPAGGIA un cristallo di guarigione. TIENI PREMUTO il FUOCO per entrare in una canalizzazione e CURARE gli alleati a portata e nel campo visivo. Riutilizzabile finché non esaurisce la carica di guarigione. Skye non può guarirsi da sola.","de-DE":"RÜSTE einen „Heilung“-Anhänger AUS. HALTE FEUERN gedrückt, um zu kanalisieren und Verbündete in Sicht- und Reichweite zu heilen. Kann mehrfach verwendet werden, bis Skyes Heilungsleiste erschöpft ist. Skye kann sich nicht selbst heilen.","id-ID":"EQUIP hiasan untuk heal. HOLD FIRE untuk channeling, Heal sekutu dalam jangkauan dan garis pandang. Bisa digunakan lagi sampai cadangan heal habis. Skye tidak bisa heal dirinya sendiri.","ko-KR":"회복 장신구를 장착합니다. 발사를 길게 누르면 정신 집중하며 범위 내에서 모습이 보이는 아군들을 회복시킵니다. 회복 에너지가 바닥날 때까지 재사용할 수 있습니다. 스카이 자신이 회복할 수는 없습니다.","fr-FR":"ÉQUIPEZ-vous d''une breloque de soin. MAINTENEZ LE TIR pour effectuer une canalisation qui soigne les alliés à portée et dans la ligne de mire. Peut être réutilisé jusqu''à épuisement de la capacité de soin. Skye ne peut pas se soigner.","en-US":"EQUIP a healing trinket. HOLD FIRE to channel, Healing allies in range and line of sight. Can be reused until her healing pool is depleted. Skye cannot heal herself.","pl-PL":"WYPOSAŻ błyskotkę leczenia. PRZYTRZYMAJ STRZAŁ, aby uleczyć sojuszników, którzy są w zasięgu i w polu widzenia. Leczenia można używać do momentu wyczerpania specjalnej puli. Skye nie może leczyć samej siebie.","pt-BR":"EQUIPE um amuleto de cura. SEGURE O DISPARO para canalizar, curando aliados dentro do alcance e na sua linha de visão. Esta habilidade pode ser REPETIDA até a reserva de cura ser esgotada. Skye não pode curar a si mesma.","ru-RU":"Выбирает исцеляющую фигурку. Удерживайте кнопку ОГОНЬ, чтобы лечить союзников в зоне видимости и действия. Можно использовать снова, пока весь запас лечения не израсходуется. Skye не может лечить себя.","th-TH":"ติดตั้งเครื่องประดับฮีล กดยิงค้างไว้เพื่อร่าย ฮีลพันธมิตรในระยะและรัศมีการมองเห็น สามารถใช้ซ้ำได้จนกว่าการฮีลของเธอจะหมดลง Skye ไม่สามารถฮีลตนเองได้","tr-TR":"İyileştiren bir figür KUŞAN. Şifa gücünü odaklayarak menzil içinde ve görüş hattındaki takım arkadaşlarını İyileştirmek için ATEŞ DÜĞMESİNİ BASILI TUT. Bu yetenek, şifa gücü tamamen tükenene kadar birden fazla kez kullanılabilir. Skye kendini iyileştiremez.","vi-VN":"TRANG BỊ 1 lưu vật hồi phục. GIỮ BẮN để vận sức, Hồi Máu cho tất cả đồng minh trong phạm vi và ở trong tầm nhìn. Có thể tái sử dụng cho đến khi hết khả năng hồi phục. Skye không thể hồi máu cho bản thân.","zh-CN":"装备治疗雕饰，【按住射击】开始输出，【治疗】技能范围内且在视线内的队友。在治疗池耗尽前，此技能可重复使用。斯凯无法治疗自己。","zh-TW":"裝備一個治療雕飾。長按「攻擊」即可開始施法，「治療」範圍和視野內的友軍，在治療能量條用完前可重複施放。絲凱無法治療自己。"}'::jsonb, '"https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('6f2a04ca-43e0-be17-7f36-b3908627744d'::uuid, 'Ultimate', '{"es-MX":"Buscadores","ar-AE":"الملاحقون","es-ES":"Buscadores","ja-JP":"シーカー","it-IT":"Cercatori","de-DE":"Rudel","id-ID":"Seekers","ko-KR":"추적자","fr-FR":"Traqueurs","en-US":"Seekers","pl-PL":"Szperacze","pt-BR":"Rastreadores","ru-RU":"Ищейки","th-TH":"Seekers","tr-TR":"İZSÜRENLER","vi-VN":"Tinh Linh Dò Đường","zh-CN":"追猎之灵","zh-TW":"追獵精靈"}'::jsonb, '{"es-MX":"EQUIPA un artefacto de buscador. DISPARA para enviar a tres buscadores para rastrear a los tres enemigos más cercanos. Si un buscador alcanza su objetivo, lo ofusca. Los enemigos pueden destruir el buscador.","ar-AE":"تجهّز بحلية ملاحق. أطلق لإرسال ثلاثة ملاحقين يطاردون أقرب ثلاثة من الأعداء. عندما يبلغ أحد الملاحقين هدفه، يصيبه بتأثير ضعف البصر. يستطيع الأعداء تدمير الملاحقين.","es-ES":"EQUIPA un amuleto de buscador. DISPARA para desplegar tres buscadores que localizan a los tres enemigos más cercanos. Si un buscador alcanza a su objetivo, limita su visión. Los enemigos pueden destruir a los Buscadores.","ja-JP":"シーカートリンケットを構える。「発射」で3体のシーカーを放ち、最も近くにいる敵3体を追跡させる。シーカーがターゲットに到達すると、対象の視界を悪化させる。敵はシーカーを破壊可能。","it-IT":"EQUIPAGGIA un cercatore cristallizzato. Usa il FUOCO per inviare tre cercatori a inseguire i tre nemici più vicini. Se un cercatore raggiunge il suo bersaglio, lo ANNEBBIA. I nemici possono distruggere i cercatori.","de-DE":"RÜSTE einen „Rudel“-Anhänger AUS. FEUERE, um drei Sucher auf die drei nahegelegensten Gegner zu hetzen. Wenn ein Sucher sein Ziel findet, wird dessen Sicht eingeschränkt. Gegner können das Rudel zerstören.","id-ID":"EQUIP hiasan Seeker. Tekan FIRE untuk mengeluarkan tiga Seeker untuk melacak tiga musuh terdekat. Jika mencapai targetnya, Seeker menerapkan Nearsight pada mereka. Musuh bisa menghancurkan Seeker.","ko-KR":"추적자 장신구를 장착합니다. 발사하면 추적자 셋을 보내 가장 가까운 적 셋을 쫓습니다. 추적자가 표적에 다다르면 해당 적의 시야를 제한합니다. 적이 추적자를 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''une breloque Traqueurs. TIREZ pour lancer trois traqueurs qui pourchasseront les trois ennemis les plus proches. Si un traqueur atteint sa cible, il réduit le champ de vision de celle-ci. Les ennemis peuvent détruire les traqueurs.","en-US":"EQUIP a Seeker trinket. FIRE to send out three Seekers to track down the three closest enemies. If a Seeker reaches its target, it Nearsights them. Enemies can destroy the Seekers.","pl-PL":"WYPOSAŻ błyskotkę Szperaczy. STRZEL, aby wysłać trzech Szperaczy, którzy wytropią trzech najbliższych wrogów. Trafienie wroga przez Szperacza wywoła krótkowzroczność. Wrogowie mogą go zniszczyć.","pt-BR":"EQUIPE um amuleto de Rastreador. DISPARE para enviar três Rastreadores que localizarão os três inimigos mais próximos. Se um Rastreador alcançar um alvo, ele causará Visão Turva a esse inimigo. Inimigos podem destruir os Rastreadores.","ru-RU":"Выбирает фигурку ищеек. Нажмите кнопку ОГОНЬ, чтобы вызвать троих ищеек, которые выслеживают ближайших противников. Ищейка ограничивает обзор у найденной цели. Враги могут уничтожить ищеек.","th-TH":"ติดตั้งเครื่องประดับ Seeker กดยิงเพื่อส่ง Seeker ออกไปสามตัวและล่าตำแหน่งของศัตรูสามคนที่อยู่ใกล้ที่สุด เมื่อถึงตัวเป้าหมาย Seeker จะจำกัดการมองเห็นของศัตรูทันที ศัตรูสามารถทำลาย Seeker ได้","tr-TR":"Bir İzsüren figürü KUŞAN. En yakındaki üç düşmanın peşine düşecek üç tane İzsüren göndermek için ATEŞ ET. Bir İzsüren hedefine ulaştığında, hedefin Görüşünü Kısıtlar. Düşmanlar İzsürenleri yok edebilir.","vi-VN":"TRANG BỊ 1 lưu vật Tinh Linh Dò Đường. BẮN để giải phóng 3 Tinh Linh Dò Đường có khả năng truy đuổi 3 kẻ địch gần nhất. Khi trúng vào kẻ địch, Tinh Linh Dò Đường sẽ khiến đối thủ bị Hạn Chế Tầm Nhìn. Kẻ địch có thể phá hủy Tinh Linh Dò Đường.","zh-CN":"装备追猎者雕饰。按【射击】即可派出三个追猎之灵，对三名距离最近的敌人进行追踪。如果追猎之灵接触到目标，即可使其【视野收缩】。追猎之灵可被敌人摧毁。","zh-TW":"裝備一個追獵精靈雕飾。點擊「攻擊」，即可放出三隻精靈，追獵三名距離最近的敵軍。精靈觸及目標時會使其視野受到限制。敵軍可破壞追獵精靈。"}'::jsonb, '"https://media.valorant-api.com/agents/6f2a04ca-43e0-be17-7f36-b3908627744d/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('117ed9e3-49f3-6512-3ccf-0cada7e3823b'::uuid, '{"es-MX":"Cypher","ar-AE":"سايفر","es-ES":"Cypher","ja-JP":"サイファー","it-IT":"Cypher","de-DE":"Cypher","id-ID":"Cypher","ko-KR":"사이퍼","fr-FR":"Cypher","en-US":"Cypher","pl-PL":"Cypher","pt-BR":"Cypher","ru-RU":"Cypher","th-TH":"Cypher","tr-TR":"CYPHER","vi-VN":"Cypher","zh-CN":"零","zh-TW":"瑟符"}'::jsonb, '{"es-MX":"Cypher, el agente de inteligencia marroquí, es un sistema de vigilancia de un solo hombre que puede monitorear todos los movimientos de sus enemigos. No hay secreto que no descubra ni maniobra que no detecte. Cypher siempre está vigilando.","ar-AE":"يعتبر سمسار المعلومات المغربي المعروف باسم سايفر شبكة مراقبة في رجل واحد قادر على رصد كل تحركات الأعداء. لا يخفى عليه أي سر. ولا تنطلي عليه أي حيلة. سايفر يقظ دائمًا.","es-ES":"Cypher es un experto en información de Marruecos que se especializa en redes de vigilancia y es capaz de seguirle la pista al enemigo constantemente. No hay secreto a salvo ni maniobra que pase desapercibida. Cypher siempre está alerta.","ja-JP":"モロッコの情報屋、サイファーは敵のあらゆる動きを監視する、いわば「一人監視網」である。どんな秘密も安全ではない。どんな企みも見逃されることはない。どんな時もサイファーは見ているのだ。","it-IT":"Il mercante d''informazioni marocchino Cypher agisce come una rete di sorveglianza che tiene sotto controllo ogni mossa del nemico. Nessun segreto è al sicuro. Nessuna manovra passa inosservata. Cypher è sempre all''erta.","de-DE":"Der marokkanische Informationshändler Cypher ist ein Ein-Mann-Überwachungskommando, das die Bewegungen des Gegners genau im Blick behält. Kein Geheimnis ist sicher. Kein Manöver bleibt unbeobachtet. Cypher entgeht nichts.","id-ID":"Seorang perantara informasi dari Maroko, Cypher, adalah jaringan pengintai yang dioperasikan satu orang yang mengawasi tiap gerakan musuh. Tidak ada rahasia yang aman. Tidak ada manuver yang tidak terlihat. Cypher selalu mengawasi.","ko-KR":"걸어 다니는 감시망이라고도 할 수 있는 모로코 출신의 정보 브로커 사이퍼는 적의 움직임과 정보를 끊임없이 감시합니다. 어떤 비밀이나 속임수를 감추고 있든 끈질기고 날카로운 사이퍼의 시선을 피할 방법은 없습니다.","fr-FR":"Véritable réseau de surveillance à lui tout seul, le vendeur d''informations marocain Cypher est capable de traquer les moindres déplacements de l''ennemi. Il révèle tous les secrets. Il détecte toutes les manœuvres. Rien n''échappe à Cypher.","en-US":"The Moroccan information broker, Cypher is a one-man surveillance network who keeps tabs on the enemy''s every move. No secret is safe. No maneuver goes unseen. Cypher is always watching.","pl-PL":"Cypher, marokański broker informacji, to jednoosobowa sieć inwigilacyjna, pozwalająca śledzić wszelkie poczynania wroga. Żadna tajemnica nie jest bezpieczna. Nikt nie przejdzie niezauważony. Cypher zawsze obserwuje.","pt-BR":"Cypher, um vendedor de informações do Marrocos, é uma verdadeira rede de vigilância de um homem só que fica de olho em cada movimento dos inimigos. Nenhum segredo está a salvo. Nenhuma manobra passa despercebida. Cypher está sempre vigiando.","ru-RU":"Торговец информацией из Марокко Cypher может самостоятельно создать целую информационную сеть для отслеживания действий противника. Под неусыпным взором Cypher все тайное становится явным.","th-TH":"Cypher นายหน้าค้าข้อมูลแห่งโมร็อกโก เขาเป็นหน่วยเฝ้าระวังที่ทำงานเพียงลำพังเพื่อตามติดความเคลื่อนไหวของศัตรูในทุกย่างก้าว ไม่มีความลับใดที่ปลอดภัย ไม่มีการซ่อนเร้นไหนที่รอดพ้นสายตาของเขา เพราะ Cypher นั้นจับจ้องอยู่เสมอ\n","tr-TR":"Faslı bilgi uzmanı ve tek kişilik gözetleme ağı Cypher, düşmanın her hareketini bilir. Her sırrını duyar. Her manevrasını görür. Cypher''ın gözleri hep üzerinizdedir.","vi-VN":"Là một chuyên gia môi giới thông tin người Ma-rốc. Cypher có thể theo dõi mọi di chuyển của đối thủ với hệ thống giám sát tinh vi của mình. Mọi bí mật đều sẽ bị phát hiện. Mọi bước đi đều sẽ bị phát giác. Không gì có thể lọt khỏi mắt của Cypher.","zh-CN":"情报贩子“零”来自直布罗陀海峡南岸，他堪比人形情报网络，紧密地监视着敌人的一举一动。在他的眼皮底下没有秘密，也没有人能瞒天过海。","zh-TW":"瑟符是摩洛哥的情報販子，隻身一人便是頂尖情報中心，窺探著敵人的一舉一動。沒有機密是安全的，沒有計謀可以逃過他的法眼。瑟符永遠監視著你。"}'::jsonb, 'Gumshoe', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/displayicon.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/displayicon.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/fullportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/fullportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/fullportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/killfeedportrait.png', 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/minimapportrait.png', null, 'https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/background.png', array['2f5078ff', '0f1923ff', '3f3f6cff', '0f192300'], true, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('117ed9e3-49f3-6512-3ccf-0cada7e3823b'::uuid, 'Ability1', '{"es-MX":"Ciberjaula","ar-AE":"المصيدة الإلكترونية","es-ES":"Prisión cibernética","ja-JP":"サイバーケージ","it-IT":"Gabbia statica","de-DE":"Cyberkäfig","id-ID":"Cyber Cage","ko-KR":"사이버 감옥","fr-FR":"Cybercage","en-US":"Cyber Cage","pl-PL":"Cyberklatka","pt-BR":"Jaula Cibernética","ru-RU":"Киберклетка","th-TH":"Cyber Cage","tr-TR":"SİBER KAFES","vi-VN":"Lồng Công Nghệ","zh-CN":"赛博囚笼","zh-TW":"網戰牢籠"}'::jsonb, '{"es-MX":"Lanza AL INSTANTE una ciberjaula frente a Cypher. ACTÍVALA para crear una zona que bloquea la visión y reproduce una señal auditiva cuando los enemigos la atraviesan.","ar-AE":"ارمِ بشكل فوري المصيدة الإلكترونية أمام سايفر. قم بالتفعيل لإنشاء نطاق يحجب الرؤية ويصدر إشارة صوتية عندما يمر الأعداء عبره.","es-ES":"Lanza de INMEDIATO la prisión cibernética frente a Cypher. ACTÍVALA para crear una zona que bloquea la visión y emite un sonido cuando los enemigos la atraviesan.","ja-JP":"自分の前方にサイバーケージを投げる。「発動」で中に入った敵の視線を遮り、敵の通過を音で知らせる空間を作り出す。","it-IT":"Lancia ALL''ISTANTE la gabbia statica davanti a Cypher. ATTIVA per creare una zona che blocca la visione e riproduce un segnale sonoro quando i nemici la attraversano.","de-DE":"Wirf den Cyberkäfig SOFORT vor Cypher. AKTIVIERE, um eine Zone zu erschaffen, die Gegnern die Sicht nimmt und ein Audiosignal abspielt, wenn sie hindurchlaufen.","id-ID":"SEKETIKA melempar cyber cage ke depan Cypher. AKTIFKAN untuk membuat zona yang menghalangi pandangan dan memainkan sinyal audio saat musuh melewatinya.","ko-KR":"사이버 감옥을 장착합니다. 발사하면 사이퍼 앞에 사이버 감옥을 던집니다. 활성화하면 시야를 차단하는 구역이 생성되어 적이 지나갈 때 신호음이 울립니다.","fr-FR":"Lancez INSTANTANÉMENT la cybercage devant Cypher. ACTIVEZ pour créer une zone qui bloque la vision et qui émet un signal sonore quand des ennemis la traversent.","en-US":"INSTANTLY toss the cyber cage in front of Cypher. ACTIVATE to create a zone that blocks vision and plays an audio cue when enemies pass through it.","pl-PL":"NATYCHMIAST rzuć cyberklatkę przed Cyphera. AKTYWUJ, by stworzyć obszar, który blokuje wizję i odtwarza podpowiedź dźwiękową, kiedy przechodzą przez niego wrogowie.","pt-BR":"INSTANTANEAMENTE joga a jaula cibernética diante de Cypher. ATIVE para criar uma Zona que bloqueia a visão e reproduz um sinal de áudio quando inimigos passam por ela.","ru-RU":"Мгновенно бросает клетку перед Cypher. Активируйте ее, чтобы ограничить обзор противников. Клетка издает особый звук, когда через нее проходят противники.","th-TH":"โยน Cyber Cage ไปยังเบื้องหน้าของ Cypher ทันที เปิดใช้งานเพื่อสร้างพื้นที่ที่จะบดบังทัศนวิสัยและส่งเสียงแจ้งเตือนศัตรูเดินผ่าน","tr-TR":"Siber kafesi ANINDA Cypher''ın önüne fırlat. Düşmanlar içinden geçtiğinde ses çıkaran ve görüşü engelleyen bir alan oluşturmak için ETKİNLEŞTİR.","vi-VN":"NGAY LẬP TỨC quăng lồng công nghệ ra phía trước Cypher. TÁI KÍCH HOẠT để tạo một vùng chắn tầm nhìn và tạo âm thanh dễ nhận biết khi đối thủ đi ngang qua.","zh-CN":"向前方投掷赛博囚笼。【激活】即可生成一片阻碍视野的区域，敌人通过时会发出提示音。","zh-TW":"立刻將網戰牢籠拋到瑟符面前。按下「啟動」，可製造出一塊當敵軍通過會發出聲音提示的區域，同時能阻擋視野。"}'::jsonb, '"https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('117ed9e3-49f3-6512-3ccf-0cada7e3823b'::uuid, 'Ability2', '{"es-MX":"Cámara Espía","ar-AE":"كاميرا التجسس","es-ES":"Cámara espía","ja-JP":"スパイカメラ","it-IT":"Spionaggio","de-DE":"Spionagekamera","id-ID":"Spycam","ko-KR":"스파이캠","fr-FR":"Caméra espionne","en-US":"Spycam","pl-PL":"Kamera Szpiegowska","pt-BR":"Câmera de Vigilância","ru-RU":"Камера","th-TH":"Spycam","tr-TR":"GİZLİ KAMERA","vi-VN":"Máy Quay Mật Thám","zh-CN":"战术监控","zh-TW":"監控攝影機"}'::jsonb, '{"es-MX":"EQUIPA una cámara espía. DISPARA para colocarla en la ubicación seleccionada. VUELVE A USAR esta habilidad para tomar el control de la vista de la cámara. Mientras la controlas, DISPARA para lanzar un dardo marcador. Este dardo revelará la ubicación de cualquier jugador impactado. Puedes recogerla para VOLVER A COLOCARLA en otro lugar.","ar-AE":"تجهّز بكاميرا تجسس. أطلق لوضع كاميرا التجسس في الموقع المستهدف. أعد استخدام هذه القدرة للتحكم برؤية الكاميرا. خلال فترة التحكم بالكاميرا، اضغط على زر الإطلاق لإطلاق سهم واسم. سيؤدي هذا السهم إلى كشف موقع أي لاعب يصيبه. يمكن التقاط هذه القدرة لإعادة تثبيتها مرة أخرى.","es-ES":"EQUIPA una cámara espía. DISPARA para colocar la cámara espía en la ubicación objetivo. VUELVE A USAR esta habilidad para controlar la visión de la cámara. Cuando tengas control de la cámara, DISPARA para lanzar un dardo marcador Que revelará la ubicación de cualquier jugador alcanzado. La cámara espía se puede recoger para VOLVER A COLOCARLA.","ja-JP":"スパイカメラを構える。「発射」で狙った地点にスパイカメラを設置する。アビリティーを「再使用」するとカメラの視点を操作することができる。カメラの操作中に「発射」で追跡ダーツを発射する。このダーツが当たったプレイヤーは位置を特定され、現在位置が表示されるようになる。このアビリティーは回収して再設置可能。","it-IT":"EQUIPAGGIA una telecamera spia. Usa il FUOCO per piazzare la telecamera spia nel punto bersagliato. USA DI NUOVO questa abilità per prendere il controllo della visuale della telecamera. Mentre controlli la telecamera, usa il FUOCO per lanciare un dardo tracciante. Questo dardo RIVELERÀ la posizione dei giocatori colpiti. Questa abilità può essere raccolta per essere RIUTILIZZATA.","de-DE":"LEGE eine Spionagekamera AN. FEUERE, um die Spionagekamera am Zielort zu platzieren. REAKTIVIERE diese Fähigkeit, um den Blickwinkel der Kamera zu steuern. FEUERE beim Steuern der Kamera, um einen Ortungspfeil zu verschießen. Dieser Pfeil deckt die Position des getroffenen Spielers auf. Du kannst diese Fähigkeit aufheben, um sie ERNEUT EINZUSETZEN.","id-ID":"EQUIP spycam. Tekan FIRE untuk menempatkan spycam di lokasi target. GUNAKAN LAGI ability ini untuk mengendalikan tampilan kamera. Saat mengendalikan kamera, tekan FIRE untuk menembakkan penanda. Penanda ini akan mengungkap lokasi pemain mana pun yang dikenainya berkat utilitas Reveal. Ability ini bisa diambil untuk DIKERAHKAN LAGI.","ko-KR":"스파이캠을 장착합니다. 발사하면 지정 위치에 스파이캠을 설치합니다. 스킬을 재사용하면 카메라를 조작할 수 있습니다. 조작하는 동안 발사를 누르면 표식용 다트가 발사되며 다트에 맞은 플레이어는 위치가 드러납니다. 이 스킬은 회수하여 다시 설치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''une caméra espionne. TIREZ pour placer la caméra espionne à l''endroit ciblé. RÉUTILISEZ cette compétence pour prendre le contrôle de la caméra. Quand vous contrôlez la caméra, TIREZ pour envoyer une fléchette de marquage. Cette fléchette révélera la position de tout joueur qu''elle a touché. La caméra peut être ramassée pour être REDÉPLOYÉE.","en-US":"EQUIP a spycam. FIRE to place the spycam at the targeted location. RE-USE this ability to take control of the camera''s view. While in control of the camera, FIRE to shoot a marking dart. This dart will Reveal the location of any player struck by the dart. This ability can be picked up to be REDEPLOYED.","pl-PL":"WYPOSAŻ kamerę szpiegowską. STRZEL, by umieścić kamerę w pożądanym miejscu. UŻYJ PONOWNIE tej umiejętności, by wyświetlić obraz z kamery. Pozostając w tym widoku STRZEL, by wypuścić lotkę oznaczającą. Ujawni ona miejsce pobytu każdego trafionego nią gracza. Można go podnieść i UŻYĆ PONOWNIE.","pt-BR":"EQUIPE uma Câmera de Vigilância. DISPARE para colocar a câmera no local-alvo. REPITA a habilidade para controlar a visão da câmera. Enquanto controla a câmera, DISPARE para lançar um dardo marcador. O dardo revelará a localização de qualquer jogador atingido. A câmera pode ser recuperada e REPOSICIONADA.","ru-RU":"Выбирает шпионскую камеру. Нажмите кнопку ОГОНЬ, чтобы поместить камеру на выбранном месте. Используйте умение снова, чтобы управлять камерой. Во время управления камерой нажмите кнопку ОГОНЬ, чтобы выстрелить отслеживающим дротиком. При попадании в игрока дротик показывает его местоположение. Камеру можно подобрать и разместить заново.","th-TH":"ติดตั้ง Spycam กดยิงเพื่อติดตั้ง Spycam ในพื้นที่ที่กำหนดไว้ กดใช้สกิลนี้อีกครั้งเพื่อควบคุมตัวกล้อง ในขณะที่ควบคุมกล้อง กดยิงเพื่อปล่อยลูกดอกระบุตำแหน่ง ลูกดอกนี้จะเปิดเผยตำแหน่งของผู้เล่นที่ถูกยิง อุปกรณ์นี้สามารถเก็บขึ้นมาได้เพื่อติดตั้งใหม่","tr-TR":"Bir gizli kamera KUŞAN. Gizli kamerayı hedef konuma yerleştirmek için ATEŞ ET. Kamera görüşünü kontrol etmek için bu yeteneği TEKRAR KULLAN. Kamera kontrolü sendeyken düşmanları işaretleyen bir iğne fırlatmak için ATEŞ ET. Bu iğne, isabet ettiği herhangi bir düşmanın konumunu Açığa Çıkarır. Bu yeteneği TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin.","vi-VN":"TRANG BỊ 1 máy quay do thám. BẮN để đặt máy quay do thám tại vị trí đã nhắm. TÁI SỬ DỤNG kỹ năng này để kiểm soát góc nhìn của máy quay. Khi đang kiểm soát máy quay, BẮN để phóng 1 phi tiêu đánh dấu. Phi tiêu này sẽ làm Lộ Vị Trí của người chơi bị bắn trúng. Kỹ năng này cho phép bạn nhặt bẫy dây lên và ĐẶT LẠI.","zh-CN":"装备摄像头，按【射击】即可将其布置于目标位置。【再次按技能键】可切换至监控镜头。在使用监控镜头期间按【射击】可发射定位镖，【揭露】所命中目标的位置。此装置可被回收并【重新部署】。","zh-TW":"裝備一個針孔攝影機。點擊「攻擊」，即可將攝影機安裝至指定地點。「重新使用」此技能，可遙控並監視攝影畫面。遙控攝影機時，點擊「攻擊」可射出記號飛鏢，被射中的玩家將被揭露行蹤。可撿起攝影機，然後「重新部署」。"}'::jsonb, '"https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('117ed9e3-49f3-6512-3ccf-0cada7e3823b'::uuid, 'Grenade', '{"es-MX":"Cable Trampa","ar-AE":"سلك التفجير","es-ES":"Cable trampa","ja-JP":"トラップワイヤー","it-IT":"Protocollo di cattura","de-DE":"Fallendraht","id-ID":"Trapwire","ko-KR":"함정","fr-FR":"Fil de détente","en-US":"Trapwire","pl-PL":"Potykacz","pt-BR":"Fio-armadilha","ru-RU":"Растяжка","th-TH":"Trapwire","tr-TR":"BUBİ TUZAĞI","vi-VN":"Bẫy Công Nghệ","zh-CN":"震慑绊线","zh-TW":"陷阱絆索"}'::jsonb, '{"es-MX":"EQUIPA un Cable Trampa. DISPARA para colocar un cable trampa destructible y camuflado en la ubicación seleccionada, que creará una línea entre ese lugar y la pared opuesta. Los jugadores enemigos que activen el cable trampa serán ralentizados y quedarán revelados tras un momento si no destruyen el dispositivo a tiempo. Puedes recogerlo y VOLVER A COLOCARLO.","ar-AE":"تجهّز بسلك تفجير. أطلق كي تثبّت سلك تفجير خفيًا قابلًا للتدمير في الموقع المنشود، مما ينشئ خطًا يمتد بين موقع التثبيت والجدار المقابل له. يتم إبطاء لاعبي العدو الذين يعبرون السلك وكشف موقعهم بعد فترة وجيزة إن لم ينجحوا في تدمير السلك في الوقت المناسب. يمكن التقاط هذه القدرة لإعادة تثبيتها مرة أخرى.","es-ES":"EQUIPA un cable trampa. DISPARA para colocar un cable trampa destructible pero oculto en la ubicación objetivo. Creará una línea que se extiende entre la ubicación en la que se ha colocado y la pared opuesta. Los jugadores enemigos que atraviesen un cable trampa quedarán ralentizados y revelados tras un breve lapso si no logran destruir el dispositivo a tiempo. El cable trampa se puede recoger para VOLVER A COLOCARLO.","ja-JP":"トラップワイヤーを構える。「発射」で狙った地点に秘密工作用の装置を設置し、反対側の壁との間にワイヤーを張り渡す。このワイヤーにかかった敵は、即座に装置を破壊しなかった場合、短時間、スロウ状態となり位置も特定される。このアビリティーは回収して「再設置」することができる。","it-IT":"EQUIPAGGIA una trappola a inciampo. Usa il FUOCO verso un punto per piazzare un cavo invisibile e distruttibile, che va a estendersi dal punto del piazzamento al muro opposto. I giocatori nemici che attraversano il cavo vengono RALLENTATI e RIVELATI dopo un breve periodo se non distruggono in tempo il dispositivo. Questa abilità può essere raccolta per essere RIUTILIZZATA.","de-DE":"RÜSTE einen Fallendraht AUS. FEUERE, um einen zerstörbaren und verdeckten Fallendraht am Zielort zu platzieren, der einen Draht zwischen dem Zielort und der gegenüberliegenden Mauer spannt. Gegnerische Spieler, die durch den Fallendraht laufen, werden nach kurzer Zeit verlangsamt und aufgedeckt, wenn sie das Gerät nicht rechtzeitig zerstören. Du kannst diese Fähigkeit aufheben, um sie ERNEUT EINZUSETZEN.","id-ID":"EQUIP trapwire. Tekan FIRE untuk menempatkan trapwire yang bisa dihancurkan dan tersembunyi di lokasi target. Trapwire juga menghasilkan bentangan garis di antara lokasi penempatan dan dinding di seberangnya. Pemain musuh yang melewati trapwire akan terkena efek Slow dan Reveal setelah beberapa saat jika mereka tidak menghancurkan benda tersebut tepat waktu. Ability ini bisa diambil untuk DIKERAHKAN LAGI.","ko-KR":"함정을 장착합니다. 발사하면 지정 위치에 파괴 가능한 위장 함정을 설치하여 설치 위치와 반대쪽 벽 사이를 연결하는 선을 생성합니다. 함정을 넘어가는 적 플레이어는 제때 장치를 파괴하지 않으면 잠시 후 둔화되고 위치가 드러납니다. 이 스킬은 회수하여 다시 설치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un fil de détente. TIREZ pour placer un fil de détente dissimulé et destructible, créant une ligne qui va du point de placement au mur opposé. Les joueurs ennemis qui franchissent le fil de détente seront ralentis et révélés après un court instant s''ils ne détruisent pas le dispositif dans les temps. Le fil peut être ramassé pour être REDÉPLOYÉ.","en-US":"EQUIP a trapwire. FIRE to place a destructible and covert trapwire at the targeted location, creating a line that spans between the placed location and the wall opposite. Enemy players who cross a trapwire will be Slowed and Revealed after a short period if they do not destroy the device in time. This ability can be picked up to be REDEPLOYED.","pl-PL":"WYPOSAŻ potykacz. STRZEL, by umieścić zniszczalny i ukryty potykacz w pożądanym miejscu, tworząc linkę między tym miejscem a przeciwległą ścianą. Wrodzy gracze, którzy wejdą w potykacz, zostaną spowolnieni i ujawnieni po krótkiej chwili, jeśli nie zniszczą urządzenia dość szybko. Można go podnieść i UŻYĆ PONOWNIE.","pt-BR":"EQUIPE um fio-armadilha. DISPARE para instalar um fio-armadilha oculto e destrutível no local-alvo, criando uma linha entre o local e a parede oposta. Jogadores inimigos que passarem pelo fio sofrerão Lentidão e ficarão Revelados depois de um curto período se não destruírem o dispositivo a tempo. A habilidade pode ser recolhida e REPOSICIONADA.","ru-RU":"Выбирает растяжку. Нажмите кнопку ОГОНЬ, чтобы установить в выбранном месте незаметную растяжку, соединяемую с противоположной стеной. Растяжка через некоторое время замедляет и показывает местоположение попавших в нее противников, если ее не успели уничтожить. Растяжку можно подобрать и разместить заново.","th-TH":"ติดตั้ง Trapwire กดยิงเพื่อติดตั้ง Trapwire ที่ทำลายได้และซ่อนตัวได้ตรงพื้นที่ที่ต้องการ สร้างเซนเซอร์ตรวจจับที่จะเชื่อมระหว่างตำแหน่งที่ติดตั้งกับกำแพงฝั่งตรงข้าม ผู้เล่นศัตรูที่เดินผ่าน Trapwire จะติดสโลว์และถูกเปิดเผยตำแหน่งหลังจากช่วงเวลาสั้น ๆ หากไม่สามารถทำลายกับดักได้ในเวลาที่กำหนด อุปกรณ์นี้สามารถเก็บขึ้นมาได้เพื่อติดตั้งใหม่","tr-TR":"Bir bubi tuzağı KUŞAN. Hedef konuma yok edilebilir, gizli bir bubi tuzağı yerleştirmek için ATEŞ ET. Yerleştirilen konum ile karşısındaki duvar arasına bir hat çekilir. Bubi tuzağına yakalanan düşmanlar cihazı zamanında yok edemedikleri takdirde kısa süre içinde Yavaşlatılır ve Açığa Çıkar. Bu yeteneği TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin.","vi-VN":"TRANG BỊ 1 bẫy dây. BẮN để đặt 1 bẫy dây tàng hình tại vị trí đã nhắm (bẫy dây này có thể bị phá hủy), tạo một đoạn dây căng ngang từ vị trị đặt bẫy đến bức tường đối diện. Đối thủ đi qua bẫy dây sẽ bị Làm Chậm và Lộ Vị Trí sau một thời gian ngắn nếu không kịp phá hủy bẫy dây. Kỹ năng này cho phép bạn nhặt bẫy dây lên và ĐẶT LẠI.","zh-CN":"装备绊线。按【射击】在目标位置与相对的墙体之间形成一条可摧毁的隐蔽绊线。敌方玩家触发绊线后若未及时摧毁该装置，将在短暂延迟后受到【减速】和【揭露】。此装置可被回收并【重新部署】。","zh-TW":"裝備一條陷阱絆索。點擊「攻擊」，在指定地點放置可破壞的隱形絆索，在該位置與對向牆壁之間拉出一條線。觸發絆索的敵軍若未及時摧毀該裝置，經過一小段時間後，將遭到「緩速、暴露行蹤」。可撿起絆索「重新部署」。"}'::jsonb, '"https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('117ed9e3-49f3-6512-3ccf-0cada7e3823b'::uuid, 'Ultimate', '{"es-MX":"Asalto Neural","ar-AE":"السرقة العصبية","es-ES":"Hurto neuronal","ja-JP":"ニューラルセフト","it-IT":"Furto neurale","de-DE":"Neuronaler Diebstahl","id-ID":"Neural Theft","ko-KR":"신경 절도","fr-FR":"Vol neural","en-US":"Neural Theft","pl-PL":"Kradzież Neuronów","pt-BR":"Assalto Neural","ru-RU":"Нейрокража","th-TH":"Neural Theft","tr-TR":"NÖRON HIRSIZI","vi-VN":"Truy Lùng Ký Ức","zh-CN":"神经取析","zh-TW":"神經駭客"}'::jsonb, '{"es-MX":"Úsalo DE INMEDIATO en un enemigo muerto seleccionado para descargar información sobre su equipo. Tras una breve demora, se revelará dos veces la ubicación de todos los jugadores enemigos con vida.","ar-AE":"استخدم هذه القدرة بشكل فوري على جثة عدو مستهدف لتنزيل المعلومات الخاصة بفريقه.  بعد فترة قصيرة، يتم الكشف عن مواقع جميع لاعبي العدو الأحياء مرتين.","es-ES":"Úsalo INSTANTÁNEAMENTE sobre un enemigo muerto para descargar información sobre su equipo.  Tras un breve lapso de tiempo, se revelará dos veces la posición de todos los jugadores enemigos vivos.","ja-JP":"デスした敵を狙って使用すると、相手チームの情報を取得する。取得後しばらくして、生存中のすべての敵の位置を 2 度特定する。","it-IT":"Usa ALL''ISTANTE sull''agente nemico morto che stai puntando per scaricare tutte le informazioni disponibili sulla sua squadra.  Dopo un breve ritardo, la posizione di tutti i giocatori nemici ancora in vita verrà RIVELATA per due volte.","de-DE":"Setze diese Fähigkeit SOFORT bei einem toten Gegner ein, um Informationen zu allen lebenden Gegnern herunterzuladen. Nach einer Verzögerung wird die Position aller lebenden Gegner zweimal aufgezeigt.","id-ID":"SEKETIKA digunakan pada musuh yang mati dan ditarget untuk mendapatkan informasi tentang tim mereka.  Setelah beberapa saat, lokasi semua pemain musuh yang hidup akan terdeteksi dua kali karena utilitas Reveal.","ko-KR":"즉시 대상으로 지정된 사망한 적 플레이어에게 사용해 적 팀의 정보를 다운로드합니다. 잠시 후 생존한 모든 적 플레이어의 위치가 두 번 드러납니다.","fr-FR":"Utilisez cette compétence INSTANTANÉMENT sur le cadavre ennemi ciblé pour télécharger des informations sur son équipe. Après un bref délai, la position de tous les joueurs ennemis en vie est révélée deux fois.","en-US":"INSTANTLY use on a targeted dead enemy to download information on their team.  After a brief delay, the location of all living enemy players will be Revealed twice.","pl-PL":"NATYCHMIAST użyj na obranym za cel zabitym przeciwniku, aby pobrać informacje na temat jego drużyny.  Po chwili położenie wszystkich żywych wrogów zostanie ujawnione dwukrotnie.","pt-BR":"Use INSTANTANEAMENTE num jogador inimigo morto alvejado para baixar informações sobre a equipe dele. Depois de um breve intervalo, a localização de todos os jogadores inimigos ainda vivos será Revelada duas vezes.","ru-RU":"При использовании на мертвом противнике вы мгновенно получаете информацию о вражеской команде. Через некоторое время будет дважды показано местоположение всех живых соперников.","th-TH":"ใช้ร่างของศัตรูที่ถูกสังหารเพื่อดาวน์โหลดข้อมูลของทีมพวกเขามา  และหลังจากเว้นช่วงไปเล็กน้อย จะทำการเผยตำแหน่งของผู้เล่นฝ่ายศัตรูที่มีชีวิตอยู่ทั้งหมดขึ้นมา 2 ครั้ง","tr-TR":"Ölü bir düşman üzerinde ANINDA kullan ve takımı hakkında bilgi indir. Kısa bir gecikmenin ardından hayatta olan diğer düşmanların konumu iki kere Açığa Çıkar.","vi-VN":"NGAY LẬP TỨC sử dụng lên mục tiêu là kẻ địch đã hy sinh, tải xuống thông tin về đội của chúng. Sau một khoảng chờ ngắn, vị trí của tất cả đối thủ còn sống sẽ bị Lộ Diện hai lần.","zh-CN":"对被击败的敌方玩家使用本技能，即可获取敌方队伍的信息。短暂延迟后，【揭露】所有存活敌方玩家的位置两次。","zh-TW":"立刻對瞄準的敵軍遺體使用此技能，可下載敵隊的資訊。短暫延遲之後，所有尚存敵軍的行蹤會「暴露」兩次。"}'::jsonb, '"https://media.valorant-api.com/agents/117ed9e3-49f3-6512-3ccf-0cada7e3823b/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('320b2a48-4d9b-a075-30f1-1f93a9b638fa'::uuid, '{"es-MX":"Sova","ar-AE":"سوفا","es-ES":"Sova","ja-JP":"ソーヴァ","it-IT":"Sova","de-DE":"Sova","id-ID":"Sova","ko-KR":"소바","fr-FR":"Sova","en-US":"Sova","pl-PL":"Sova","pt-BR":"Sova","ru-RU":"Sova","th-TH":"Sova","tr-TR":"SOVA","vi-VN":"Sova","zh-CN":"猎枭","zh-TW":"蘇法"}'::jsonb, '{"es-MX":"Proveniente de la tundra del eterno invierno de Rusia, Sova rastrea, encuentra y elimina a sus enemigos con gran eficiencia y precisión. Su arco personalizado y sus increíbles habilidades de exploración impedirán que sus enemigos puedan esconderse de él. ","ar-AE":"مع ولادته من رحم الشتاء الأزلي المخيم على سهول التندرا في روسيا، يقوم سوفا بالبحث وتقفي الأثر والقضاء على الأعداء بكفاءة ودقة فائقتين. قوسه المصنوع خصيصًا من أجله وقدراته الاستطلاعية المدهشة يضمنان أنك تستطيع الهرب، ولكن لن يمكنك أبدًا الاختباء منه.","es-ES":"Nacido en el eterno invierno de la tundra rusa, Sova destaca a la hora de localizar, perseguir y eliminar a los enemigos con una eficiencia y una precisión inclementes. Su arco personalizado junto con su sobrenatural capacidad de rastreamiento hacen que sea imposible escapar. ","ja-JP":"とこしえの冬、ロシアの凍原で生まれたソーヴァは、冷徹かつ確実に敵を追跡、発見し、そして排除する。たとえ逃げようとしても、彼の特別製の弓と恐るべき偵察アビリティーから身を隠すことはできない。 ","it-IT":"Nato tra le nevi perenni della tundra russa, Sova insegue, trova ed elimina i nemici con precisione e spietata efficienza. Il suo arco modificato, combinato alle sue incredibili doti da ricognitore, lo rendono un cacciatore implacabile. ","de-DE":"Sova stammt aus dem ewigen Winter der russischen Tundra und verfolgt, findet und eliminiert Gegner mit gnadenloser Effizienz und Präzision. Sein Spezialbogen und seine unglaublichen Späherfähigkeiten sorgen dafür, dass du zwar fliehen, aber nicht entkommen kannst. ","id-ID":"Terlahir di teritori tundra Rusia yang diselimuti musim dingin abadi, Sova dapat melacak, menemukan, dan menghabisi musuh dengan efisiensi serta akurasi yang dahsyat. Busur khusus dan ability pengintaiannya yang sangat kuat, dapat memastikan bahwa musuh bisa lari tetapi tidak bisa sembunyi. ","ko-KR":"겨울이 끝없이 이어지는 러시아 툰드라 지대에서 온 소바는 적들을 추적하고 발견하는 능력이 뛰어나며 정밀하면서도 무자비하게 적을 섬멸합니다. 직접 제작한 활과 뛰어난 정찰 스킬은 숨어 있는 적도 놓치지 않습니다.","fr-FR":"Né dans l''hiver éternel de la toundra russe, Sova traque, trouve et élimine ses ennemis avec une efficacité et une précision redoutables. Ses incroyables talents d''éclaireur et son arc personnalisé lui garantissent que sa cible ne fuira jamais très longtemps. ","en-US":"Born from the eternal winter of Russia''s tundra, Sova tracks, finds, and eliminates enemies with ruthless efficiency and precision. His custom bow and incredible scouting abilities ensure that even if you run, you cannot hide. ","pl-PL":"Sova to urodzony w skutej wieczną zimą rosyjskiej tundrze tropiciel, który śledzi, namierza i eliminuje wrogów z bezwzględną skutecznością i precyzją. Jego niestandardowy łuk w połączeniu z niesamowitymi umiejętnościami tropiącymi sprawiają, że nie ma przed nim ucieczki. ","pt-BR":"Nascido sob o eterno inverno das tundras russas, Sova rastreia, encontra e elimina inimigos com eficiência e precisão implacáveis. Seu arco personalizado e suas habilidades inigualáveis de reconhecimento garantem que nenhuma presa escape. ","ru-RU":"Рожденный в вечной мерзлоте российского заполярья, Sova выслеживает и уничтожает противников с холодной расчетливостью и эффективностью. Этот первоклассный разведчик, экипированный особым луком, найдет вас, где бы вы ни прятались. ","th-TH":"Sova เกิดในช่วงฤดูหนาวอันยาวนาน ณ ทุ้งทุนดราแห่งรัสเซีย เขาติดตาม ตามล่า กำจัดศัตรูได้อย่างเด็ดขาดและแม่นยำ ด้วยธนูพิเศษที่ดัดแปลงเอง พร้อมความสามารถในการล่าชั้นเลิศ ต่อให้คุณหนีไปสุดขอบฟ้าก็ไม่มีวันรอดพ้นจากเงื้อมมือของเขา","tr-TR":"Rusya''nın uçsuz bucaksız tundralarında yetişen Sova düşmanlarını acımasız bir verimlilik ve titizlikle tespit eder, izlerini sürer ve onları yok eder. Özel yayı ve sıra dışı iz sürme yetenekleri ile ondan kaçsanız da asla saklanamazsınız. ","vi-VN":"Sinh ra tại vùng lãnh nguyên lạnh giá của nước Nga, Sova có khả năng tìm kiếm, đánh dấu và tiêu diệt đối thủ một cách hiệu quả và chính xác. Sở hữu cây cung đặc chế và những kỹ năng trinh sát hiểm hóc, con mồi của Sova sẽ chẳng bao giờ có thể trốn thoát. ","zh-CN":"”猎枭“生长于终年严寒的北方冻原。他能够精准而高效地追踪、锁定和歼灭敌人。凭借一把特制战弓和无与伦比的侦察能力，他能让猎物无所遁形、无处可逃。 ","zh-TW":"蘇法出生於俄羅斯的永凍冰原，他靠著快捷而精準的身手，緊追在後、曝光敵蹤、將目標無情殲滅。他手持改造弓，結合出色的偵察能力，讓你逃得了一時，躲不過一世。 "}'::jsonb, 'Hunter', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/displayicon.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/displayicon.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/fullportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/fullportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/fullportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/killfeedportrait.png', 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/minimapportrait.png', null, 'https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/background.png', array['355285ff', '0f1923ff', '101c47ff', '0f192300'], false, true, '1b47567f-8f7b-444b-aae3-b0c634622d10'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('320b2a48-4d9b-a075-30f1-1f93a9b638fa'::uuid, 'Ability1', '{"es-MX":"Proyectil Eléctrico","ar-AE":"السهم الصاعق","es-ES":"Flecha explosiva","ja-JP":"ショックボルト","it-IT":"Freccia elettrica","de-DE":"Schockschuss","id-ID":"Shock Bolt","ko-KR":"충격 화살","fr-FR":"Électroflèche","en-US":"Shock Bolt","pl-PL":"Strzała-piorun","pt-BR":"Flecha de Choque","ru-RU":"Шоковая стрела","th-TH":"Shock Bolt","tr-TR":"ŞOK OKU","vi-VN":"Sốc Điện","zh-CN":"雷击箭","zh-TW":"震波箭"}'::jsonb, '{"es-MX":"EQUIPA un arco con un proyectil eléctrico. DISPARA para lanzarlo. El proyectil detonará al impactar y dañará a los jugadores cercanos. MANTÉN PRESIONADO EL DISPARO para aumentar el alcance del proyectil. Usa el DISPARO SECUNDARIO para que la flecha rebote hasta dos veces.","ar-AE":"تجهّز بقوسٍ يطلق سهمًا صاعقًا. أطلق لكي ترمي السهم المتفجر إلى الأمام حتى ينفجر عند الارتطام ويلحق الضرر باللاعبين المتواجدين في الجوار. تابع الضغط على زر الإطلاق لتطيل مدى السهم. استخدم الإطلاق البديل كي تضيف إمكانية ارتداد ذلك السهم مرتين كحد أقصى.","es-ES":"EQUIPA un arco con una flecha explosiva. DISPARA para lanzar la flecha explosiva hacia delante. Explotará cuando impacte e infligirá daño a los enemigos cercanos. MANTÉN PULSADO para ampliar su alcance. Utiliza el DISPARO ALTERNATIVO para añadir hasta dos rebotes a la flecha.","ja-JP":"弓を構え、ショックボルトをつがえる。「発射」でショックボルトを前方に射出する。この矢は着弾すると爆発し、周囲のプレイヤーにダメージを与える。「発射長押し」で矢をより遠くに射ることができる。「オルト射撃」でこの矢を最大 2 回までバウンド可能にする。","it-IT":"EQUIPAGGIA un arco con una freccia elettrica. Usa il FUOCO per scoccare il dardo che esplode al contatto, danneggiando i giocatori vicini. TIENI PREMUTO il FUOCO per estendere la gittata della freccia. Usa il FUOCO ALTERNATIVO per aggiungere fino a due rimbalzi a questa freccia.","de-DE":"LEGE einen Bogen mit einem Schockschuss AN. FEUERE, um einen explodierenden Schuss abzugeben, der beim Aufprall hochgeht und Spielern in der Nähe Schaden zufügt. HALTE FEUERN gedrückt, um die Reichweite des Projektils zu erhöhen. ALT. FEUERMODUS, damit der Schuss bis zu zweimal abprallt.","id-ID":"EQUIP busur dan shock bolt. Tekan FIRE untuk mengirim ledakan petir yang terdetonasi saat menabrak, ledakan tersebut memberikan damage pada pemain di sekitar. HOLD FIRE untuk memperluas jangkauan proyektil dan ALT FIRE untuk menambahkan maksimal dua pantulan pada anak panah ini.","ko-KR":"충격 화살과 활을 장착합니다. 발사하면 충돌 시 폭발해 주변 플레이어에게 피해를 입히는 화살을 전방에 쏩니다. 발사를 길게 누르면 화살의 사거리가 늘어납니다. 보조 공격 시 화살이 최대 두 번 더 튕깁니다.","fr-FR":"ÉQUIPEZ-vous d''un arc et d''une flèche électrique. TIREZ pour décocher la flèche, qui explose à l''impact et blesse les joueurs proches. MAINTENEZ LE TIR pour augmenter la portée du projectile. Utilisez le TIR SECONDAIRE pour ajouter jusqu''à deux rebonds à cette flèche.","en-US":"EQUIP a bow with a shock bolt. FIRE to send the explosive bolt forward, detonating upon collision and damaging players nearby. HOLD FIRE to extend the range of the projectile. ALT FIRE to add up to two bounces to this arrow.","pl-PL":"WYPOSAŻ łuk ze strzałą-piorunem. STRZEL, by wypuścić wybuchową strzałę, która w momencie trafienia eksploduje i zadaje obrażenia pobliskim graczom. PRZYTRZYMAJ STRZAŁ, by zwiększyć zasięg pocisku. Przycisk ALT. STRZAŁU pozwala zwiększyć liczbę odbić strzały o maksymalnie dwa.","pt-BR":"EQUIPE um arco com uma flecha de choque. DISPARE para lançar a flecha, que explode ao impacto, causando dano aos jogadores próximos. SEGURE O DISPARO para estender o alcance do projétil. Use o DISPARO ALTERNATIVO para adicionar até dois ricochetes à flecha.","ru-RU":"Выбирает шоковую стрелу. Нажмите кнопку ОГОНЬ, чтобы выпустить стрелу, летящую по прямой. При столкновении она срабатывает, нанося урон игрокам поблизости. Удерживайте кнопку ОГОНЬ для увеличения дальности выстрела. При нажатии кнопки АЛЬТ. ОГОНЬ стрела отскакивает от стен до двух раз.","th-TH":"ติดตั้งธนูสำหรับยิง Shock Bolt กดยิงเพื่อปล่อยลูกธนูหัวระเบิดไปข้างหน้า โดยจะระเบิดเมื่อปะทะแล้วสร้างความเสียหายแก่ผู้เล่นใกล้เคียง กดยิงค้างไว้เพื่อเพิ่มระยะทางการยิง กดโหมดยิงเสริมเพื่อเพิ่มจำนวนการเด้งของลูกธนูมากขึ้นสูงสุดสองครั้ง","tr-TR":"Şok okuna sahip bir yay KUŞAN. Patlayıcı oku ileri yollamak için ATEŞ ET. Ok çarpışma anında infilak eder ve yakındaki oyunculara hasar verir. Atış mesafesini uzatmak için ATEŞ DÜĞMESİNİ BASILI TUT. Oku iki kereye kadar sektirmek için ALT. ATIŞ kullan.","vi-VN":"TRANG BỊ 1 cây cung bắn tên điện. BẮN để phóng mũi tên điện gây nổ ra phía trước, sẽ kích nổ khi va chạm và gây sát thương lên tất cả người chơi xung quanh. GIỮ BẮN để tăng tầm bắn của mũi tên. BẮN PHỤ để tăng thêm tối đa 2 lần nảy cho mũi tên.","zh-CN":"装备弓和雷击箭，按【射击】即可将箭矢向前射出，箭矢在碰撞物体后爆炸，对附近的玩家造成伤害。【按住射击】可延长投射距离。按【辅助射击】可为该弩箭增加一次弹射次数，最多两次。","zh-TW":"裝備一把弓，配有震波箭。點擊「攻擊」，即可向前射出這支爆破箭，觸物後的爆炸將傷害附近玩家。長按「攻擊」可增加射程。點擊「輔助攻擊」，可使箭矢彈射最多兩次。"}'::jsonb, '"https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('320b2a48-4d9b-a075-30f1-1f93a9b638fa'::uuid, 'Ability2', '{"es-MX":"Proyectil Rastreador","ar-AE":"سهم الاستطلاع","es-ES":"Proyectil de reconocimiento","ja-JP":"リコンボルト","it-IT":"Freccia sonar","de-DE":"Aufklärungsgeschoss","id-ID":"Recon Bolt","ko-KR":"정찰용 화살","fr-FR":"Flèche de reconnaissance","en-US":"Recon Bolt","pl-PL":"Strzała Zwiadowcza","pt-BR":"Flecha Rastreadora","ru-RU":"Разведстрела","th-TH":"Recon Bolt","tr-TR":"KEŞİF OKU","vi-VN":"Tên Do Thám","zh-CN":"寻敌箭","zh-TW":"偵察箭"}'::jsonb, '{"es-MX":"EQUIPA un arco con un proyectil rastreador. DISPARA para lanzarlo. El proyectil se activará al impactar y revelará la ubicación de los enemigos cercanos que estén dentro de su alcance de visión. Los enemigos pueden destruir este proyectil. MANTÉN PRESIONADO EL DISPARO para aumentar el alcance del proyectil. Usa el DISPARO SECUNDARIO para que la flecha rebote hasta dos veces. ","ar-AE":"تجهّز بقوس مع سهم استطلاع. أطلق لإرسال سهم استطلاع إلى الأمام، حيث يتم تفعيله عند الارتطام كاشفًا مواقع الأعداء المحيطين الواقعين ضمن خط رؤية السهم. يستطيع الأعداء تدمير هذا السهم. تابع الضغط على زر الإطلاق لتطيل مدى السهم. استخدم الإطلاق البديل كي تضيف إمكانية ارتداد ذلك السهم مرتين كحد أقصى. ","es-ES":"EQUIPA un arco con un proyectil de reconocimiento. Se activará cuando impacte y revelará la posición de los enemigos que se encuentren en la línea de visión del proyectil. El proyectil puede ser destruido. MANTÉN PULSADO para ampliar su alcance. Utiliza el DISPARO ALTERNATIVO para añadir hasta dos rebotes a la flecha. ","ja-JP":"弓を構え、リコンボルトをつがえる。「発射」でリコンボルトを前方に射出する。この矢は着弾すると起動し、矢の場所から視線が通る周囲のすべての敵の位置を特定する。敵はこのボルトを破壊可能。「発射長押し」で射程距離を伸ばすことができ、「オルト射撃」でこの矢を最大 2 回までバウンド可能にする。 ","it-IT":"EQUIPAGGIA un arco con una freccia sonar. Usa il FUOCO per scoccare la freccia sonar, che si attiva al contatto e RIVELA la posizione dei nemici entro il suo raggio visivo. I nemici possono distruggere la freccia. TIENI PREMUTO il FUOCO per estendere la gittata della freccia. Usa il FUOCO ALTERNATIVO per aggiungere fino a due rimbalzi a questa freccia. ","de-DE":"RÜSTE einen Bogen mit einem Aufklärungsgeschoss AUS. FEUERE, um das Aufklärungsgeschoss abzuschießen. Er wird beim Aufprall aktiviert und deckt die Position von Gegnern in der Nähe auf, die sich im Sichtfeld des Pfeils befinden. Gegner können dieses Projektil zerstören. HALTE FEUERN gedrückt, um die Reichweite des Projektils zu erhöhen. ALT. FEUERMODUS, damit der Schuss bis zu zweimal abprallt. ","id-ID":"EQUIP busur dan recon bolt. Tekan FIRE untuk menembakkan bolt ke depan, yang akan aktif saat menabrak dan mengungkap lokasi musuh selama di garis pandang bolt. Musuh bisa menghancurkan bolt ini. HOLD FIRE untuk menambahkan maksimal dua pantulan pada anak panah ini.","ko-KR":"정찰 화살과 활을 장착합니다. 발사하면 정찰 화살을 전방에 쏘아 화살이 꽂힌 곳을 기준으로 모습이 드러난 주변 적의 위치를 표시합니다. 적이 이 화살을 파괴할 수 있습니다. 발사를 길게 누르면 화살의 사거리가 늘어납니다. 보조 공격 시 화살이 최대 두 번 더 튕깁니다.","fr-FR":"ÉQUIPEZ-vous d''un arc et d''une flèche de reconnaissance. TIREZ pour décocher la flèche, qui s''active à l''impact et révèle la position des ennemis proches se trouvant dans sa ligne de vue. Les ennemis peuvent détruire cette flèche. MAINTENEZ LE TIR pour augmenter la portée du projectile. Utilisez le TIR SECONDAIRE pour ajouter jusqu''à deux rebonds à cette flèche. ","en-US":"EQUIP a bow with recon bolt. FIRE to send the recon bolt forward, activating upon collision and Revealing the location of nearby enemies caught in the line of sight of the bolt. Enemies can destroy this bolt. HOLD FIRE to extend the range of the projectile. ALT FIRE to add up to two bounces to this arrow. ","pl-PL":"WYPOSAŻ łuk ze strzałą zwiadowczą. STRZEL, by posłać przed siebie strzałę zwiadowczą, która w momencie trafienia aktywuje się i ujawnia miejsce pobytu przeciwników będących w polu działania strzały. Wrogowie mogą ją zniszczyć. PRZYTRZYMAJ STRZAŁ, by zwiększyć zasięg pocisku. Przycisk ALT. STRZAŁU pozwala zwiększyć liczbę odbić strzały o maksymalnie dwa. ","pt-BR":"EQUIPE um arco com uma flecha de reconhecimento. DISPARE para lançar a flecha, que é ativada mediante impacto e Revela a localização de quaisquer inimigos próximos da linha de visão. Inimigos podem destruí-la. SEGURE O DISPARO para estender o alcance do projétil. Use o DISPARO ALTERNATIVO para adicionar até dois ricochetes à flecha. ","ru-RU":"Выбирает разведстрелу. Нажмите кнопку ОГОНЬ, чтобы выпустить стрелу, летящую по прямой. При столкновении она активируется, показывая местоположение противников в зоне видимости. Враги могут уничтожить стрелу. Удерживайте кнопку ОГОНЬ для увеличения дальности выстрела. При нажатии кнопки АЛЬТ. ОГОНЬ стрела отскакивает от стен до двух раз. ","th-TH":"ติดตั้งธนูสำหรับยิง Recon Bolt กดยิงเพื่อปล่อย Recon Bolt ไปข้างหน้า จะเปิดใช้งานเมื่อปะทะและเปิดเผยตำแหน่งของผู้เล่นใกล้เคียงที่อยู่ในรัศมีระยะมองเห็นของลูกธนู ศัตรูสามารถทำลายลูกธนูนี้ได้ กดยิงค้างไว้เพื่อเพิ่มระยะทางการยิง กดโหมดยิงเสริมเพื่อเพิ่มจำนวนการเด้งของลูกธนูมากขึ้นสูงสุดสองครั้ง ","tr-TR":"Keşif okuna sahip bir yay KUŞAN. Keşif okunu ileri yollamak için ATEŞ ET. Ok çarpışma anında etkinleşir ve görüş hattı yakınında kalan düşmanların konumunu Açığa Çıkarır. Düşmanlar bu oku yok edebilir. Atış mesafesini uzatmak için ATEŞ DÜĞMESİNİ BASILI TUT. Oku iki kereye kadar sektirmek için ALT. ATIŞ kullan. ","vi-VN":"TRANG BỊ 1 cây cung bắn tên trinh sát. BẮN để phóng 1 mũi tên trinh sát ra phía trước, kích hoạt khi va chạm và làm Lộ Vị Trí của tất cả đối thủ trong phạm vi tầm nhìn của mũi tên. Đối thủ có thể phá hủy mũi tên này. GIỮ BẮN để tăng tầm bắn của mũi tên. BẮN PHỤ để tăng thêm tối đa 2 lần nảy cho mũi tên. ","zh-CN":"装备弓和寻敌箭，按【射击】即可将箭矢向前射出，箭矢在碰撞物体后激活声纳并【揭露】探测范围内的敌人位置。敌人可摧毁该箭矢。【按住射击】可延长投射距离。按【辅助射击】可为该弩箭增加一次弹射次数，最多两次。 ","zh-TW":"裝備一把弓，配有偵察箭。點擊「攻擊」，即可向前射出偵察箭，觸物後將直接啟動，處於偵測範圍內的敵軍將被揭露行蹤，敵軍可破壞此箭。長按「攻擊」可增加射程。點擊「輔助攻擊」，可使箭矢彈射最多兩次。 "}'::jsonb, '"https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('320b2a48-4d9b-a075-30f1-1f93a9b638fa'::uuid, 'Grenade', '{"es-MX":"Dron Búho","ar-AE":"درون البومة","es-ES":"Dron de reconocimiento","ja-JP":"オウルドローン","it-IT":"Drone sorvegliante","de-DE":"Eulendrohne","id-ID":"Owl Drone","ko-KR":"올빼미 드론","fr-FR":"Drone rapace","en-US":"Owl Drone","pl-PL":"Sowi Dron","pt-BR":"Drone Coruja","ru-RU":"Дрон-сова","th-TH":"Owl Drone","tr-TR":"BAYKUŞ DRON","vi-VN":"Drone Do Thám","zh-CN":"枭型无人机","zh-TW":"夜梟無人機"}'::jsonb, '{"es-MX":"EQUIPA un Dron Búho. DISPARA para desplegarlo y controlar el movimiento del dron. Mientras lo controlas, DISPARA para lanzar un dardo marcador. Este dardo revelará la ubicación de cualquier jugador impactado. Los enemigos pueden destruir el Dron Búho.","ar-AE":"تجهّز بدرون البومة. أطلق لنشر الدرون والتحكم في حركتها. أطلق أثناء التحكم في حركة الدرون لكي ترمي سهمًا واسمًا. سيؤدي هذا السهم إلى كشف موقع أي لاعب يصيبه. يستطيع الأعداء تدمير درون البومة.","es-ES":"EQUIPA un dron de reconocimiento. DISPARA para desplegar el dron y controlar su movimiento. Cuando tengas el control del dron, DISPARA para lanzar un dardo marcador Que revelará la ubicación de cualquier jugador alcanzado. Los enemigos pueden destruir el Dron de reconocimiento.","ja-JP":"フクロウ型のドローンを準備する。「発射」でこのドローンを起動して操作する。ドローンの操作中に「発射」でマーキングダーツを発射する。このダーツが当たったプレイヤーは位置を特定され、現在位置が表示されるようになる。敵はオウルドローンを破壊可能。","it-IT":"EQUIPAGGIA un drone di sorveglianza. Usa il FUOCO per attivare il drone e prenderne il controllo dei movimenti. Mentre controlli il drone, usa il FUOCO per lanciare un dardo tracciante. Questo dardo RIVELERÀ la posizione dei giocatori colpiti. I nemici possono distruggere il drone di sorveglianza.","de-DE":"RÜSTE eine Eulendrohne AUS. FEUERE, um die Drohne einzusetzen und sie zu steuern. FEUERE, während du die Drohne steuerst, um einen Ortungspfeil zu verschießen. Dieser Pfeil deckt die Position des getroffenen Spielers auf. Gegner können die Eulendrohne zerstören.","id-ID":"EQUIP owl drone. Tekan FIRE untuk mengerahkan dan mengendalikan drone. Saat dikendalikan, tekan FIRE untuk menembakkan panah penanda. Panah ini memiliki utilitas Reveal sehingga akan mendeteksi lokasi pemain mana pun yang dikenainya. Musuh bisa menghancurkan Owl Drone.","ko-KR":"올빼미 드론을 장착합니다. 발사하면 드론을 날려 조종합니다. 드론을 조종하는 동안 발사를 누르면 표식용 다트가 발사됩니다. 다트에 맞은 플레이어는 위치가 드러납니다. 적이 올빼미 드론을 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un drone rapace. TIREZ pour déployer et prendre le contrôle du drone. Quand vous contrôlez le drone, TIREZ pour envoyer une fléchette de marquage. Cette fléchette révélera la position de tout joueur qu''elle a touché. Les ennemis peuvent détruire le drone rapace.","en-US":"EQUIP an owl drone. FIRE to deploy and take control of movement of the drone. While in control of the drone, FIRE to shoot a marking dart. This dart will Reveal the location of any player struck by the dart. Enemies can destroy the Owl Drone.","pl-PL":"WYPOSAŻ sowi dron. STRZEL, by wypuścić drona i przejąć nad nim kontrolę. Sterując nim, STRZEL, by wypuścić lotkę oznaczającą. Ujawni ona miejsce pobytu każdego trafionego nią gracza. Wrogowie mogą zniszczyć Sowiego Drona.","pt-BR":"EQUIPE um drone coruja. DISPARE para acionar e pilotar o drone. Enquanto pilota o drone, DISPARE para atirar um dardo marcador. O dardo revelará a localização de qualquer jogador atingido. Inimigos podem destruir o Drone Coruja.","ru-RU":"Выбирает дрон-сову. Нажмите кнопку ОГОНЬ, чтобы выпустить управляемый дрон. Управляя дроном, нажмите кнопку ОГОНЬ, чтобы выстрелить помечающим дротиком. При попадании в игрока дротик показывает его местоположение. Враги могут уничтожить дрон-сову.","th-TH":"ติดตั้ง Owl Drone กดยิงเพื่อปล่อยและควบคุมการเคลื่อนไหวของโดรน ในขณะที่ควบคุมโดรน กดยิงเพื่อปล่อยลูกดอกระบุตำแหน่ง ลูกดอกนี้จะเปิดเผยตำแหน่งของผู้เล่นที่ถูกยิง ศัตรูสามารถทำลาย Owl Drone ได้","tr-TR":"Bir Baykuş Dron KUŞAN. Dronu göndermek ve hareketlerini kontrol etmek için ATEŞ ET. Dronun kontrolü sendeyken düşmanları işaretleyen bir iğne fırlatmak için ATEŞ ET. Bu iğne, isabet ettiği herhangi bir düşmanın konumunu Açığa Çıkarır. Düşmanlar Baykuş Dron''u yok edebilir.","vi-VN":"TRANG BỊ 1 drone cú vọ. BẮN để sử dụng và kiểm soát di chuyển của drone. Khi đang kiểm soát drone, BẮN để phóng 1 phi tiêu đánh dấu. Phi tiêu này sẽ làm Lộ Vị Trí của người chơi bị bắn trúng. Kẻ địch có thể phá hủy Drone Do Thám.","zh-CN":"装备枭型无人机，按【射击】即可部署并操作无人机，在操作期间按【射击】可发射定位镖，【揭露】所命中目标的位置。枭型无人机可被敌人摧毁。","zh-TW":"裝備一台夜梟無人機。點擊「攻擊」即可讓無人機升空並開始遙控。飛行時點擊「攻擊」，可發射記號飛鏢，被射中的玩家將被揭露行蹤。敵軍可破壞夜梟無人機。"}'::jsonb, '"https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('320b2a48-4d9b-a075-30f1-1f93a9b638fa'::uuid, 'Ultimate', '{"es-MX":"Furia del Cazador","ar-AE":"غضب الصياد","es-ES":"Furia del cazador","ja-JP":"ハンターズフューリー","it-IT":"Furia del cacciatore","de-DE":"Zorn des Jägers","id-ID":"Hunter''s Fury","ko-KR":"사냥꾼의 분노","fr-FR":"Fureur du chasseur","en-US":"Hunter''s Fury","pl-PL":"Furia Łowcy","pt-BR":"Fúria do Caçador","ru-RU":"Гнев охотника","th-TH":"Hunter''s Fury","tr-TR":"AVCININ HİDDETİ","vi-VN":"Thợ Săn Cuồng Nộ","zh-CN":"狂猎之怒","zh-TW":"獵者之怒"}'::jsonb, '{"es-MX":"EQUIPA un arco con tres ráfagas de energía de largo alcance que atraviesan las paredes. DISPARA para lanzar una ráfaga de energía frente a Sova que infligirá daño y revelará la ubicación de los enemigos impactados. Puedes VOLVER A USAR esta habilidad hasta dos veces más mientras su contador esté activo.","ar-AE":"تجهّز بقوس وثلاثة أسهم طاقة بعيدة المدى قادرة على اختراق الجدران. أطلق لتحرير سهم طاقة في خط مستقيم أمام سوفا، مما يلحق الضرر ويكشف موقع الأعداء المتواجدين على الخط. يمكن إعادة استخدام هذه القدرة حتى مرتين إضافيتين أثناء استمرار عمل مؤقت القدرة.","es-ES":"EQUIPA un arco con tres proyectiles de energía de largo alcance que atraviesan paredes. DISPARA para lanzar un proyectil de energía en línea recta frente a Sova, que infligirá daño y revelará la posición de los enemigos que se encuentren a su paso. Esta habilidad puede VOLVERSE A USAR hasta dos veces más mientras el temporizador de la habilidad esté activo.","ja-JP":"弓を構え、3 回分のエナジーブラストを準備する。このエナジーブラストは射程距離が長く、壁を貫通する。「発射」でソーヴァの前方に一直線にエナジーブラストを放ち、巻き込んだ敵にダメージを与えると共に、その位置を特定し、表示する。このアビリティーはタイマーが切れるまでにさらに 2 回「再使用」することができる。","it-IT":"EQUIPAGGIA un arco con tre colpi a lunga gittata che passano attraverso i muri. Usa il FUOCO per rilasciare una scarica di energia in linea retta davanti a Sova, infliggendo danni e RIVELANDO la posizione dei nemici colpiti. Questa abilità può essere RIUTILIZZATA fino a due volte mentre il timer dell''abilità è attivo.","de-DE":"RÜSTE einen Bogen mit drei Energiestößen AUS, die eine große Reichweite haben und Mauern durchdringen. FEUERE, um einen Energiestoß in einer Linie vor Sova zu entfesseln, der Schaden verursacht und die Position von getroffenen Gegnern aufdeckt. Diese Fähigkeit kann bis zu zweimal REAKTIVIERT werden, solange der Timer der Fähigkeit nicht abgelaufen ist.","id-ID":"EQUIP busur dan tiga ledakan jarak jauh yang energinya dapat menembus dinding. Tekan FIRE untuk melepas garis yang memuat ledakan energi dari depan Sova. Garis tersebut menghasilkan damage dan mendeteksi lokasi musuh yang ada di dalamnya. Ability ini bisa DIGUNAKAN LAGI sampai dua kali lagi selama timer ability aktif.","ko-KR":"벽을 관통하는 에너지 3개를 장거리로 발사하는 활을 장착합니다. 발사하면 전방에 일직선상으로 에너지를 날려 닿은 적에게 피해를 입히고 위치를 드러냅니다. 스킬 지속시간이 활성화된 상태에서 최대 두 번 더 다시 사용할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un arc et de trois projectiles d''énergie à longue portée capables de traverser les murs. TIREZ pour décocher un projectile d''énergie en ligne droite, qui inflige des dégâts et révèle la position des ennemis touchés. Cette compétence peut être RÉUTILISÉE jusqu''à deux fois de plus tant que la compétence est active.","en-US":"EQUIP a bow with three long-range, wall-piercing energy blasts. FIRE to release an energy blast in a line in front of Sova, dealing damage and Revealing the location of enemies caught in the line. This ability can be RE-USED up to two more times while the ability timer is active.","pl-PL":"WYPOSAŻ łuk z trzema eksplozjami energii dalekiego zasięgu, przebijającymi ściany. STRZEL, by wypuścić eksplozję energii lecącą na wprost Sovy, zadającą obrażenia i ujawniającą miejsce pobytu przeciwników w jej polu działania. Można jej UŻYĆ PONOWNIE do dwóch razy, dopóki licznik umiejętności jest aktywny.","pt-BR":"EQUIPE um arco com três disparos de longo alcance que perfuram paredes. DISPARE para atirar um raio de energia diante de Sova, causando dano e Revelando a localização dos inimigos que estiverem na linha. A habilidade pode ser REPETIDA até mais duas vezes enquanto o cronômetro de habilidade estiver ativo.","ru-RU":"Выбирает три стрелы с дальнобойными, пробивающими стены импульсами. Нажмите кнопку ОГОНЬ, чтобы выпустить импульс по прямой перед агентом, нанося урон и показывая местоположение всех раненых врагов. Умение можно использовать еще два раза, пока активен таймер.","th-TH":"ติดตั้งธนูด้วยพลังงานที่สามารถยิงทะลุกำแพงสามนัด กดยิงเพื่อปล่อยพลังงานเป็นเส้นด้านหน้า Sova สร้างความเสียหายและเปิดเผยตำแหน่งของศัตรูที่อยู่ในรัศมี สกิลนี้สามารถใช้ซ้ำได้อีกสองครั้งในขณะที่ยังอยู่ในระยะเวลาที่กำหนด","tr-TR":"Üç taneye kadar duvar delici enerji patlaması ateşleyebilen bir yay KUŞAN. Sova''nın önündeki bir hat üzerinde enerji patlamaları oluşturmak ve isabet alan düşmanlara hasar verip konumlarını Açığa Çıkarmak için ATEŞ ET. Bu yetenek, yetenek sayacı etkinken iki kez daha YENİDEN KULLANILABİLİR.","vi-VN":"TRANG BỊ 1 cây cung với 3 mũi tên năng lượng có tầm bắn xa và khả năng xuyên tường. BẮN để phóng 1 mũi tên năng lượng trên đường thẳng ra phía trước Sova, gây sát thương và làm Lộ Vị Trí của đối thủ trên đường đi của mũi tên. Kỹ năng này có thể TÁI SỬ DỤNG tối đa thêm 2 lần nữa khi đồng hồ đếm của kỹ năng đang kích hoạt.","zh-CN":"装备弓和三发可穿墙的远程能量箭。按【射击】即向猎枭的前方发射一道能量冲击波，对直线上的敌人造成伤害并【揭露】其位置。此技能在计时器结束前可【再次使用】最多两次。","zh-TW":"裝備一把弓，配有三發可穿牆的遠距離爆擊光束。點擊「攻擊」，即可在蘇法身前發射一直線的爆擊光束，對擊中的敵軍造成傷害並「揭露」其行蹤。技能啟用期間，還能再「重新施放」最多兩次。"}'::jsonb, '"https://media.valorant-api.com/agents/320b2a48-4d9b-a075-30f1-1f93a9b638fa/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, '{"es-MX":"Miks","ar-AE":"ميكس","es-ES":"Miks","ja-JP":"ミクス","it-IT":"Miks","de-DE":"Miks","id-ID":"Miks","ko-KR":"믹스","fr-FR":"Miks","en-US":"Miks","pl-PL":"Miks","pt-BR":"Miks","ru-RU":"Miks","th-TH":"Miks","tr-TR":"MIKS","vi-VN":"Miks","zh-CN":"迷核","zh-TW":"米克什"}'::jsonb, '{"es-MX":"Miks llega directo desde Croacia para apoderarse del escenario en una explosión de energía sonora. Con una pasión contagiosa y un poder supersónico, motiva al resto del equipo para que avance al unísono mientras marca el ritmo en el campo de batalla.","ar-AE":"من قلب كرواتيا، يعتلي ميكس المسرح مشعًا بطاقة صوتية صافية. وبحماسه المُعدي وقدراته الصوتية، يحشد أعضاء فرقته ليتحركوا بتناغم تام وهم يفرضون إيقاعهم معًا على ساحة المعركة.","es-ES":"Directo desde Croacia, Miks sube al escenario y canaliza energía sónica pura. Con su pasión contagiosa y sus poderes sónicos, reúne a su equipo para avanzar al unísono y seguir el ritmo juntos en el campo de batalla.","ja-JP":"クロアチア出身のミクスは、純粋な音のエネルギーをまといステージに立つ。ほとばしる情熱と音の力で仲間を奮い立たせ、戦場にテンポを刻みながらチームをひとつに導く。","it-IT":"Direttamente dalla Croazia, Miks entra in scena sprigionando pura energia sonora. Con la sua passione contagiosa e i suoi poteri sonici, ispira la sua squadra ad agire all''unisono mentre tutti insieme dettano il ritmo sul campo di battaglia.","de-DE":"Miks aus Kroatien betritt die Bühne und kanalisiert pure Soundenergie. Mit seiner ansteckenden Leidenschaft und seinen Schallkräften motiviert er sein Team, als Einheit zu agieren, während sie gemeinsam den Takt auf dem Schlachtfeld angeben.","id-ID":"Langsung dari Kroasia, Miks naik ke panggung dengan menyalurkan energi suara murni. Dengan semangat yang menular dan kekuatan soniknya, dia menyatukan skuadnya untuk bergerak sebagai satu, mengatur tempo dan menguasai medan pertempuran bersama.","ko-KR":"크로아티아에서 온 믹스가 순수한 소리 에너지를 발산하며 무대에 오릅니다. 그는 전염성 강한 열정과 음파의 힘으로 분대원들을 하나로 뭉치게 하고, 함께 전장의 속도를 조절합니다.","fr-FR":"Tout droit venu de Croatie, Miks monte sur scène en canalisant une énergie sonore pure. Avec sa passion contagieuse et ses pouvoirs soniques, il rassemble son escouade pour avancer à l''unisson et donner le rythme sur le champ de bataille.","en-US":"Straight from Croatia, Miks takes the stage channeling pure sound energy. With his infectious passion and sonic powers, he rallies his squad to move as one as they set the tempo on the battlefield together.","pl-PL":"Prosto z Chorwacji – Miks wchodzi na scenę, emanując czystą energią muzyki. Dzięki swojej zaraźliwej pasji i dźwiękowym mocom zagrzewa swój oddział do wspólnego działania, gdy razem nadają tempo na polu bitwy.","pt-BR":"Diretamente da Croácia, Miks sobe ao palco canalizando pura energia sonora. Com sua paixão contagiante e seus poderes sônicos, ele coordena o esquadrão para que todos se movam em sincronia, ditando juntos o ritmo do campo de batalha.","ru-RU":"На сцену выходит Miks – агент из Хорватии и само воплощение силы звука. Своим оптимизмом и музыкальными способностями Miks побуждает команду действовать как единое целое и задает общий темп на поле боя.","th-TH":"Miks ที่ส่งตรงจากโครเอเชีย พร้อมระเบิดพลังเสียงล้วน ๆ เพื่อขึ้นครองเวทีแล้ว ด้วยความมุ่งมั่นอันเร่าร้อนและพลังคลื่นเสียง เขาจะรวมทั้งทีมให้ลงมืออย่างพร้อมเพรียง คุมจังหวะในสนามรบไปด้วยกัน","tr-TR":"Hırvatistan''dan gelen Miks, saf ses enerjisini sahneye taşıyor. Bulaşıcı tutkusu ve ses dalgalarını kontrol eden güçleriyle ekibini birlikte hareket etmeye teşvik eder ve savaş alanının temposunu beraber değiştirirler.","vi-VN":"Thẳng tiến từ Croatia, Miks bước lên sân khấu, dẫn dắt nguồn năng lượng âm thanh thuần khiết. Với đam mê lan tỏa và sức mạnh sóng âm của mình, anh hiệu triệu đồng đội hòa nhịp như một thể thống nhất, cùng nhau thiết lập nhịp điệu trên chiến trường.","zh-CN":"来自欧洲中南部的“迷核”能够操控纯粹的声波能量。凭借极具感染力的激情和独特的音波力量，他率领全队协同作战，定下战场的主导节奏。","zh-TW":"來自克羅埃西亞的米克什登上舞台，釋放純粹的音浪能量。他憑藉充滿感染力的熱情和音樂的力量，帶領隊伍協同一心，主宰戰場節奏。"}'::jsonb, 'Iris', '2026-03-18T15:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/displayicon.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/displayicon.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/fullportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/fullportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/fullportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/killfeedportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/minimapportrait.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/homescreenpromotileimage.png', 'https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/background.png', array['462b75ff', '0f1923ff', '344673ff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, 'Grenade', '{"es-MX":"Pulso M","ar-AE":"النبضة المدوّية","es-ES":"Pulso disonante","ja-JP":"M-パルス","it-IT":"Impulso","de-DE":"M-Impuls","id-ID":"M-pulse","ko-KR":"M-파동","fr-FR":"M-pulsion","en-US":"M-pulse","pl-PL":"M-puls","pt-BR":"Pulso M","ru-RU":"М-пульс","th-TH":"M-pulse","tr-TR":"M PATLAMASI","vi-VN":"Xung Lực","zh-CN":"电音脉冲","zh-TW":"M脈衝"}'::jsonb, '{"es-MX":"EQUIPA la habilidad Pulso M. Presiona DISPARO SECUNDARIO para alternar entre el modo de conmoción y el de curación. DISPARA para lanzar el dispositivo. Al impactar, Pulso M emite ondas sonoras que conmocionan o curan a los agentes.","ar-AE":"تجهّز بقدرة النبضة المدوّية. اضغط على زر الإطلاق البديل للتبديل بين تأثيري الارتجاج والعلاج. أطلق لرمي الجهاز. عند الهبوط، يرسل جهاز النبضة المدوّية موجات صوتية تُصيب اللاعبين إما بالارتجاج أو العلاج.","es-ES":"EQUIPA Pulso disonante. Utiliza el DISPARO ALTERNATIVO para cambiar entre el modo de conmoción y el de curación. DISPARA para lanzar el dispositivo. Al impactar, Pulso disonante emite ondas sonoras que conmocionan o curan a los jugadores.","ja-JP":"M-パルスを構える。「オルト射撃」でスタンと回復の効果を切り替え、「発射」で投げる。M-パルスは地面に触れると音波を放ち、プレイヤーをスタン状態にするか、回復する。","it-IT":"EQUIPAGGIA un Impulso. Usa il FUOCO ALTERNATIVO per alternare tra STORDIMENTO e CURE. Usa il FUOCO per lanciare il dispositivo. All''atterraggio, l''Impulso emette onde sonore che STORDISCONO o CURANO i giocatori.","de-DE":"RÜSTE M-Impuls AUS. ALT. FEUERMODUS, um zwischen „Betäuben“ und „Heilung“ umzuschalten. FEUERE, um das Gerät zu werfen. Beim Landen sendet M-Impuls Schallwellen aus, die Spieler entweder betäuben oder heilen.","id-ID":"EQUIP M-pulse. Tekan ALT FIRE untuk mengganti output antara Concuss dan Healing. Tekan FIRE untuk melempar alat. Saat mendarat, M-pulse memancarkan gelombang suara yang akan memberikan efek Concuss atau Heal pada pemain yang terkena.","ko-KR":"M-파동을 장착합니다. 보조 공격 시 뇌진탕과 치유 모드를 전환합니다. 발사하면 기기를 던집니다. 지면에 닿으면 M-파동이 음파를 방출해, 플레이어에게 뇌진탕을 일으키거나 체력을 회복시킵니다.","fr-FR":"ÉQUIPEZ M-pulsion. Utilisez le TIR SECONDAIRE pour basculer entre les modes Désorientation et Soin. TIREZ pour lancer l''objet. À l''atterrissage, M-pulsion émet des ondes sonores, qui désorientent ou soignent les joueurs.","en-US":"EQUIP M-pulse. ALT-FIRE to toggle between Concuss and Healing outputs. FIRE to throw the device. Upon landing, M-pulse sends out sound waves, either Concussing or Healing players.","pl-PL":"WYPOSAŻ M-puls. ALT. STRZAŁ przełącza między ogłuszeniem a leczeniem. STRZEL, by rzucić urządzenie. Po wylądowaniu M-puls wysyła fale dźwiękowe, które ogłuszają lub leczą graczy.","pt-BR":"EQUIPE Pulso M. O DISPARO ALTERNATIVO alterna entre Concussão e Cura. DISPARE para lançar o dispositivo. Ao ser posicionado, o Pulso M emite ondas sonoras que causam Concussão ou Curam os jogadores.","ru-RU":"Выбирает \"М-пульс\". Нажимайте кнопку АЛЬТ. ОГОНЬ, чтобы переключаться между режимами оглушения и лечения. Нажмите кнопку ОГОНЬ, чтобы бросить устройство. После приземления \"М-пульс\" распространяет звуковые волны, которые оглушают или лечат игроков.","th-TH":"ติดตั้ง M-pulse กดโหมดยิงเสริมเพื่อสลับระหว่างการมอบสถานะกระทบกระเทือนและการฮีล กดยิงเพื่อขว้างอุปกรณ์ เมื่อตกลงพื้น M-pulse จะส่งคลื่นเสียงออกไป ทำให้ผู้เล่นติดสถานะกระทบกระเทือนหรือได้รับการฮีล","tr-TR":"M Patlaması''nı KUŞAN. ALT. ATIŞ ile Sersemletme ve İyileştirme arasında geçiş yap. Cihazı fırlatmak için ATEŞ ET. M Patlaması yere düştüğünde ses dalgaları yayarak oyunculara Sersemletme veya İyileştirme uygular.","vi-VN":"TRANG BỊ Xung Lực. BẮN PHỤ để chuyển đổi giữa hiệu ứng Làm Choáng và Hồi Máu. BẮN để quăng thiết bị về phía trước. Khi tiếp đất, Xung Lực phát ra sóng âm, Làm Choáng hoặc Hồi Máu cho người chơi.","zh-CN":"装备电音脉冲。按【辅助射击】可在震荡输出与治疗输出之间切换。按【射击】投掷装置。落地时，电音脉冲会释放声波，对玩家造成震荡或治疗效果。","zh-TW":"裝備「M脈衝」。點擊「輔助攻擊」在暈眩和治療效果間切換。點擊「攻擊」拋出裝置。落地時會釋放音波，對玩家造成暈眩或治療效果。"}'::jsonb, '"https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, 'Ability2', '{"es-MX":"Campo Sonoro","ar-AE":"هيئة الموجة","es-ES":"Onda sonora","ja-JP":"ウェーブフォーム","it-IT":"Forma d''onda","de-DE":"Wellenform","id-ID":"Waveform","ko-KR":"웨이브폼","fr-FR":"Forme d''onde","en-US":"Waveform","pl-PL":"Fala","pt-BR":"Ressonância","ru-RU":"Дым-машина","th-TH":"Waveform","tr-TR":"DALGA FORMU","vi-VN":"Dạng Sóng","zh-CN":"声波帷幕","zh-TW":"波形屏障"}'::jsonb, '{"es-MX":"EQUIPA un mapa de apuntado. DISPARA para fijar ubicaciones. Presiona DISPARO SECUNDARIO para desplegar humos en las ubicaciones objetivo.","ar-AE":"تجهّز بأداة استهداف خريطة. أطلق لتحديد الأماكن. اضغط على زر الإطلاق البديل لتوليد الدخان في الأماكن المحددة.","es-ES":"EQUIPA un selector de mapa. DISPARA para fijar ubicaciones. Utiliza el DISPARO ALTERNATIVO para generar humo en las ubicaciones seleccionadas.","ja-JP":"マップを開き、「発射」で地点を設定する。「オルト射撃」で選択した地点にスモークを発生させる。","it-IT":"EQUIPAGGIA un sistema di puntamento. Usa il FUOCO per impostare le posizioni sulla mappa. Usa il FUOCO ALTERNATIVO per generare fumogeni nelle posizioni selezionate.","de-DE":"RÜSTE eine Kartenzielauswahl AUS. FEUERE, um Zielorte festzulegen. ALT. FEUERMODUS, um an den ausgewählten Orten Rauch erscheinen zu lassen.","id-ID":"EQUIP Map Targeter. Tekan FIRE untuk menentukan lokasi. Tekan ALT FIRE untuk memunculkan Asap di lokasi yang dipilih.","ko-KR":"지도 표적기를 장착합니다. 발사하면 위치를 지정합니다. 보조 공격 시 선택한 위치에 연막을 생성합니다.","fr-FR":"ÉQUIPEZ-vous d''une carte tactique. TIREZ pour définir les positions. Utilisez le TIR SECONDAIRE pour déployer des fumigènes aux positions sélectionnées.","en-US":"EQUIP a Map Targeter. FIRE to set locations. ALT-FIRE to spawn Smokes at selected locations.","pl-PL":"WYPOSAŻ celownik mapy. STRZEL, by oznaczyć miejsca. ALT. STRZAŁ, by stworzyć zasłony dymne w wybranych miejscach.","pt-BR":"EQUIPE um Mapa Tático. DISPARE para definir os locais. O DISPARO ALTERNATIVO gera Fumaças nos locais selecionados.","ru-RU":"Открывает карту. Нажмите кнопку ОГОНЬ, чтобы указать места. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы разместить дымовые завесы в указанных местах.","th-TH":"ติดตั้งอุปกรณ์กำหนดเป้าหมายบนแผนที่ กดยิงเพื่อกำหนดตำแหน่ง กดโหมดยิงเสริมเพื่อปล่อยควันในตำแหน่งที่เลือก","tr-TR":"Bir Harita Hedefleyicisi KUŞAN. Konum belirlemek için ATEŞ ET. ALT. ATIŞ ile belirlediğin konumlarda duman oluştur.","vi-VN":"TRANG BỊ một bộ Chọn Vị Trí Mục Tiêu Trên Bản Đồ. BẮN để chỉ định vị trí mục tiêu. BẮN PHỤ để tạo Khói tại các vị trí đã chọn.","zh-CN":"装备地图定位仪。按【射击】设定位置。按【辅助射击】在选定位置释放烟雾。","zh-TW":"裝備地圖定位器。點擊「攻擊」選擇位置。點擊「輔助攻擊」在選定的位置製造煙幕。"}'::jsonb, '"https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, 'Ability1', '{"es-MX":"Armonía","ar-AE":"التناغم","es-ES":"Armonizar","ja-JP":"ハーモナイズ","it-IT":"Armonizzazione","de-DE":"Harmonisieren","id-ID":"Harmonize","ko-KR":"화음","fr-FR":"Harmonisation","en-US":"Harmonize","pl-PL":"Harmonizacja","pt-BR":"Harmonia","ru-RU":"Созвучие","th-TH":"Harmonize","tr-TR":"ARMONİ","vi-VN":"Hòa Âm","zh-CN":"共振谐律","zh-TW":"調和"}'::jsonb, '{"es-MX":"EQUIPA la habilidad Armonía. Apunta a un aliado y DISPARA para aplicarte a ti y a tu compañero un potenciador de combate que se restablece con cada asesinato. Presiona DISPARO SECUNDARIO para que el efecto del potenciador de combate se aplique solo a ti.","ar-AE":"تجهّز بقدرة التناغم. استهدف حليفًا واضغط على زر الإطلاق لتفعيل محفز قتال على نفسك والحليف يتجدد مع كل عملية قتل. اضغط على زر الإطلاق البديل لمنح نفسك محفز قتال.","es-ES":"EQUIPA Armonizar Selecciona a un aliado y DISPARA para otorgaros un estimulante de combate que se reinicia con cada asesinato. Utiliza el DISPARO ALTERNATIVO para otorgarte el estimulante de combate.","ja-JP":"ハーモナイズを構える。味方に狙いをつけて「発射」で、自分と味方がバトルスティムを獲得する。この効果はキルするたびに更新される。「オルト射撃」で自分自身がバトルスティムを獲得する。","it-IT":"EQUIPAGGIA Armonizzazione. Prendi di mira un alleato e usa il FUOCO per attivare un effetto ENERGIZZANTE su di te e sull''alleato che si rinnova a ogni uccisione. Usa il FUOCO ALTERNATIVO per applicare l''effetto ENERGIZZANTE su di te.","de-DE":"RÜSTE „Harmonisieren“ AUS. Ziele auf einen Verbündeten und FEUERE, um bei dir und deinem Verbündeten einen Kampf-Stim zu aktivieren, der bei jedem Kill erneuert wird. ALT. FEUERMODUS, um dir selbst einen Kampf-Stim zu verleihen.","id-ID":"EQUIP Harmonize. Bidik sekutu lalu Tekan FIRE untuk mengaktifkan Combat Stim pada diri sendiri dan sekutu. Efeknya akan diperbarui setiap kali mendapat kill. Tekan ALT FIRE untuk memberikan Combat Stim pada diri sendiri.","ko-KR":"화음을 장착합니다. 아군 한 명을 조준하고 발사하면 자신과 해당 아군에게 전투 자극제 효과를 활성화합니다. 적을 처치하면 지속시간이 초기화됩니다. 보조 공격 시 자신에게 전투 자극제를 부여합니다.","fr-FR":"ÉQUIPEZ Harmonisation. Visez un allié et TIREZ pour activer un Stimulant de combat sur vous-même et l''allié. Ce Stimulant se réinitialise à chaque élimination. Utilisez le TIR SECONDAIRE pour accorder le Stimulant uniquement à vous-même.","en-US":"EQUIP Harmonize. Target an ally and FIRE to activate a Combat Stim on yourself and the ally that refreshes with each kill. ALT-FIRE to grant Combat Stim to yourself.","pl-PL":"WYPOSAŻ Harmonizację. Namierz sojusznika i STRZEL, by aktywować stymulant bitewny na sobie i sojuszniku, który odnawia się przy każdym zabójstwie. ALT. STRZAŁ, by przyznać stymulant bitewny sobie.","pt-BR":"EQUIPE Harmonia. Mire em um aliado e DISPARE para ativar um Estimulante de Combate em você e no aliado que é renovado a cada abate. O DISPARO ALTERNATIVO concede Estimulante de Combate para você.","ru-RU":"Выбирает \"Созвучие\". Нацельтесь на союзника и нажмите кнопку ОГОНЬ, чтобы активировать боевой стимулятор для себя и союзника. Эффект стимулятора обновляется после каждого убийства. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы активировать боевой стимулятор для себя.","th-TH":"ติดตั้ง Harmonize เล็งเป้าไปที่เพื่อนร่วมทีมแล้วกดยิงเพื่อเปิดใช้งาน Combat Stim ให้กับตัวเองและเพื่อนร่วมทีม ซึ่งจะรีเฟรชทุกครั้งที่ฆ่าได้ กดโหมดยิงเสริมเพื่อมอบ Combat Stim ให้กับตัวเอง","tr-TR":"Armoni''yi KUŞAN. Bir takım arkadaşını hedef alarak ATEŞ ET ve hem kendine hem de hedeflediğin takım arkadaşına her öldürmeyle yenilenen bir Kuvvetli Savaş etkisi uygula. ALT. ATIŞ ile Kuvvetli Savaş etkisini kendine uygulayabilirsin.","vi-VN":"TRANG BỊ Hòa Âm. Nhắm vào một đồng minh và BẮN để kích hoạt Khuấy Động Giao Tranh lên bản thân và đồng minh đó, hiệu ứng sẽ được làm mới sau mỗi lần hạ gục. BẮN PHỤ để Khuấy Động Giao Tranh cho bản thân.","zh-CN":"装备共振谐律。锁定一名队友并按下【射击】，为你和该队友激活【作战强化】效果，每次击败都会刷新效果。按【辅助射击】让自己获得【作战强化】效果。","zh-TW":"裝備「調和」。瞄準一名友軍點擊「攻擊」，賦予自身和該友軍「激發戰意」增益，效果會在每次擊殺後重置。點擊「輔助攻擊」賦予自身「激發戰意」。"}'::jsonb, '"https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, 'Ultimate', '{"es-MX":"Frecuencia Sísmica","ar-AE":"زلزال البيس","es-ES":"Seísmo de graves","ja-JP":"ベースクエイク","it-IT":"Sisma sonoro","de-DE":"Bassbeben","id-ID":"Bassquake","ko-KR":"요동치는 베이스","fr-FR":"Basse sismique","en-US":"Bassquake","pl-PL":"Basowstrząs","pt-BR":"Melodia Sísmica","ru-RU":"Басовый удар","th-TH":"Bassquake","tr-TR":"BAS DEPREMİ","vi-VN":"Âm Chấn","zh-CN":"音脉强袭","zh-TW":"低音震盪"}'::jsonb, '{"es-MX":"EQUIPA la habilidad Frecuencia Sísmica. DISPARA para acumular radiación sónica y proyectarla hacia adelante, lo que empuja hacia atrás, ensordece y ralentiza a los agentes.","ar-AE":"تجهّز بقدرة زلزال البيس. أطلق لتجميع الطاقة وإطلاق الإشعاع الصوتي إلى الأمام، مما يدفع اللاعبين إلى الخلف ويصيبهم بالصمم ويبطئهم.","es-ES":"EQUIPA Seísmo de graves. DISPARA para acumular y lanzar un brillo sónico hacia delante que repele, ensordece y ralentiza a los jugadores.","ja-JP":"ベースクエイクを構える。「発射」でソニックレディアンスをチャージして前方に放つ。命中したプレイヤーをノックバックし、聴覚を奪い、スロウ状態にする。","it-IT":"EQUIPAGGIA Sisma sonoro. Usa il FUOCO per accumulare radianza sonica e sprigionarla in avanti, RESPINGENDO, ASSORDANDO e RALLENTANDO i giocatori.","de-DE":"RÜSTE „Bassbeben“ AUS. FEUERE, um einen Schallstrahl aufzubauen und nach vorne freizusetzen, der Spieler zurückstößt, taub macht und verlangsamt.","id-ID":"EQUIP Bassquake. Tekan FIRE untuk mengisi daya dan melepaskan Sonic Radiance ke depan, mendorong mundur, menerapkan efek Deafen dan Slow ke pemain.","ko-KR":"요동치는 베이스를 장착합니다. 발사하면 음파를 충전 후, 전방으로 방출하여 모든 플레이어를 뒤로 밀어내고, 청력을 약화시키며, 둔화시킵니다.","fr-FR":"ÉQUIPEZ Basse sismique. TIREZ pour accumuler et libérer de la Radiance sonique vers l''avant, repoussant, assourdissant et ralentissant les joueurs.","en-US":"EQUIP Bassquake. FIRE to build up and unleash Sonic Radiance forward, knocking back, Deafening, and Slowing players.","pl-PL":"WYPOSAŻ Basowstrząs. STRZEL, by naładować i wyzwolić przed sobą soniczną promienność, która odrzuca, ogłusza i spowalnia graczy.","pt-BR":"EQUIPE Melodia Sísmica. DISPARE para carregar e lançar Radiância Sônica à frente, que empurra e causa Surdez e Lentidão nos jogadores.","ru-RU":"Выбирает \"Басовый удар\". Нажмите кнопку ОГОНЬ, чтобы подготовить и выпустить звуковую волну, которая отбрасывает, лишает слуха и замедляет игроков.","th-TH":"ติดตั้ง Bassquake กดยิงเพื่อสะสมพลังและปลดปล่อย Sonic Radiance ไปข้างหน้า ซึ่งจะกระแทกศัตรูให้ถอยหลัง พร้อมติดสถานะถูกจำกัดการได้ยินและสโลว์","tr-TR":"Bas Depremi''ni KUŞAN. İleriye doğru bir Ses Işıltısı hazırlayıp fırlatmak için ATEŞ ET. Oyuncuları geriye savurur, Sağırlaştırma ve Yavaşlatma uygular.","vi-VN":"TRANG BỊ Âm Chấn. BẮN để tích tụ và phóng thích Bức Xạ Âm Thanh về phía trước, đẩy lùi, Vô Hiệu Hóa Thính Giác và Làm Chậm người chơi trúng phải.","zh-CN":"装备音脉强袭。按【射击】积蓄能量并向前释放音波源光，击退目标，并对其造成【致聋】和【减速】。","zh-TW":"裝備「低音震盪」。點擊「攻擊」蓄力並朝前方射出聲波光砲，對玩家造成擊退、喪失聽覺及緩速效果。"}'::jsonb, '"https://media.valorant-api.com/agents/7c8a4701-4de6-9355-b254-e09bc2a34b72/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('7c8a4701-4de6-9355-b254-e09bc2a34b72'::uuid, 200000, '2026-03-17T22:00:00Z'::timestamp with time zone, '2026-04-15T22:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('1e58de9c-4950-5125-93e9-a0aee9f98746'::uuid, '{"es-MX":"Killjoy","ar-AE":"كيلجوي","es-ES":"Killjoy","ja-JP":"キルジョイ","it-IT":"Killjoy","de-DE":"Killjoy","id-ID":"Killjoy","ko-KR":"킬조이","fr-FR":"Killjoy","en-US":"Killjoy","pl-PL":"Killjoy","pt-BR":"Killjoy","ru-RU":"Killjoy","th-TH":"Killjoy","tr-TR":"KILLJOY","vi-VN":"Killjoy","zh-CN":"奇乐","zh-TW":"愷宙"}'::jsonb, '{"es-MX":"La prodigio alemana Killjoy asegura fácilmente los puntos estratégicos del campo de batalla con su arsenal de inventos. Si el daño que inflige no detiene a sus enemigos, las debilitaciones de sus robots la ayudarán a aniquilarlos.","ar-AE":"تؤمّن كيلجوي، العبقرية الألمانية، البقع الحساسة في ميدان القتال دون جهد يُذكر بفضل ترسانة اختراعاتها. وإذا لم يتكفل الضرر الناجم عن الأدوات بقتل أعدائها، فإن المثبط الذي توفره روبوتاتها سيدمرهم بلا أدنى شك.","es-ES":"Killjoy es una brillante agente alemana que se encarga de tomar posiciones clave del campo de batalla con su arsenal de inventos. Si su daño no acaba con los enemigos, su horda de robots ayudarán a su equipo a despejarlos en un abrir y cerrar de ojos.","ja-JP":"ドイツ出身の天才キルジョイは発明した兵器を操り、難なく戦場を掌握する。敵の動きを止めるのに武器によるダメージでは不十分なら、彼女のロボットを使ったデバフが敵の迅速な処理に一役買うだろう。","it-IT":"Killjoy, la teutonica geniale, conquista senza sforzo posizioni chiave sul campo di battaglia con il suo arsenale di invenzioni. Quando i suoi robot non bastano a eliminare direttamente i nemici, le consentono comunque di sbarazzarsene con facilità.","de-DE":"Das deutsche Genie Killjoy sichert mühelos Schlüsselpositionen auf dem Schlachtfeld mit ihrem Arsenal von Erfindungen. Wenn der Schaden die Gegner nicht ausschaltet, geben ihnen die von den Robotern verteilten Schwächungen den Rest.","id-ID":"Sang genius dari Jerman, Killjoy, dengan mudah mengamankan posisi penting di battlefield dengan segudang penemuannya. Jika damage yang dihasilkan temuannya tidak menghentikan musuh, debuff robot-robotnya akan mengatasinya.","ko-KR":"독일의 천재 킬조이는 다양한 발명품을 사용해 전장의 주요 위치를 손쉽게 확보합니다. 발명품으로 적을 쓰러뜨릴 수는 없더라도 해로운 효과를 이용해 적을 단숨에 제압할 수 있습니다.","fr-FR":"Véritable génie originaire d''Allemagne, Killjoy sécurise et défend les positions clés sans effort grâce à son arsenal d''inventions. Si son équipement ne suffit pas à arrêter l''ennemi, ce sont les malus de ses robots qui en feront du menu fretin.","en-US":"The genius of Germany, Killjoy effortlessly secures key battlefield positions with her arsenal of inventions. If their damage doesn''t take her enemies out, the debuff her robots provide will make short work of them.","pl-PL":"Killjoy, genialna Niemka, z łatwością broni kluczowych pozycji na polu walki, korzystając ze swoich wynalazków. Jeśli sama nie wykończy swoich wrogów, osłabienia wywołane przez jej roboty z pewnością dokończą dzieła zniszczenia.","pt-BR":"Killjoy, uma alemã genial, defende posições-chave no campo de batalha facilmente com seu arsenal de invenções. Se o dano causado por seu equipamento não der cabo dos inimigos, os efeitos negativos de seus queridos robôs dão conta do recado.","ru-RU":"Гений из Германии Killjoy с легкостью защищает территорию на поле боя с помощью своего арсенала изобретений. И если противники все же уцелеют, то эффекты ослабления помогут Killjoy добить их.","th-TH":"Killjoy อัจฉริยะจากเยอรมนีเข้าควบคุมและป้องกันตำแหน่งสำคัญในสนามรบด้วยกองทัพสิ่งประดิษฐ์ของเธอ หากความเสียหายจากอุปกรณ์ของเธอหยุดศัตรูไม่ได้ ดีบัฟจากหุ่นยนต์ของเธอจะช่วยจัดการให้เอง","tr-TR":"Alman dâhi Killjoy, kendi icatlarından oluşan cephaneliğiyle savaş meydanını kontrol altına alır. Cihazlarının verdiği hasar rakiplerini durdurmaya yetmezse robotlarının yardımıyla rakiplerini zayıflatarak onların ortadan kaldırılmalarını kolaylaştırır.","vi-VN":"Một thiên tài từ nước Đức với hàng loạt những sáng chế độc đáo, Killjoy hoàn toàn dễ dàng bảo kê những vị trí quan trọng nhất để thống lĩnh chiến trường. Ngoài việc sở hữu thiết bị có sát thương khủng, kỹ năng làm suy yếu đối thủ từ các robot sẽ giúp cô chặn đứng mọi kẻ địch chỉ trong tích tắc.","zh-CN":"“奇乐”是来自莱茵河畔的天才发明家，她擅长使用陷阱、炮台和地雷来控制和防守战场上的关键位置。敌人若是不懂知难而退，便会发现这些装置个头虽小，制造的麻烦却很大。","zh-TW":"愷宙是位來自德國的天才，她擅長使用自己發明的多種武器，好整以暇地守住戰場上的重要點位，使敵人無法越雷池一步。這些武器就算沒把敵人立即擊倒，也足以靠著附加的減益效果使他們舉步維艱。"}'::jsonb, 'Killjoy', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/displayicon.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/displayicon.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/fullportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/fullportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/fullportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/killfeedportrait.png', 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/minimapportrait.png', null, 'https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/background.png', array['522162ff', '0f1923ff', '413950ff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1e58de9c-4950-5125-93e9-a0aee9f98746'::uuid, 'Grenade', '{"es-MX":"Nanoplaga","ar-AE":"سرب نانو","es-ES":"Nanoenjambre","ja-JP":"ナノスワーム","it-IT":"Nanosciame","de-DE":"Nanoschwarm","id-ID":"Nanoswarm","ko-KR":"나노스웜","fr-FR":"Essaim de nanites","en-US":"Nanoswarm","pl-PL":"Nanorój","pt-BR":"Nanoenxame","ru-RU":"Нанорой","th-TH":"Nanoswarm","tr-TR":"NANOSÜRÜ","vi-VN":"Bom Nano","zh-CN":"纳米蜂群","zh-TW":"奈米機器蟲"}'::jsonb, '{"es-MX":"EQUIPA una granada de Nanoplaga. DISPARA para lanzar la granada. Al caer, la granada se oculta. Usa el DISPARO SECUNDARIO para lanzarla bombeada. ACTIVA la Nanoplaga para desplegar un enjambre mortal de nanobots.  ","ar-AE":"تجهّز بقنبلة سرب النانو. أطلق لرمي القنبلة. عند ارتطامها، تدخل قنبلة سرب النانو في طور التخفي. استخدم الإطلاق البديل للإلقاء المقوس. قم بتفعيل سرب النانو لنشر سرب مدمر من روبوتات النانو.","es-ES":"EQUIPA una granada de nanoenjambre. DISPARA para lanzar la granada. Cuando aterriza, la granada enjambre se camufla. Utiliza el DISPARO ALTERNATIVO para tirarla. ACTIVA el nanoenjambre para desplegar un enjambre de nanobots.  ","ja-JP":"ナノスワームグレネードを構え、「発射」で投げる。地面に落ちるとナノスワームは透明になる。「オルト射撃」で軽く放る。「発動」でナノボットの群れを展開し、ダメージを与える。  ","it-IT":"EQUIPAGGIA una granata Nanosciame. Usa il FUOCO per lanciare la granata. All''impatto, il Nanosciame entra in uno stato di occultamento. Usa il FUOCO ALTERNATIVO per lanciare la granata dal basso verso l''alto. ATTIVA il Nanosciame per scatenare uno sciame di nanobot che infligge danni.  ","de-DE":"RÜSTE eine Nanoschwarm-Granate AUS. FEUERE, um die Granate zu werfen. Nach dem Landen tarnt sich der Nanoschwarm. ALT. FEUERMODUS, um die Granate eine kurze Distanz zu werfen. AKTIVIERE den Nanoschwarm, um einen Schaden verursachenden Schwarm Nanoroboter freizulassen.","id-ID":"EQUIP granat Nanoswarm. Tekan FIRE untuk melempar granat. Saat mendarat, Nanoswarm jadi tersembunyi dari musuh. Tekan ALT FIRE untuk melempar tinggi. AKTIFKAN Nanoswarm untuk mengerahkan kerumunan nanobot penghasil damage.","ko-KR":"나노스웜 수류탄을 장착합니다. 발사하면 수류탄을 투척합니다. 수류탄은 지면에 닿으면 잠복 상태가 됩니다. 보조 공격 시 높이 던집니다. 나노스웜을 활성화하면 적에게 피해를 입히는 나노스웜을 발사합니다.","fr-FR":"ÉQUIPEZ-vous d''une grenade à essaim de nanites. TIREZ pour lancer la grenade. À l''atterrissage, la grenade se camoufle. Utilisez le TIR SECONDAIRE pour la lancer en cloche. ACTIVEZ la grenade pour déployer un essaim de nanites.  ","en-US":"EQUIP a Nanoswarm grenade. FIRE to throw the grenade. Upon landing, the Nanoswarm goes covert. ALT FIRE to lob. ACTIVATE the Nanoswarm to deploy a damaging swarm of nanobots.  ","pl-PL":"WYPOSAŻ granat nanoroju. STRZEL, by rzucić granat. Po wylądowaniu na ziemi nanorój ukrywa się. Naciśnij ALT. STRZAŁ, by cisnąć. AKTYWUJ nanorój, by wypuścić niszczycielski rój nanobotów.  ","pt-BR":"EQUIPE uma granada Nanoenxame. DISPARE para lançar a granada. Ao atingir uma superfície, a Nanoenxame fica oculta. Use o DISPARO ALTERNATIVO para arremessar a curta distância. ATIVE a Nanoenxame para acionar um enxame de nanorrobôs que causam dano.  ","ru-RU":"Выбирает гранату \"Улей\". Нажмите кнопку ОГОНЬ, чтобы бросить гранату. После приземления граната маскируется. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы сделать бросок снизу. Активируйте \"Улей\", чтобы выпустить рой наносящих урон наноботов.  ","th-TH":"ติดตั้งระเบิด Nanoswarm กดยิงเพื่อขว้างระเบิด เมื่อถึงพื้น Nanoswarm จะซ่อนตัวทันที กดโหมดยิงเสริมเพื่อโยนออกไปในระยะสั้น ๆ เปิดใช้งาน Nanoswarm เพื่อปล่อยฝูง Nanobots ออกไปสร้างความเสียหาย  ","tr-TR":"Nanosürü bombası KUŞAN. Bombayı fırlatmak için ATEŞ ET. Nanosürü bir yere isabet ettiği anda gizlenir. Yavaşça fırlatmak için ALT. ATIŞ kullan. Hasar veren nano robot sürüsünü salmak için Nanosürü''yü ETKİNLEŞTİR.","vi-VN":"TRANG BỊ 1 quả Bom Nano. BẮN để quăng về phía trước. Khi chạm đất, Bom Nano sẽ trở nên tàng hình. BẮN PHỤ để ném cao. KÍCH HOẠT Bom Nano để phát tán các hạt Nano siêu nhỏ có khả năng gây sát thương.  ","zh-CN":"装备纳米蜂群手雷，按【射击】将其掷出。蜂群手雷会在落地后隐形。按【辅助射击】可轻抛。【激活】纳米蜂群即可部署一群纳米机器人，造成伤害。","zh-TW":"裝備一枚奈米機器蟲手榴彈。點擊「攻擊」即可拋出手榴彈，奈米機器蟲會在著地之後進入隱形狀態，點擊「輔助攻擊」則可低手拋出。按下「啟動」即可部署一群會造成敵人傷害的奈米機器蟲。  "}'::jsonb, '"https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1e58de9c-4950-5125-93e9-a0aee9f98746'::uuid, 'Ability1', '{"es-MX":"Alarmabot","ar-AE":"روبوت الإنذار","es-ES":"Bot de alarma","ja-JP":"アラームボット","it-IT":"Roboallarme","de-DE":"Alarmbot","id-ID":"Alarmbot","ko-KR":"알람봇","fr-FR":"Bot-alarme","en-US":"ALARMBOT","pl-PL":"Bot Alarmowy","pt-BR":"Robô de Alarme","ru-RU":"Тревогобот","th-TH":"Alarmbot","tr-TR":"ALARM BOTU","vi-VN":"Robot Báo Động","zh-CN":"自动哨兵","zh-TW":"電偵追擊號"}'::jsonb, '{"es-MX":"EQUIPA un Alarmabot encubierto. DISPARA para desplegar un bot que caza a los enemigos que entren en su alcance. Después de alcanzar a su objetivo, el bot explota y aplica Vulnerable a los enemigos en el área. MANTÉN PRESIONADO EQUIPAR para recuperar un bot desplegado.","ar-AE":"تجهّز بروبوت إنذار خفي. أطلق لنشر روبوت يقوم بمطاردة الأعداء المتواجدين في مداه. ينفجر الروبوت بعد الوصول إلى هدفه ليلحق تأثير الهشاشة بالأعداء في المنطقة. استمر في الضغط على التجهيز لاستدعاء الروبوت بعد نشره.","es-ES":"EQUIPA un bot de alarma camuflado. DISPARA para desplegar un bot que dará caza a los enemigos que estén dentro del alcance. Tras alcanzar su objetivo, el bot explota y aplica vulnerabilidad a los enemigos de la zona. MANTÉN PULSADO EQUIPAR para recoger un bot desplegado.","ja-JP":"ステルス性のアラームボットを構え、「発射」で設置する。このボットは範囲内に入った敵を追尾する。ターゲットに到達すると爆発し、範囲内の敵に弱体化を付与する。長押しで設置したボットを回収する。","it-IT":"EQUIPAGGIA un Roboallarme mimetico. Usa il FUOCO per piazzare il bot, il quale inseguirà i nemici che entrano nel suo raggio d''azione.  Una volta raggiunto il bersaglio, il bot esplode rendendo Vulnerabili i nemici circostanti. TIENI PREMUTO EQUIPAGGIA per richiamare il bot piazzato.","de-DE":"RÜSTE einen verdeckten Alarmbot AUS. FEUERE, um einen Roboter aufzustellen, der Gegner jagt, die in Reichweite kommen. Wenn er sein Ziel erreicht, explodiert der Roboter und belegt nahe Gegner mit „Verwundbar“. HALTE AUSRÜSTEN, um den aufgestellten Roboter zurückzurufen.","id-ID":"EQUIP Alarmbot tersembunyi. Tekan FIRE untuk mengerahkan bot yang memburu musuh di dalam area jangkauan. Setelah target dipilih, bot meledak dan menerapkan utilitas Vulnerable pada musuh di area tersebut. Tekan TAHAN GUNAKAN untuk memanggil kembali bot yang dikerahkan.","ko-KR":"잠복 알람봇을 장착합니다. 발사하면 범위 내에 들어온 적을 추적하는 봇을 배치합니다. 대상에 도달하면 봇은 폭발하여 해당 지역 내에 있는 적을 취약 상태로 만듭니다. 장착을 길게 누르면 배치된 봇을 회수합니다.","fr-FR":"ÉQUIPEZ-vous d''un robot d''alarme camouflé. TIREZ pour déployer un robot qui traque les ennemis à sa portée.  Quand il atteint sa cible, le robot explose et inflige l''altération d''état Vulnérable aux ennemis dans la zone. MAINTENEZ LA TOUCHE D''ÉQUIPEMENT pour rappeler un robot déployé.","en-US":"EQUIP a covert Alarmbot. FIRE to deploy a bot that hunts down enemies that get in range.  After reaching its target, the bot explodes and applies Vulnerable to enemies in the area. HOLD EQUIP to recall a deployed bot.","pl-PL":"WYPOSAŻ tajnego Bota Alarmowego. STRZEL, by wypuścić Bota ścigającego wrogów w jego zasięgu.  Po dotarciu do celu Bot wybucha, sprawiając, że wrogowie przebywający na obszarze wybuchu stają się podatni na ataki. PRZYTRZYMAJ przycisk WYPOSAŻENIA, by odwołać wypuszczonego Bota.","pt-BR":"EQUIPE um Robô de Alarme oculto. DISPARE para ativar um robô que persegue os inimigos que entram no alcance. Ao se aproximar do alvo, o robô explode, aplicando Vulnerável aos inimigos na área. SEGURE EQUIPAR para retirar um robô ativado.","ru-RU":"Выбирает замаскированного бота-паука. Нажмите кнопку ОГОНЬ, чтобы выпустить бота, который атакует противников, оказавшихся в его радиусе действия. Достигнув цели, бот взрывается и делает противников в области взрыва уязвимыми. Удерживайте кнопку умения, чтобы отозвать бота.","th-TH":"ติดตั้ง Alarmbot ลับ กดยิงเพื่อปล่อยบอทที่จะไล่ล่าศัตรูที่อยู่ในรัศมี  เมื่อไปถึงเป้าหมายของมันแล้ว บอทจะระเบิดและทำให้ศัตรูในพื้นที่ติดสถานะเปราะบาง กดปุ่ม ติดตั้ง ค้างไว้เพื่อเรียกบอทที่ถูกส่งออกไปกลับมา","tr-TR":"Gizli bir Alarm Botu KUŞAN. Menzili içine giren düşmanların peşine düşen bir robot göndermek için ATEŞ ET. Robot hedefine ulaştığında patlayarak bölge içindeki düşmanları Savunmasız hale getirir. Gönderdiğin botu geri çağırmak için KUŞANMA DÜĞMESİNİ BASILI TUT.","vi-VN":"TRANG BỊ 1 Robot Báo Động tàng hình. BẮN để sử dụng robot, có khả năng săn lùng kẻ địch trong phạm vi truy tìm. Khi bắt được mục tiêu, robot sẽ nổ tung và đặt hiệu ứng Suy Yếu lên tất cả kẻ địch trong khu vực. GIỮ TRANG BỊ để gọi robot về.","zh-CN":"装备隐形的自动哨兵。按【射击】可部署机器人来追踪进入范围的敌人。机器人会在接触目标后爆炸，施加【易伤】效果。【按住技能键】可召回已部署的机器人。","zh-TW":"裝備一個隱形的警報機器人。點擊「攻擊」，即可部署一個機器人，來自動追擊進入偵測範圍內的敵人；追到目標後機器人會引爆，並對範圍內的敵人附加衰弱效果。長按「裝備」，即可召回已部署的機器人。"}'::jsonb, '"https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1e58de9c-4950-5125-93e9-a0aee9f98746'::uuid, 'Ability2', '{"es-MX":"Torreta","ar-AE":"المدفع","es-ES":"Torreta","ja-JP":"タレット","it-IT":"Torretta","de-DE":"Geschützturm","id-ID":"Turret","ko-KR":"포탑","fr-FR":"Tourelle","en-US":"TURRET","pl-PL":"Działko","pt-BR":"Torreta","ru-RU":"ТУРЕЛЬ","th-TH":"Turret","tr-TR":"TARET","vi-VN":"Trụ Súng","zh-CN":"哨戒炮台","zh-TW":"重火力砲塔"}'::jsonb, '{"es-MX":"EQUIPA una torreta. DISPARA para desplegar una torreta que les dispara a los enemigos cercanos en un cono de 100 grados. Al apuntar, vuelve a EQUIPAR para cambiar la dirección de la torreta y MANTÉN el DISPARO SECUNDARIO para rotarla. MANTÉN PRESIONADO EQUIPAR para recuperar una torreta desplegada.","ar-AE":"تجهّز بمدفع رشاش. أطلق لنشر مدفع رشاش يطلق النار على الأعداء ضمن مخروط بزاوية 100. أثناء الاستهداف، تجهّز مجددًا لتبديل اتجاه المدفع الرشاش، تابع الضغط على زر الإطلاق البديل للتدوير. تابع الضغط على زر التجهّز لسحب المدفع الرشاش المنصوب.","es-ES":"EQUIPA una torreta. DISPARA para desplegar una torreta que ataca a los enemigos en un cono de 100 grados. Al apuntar, vuelve a EQUIPAR para cambiar la dirección de la torreta y MANTÉN PULSADO el DISPARO ALTERNATIVO para rotar. MANTÉN PULSADO EQUIPAR para recoger la torreta desplegada.","ja-JP":"タレットを構える。「発射」で設置する。タレットは100度の扇状範囲内にいる敵を攻撃する。ターゲット中にもう一度構えるとタレットの方向が切り替わり、「オルト射撃長押し」で回転する。長押しで設置したタレットを呼び戻せる。","it-IT":"EQUIPAGGIA una Torretta. Usa il FUOCO per piazzare una Torretta che apre il fuoco contro tutti i nemici che entrano nel suo cono visivo da 100°. Mentre miri, EQUIPAGGIA nuovamente per cambiare direzione della Torretta. Tieni premuto il FUOCO ALTERNATIVO per ruotarla. TIENI PREMUTO EQUIPAGGIA per richiamare la Torretta piazzata.","de-DE":"RÜSTE einen Geschützturm AUS. FEUERE, um einen Geschützturm aufzustellen, der in einem 100-Grad-Kegel auf Gegner schießt. RÜSTE während dem Zielen erneut AUS, um die Geschützturmrichtung zu ändern. HALTE ALT. FEUERMODUS zum Rotieren. HALTE AUSRÜSTEN, um den aufgestellten Geschützturm zurückzurufen.","id-ID":"EQUIP Turret. TEKAN FIRE untuk mengerahkan turret yang menembak musuh dalam sudut kerucut 100 derajat. Saat membidik, tekan EQUIP lagi untuk mengganti arah turret. TAHAN ALT FIRE untuk memutarnya. TAHAN TOMBOL EQUIP untuk memanggil kembali turret yang dikerahkan.","ko-KR":"포탑을 장착합니다. 발사하면 100도 범위에 있는 적을 공격하는 포탑을 배치합니다. 다시 장착해 포탑 방향을 전환할 수 있으며, 보조 공격을 길게 눌러 회전시킬 수 있습니다. 장착을 길게 누르면 배치된 포탑을 회수합니다.","fr-FR":"ÉQUIPEZ-vous d''une tourelle. TIREZ pour déployer une tourelle qui tire sur les ennemis dans un cône de 100 degrés. En ciblant, ÉQUIPEZ à nouveau pour changer l''orientation de la tourelle, MAINTENEZ LE TIR SECONDAIRE pour pivoter. MAINTENEZ LA TOUCHE D''ÉQUIPEMENT pour rappeler la tourelle déployée.","en-US":"EQUIP a Turret. FIRE to deploy a turret that fires at enemies in a 100 degree cone. While targeting, EQUIP again to swap turret direction, HOLD ALT FIRE to rotate. HOLD EQUIP to recall the deployed turret.","pl-PL":"WYPOSAŻ działko. STRZEL, by wypuścić działko, które automatycznie ostrzeliwuje wrogów w promieniu 100 stopni. Podczas namierzania WYPOSAŻ ponownie, by zmienić kierunek działka, i PRZYTRZYMAJ ALT. STRZAŁ, by obrócić. PRZYTRZYMAJ przycisk WYPOSAŻENIA, by odwołać wypuszczone działko.","pt-BR":"EQUIPE uma Torreta. DISPARE para ativar uma torreta que atira em inimigos em um cone de 100°. Ao posicionar, EQUIPE novamente para alterar a direção da torreta, segure o DISPARO ALTERNATIVO para girar. SEGURE EQUIPAR para recolher a torreta ativada.","ru-RU":"Выбирает турель. Нажмите кнопку ОГОНЬ, чтобы установить турель, которая автоматически отслеживает противников в 100-градусном секторе. Во время прицеливания нажмите кнопку умения, чтобы изменить направление турели; удерживайте кнопку АЛЬТ. ОГОНЬ, чтобы повернуть турель. Удерживайте кнопку умения, чтобы отозвать турель.","th-TH":"ติดตั้ง Turret กดยิงเพื่อปล่อยป้อมปืนที่จะยิงศัตรูในรูปกรวย 100 องศา ขณะเล็งเป้าหมาย ติดตั้งอีกครั้งเพื่อสลับทิศทางของป้อมปืน กดโหมดยิงเสริมค้างเพื่อหมุน กดปุ่มติดตั้งค้างเพื่อเรียกป้อมปืนที่ถูกส่งออกไปกลับมา","tr-TR":"Bir taret KUŞAN. 100 derecelik bir koni içindeki düşmanlara ateş eden bir taret yerleştirmek için ATEŞ ET. Taretin yönünü değiştirmek için hedef alırken tekrar KUŞAN. Döndürmek için ALT. ATIŞ''ı BASILI TUT. Yerleştirdiğin tareti kaldırmak için KUŞANMA DÜĞMESİNİ BASILI TUT.","vi-VN":"TRANG BỊ 1 Trụ Súng. BẮN để đặt 1 trụ súng có khả năng bắn đối thủ trong phạm vi hình nón với góc 100 độ. Khi đang nhắm mục tiêu, TRANG BỊ lần nữa để đổi hướng trụ súng, GIỮ BẮN PHỤ để xoay. GIỮ TRANG BỊ để thu trụ súng về.","zh-CN":"装备炮台，按【射击】即可部署，向100度范围内的敌人开火。瞄准期间，再次按【装备】可转换炮台方向，按【辅助射击】即可旋转。按住【装备】可召回已部署的炮台。","zh-TW":"裝備一座砲塔。點擊「攻擊」，即可部署該砲塔，對100度扇形範圍內的敵人開火。瞄準時再次點擊「裝備」可調整砲塔方向，長按「輔助攻擊」即可轉動。長按「裝備」，即可召回已部署的砲塔。"}'::jsonb, '"https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1e58de9c-4950-5125-93e9-a0aee9f98746'::uuid, 'Ultimate', '{"es-MX":"Contención","ar-AE":"أداة التثبيت","es-ES":"Bloqueo","ja-JP":"ロックダウン","it-IT":"Blocco","de-DE":"Abriegelung","id-ID":"Lockdown","ko-KR":"봉쇄","fr-FR":"Confinement","en-US":"Lockdown","pl-PL":"Blokada","pt-BR":"Confinamento","ru-RU":"Блокировка","th-TH":"Lockdown","tr-TR":"TECRİT","vi-VN":"Cầm Chân","zh-CN":"全面封锁","zh-TW":"全面封鎖"}'::jsonb, '{"es-MX":"EQUIPA un dispositivo de inmovilización. DISPARA para desplegar el dispositivo. Tras cargar, el dispositivo detiene a todos los enemigos dentro de su radio. Los enemigos pueden destruir el dispositivo.","ar-AE":"تجهّز بأداة التثبيت. أطلق لنشر الأداة. بعد فترة استعداد طويلة، تقوم الأداة باحتجاز جميع الأعداء المتواجدين ضمن نطاقها. بوسع الأعداء تدمير الأداة.","es-ES":"EQUIPA el dispositivo de bloqueo. DISPARA para desplegar el dispositivo. Tras un largo periodo de carga, el dispositivo detiene a todos los enemigos que estén dentro del radio de efecto. Los enemigos pueden destruir el dispositivo.","ja-JP":"ロックダウン装置を構え、「発射」で展開する。装置はしばらくチャージしてから、範囲内にいるすべての敵を拘束する。敵はこの装置を破壊することができる。","it-IT":"EQUIPAGGIA il dispositivo di blocco. Usa il FUOCO per piazzare il dispositivo. Dopo un lungo periodo di attivazione, il dispositivo blocca tutti i nemici rimasti all''interno del raggio. I nemici possono distruggere il dispositivo.","de-DE":"RÜSTE das Abriegelungsfeld AUS. FEUERE, um das Feld aufzustellen. Nach einer langen Ladephase werden alle Spieler in Reichweite gehindert. Das Feld kann zerstört werden.","id-ID":"EQUIP perangkat Lockdown. Tekan FIRE untuk mengerahkan perangkat. Setelah dikerahkan, perangkat akan menerapkan utilitas Detain sehingga musuh yang ada di dalam radius terperangkap. Perangkat bisa dihancurkan oleh musuh.","ko-KR":"봉쇄 장치를 장착합니다. 발사하면 장치를 배치합니다. 대기시간 이후 범위 내 탐지된 모든 적을 구속합니다. 봉쇄 장치는 적에 의해 파괴될 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un dispositif de confinement. TIREZ pour déployer le dispositif. Après un long délai d''activation, le dispositif retient tous les ennemis pris dans sa zone d''effet. Le dispositif peut être détruit par les ennemis.","en-US":"EQUIP the Lockdown device. FIRE to deploy the device. After a long windup, the device Detains all enemies caught in the radius. The device can be destroyed by enemies.","pl-PL":"WYPOSAŻ urządzenie blokujące. STRZEL, by wypuścić urządzenie. Po dłuższej chwili urządzenie zatrzymuje wszystkich wrogów w promieniu swojego działania. Urządzenie może zostać zniszczone przez przeciwników.","pt-BR":"EQUIPE o dispositivo de Confinamento. DISPARE para ativá-lo. Após um longo processo de ativação, o dispositivo detém todos os inimigos no raio de alcance. O dispositivo pode ser destruído pelos inimigos.","ru-RU":"Выбирает генератор поля блокировки. Нажмите кнопку ОГОНЬ, чтобы установить генератор. Задерживает всех противников, находящихся в радиусе действия. Противники могут вывести генератор из строя.","th-TH":"ติดตั้งอุปกรณ์ Lockdown กดยิงเพื่อปล่อยอุปกรณ์ หลังจากเปิดใช้งานไว้สักพักอุปกรณ์จะควบคุมศัตรูทุกตัวที่อยู่ในรัศมี ศัตรูสามารถทำลายอุปกรณ์ได้","tr-TR":"Tecrit cihazını KUŞAN. Cihazı yerleştirmek için ATEŞ ET. Uzun bir hazırlık süresinin ardından cihazın etki alanında kalan düşmanların hepsi Alıkoyulur. Bu cihaz düşmanlar tarafından yok edilebilir.","vi-VN":"TRANG BỊ thiết bị Cầm Chân. BẮN để sử dụng thiết bị. Sau một khoảng thời gian chờ dài, thiết bị sẽ Giam Cầm tất cả kẻ địch trong phạm vi. Thiết bị có thể bị phá hủy bởi kẻ địch.","zh-CN":"装备封锁装置。按【射击】进行部署。在长时间的启动后，束缚有效半径内的所有敌人。该装置可被敌人摧毁。","zh-TW":"裝備一件封鎖裝置。點擊「攻擊」即可部署該裝置，在長時間暖機之後，裝置會拘束所有半徑範圍內的敵人。敵人可以摧毀此裝置。"}'::jsonb, '"https://media.valorant-api.com/agents/1e58de9c-4950-5125-93e9-a0aee9f98746/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('95b78ed7-4637-86d9-7e41-71ba8c293152'::uuid, '{"es-MX":"Harbor","ar-AE":"هاربور","es-ES":"Harbor","ja-JP":"ハーバー","it-IT":"Harbor","de-DE":"Harbor","id-ID":"Harbor","ko-KR":"하버","fr-FR":"Harbor","en-US":"Harbor","pl-PL":"Harbor","pt-BR":"Harbor","ru-RU":"Harbor","th-TH":"Harbor","tr-TR":"HARBOR","vi-VN":"Harbor","zh-CN":"海神","zh-TW":"哈泊"}'::jsonb, '{"es-MX":"Originario de las costas de la India, Harbor arrasa el campo de batalla utilizando tecnología ancestral que controla el agua. Desata corrientes furiosas y olas aplastantes para escudar aliados o apalear a sus oponentes.","ar-AE":"مع قدومه من سواحل الهند، يقتحم هاربور ميدان القتال حاملًا تحفة تقنية قديمة يهيمن بفضلها على القوى المائية. ويطلق تيارات مائية جامحة وأمواجًا ساحقة لتدريع حلفائه أو إغراق من يعترضون طريقه.","es-ES":"Desde las costas de la India, Harbor llega al campo de batalla armado con tecnología ancestral capaz de controlar el agua. Libera espumosos torrentes y demoledoras olas para escudar a sus aliados o machacar a quien se interponga en su camino.","ja-JP":"インド沿岸部からやってきたハーバーは、古代のテクノロジーによって水を巧みに操り、戦場に嵐を巻き起こす。ハーバーの繰り出す激流や荒波は、味方を守る盾にも、敵を打ち倒す一撃にもなるだろう。","it-IT":"Dalla costa dell''India, Harbor travolge il campo di battaglia brandendo un''antica tecnologia in grado di dominare l''acqua. Scatena rapide intense e onde travolgenti per proteggere i suoi alleati o colpire duramente i nemici.","de-DE":"Harbor stürmt von Indiens Küsten mit uralter Technologie auf das Feld und beherrscht das Wasser. Er entfesselt Stromschnellen und Sturmfluten, mit denen er seine Verbündeten schützt oder seine Gegner auf Abstand hält.","id-ID":"Berasal dari pesisir India, Harbor menyerbu battlefield menggunakan teknologi kuno yang dapat mengendalikan air. Dia mengeluarkan arus deras berbuih dan ombak mematikan untuk melindungi sekutu, atau menghancurkan siapa pun yang menentangnya.","ko-KR":"인도 해안에서 온 하버는 물을 조종하는 고대 기술로 전장을 휩씁니다. 거센 급류와 강력한 파도로 아군을 보호하거나 적을 공격합니다.","fr-FR":"Venu de la côte indienne, Harbor déferle sur le terrain grâce à une technologie antique qui lui permet de contrôler l''eau. Il déchaîne des torrents bouillonnants et de terribles lames d''eau pour protéger ses alliés et noyer ses adversaires.","en-US":"Hailing from India’s coast, Harbor storms the field wielding ancient technology with dominion over water. He unleashes frothing rapids and crushing waves to shield his allies, or pummel those that oppose him.","pl-PL":"Pochodzący z Indii Harbor bierze pole szturmem, dzierżąc starożytną technologię i władając wodą. Uwalnia dzikie prądy i miażdżące fale, by chronić swoich sojuszników i zalewać tych, którzy stają mu na drodze.","pt-BR":"Vindo do litoral indiano, Harbor entra em campo com a força da tormenta, empunhando tecnologia ancestral com domínio sobre a água. Ele libera corredeiras espumantes e ondas esmagadoras para proteger seus aliados ou atacar aqueles que se opõem a ele.","ru-RU":"Агент Harbor с индийского побережья обрушивает бурю на поле боя, используя древнюю технологию управления водой. Он повелевает бурлящими потоками и сокрушительными волнами, чтобы защитить союзников или разгромить противников.","th-TH":"Harbor ผู้ล่องไหลมาจากชายฝั่งของอินเดียโถมเข้าสู่การต่อสู้พร้อมเทคโนโลยีโบราณที่กุมพลังเหนือสายน้ำ เขาจะปล่อยคลื่นกระแทกอันเชี่ยวกรากเพื่อปกป้องเหล่าพันธมิตร หรือจัดการผู้ที่กล้ามาต่อกรกับเขา","tr-TR":"Hindistan''ın kıyılarından gelen Harbor, kadim teknolojilerle suya hükmederek sahada fırtınalar koparıyor. Dostlarını korumak ve düşmanlarını alt etmek için güçlü akıntılar ve coşkun dalgalar çağırıyor.","vi-VN":"Xuất thân từ vùng bờ biển của Ấn Độ, Harbor nhấn chìm chiến trường bằng thứ công nghệ cổ xưa có khả năng điều khiển nước. Hắn tung ra những ngọn thác hung dữ và những con sóng bạc đầu để bảo hộ cho đồng đội hoặc đè bẹp kẻ thù.","zh-CN":"“海神”来自印度洋沿岸，借助古代科技的力量，他能够灵活地控制水的形态，释放出激流和巨浪来保护队友或击溃敌人。","zh-TW":"哈泊來自印度沿岸地區，他操縱著古代科技，支配水的力量，如潮水般洶湧衝上戰場。他會放出水沫四濺的湍流和勢不可擋的浪潮，給予友軍護盾，並狠狠擊潰敵軍。"}'::jsonb, 'Mage', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/displayicon.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/displayicon.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/fullportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/fullportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/fullportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/killfeedportrait.png', 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/minimapportrait.png', null, 'https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/background.png', array['275146ff', '0f1923ff', '11434eff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('95b78ed7-4637-86d9-7e41-71ba8c293152'::uuid, 'Ability1', '{"es-MX":"Marea Alta","ar-AE":"المد العالي","es-ES":"Marea alta","ja-JP":"ハイタイド","it-IT":"Alta marea","de-DE":"Flut","id-ID":"High Tide","ko-KR":"만조","fr-FR":"Marée haute","en-US":"High Tide","pl-PL":"Wysoki Przypływ","pt-BR":"Maré Alta","ru-RU":"Гребень волны","th-TH":"High Tide","tr-TR":"TAŞKIN","vi-VN":"Thủy Triều Dâng Trào","zh-CN":"狂潮","zh-TW":"上古水牆"}'::jsonb, '{"es-MX":"EQUIPA la habilidad Marea Alta. DISPARA para enviar agua hacia adelante por el suelo. MANTÉN PRESIONADO EL DISPARO para guiar el agua hacia tu retícula y generar una pantalla que bloquea la visión a lo largo de su trayectoria. Usa el DISPARO SECUNDARIO para detener el agua antes de tiempo. Los jugadores que crucen Marea Alta quedan ralentizados.","ar-AE":"تجهّز بالمد العالي. أطلق لإرسال الماء إلى الأمام على مستوى الأرض. تابع الضغط على زر الإطلاق لتوجيه الماء نحو مؤشر التصويب، حيث يتولّد حاجز يحجب الرؤية على طول المسار. استخدم الإطلاق البديل لإيقاف الماء مبكرًا. يتعرّض جميع اللاعبين الذين يعبرون المد العالي إلى الإبطاء.","es-ES":"EQUIPA Marea alta. DISPARA para lanzarla hacia adelante por el suelo. MANTÉN PULSADO para guiar el agua hacia la dirección de la mira, lo que genera una pantalla que bloquea la visión por todo el recorrido. Utiliza el DISPARO ALTERNATIVO para detener el agua antes de tiempo. Marea alta ralentiza a todos los jugadores a los que atraviesa.","ja-JP":"ハイタイドを構える。「発射」で前方に向かって、または「発射長押し」でクロスヘアの方向に誘導しながら水の軌跡を地面に描き、その軌跡上に視界を遮るスクリーンを発生させる。「オルト射撃」で早めに水を止めることができる。ハイタイドを通過したすべてのプレイヤーはスロウ状態になる。","it-IT":"EQUIPAGGIA Alta marea. Usa il FUOCO per mandare l''acqua in avanti lungo il terreno. TIENI PREMUTO il FUOCO per guidare l''acqua nella direzione del tuo reticolo, generando uno schermo che blocca la visione lungo il percorso. Usa il FUOCO ALTERNATIVO per fermare l''acqua in anticipo. Gli agenti che attraversano Alta marea vengono RALLENTATI.","de-DE":"RÜSTE „Flut“ AUS. FEUERE, um Wasser über den Boden zu schicken. HALTE FEUERN GEDRÜCKT, um das Wasser zu deinem Fadenkreuz zu lenken und eine Wasserwand zu erschaffen, die die Sicht blockiert. ALT. FEUERMODUS, um das Wasser frühzeitig zu stoppen. Alle Spieler, die „Flut“ durchqueren, werden verlangsamt.","id-ID":"EQUIP High Tide. Tekan FIRE untuk melempar air ke depan di sepanjang daratan. HOLD FIRE untuk mengarahkan air ke crosshair-mu, memunculkan Layar yang menghalangi pandangan di sepanjang jalur air. Tekan ALT FIRE untuk menghentikan air lebih awal. Semua pemain yang melewati High Tide akan terkena Slow.","ko-KR":"만조를 장착합니다. 발사하면 지면을 따라 물을 앞으로 보냅니다. 발사를 길게 누르면 조준점 방향으로 물을 유도합니다. 물은 지나가는 길에 시야를 가리는 장막을 생성합니다. 보조 공격 시 물이 일찍 멈춥니다. 만조를 통과하는 모든 플레이어는 둔화됩니다.","fr-FR":"ÉQUIPEZ-vous de Marée haute. TIREZ pour lancer de l''eau vers l''avant, parallèlement au sol. MAINTENEZ LE TIR pour la guider dans la direction du réticule et faire apparaître un mur liquide sur son passage. Utilisez le TIR SECONDAIRE pour arrêter la compétence prématurément. Tous les joueurs traversant Marée haute sont ralentis.","en-US":"EQUIP High Tide. FIRE to send water forward along the ground. HOLD FIRE to guide the water towards your crosshair spawning a vision blocking Screen along the path. ALT FIRE to stop the water early. All players crossing High Tide are Slowed.","pl-PL":"WYPOSAŻ Wysoki Przypływ. STRZEL, aby wysłać wodę naprzód po ziemi. PRZYTRZYMAJ STRZAŁ, aby kierować wodę w stronę wskazaną przez twój celownik, tworząc zasłaniającą pole widzenia ścianę wzdłuż jej ścieżki. Naciśnij ALT. STRZAŁ, aby woda zatrzymała się wcześniej. Gracze trafieni Wysokim Przypływem zostają SPOWOLNIENI.","pt-BR":"EQUIPE Maré Alta. DISPARE para enviar água para frente junto ao chão. SEGURE O DISPARO para guiar a água na direção da sua retícula, fazendo surgir uma Parede que bloqueia a visão ao longo do caminho. Use o DISPARO ALTERNATIVO para parar a água mais cedo. Todos os jogadores que atravessam a Maré Alta sofrem Lentidão.","ru-RU":"Выбирает \"Гребень волны\". Нажмите ОГОНЬ, чтобы послать воду вперед по земле. Удерживайте ОГОНЬ, чтобы перемещать воду по карте в направлении своего прицела и создать экран, блокирующий обзор, вдоль этой траектории. Нажмите АЛЬТ. ОГОНЬ, чтобы остановить воду. Все игроки, столкнувшиеся с \"Гребнем волны\", замедляются.","th-TH":"ติดตั้ง High Tide กดยิงเพื่อปล่อยสายน้ำออกไปข้างหน้าไปตามพื้น กดยิงค้างไว้เพื่อนำทางสายน้ำไปทางเป้าเล็งของคุณ และสร้างกำแพงบดบังทัศนวิสัยขึ้นมาตามเส้นทางของสายน้ำ กดโหมดยิงเสริมเพื่อหยุดสายน้ำก่อนเวลาที่กำหนด ผู้เล่นทั้งหมดที่เดินผ่าน High Tide จะติดสโลว์","tr-TR":"Taşkın''ı KUŞAN. Suyu zemin boyunca hareket ettirmek için ATEŞ ET. Suyu nişangâhının baktığı tarafa yöneltmek ve güzergâhı boyunca görüş engelleyen bir perde oluşturmak için ATEŞ DÜĞMESİNİ BASILI TUT. Suyu erkenden durdurmak için ALT. ATIŞ''a bas. Taşkın''ı geçen tüm oyuncular Yavaşlar.","vi-VN":"TRANG BỊ Thủy Triều Dâng Trào. BẮN để phóng nguồn nước về phía trước dọc mặt đất. GIỮ BẮN để điều khiển nguồn nước theo hướng tâm ngắm, tạo ra một Màn Chắn che tầm nhìn dọc đường đi. BẮN PHỤ để ngắt sớm kỹ năng. Những người chơi đi qua Thủy Triều Dâng Trào bị Làm Chậm.","zh-CN":"装备狂潮。按【射击】使水流沿地面向前延展。【按住射击】可使水流朝准星方向卷曲，沿路生成一道封锁视野的屏障。按【辅助射击】可提前中断水流。所有穿过狂潮的玩家都将受到【减速】。","zh-TW":"裝備「上古水牆」。點擊「攻擊」即可沿著地面向前送出水牆。按住「攻擊」可讓水牆朝十字準星的方向前進，沿路生成遮蔽視線的障壁。點按「輔助攻擊」可以提早停止水流。碰到「上古水牆」的玩家會遭到「緩速」。"}'::jsonb, '"https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('95b78ed7-4637-86d9-7e41-71ba8c293152'::uuid, 'Grenade', '{"es-MX":"Remolino Ciclónico","ar-AE":"الموجة العاصفة","es-ES":"Descarga tormentosa","ja-JP":"ストームサージ","it-IT":"Impeto tempestoso","de-DE":"Sturmschwall","id-ID":"Storm Surge","ko-KR":"폭풍 쇄도","fr-FR":"Tempête déferlante","en-US":"Storm Surge","pl-PL":"Burzowe Przepięcie","pt-BR":"Temporal","ru-RU":"Водоворот","th-TH":"Storm Surge","tr-TR":"FIRTINA AKINI","vi-VN":"Bão Tố Nổi Dậy","zh-CN":"乱涌","zh-TW":"驚濤湧浪"}'::jsonb, '{"es-MX":"EQUIPA un Remolino Ciclónico. DISPARA para lanzar un remolino explosivo que ralentiza y ofusca temporalmente a los jugadores que se encuentran dentro de él tras un tiempo breve.","ar-AE":"تجهّز بموجة عاصفة. أطلق لرمي وإنشاء دوامة متفجرة تسبب الإبطاء وضعف البصر للاعبين في داخلها بعد مدة قصيرة.","es-ES":"EQUIPA Descarga tormentosa. DISPARA para lanzar, lo que crea un remolino explosivo que ralentiza y limita la visión de los jugadores en su interior tras un breve periodo de tiempo.","ja-JP":"ストームサージを構える。「発射」で投げ、短時間の後に爆発を引き起こして中に入ったプレイヤーをスロウ状態にし、視界を悪化させる渦を発生させる。","it-IT":"EQUIPAGGIA Impeto tempestoso. Usa il FUOCO per lanciarlo, creando un turbine esplosivo che RALLENTA e ANNEBBIA i giocatori al suo interno dopo un breve ritardo.","de-DE":"RÜSTE „Sturmschwall“ AUS. FEUERE, um ihn zu werfen und einen explosiven Strudel zu erschaffen, der Spieler, die sich in ihm befinden, nach kurzer Zeit verlangsamt und ihre Sicht einschränkt.","id-ID":"EQUIP Storm Surge. Tekan FIRE untuk melempar, menciptakan pusaran air eksplosif yang menerapkan Slow dan Nearsight pada pemain di dalamnya setelah beberapa saat.","ko-KR":"폭풍 쇄도를 장착합니다. 발사하면 던져서 폭발하는 소용돌이를 생성합니다. 소용돌이는 짧은 시간 이후 내부의 플레이어를 둔화시키고 시야를 제한합니다.","fr-FR":"ÉQUIPEZ-vous de Tempête déferlante. TIREZ pour lancer et créer un tourbillon explosif qui rend myopes et ralentit les joueurs qui se trouvent à l''intérieur après un court instant.","en-US":"EQUIP Storm Surge. FIRE to throw, creating an explosive whirlpool that Slows and Nearsights players within it after a short duration.","pl-PL":"WYPOSAŻ Burzowe Przepięcie. STRZEL, aby rzucić, tworząc wybuchowy wir, który po chwili nakłada na znajdujących się w środku graczy spowolnienie i krótkowzroczność.","pt-BR":"EQUIPE um Temporal. DISPARE para lançar, criando um redemoinho explosivo que causa Lentidão e Visão Turva aos jogadores dentro dele após um curto período.","ru-RU":"\nВыбирает \"Водоворот\". Нажмите ОГОНЬ для броска, чтобы создать взрывную воронку, которая замедляет и ограничивает обзор игроков вскоре после того, как те оказались в ее пределах.","th-TH":"ติดตั้ง Storm Surge กดยิงเพื่อขว้าง และสร้างน้ำวนระเบิดที่ทำให้ผู้เล่นที่อยู่ภายในติดสถานะถูกจำกัดการมองเห็นและสโลว์หลังจากผ่านไประยะเวลาสั้น ๆ","tr-TR":"Fırtına Akını''nı KUŞAN. Fırlatmak için ATEŞ ET ve kısa bir sürenin ardından içindeki oyuncuları Yavaşlatan ve onların Görüşlerini Kısıtlayan patlayıcı bir girdap oluştur.","vi-VN":"TRANG BỊ Bão Tố Nổi Dậy. BẮN để ném, tạo ra một xoáy nước phát nổ khiến người chơi đứng bên trong bị Làm Chậm và Hạn Chế Tầm Nhìn sau một khoảng thời gian ngắn.","zh-CN":"装备乱涌。按【射击】向前投掷，制造一股具有强大破坏力的漩流，短时间后使漩流内的玩家受到【减速】和【视野收缩】。","zh-TW":"裝備「驚濤湧浪」。點擊「攻擊」投出，製造一道爆炸性的漩渦，玩家置身其中一小段時間後會遭到緩速和限制視野。"}'::jsonb, '"https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('95b78ed7-4637-86d9-7e41-71ba8c293152'::uuid, 'Ability2', '{"es-MX":"Cúpula","ar-AE":"الخليج","es-ES":"Cala","ja-JP":"コーヴ","it-IT":"Baia","de-DE":"Bucht","id-ID":"Cove","ko-KR":"해만","fr-FR":"Dôme aqueux","en-US":"Cove","pl-PL":"Zatoka","pt-BR":"Enseada","ru-RU":"Залив","th-TH":"Cove","tr-TR":"DALGAKIRAN","vi-VN":"Thủy Khiên","zh-CN":"海盾","zh-TW":"防彈海灣"}'::jsonb, '{"es-MX":"EQUIPA una Cúpula. ACTIVA para formar un humo de agua en la ubicación seleccionada. MANTÉN PRESIONADO EL DISPARO mientras apuntas para alejar el marcador aún más y MANTÉN PRESIONADO EL DISPARO SECUNDARIO para acercarlo. RECARGA para alternar la vista de selección de objetivos. REACTIVA para proteger el humo de agua, bloqueando cualquier bala que lo alcance. El humo de agua con escudo se puede destruir.","ar-AE":"تجهّز بخليج. قم بالتفعيل لتشكيل دخان مائي في الموقع المحدد. تابع الضغط على زر الإطلاق أثناء الاستهداف لتحريك المؤشر إلى مسافة أبعد، وتابع الضغط على زر الإطلاق البديل لتقريبه. أعد التلقيم لتفعيل/تعطيل عرض نافذة الاستهداف. أعد التفعيل لتدعيم الدخان المائي بدرع يصد أي طلقات تصيبه. يمكن تدمير الدخان المائي المدرّع.","es-ES":"EQUIPA Cala. ACTIVA para desatar humo acuoso en la ubicación seleccionada. MANTÉN PULSADO al apuntar para que el marcador se aleje más. MANTÉN PULSADO el DISPARO ALTERNATIVO para acercarlo. PULSA RECARGAR para cambiar el modo de apuntado. REACTIVA la habilidad para otorgar un escudo al humo acuoso, que bloqueará todas las balas. El humo acuoso con escudo se puede destruir.","ja-JP":"コーヴを構える。「発動」で狙った場所に水のスモークを形成する。ターゲット中は「発射長押し」でマーカーが遠くへ、「オルト射撃長押し」で近くへ移動する。また「リロード」で照準視点が切り替わる。「再発動」で水のスモークをあらゆる銃弾を防ぐシールド化する。シールド化した水のスモークは破壊可能。","it-IT":"EQUIPAGGIA Baia. ATTIVA per generare un fumogeno acquatico nella posizione selezionata. TIENI PREMUTO il FUOCO mentre miri per allontanare l''indicatore e TIENI PREMUTO IL FUOCO ALTERNATIVO per farlo avvicinare. PREMI RICARICA per attivare o disattivare la visuale di puntamento. RIATTIVA per fornire al fumogeno acquatico uno scudo che blocca tutti i proiettili. Il fumogeno acquatico protetto dallo scudo può essere distrutto.","de-DE":"RÜSTE „Bucht“ AUS. AKTIVIEREN, um am Zielort eine Kuppel aus Wasser zu erschaffen. HALTE FEUERN GEDRÜCKT, um die Markierung von dir zu entfernen, und HALTE ALT. FEUERMODUS GEDRÜCKT, um sie zu dir zu bewegen. DRÜCKE NACHLADEN, um zum Zielmodus umzuschalten. REAKTIVIEREN, um der Wasserkuppel einen Schild zu geben, der alle Kugeln blockt. Die mit dem Schild geschützte Wasserkuppel kann zerstört werden.","id-ID":"EQUIP Cove. AKTIFKAN untuk membentuk Asap air di lokasi yang dipilih. HOLD FIRE saat menarget untuk menjauhkan penanda, dan HOLD ALT FIRE untuk mendekatkannya. Tekan RELOAD untuk berganti tampilan penargetan. AKTIFKAN ULANG untuk memberi Shield pada Asap air sehingga peluru tidak bisa menembus. Asap air yang diberi Shield bisa dihancurkan.","ko-KR":"해만을 장착합니다. 활성화하면 선택한 위치에 물 연막을 생성합니다. 발사를 길게 누르면 표시 위치를 더 멀리 옮기고, 보조 공격을 길게 누르면 더 가까이 옮깁니다. 재장전을 누르면 조준점을 끄고 켭니다. 다시 활성화하면 물 연막에 보호막을 씌워, 연막에 맞는 모든 탄환을 막습니다. 보호막이 씌워진 연막은 파괴될 수 있습니다.","fr-FR":"ÉQUIPEZ-vous de Dôme aqueux. ACTIVEZ pour placer un fumigène d''eau à l''emplacement ciblé. MAINTENEZ LE TIR tout en visant pour éloigner le marqueur et MAINTENEZ LE TIR SECONDAIRE pour le rapprocher. RECHARGEZ pour repasser en visée. RÉACTIVEZ pour protéger le fumigène d''eau et repousser les balles qui l''atteignent. Le fumigène d''eau protégé peut être détruit.","en-US":"EQUIP Cove. ACTIVATE to form a water Smoke in the select location. HOLD FIRE while targeting to move the marker further away and HOLD ALT FIRE to move it closer. RELOAD to toggle targeting view. REACTIVATE to Shield the water Smoke, blocking any bullets that hit it. The Shielded water Smoke can be destroyed.","pl-PL":"WYPOSAŻ Zatokę. AKTYWUJ, by przywołać wodnisty dym na wybranym obszarze. PRZYTRZYMAJ STRZAŁ podczas namierzania, by oddalić znacznik, i PRZYTRZYMAJ ALT. STRZAŁ, by go przybliżyć. PRZEŁADUJ, by przełączyć widok namierzania. REAKTYWUJ, aby osłonić wodnisty dym tarczą, która blokuje wszystkie pociski. Otoczony tarczą wodnisty dym może zostać zniszczony.","pt-BR":"EQUIPE Enseada. ATIVE para formar uma Fumaça de água no local selecionado. SEGURE O DISPARO enquanto mira para afastar o marcador e SEGURE O DISPARO ALTERNATIVO para aproximá-lo. RECARREGUE para trocar a visão de posicionamento. REATIVE para criar um Escudo ao redor da Fumaça de água, que bloqueia as balas que a atingem. A Fumaça de água com Escudo pode ser destruída.","ru-RU":"Выбирает \"Залив\". При активации создает водную завесу в выбранной точке. Чтобы увеличить дальность броска, удерживайте кнопку ОГОНЬ при прицеливании. Чтобы уменьшить дальность броска, удерживайте кнопку АЛЬТ. ОГОНЬ. Нажмите кнопку ПЕРЕЗАРЯДКИ, чтобы переключиться на обычный режим прицеливания. Нажмите кнопку умения повторно, чтобы укрепить завесу и блокировать прилетающие в нее пули. Укрепленную водную завесу можно уничтожить.","th-TH":"ติดตั้ง Cove เปิดใช้งานเพื่อสร้างควันสายน้ำในตำแหน่งที่กำหนด กดยิงค้างไว้ในขณะที่เล็งเป้าหมายเพื่อย้ายเครื่องหมายให้ไกลออกไปและกดโหมดยิงเสริมค้างไว้เพื่อย้ายเครื่องหมายให้ใกล้เข้ามา กดรีโหลดเพื่อสับเปลี่ยนเป็นมุมมองการเล็งเป้าหมาย เปิดใช้งานอีกครั้งเพื่อสร้างควันสายน้ำให้เป็นโล่ป้องกันกระสุนที่ยิงใส่ ควันสายน้ำที่เป็นโล่ป้องกันสามารถทำลายได้","tr-TR":"Dalgakıran''ı KUŞAN. Belirlenen konumda bir su dumanı oluşturmak için ETKİNLEŞTİR. Hedef alma esnasında işaretçiyi daha uzağa götürmek için ATEŞ DÜĞMESİNİ BASILI TUT, yakına getirmek içinse ALT. ATIŞ DÜĞMESİNİ BASILI TUT. Hedef almaya geçmek için DOLDURMA DÜĞMESİNE BAS. Su dumanını korumak ve ona isabet eden tüm kurşunları engellemek için TEKRAR ETKİNLEŞTİR. Korunan su dumanı yok edilebilir.","vi-VN":"TRANG BỊ Thủy Khiên. KÍCH HOẠT để tạo 1 đám Khói nước tại vị trí chỉ định. GIỮ BẮN trong khi nhắm mục tiêu để di chuyển điểm đánh dấu ra xa và GIỮ BẮN PHỤ để đưa điểm đánh dấu lại gần. THAY ĐẠN để bật/tắt nhắm mục tiêu. TÁI KÍCH HOẠT để tạo Khiên cho Khói nước, chặn mọi đường đạn bắn vào. Khói nước được tạo Khiên có thể bị phá hủy.","zh-CN":"装备海盾。【激活】后在选定位置形成一道水雾。瞄准期间，【按住射击】可将标记移远，【按住辅助射击】可将标记移近。【换弹】即可切换至瞄准视野。【再次激活】技能即可为水雾生成护盾，阻挡所有命中它的子弹。受护盾保护的水雾可被敌人摧毁。","zh-TW":"裝備「防彈海灣」。按下「啟動」在指定地點生成水霧。瞄準時按住「攻擊」，可將標記移動至遠處；按住「輔助攻擊」可將其移近。按下「填彈」切換瞄準視角。「重施技能」為水霧加上護盾，可阻擋子彈。加上護盾的水霧可被破壞。"}'::jsonb, '"https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('95b78ed7-4637-86d9-7e41-71ba8c293152'::uuid, 'Ultimate', '{"es-MX":"Cataclismo","ar-AE":"تصفية الحساب","es-ES":"Ajuste de cuentas","ja-JP":"レコニング","it-IT":"Resa dei conti","de-DE":"Gissung","id-ID":"Reckoning","ko-KR":"심판","fr-FR":"Raz-de-marée","en-US":"Reckoning","pl-PL":"Rozrachunek","pt-BR":"Acerto de Contas","ru-RU":"Расчет курса","th-TH":"Reckoning","tr-TR":"KAYNAMA NOKTASI","vi-VN":"Thủy Nộ","zh-CN":"怒涛","zh-TW":"湧泉審判"}'::jsonb, '{"es-MX":"EQUIPA la habilidad Cataclismo DISPARA para liberar todo el poder de tu artefacto; lanza una ráfaga de agua que se precipita hacia adelante para ofuscar y ralentizar a los enemigos que alcance.","ar-AE":"تجهّز بتصفية الحساب. أطلق لتحرير كامل قوة تحفتك، لتُطلق تيارًا مائيًا يندفع إلى الأمام ويسبب ضعف البصر والإبطاء للأعداء المصابين.","es-ES":"EQUIPA Ajuste de cuentas. DISPARA para desatar el poder máximo de tu artefacto, lo que libera un torrente de agua que avanza hacia adelante, lo que ralentiza y limita la visión de los enemigos golpeados.","ja-JP":"レコニングを構える。「発射」で遺物の力を解き放ち、前方に進む水の奔流を発生させる。当たった敵は視界悪化とスロウ状態を受ける。","it-IT":"EQUIPAGGIA la Resa dei conti. Usa il FUOCO per scatenare tutto il potere del tuo manufatto, liberando un cavallone che avanza ANNEBBIANDO e RALLENTANDO i nemici che investe.","de-DE":"RÜSTE „Gissung“ AUS. FEUERE, um die ganze Macht deines Artefakts zu entfesseln und einen Wasserschwall freizusetzen, der vorwärts schwappt, um getroffene Gegner zu verlangsamen und ihre Sicht einzuschränken.","id-ID":"EQUIP Reckoning. Tekan FIRE untuk melepaskan kekuatan penuh artefakmu, melepaskan semburan air yang melesat maju untuk menerapkan Nearsight dan Slow pada musuh yang terkena.","ko-KR":"심판을 장착합니다. 발사하면 유물의 모든 힘을 해방해, 물의 파도를 방출합니다. 물의 파도는 앞으로 나아가며 맞은 적의 시야를 제한하고 둔화시킵니다.","fr-FR":"ÉQUIPEZ-vous de Raz-de-marée. TIREZ pour libérer toute la puissance de votre relique et libérer un torrent d''eau vers l''avant qui rend myopes et ralentit les ennemis touchés.","en-US":"EQUIP Reckoning. FIRE to unleash the full power of your artifact, releasing a surge of water that barrels forward to Nearsight and Slow enemies that are hit.","pl-PL":"WYPOSAŻ Rozrachunek. STRZEL, aby użyć pełni mocy swego artefaktu, uwalniając wodę pędzącą w przód, która nakłada na trafionych przeciwników efekty krótkowzroczności i spowolnienia.","pt-BR":"EQUIPE Acerto de Contas. DISPARE para liberar todo o poder do seu artefato, lançando uma onda que avança em direção aos inimigos, causando Visão Turva e Lentidão nos inimigos atingidos.","ru-RU":"Выбирает \"Расчет курса\". Нажмите ОГОНЬ, чтобы высвободить мощь артефакта и направить в сторону врагов поток воды, который замедляет и ограничивает обзор пораженных противников.","th-TH":"ติดตั้ง Reckoning กดยิงเพื่อปลดปล่อยพลังของวัตถุโบราณอย่างเต็มรูปแบบ และส่งคลื่นน้ำพุ่งไปข้างหน้าเพื่อทำให้ศัตรูที่โดนติดสถานะถูกจำกัดการมองเห็นและสโลว์","tr-TR":"Kaynama Noktası''nı KUŞAN. Yadigârının gerçek gücünü açığa çıkarmak için ATEŞ ET ve ileri doğru giderek isabet ettiği düşmanlara Görüş Kısıtlama ve Yavaşlatma uygulayan bir su dalgası oluştur.","vi-VN":"TRANG BỊ Thủy Nộ. BẮN để giải phóng toàn bộ sức mạnh của tạo vật, phóng ra một dòng nước dữ dội lao thẳng về phía trước, Hạn Chế Tầm Nhìn và Làm Chậm kẻ địch trúng phải.","zh-CN":"装备怒涛。按【射击】释放圣物的全部力量，激起汹涌水流向前奔涌，被水流命中的敌人会受到【视野收缩】和【减速】。","zh-TW":"裝備「湧泉審判」。點擊「攻擊」釋放古文物的全部威力，形成一道湧浪往前翻湧，命中的敵軍會遭到緩速和限制視野。"}'::jsonb, '"https://media.valorant-api.com/agents/95b78ed7-4637-86d9-7e41-71ba8c293152/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, '{"es-MX":"Vyse","ar-AE":"فايس","es-ES":"Vyse","ja-JP":"ヴァイス","it-IT":"Vyse","de-DE":"Vyse","id-ID":"Vyse","ko-KR":"바이스","fr-FR":"Vyse","en-US":"Vyse","pl-PL":"Vyse","pt-BR":"Vyse","ru-RU":"Vyse","th-TH":"Vyse","tr-TR":"VYSE","vi-VN":"Vyse","zh-CN":"维斯","zh-TW":"薇絲"}'::jsonb, '{"es-MX":"Vyse, la mente maestra metálica, libera metal líquido para aislar, atrapar y desarmar a sus enemigos. Mediante su astucia y manipulación, obliga a quienes se opongan a ella a temerle al campo de batalla mismo.","ar-AE":"تطلق خبيرة المعادن فايس المعدن السائل لعزل الأعداء والإيقاع بهم وتجريدهم من أسلحتهم. بفضل ذكائها الحاد وقدرتها على التلاعب، تجعل جميع خصومها يخشون ساحة المعركة نفسها.","es-ES":"La prodigiosa ferromante Vyse crea metal en estado líquido para aislar, atrapar y desarmar a sus enemigos. Gracias a su astucia y poder de manipulación, fuerza a sus oponentes a desconfiar incluso del campo de batalla.","ja-JP":"金属を操る戦術家であるヴァイスは、液体金属を駆使して敵を孤立させ、罠にかけて無力化する。狡猾さと策略によって敵を操り、戦場そのものを恐れさせる。","it-IT":"La dominatrice del metallo Vyse scatena un metallo liquido che isola, intrappola e disarma i suoi nemici. Con astuzia e manipolazione, costringe chi le si oppone a temere anche il campo di battaglia.","de-DE":"Das metallmanipulierende Genie Vyse entfesselt flüssiges Metall, um damit ihre Gegner zu isolieren, festzusetzen und zu entwaffnen. Wer sich ihr widersetzt, wird das Schlachtfeld selbst fürchten, wenn sie mit ihren fiesen Tricks und Manipulationen anrückt.","id-ID":"Mastermind metalik Vyse mengeluarkan logam cair untuk mengisolasi, menjebak, dan melucuti senjata musuh-musuhnya. Dengan kelicikan dan manipulasi, dia memaksa semua yang menentangnya untuk takut memasuki battlefield.","ko-KR":"강철 장인 바이스는 액체 금속을 사용하여 적을 고립시키고, 함정에 빠뜨리고, 무력화합니다. 그 간계와 술수를 본 적들은 전장 자체를 두려워하게 됩니다.","fr-FR":"La génie du métal Vyse utilise le métal liquide pour isoler, piéger et désarmer ses ennemis. Par la ruse et la manipulation, elle force tous ses adversaires à craindre le champ de bataille lui-même.","en-US":"Metallic mastermind Vyse unleashes liquid metal to isolate, trap, and disarm her enemies. Through cunning and manipulation, she forces all who oppose her to fear the battlefield itself.","pl-PL":"Genialna metalurgiczka Vyse wykorzystuje ciekły metal do izolowania, więzienia i rozbrajania wrogów. Dzięki swojemu sprytowi i zdolnościom manipulacji zmusza wszystkich, którzy się jej sprzeciwiają, by lękali się już samego pola bitwy.","pt-BR":"A mestre dos metais Vyse usa metal líquido para isolar, prender e desarmar os inimigos. Com astúcia e manipulação, ela faz todos os adversários que a enfrentam temerem o próprio campo de batalha.","ru-RU":"Vyse умеет управлять жидким металлом, запирая, пленяя и обезоруживая врагов с его помощью. Хитростью и мастерством она вынудит любого, кто встанет на ее пути, бояться самого поля боя.","th-TH":"จอมบงการแห่งโลหะ Vyse จะใช้โลหะเหลวเพื่อแยกกัก ดักจับ และปลดอาวุธเหล่าศัตรูของเธอ เธออาศัยเล่ห์เหลี่ยมและการปั่นประสาท เพื่อฝังความกลัวแม้กระทั่งการเดินในสนามรบลงในหัวของเหล่าศัตรูของเธอ","tr-TR":"Vyse sıvı metali kontrol ederek düşmanlarını sürüden ayıran, tuzağa düşüren ve silahsız bırakan bir dâhi. Kurnazlığı ve manipülasyon kabiliyeti sayesinde karşısına çıkanları bizzat savaş alanının kendisinden korkar hale getirir.","vi-VN":"Vyse - bậc thầy kim loại, có khả năng sử dụng thép lỏng để cô lập, gài bẫy và khóa vũ khí của kẻ địch. Với chiến lược xảo quyết và kỹ năng kiểm soát tàng hình, cô sẽ khiến mọi kẻ địch phải nếm mùi kinh hãi của chiến trường.","zh-CN":"“维斯”是一位高智商金属能力者。她能自由操纵液态金属的形态，为敌人设下重重陷阱和障碍，甚至解除他们的武装。敌人与她对抗，就像在与整个战场为敌。","zh-TW":"善於謀略與操縱金屬的薇絲能釋放液態金屬來隔絕、誘捕敵軍，甚至卸除其武裝。工於心計的她能輕易操控對手心智，讓戰場成為恐懼的代名詞。"}'::jsonb, 'Nox', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/displayicon.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/displayicon.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/fullportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/fullportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/fullportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/killfeedportrait.png', 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/minimapportrait.png', null, 'https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/background.png', array['492280ff', '0f1923ff', 'ffffffff', '0f192300'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, 'Ability1', '{"es-MX":"Cortacaminos","ar-AE":"المقص","es-ES":"Cizallas","ja-JP":"シアー","it-IT":"Sfoltitura","de-DE":"Scheren","id-ID":"Shear","ko-KR":"가지치기","fr-FR":"Cisaille","en-US":"Shear","pl-PL":"Ścięcie","pt-BR":"Cerca-Viva","ru-RU":"Замуровка","th-TH":"Shear","tr-TR":"DİKENLİ ÇİT","vi-VN":"Tường Thép","zh-CN":"裁断","zh-TW":"斷路鐵牆"}'::jsonb, '{"es-MX":"EQUIPA filamentos de metal líquido. DISPARA para colocar una pared oculta a modo de trampa. Cuando un enemigo la cruce, una pared indestructible saldrá del suelo detrás suyo. La pared durará un breve periodo antes de disiparse.","ar-AE":"تجهّز بخيوطٍ من المعدن السائل. أطلق لنصب فخ جداري مخفي. عندما يعبر العدو، ينبثق جدارٌ غير قابلٍ للتدمير من الأرض خلفه. يبقى الجدار قائماً لفترة وجيزة قبل أن يتلاشى.","es-ES":"EQUIPA filamentos de metal líquido. DISPARA para colocar un muro trampa oculto. Cuando un enemigo lo atraviese, un muro indestructible surgirá del suelo a su paso. El muro dura un breve periodo de tiempo antes de disiparse.","ja-JP":"液体金属のフィラメントを構える。「発射」でステルス状態の壁のトラップを設置する。敵が通過すると、その背後の地面から破壊不能な壁が出現する。壁は短時間出現した後に消滅する。","it-IT":"EQUIPAGGIA dei filamenti di metallo liquido. Usa il FUOCO per piazzare un muro trappola invisibile. Quando un nemico lo attraversa, un muro indistruttibile spunta dal terreno alle sue spalle. Il muro dura un breve lasso di tempo prima di dissolversi.","de-DE":"RÜSTE Filamente aus flüssigem Metall AUS. FEUERE, um versteckte Mauerfallen zu platzieren. Laufen Gegner daran vorbei, schießt eine unzerstörbare Mauer hinter ihnen aus dem Boden. Die Mauer bleibt kurze Zeit bestehen und verpufft dann.","id-ID":"EQUIP filamen dari logam cair. Tekan FIRE untuk menempatkan perangkap dinding tersembunyi. Saat musuh melintas, dinding yang tidak bisa hancur tersebut akan muncul dari dalam tanah di belakang mereka. Dinding ini bertahan selama beberapa saat sebelum menghilang.","ko-KR":"액체 금속 필라멘트를 장착합니다. 발사하면 숨겨진 장벽 함정을 설치합니다. 적이 지나가면 지면에서 파괴할 수 없는 벽이 폭발하며 솟아오릅니다. 벽은 잠시 유지되다가 사라집니다.","fr-FR":"ÉQUIPEZ-vous de filaments de métal liquide. TIREZ pour placer un piège invisible sur un mur. Lorsqu''un ennemi passe devant, un mur indestructible jaillit du sol derrière lui. Le mur ne dure qu''un bref instant avant de disparaître.","en-US":"EQUIP filaments of liquid metal. FIRE to place a hidden wall trap. When an enemy crosses, an indestructible wall bursts from the ground behind them. The wall lasts for a brief time before dissipating.","pl-PL":"WYPOSAŻ włókna ciekłego metalu. STRZEL, by umieścić ukrytą ścianę-pułapkę. Kiedy wróg przejdzie obok jednej z nich, z ziemi za nim wyrośnie niezniszczalna ściana. Ściana utrzymuje się przez krótki czas, po czym znika.","pt-BR":"EQUIPE filamentos de metal líquido. DISPARE para posicionar uma armadilha de parede oculta. Quando um inimigo passa por ela, uma parede indestrutível emerge do chão atrás dele. A parede dura um breve período antes de se dissipar.","ru-RU":"Выбирает струйки жидкого металла. Нажмите кнопку ОГОНЬ, чтобы разместить скрытую стену-ловушку. Когда через нее переступает противник, позади него из земли вырастает неразрушимая стена. Она существует некоторое время, после чего распадается.","th-TH":"ติดตั้งเส้นใยโลหะเหลว กดยิงเพื่อฝังกับดักกำแพงซ่อนไว้ เมื่อศัตรูเดินผ่าน กำแพงที่ทำลายไม่ได้จะพุ่งขึ้นมาจากพื้นดินด้านหลังของศัตรู กำแพงจะคงอยู่เป็นเวลาชั่วครู่ก่อนจะสลายไป","tr-TR":"Bir miktar sıvı metal KUŞAN. Gizli bir duvar tuzağı yerleştirmek için ATEŞ ET. Bir düşman tuzaktan geçtiğinde arkasında yok edilemeyen bir duvar oluşur. Duvar kısa bir süre sonra ortadan kalkar.","vi-VN":"TRANG BỊ một mẫu thép lỏng. BẮN để đặt một tường bẫy tàng hình. Khi kẻ địch đi qua, một bức tường không thể bị phá hủy sẽ trồi lên từ mặt đất bên dưới chúng. Bức tường tồn tại trong một thời gian ngắn trước khi biến mất.","zh-CN":"装备条状液态金属。按【射击】放置一道隐藏的隔断陷阱。当有敌人经过时，会在其身后升起一道无法摧毁的屏障墙。墙体将在一段时间后自行瓦解。","zh-TW":"裝備液態金屬絲線，點擊「攻擊」即可在牆面放置陷阱。敵方經過時觸發，其身後會升起一道無法破壞的金屬牆。金屬牆會在持續一段時間後消失。"}'::jsonb, '"https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, 'Ability2', '{"es-MX":"Rosa Metálica","ar-AE":"الوردة الكهربائية","es-ES":"Rosa metálica","ja-JP":"アークローズ","it-IT":"Rosa lucente","de-DE":"Bogenrose","id-ID":"Arc Rose","ko-KR":"아크 장미","fr-FR":"Rose métallique","en-US":"Arc Rose","pl-PL":"Łukowa Róża","pt-BR":"Rosa Arcana","ru-RU":"Дуговая роза","th-TH":"Arc Rose","tr-TR":"ARK GÜLÜ","vi-VN":"Hoa Thép","zh-CN":"弧光玫瑰","zh-TW":"弧光薔薇"}'::jsonb, '{"es-MX":"EQUIPA una Rosa Metálica. Apunta a una superficie y DISPARA para colocar una Rosa Metálica camuflada, o usa el DISPARO SECUNDARIO para colocarla al otro lado de la superficie seleccionada. REUTILÍZALA para cegar a todos los jugadores que la vean. Puedes recogerla para VOLVER A COLOCARLA en otro lugar.","ar-AE":"تجهّز بوردة كهربائية. استهدف سطحًا وأطلق لوضع وردة كهربائية مخفية عليه، أو استخدم الإطلاق البديل لزرع الوردة الكهربائية ضمن السطح. أعد الاستخدام لإصابة كل اللاعبين الذين ينظرون إليها بتأثير العمى. يمكن التقاط هذه القدرة لإعادة تثبيتها مرة أخرى.","es-ES":"EQUIPA una rosa metálica. Apunta a una superficie y DISPARA para colocar una rosa invisible o utiliza el DISPARO ALTERNATIVO para colocarla atravesada. VUELVE A LANZARLA para cegar a todos los jugadores que estén mirando en su dirección. La rosa metálica se puede recoger para VOLVER A COLOCARLA.","ja-JP":"アークローズを構える。面を狙い、「発射」でステルス状態のアークローズを設置する。または「オルト射撃」で貫通した向こう側へ設置する。「再使用」で、それを見ているすべてのプレイヤーの視界を奪う。このアビリティーは回収して再設置可能。","it-IT":"EQUIPAGGIA una rosa. Punta una superficie e usa il FUOCO per piazzare una rosa invisibile, o il FUOCO ALTERNATIVO per piazzarla attraverso la superficie. RIUTILIZZA l''abilità per accecare tutti i giocatori che guardano la rosa. Questa abilità può essere raccolta per essere RIPOSIZIONATA.","de-DE":"RÜSTE eine Bogenrose AUS. Ziele auf eine Oberfläche und FEUERE, um eine getarnte Bogenrose zu platzieren, oder nutze den ALT. FEUERMODUS zum Platzieren der Bogenrose. REAKTIVIEREN, um alle Spieler zu blenden, die in die Richtung blicken. Du kannst diese Fähigkeit aufheben, um sie ERNEUT EINZUSETZEN.","id-ID":"EQUIP Arc Rose. Targetkan permukaan dan tekan FIRE untuk menempatkan Arc Rose yang sudah disembunyikan, atau tekan ALT FIRE untuk menempatkan Arc Rose melewatinya. GUNAKAN LAGI untuk membuat silau semua pemain yang melihatnya. Ability ini bisa diambil untuk DIKERAHKAN LAGI.","ko-KR":"아크 장미를 장착합니다. 표면을 겨냥해 발사하면 숨겨진 아크 장미를 배치하거나, 보조 공격 시 그 너머에 아크 장미를 배치합니다. 다시 사용 시 아크 장미를 바라보는 모든 플레이어가 실명합니다. 이 스킬은 회수하여 다시 설치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''une rose métallique. Visez une surface et TIREZ pour placer une rose métallique furtive, ou utilisez le TIR SECONDAIRE pour placer la rose métallique à travers la surface. RÉUTILISEZ pour aveugler tous les joueurs qui la regardent. La rose peut être ramassée pour être REDÉPLOYÉE.","en-US":"EQUIP an Arc Rose. Target a surface and FIRE to place a stealthed Arc Rose, or ALT FIRE to place the Arc Rose through it. REUSE to blind all players looking at it. This ability can be picked up to be REDEPLOYED.","pl-PL":"WYPOSAŻ Łukową Różę. Wyceluj w powierzchnię i STRZEL, aby umieścić na niej ukrytą Łukową Różę – lub wykonaj ALT. STRZAŁ, by umieścić Łukową Różę po jej drugiej stronie. UŻYJ PONOWNIE, by oślepić wszystkich patrzących na nią graczy. Można ją podnieść i UŻYĆ PONOWNIE.","pt-BR":"EQUIPE uma Rosa Arcana. Mire em uma superfície e DISPARE para posicionar uma Rosa Arcana oculta, ou use o DISPARO ALTERNATIVO para posicionar a Rosa Arcana através da superfície. USE NOVAMENTE para cegar todos os jogadores que estiverem olhando para ela. A habilidade pode ser recuperada e REPOSICIONADA.","ru-RU":"Выбирает дуговую розу. Выберите целью поверхность и нажмите кнопку ОГОНЬ, чтобы разместить на ней скрытую дуговую розу. Нажмите кнопку АЛЬТ. ОГОНЬ для размещения сквозь поверхность. Используйте умение повторно, чтобы ослепить всех игроков, обращенных к ней лицом. Розу можно подобрать и разместить заново.","th-TH":"ติดตั้ง Arc Rose เล็งเป้าหมายไปที่พื้นผิวและยิง เพื่อวาง Arc Rose ซ่อนไว้ หรือกดโหมดยิงเสริมเพื่อปล่อย Arc Rose ทะลุผ่านไป ใช้ซ้ำเพื่อทำให้ผู้เล่นทุกคนที่จ้องมองสูญเสียการมองเห็น อุปกรณ์นี้สามารถเก็บขึ้นมาได้เพื่อติดตั้งใหม่","tr-TR":"Bir Ark Gülü KUŞAN. Gizli bir Ark Gülü yerleştirmek için bir yüzeye hedef al ve ATEŞ ET. Ark Gülü''nü duvarın arkasına yerleştirmek için ALT. ATIŞ kullan. Ark Gülü''ne bakan tüm oyuncuları kör etmek için yeteneği TEKRAR KULLAN. Bu yeteneği TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin.","vi-VN":"TRANG BỊ 1 Hoa Thép. Chọn một bề mặt và BẮN để đặt Hoa Thép tàng hình, hoặc BẮN PHỤ để đặt Hoa Thép xuyên qua bề mặt đó. TÁI KÍCH HOẠT để làm mù tất cả người chơi trong phạm vi đang nhìn vào nó. Kỹ năng này cho phép bạn nhặt Hoa Thép lên và ĐẶT LẠI.","zh-CN":"装备弧光玫瑰。选择一块墙面，放置隐形的弧光玫瑰，按【辅助射击】可部署到墙的另一侧。【再次按技能键】可致盲所有目击闪爆点的玩家。此技能可回收和【重新部署】。","zh-TW":"裝備一朵弧光薔薇。瞄準一面牆，點擊「攻擊」放置一朵隱密的弧光薔薇，或是點擊「輔助攻擊」將其放置在牆面另一側。重施技能即可致盲所有看著該牆面的玩家。可撿起弧光薔薇，然後「重新部署」。"}'::jsonb, '"https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, 'Grenade', '{"es-MX":"Enredadera Filosa","ar-AE":"الأشواك الحادة","es-ES":"Zarzal lacerante","ja-JP":"レーザーヴァイン","it-IT":"Rovi taglienti","de-DE":"Rasiermesserranken","id-ID":"Razorvine","ko-KR":"면도날 덩굴","fr-FR":"Ronces barbelées","en-US":"Razorvine","pl-PL":"Cierniste Pnącze","pt-BR":"Espinheiro Cortante","ru-RU":"Острая лоза","th-TH":"Razorvine","tr-TR":"KESKİN SARMAŞIK","vi-VN":"Bẫy Thép","zh-CN":"剃刀藤蔓","zh-TW":"荊棘鐵網"}'::jsonb, '{"es-MX":"EQUIPA un nido de metal líquido. DISPARA para lanzarlo. Tras aterrizar, el nido se vuelve invisible. Al ACTIVARSE, se extiende hasta convertirse en una enredadera filosa grande que ralentizará e infligirá daño a todos los jugadores que se muevan a través de ella.","ar-AE":"تجهّز بعشٍ من المعدن السائل. أطلق لرميه. عند الهبوط، يصبح العش غير مرئي. عند التفعيل، يمتد ليصبح عشًا كبيرًا من الأشواك الحادة التي تبطئ وتلحق الضرر بجميع اللاعبين الذين يمرون من خلالها.","es-ES":"EQUIPA un amasijo de metal líquido. DISPARA para lanzarlo. Al aterrizar, el amasijo se vuelve invisible. Al ACTIVARSE, se extiende para formar un zarzal lacerante que ralentiza y daña a todos los jugadores que lo atraviesen.","ja-JP":"液体金属のネストを構える。「発射」で射出する。地面に触れると、ネストは視認できなくなる。「発動」すると、大きなレーザーヴァインのネストが広がり、通過するすべてのプレイヤーの移動速度を低下させ、ダメージを与える。","it-IT":"EQUIPAGGIA un groviglio di metallo liquido. Usa il FUOCO per lanciarlo. Dopo l''atterraggio, il groviglio diventa invisibile. Quando viene ATTIVATO, da esso si espande un grande campo di rovi che rallenta e danneggia tutti i giocatori che lo attraversano.","de-DE":"RÜSTE ein Nest aus flüssigem Metall AUS. FEUERE, um das Nest zu werfen. Bei der Landung wird das Nest unsichtbar. Bei der AKTIVIERUNG breitet es sich zu einem großen Nest mit rasiermesserscharfen Ranken aus, die Spieler verlangsamen sich und nehmen Schaden, wenn sie sich hindurchbewegen.","id-ID":"EQUIP sarang dari logam cair. Tekan FIRE untuk meluncurkan. Saat mendarat, sarang menjadi tidak terlihat. Saat DIAKTIFKAN, ini akan menyebar menjadi sarang razorvine besar. Sarang tersebut menerapkan utilitas slow dan damage pada semua pemain yang melewatinya.","ko-KR":"액체 금속 둥지를 장착합니다. 발사하면 날립니다. 둥지는 지면에 닿으면 보이지 않게 됩니다. 활성화하면 거대한 면도날 덩굴 둥지가 펼쳐지며, 이를 통과하는 모든 플레이어의 속도를 늦추고 피해를 입힙니다.","fr-FR":"ÉQUIPEZ-vous d''un nid de métal liquide. TIREZ pour le lancer. En retombant, le nid devient invisible. Une fois ACTIVÉ, il s''étend en un large nid de ronces barbelées qui ralentit et blesse tous les joueurs qui le traversent.","en-US":"EQUIP a nest of liquid metal. FIRE to launch. Upon landing, the nest becomes invisible. When ACTIVATED, it sprawls out into a large razorvine nest which slows and damages all players who move through it.","pl-PL":"WYPOSAŻ gniazdo ciekłego metalu. STRZEL, by je wyrzucić. Po wylądowaniu gniazdo staje się niewidoczne. Po AKTYWACJI rozrośnie się w duże gniazdo ostrych jak brzytwa pnączy, spowalniając i zadając obrażenia wszystkim graczom, którzy przez nie przejdą.","pt-BR":"EQUIPE um emaranhado de metal líquido. DISPARE para lançar. Ao cair, o metal se torna invisível. Quando ATIVADO, ele se espalha e cria um grande espinheiro que causa Lentidão e dano a todos os jogadores que passam por ele.","ru-RU":"Выбирает клубок из жидкого металла. Нажмите кнопку ОГОНЬ, чтобы выпустить его. Коснувшись земли, он становится невидимым. При активации он распускается, становясь скопищем острых лоз, которые замедляют всех игроков, передвигающихся в этой области, а также наносят им урон.","th-TH":"ติดตั้งขดโลหะเหลว กดยิงเพื่อปล่อยออกไป เมื่อตกถึงพื้น ขดโลหะเหลวจะเข้าสู่สถานะล่องหน เมื่อเริ่มทำงาน ขดโลหะเหลวจะกางออกเป็นม่านลวดหนามขนาดใหญ่ ซึ่งจะทำให้ผู้เล่นทุกคนที่เดินผ่านติดสโลว์และได้รับความเสียหาย","tr-TR":"Bir miktar sıvı metal KUŞAN. Fırlatmak için ATEŞ ET. Sıvı metal indiği konumda görünmez olur. Keskin sarmaşıklardan oluşan ve içerisindeki tüm oyuncuları yavaşlatıp onlara hasar veren geniş bir alan oluşturmak için ETKİNLEŞTİR.","vi-VN":"TRANG BỊ một bẫy thép lỏng. BẮN để quăng. Khi chạm đất, bẫy sẽ trở nên tàng hình. Khi KÍCH HOẠT, các nhành thép sắc lẹm sẽ mọc ra xung quanh, làm chậm và gây sát thương lên tất cả người chơi đi qua nó.","zh-CN":"装备网状的液态金属。按【射击】将其投射出去。该装置会在落地时隐形。激活后，它会从地面伸出大量剃刀藤蔓，对穿行的所有玩家造成伤害和减速。","zh-TW":"裝備一張液態金屬網，點擊「攻擊」發射。落地後，金屬網會隱形。啟動時會擴張成大範圍的荊棘鐵網，對穿過該區域的玩家造成緩速與傷害效果。"}'::jsonb, '"https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, 'Ultimate', '{"es-MX":"Jardín Magnético","ar-AE":"الحديقة الفولاذية","es-ES":"Jardín de acero","ja-JP":"スチールガーデン","it-IT":"Giardino d''acciaio","de-DE":"Stahlgarten","id-ID":"Steel Garden","ko-KR":"강철 정원","fr-FR":"Jardin d''acier","en-US":"Steel Garden","pl-PL":"Stalowy Ogród","pt-BR":"Jardim de Aço","ru-RU":"Стальной сад","th-TH":"Steel Garden","tr-TR":"ÇELİK BAHÇESİ","vi-VN":"Vườn Thép Gai","zh-CN":"铁棘禁园","zh-TW":"叢棘盛開"}'::jsonb, '{"es-MX":"EQUIPA un arbusto de metal líquido. DISPARA para lanzar el metal que sale de ti como un torrente de espinas metálicas, lo que BLOQUEA las armas principales de los enemigos tras una breve carga.","ar-AE":"تجهّز بأشواكٍ من المعدن السائل. أطلق لإرسال المعدن على شكل سيل من الأشواك المعدنية، مما يعطل الأسلحة الأساسية لدى الأعداء بعد فترة وجيزة.","es-ES":"EQUIPA una zarza de metal líquido. DISPARA para lanzar el metal que surge de tu interior como un torrente de espinas de metal, INUTILIZANDO las armas principales de los enemigos tras un breve tiempo de carga.","ja-JP":"液体金属のイバラを構える。「発射」で自身から金属のトゲの奔流が噴出する。短いチャージの後、敵のプライマリ武器を使用不能にする。","it-IT":"EQUIPAGGIA un rovo di metallo liquido. Usa il FUOCO per sprigionare in avanti il metallo in eruzione come un torrente di spine metalliche, INCEPPANDO l''arma primaria di ogni nemico investito dopo un breve periodo di attivazione.","de-DE":"RÜSTE ein Dornengestrüpp aus flüssigem Metall AUS. FEUERE, um das Metall in Form von Metalldornen aus dir herausstoßen zu lassen. Nach einer kurzen Aufladezeit werden die Primärwaffen von Gegnern mit LADEHEMMUNGEN belegt.","id-ID":"EQUIP semak belukar dari logam cair. Tekan FIRE untuk mengeluarkan logam yang menyembur dari Vyse sebagai semburan duri logam. Kemudian, JAMMING senjata utama musuh setelah windup singkat.","ko-KR":"액체 금속 가시를 장착합니다. 발사하면 뿜어져 나온 금속이 가시가 되어 날아가고, 짧은 대기시간 이후 적의 주 무기를 사용 불가 상태로 만듭니다.","fr-FR":"ÉQUIPEZ-vous d''une ronce de métal liquide. TIREZ pour faire éclater le métal autour de vous en un torrent de ronces métalliques, ce qui ENRAYE les armes principales des adversaires après un bref délai.","en-US":"EQUIP a bramble of liquid metal. FIRE to send the metal erupting from you as a torrent of metal thorns, JAMMING enemy primary weapons after a brief windup.","pl-PL":"WYPOSAŻ cierń ciekłego metalu. STRZEL, aby metal wyleciał z ciebie w postaci strumienia metalowych kolców, ZACINAJĄC bronie podstawowe wrogów po krótkim czasie.","pt-BR":"EQUIPE um espinheiro de metal líquido. DISPARE para lançar metal como uma torrente de espinhos metálicos, BLOQUEANDO as armas primárias inimigas após um breve período.","ru-RU":"Выбирает сплетение из жидкого металла. Нажмите кнопку ОГОНЬ, чтобы выпустить созданный вами металл в виде потока металлических шипов, который после некоторой задержки ЗАКЛИНИВАЕТ основное оружие противников.","th-TH":"ติดตั้งพุ่มหนามโลหะเหลว กดยิงเพื่อส่งโลหะที่จะแตกกระจายออกจากตัวคุณในรูปคลื่นหนามโลหะ หลังจากรอครู่หนึ่ง จะทำให้อาวุธหลักของศัตรูใช้งานไม่ได้","tr-TR":"Dikenli bir sıvı metal KUŞAN. Metal dikenlerden oluşan bir akım gönderip kısa bir süre sonra düşmanların birincil silahlarına TUTUKLUK YAPTIRMAK için ATEŞ ET.","vi-VN":"TRANG BỊ một rễ cây thép lỏng. BẮN để phóng gai thép ra xung quanh, KHÓA VŨ KHÍ của tất cả kẻ địch sau một thoáng chờ.","zh-CN":"装备液态金属荆团。按【射击】在短暂的蓄力后，向四周展开荆棘领域，阻塞敌人的主要武器。","zh-TW":"裝備一叢液態金屬荊棘，點擊「攻擊」即可從自身位置發出一道金屬荊棘洪流，在短暫延遲後干擾敵方主要武器。"}'::jsonb, '"https://media.valorant-api.com/agents/efba5359-4016-a1e5-7626-b1ae76895940/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('efba5359-4016-a1e5-7626-b1ae76895940'::uuid, 200000, '2024-08-28T21:00:00Z'::timestamp with time zone, '2024-09-26T21:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('707eab51-4836-f488-046a-cda6bf494859'::uuid, '{"es-MX":"Viper","ar-AE":"فايبر","es-ES":"Viper","ja-JP":"ヴァイパー","it-IT":"Viper","de-DE":"Viper","id-ID":"Viper","ko-KR":"바이퍼","fr-FR":"Viper","en-US":"Viper","pl-PL":"Viper","pt-BR":"Viper","ru-RU":"Viper","th-TH":"Viper","tr-TR":"VIPER","vi-VN":"Viper","zh-CN":"蝰蛇","zh-TW":"薇蝮"}'::jsonb, '{"es-MX":"Viper, la química estadounidense, despliega un arsenal químico y venenoso para controlar el campo de batalla y reducir la visión de sus enemigos. Si las toxinas no matan a su presa, sin duda sus juegos mentales lo harán.","ar-AE":"تنشر الكيميائية الأمريكية المعروفة باسم فايبر مجموعة من الأجهزة الكيميائية السامة للتحكم بميدان القتال وخنق قدرة العدو على الرؤية. وتتكفل أساليب خداعها البارعة بقتل فريستها إن لم تنجح سمومها في تحقيق ذلك.","es-ES":"Viper es una química estadounidense con un amplio arsenal de dispositivos venenosos que le sirven para tomar el control del campo de batalla y cegar a los enemigos. Si las toxinas no acaban con su presa, la paranoia la rematará.","ja-JP":"アメリカ合衆国の化学者であるヴァイパーは、危険な化学兵器を駆使して戦況を巧みに操り、敵の視界を妨げることができる。仮にその標的が毒で力尽きなかったとしても、彼女が仕掛ける心理戦の毒牙から逃れることはできないのだ。","it-IT":"La scienziata americana Viper ha una serie di dispositivi chimici velenosi con i quali controlla il campo di battaglia e blocca la visione nemica. Se le tossine non uccidono la sua preda, lo faranno i suoi giochetti mentali.","de-DE":"Die US-amerikanische Chemikerin Viper setzt eine Reihe von Geräten mit giftigen Chemikalien ein, um die Kontrolle über das Schlachtfeld zu behalten und dem Gegner die Sicht zu nehmen. Falls das Gift ihre Beute nicht zur Strecke bringt, erledigen ihre Psychospielchen das Übrige.","id-ID":"Seorang Ahli Kimia dari Amerika, Viper, mengerahkan sejumlah perangkat kimia beracun untuk mengendalikan battlefield dan menghalangi pandangan musuh. Jika racun tidak membunuh musuhnya, permainan pikirannya pasti menghabisi mereka.","ko-KR":"미국 출신 화학자 바이퍼는 다양한 화학 무기로 전장을 장악하고 적의 시야를 차단합니다. 화학 공격으로부터 살아남는다고 해도 바이퍼의 심리전에 놀아날 뿐입니다.","fr-FR":"Viper est une chimiste américaine qui déploie un arsenal d''appareils toxiques pour contrôler le champ de bataille et entraver la vision des ennemis. Si les toxines ne suffisent pas à abattre sa proie, ses machinations finiront le travail.","en-US":"The American Chemist, Viper deploys an array of poisonous chemical devices to control the battlefield and choke the enemy''s vision. If the toxins don''t kill her prey, her mindgames surely will.","pl-PL":"Amerykańska chemiczka Viper wykorzystuje urządzenia z trującymi chemikaliami, by kontrolować pole walki i ograniczać wizję wroga. Jeśli nie wykończy ofiary toksynami, z pewnością zrobi to psychologicznie.","pt-BR":"Viper, a química dos Estados Unidos, emprega uma variedade de dispositivos químicos venenosos para controlar o campo de batalha e prejudicar a visão do inimigo. Se as toxinas não matarem a presa, seus jogos mentais certamente o farão.","ru-RU":"Химик из США Viper устанавливает контроль над полем боя с помощью источающих токсичный газ устройств и ограничивает обзор противникам. А тех, кого ей не удастся отравить, она непременно перехитрит.","th-TH":"Viper นักเคมีสาวชาวอเมริกันใช้อุปกรณ์ทางเคมีที่เป็นพิษเพื่อควบคุมสนามรบและบดบังทัศนวิสัยของศัตรู หากเหยื่อของเธอไม่ได้ตายด้วยพิษ ก็ตายด้วยสงครามจิตวิทยาเนี่ยแหละ","tr-TR":"Amerikalı kimyager Viper zehir yüklü, çeşit çeşit kimyasal cihazıyla savaş alanını kontrol altında tutarken düşmanın görüşünü de sekteye uğratır. Avını zehriyle değilse bile aklıyla mutlaka avcunun içine alır.","vi-VN":"Là Chuyên Gia Hóa Học người Mỹ, Viper tung ra một loạt các thiết bị hóa học độc hại để kiểm soát chiến trường và bóp nghẹt tầm nhìn của đối thủ. Nếu kẻ địch không bị tiêu diệt bởi chất độc thì cũng mất mạng bởi tâm thuật của cô.","zh-CN":"“蝰蛇”是一位来自美洲大陆的化学家，擅长部署毒性化学装置来控制战场并削弱敌人的视野。即便猎物没倒在她的毒素之下，她也会利用心理战将其击溃。","zh-TW":"薇蝮是名美國化學家，她的特長是部署五花八門的劇毒化武，掌控戰局的同時，還能妨礙敵人視野。即使毒藥沒能殺死對手，她的心理戰術也會虐死人。"}'::jsonb, 'Pandemic', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/displayicon.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/displayicon.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/fullportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/fullportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/fullportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/killfeedportrait.png', 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/minimapportrait.png', null, 'https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/background.png', array['1a5f46ff', '0f1923ff', '2c4f5eff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('707eab51-4836-f488-046a-cda6bf494859'::uuid, 'Ability1', '{"es-MX":"Nube Venenosa","ar-AE":"السحابة السامة","es-ES":"Nube venenosa","ja-JP":"ポイズンクラウド","it-IT":"Miasma","de-DE":"Giftwolke","id-ID":"Poison Cloud","ko-KR":"독성 연기","fr-FR":"Nuage de poison","en-US":"Poison Cloud","pl-PL":"Toksyczna Chmura","pt-BR":"Nuvem Venenosa","ru-RU":"Ядовитое облако","th-TH":"Poison Cloud","tr-TR":"ZEHİR BULUTU","vi-VN":"Cầu Hóa Chất","zh-CN":"瘴云","zh-TW":"腐蝕毒霧"}'::jsonb, '{"es-MX":"EQUIPA un lanzador de gas. DISPARA para lanzarlo y que permanezca durante la ronda. Usa el DISPARO SECUNDARIO para lanzarlo por debajo. VUELVE A USAR la habilidad para crear una nube de gas tóxica que hace decrecer la vida de los oponentes dentro de ella a costa de usar combustible. Esta habilidad se puede recoger y VOLVER A COLOCAR antes del comienzo de la ronda y se puede VOLVER A USAR más de una vez a lo largo de la misma.","ar-AE":"تجهّز بقدرة نافث غاز. أطلق لرمي النافث القادر على البقاء طيلة الجولة. استخدم الإطلاق البديل للإلقاء المقوس. أعد استخدام القدرة لإنشاء سحابة من الغاز السام تصيب الخصوم داخلها بتأثير التدهور مع استهلاك الوقود. يمكن التقاط هذه القدرة لإعادة نشرها مرة أخرى قبل بدء الجولة ويمكن إعادة استخدامها أكثر من مرة واحدة على مدار الجولة.","es-ES":"EQUIPA una granada de gas. DISPARA para lanzar la granada, que permanecerá toda la ronda. Utiliza el DISPARO ALTERNATIVO para tirarla. VUELVE A USAR la habilidad para generar una nube de gas tóxico que aplica declive a los rivales en su interior a cambio de combustible. La granada se puede recoger para VOLVER A COLOCARLA antes de que empiece la ronda y se puede VOLVER A USAR más de una vez durante la ronda.","ja-JP":"ガス発生器を構える。「発射」で発生器を投げる。この装置はラウンド終了まで残り続ける。「オルト射撃」で軽く放る。アビリティーを「再使用」すると、燃料を消費して有毒ガスの霧を発生させ、霧の中にいる敵に「衰弱」効果を与える。このアビリティーはラウンド開始までは回収して「再設置」することができ、ラウンド中は何度でも「再使用」できる。","it-IT":"EQUIPAGGIA un emettitore di gas. Usa il FUOCO per lanciare l''emettitore, che rimarrà dove è atterrato per tutto il round. Usa il FUOCO ALTERNATIVO per lanciare l''emettitore dal basso verso l''alto. USA DI NUOVO l''abilità per far produrre all''emettitore una nube di gas tossico che DETERIORA i bersagli al suo interno consumando carburante. L''emettitore può essere raccolto per essere RIPOSIZIONATO prima che il round inizi e questa abilità può essere usata PIÙ DI UNA VOLTA durante il round.","de-DE":"RÜSTE einen Gaskanister AUS. FEUERE, um den Kanister auf den Boden zu werfen, wo er die ganze Runde über liegen bleibt. ALT. FEUERMODUS für einen Unterhandwurf. REAKTIVIERE die Fähigkeit, um mit Treibstoff eine Giftgaswolke zu erschaffen. Gegner in der Wolke werden mit „Verfall“ belegt. Du kannst diese Fähigkeit ERNEUT EINSETZEN, bevor die Runde beginnt, und sie kann während der Runde mehr als einmal REAKTIVIERT werden.","id-ID":"EQUIP pemancar gas. Tekan FIRE untuk melempar pemancar yang terus ada sepanjang ronde. Tekan ALT FIRE untuk melempar tinggi. GUNAKAN LAGI ability ini untuk menciptakan awan gas beracun yang menerapkan Decay pada lawan di dalamnya dengan mengorbankan bahan bakar. Ability ini bisa diambil untuk DI-REDEPLOY sebelum ronde dimulai dan bisa DIGUNAKAN LAGI lebih dari satu kali sepanjang ronde.","ko-KR":"가스 방사기를 장착합니다. 발사 시 라운드 내내 유지되는 방사기를 던집니다. 보조 공격 시 가깝게 던집니다. 스킬을 재사용하면 연료를 소모해 적을 부패시키는 독성 가스 구름을 만듭니다. 라운드 시작 전에 주운 후 재배치할 수 있으며 라운드 중 한 번 이상 재사용이 가능합니다.","fr-FR":"ÉQUIPEZ-vous d''un diffuseur de gaz. TIREZ pour lancer le diffuseur, qui reste présent jusqu''à la fin de la manche. Utilisez le TIR SECONDAIRE pour le lancer en cloche. RÉUTILISEZ la compétence pour créer un nuage de fumée toxique qui désagrège les adversaires à l''intérieur en consommant du carburant. Cette compétence peut être ramassée et REDÉPLOYÉE avant le début de la manche et RÉUTILISÉE plus d''une fois pendant la manche.","en-US":"EQUIP a gas emitter. FIRE to throw the emitter that perpetually remains throughout the round. ALT FIRE to lob. RE-USE the ability to create a toxic gas cloud that Decays opponents inside it at the cost of fuel. This ability can be picked up to be REDEPLOYED before the round starts and can be RE-USED more than once throughout the round.","pl-PL":"WYPOSAŻ emiter gazu. STRZEL, by rzucić emiter, który można wykorzystywać przez całą rundę. Naciśnij ALT. STRZAŁ, by cisnąć. UŻYJ PONOWNIE tej umiejętności, by stworzyć chmurę toksycznego gazu, która wykorzystuje paliwo i powoduje rozpad objętych wrogów. Można podnieść i PONOWNIE ROZŁOŻYĆ przed rozpoczęciem rundy. Można UŻYĆ PONOWNIE więcej niż raz w trakcie rundy.","pt-BR":"EQUIPE um emissor de gás. DISPARE para jogar o emissor, que permanece até o fim da rodada. Use o DISPARO ALTERNATIVO para arremessar a curta distância. REPITA para criar uma nuvem de gás tóxico que consome combustível e causa Deterioração nos adversários dentro dela. A habilidade pode ser recolhida e REPOSICIONADA antes do início da rodada e pode ser REUTILIZADA mais de uma vez ao longo da rodada.","ru-RU":"Выбирает распылитель газа. Нажмите кнопку ОГОНЬ, чтобы выбросить распылитель, который остается на месте до конца раунда. Нажмите АЛЬТ. ОГОНЬ для броска снизу. Примените умение повторно, чтобы выпустить из распылителя облако ядовитого дыма, которое наносит периодический урон врагам, расходуя топливо. Можно подобрать и разместить заново перед началом раунда, а также использовать больше одного раза за раунд.","th-TH":"ติดตั้งอุปกรณ์ประจุควัน กดยิงเพื่อขว้างอุปกรณ์ประจุควันที่จะคงอยู่ตลอดจนจบเกมออกไป กดโหมดยิงเสริมเพื่อโยนออกไปในระยะสั้น ๆ ใช้สกิลอีกครั้งเพื่อสร้างหมอกควันพิษซึ่งจะทำให้คู่ต่อสู้ข้างในหมอกควันติดสภาวะเสื่อมสลายด้วยพลังงานสกิลที่มีอยู่ เก็บสกิลนี้คืนเพื่อให้พร้อมสำหรับการวางใหม่ได้ก่อนที่จะเริ่มรอบ และใช้ซ้ำได้มากกว่าหนึ่งครั้งตลอดทั้งรอบ","tr-TR":"Bir gaz salgılayıcı KUŞAN. Tur boyunca devamlı yerde kalacak salgılayıcıyı fırlatmak için ATEŞ ET. Yavaşça fırlatmak için ALT. ATIŞ kullan. Yakıt harcayarak içindeki rakiplere Çürüme uygulayan zehirli bir duman bulutu oluşturmak için yeteneği TEKRAR KULLAN. Bu yeteneği tur başlamadan önce TEKRAR YERLEŞTİRMEK üzere bıraktığın yerden alabilirsin ve tur boyunca birden fazla kez TEKRAR KULLANABİLİRSİN.","vi-VN":"TRANG BỊ 1 máy tạo hóa chất. BẮN để quăng thiết bị về phía trước, có thời gian tồn tại đến hết vòng đấu. BẮN PHỤ để ném cao. KÍCH HOẠT LẠI kỹ năng sẽ tiêu hao nhiên liệu và tạo ra 1 quả cầu hóa chất làm Phân Rã kẻ địch đứng bên trong. Kỹ năng này có thể được nhặt lên và ĐẶT LẠI trước khi vòng đấu bắt đầu, và có thể KÍCH HOẠT LẠI nhiều hơn 1 lần trong suốt vòng đấu.","zh-CN":"装备气雾喷射器，按【射击】将其掷出，该装置会一直存在至回合结束。按【辅助射击】可轻抛。【再次按技能键】可消耗燃料生成一团化学烟雾，消耗燃料对其中的敌人造成腐坏。回合开始前，可拾取喷射器，将其【重新部署】。在回合中，此技能可以多次【重复使用】。","zh-TW":"裝備一瓶瓦斯彈罐。點擊「攻擊」即可丟出，該回合中此彈罐不會消失。點擊「輔助攻擊」，則可低手拋出。「重施技能」可以製造一團毒霧，對毒霧中的對手造成「侵蝕」效果，須消耗自身的燃料存量。回合開始前，此技能可以撿起並「重新部署」，該回合中可多次「重新施放」。\r\n"}'::jsonb, '"https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('707eab51-4836-f488-046a-cda6bf494859'::uuid, 'Ability2', '{"es-MX":"Cortina Tóxica","ar-AE":"الجدار السام","es-ES":"Pantalla tóxica","ja-JP":"トキシックスクリーン","it-IT":"Quarantena","de-DE":"Toxinschirm","id-ID":"Toxic Screen","ko-KR":"독성 장막","fr-FR":"Écran toxique","en-US":"Toxic Screen","pl-PL":"Toksyczna Zasłona","pt-BR":"Cortina Tóxica","ru-RU":"Токсичная завеса","th-TH":"Toxic Screen","tr-TR":"ZEHİR PERDESİ","vi-VN":"Tường Hóa Chất","zh-CN":"毒幕","zh-TW":"毒雲瘴壁"}'::jsonb, '{"es-MX":"EQUIPA un lanzador de emisores de gas que penetran el terreno. DISPARA para desplegar una línea de emisores de gas. VUELVE A USAR la habilidad para crear un muro alto de gas tóxico que hace decrecer la vida de los oponentes que lo atraviesen a costa de usar combustible. Esta habilidad se puede VOLVER A USAR más de una vez.","ar-AE":"تجهّز بقاذفة نافثات الغاز التي تخترق التضاريس. أطلق القاذفة لنشر خط طويل من نافثات الغاز. أعد استخدام القدرة لإنشاء جدار مرتفع من الغاز السام يصيب الخصوم الذين يعبرونه بتأثير التدهور مع استهلاك الوقود. يمكن إعادة استخدام هذه القدرة أكثر من مرة.","es-ES":"EQUIPA un lanzagranadas de gas que atraviesa los obstáculos del terreno. DISPARA para desplegar una larga hilera de granadas de gas. VUELVE A USAR la habilidad para crear un alto muro de gas tóxico que aplica declive a los rivales en su interior a cambio de combustible. Se puede VOLVER A USAR más de una vez.","ja-JP":"地形を貫通してガス発生器を設置する射出装置を構える。「発射」で長い列状のガス発生器を射出する。アビリティーを「再使用」すると、燃料を消費して有毒ガスを高い壁状に発生させ、壁を通過した敵に「衰弱」効果を与える。このアビリティーは何度でも「再使用」できる。","it-IT":"EQUIPAGGIA un lancia-emettitori di gas che penetra nel terreno. Usa il FUOCO per piazzare una lunga linea di emettitori di gas. USA DI NUOVO l''abilità per innalzare un alto muro di gas tossico che DETERIORA i bersagli che lo attraversano consumando carburante. Questa abilità può essere RIATTIVATA più di una volta.","de-DE":"RÜSTE einen Gasventilwerfer AUS, das Terrain durchdringt. FEUERE, um eine lange Linie aus Gasventilen zu platzieren. REAKTIVIERE die Fähigkeit, um mit Treibstoff eine hohe Wand aus Giftgas zu erschaffen. Gegner, die die Wolke durchqueren, werden mit „Verfall“ belegt. Du kannst diese Fähigkeit mehrmals REAKTIVIEREN.","id-ID":"EQUIP pelontar pemancar gas yang menembus tanah. Tekan FIRE untuk mengerahkan sebaris panjang pemancar gas. GUNAKAN LAGI ability ini untuk menciptakan dinding tinggi gas beracun yang menerapkan utilitas Decay pada lawan yang melewatinya dengan mengorbankan bahan bakar. Ability ini bisa DIGUNAKAN LAGI lebih dari sekali.","ko-KR":"지형지물을 관통하는 가스 방사기 발사기를 장착합니다. 발사하면 여러 개의 가스 방사기를 일렬로 길게 배치합니다. 스킬을 다시 사용하면 연료를 소모해 가로지르는 적을 부패시키는 높은 독성 연기 장벽을 생성합니다. 이 스킬은 여러 번 재사용이 가능합니다.","fr-FR":"ÉQUIPEZ-vous d''un lance-diffuseurs de gaz qui traverse les obstacles. TIREZ pour déployer une longue ligne de diffuseurs de gaz. RÉUTILISEZ la compétence pour créer un mur de gaz toxique qui désagrège les adversaires qui le franchissent en consommant du carburant. Cette compétence peut être RÉUTILISÉE plus d''une fois.","en-US":"EQUIP a gas emitter launcher that penetrates terrain. FIRE to deploy a long line of gas emitters. RE-USE the ability to create a tall wall of toxic gas that Decays opponents that cross it at the cost of fuel. This ability can be RE-USED more than once.","pl-PL":"WYPOSAŻ wyrzutnię emitera gazu przebijającą otoczenie. STRZEL, by wypuścić długą linię emiterów gazu. UŻYJ PONOWNIE umiejętności, by stworzyć wysoką ścianę toksycznego gazu, która kosztem paliwa powoduje rozpad przekraczających ją przeciwników. Tej umiejętności można UŻYĆ PONOWNIE więcej niż raz.","pt-BR":"EQUIPE um lançador de emissores de gás que atravessam terreno. DISPARE para lançar uma longa linha de emissores de gás. REPITA para criar uma parede alta de gás tóxico que consome combustível causa Deterioração nos adversários dentro dela. A habilidade pode ser REPETIDA mais de uma vez.","ru-RU":"Выбирает распылители газа, проникающие сквозь препятствия. Нажмите кнопку ОГОНЬ, чтобы выстрелить длинной очередью распылителей. При повторном использовании распылители образуют стену ядовитого дыма, расходуя топливо. Враги, пересекающие стену, получают периодический урон. Умение можно применять больше одного раза.","th-TH":"ติดตั้งเครื่องยิงอุปกรณ์ประจุควันที่ทะลุสิ่งกีดขวางได้ กดยิงเพื่อติดตั้งอุปกรณ์ประจุควันเป็นแนวยาว ใช้สกิลอีกครั้งเพื่อสร้างกำแพงควันพิษซึ่งจะทำให้คู่ต่อสู้ที่เดินผ่านกำแพงควันพิษติดสภาวะเสื่อมสลายด้วยพลังงานสกิลที่มีอยู่ สกิลนี้ใช้ซ้ำได้มากกว่าหนึ่งครั้ง","tr-TR":"Yüzeyleri delip geçen bir gaz salgılayıcı fırlatıcısı KUŞAN. Gaz salgılayıcılardan uzun bir hat oluşturmak için ATEŞ ET. Yeteneği TEKRAR KULLAN ve içinden geçen rakiplere Çürüme uygulayan yüksek bir zehir duvarı yakıt karşılığında oluştur. Bu yetenek birden fazla kez TEKRAR KULLANILABİLİR.","vi-VN":"TRANG BỊ 1 thiết bị phóng máy tạo khí độc có khả năng bắn xuyên địa hình. BẮN để đặt 1 hàng dài các máy tạo khí độc. TÁI SỬ DỤNG kỹ năng này để tiêu hao nhiên liệu và tạo ra một bức tường khí độc làm Phân Rã kẻ địch đi qua. Kỹ năng này có thể TÁI SỬ DỤNG nhiều hơn 1 lần.","zh-CN":"装备可穿越地形的气雾喷射器，按【射击】沿一条直线部署气雾喷射器阵列。【再次按技能键】可产生一道气雾幕墙，消耗燃料对穿过幕墙的敌人造成腐坏。此技能可以多次【重复使用】。","zh-TW":"裝備可穿透地形物的瓦斯彈罐發射器。點擊「攻擊」即可部署一直線的瓦斯彈罐。「重施技能」須消耗自身的燃料存量，可製造一道高聳的毒氣瘴壁，對穿越的對手造成「侵蝕」效果。此技能可多次「重新施放」。"}'::jsonb, '"https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('707eab51-4836-f488-046a-cda6bf494859'::uuid, 'Grenade', '{"es-MX":"Mordedura","ar-AE":"لدغة الأفعى","es-ES":"Veneno de serpiente","ja-JP":"スネークバイト","it-IT":"Morso velenoso","de-DE":"Kontamination","id-ID":"Snake Bite","ko-KR":"뱀 이빨","fr-FR":"Morsure du serpent","en-US":"Snake Bite","pl-PL":"Jadowite Ukąszenie","pt-BR":"Veneno de Cobra","ru-RU":"Змеиный укус","th-TH":"Snake Bite","tr-TR":"ASİT HAVUZU","vi-VN":"Bẫy Hóa Chất","zh-CN":"蛇吻","zh-TW":"蛇咬毒液"}'::jsonb, '{"es-MX":"EQUIPA un lanzador de químicos. DISPARA para lanzar un contenedor que se rompe al impactar contra el suelo y crea una zona química que permanece en el campo, la cual inflige daño y aplica Vulnerable.","ar-AE":"تجهّز بقاذفة كيميائية. أطلق لترسل عبوة تتهشم عند اصطدامها بالأرض لتنشئ منطقة كيميائية طويلة الأمد تسبب الضرر وتأثير الهشاشة.","es-ES":"EQUIPA un lanzador químico. DISPARA para lanzar un cartucho que se rompe al impactar contra el suelo, lo que genera una zona química persistente que inflige daño y aplica vulnerabilidad.","ja-JP":"化学物質の射出装置を構える。「発射」で化学物質のキャニスターを射出する。このキャニスターは地面に触れると破裂して、化学物質の汚染地帯を作り出す。汚染は長時間持続し、踏み込んだ者にダメージと弱体化を与える。","it-IT":"EQUIPAGGIA un lanciagranate chimico. Usa il FUOCO per lanciare una fiala che si infrange al contatto col suolo, generando una pozzanghera acida che danneggia i nemici e li rende Vulnerabili.","de-DE":"RÜSTE einen Chemikalienwerfer AUS. FEUERE, um einen Kanister abzuschießen, der beim Aufprall auf dem Boden zerspringt und eine temporäre Chemikalienpfütze hinterlässt, die Schaden zufügt und mit „Verwundbar“ belegt.","id-ID":"EQUIP pelontar zat kimia. Tekan FIRE untuk melontarkan tabung yang hancur saat membentur lantai. Tabung menghasilkan zona kimia tahan lama yang memberikan damage dan utilitas Vulnerable.","ko-KR":"화학 물질 발사기를 장착합니다. 발사하면 바닥에 떨어졌을 때 폭발하는 통을 날립니다. 통은 폭발하며 적에게 취약을 적용하고 피해를 입히는 화학 물질 지역을 일정 시간 동안 생성합니다.","fr-FR":"ÉQUIPEZ-vous d''un lance-grenades chimiques. TIREZ pour lancer une grenade qui se brise en touchant le sol, créant une zone chimique persistante qui inflige des dégâts et l''altération d''état Vulnérable.","en-US":"EQUIP a chemical launcher. FIRE to launch a canister that shatters upon hitting the floor, creating a lingering chemical zone that damages and applies Vulnerable.","pl-PL":"WYPOSAŻ wyrzutnię chemikaliów. STRZEL, by odpalić kanister, który rozbija się po kontakcie z ziemią. W wyniku tego powstaje tymczasowa chemiczna strefa, która zadaje obrażenia i powoduje podatność.","pt-BR":"EQUIPE um lançador químico. DISPARE para lançar um cilindro que se rompe ao atingir o chão, gerando uma zona química duradoura que causa dano aos inimigos e aplica Vulnerável a eles.","ru-RU":"Выбирает капсулу с кислотой. Нажмите кнопку ОГОНЬ, чтобы запустить капсулу, которая разбивается при падении, оставляя после себя лужу кислоты. Попавшие в кислоту противники получают урон и становятся уязвимыми.","th-TH":"ติดตั้งเครื่องยิงสารเคมี กดยิงเพื่อปล่อย\nกระป๋องที่จะระเบิดเมื่อตกถึงพื้น ก่อให้เกิด\nพื้นที่เขตสารเคมีที่สร้างความเสียหายให้กับศัตรูและ\nสร้างความอ่อนแอกับพวกเขา","tr-TR":"Bir kimyasal fırlatıcı KUŞAN. Yere çarptığında parçalanan bir kapsül fırlatmak için ATEŞ ET. Oluşturduğu uzun süreli kimyasal alanda kalan düşmanlar hasar alır ve Savunmasız hale gelir.","vi-VN":"TRANG BỊ 1 thiết bị phóng hóa chất. BẮN để phóng 1 ống hóa chất sẽ vỡ khi chạm đất và tạo ra một vùng hoá chất có khả năng gây sát thương và gây hiệu ứng Suy Yếu.","zh-CN":"装备化学品发射器，按【射击】即可射出一个触地即碎的化学容器，碎裂后会留下一滩化学溶液，对范围内的目标造成伤害并施加【易伤】。","zh-TW":"裝備一個化武發射器。點擊「攻擊」即可發射一個觸地後立刻碎裂的化武罐，形成一個受到化合物汙染、持續揮發毒性的區域，身處其中時會感到衰弱。"}'::jsonb, '"https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('707eab51-4836-f488-046a-cda6bf494859'::uuid, 'Ultimate', '{"es-MX":"Fosa Vipérea","ar-AE":"جحر الأفعى","es-ES":"Pozo de la víbora","ja-JP":"ヴァイパーズピット","it-IT":"Rischio biologico","de-DE":"Schlangengrube","id-ID":"Viper''s Pit","ko-KR":"독사의 구덩이","fr-FR":"Nid de vipères","en-US":"Viper''s Pit","pl-PL":"Gniazdo Żmij","pt-BR":"Poço Peçonhento","ru-RU":"Гнездо гадюки","th-TH":"Viper''s Pit","tr-TR":"VIPER''IN İNİ","vi-VN":"Hang Xà","zh-CN":"蝰腹","zh-TW":"蝮蛇領域"}'::jsonb, '{"es-MX":"EQUIPA un rociador y DISPARA para lanzar una nube de químicos en todas direcciones alrededor de Viper, lo cual crea una gran nube que ofusca a los jugadores y reduce la vida de los enemigos que estén dentro de ella. MANTÉN PRESIONADO el botón de la habilidad para desactivar la nube manualmente.","ar-AE":"تجهّز ببخاخ كيميائي. أطلق لنشر سحابة كيميائية في جميع الاتجاهات حول فايبر، مما يكوّن سحابة واسعة النطاق تصيب اللاعبين بتأثير قصر النظر وتدهور صحة الأعداء داخل النطاق. تابع الضغط على زر القدرة لتشتيت السحابة مبكرًا.","es-ES":"EQUIPA un pulverizador químico. DISPARA para pulverizar una nube química en todas direcciones alrededor de Viper, lo que genera una gran nube que limita la visión de los jugadores y aplica declive a la vida de los enemigos que se encuentren dentro de ella. MANTÉN PULSADA la tecla de habilidad para hacer que la nube se disperse antes de tiempo.","ja-JP":"化学物質の散布装置を構える。「発射」でヴァイパーの周囲の全方向に化学物質を噴霧し、広い範囲に霧を発生させる。霧の内部にいるプレイヤーは視界が悪化し、敵である場合は「衰弱」も引き起こす。アビリティーキーを「長押し」で、この霧を早期に消すことができる。","it-IT":"EQUIPAGGIA un nebulizzatore chimico. Usa il FUOCO per diffondere una nube chimica che si espande in tutte le direzioni intorno a Viper. La nuvola tossica così creata ANNEBBIA i giocatori e DETERIORA la salute massima dei nemici al proprio interno. TIENI PREMUTA l''abilità per disperdere prima la nube.","de-DE":"RÜSTE einen Chemikalienzerstäuber AUS. FEUERE, um eine Chemikalienwolke rund um Viper herum zu versprühen. Diese Wolke schränkt die Sichtweite aller Spieler ein und lässt das Leben von Gegnern in ihr sinken. HALTE die Fähigkeiten-Taste, um die Wolke frühzeitig freizusetzen.","id-ID":"EQUIP penyemprot zat kimia. Tekan FIRE untuk menyemprotkan awan zat kimia ke segala arah di sekitar Viper, yang memberi utilitas Nearsight pada pemain dan utilitas Decay pada health musuh. Tekan TAHAN pada tombol ability untuk menyebarkan awan lebih awal.","ko-KR":"화학 물질 분사기를 장착합니다. 발사하면 사방으로 화학 물질 연기를 분사해 안에 있는 플레이어의 시야를 제한하고 적의 체력을 부패시키는 거대 연기를 생성합니다. 스킬 키를 길게 누르면 연기가 일찍 사라집니다.","fr-FR":"ÉQUIPEZ-vous d''un vaporisateur chimique. TIREZ pour vaporiser un nuage chimique tout autour de Viper, créant un large nuage qui rend myopes les joueurs et désagrège les PV des ennemis qui se trouvent dedans. MAINTENEZ la touche de la compétence pour dissiper le nuage prématurément.","en-US":"EQUIP a chemical sprayer. FIRE to spray a chemical cloud in all directions around Viper, creating a large cloud that Nearsights players and Decays the health of enemies inside of it. HOLD the ability key to disperse the cloud early.","pl-PL":"WYPOSAŻ rozpylacz chemikaliów. STRZEL, by rozpylić wokół Viper chemiczną chmurę, tworząc spory obłok, który wywołuje krótkowzroczność u graczy i powoduje rozpad zdrowia wrogów na obszarze jego działania. PRZYTRZYMAJ przycisk umiejętności, by wcześniej rozproszyć chmurę.","pt-BR":"EQUIPE um borrifador químico. DISPARE para borrifar uma nuvem química em todas as direções ao redor de Viper, criando uma grande nuvem que causa Visão Turva e Deteriora a Vida dos inimigos dentro dela. SEGURE a tecla de habilidade para dispersar a nuvem mais cedo.","ru-RU":"Выбирает распылитель химикатов. Нажмите кнопку ОГОНЬ, чтобы распылить вокруг Viper облако химикатов, ограничивая обзор находящихся в нем игроков и нанося им периодический урон. Удерживайте кнопку умения, чтобы остановить распыление.","th-TH":"ติดตั้งเครื่องพ่นสเปรย์เคมี กดยิงเพื่อสเปรย์กลุ่มควันเคมีทุกทิศทางรอบ ๆ Viper สร้างกลุ่มควันขนาดใหญ่ที่จะจำกัดการมองเห็นและสร้างความเสื่อมสลายแก่พลังชีวิตของศัตรูที่ติดอยู่ภายใน กดปุ่มสกิลค้างไว้เพื่อสลายควันก่อนเวลา","tr-TR":"Bir kimyasal püskürtücü KUŞAN. Viper''ın etrafında her yöne yayılan kimyasal bir bulut oluşturmak için ATEŞ ET. Oluşan geniş bulut, içinde kalan oyuncuların Görüşünü Kısıtlar ve düşmanların canlarını Çürütür. Bulutu erken dağıtmak için yetenek düğmesini BASILI TUT.","vi-VN":"TRANG BỊ 1 máy phun hóa chất. BẮN để phun hóa chất ra mọi hướng xung quanh Viper, tạo 1 đám khói có khả năng Hạn Chế Tầm Nhìn của người chơi và Phân Rã máu tối đa của kẻ địch trong phạm vi. GIỮ phím kỹ năng để làm tan khói sớm hơn.","zh-CN":"装备化学喷雾器。按【射击】即可朝蝰蛇的四周喷射化学气雾，产生大片云雾，使范围内的玩家【视野收缩】并使敌人受到【腐坏】效果。【按住技能键】可使气雾提前消散。","zh-TW":"裝備一個化武噴霧器。點擊「攻擊」，即可在薇蝮身周噴出霧狀化武，製造一片大型毒霧雲，可「限制玩家視野」，並「毒蝕」範圍內敵人的生命值。長按「技能」可提早解除毒霧雲。"}'::jsonb, '"https://media.valorant-api.com/agents/707eab51-4836-f488-046a-cda6bf494859/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('eb93336a-449b-9c1b-0a54-a891f7921d69'::uuid, '{"es-MX":"Phoenix","ar-AE":"فينيكس","es-ES":"Phoenix","ja-JP":"フェニックス","it-IT":"Phoenix","de-DE":"Phoenix","id-ID":"Phoenix","ko-KR":"피닉스","fr-FR":"Phoenix","en-US":"Phoenix","pl-PL":"Phoenix","pt-BR":"Phoenix","ru-RU":"Phoenix","th-TH":"Phoenix","tr-TR":"PHOENIX","vi-VN":"Phoenix","zh-CN":"不死鸟","zh-TW":"菲尼克斯"}'::jsonb, '{"es-MX":"Phoenix proviene del Reino Unido. El poder estelar de Phoenix se manifiesta en su estilo de combate al incendiar el campo de batalla con sus granadas aturdidoras y cegadoras. Sin importar si cuenta con apoyo o no, participará en la batalla bajo sus propios términos.","ar-AE":"تظهر قوة النجم التي يتمتع بها فينيكس القادم من المملكة المتحدة جلية في أسلوبه القتالي، حيث يشعل ميدان القتال بتألقه ووميضه. وسواء كانت لديه رفقة أم لا فهو يندفع نحو القتال دائمًا دون انتظار أحد.","es-ES":"Phoenix proviene del Reino Unido y sus poderes estelares salen a relucir con su estilo de combate, que prende fuego al campo de batalla de forma deslumbrante. Con apoyo o en solitario, él es quien decide cuándo y cómo se lucha.","ja-JP":"イギリスからやってきたスター、フェニックスの力は、彼自身の戦闘スタイルによってさらに輝きを増し、戦場を閃光と火炎で燃え上がらせる。彼は援護の有無など気にもせず、単身で戦闘の只中に飛び込んでいくのだ。","it-IT":"Originario del Regno Unito, Phoenix brilla per il suo stile di combattimento, che infiamma il campo di battaglia come un lampo abbagliante. Con o senza rinforzi, è sempre pronto a gettarsi nella mischia secondo le sue regole.","de-DE":"Phoenix stammt aus Großbritannien und seine Starqualitäten kommen auch in seinen Kampffähigkeiten zur Geltung. Ob mit oder ohne Verstärkung - der Kampf beginnt, wenn er es sagt.","id-ID":"Berasal dari Britania Raya, kilau daya tarik Phoenix terlihat dalam gaya bertarungnya, menyulut battlefield dengan kilat dan api. Saat sendiri maupun dibantu rekannya, dia akan memasuki pertarungan sesuka hatinya.","ko-KR":"영국 출신 피닉스의 탁월한 능력은 전장을 섬광탄과 불꽃으로 수놓는 전투 스타일에서 비롯됩니다. 팀의 지원이 있든 없든 피닉스는 자신만의 방식으로 전투를 이끌어갑니다.","fr-FR":"En provenance du Royaume-Uni, Phoenix illumine le champ de bataille avec ses pouvoirs astraux et son style de combat flamboyant. Peu importe que les renforts arrivent ou non, il fonce au combat quand il le décide.","en-US":"Hailing from the U.K., Phoenix''s star power shines through in his fighting style, igniting the battlefield with flash and flare. Whether he''s got backup or not, he''s rushing in to fight on his own terms.","pl-PL":"Wywodzący się z Wielkiej Brytanii Phoenix bryluje na polu walki za sprawą swych popisowych mocy, rozjaśniając okolicę błyskiem i stylem. Z towarzyszami lub bez, zawsze rwie się do starcia na własnych zasadach.","pt-BR":"Chegando com tudo diretamente do Reino Unido, o poder estelar de Phoenix reluz em seu estilo de luta, incendiando o campo de batalha com luz e estilo. Tendo ajuda ou não, ele entra na luta como e quando achar que deve.","ru-RU":"Представитель Великобритании Phoenix демонстрирует звездную силу во всех аспектах своего боевого стиля: он сражается красиво и ярко, всегда навязывает противнику свои условия и отважно устремляется в бой даже без поддержки.","th-TH":"Phoenix ผู้มีชื่อเสียงเลื่องลือแห่งสหราชอาณาจักร พลังของเขาลุกโชติช่วงด้วยสไตล์การต่อสู้ ซึ่งเผาไหม้สนามรบให้เป็นจุณด้วยแสงสว่างและเปลวไฟ ไม่ว่าจะมีทีมคอยสนับสนุนหรือไม่ \nเขาก็จะพุ่งสู่สงครามด้วยความตั้งใจของตนเองเสมอ","tr-TR":"Aramıza Birleşik Krallık''tan katılan ve yıldızlardan aldığı gücü dövüş stilinin her noktasına yansıtan Phoenix, savaş alanını alevlerle ve patlamalarla aydınlatır. Arkasında destek olsun olmasın, bildiği gibi savaşmak için ileri atılacağından şüpheniz olmasın.","vi-VN":"Xuất thân từ nước Anh đầy mưa gió, sức mạnh của Phoenix nằm ở lối chiến đấu của hắn, với khả năng thiêu đốt cả chiến trường bằng hỏa mù chói lóa. Phoenix luôn tỏa sáng dù là phối hợp tác chiến cùng đồng đội hay chiến đấu độc lập.","zh-CN":"来自不列颠群岛的“不死鸟”举手投足中无处不洋溢着大牌明星风范，他就像一团耀眼的烈焰，动辄燃遍全场。对他来说，有没有后援不重要，冲锋陷阵时的派头更重要。","zh-TW":"菲尼克斯來自英國，他的星辰之力融會於其戰鬥風格中，發出的烈焰足以讓星火燎原。不管有沒有後援，他都能衝鋒陷陣，獨自撂倒敵人。"}'::jsonb, 'Phoenix', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/displayicon.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/displayicon.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/fullportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/fullportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/fullportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/killfeedportrait.png', 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/minimapportrait.png', null, 'https://media.valorant-api.com/agents/eb93336a-449b-9c1b-0a54-a891f7921d69/background.png', array['74321cff', '0f1923ff', '262423ff', '0f192300'], true, true, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, '{"es-MX":"Veto","ar-AE":"فيتو","es-ES":"Veto","ja-JP":"ヴィトー","it-IT":"Veto","de-DE":"Veto","id-ID":"Veto","ko-KR":"비토","fr-FR":"Veto","en-US":"Veto","pl-PL":"Veto","pt-BR":"Veto","ru-RU":"Veto","th-TH":"Veto","tr-TR":"VETO","vi-VN":"Veto","zh-CN":"禁灭","zh-TW":"維托"}'::jsonb, '{"es-MX":"Veto es un vigilante originario de Senegal que, con la ayuda de una mutación genética, desafía las reglas del combate al anular los poderes y la tecnología de sus oponentes. En el campo de batalla de Veto, las armas son tu única garantía.","ar-AE":"مع تعزيزه بطفرته الجينية الفائقة، يتحدى الشرطي السنغالي فيتو قواعد الاشتباك عبر إبطال مفعول قدرات خصومه وتقنياتهم. في معارك فيتو، مهاراتك في استخدام الأسلحة هي الضمان الوحيد للنجاة.","es-ES":"Veto, un asesino a sueldo senegalés cuya fuerza radica en una potente mutación genética, pone en jaque el funcionamiento de las iniciaciones anulando tanto las capacidades como la tecnología de su oponente. Cuando juegas en el campo de Veto, las armas de fuego son el mejor aliado.","ja-JP":"セネガル出身のヴィトーは制御不能なDNA変異によって力を得た武闘派の精鋭だ。敵のパワーとテクノロジーを無効化し、戦いのルールを塗り替える。戦場にヴィトーがいるなら、確実なのは銃撃だけだ。","it-IT":"Potenziato da un''inarrestabile mutazione genetica, il vigilante senegalese Veto infrange ogni regola d''ingaggio annullando i poteri e la tecnologia degli avversari. Quando Veto è in battaglia, le armi sono l''unica certezza.","de-DE":"Seine unglaublichen DNA-Mutationen versetzen den senegalesischen Vollstrecker Veto in die Lage, alle Kräfte und Technologien seiner Gegner zu neutralisieren und so die Situation auf dem Schlachtfeld grundlegend umzuwälzen. Auf Vetos Schlachtfeld kannst du dich nur auf deine Waffe verlassen.","id-ID":"Diperkuat mutasi DNA yang tak terbendung, enforcer asal Senegal Veto menabrak aturan tempur dengan melumpuhkan kekuatan dan teknologi lawannya. Di medan tempur Veto, tembakan adalah satu-satunya peganganmu.","ko-KR":"멈출 수 없는 DNA 변이로 강화된 세네갈 출신 집행자 비토는 상대의 능력과 기술을 무력화함으로써 교전 수칙을 무시합니다. 비토의 전장에서 믿을 건 사격 실력뿐입니다.","fr-FR":"Alimenté par une mutation génétique imparable, Veto, l''homme de main sénégalais, défie les règles du combat en neutralisant les pouvoirs et la technologie de ses adversaires. La seule chose que vous trouverez avec Veto sur le champ de bataille, c''est des armes.","en-US":"Empowered by an unstoppable DNA mutation, Senegalese enforcer Veto defies the rules of engagement by nullifying his opponent''s powers and technology. On Veto''s battlefield, gunplay is your only guarantee.","pl-PL":"Senegalski stróż prawa Veto, wzmocniony przez niepohamowaną mutację DNA, tworzy własne zasady walki, przeciwdziałając mocom i technologii przeciwnika. Gdy mu się sprzeciwiasz, możesz ufać wyłącznie swojej broni palnej.","pt-BR":"Portador de uma mutação genética avassaladora, o implacável Agente senegalês Veto desafia as regras do combate, anulando os poderes e as tecnologias de seus oponentes. No campo de batalha do Veto, a troca de tiros é sua melhor opção.","ru-RU":"Veto, заступник из Сенегала, усилен мощной мутацией ДНК. Он меняет правила ведения боя, нейтрализуя силы и технику врага. Сражаясь с Veto, можно полагаться только на оружие.","th-TH":"Veto ผู้รักษากฎหมายชาวเซเนกัลที่ได้รับพลังจากการกลายพันธุ์ของ DNA ที่ไม่อาจหยุดยั้งได้ แหกกฎการต่อสู้ด้วยการทำให้พลังและเทคโนโลยีของคู่ต่อสู้ไร้ผล ในสนามรบของ Veto มีแต่ปืนเท่านั้นที่จะช่วยคุณได้","tr-TR":"Durdurulamaz bir DNA mutasyonuyla gücüne güç katan Senegalli fedai Veto, rakibinin güçlerini ve teknolojisini etkisiz kılarak çatışma kurallarını hiçe sayıyor. Veto''nun savaş meydanında tek güvenilir seçeneğin silahların.","vi-VN":"Được cường hóa bởi đột biến gien bất khả kháng cự, Veto - người thi hành luật đến từ Senegal - thách thức mọi quy tắc chiến đấu bằng cách vô hiệu hóa toàn bộ sức mạnh và công nghệ của đối thủ. Trên chiến trường của Veto, kỹ năng bắn súng là thứ duy nhất giúp bạn toàn mạng.","zh-CN":"来自西非的“禁灭”是一名压制型英雄，因基因突变获得了超凡力量。禁灭打破了既有的战斗规则，无论敌人使出怎样的手段和科技，在他面前都形同虚设。禁灭出现在战场上时，只有枪法才是你唯一的保障。","zh-TW":"維托是來自塞內加爾的執法者，身上帶有無可遏抑的DNA突變，也因此獲得能力強化。他能使對手的能力和科技武器變成毫無作用，完全視戰鬥規則為無物。與維托交戰時，槍法是你唯一的依靠。"}'::jsonb, 'Pine', '2025-10-07T22:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/displayicon.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/displayicon.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/fullportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/fullportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/fullportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/killfeedportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/minimapportrait.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/homescreenpromotileimage.png', 'https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/background.png', array['1a5d65ff', '0f1923ff', '0f1923ff', '1a5d65ff'], false, false, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, 'Ability2', '{"es-MX":"Interceptor","ar-AE":"جهاز الاعتراض","es-ES":"Interceptor","ja-JP":"インタセプター","it-IT":"Intercettore","de-DE":"Abfänger","id-ID":"Interceptor","ko-KR":"요격기","fr-FR":"Intercepteur","en-US":"Interceptor","pl-PL":"Interceptor","pt-BR":"Interceptador","ru-RU":"Перехватчик","th-TH":"Interceptor","tr-TR":"TEHDİTSAVAR","vi-VN":"Đánh Chặn","zh-CN":"噬源体","zh-TW":"攔截器"}'::jsonb, '{"es-MX":"EQUIPA el Interceptor. DISPARA para colocar el Interceptor en la ubicación prevista. Una vez colocado, VUELVE A USAR para activarlo. Una vez activado, destruirá cualquier utilidad que pueda REBOTAR contra un jugador o que se pueda destruir de forma normal con disparos. Los enemigos pueden destruir el Interceptor.","ar-AE":"تجهّز بجهاز الاعتراض. أطلق لوضع جهاز الاعتراض في الموضع المحدد. بعد وضعه، أعد الاستخدام لتفعيله. عند التفعيل، سيدمّر أي معدات قابلة للارتداد عن اللاعب و\\أو  قابلة للتدمير بإطلاق النار عليها. يستطيع الأعداء تدمير جهاز الاعتراض.","es-ES":"EQUIPA el interceptor. DISPARA para colocar el interceptor en la ubicación proyectada. Una vez colocado, VUELVE A USAR la habilidad para activarlo. Cuando esté activado, destruirá toda la utilidad que fuera a rebotar contra un jugador o a resultar eliminada de forma natural con disparos. Los enemigos pueden destruir el interceptor.","ja-JP":"インタセプターを構える。「発射」でインタセプターを指定の地点に設置する。設置後、「再使用」で起動できる。起動中は、プレイヤーに当たると跳ね返るユーティリティーまたは銃撃により破壊可能なユーティリティーを破壊する。敵はインタセプターを破壊可能。","it-IT":"EQUIPAGGIA l''Intercettore. Usa il FUOCO per piazzare l''Intercettore nel punto evidenziato. Dopo il piazzamento, USA DI NUOVO per attivarlo. Una volta attivato, distruggerà qualsiasi utilità che RIMBALZEREBBE su un giocatore e/o verrebbe distrutta naturalmente dalle armi da fuoco. I nemici possono distruggere l''Intercettore.","de-DE":"RÜSTE den Abfänger AUS. FEUERE, um den Abfänger am gewählten Zielort zu platzieren. VERWENDE ihn nach dem Platzieren ERNEUT, um ihn zu aktivieren. Sobald er aktiv ist, zerstört er jegliche Unterstützung, die an einem Spieler ABPRALLEN würde und/oder durch Beschuss zerstört würde. Gegner können den Abfänger zerstören.","id-ID":"EQUIP Interceptor. TEKAN FIRE untuk menempatkan Interceptor di lokasi yang diproyeksikan. Setelah ditempatkan, GUNAKAN LAGI untuk mengaktifkan. Setelah aktif, Interceptor akan menghancurkan semua utility yang akan MEMANTUL dari pemain dan/atau hancur sendiri oleh tembakan. Musuh bisa menghancurkan Interceptor.","ko-KR":"요격기를 장착합니다. 발사하면 예상 위치에 요격기를 설치합니다. 설치 후 다시 사용하면 활성화됩니다. 활성화되면 플레이어에게서 튕겨 나오거나 사격으로 파괴할 수 있는 모든 장치를 파괴합니다. 적이 요격기를 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous de l''intercepteur. TIREZ pour placer l''intercepteur à l''emplacement prévu. Une fois placé, RÉUTILISEZ cette compétence pour activer. Une fois activé, il détruira les utilitaires qui peuvent REBONDIR sur un joueur et/ou être détruits par des tirs. Les ennemis peuvent détruire l''intercepteur.","en-US":"EQUIP the Interceptor. FIRE to place the Interceptor at projected location. Once placed, RE-USE to activate. Once active, it will destroy any utility that would BOUNCE off a player and/or be destroyed naturally by gunfire. Enemies can destroy the Interceptor.","pl-PL":"WYPOSAŻ Interceptor. STRZEL, aby umieścić Interceptor we wskazanym miejscu. Po umieszczeniu UŻYJ PONOWNIE, by go aktywować. Po aktywacji zniszczy każdy przedmiot użytkowy, który ODBIŁBY się od gracza lub został normalnie zniszczony przez ostrzał. Wrogowie mogą zniszczyć ten Interceptor.","pt-BR":"EQUIPE o Interceptador. DISPARE para posicionar o Interceptador no local determinado. Depois de posicionado, REPITA para ativar. Uma vez ativado, ele destruirá qualquer utilitário que REBATERIA em um jogador e/ou que seria destruído naturalmente por tiros. Inimigos podem destruir o Interceptador.","ru-RU":"Выбирает перехватчик. Нажмите ОГОНЬ, чтобы разместить перехватчик в выбранной точке. При повторном применении умения перехватчик активируется. После активации он уничтожает любое устройство, которое отскочило бы от агента и/или могло бы быть уничтожено выстрелами. Враги могут уничтожить перехватчик.","th-TH":"ติดตั้ง Interceptor กดยิงเพื่อวาง Interceptor ไว้ในตำแหน่งที่แสดง หลังจากวางแล้ว ให้ใช้งานอีกครั้งเพื่อเปิดใช้งาน หลังจากเปิดใช้งานแล้ว จะทำลายสกิลที่จะกระเด้งออกจากผู้เล่นและ/หรือถูกยิงทำลายได้ ศัตรูสามารถทำลาย Interceptor ได้","tr-TR":"Tehditsavar''ı KUŞAN. Tehditsavar''ı belirlenen konuma yerleştirmek için ATEŞ ET. Yerleştirdikten sonra etkinleştirmek için TEKRAR KULLAN. Etkin haldeki Tehditsavar bir oyuncudan SEKEBİLEN veya silahla yok edilebilen bütün yetenekleri yok eder. Düşmanlar Tehditsavar''ı yok edebilir.","vi-VN":"TRANG BỊ Mảnh Đánh Chặn. BẮN để đặt Mảnh Đánh Chặn tại địa điểm chỉ định. Sau khi đặt, TÁI SỬ DỤNG để kích hoạt. Sau khi kích hoạt, mảnh dị thể này sẽ phá hủy mọi tiện ích có thể NẢY khỏi người chơi hoặc bị phá hủy do trúng đạn. Kẻ địch có thể phá hủy Mảnh Đánh Chặn.","zh-CN":"装备噬源体。按【射击】将其部署至目标位置。部署后，【再次使用】技能即可激活。激活后，噬源体将摧毁一切能从玩家身上弹开或被枪火自然摧毁的装置。 噬源体可被敌人摧毁。 ","zh-TW":"裝備攔截器。點擊「攻擊」可將攔截器放置於指定地點。放置後，「重施技能」即可啟用。啟用後，它會摧毀任何會從玩家身上反彈和/或可被槍火摧毀的戰略工具。敵軍可破壞攔截器。"}'::jsonb, '"https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, 'Grenade', '{"es-MX":"Corte Transversal","ar-AE":"الصدع العرضي","es-ES":"Corte transversal","ja-JP":"クロスカット","it-IT":"Scorciatoia","de-DE":"Kreuzhieb","id-ID":"Crosscut","ko-KR":"지름길","fr-FR":"Vortex","en-US":"Crosscut","pl-PL":"Skrót","pt-BR":"Travessia","ru-RU":"Связка","th-TH":"Crosscut","tr-TR":"GERİ SAR","vi-VN":"Lối Tắt","zh-CN":"涡流折跃","zh-TW":"穿越之徑"}'::jsonb, '{"es-MX":"EQUIPA un vórtice. DISPARA para colocarlo en el suelo. Mientras estés dentro del alcance y mirando al vórtice, ACTIVA para teletransportarte a él. Durante la FASE DE COMPRA, el vórtice se puede recuperar para VOLVER A USARLO.","ar-AE":"تجهّز بدوّامة. أطلق لوضعها على الأرض. عند الوجود ضمن النطاق والنظر إلى الدوّامة، قم بالتفعيل لتنفيذ الانتقال السريع إليها. خلال مرحلة الشراء، يمكن استرجاع الدوّامة لإعادة نشرها.","es-ES":"EQUIPA un remolino. DISPARA para colocarlo en el suelo. Cuando tengas el remolino al alcance y te posiciones en su dirección, ACTIVA para teleportarte hasta él. Durante la FASE DE COMPRA, puede recuperarse el remolino para VOLVER A COLOCARLO.","ja-JP":"渦状の物体を装備する。「発射」で地面に設置する。範囲内で渦を見ている間に「発動」すると、渦の位置にテレポートする。購入フェーズ中、渦は回収して再設置が可能。","it-IT":"EQUIPAGGIA un vortice. Usa il FUOCO per piazzarlo a terra. Mentre sei a portata e guardi il vortice, ATTIVA per teletrasportarti su di esso. Durante la FASE DI ACQUISTO, è possibile recuperare il vortice per RIUTILIZZARLO.","de-DE":"RÜSTE einen Strudel AUS. FEUERE, um ihn auf dem Boden zu platzieren. Solange du in Reichweite bist und den Strudel ansiehst, kannst du ihn AKTIVIEREN, um dich zu ihm zu teleportieren. In der KAUFPHASE kann der Strudel zurückgeholt und NEU AUFGESTELLT werden.","id-ID":"EQUIP vortex. TEKAN FIRE untuk menempatkan di darat. Saat dalam jangkauan dan melihat vortex, AKTIFKAN untuk berteleportasi ke vortex. Selama BUY PHASE, vortex bisa diambil kembali untuk DIKERAHKAN LAGI.","ko-KR":"소용돌이를 장착합니다. 발사하면 지면에 설치합니다. 범위 내에서 소용돌이를 바라볼 때 활성화하면 해당 소용돌이로 순간이동합니다. 구매 단계에서 소용돌이를 회수하여 재배치할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un vortex. TIREZ pour le poser sur le sol. Lorsque vous êtes à portée et que vous regardez le vortex, ACTIVEZ pour vous téléporter jusqu''au vortex. Pendant la PHASE D''ACHATS, le vortex peut être récupéré pour être REDÉPLOYÉ.","en-US":"EQUIP a vortex. FIRE to place on the ground. While in range and looking at the vortex, ACTIVATE to teleport to the vortex. During the BUY PHASE, the vortex can be reclaimed to be REDEPLOYED.","pl-PL":"WYPOSAŻ Wir. STRZEL, by umieścić go na ziemi. AKTYWUJ, będąc w zasięgu i patrząc na Wir, by się do niego teleportować. Podczas FAZY ZAKUPÓW można odzyskać Wir, co pozwoli go UŻYĆ PONOWNIE.","pt-BR":"EQUIPE um vórtice. DISPARE para posicioná-lo no chão. Enquanto estiver dentro do alcance e olhando para o vórtice, ATIVE para se teleportar até ele. Durante a FASE DE COMPRA, o vórtice pode ser recolhido e REPOSICIONADO.","ru-RU":"Выбирает вихрь. Нажмите ОГОНЬ, чтобы разместить его на земле. Находясь в области действия и смотря на вихрь, нажмите кнопку умения, чтобы переместиться к нему. Во время фазы покупок вихрь можно вернуть, чтобы разместить заново.","th-TH":"ติดตั้งกระแสวน กดยิงเพื่อวางลงบนพื้น ขณะอยู่ในรัศมีและมองไปที่กระแสวน ให้เปิดใช้งานเพื่อเทเลพอร์ตไปยังกระแสวน ในช่วงการซื้อ กระแสวนจะเก็บกลับมาเพื่อใช้งานใหม่ได้","tr-TR":"Bir burgaç KUŞAN. Zemine yerleştirmek için ATEŞ ET. Burgaca ışınlanmak için menzilindeyken ve burgaca bakarken ETKİNLEŞTİR. SATIN ALMA EVRESİ sırasında burgacı TEKRAR YERLEŞTİRMEK üzere geri alabilirsin.","vi-VN":"TRANG BỊ 1 lốc xoáy. BẮN để đặt lốc xoáy trên mặt đất. Khi ở trong phạm vi và nhìn vào lốc xoáy, KÍCH HOẠT để dịch chuyển đến lốc xoáy. Trong GIAI ĐOẠN MUA ĐỒ, có thể thu hồi lốc xoáy để TRIỂN KHAI LẠI.","zh-CN":"装备一颗漩涡能量球。按【射击】将其放置于地面。在技能范围内且瞄准漩涡时，【激活】技能即可传送至漩涡所在位置。在购买阶段期间，可将能量球回收并【重新部署】。","zh-TW":"裝備一道漩渦，點擊「攻擊」可放置在地上，當你進入範圍並看著漩渦，「啟動」即可傳送至漩渦的位置。選購階段可以回收漩渦以重新部署。"}'::jsonb, '"https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, 'Ultimate', '{"es-MX":"Evolución","ar-AE":"التطور","es-ES":"Evolución","ja-JP":"エヴォリューション","it-IT":"Evoluzione","de-DE":"Evolution","id-ID":"Evolution","ko-KR":"진화","fr-FR":"Évolution","en-US":"Evolution","pl-PL":"Ewolucja","pt-BR":"Evolução","ru-RU":"Эволюция","th-TH":"Evolution","tr-TR":"EVRİM","vi-VN":"Tiến Hóa","zh-CN":"完全进化","zh-TW":"終極突變"}'::jsonb, '{"es-MX":"Comienza a mutar por completo al INSTANTE, obtiene un potenciador de combate, regeneración y se vuelve INMUNE a todas las formas de debilitación.","ar-AE":"تبدأ بالتحوّل الكامل فورًا، فتحصل على محفز قتالي وتجديد للحياة، وتصبح منيعًا ضد جميع تأثيرات الإضعاف.","es-ES":"Comienza a mutar completamente AL INSTANTE, lo que le proporciona un estimulante de combate, regeneración e INMUNIDAD a toda clase de debilitaciones.","ja-JP":"即座に完全変異を開始し、バトルスティムと回復を獲得する。また、あらゆるデバフ効果が無効となる。","it-IT":"Inizi ISTANTANEAMENTE una mutazione completa, ottenendo un effetto ENERGETICO, rigenerandoti e diventando IMMUNE a ogni forma di debuff.","de-DE":"Beginnt SOFORT die vollständige Mutation, bekommt eine Kampfstimulation, Regeneration und wird IMMUN gegen alle Debuffs.","id-ID":"SEKETIKA mulai bermutasi sepenuhnya, mendapatkan combat stim, regenerasi, dan menjadi KEBAL terhadap segala bentuk debuff.","ko-KR":"즉시 완전하게 변이하여 전투 자극제, 체력 회복 효과를 얻고 모든 형태의 해로운 효과에 면역 상태가 됩니다.","fr-FR":"Vous commencez INSTANTANÉMENT à muter complètement, vous gagnez un stimulant de combat, de la régénération et vous êtes IMMUNISÉ contre toutes les formes de malus.","en-US":"INSTANTLY begin to fully mutate, gaining a combat stim, regeneration, and becoming IMMUNE to all forms of debuffs.","pl-PL":"NATYCHMIAST przechodzi pełną mutację, zyskując stymulant bitewny, regenerację oraz ODPORNOŚĆ na wszystkie formy osłabień.","pt-BR":"Inicia INSTANTANEAMENTE uma mutação completa, ganhando Estimulante de Combate e Regeneração, e se torna IMUNE a todas as formas de enfraquecimento.","ru-RU":"Мгновенно начинает мутировать, получая эффект боевого стимулятора и невосприимчивость ко всем отрицательным эффектам, а также восстанавливая здоровье.","th-TH":"เริ่มกลายพันธุ์โดยสมบูรณ์ในทันที พร้อมทั้งรับบัฟ Combat Stim, ฟื้นฟูพลังชีวิต และไม่ติดดีบัฟทุกรูปแบบ","tr-TR":"ANINDA tamamen mutasyona uğramaya başlayarak kuvvetli savaş ile can yenilemesi ve bütün zayıflatma etkilerine karşı BAĞIŞIKLIK kazanırsın.","vi-VN":"NGAY LẬP TỨC biến dị hoàn toàn, được khuấy động giao tranh, hồi máu và MIỄN NHIỄM với mọi loại bùa hại.","zh-CN":"立即进入完全变异形态，获得【作战强化】效果和再生能力，并免疫所有形式的减益效果。 ","zh-TW":"立即開始完全突變，獲得「激發戰意」增益、生命回復，並「免疫」所有類型的減益效果。"}'::jsonb, '"https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, 'Ability1', '{"es-MX":"Asfixia","ar-AE":"القبضة المحكمة","es-ES":"Asfixia","ja-JP":"チョークホールド","it-IT":"Morsa","de-DE":"Schwitzkasten","id-ID":"Chokehold","ko-KR":"목조르기","fr-FR":"Étranglement","en-US":"Chokehold","pl-PL":"Przyduszenie","pt-BR":"Imobilidade","ru-RU":"Удушение","th-TH":"Chokehold","tr-TR":"DARBOĞAZ","vi-VN":"Khóa Cứng","zh-CN":"裂变残片","zh-TW":"鎖喉"}'::jsonb, '{"es-MX":"EQUIPA un fragmento viscoso de tu mutación. DISPARA para lanzar. El fragmento se despliega al impactar contra el suelo, creando una trampa que inmoviliza a los enemigos. Los enemigos inmovilizados quedan ensordecidos y debilitados Los enemigos pueden destruir la trampa antes de que se active.","ar-AE":"تجهّز بشظية لزجة ناتجة عن عملية تحوّلك. أطلق لرميها. تنتشر الشظية عند ارتطامها بالأرض لتُنشئ فخًا يثبت الأعداء في مكانهم. يصاب الأعداء المثبّتون بتأثيري الصمم وتدهور الصحة. يستطيع الأعداء تدمير الفخ قبل تفعيله.","es-ES":"EQUIPA un pedazo viscoso de tu mutación. DISPARA para lanzarlo. El fragmento se despliega al impactar contra el suelo y crea una trampa que detiene a los enemigos en el sitio. Ensordece y aplica declive a los enemigos retenidos. Los enemigos pueden destruir la trampa antes de que se active.","ja-JP":"変異から生じた粘性の欠片を構える。「発射」で投げる。欠片は地面に当たると展開され、敵をその場に拘束するトラップを生成する。拘束された敵は聴覚を奪われ、「衰弱」効果を受ける。敵は起動前のトラップを破壊可能。","it-IT":"EQUIPAGGIA un frammento viscoso della tua mutazione. Usa il FUOCO per lanciarlo. Il frammento si attiva quando tocca terra, creando una trappola che immobilizza i nemici. I nemici coinvolti vengono ASSORDATI e DETERIORATI. I nemici possono distruggere la trappola prima che si attivi.","de-DE":"RÜSTE ein zähflüssiges Fragment deiner Mutation AUS. FEUERE, um es zu werfen. Das Fragment wird beim Einschlag auf dem Boden eingesetzt und bildet eine Falle, die Gegner an Ort und Stelle festhält. Festgehaltenen Gegnern werden Taubheit und Verfall zugefügt. Gegner können die Falle zerstören, bevor sie aktiviert wird.","id-ID":"EQUIP fragmen kental dari mutasimu. TEKAN FIRE untuk melempar. Fragmen ini akan aktif saat mengenai tanah, menciptakan perangkap untuk menahan musuh di tempat. Musuh yang tertahan akan terkena efek Deafen dan Decay. Musuh bisa menghancurkan perangkap sebelum diaktifkan.","ko-KR":"변이의 점성 조각을 장착합니다. 발사하면 던집니다. 조각은 땅에 닿으면 적을 그 자리에 속박하는 함정을 생성합니다. 속박된 적은 청력이 약화되고 부패 효과를 받습니다. 적은 함정이 활성화되기 전에 함정을 파괴할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un fragment visqueux de votre mutation. TIREZ pour le lancer. Le fragment se déploie lorsqu''il touche le sol, créant un piège qui immobilise les ennemis. Les ennemis retenus sont assourdis et leurs PV se désagrègent. Les ennemis peuvent détruire le piège avant qu''il ne s''active.","en-US":"EQUIP a viscous fragment of your mutation. FIRE to throw. The fragment deploys upon hitting the ground, creating a trap to hold enemies in place. Held enemies are Deafened, and Decayed. Enemies can destroy the trap before activation.","pl-PL":"WYPOSAŻ lepki fragment swojej mutacji. STRZEL, by rzucić. Fragment rozstawia się w momencie trafienia w ziemię, tworząc pułapkę, która zatrzymuje wrogów. Zatrzymani wrogowie zostają ogłuszeni i ulegają rozpadowi. Wrogowie mogą zniszczyć pułapkę, zanim w nią wejdą.","pt-BR":"EQUIPE um fragmento viscoso da sua mutação. DISPARE para lançar. O fragmento é acionado com o impacto no chão, criando uma armadilha que prende os inimigos no lugar. Inimigos presos sofrem Surdez e Deterioração. Inimigos podem destruir a armadilha antes da ativação.","ru-RU":"Выбирает вязкий мутировавший сгусток. Нажмите ОГОНЬ, чтобы бросить его. При столкновении с поверхностью сгусток преобразуется в ловушку, которая удерживает врагов. Также она лишает их слуха и наносит им периодический урон. Враги могут уничтожить ловушку до активации.","th-TH":"ติดตั้งชิ้นส่วนหนืดจากการกลายพันธุ์ กดยิงเพื่อขว้าง ชิ้นส่วนจะทำงานเมื่อกระทบกับพื้น และสร้างกับดักเพื่อยึดศัตรูให้อยู่กับที่ ศัตรูที่ถูกยึดอยู่กับที่จะถูกจำกัดการได้ยินและติดสถานะเสื่อมสลาย ศัตรูสามารถทำลายกับดักก่อนกับดักทำงานได้","tr-TR":"Mutasyonundan yapışkan bir parçacık KUŞAN. Fırlatmak için ATEŞ ET. Parçacık yere değdiğinde açılır ve düşmanları yerine sabitleyen bir tuzak oluşturur. Sabitlenmiş düşmanlar Sağır olur ve Çürüme hasarı almaya başlar. Düşmanlar etkinleşmeden önce tuzağı yok edebilir.","vi-VN":"TRANG BỊ 1 mảnh kết dính từ dị thể của bạn. BẮN để ném. Mảnh kết dính sẽ bung ra khi chạm mặt đất, tạo thành bẫy để giữ chân kẻ địch. Những kẻ địch bị giam giữ sẽ mất đi Thính Giác và chịu Phân Rã. Kẻ địch có thể phá hủy bẫy trước khi kích hoạt.","zh-CN":"装备一块由异变产生的黏液碎片。按【射击】将其掷出。碎片会在碰到地面时部署为陷阱，困住经过的敌人。被困敌人将受到【致聋】和【腐坏】效果。陷阱激活前可被敌人摧毁。","zh-TW":"裝備你突變而來的黏性碎片，點擊「攻擊」即可拋出。該碎片碰撞到地面時即刻部署，創造出能束縛敵軍的陷阱；被束縛的目標會遭到「致聾」和「侵蝕」。敵軍可在陷阱啟動前將之摧毀。"}'::jsonb, '"https://media.valorant-api.com/agents/92eeef5d-43b5-1d4a-8d03-b3927a09034b/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('92eeef5d-43b5-1d4a-8d03-b3927a09034b'::uuid, 200000, '2025-10-07T18:00:00Z'::timestamp with time zone, '2025-11-04T22:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, '{"es-MX":"Astra","ar-AE":"أسترا","es-ES":"Astra","ja-JP":"アストラ","it-IT":"Astra","de-DE":"Astra","id-ID":"Astra","ko-KR":"아스트라","fr-FR":"Astra","en-US":"Astra","pl-PL":"Astra","pt-BR":"Astra","ru-RU":"Astra","th-TH":"Astra","tr-TR":"ASTRA","vi-VN":"Astra","zh-CN":"星礈","zh-TW":"亞星卓"}'::jsonb, '{"es-MX":"La agente ghanesa Astra canaliza las energías del cosmos para remodelar los campos de batalla a su antojo. Con pleno dominio de su forma astral y un talento para una profunda previsión estratégica, siempre está eones por delante del próximo movimiento de su enemigo.","ar-AE":"تسخّر العميلة الغانية أسترا الطاقات الكونية لإعادة تشكيل معالم ميادين القتال وفقًا لرغباتها الشخصية. ومع تحكمها الكامل بهيئتها الفضائية، وموهبتها في الرؤية الاستراتيجية المعمقة، تسبق خطوة خصومها التالية على الدوام بسنوات ضوئية.","es-ES":"Astra, la agente ghanesa, controla las energías del cosmos para dar forma al campo de batalla a su antojo. Con pleno dominio de su forma astral y un gran talento para la anticipación estratégica, siempre va eones por delante de los movimientos de sus enemigos.","ja-JP":"ガーナ人エージェントのアストラは、宇宙のエネルギーを駆使して戦場を思いのままに作り変える。アストラルフォームを自在に操り、戦略的な先見性を備えた彼女は、敵のはるか先を行くことができる。","it-IT":"Astra, la viaggiatrice astrale ghanese, sfrutta le energie del cosmo per plasmare a piacimento il campo di battaglia. Grazie alla completa padronanza della sua forma astrale e a una lungimiranza strategica quasi soprannaturale, è sempre eoni avanti rispetto alla prossima mossa del nemico.","de-DE":"Die ghanaische Agentin Astra nutzt die Energien des Kosmos, um das Schlachtfeld nach ihren Vorlieben zu verändern. Durch ihre Astralform und ihr Talent für strategische Weitsicht ist sie dem nächsten Zug ihrer Gegner immer Äonen voraus.","id-ID":"Agen asal Ghana, Astra, memberdayakan kekuatan semesta untuk mereka ulang battlefield sesuka hatinya. Dengan kendali penuh atas wujud astralnya dan bakat meramal strategisnya, dia akan selalu unggul dari musuhnya.","ko-KR":"가나 출신 요원 아스트라는 우주의 힘을 활용해 자신의 마음에 따라 전장의 모습을 바꿉니다. 천상계 형상을 자유자재로 이용하고 심도 있게 전략을 예측해 언제나 적보다 몇 수 앞서 움직입니다.","fr-FR":"L''agent ghanéen Astra canalise les énergies du cosmos pour façonner le champ de bataille à sa convenance. Avec une maîtrise complète de sa forme astrale et un talent pour la planification stratégique, elle a toujours une large avance sur ses ennemis.","en-US":"Ghanaian Agent Astra harnesses the energies of the cosmos to reshape battlefields to her whim. With full command of her astral form and a talent for deep strategic foresight, she''s always eons ahead of her enemy''s next move.","pl-PL":"Ghańska agentka Astra ujarzmia kosmiczne energie, by przeobrazić pola bitwy według własnego widzimisię. Dzięki temu, że w pełni panuje nad swoją astralną formą i ma niezwykły talent do przewidywania strategicznych posunięć, zawsze wyprzedza o całe eony kolejne działania wroga.","pt-BR":"Astra, a Agente ganense, utiliza energias cósmicas para moldar o campo de batalha a seu bel-prazer. Com total domínio da sua forma astral e um talento estratégico nato, ela está sempre anos-luz à frente dos inimigos.","ru-RU":"Astra, агент из Ганы, управляет пространством и временем и способна изменять поле битвы. Полный контроль над астральной формой и талант стратегического предвидения позволяют ей опережать врага на целую вечность.","th-TH":"Astra เอเจนท์ชาวกานาผู้ควบคุมพลังแห่งจักรวาลเพื่อปรับรูปแบบสนามรบให้เป็นไปตามความต้องการของเธอ ด้วยความสามารถในการควบคุมร่างดวงดาวและพรสวรรค์ในการวางแผนกลยุทธ์อย่างลึกซึ้งของเธอ เธอมักจะนำหน้าศัตรูอยู่หนึ่งก้าวเสมอ","tr-TR":"Ganalı ajan Astra, kozmosun enerjisini kullanarak savaş meydanını lehine değiştirebiliyor. Astral yolculuğu üzerinde tam kontrole sahip olması ve engin stratejik öngörüsüyle, düşmanın bir sonraki hamlesinden her zaman birkaç ışık yılı önde.","vi-VN":"Astra là một đặc vụ tới từ Ghana, cô sử dụng năng lượng của vũ trụ để định hình trận chiến theo ý muốn của bản thân. Với khả năng điều khiển thể tinh vân và tài năng chiến thuật bao quát, cô ấy luôn đi trước đối thủ của mình 10 bước.","zh-CN":"来自非洲大陆的“星礈”可以操控宇宙能量来重塑战场。她可以进入星界形态，以超脱凡界的战略眼光洞悉战场，抢在敌人行动之前便占得先机。","zh-TW":"亞星卓來自非洲迦納，她能駕馭宇宙之力，「隨星所欲」重塑戰場形勢。她完全掌控了星體型態的力量，且擁有洞見觀瞻的戰略能力，因此總是能遙遙領先對手。"}'::jsonb, 'Rift', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/displayicon.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/displayicon.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/fullportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/fullportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/fullportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/killfeedportrait.png', 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/minimapportrait.png', null, 'https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/background.png', array['26146cff', '0f1923ff', '5210c6ff', '0f192300'], true, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, 'Ability1', '{"es-MX":"Pulso Estelar","ar-AE":"النبضة النجمية","es-ES":"Pulso nova","ja-JP":"ノヴァパルス","it-IT":"Nova pulsante","de-DE":"Nova-Impuls","id-ID":"Nova Pulse","ko-KR":"신성 파동","fr-FR":"Impulsion nova","en-US":"Nova Pulse","pl-PL":"Puls Nowej","pt-BR":"Pulso Nova","ru-RU":"Взрыв сверхновой","th-TH":"Nova Pulse","tr-TR":"NOVA DARBESİ","vi-VN":"Xung Nhịp Tân Tinh","zh-CN":"新星脉冲","zh-TW":"新星震盪"}'::jsonb, '{"es-MX":"Coloca estrellas en Modo Astral (botón de definitiva).\r\n\r\nACTIVA una estrella para detonar un Pulso Estelar. El Pulso Estelar carga brevemente y luego se activa, lo que conmociona a todos los jugadores en el área.","ar-AE":"ازرع النجوم في الهيئة الفضائية (مفتاح القدرة الخارقة)\n\nقم بتفعيل نجمة لتفجير نبضة نجمية. تشحن النبضة النجمية لفترة قصيرة ثم تضرب، فتصيب بصدمة ارتجاجية جميع اللاعبين في نطاقها.","es-ES":"Coloca estrellas en Forma astral (tecla de la definitiva).\nACTIVA una estrella para detonar un Pulso nova. El Pulso nova se carga brevemente y explota, lo que aturde a todos los jugadores en la zona.","ja-JP":"「アストラルフォーム」(アルティメットキー) でスターを設置。\n\nスターを「発動」することで「ノヴァパルス」を起爆する。「ノヴァパルス」は少しの間チャージしてから爆発し、範囲内のすべてのプレイヤーをスタンさせる。","it-IT":"Piazza le stelle mentre sei in forma astrale (Ultima).\n\nATTIVA una stella per far esplodere una Nova pulsante. La Nova pulsante si carica brevemente e poi colpisce, STORDENDO tutti gli agenti nella sua area.","de-DE":"Platziere Sterne in Astraler Form (Ult-Taste).\n\nAKTIVIERE einen Stern, um einen Nova-Impuls auszusenden. Der Impuls lädt kurz auf und betäubt dann alle Gegner im Wirkungsbereich.","id-ID":"Tempatkan Star dalam Astral Form (Tombol Ultima)\n\nAKTIFKAN satu Star untuk meledakkan Nova Pulse. Nova Pulse membutuhkan charge sejenak sebelum menyerang. Ability ini memberikan utilitas Concuss pada semua pemain di area tersebut.","ko-KR":"천상계 형상에서 별을 설치합니다. (궁극기 키)\n\n활성화 시 별 하나를 폭파해 신성 파동을 만들어 냅니다. 신성 파동은 짧은 충전 시간 이후 범위 내 모든 플레이어에게 뇌진탕을 일으킵니다.","fr-FR":"Placez des étoiles sous sa forme astrale (touche d''ultime).\n\nACTIVEZ une étoile pour faire exploser une impulsion nova. L''impulsion nova se charge brièvement avant d''exploser, désorientant tous les joueurs dans son rayon d''effet.","en-US":"Place Stars in Astral Form (Ultimate Key).\r\n\r\nACTIVATE a Star to detonate a Nova Pulse. The Nova Pulse charges briefly then strikes, Concussing all players in its area.","pl-PL":"Umieść Gwiazdki w Postaci Astral (przycisk ulta).\n\nAKTYWUJ Gwiazdkę, by zdetonować Puls Nowej. Puls Nowej ładuje się przez chwilę, po czym uderza, ogłuszając wszystkich graczy znajdujących się w strefie rażenia.","pt-BR":"Posicione Estrelas na Forma Astral (tecla da Ultimate).\r\n\r\nATIVE uma Estrela para detonar um Pulso Nova. O Pulso Nova carrega brevemente e depois explode, causando Concussão a todos os jogadores na área.","ru-RU":"Разместите звезды в Астральной форме (нажмите кнопку абсолютного умения). \nАктивируйте звезду, чтобы вызвать взрыв сверхновой. Умение быстро заряжается и оглушает всех игроков в зоне действия.","th-TH":"จัดวางดวงดาวใน Astral Form (ปุ่มอัลติเมท)\n\nเปิดใช้งานดวงดาวเพื่อจุดชนวน Nova Pulse สกิล Nova Pulse จะชาร์จครู่หนึ่งก่อนที่จะทำงาน สร้างความเสียหายแก่ผู้เล่นทุกคนที่อยู่ในบริเวณนั้น","tr-TR":"Astral Yolcu halindeyken yıldız yerleştir (ulti düğmesi).\n\nPatlayarak Nova Darbesi oluşturması için bir yıldızı ETKİNLEŞTİR. Nova Darbesi kısa bir süre güç topladıktan sonra patlayarak etki alanı içindeki tüm oyuncuları Sersemletir.","vi-VN":"Sắp xếp các Ngôi Sao thành Thể Tinh Vân (Phím Chiêu Cuối).\n\nKÍCH HOẠT 1 Ngôi Sao để kích nổ Xung Nhịp Tân Tinh. Xung Nhịp Tân Tinh sẽ tụ trong thoáng chốc trước khi phóng thích, Làm Choáng toàn bộ người chơi trong khu vực ảnh hưởng.","zh-CN":"进入星界形态（终极技能键）并放置星体。\n\n【激活】一颗星体，引发一次新星脉冲。新星脉冲会在短暂充能后爆发，使范围内的所有玩家受到【震荡】。","zh-TW":"以星體型態（大絕鍵）放置星辰。\r\n\r\n按下「啟動」，可引爆星辰化作新星震盪，短暫延遲後會發動攻擊，「暈眩」範圍內所有玩家。"}'::jsonb, '"https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, 'Ability2', '{"es-MX":"Nebulosa / Disipar","ar-AE":"السديم  / تبديد","es-ES":"Nebulosa / Disipar","ja-JP":"ネビュラ / ディシペイト","it-IT":"Nebulosa/Dissoluzione","de-DE":"Sternnebel/Zerstreuen","id-ID":"Nebula/Dissipate","ko-KR":"성운 / 소멸","fr-FR":"Nébuleuse / Dissipation","en-US":"Nebula  / Dissipate","pl-PL":"Mgławica/Rozproszenie","pt-BR":"Nebulosa / Dissipar","ru-RU":"Туманность / Рассеивание","th-TH":"Nebula  / Dissipate","tr-TR":"YILDIZ BULUTU / KOZMİK ÇÖZÜNÜM","vi-VN":"Tinh Vân / Tán Xạ","zh-CN":"星云/消散","zh-TW":"迷濛星雲／星解變裂"}'::jsonb, '{"es-MX":"Coloca estrellas en Modo Astral (botón de definitiva) \n\nACTIVA una estrella para transformarla en una Nebulosa (humo).\n\nUSA mientras apuntas a una estrella para Disiparla, lo que devuelve la estrella para colocarla en una nueva ubicación después de un momento.\n\nDisipar forma una Nebulosa falsa brevemente en la ubicación de la estrella antes de regresar.","ar-AE":"ازرع النجوم في الهيئة الفضائية (مفتاح القدرة الخارقة). \n\nقم بتفعيل نجمة لتحويلها إلى سديم (دخان).\n\nاستخدم نجمة لتبديده، مما يعيد النجمة لوضعها في بقعة جديدة بعد فترة.\n\nتشكّل قدرة التبديد سديمًا مزيفًا لفترة قصيرة في موقع النجمة قبل عودتها.","es-ES":"Coloca estrellas en Forma astral (tecla de la definitiva). \nACTIVA una estrella para transformarla en una Nebulosa (humo).\nUSA una estrella para disiparla, lo que recupera la estrella para poder volver a colocarla tras un tiempo.\nDisipar una estrella crea una breve Nebulosa falsa en su ubicación antes de recuperarla.","ja-JP":"「アストラルフォーム」(アルティメットキー) でスターを設置。\r\n\r\nスターを「発動」することで「ネビュラ」(スモーク) に変える。\r\n\r\nスターを「使用」すると「ディシペイト」の効果により、少ししてからスターを回収する。回収したスターは新たな場所に設置可能になる。\r\n\r\n回収する前、「ディシペイト」によって少しの間、偽の「ネビュラ」がスターのある場所に形成される。","it-IT":"Piazza le stelle mentre sei in forma astrale (Ultima). \n\nATTIVA una stella per trasformarla in una Nebulosa che agisce come un fumogeno.\n\nUSA una stella per dissolverla e renderla nuovamente disponibile da piazzare altrove dopo un certo periodo.\n\nPrima di rientrare, Dissoluzione forma una finta Nebulosa nella posizione della stella.","de-DE":"Platziere Sterne in Astraler Form (Ult-Taste). \n\nAKTIVIERE einen Stern, um ihn in einen Sternnebel zu verwandeln (Rauch).\nNUTZE einen Stern, um ihn zu zerstreuen und ihn nach kurzer Abklingzeit an einem neuen Ort zu platzieren.\n„Zerstreuen“ verursacht dort, wo der Stern war, einen kurzlebigen fingierten Sternnebel.","id-ID":"Tempatkan Star dalam Astral Form (Tombol Ultima). \nAKTIFKAN satu Star untuk mengubahnya menjadi Nebula (asap). PAKAI satu Star untuk melenyapkannya (dengan utilitas Dissipate) dan mengembalikannya agar bisa ditempatkan di lokasi baru setelah beberapa saat. Utilitas Dissipate akan membentuk Nebula palsu sejenak di lokasi Star sebelum benda tersebut kembali.","ko-KR":"천상계 형상에서 별을 설치합니다. (궁극기 키)\n활성화 시 별 하나를 성운(연막)으로 변형합니다.\n별은 사용 시 소멸하며, 잠시 후 다른 곳에 설치할 수 있게 됩니다.\n별이 소멸하면 그 자리에 잠시 가짜 성운이 생성됩니다.","fr-FR":"Placez des étoiles sous sa forme astrale (touche d''ultime). \n\nACTIVEZ une étoile pour la transformer en nébuleuse (fumigène). UTILISEZ une étoile pour la dissiper, ce qui vous permettra d''en placer une autre à un autre endroit après un délai. La dissipation forme brièvement une fausse nébuleuse à l''emplacement de l''étoile.","en-US":"Place Stars in Astral Form (Ultimate Key). \r\n\r\nACTIVATE a Star to transform it into a Nebula (smoke).\r\n\r\nUSE a Star to Dissipate it, returning the Star to be placed in a new location after a delay.\r\n\r\nDissipate briefly forms a fake Nebula at the Star''s location before returning.","pl-PL":"Umieść Gwiazdki w Postaci Astral (przycisk ulta). \n\nAKTYWUJ Gwiazdkę, aby zmienić ją w Mgławicę (dym). UŻYJ Gwiazdki, żeby dokonać jej Rozproszenia, powodując tym samym umieszczenie jej po krótkiej chwili w nowym miejscu. Rozproszenie tworzy na krótko fałszywą Mgławicę w miejscu położenia Gwiazdki, nim ta powróci.","pt-BR":"Posicione Estrelas na Forma Astral (X). \n\nATIVE uma Estrela para transformá-la em uma Nebulosa (fumaça).\n\nUSE uma Estrela para dissipá-la, retornando a Estrela para ser posicionada em um novo local após um período.\n\nDissipar forma brevemente uma Nebulosa falsa na localização da Estrela antes de retornar.","ru-RU":"Разместите звезды в Астральной форме (нажмите кнопку абсолютного умения). \nАктивируйте звезду, чтобы преобразовать ее в туманность (газо-пылевое облако).\nВыберите звезду, чтобы рассеять ее. Звезда исчезает, и через некоторое время ее можно разместить в другом месте.\nПеред исчезновением звезда ненадолго создает ложную туманность.","th-TH":"จัดวางดวงดาวใน Astral Form (ปุ่มอัลติเมท) \n\nใช้งานดวงดาวเพื่อแปลงเป็น Nebula (ควัน)\n\nใช้ดวงดาวเพื่อกระจายมันออก ส่งคืนดาวเพื่อวางในตำแหน่งใหม่หลังจากดีเลย์\n\nการกระจายจะสร้าง Nebula ปลอมเป็นเวลาสั้น ๆ ในตำแหน่งของดาวก่อนที่จะกลับมา","tr-TR":"Astral Yolcu halindeyken yıldız yerleştir (ulti düğmesi). \nDönüşerek Yıldız Bulutu (duman) oluşturması için bir yıldızı ETKİNLEŞTİR.\nBir yıldızı Kozmik Çözünüm''le geri almak için KULLAN. Geri alınan yıldızı belli bir süre sonra tekrar yerleştirebilirsin.\nKozmik Çözünüm, dönmeden önce yıldızın yerinde kısa süreliğine sahte bir Yıldız Bulutu oluşturur.","vi-VN":"Sắp xếp các Ngôi Sao ở Thể Tinh Vân (Phím Chiêu Cuối). \n\nKÍCH HOẠT 1 Ngôi Sao để biến đổi nó thành Tinh Vân (khói).\n\nSỬ DỤNG 1 Ngôi Sao để Tán Xạ, đưa Ngôi Sao đến vị trí mới sau khoảng thời gian trì hoãn.\n\nTán Xạ tạo 1 Tinh Vân giả trong thoáng chốc tại vị trí của Ngôi Sao trước khi đến vị trí mới.","zh-CN":"进入星界形态（终极技能键）并放置星体。\n\n【激活】一颗星体，将其转化为星云（烟雾）。\n对星体按【使用】键即可将其驱散和回收，以便在一段时间后重新布置。\n驱散星云后，其所在位置仍会短暂存续一片混淆视听的假星云，直至星体回收完毕。","zh-TW":"以星體型態（大絕鍵）放置星辰。 \r\n\r\n按下「啟動」可使星辰化作迷濛星雲 (煙霧)。\r\n\r\n在星辰上按下「使用」造成星解變裂來收回星辰，短暫延遲後可將該星辰放在不同位置。\r\n\r\n在收回星辰之前，星解變裂會在該位置短暫形成一個假的迷濛星雲。\r\n\r\n"}'::jsonb, '"https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, 'Grenade', '{"es-MX":"Pozo Gravitacional","ar-AE":"بئر الجاذبية","es-ES":"Pozo gravitatorio","ja-JP":"グラビティウェル","it-IT":"Pozzo gravitazionale","de-DE":"Gravitationsbrunnen","id-ID":"Gravity Well","ko-KR":"중력의 샘","fr-FR":"Puits de gravité","en-US":"Gravity Well","pl-PL":"Studnia Grawitacyjna","pt-BR":"Poço Gravitacional","ru-RU":"Гравитационный колодец","th-TH":"Gravity Well","tr-TR":"ÇEKİM ALANI","vi-VN":"Cầu Trọng Lực","zh-CN":"重力之阱","zh-TW":"引力黑洞"}'::jsonb, '{"es-MX":"Coloca estrellas en Modo Astral (botón de definitiva).\r\n\r\nACTIVA una estrella para formar un Pozo Gravitacional. Los jugadores en el área son atraídos hacia el centro antes de que estalle, lo que causa que todos los jugadores que aún siguen atrapados se vuelvan vulnerables.","ar-AE":"ازرع النجوم في الهيئة الفضائية (مفتاح القدرة الخارقة).\n\nقم بتفعيل نجمة لتشكيل بئر جاذبية. يتم سحب اللاعبين المتواجدين في النطاق باتجاه المركز قبل انفجاره، مما يجعل جميع اللاعبين عالقين ضمن الهشاشة.","es-ES":"Coloca estrellas en Forma astral (tecla de la definitiva).\nACTIVA una estrella para crear un Pozo gravitatorio. Atrae hacia el centro a todos los jugadores en la zona antes de que explote, lo que causa que todos los jugadores atrapados en el interior se vuelvan vulnerables.","ja-JP":"「アストラルフォーム」(アルティメットキー) でスターを設置。\n\nスターを「発動」することで「グラビティウェル」を形成する。範囲内のプレイヤーを中心に引き寄せてから爆発して、範囲内に残っていたすべてのプレイヤーを弱体化させる。","it-IT":"Piazza le stelle mentre sei in forma astrale (Ultima).\n\nATTIVA una stella per formare un Pozzo gravitazionale. Gli agenti nell''area vengono attirati verso il centro che poi collassa in un''esplosione, rendendo VULNERABILI tutti quelli ancora intrappolati all''interno.","de-DE":"Platziere Sterne in Astraler Form (Ult-Taste).\n\nAKTIVIERE einen Stern, um ihn in einen Gravitationsbrunnen zu verwandeln. Spieler innerhalb des Gebietes werden zum Zentrum gezogen, bevor es explodiert und alle darin gefangenen Gegner verwundbar macht.","id-ID":"Tempatkan Star dalam Astral Form (Tombol Ultima).\n\nAKTIFKAN satu Star untuk membentuk Gravity Well. Pemain di area tersebut tersedot ke pusatnya sebelum liang meledak. Semua pemain yang masih terjebak di dalamnya terkena utilitas Vulnerable.","ko-KR":"천상계 형상에서 별을 설치합니다. (궁극기 키)\n\n활성화 시 별 하나를 중력의 샘으로 변형합니다. 중력의 샘은 범위 내 플레이어들을 끌어당기다가 폭발하며, 폭발에 닿은 플레이어들은 취약 상태가 됩니다.","fr-FR":"Placez des étoiles sous sa forme astrale (touche d''ultime).\n\nACTIVEZ une étoile pour former un puits de gravité. Les joueurs dans la zone sont attirés vers le centre avant qu''il n''explose. L''explosion applique l''altération d''état Vulnérable aux joueurs piégés.","en-US":"Place Stars in Astral Form (Ultimate Key).\r\n\r\nACTIVATE a Star to form a Gravity Well. Players in the area are pulled toward the center before it explodes, making all players still trapped inside Vulnerable.","pl-PL":"Umieść Gwiazdki w Postaci Astral (przycisk ulta).\n\nAKTYWUJ Gwiazdkę, aby stworzyć Studnię Grawitacyjną. Studnia Grawitacyjna przyciąga do środka znajdujących się w pobliżu graczy, a następnie wybucha, wywołując podatność u wszystkich wciąż uwięzionych agentów.","pt-BR":"Posicione Estrelas na Forma Astral (tecla da Ultimate).\r\n\r\nATIVE uma Estrela para formar um Poço Gravitacional. Jogadores na área são puxados em direção ao centro antes dele explodir, deixando todos os jogadores ainda presos dentro dele Vulneráveis.","ru-RU":"Разместите звезды в Астральной форме (нажмите кнопку абсолютного умения).\nАктивируйте звезду, чтобы создать гравитационный колодец. Игроки в области действия умения притягиваются к центру, после чего колодец взрывается, делая игроков внутри уязвимыми.","th-TH":"จัดวางดวงดาวใน Astral Form (ปุ่มอัลติเมท)\n\nเปิดใช้งานดวงดาวเพื่อสร้าง Gravity Well ผู้เล่นที่อยู่ในบริเวณจะถูกดึงเข้าจุดศูนย์กลางก่อนที่มันจะระเบิด ส่งผลให้ผู้เล่นที่ติดอยู่ภายในได้รับสถานะเปราะบาง","tr-TR":"Astral Yolcu halindeyken yıldız yerleştir (ulti düğmesi).\n\nÇekim Alanı oluşturmak için bir yıldızı ETKİNLEŞTİR. Etki alanı içindeki oyuncular merkeze çekilir ve ardından merkez patlayarak içerideki oyuncuları Savunmasız hale getirir.","vi-VN":"Sắp xếp các Ngôi Sao ở Thể Tinh Vân (Phím Chiêu Cuối).\n\nKÍCH HOẠT 1 Ngôi Sao để tạo thành Cầu Trọng Lực. Người chơi trong khu vực ảnh hưởng sẽ bị hút về trung tâm Cầu Trọng Lực trước khi cầu phát nổ và khiến cho toàn bộ người chơi mắc kẹt bên trong bị Suy Yếu.","zh-CN":"进入星界形态（终极技能键）并放置星体。\n\n【激活】一颗星体，将其转化为重力之阱。处于该区域内的玩家会被拉向中心点，随后重力之阱引爆，对陷入其中的所有玩家施加【易伤】效果。","zh-TW":"以星體型態（大絕鍵）放置星辰。\r\n\r\n按下「啟動」，可使星辰化作引力黑洞，將範圍內的玩家拉向中心，隨後爆炸，使所有仍困在其中的玩家衰弱。"}'::jsonb, '"https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, 'Ultimate', '{"es-MX":"Modo Astral / División \nCósmica","ar-AE":"الهيئة الفضائية /\r\nالفجوة الكونية","es-ES":"Forma astral / Separación\ncósmica","ja-JP":"アストラルフォーム /\nコズミックディバイド","it-IT":"Forma astrale/\nDivisione cosmica","de-DE":"Astrale Form/Spaltung","id-ID":"Astral Form/Cosmic Divide","ko-KR":"천상계 형상 / 우주 장벽","fr-FR":"Forme astrale / Division\ncosmique","en-US":"Astral Form / Cosmic Divide","pl-PL":"Postać Astral/Gwiezdna Rysa","pt-BR":"Forma Astral / Divisa\nCósmica","ru-RU":"Астральная форма/\nПространственный разлом","th-TH":"Astral Form / Cosmic Divide","tr-TR":"ASTRAL YOLCU / \nKOZMİK AYRIM","vi-VN":"Thể Tinh Vân /\nPhân Chia Vũ Trụ","zh-CN":"星界形态/宇宙分裂","zh-TW":"星體型態／無垠星幕"}'::jsonb, '{"es-MX":"ACTIVA esta habilidad para entrar en Modo Astral, donde puedes colocar estrellas con DISPARO. Puedes reactivar las estrellas más tarde, lo que las transforma en un Pulso Estelar, Nebulosa o Pozo Gravitacional.\r\n\r\nCuando División Cósmica esté cargada, usa el DISPARO SECUNDARIO en Modo Astral para comenzar a apuntar, luego DISPARO para elegir dos ubicaciones. Una División Cósmica infinita conecta los dos puntos que selecciones. División Cósmica bloquea las balas y el sonido.","ar-AE":"قم بالتفعيل للدخول في الهيئة الفضائية حيث يمكنك زرع النجوم باستخدام زر الإطلاق. يمكن إعادة تفعيل النجوم لاحقًا، مما يحولها إلى نبضة نجمية أو سديم أو بئر جاذبية.\n\nعند شحن الفجوة الكونية، استخدم الإطلاق البديل في الهيئة الفضائية للبدء في تصويبها، ثم زر الإطلاق لاختيار بقعتين. تربط فجوة كونية لا نهائية بين النقطتين اللتين اخترتهما. تحجب الفجوة الكونية الرصاص والأصوات.","es-ES":"ACTIVA para entrar en Forma astral y poder colocar estrellas con el DISPARO. Las estrellas se pueden reactivar más tarde para transformarlas en un Pulso nova, una Nebulosa o un Pozo gravitatorio.\nCuando Separación cósmica está cargada, usa el DISPARO ALTERNATIVO en Forma astral para empezar a apuntar y, a continuación, el DISPARO para elegir dos ubicaciones. Se creará una Separación cósmica infinita que conecte los dos puntos. Separación cósmica bloquea las balas y el sonido.","ja-JP":"「発動」すると「アストラルフォーム」になり、「発射」でスターを設置可能になる。スターは各アビリティーで再発動させることで「ノヴァパルス」、「ネビュラ」、「グラビティウェル」に変化する。\r\n\r\n「コズミックディバイド」のチャージが完了している場合、「アストラルフォーム」の状態で「オルト射撃」を押すとエイムを開始し、その後「発射」で 2 つの地点を指定することで、その 2 点を結ぶ無限の長さの「コズミックディバイド」を出現させる。「コズミックディバイド」は銃弾と音をブロックする。","it-IT":"ATTIVA per entrare in forma astrale, in cui puoi piazzare stelle premendo il FUOCO. Le stelle possono essere attivate in un secondo momento e trasformate alternativamente in Nova pulsante, Nebulosa o Pozzo gravitazionale.\n\nQuando Divisione cosmica è carica, usa il FUOCO ALTERNATIVO mentre sei in forma astrale per mirare, poi usa il FUOCO per scegliere due punti sulla mappa: una Divisione cosmica infinita verrà generata a collegamento tra di essi. Divisione cosmica blocca i proiettili e attutisce notevolmente i suoni.","de-DE":"AKTIVIERE, um in die Astrale Form zu wechseln, in der du mit FEUERN Sterne platzieren kannst. Sterne können später reaktiviert und in einen Nova-Impuls, einen Sternnebel oder einen Gravitationsbrunnen verwandelt werden.\n\nWenn „Astrale Spaltung“ aufgeladen ist, kannst du in der Astralen Form mit ALT. FEUERMODUS zielen und FEUERN, um einen zweiten Ort auswählen. Eine unendliche Astrale Spaltung verbindet die ausgewählten Punkte. „Astrale Spaltung“ blockt Kugeln und Geräusche.","id-ID":"AKTIFKAN untuk memasuki Astral Form yang memungkinkanmu menempatkan Star dengan menekan FIRE. Star bisa diaktifkan ulang kemudian dan diubah menjadi Nova Pulse, Nebula, atau Gravity Well. Saat Cosmic Divide di-charge, gunakan ALT FIRE dalam Astral Form untuk mulai membidiknya, lalu FIRE untuk memilih dua lokasi. Cosmic Divide menghubungkan dua titik yang kamu pilih dengan leluasa, lalu menangkis peluru dan suara.","ko-KR":"활성화 시 공격으로 별을 설치할 수 있는 천상계 형상으로 변신합니다. 이후에 별을 다시 활성화하여 신성 파동, 성운, 중력의 샘으로 바꿀 수 있습니다.\n\n우주 장벽이 준비되면 천상계 형상에서 보조 공격을 눌러 조준하고, 공격으로 두 지점을 선택합니다. 우주 장벽은 선택한 두 지점을 이으며 탄환을 막고 소리를 흡수합니다.","fr-FR":"ACTIVEZ pour entrer en forme astrale, ce qui vous permet de placer des étoiles en TIRANT. Vous pouvez ensuite réactiver ces étoiles pour les transformer en impulsion nova, nébuleuse ou puits de gravité.\n\nLorsque Division cosmique est chargée, utilisez le TIR SECONDAIRE en forme astrale pour viser, puis TIREZ pour sélectionner deux emplacements. Une division cosmique infinie connectera les deux points sélectionnés. Division cosmique bloque les balles et les sons.","en-US":"ACTIVATE to enter Astral Form where you can place Stars with FIRE. Stars can be reactivated later, transforming them into a Nova Pulse, Nebula, or Gravity Well.\r\n\r\nWhen Cosmic Divide is charged, use ALT FIRE in Astral Form to begin aiming it, then FIRE to select two locations. An infinite Cosmic Divide connects the two points you select. Cosmic Divide blocks bullets and sound.","pl-PL":"AKTYWUJ, by wejść w Postać Astral, w której możesz umieszczać Gwiazdki za pomocą STRZAŁU. Gwiazdki można aktywować później, zmieniając je w Puls Nowej, Mgławicę lub Studnię Grawitacyjną.\n\nGdy Kosmiczny Podział jest naładowany, użyj ALT. STRZAŁU w Postaci Astral, aby rozpocząć celowanie, a następnie STRZAŁU, aby wskazać dwa miejsca. Nieskończony Kosmiczny Podział łączy dwa wybrane przez ciebie punkty. Kosmiczny Podział blokuje pociski i dźwięki.","pt-BR":"ATIVE para entrar na Forma Astral, em que você pode posicionar Estrelas com DISPARO. As Estrelas podem ser reativadas depois para serem transformadas em Pulso Nova, Nebulosa ou Poço Gravitacional.\n\nQuando Divisa Cósmica estiver carregada, use o DISPARO ALTERNATIVO na Forma Astral para começar a mirar e, depois, o DISPARO para escolher dois locais. Uma Divisa Cósmica infinita surge e conecta os pontos selecionados. A Divisa Cósmica bloqueia disparos e sons.","ru-RU":"Нажмите кнопку умения, чтобы войти в Астральную форму и разместить звезды с помощью кнопки ОГОНЬ. Затем звезды можно активировать, чтобы применить умения \"Взрыв сверхновой\", \"Туманность\" или \"Гравитационный колодец\".\nКогда \"Пространственный разлом\" заряжен, используйте кнопку АЛЬТ. ОГОНЬ в Астральной форме, чтобы начать прицеливание, а затем кнопку ОГОНЬ для выбора двух точек. Бесконечный \"Пространственный разлом\" проходит через две выбранные точки. Он блокирует пули и звуки.","th-TH":"เปิดใช้งานเพื่อเข้าสู่ Astral Form ที่คุณสามารถจัดวางดวงดาวด้วยปุ่มยิง ดวงดาวจะใช้งานได้อีกครั้งในภายหลัง เพื่อแปลงเป็น Nova Pulse, Nebula หรือ Gravity Well\n\nเมื่อชาร์จ Cosmic Divide แล้ว ใช้ปุ่มยิงเสริมใน Astral Form เพื่อเริ่มเล็ง แล้วใช้ปุ่มกดยิงเพื่อเลือกพื้นที่สองจุด Cosmic Divide ที่ไม่มีที่สิ้นสุดจะเชื่อมต่อทั้งสองจุดที่คุณเลือก Cosmic Divide จะบล็อกกระสุนและเสียง","tr-TR":"ATIŞ düğmesiyle yıldız yerleştirebileceğin Astral Yolcu haline geçmek için ETKİNLEŞTİR. Yerleştirilen yıldızlar daha sonra etkinleştirilerek Nova Darbesi, Yıldız Bulutu ve Çekim Alanı''na dönüştürülebilir.\n\nKozmik Ayrım yeteneği hazır olduğunda Astral Yolcu halindeyken ALT. ATIŞ kullanarak hedef al ve ATIŞ düğmesine basarak iki konum seç. Bu iki konum arasında sonsuz bir Kozmik Ayrım bağlantısı oluşur. Kozmik Ayrım mermileri ve sesleri engeller.","vi-VN":"KÍCH HOẠT để chuyển sang Thể Tinh Vân và bạn có thể đặt những Ngôi Sao bằng nút BẮN. Những Ngôi Sao có thể được tái kích hoạt sau đó để chuyển thành Xung Nhịp Tân Tinh, Tinh Vân hoặc Cầu Trọng Lực.\n\nKhi Phân Chia Vũ Trụ đã tụ đầy, BẮN PHỤ ở Thể Tinh Vân để bắt đầu ngắm bắn, sau đó BẮN để chọn 2 vị trí. Một đường Phân Chia Vũ Trụ không có giới hạn sẽ nối 2 điểm đã chọn lại với nhau. Phân Chia Vũ Trụ có khả năng chặn đạn và âm thanh.","zh-CN":"激活该技能可进入星界形态，在此状态下按【射击】即可放置星体。随后你可重新激活星体，将其转化为【新星脉冲】、【星云】或【重力之阱】。\r\n\r\n当【宇宙分裂】充能完毕时，你可在星体形态下使用【辅助射击】进行瞄准，然后按【射击】选择两个位置。一道无边无际的宇宙裂隙会在两个位置之间生成，阻挡所有子弹并完全阻隔声音的传播。","zh-TW":"按下「啟動」可進入星體型態，使用「攻擊」來放置星辰；之後可重新啟動星辰，化作新星震盪、迷濛星雲或引力黑洞。\r\n\r\n無垠星幕充能完成時，以星體型態使用「輔助攻擊」開始瞄準，接著使用「攻擊」來選擇兩個位置，並在兩點之間製造一個無限延伸的無垠星幕，可阻擋所有子彈與聲音傳遞。"}'::jsonb, '"https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('41fb69c1-4189-7b37-f117-bcaf1e96f1bf'::uuid, 'Passive', '{"es-MX":"Modo Astral","ar-AE":"الهيئة الفضائية","es-ES":"Forma astral","ja-JP":"アストラルフォーム","it-IT":"Forma astrale","de-DE":"Astralform","id-ID":"Astral Form","ko-KR":"천상계 형상","fr-FR":"Forme astrale","en-US":"Astral Form","pl-PL":"Postać Astral","pt-BR":"Forma Astral","ru-RU":"Астральная форма","th-TH":"Astral Form","tr-TR":"ASTRAL YOLCU","vi-VN":"Thể Tinh Vân","zh-CN":"星界形态","zh-TW":"星體型態"}'::jsonb, '{"es-MX":"ACTIVA la definitiva para entrar en Modo Astral y el DISPARO PRINCIPAL para colocar estrellas. Apunta a las estrellas con tu Pulso Estelar, Nebulosa o Pozo Gravitacional para usar esas habilidades.","ar-AE":"قم بتفعيل القدرة الخارقة للدخول في الهيئة الفضائية واضغط على زر الإطلاق الأساسي لزرع النجوم. استهدف النجوم بقدرات النبضة النجمية أو السديم أو بئر الجاذبية لديك لاستخدام تلك القدرات.","es-ES":"ACTIVA la definitiva para entrar en Forma astral y colocar estrellas con el DISPARO PRINCIPAL. Apunta a las estrellas con Pulso nova, Nebulosa y Pozo gravitatorio para usar dichas habilidades.","ja-JP":"アルティメットを「発動」すると「アストラルフォーム」になり、プライマリでスターを設置する。「ノヴァパルス」、「ネビュラ」、「グラビティウェル」でスターを指定すると各アビリティーを使用できる。","it-IT":"ATTIVA l''Ultima per entrare in forma astrale e usa il FUOCO PRIMARIO per piazzare le stelle. Punta le stelle e premi nova pulsante, nebulosa o pozzo gravitazionale per attivarne la rispettiva abilità.","de-DE":"AKTIVIERE deine Ult, um in die Astrale Form zu wechseln und PRIMÄRFEUER, um Sterne zu platzieren. Nimm Sterne mit deinem Nova-Impuls, dem Sternnebel oder dem Gravitationsbrunnen ins Visier, um die jeweilige Fähigkeit einzusetzen.","id-ID":"AKTIFKAN Ultima untuk memasuki Astral Form. Tekan PRIMARY FIRE untuk menempatkan Star. Bidik Star dengan Nova Pulse, Nebula, atau Gravity Well-mu untuk menggunakan berbagai ability tersebut.","ko-KR":"궁극기 활성화 시 천상계 형상으로 변신하며, 주 공격으로 별을 설치할 수 있습니다. 별을 조준하면 신성 파동, 성운, 중력의 샘 스킬을 사용할 수 있습니다.","fr-FR":"ACTIVEZ votre ultime pour entrer en forme astrale et TIREZ pour placer des étoiles. Visez ces étoiles avec Impulsion nova, Nébuleuse ou Puits de gravité pour utiliser ces compétences.","en-US":"ACTIVATE Ultimate to enter Astral Form and PRIMARY FIRE to place Stars. Target Stars with your Nova Pulse, Nebula, or Gravity Well to use those abilities.","pl-PL":"AKTYWUJ ulta, by wejść w Postać Astral, i użyj STRZAŁU PODSTAWOWEGO, by umieścić Gwiazdki. Namierz Gwiazdki przy użyciu Pulsu Nowej, Mgławicy lub Studni Grawitacyjnej, aby skorzystać z tych umiejętności.","pt-BR":"ATIVE a Ultimate para entrar na Forma Astral e use DISPARO para posicionar Estrelas. Atinja as Estrelas com Pulso Nova, Nebulosa ou Poço Gravitacional para utilizar essas habilidades.","ru-RU":"Активируйте абсолютное умение, чтобы войти в Астральную форму, и разместите звезды с помощью кнопки ОСНОВНОГО РЕЖИМА СТРЕЛЬБЫ. К звездам можно применять умения \"Взрыв сверхновой\", \"Туманность\" и \"Гравитационный колодец\".","th-TH":"เปิดใช้งานอัลติเมทเพื่อเข้าสู่ Astral Form แล้วกดปุ่มอาวุธหลักเพื่อจัดวางดวงดาว เล็งไปที่ดวงดาวด้วย Nova Pulse, Nebula หรือ Gravity Well ของคุณเพื่อใช้สกิลเหล่านั้น","tr-TR":"Astral Yolcu haline geçmek için ultiyi ETKİNLEŞTİR ve TEMEL ATIŞ düğmesiyle yıldız yerleştir. Yeteneklerini kullanmak için yıldızları Nova Darbesi, Yıldız Bulutu veya Çekim Alanı''yla hedef al.","vi-VN":"KÍCH HOẠT Chiêu Cuối để chuyển sang Thể Tinh Vân và BẮN để đặt các Ngôi Sao. Nhắm vào những Ngôi Sao với Xung Nhịp Tân Tinh, Tinh Vân hoặc Cầu Trọng Lực để sử dụng những kỹ năng đó.","zh-CN":"激活【终极技能】以进入星界形态，按【射击】来放置星体。随后，你可以对星体使用【新星脉冲】、【星云】和【重力之阱】技能来将其激活。","zh-TW":"「啟動」大絕可進入星體型態，使用「主要攻擊」來放置星辰。使用新星震盪、迷濛星雲或引力黑洞指定星辰，即可施放技能。"}'::jsonb, '"https://media.valorant-api.com/agents/41fb69c1-4189-7b37-f117-bcaf1e96f1bf/abilities/passive/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('9f0d8ba9-4140-b941-57d3-a7ad57c6b417'::uuid, '{"es-MX":"Brimstone","ar-AE":"بريمستون","es-ES":"Brimstone","ja-JP":"ブリムストーン","it-IT":"Brimstone","de-DE":"Brimstone","id-ID":"Brimstone","ko-KR":"브림스톤","fr-FR":"Brimstone","en-US":"Brimstone","pl-PL":"Brimstone","pt-BR":"Brimstone","ru-RU":"Brimstone","th-TH":"Brimstone","tr-TR":"BRIMSTONE","vi-VN":"Brimstone","zh-CN":"炼狱","zh-TW":"布史東"}'::jsonb, '{"es-MX":"Proveniente de EE.UU., el arsenal orbital de Brimstone asegura una ventaja constante para su equipo. Su habilidad de proporcionar información de forma precisa y segura lo hace un comandante sin igual en el campo.","ar-AE":"مع انضمامه من الولايات المتحدة الأمريكية، يمتلك بريمستون ترسانة مدارية تضمن امتلاك فريقه الأفضلية على الدوام. وتتكفل قدرته على إيصال معدات دعمه بدقة وأمان في جعله القائد الميداني الذي لا يوجد نظير له.","es-ES":"De origen estadounidense, Brimstone cuenta con un arsenal de órbita que garantiza que su equipo siempre vaya por delante. Su capacidad para aportar herramientas de utilidad de una forma segura y precisa lo convierte en un comandante de primera línea sin igual.","ja-JP":"アメリカ合衆国から参戦したブリムストーンの衛星軌道兵器があれば、部隊は常に優位に立つことができる。離れた場所から確実に支援を送るアビリティーを持つ彼は、現地での指揮にうってつけの存在なのだ。","it-IT":"L''arsenale orbitale dello statunitense Brimstone fa in modo che la sua squadra abbia sempre un vantaggio. La sua capacità di fornire utilità con precisione e sicurezza lo rende un comandante pragmatico e impareggiabile.","de-DE":"Brimstone kommt aus den USA und sein orbitales Arsenal sorgt dafür, dass sein Team stets einen klaren Vorteil hat. Er sorgt präzise und sicher für Unterstützung, was ihn zu einem perfekten Kommandanten macht.","id-ID":"Bergabung dari AS, persenjataan orbital Brimstone memastikan squad-nya selalu di posisi menguntungkan. Kemampuannya dalam mendaratkan bantuan secara presisi dan aman menjadikannya seorang komandan tempur tidak tertandingi.","ko-KR":"미국 출신 브림스톤은 궤도 무기를 활용해 아군에게 유리하도록 전투를 이끕니다. 안전하고 정확하게 다양한 수단으로 팀을 보조하는 능력 덕분에 그는 최고의 야전 사령관으로 불립니다.","fr-FR":"Tout droit venu des États-Unis d''Amérique, Brimstone possède un arsenal orbital qui permet à son escouade de toujours avoir l''avantage. La précision et la fiabilité de ses compétences utilitaires font de lui un commandant sans égal sur le terrain.","en-US":"Joining from the U.S.A., Brimstone''s orbital arsenal ensures his squad always has the advantage. His ability to deliver utility precisely and safely make him the unmatched boots-on-the-ground commander.","pl-PL":"Orbitalny arsenał pochodzącego z USA Brimstone’a zawsze zapewnia jego zespołowi przewagę. Jego zdolność zapewnienia precyzyjnego i bezpiecznego wsparcia czyni go niezrównanym dowódcą w samym sercu akcji.","pt-BR":"Vindo diretamente dos EUA, o arsenal orbital do Brimstone garante que o esquadrão dele sempre esteja em vantagem. Sua capacidade de oferecer utilitários com precisão e segurança faz dele um comandante inigualável na linha de frente.","ru-RU":"Уроженец США Brimstone обеспечивает своей команде преимущество перед противником благодаря орбитальной технике. Возможность удаленно оказывать помощь там, где это требуется, делает его несравненным боевым командиром.","th-TH":"Brimstone เข้าร่วมจากสหรัฐอเมริกา การโจมตีด้วย Orbital Arsenal ของเขาจะช่วยให้ทีมได้เปรียบเสมอ ความสามารถในการสนับสนุนอย่างแม่นยำจากระยะไกลทำให้เขาเป็นผู้บัญชาการภาคพื้นดินที่ไม่มีใครเทียบได้","tr-TR":"Aramıza ABD''den katılan Brimstone''un hava araçları sayesinde takımı her zaman 1-0 öndedir. Gereken her türlü işlevselliği titizlikle ve güvenle sağlaması, muharebe alanında bu kumandanı eşsiz kılar.","vi-VN":"Đến từ Hợp chủng quốc Hoa Kỳ, Brimstone luôn đảm bảo lợi thế cho đồng đội bằng những vũ khí tối tân ngoài quỹ đạo của mình. Những chiêu thức mang lại khả năng hỗ trợ chính xác và đảm bảo an toàn khiến Brimstone xứng đáng là một sĩ quan lục quân vô địch.","zh-CN":"“炼狱”来自美洲大陆，他能使用各种轨道武器来为团队提供精确支援和创造战术优势，是前线指挥官的不二人选。  ","zh-TW":"來自美國的布史東擁有強大的衛星武器，讓他的隊伍永遠處於優勢。他能投放戰略工具支援前線，包準「恰到好處」且萬無一失，讓他成為地表最強指揮官。"}'::jsonb, 'Sarge', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/displayicon.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/displayicon.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/fullportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/fullportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/fullportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/killfeedportrait.png', 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/minimapportrait.png', null, 'https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/background.png', array['363c4fff', '0f1923ff', '211d21ff', '0f192300'], false, true, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('9f0d8ba9-4140-b941-57d3-a7ad57c6b417'::uuid, 'Grenade', '{"es-MX":"Baliza Potenciadora","ar-AE":"المحفز اللاسلكي","es-ES":"Baliza estimulante","ja-JP":"スティムビーコン","it-IT":"Energetico","de-DE":"Stim-Pack","id-ID":"Stim Beacon","ko-KR":"자극제 신호기","fr-FR":"Balise stimulante","en-US":"Stim Beacon","pl-PL":"Nadajnik Stymulujący","pt-BR":"Sinalizador Estimulante","ru-RU":"Маячок-стимулятор","th-TH":"Stim Beacon","tr-TR":"KUVVET İŞARETİ","vi-VN":"Cường Hóa Hỏa Lực","zh-CN":"振奋信标","zh-TW":"激勵信號"}'::jsonb, '{"es-MX":"Lanza AL INSTANTE una baliza potenciadora. Al caer, crea un campo que otorga un Potenciador de combate y un aumento de movimiento a los jugadores.","ar-AE":"ارمِ محفزًا لاسلكيًا على الفور. عند هبوطه على الأرض، ينشئ حقلًا يمنح اللاعبين محفز قتال وتعزيز سرعة.","es-ES":"Lanza INSTANTÁNEAMENTE una baliza estimulante. Al aterrizar, crea un campo que otorga Estimulante de combate y un aumento de velocidad a los jugadores.","ja-JP":"スティムビーコンを投げる。スティムビーコンは地面に落ちるとフィールドを展開し、その中にいるプレイヤーにバトルスティムとスピードブーストを付与する。","it-IT":"Lancia ALL''ISTANTE un energetico. All''atterraggio, genera un campo ENERGIZZANTE e un bonus di velocità per i giocatori nel raggio d''azione.","de-DE":"Wirf SOFORT ein Stim-Pack auf den Boden. Beim Aufprall erzeugt das Stim-Pack ein Feld, das Spielern Kampf-Stim und einen Geschwindigkeitsboost verleiht.","id-ID":"Lempar suar stim dalam SEKETIKA. Saat mendarat, suar stim akan menghasilkan area yang memberikan utilitas Combat Stim dan Speed Boost pada pemain.","ko-KR":"즉시 자극제 신호기를 던집니다. 신호기가 떨어진 곳에는 플레이어에게 전투 자극제와 속도 상승 효과를 부여하는 영역이 생성됩니다.","fr-FR":"Lancez INSTANTANÉMENT une balise stimulante. Lorsqu''elle touche le sol, la balise crée un champ qui octroie l''effet Stimulant de combat et un bonus de vitesse aux joueurs.","en-US":"INSTANTLY toss down a stim beacon. Upon landing, it creates a field that grants players a Combat Stim and a Speed Boost.","pl-PL":"NATYCHMIAST rzuć nadajnik stymulujący. Po wylądowaniu na ziemi wytworzy pole zapewniające graczom stymulant bitewny i premię do szybkości.","pt-BR":"INSTANTANEAMENTE arremesse um sinalizador estimulante. Ao pousar, ele criará um campo que concede um Estimulante de Combate e um Impulso de Velocidade aos jogadores.","ru-RU":"Мгновенно бросает себе под ноги маячок-стимулятор. После приземления маячка ближайшие игроки получают боевой стимулятор и повышенную скорость передвижения.","th-TH":"ขว้าง Stim Beacon ออกไปทันที เมื่อลงถึงพื้น Stim Beacon จะสร้างพื้นที่ที่มอบบัฟ Combat Stim และมอบความเร็วในการยิงแก่ผู้เล่น","tr-TR":"ANINDA bir Kuvvet İşareti at. Yere inen Kuvvet İşareti oyunculara Kuvvetli Savaş ve Hız Takviyesi sağlayan bir alan oluşturur.","vi-VN":"NGAY LẬP TỨC gọi xuống 1 đèn hiệu cường hóa hỏa lực. Khi được đặt xuống, đèn hiệu này sẽ tạo ra 1 khu vực Khuấy Động Giao Tranh và Tăng Tốc Độ cho người chơi trong phạm vi.","zh-CN":"立即向前方投掷振奋信标，它在落地后会生成一片增益区域，给予其中的玩家【作战强化】和【加速】效果。","zh-TW":"立刻將一個激勵信號拋到面前，觸地時會製造一個力場，賦予範圍內的玩家「激發戰意」增益與「速度加成」。"}'::jsonb, '"https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('9f0d8ba9-4140-b941-57d3-a7ad57c6b417'::uuid, 'Ability1', '{"es-MX":"La Incendiaria","ar-AE":"القنبلة الحارقة","es-ES":"Incendiario","ja-JP":"インセンディアリー","it-IT":"Incendiario","de-DE":"Brandbeschuss","id-ID":"Incendiary","ko-KR":"소이탄","fr-FR":"Bombe incendiaire","en-US":"Incendiary","pl-PL":"Podpalacz","pt-BR":"Incendiário","ru-RU":"Зажигательная граната","th-TH":"Incendiary","tr-TR":"YAKICI","vi-VN":"Lựu Đạn Lửa","zh-CN":"燃烧榴弹","zh-TW":"灼人燃彈"}'::jsonb, '{"es-MX":"EQUIPA un lanzagranadas incendiario y DISPARA para lanzar una granada que explota al quedar en el suelo. Esta crea una zona de fuego que permanece en el campo y daña a los enemigos que estén dentro de ella.","ar-AE":"تجهّز بقاذفة قنابل حارقة. أطلق قنبلة يدوية تنفجر عندما تصل إلى الأرض وتتوقف عن الحركة لتخلق منطقة نارية طويلة الأمد تسبب الضرر للاعبين المتواجدين في نطاقها.","es-ES":"EQUIPA un lanzagranadas incendiarias. DISPARA una granada que detona cuando se detiene en el suelo, lo que genera una zona de fuego persistente que daña a los jugadores que estén en su interior.","ja-JP":"焼夷グレネードランチャーを装備する。「発射」でグレネードを射出する。このグレネードは地面に落ちると破裂し、地面を継続的に炎上させて範囲内のプレイヤーにダメージを与える。 ","it-IT":"EQUIPAGGIA un lanciagranate incendiario. Usa il FUOCO per lanciare una granata che esplode quando si ferma, creando una zona di fuoco persistente che danneggia i giocatori al suo interno.","de-DE":"RÜSTE einen Brandgranatenwerfer AUS. FEUERE, um eine Granate abzuschießen, die explodiert sobald sie auf dem Boden liegen bleibt und einen temporären Flammenteppich hinterlässt, der Spielern in diesem Bereich Schaden zufügt.","id-ID":"EQUIP pelontar granat yang membakar. Tekan FIRE untuk meluncurkan granat yang terdetonasi saat mencapai lantai. Granat tersebut menghasilkan zona kimia yang memberi damage pada pemain di dalam zona.","ko-KR":"소이탄 발사기를 장착합니다. 발사하면 바닥에 떨어졌을 때 폭발하는 소이탄을 날려 적에게 피해를 입히는 화염 구역을 생성합니다. 생성된 구역은 일정 시간 유지됩니다.","fr-FR":"ÉQUIPEZ-vous d''un lance-grenades incendiaires. TIREZ pour lancer une grenade qui explose lorsqu''elle s''arrête au sol, créant une zone enflammée persistante qui blesse les joueurs.","en-US":"EQUIP an incendiary grenade launcher. FIRE to launch a grenade that detonates as it comes to a rest on the floor, creating a lingering fire zone that damages players within the zone.","pl-PL":"WYPOSAŻ wyrzutnię granatów zapalających. STRZEL, by wystrzelić granat, który po zatrzymaniu się na ziemi wybucha, tworząc tymczasowy ognisty obszar zadający obrażenia znajdującym się na nim graczom.","pt-BR":"EQUIPE um lançador de granadas incendiárias. DISPARE para lançar uma granada que detona no chão, gerando uma zona de fogo que causa dano aos jogadores dentro dela.","ru-RU":"Выбирает зажигательный гранатомет. Нажмите кнопку ОГОНЬ, чтобы запустить гранату, которая падает и взрывается после остановки, образуя горящую область, в которой все игроки получают урон.","th-TH":"ติดตั้งเครื่องยิงระเบิดเพลิง กดยิงเพื่อปล่อยระเบิดที่จะระเบิดเมื่อตกสู่พื้น ก่อให้เกิดเปลวไฟที่จะสร้างความเสียหายแก่ผู้เล่นที่อยู่ในบริเวณนั้น","tr-TR":"Bir yangın bombası atar KUŞAN. Yerde durduğu anda infilak eden bir bomba fırlatmak için ATEŞ ET. Yerde bir süre kalan alev bölgesi, içindeki oyunculara hasar verir.","vi-VN":"Brim sử dụng súng phóng lựu để bắn ra một lựu đạn lửa. BẮN để phóng lựu đạn theo hướng chỉ định, khi lựu đạn chạm đất sẽ phát nổ và tạo ra một vùng lửa gây sát thương lên cho bất kỳ ai bước qua.","zh-CN":"装备燃烧弹发射器。按【射击】发射一枚榴弹，在落地停稳后引爆，生成一片持续燃烧的区域，对进入其中的玩家造成伤害。","zh-TW":"裝備一個燃燒榴彈發射器。點擊「攻擊」即可發射一枚燃燒彈，在地面停止滾動後爆炸，製造一個持續燃燒的區域，對其中玩家造成傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('9f0d8ba9-4140-b941-57d3-a7ad57c6b417'::uuid, 'Ability2', '{"es-MX":"Humo Celestial","ar-AE":"دخان السماء","es-ES":"Cortina de humo","ja-JP":"スカイスモーク","it-IT":"Cortina fumogena","de-DE":"Rauch am Himmel","id-ID":"Sky Smoke","ko-KR":"공중 연막","fr-FR":"Frappe fumigène","en-US":"Sky Smoke","pl-PL":"Podniebny Dym","pt-BR":"Fumaça Celeste","ru-RU":"Небесный дым","th-TH":"Sky Smoke","tr-TR":"DUMANLI HAVA SAHASI","vi-VN":"Bom Hỏa Mù","zh-CN":"空投烟幕","zh-TW":"垂天煙幕"}'::jsonb, '{"es-MX":"EQUIPA un mapa táctico. DISPARA para marcar las ubicaciones en las que caerán las nubes de humo de Brimstone. Usa el DISPARO SECUNDARIO para confirmar y lanzar nubes de humo de larga duración que bloquearán la visión en la zona seleccionada.","ar-AE":"تجهز بخريطة تكتيكية. أطلق لتحديد المناطق التي ستهبط فيها سحب بريمستون الدخانية. استخدم الإطلاق البديل للتأكيد وإطلاق سحب دخان طويلة الأمد تحجب الرؤية في المنطقة المستهدفة.","es-ES":"EQUIPA un mapa táctico. DISPARA para fijar ubicaciones en las que aparecerán nubes de humo de Brimstone. Utiliza el DISPARO ALTERNATIVO para confirmar. Esto liberará nubes de humo de larga duración que bloquearán la visión en la zona seleccionada.","ja-JP":"タクティカルマップを開く。「発射」でブリムストーンの煙幕弾の着弾地点を設定する。「オルト射撃」で設定を確定し、煙幕弾を撃ち込む。煙幕は長時間滞留して、指定した地点の視線を遮る。","it-IT":"EQUIPAGGIA una mappa tattica. Usa il FUOCO per impostare i punti in cui atterreranno le nuvole di fumo di Brimstone. Usa il FUOCO ALTERNATIVO per confermare e lanciare le nuvole di fumo a lunga durata che bloccano la visione nell''area selezionata.","de-DE":"RÜSTE eine taktische Karte AUS. FEUERE, um festzulegen, an welchen Positionen die Rauchwolken von Brimstone einschlagen sollen. ALT. FEUERMODUS, um die Positionen zu bestätigen und langanhaltende Rauchwolken abzufeuern, die die Sicht im gewählten Bereich blockieren.","id-ID":"EQUIP map taktis. Tekan FIRE untuk menentukan lokasi untuk mendaratkan awan asap, dan ALT FIRE untuk mengonfirmasi serta meluncurkan awan asap yang tahan lama. Awan tersebut menghalangi pandangan di area yang telah ditentukan.","ko-KR":"전술 지도를 장착합니다. 발사하면 브림스톤의 연막을 퍼뜨릴 위치를 설정합니다. 보조 공격 시 위치 확정 후 연막을 날려 한동안 선택한 지역의 시야를 차단합니다.","fr-FR":"ÉQUIPEZ-vous d''une carte tactique. TIREZ pour définir les endroits où les nuages de fumée de Brimstone atterriront. Utilisez le TIR SECONDAIRE pour confirmer, ce qui lance des nuages de fumée durables qui bloquent la vision dans la zone sélectionnée.","en-US":"EQUIP a tactical map. FIRE to set locations where Brimstone''s smoke clouds will land. ALT FIRE to confirm, launching long-lasting smoke clouds that block vision in the selected area.","pl-PL":"WYPOSAŻ mapę taktyczną. STRZEL, by określić lokacje, w których zostaną umieszczone chmury dymu Brimstone’a. Zatwierdź wybór przyciskiem ALT. STRZAŁU, by wystrzelić długotrwałe chmury dymu blokujące wizję na danym obszarze.","pt-BR":"EQUIPE um mapa tático. DISPARE para marcar os locais onde as nuvens de fumaça de Brimstone pousarão. Use o DISPARO ALTERNATIVO para confirmar, lançando nuvens de fumaça de longa duração que bloqueiam a visão na área selecionada.","ru-RU":"Выбирает тактическую карту. Нажмите кнопку ОГОНЬ, чтобы указать на карте места для установки дымовых завес. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы установить несколько дымовых завес продолжительного действия, закрывающих обзор в указанной области.","th-TH":"ติดตั้งแผนที่ยุทธวิธี กดยิงเพื่อกำหนดตำแหน่งที่จะควันของ Brimstone จะปล่อยออกมา กดโหมดยิงเสริมเพื่อยืนยันตำแหน่ง ปล่อยกลุ่มควันที่จะบดบังทัศนวิสัยในพื้นที่ที่กำหนดไว้เป็นเวลานาน","tr-TR":"Bir taktik harita KUŞAN. Brimstone''un duman bulutlarının ineceği konumları belirlemek için ATEŞ ET. Seçili alanda görüş engelleyen uzun süreli duman bulutları oluşturmak için ALT. ATIŞ ile onayla.","vi-VN":"TRANG BỊ 1 bản đồ chiến thuật. BẮN để chọn vị trí cho đám khói của Brimstone. BẮN PHỤ để xác nhận và phóng một đám khói có thời gian tồn tại rất lâu với mục đích chắn tầm nhìn trong khu vực chỉ định.","zh-CN":"装备战术地图。按【射击】设定烟幕落地的位置。按【辅助射击】以确认，呼叫历久不散的烟云来阻碍该选定区域的视野。","zh-TW":"裝備一個戰術地圖。點擊「攻擊」，可指定煙幕發射的地點。點擊「輔助攻擊」進行確認，在指定區域發射一大片煙幕，可阻擋視野且久不退散。"}'::jsonb, '"https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('9f0d8ba9-4140-b941-57d3-a7ad57c6b417'::uuid, 'Ultimate', '{"es-MX":"Ataque Orbital","ar-AE":"الضربة المدارية","es-ES":"Golpe orbital","ja-JP":"オービタルストライク","it-IT":"Raggio orbitale","de-DE":"Luftschlag","id-ID":"Orbital Strike","ko-KR":"궤도 일격","fr-FR":"Rayon orbital","en-US":"Orbital Strike","pl-PL":"Ostrzał Orbitalny","pt-BR":"Ataque Orbital","ru-RU":"Орбитальный удар","th-TH":"Orbital Strike","tr-TR":"UYDU SALDIRISI","vi-VN":"Bão Laser Không Kích","zh-CN":"天基光束","zh-TW":"衛星空襲"}'::jsonb, '{"es-MX":"EQUIPA un mapa táctico y DISPARA para lanzar un ataque orbital prolongado de un láser en la ubicación seleccionada. Este infligirá mucho daño con el tiempo a los jugadores que estén en la zona.","ar-AE":"تجهّز بخريطة تكتيكية. أطلق لنشر ليزر مداري طويل الأمد على المنطقة المستهدفة لتلحق ضررًا كبيرًا مع مرور الوقت باللاعبين المتواجدين في تلك المنطقة.","es-ES":"EQUIPA un mapa táctico. DISPARA para lanzar un golpe orbital en la ubicación objetivo con un láser persistente, que provocará un gran daño prolongado a los jugadores que se encuentren en la zona seleccionada.","ja-JP":"タクティカルマップを開く。「発射」で指定した地点に衛星軌道上からレーザー攻撃を行い、エリア内のプレイヤーに長時間に渡って継続的な大ダメージを与える。","it-IT":"EQUIPAGGIA una mappa tattica. Usa il FUOCO per lanciare un attacco orbitale persistente nel punto selezionato, che infligge ingenti danni nel tempo ai giocatori all''interno dell''area selezionata.","de-DE":"ÖFFNE eine taktische Karte. FEUERE, um einen temporären Laser-Luftschlag am Zielort anzufordern, der bei Spielern am Zielort hohen Schaden über Zeit verursacht.","id-ID":"EQUIP map taktis. Tekan FIRE untuk meluncurkan laser Orbital Strike tahan lama di lokasi yang telah ditentukan. Laser itu menghasilkan damage tinggi seiring waktu pada pemain yang berada di area tersebut.","ko-KR":"전술 지도를 장착합니다. 발사하면 선택한 위치에 궤도 일격 레이저를 쏘아 해당 영역에 있는 플레이어에게 큰 지속 피해를 입힙니다.","fr-FR":"ÉQUIPEZ-vous d''une carte tactique. TIREZ pour ordonner une frappe orbitale persistante à l''endroit sélectionné, ce qui inflige d''importants dégâts sur la durée aux joueurs pris dans la zone.","en-US":"EQUIP a tactical map. FIRE to launch a lingering orbital strike laser at the selected location, dealing high damage-over-time to players caught in the selected area.","pl-PL":"WYPOSAŻ mapę taktyczną. STRZEL, by odpalić długotrwały laserowy ostrzał orbitalny na wybranym obszarze, zadający duże obrażenia w czasie graczom, którzy znajdą się w strefie ataku.","pt-BR":"EQUIPE um mapa tático. DISPARE para lançar um ataque prolongado de laser orbital no local selecionado, causando muito dano ao longo do tempo aos jogadores na área selecionada.","ru-RU":"Выбирает тактическую карту. Нажмите кнопку ОГОНЬ, чтобы запустить орбитальный удар, наносящий высокий периодический урон игрокам, находящимся в выбранной зоне.","th-TH":"ติดตั้งแผนที่ยุทธวิธี กดยิงเพื่อปล่อย\nOrbital Strike ไปยังพื้นที่ที่กำหนด ซึ่งจะ\nสร้างความเสียหายที่จะเพิ่มความรุนแรงขึ้นเรื่อย ๆ กับผู้เล่นที่อยู่ในพื้นที่นั้น","tr-TR":"Bir taktik harita KUŞAN. Seçili konuma bir süre yerde kalan bir uydu saldırısı lazeri fırlatmak için ATEŞ ET. Seçili alanda kalan oyuncular zaman içinde yüksek hasar alır.","vi-VN":"Brim mở ra bản đồ chiến thuật. BẮN để phóng một chùm tia laser từ quỹ đạo vào vị trí chỉ định, gây sát thương lớn theo thời gian cho tất cả người chơi trong phạm vi ảnh hưởng.","zh-CN":"装备战术地图。按【射击】向选定位置发射轨道激光炮，对区域内的玩家造成高额持续伤害。","zh-TW":"裝備一個戰術地圖。點擊「攻擊」，即可向指定地點發射衛星空襲雷射，對範圍內的玩家造成重度持續傷害。"}'::jsonb, '"https://media.valorant-api.com/agents/9f0d8ba9-4140-b941-57d3-a7ad57c6b417/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, '{"es-MX":"Iso","ar-AE":"آيسو","es-ES":"Iso","ja-JP":"アイソ","it-IT":"Iso","de-DE":"Iso","id-ID":"Iso","ko-KR":"아이소","fr-FR":"Iso","en-US":"Iso","pl-PL":"Iso","pt-BR":"Iso","ru-RU":"Iso","th-TH":"Iso","tr-TR":"ISO","vi-VN":"Iso","zh-CN":"壹决","zh-TW":"離索"}'::jsonb, '{"es-MX":"El agente chino Iso es un neutralizador a sueldo que entra en estado de fluidez para desmantelar a sus oponentes. Reconfigura la energía ambiental para convertirla en una protección a prueba de balas y avanza con determinación hacia su próximo duelo a muerte.","ar-AE":"يدخل اختصاصي المهام الصعبة المأجور الصيني آيسو في حالة تركيز خاص لتقويض أركان الخصوم. ومن خلال تحويل الطاقة المحيطة إلى حماية مضادة للرصاص، يتقدم بتركيز ليخوض مبارزته التالية حتى الموت.","es-ES":"Iso, el asesino a sueldo chino, entra en un estado de flujo de energía para acabar con sus rivales. Capaz de reconfigurar la energía del ambiente para crear una protección a prueba de balas, avanza concentrado hacia su siguiente duelo a muerte.","ja-JP":"中国出身の雇われフィクサーであるアイソは、フロー状態に入って敵の勢力を解体する。彼は周囲のエネルギーを防弾の守りとして再構築しながら、命を懸けた次の決闘へと向かう。","it-IT":"Iso, il risolutore su commissione cinese, entra in uno stato di concentrazione elevata per distruggere i nemici. Trasformando l''energia ambientale in una protezione antiproiettile, si lancia sicuro nel suo prossimo duello all''ultimo sangue.","de-DE":"Der chinesische Problemlöser Iso kommt in einen Flow und nimmt so seine Gegner auseinander. Er wandelt Umgebungsenergie in kugelsichere Panzerung um und sucht zielstrebig nach seinem nächsten Duell auf Leben und Tod.","id-ID":"Eksekutor bayaran terpercaya asal Cina, Iso, memasuki kondisi fokus untuk memberantas lawan. Dengan merombak energi sekitar menjadi proteksi antipeluru, dia fokus maju ke duel selanjutnya hingga titik darah penghabisan.","ko-KR":"중국 출신인 청부 해결사 아이소는 집중 상태에 들어가 적을 와해시킵니다. 아이소는 주변 에너지를 방탄 보호막으로 재구성해 전진하며 쓰러질 때까지 다음 결투 상대에게 집중합니다.","fr-FR":"Venu de Chine et spécialiste de missions délicates, Iso se fond dans le flux de radianite pour démanteler les réseaux ennemis. Capable de restructurer l''énergie ambiante en protection pare-balles, rien ne l''arrêtera sur le chemin de son prochain duel à mort.","en-US":"Chinese fixer for hire Iso falls into a flow state to dismantle the opposition. Reconfiguring ambient energy into bulletproof protection, he advances with focus towards his next duel to the death.","pl-PL":"Iso, chiński macher na zlecenie, wchodzi w stan skupienia, aby łamać wszelki opór. Przekształcając energię otoczenia w kuloodporną osłonę, naciera w skupieniu w kierunku następnego pojedynku na śmierć i życie.","pt-BR":"Iso é um mercenário chinês que entra em estado de fluxo para desmantelar os oponentes. Ele reconfigura a energia do ambiente para se proteger de balas e avança totalmente focado em direção ao próximo duelo até a morte.","ru-RU":"Китайский агент Iso – опытный боец, способный устранить любую цель. Он преобразовывает окружающую энергию в пуленепробиваемые щиты и уверенно вступает в отчаянные бои один на один.","th-TH":"มือปืนรับจ้างชาวจีน Iso จะเข้าสู่สภาวะจดจ่อเพื่อทำลายล้างคู่ต่อสู้ ด้วยเทคโนโลยีการเปลี่ยนแปลงพลังงาน Radianite ในสภาพแวดล้อมให้กลายเป็นเกราะป้องกันกระสุน เขาทะยานสู่การดวลครั้งต่อไปอย่างมุ่งมั่น","tr-TR":"Çinli kiralık suikastçı Iso düşmanların saflarını darmadağın etmek için bir akış haline girer. Çevredeki enerjiyi yeniden şekillendirerek kurşun geçirmez bir kalkana dönüştüren Iso odağını yitirmeden bir sonraki ölümüne düellosuna ilerler.","vi-VN":"\"Lính đánh thuê\" người Trung Quốc, Iso rơi vào trạng thái dòng chảy để triệt tiêu đối thủ. Anh tái định hình cấu trúc năng lượng xung quanh thành một lớp bảo vệ chống đạn và vận sức tập trung vào trận đấu tay đôi tiếp theo cho đến khi có người ngã xuống.","zh-CN":"“壹决”是华夏文明的后裔。他是枪斗的艺术家，战斗时仿佛沉浸在自我的心流中，将对手的抵抗悉数瓦解。他还能重构环境中的能量来阻挡子弹。战斗中的他时刻保持专注，并渴望与强敌一决高下。","zh-TW":"中國傭兵離索進入殺戮心流狀態，重組周圍環境的能量化作防彈護盾，專心致志地邁向下一次生死對決。"}'::jsonb, 'Sequoia', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/displayicon.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/displayicon.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/fullportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/fullportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/fullportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/killfeedportrait.png', 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/minimapportrait.png', null, 'https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/background.png', array['30336eff', '0f1923ff', '20155dff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, 'Ability1', '{"es-MX":"Recorte","ar-AE":"التقويض","es-ES":"Socavar","ja-JP":"アンダーカット","it-IT":"Riduzione","de-DE":"Molekularblitz","id-ID":"Undercut","ko-KR":"약화","fr-FR":"Sape","en-US":"Undercut","pl-PL":"Podcięcie","pt-BR":"Centelha Debilitante","ru-RU":"Дестабилизация","th-TH":"Undercut","tr-TR":"GAREZ","vi-VN":"Xuyên Tâm","zh-CN":"稳态剥离","zh-TW":"削減"}'::jsonb, '{"es-MX":"EQUIPA un proyectil molecular. DISPARA para lanzarlo hacia adelante. Aplica brevemente Vulnerable y Suprime a todos los jugadores que toque. Puede atravesar objetos sólidos, incluidas las paredes.","ar-AE":"تجهّز بصاعقة جزيئية. أطلق لرميها للأمام، مع تطبيق تأثيري هشاشة وقمع قصيري المدة على جميع اللاعبين الذين تلمسهم. يمكن أن تمر الصاعقة عبر الأجسام الصلبة، بما في ذلك الجدران.","es-ES":"EQUIPA un proyectil molecular. DISPARA para lanzarlo hacia delante, lo que aplica vulnerabilidad y suprime a todos los jugadores que toca durante un breve periodo. El proyectil puede atravesar objetos sólidos, incluso paredes.","ja-JP":"分子ボルトを構える。「発射」でボルトを前方に投げ、それに触れたすべてのプレイヤーを短時間弱体化させてアビリティーを封じ込める。ボルトは壁を含む固体のオブジェクトを通り抜けられる。","it-IT":"EQUIPAGGIA un dardo molecolare. Usa il FUOCO per lanciarlo in avanti, applicando brevemente VULNERABILE e SOPPRESSIONE a tutti i giocatori che tocca. Il dardo può attraversare gli oggetti solidi, muri compresi.","de-DE":"RÜSTE einen Molekularblitz AUS. FEUERE, um ihn nach vorn zu werfen. Alle Spieler, die von ihm berührt werden, werden kurzzeitig verwundbar und unterdrückt. Der Blitz kann feste Objekte, einschließlich Wände, durchdringen.","id-ID":"EQUIP petir molekuler. Tekan FIRE untuk melemparnya ke depan, sesaat menerapkan Vulnerable & Suppress pada semua pemain yang tersentuh. Petir dapat menembus benda padat, termasuk dinding.","ko-KR":"분자 탄환을 장착합니다. 발사하면 탄환을 전방으로 날려 적중한 모든 플레이어를 잠시 취약 상태로 만들고 제압합니다. 탄환은 벽을 포함해 단단한 물체를 관통할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un carreau moléculaire. TIREZ pour le lancer vers l''avant, ce qui rend brièvement vulnérables et neutralise tous les joueurs touchés. Le carreau peut traverser les objets solides, murs y compris.","en-US":"EQUIP a molecular bolt. FIRE to throw it forward, briefly applying Vulnerable & Suppress to all players it touches. The bolt can pass through solid objects, including walls.","pl-PL":"WYPOSAŻ molekularną strzałę. STRZEL, by wypuścić ją przed siebie, powodując chwilową podatność i tłumiąc wszystkich dotkniętych przez nią graczy. Strzała może przelatywać przez stałe obiekty, w tym ściany.","pt-BR":"EQUIPE um feixe molecular. DISPARE para lançá-lo à frente e aplicar Vulnerabilidade e Supressão por um curto período a todos os jogadores que tocar. O feixe pode atravessar objetos sólidos, inclusive paredes.","ru-RU":"Выбирает молекулярную энергию. Нажмите ОГОНЬ, чтобы метнуть ее, подавив и сделав уязвимыми игроков, которых она коснется. Энергия проходит сквозь стены и другие твердые объекты.","th-TH":"ติดตั้งลูกบอลโมเลกุล กดยิงเพื่อขว้างออกไป มอบสถานะเปราะบางและยับยั้งพลังแก่ผู้เล่นทุกคนที่โดนเป็นเวลาสั้น ๆ ลูกบอลจะทะลุผ่านวัตถุของแข็งได้ รวมถึงกำแพง","tr-TR":"Bir moleküler dalga KUŞAN. Dalgayı ileri fırlatarak temas ettiği bütün oyunculara Savunmasız ve Sindirme etkileri uygulamak için ATEŞ ET. Bu dalga duvarlar dahil olmak üzere sert cisimlerin içinden geçebilir.","vi-VN":"TRANG BỊ 1 tia phân tử. BẮN để phóng tia ra phía trước, áp dụng hiệu ứng Suy Yếu & Áp Chế trong thoáng chốc lên tất cả người chơi trúng chiêu. Tia phân tử có thể đi xuyên qua các vật thể rắn, bao gồm tường.","zh-CN":"装备扰乱分子结构的能量箭。按【射击】将其向前掷出，对触碰到的所有玩家施加短暂的【易伤】与【压制】效果。此能量箭可穿透墙壁等固体障碍。","zh-TW":"點擊「裝備」裝備一枚分子螺旋彈，點擊「攻擊」即可向前拋擲，所有被觸及的玩家會暫時進入「衰弱」及「抑制」狀態。此彈體可貫穿牆壁等堅硬物體。"}'::jsonb, '"https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, 'Ultimate', '{"es-MX":"Lista Negra","ar-AE":"مبارزة العالم الموازي","es-ES":"Contrato de asesinato","ja-JP":"キルコントラクト","it-IT":"Singolar tenzone","de-DE":"Auftragsmord","id-ID":"Kill Contract","ko-KR":"청부 계약","fr-FR":"Duel à huis clos","en-US":"Kill Contract","pl-PL":"Zlecenie Zabójcy","pt-BR":"Contrato de Abate","ru-RU":"Контракт на убийство","th-TH":"Kill Contract","tr-TR":"KİRALIK KATİL","vi-VN":"Giao Kèo Chết Chóc","zh-CN":"决斗通牒","zh-TW":"決滅"}'::jsonb, '{"es-MX":"EQUIPA una arena interdimensional. DISPARA para lanzar una columna de energía a través del campo de batalla, que arrastra y cura tanto a ti como al primer enemigo alcanzado a la arena para un duelo a muerte.","ar-AE":"تجهّز بحلبة تنتمي لعالم موازٍ. أطلق لإلقاء عمود من الطاقة عبر ساحة المعركة، مما يؤدي إلى علاجك أنت وأول عدو مصاب وسحبكما إلى الحلبة للمبارزة حتى الموت.","es-ES":"EQUIPA una arena interdimensional. DISPARA para lanzar una columna de energía a través del campo de batalla que os arrastra y cura a ti y al primer enemigo alcanzado a la arena para enfrentaros en un duelo hasta la muerte.","ja-JP":"異次元空間を構築し、「発射」でフィールドにライン状のエネルギーを投射する。ラインは自分と最初に命中した敵を回復しながらその空間に引き込み、異次元空間で命を懸けた決闘が強制される。","it-IT":"EQUIPAGGIA un''arena interdimensionale. Usa il FUOCO per lanciare una colonna di energia attraverso il campo di battaglia che trascina nell''arena te e il primo nemico colpito e vi cura per un duello all''ultimo sangue.","de-DE":"RÜSTE eine interdimensionale Arena AUS. FEUERE, um eine Energiesäule loszuschicken. Diese zieht dich und den ersten getroffenen Gegner in die Arena und heilt euch. In der Arena müsst ihr bis zum Tod kämpfen.","id-ID":"EQUIP arena antardimensi. Tekan FIRE untuk melemparkan selajur energi ke seluruh medan tempur, memberi heal dan menarikmu serta musuh pertama yang terkena ke dalam arena untuk berduel sampai titik darah penghabisan.","ko-KR":"장착하면 차원의 결투장을 준비합니다. 발사하면 전장에 에너지파를 날려 처음으로 적중한 적과 자신의 체력을 회복시키고 함께 결투장으로 이동합니다. 결투장으로 끌려온 적과 쓰러질 때까지 결투합니다.","fr-FR":"ÉQUIPEZ-vous d''une arène interdimensionnelle. Utilisez le TIR PRINCIPAL pour produire une colonne d''énergie sur le terrain, vous soignant vous et le premier ennemi touché et l''attirant  avec vous dans l''arène et pour un duel à mort.","en-US":"EQUIP an interdimensional arena. FIRE to hurl a column of energy through the battlefield, pulling and healing both you and the first enemy hit into the arena to duel to the death.","pl-PL":"WYPOSAŻ międzywymiarową arenę. STRZEL, aby cisnąć przez pole bitwy kolumnę energii. Uleczy ona ciebie oraz pierwszego trafionego wroga i wciągnie was na arenę, na której będziecie walczyć w pojedynku na śmierć i życie.","pt-BR":"EQUIPE uma arena interdimensional. DISPARE para lançar uma coluna de energia pelo campo de batalha que puxa você e o primeiro inimigo atingido por ela para a arena para duelarem até a morte após curar vocês dois.","ru-RU":"Выбирает межпространственную арену. Нажмите ОГОНЬ, чтобы выпустить поток энергии. Первый противник, которого коснется поток, и Iso восполняют здоровье и перемещаются на арену, покинуть которую можно только после убийства оппонента.","th-TH":"ติดตั้งสนามประลองระหว่างมิติ กดยิงเพื่อขว้างเสาพลังงานผ่านสนามรบ ซึ่งจะดึงและฮีลทั้งตัวคุณและศัตรูคนแรกที่โดนเข้าสู่สนามประลองเพื่อมาดวลกันให้ตายไปข้าง","tr-TR":"Bir boyutlararası arena KUŞAN. Seni ve temas ettiği ilk düşmanı iyileştirip ölümüne bir düelloya gireceğiniz arenaya çekecek bir enerji dalgasını savaş meydanına göndermek için ATEŞ ET.","vi-VN":"TRANG BỊ 1 đấu trường đa chiều. BẮN để ném một cột năng lượng ra giữa chiến trường, kéo và hồi máu cả bạn lẫn kẻ địch đầu tiên trúng phải vào một đấu trường để đấu tay đôi cho đến khi một người ngã xuống.","zh-CN":"构筑一座异次元竞技场。按【射击】发出一道穿越战场的能量矩阵，将命中的首名敌人拉进竞技场，双方同时获得治疗，并展开一对一决斗。","zh-TW":"裝備一個次元空間，點擊「攻擊」即可擲出一道貫穿戰場的能量束，治療第一位命中的對手與自身，並拉進空間內進行生死對決。"}'::jsonb, '"https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, 'Ability2', '{"es-MX":"Remate","ar-AE":"الإطلاق المزدوج","es-ES":"Disparo doble","ja-JP":"ダブルタップ","it-IT":"Doppio tocco","de-DE":"Dublette","id-ID":"Double Tap","ko-KR":"구슬 보호막","fr-FR":"Tir couplé","en-US":"Double Tap","pl-PL":"Dublet","pt-BR":"Fluxo Protetor","ru-RU":"Контрольный выстрел","th-TH":"Double Tap","tr-TR":"ÇELİK İRADE","vi-VN":"Truy Kích","zh-CN":"战斗心流","zh-TW":"雙源"}'::jsonb, '{"es-MX":"Comienzas a enfocarte AL INSTANTE. Al enfocarte: Obtienes un escudo que absorbe una instancia de daño de cualquier fuente, recargas más rápido y entras en un estado de flujo durante el cual los enemigos derribados que mates o dañes generan un orbe de energía. Al dispararle a este orbe, se reinician el estado de fluidez y el escudo actual, o recibes otro.","ar-AE":"ابدأ فورًا في شحن مؤقت التركيز لديك. بمجرد اكتمال الشحن، تكسب درعًا يمتص جرعة واحدة من الضرر من أي مصدر، وتعيد التلقيم بسرعة أكبر، وتدخل في طور تركيز تتولد خلاله كرة طاقة عند قتل الأعداء أو إلحاق الضرر بهم. يؤدي الإطلاق على هذه الكرة إلى تجديد طور التركيز لديك ودرعك الحالي، أو إلى منحك درعًا آخر.","es-ES":"Comienza a concentrarte AL INSTANTE. Al concentrarte: Obtienes un escudo que absorbe una única vez el daño de cualquier fuente, recargas más rápido y entras en un estado de flujo durante el cual los enemigos derribados que has asesinado o dañado generan un orbe de energía. Al disparar al orbe, se reinician el estado de flujo y el escudo, o recibes otro.","ja-JP":"フォーカスの詠唱を即座に開始する。フォーカス状態になると、いかなる種類のダメージでも1回分無効化できるシールドを獲得する。また、よりすばやくリロードでき、フロー状態に入る。その効果中は、倒した敵やダメージを与えた敵からエネルギーオーブが生成される。このオーブを撃つと、フロー状態および獲得済みのシールドが更新されるか、新しいシールドが付与される。","it-IT":"Iso inizia ALL''ISTANTE a concentrarsi. Una volta concentrato, ottiene uno scudo che assorbe un singolo evento di danno da qualsiasi fonte, ricarica più velocemente ed entra in uno stato di trance durante il quale i nemici abbattuti che ha ucciso o danneggiato generano una sfera di energia. Sparando a questa sfera ripristini la durata dello stato di trance e dello scudo già esistente, oppure ne ottieni un altro.","de-DE":"Fokussiere deine Konzentration SOFORT! Bei vollständiger Konzentration: Erhalte einen Panzer, der eine Schadensinstanz von jeder Quelle absorbiert, und du lädst schneller nach. Du kommst auch in einen Flow. Zu Boden gegangene Gegner, die du im Flow-Zustand tötest oder verletzt, erzeugen eine Energiekugel. Schieße die Kugel ab, um deinen Flow-Zustand und deinen bestehenden Panzer zurückzusetzen, oder um dir einen neuen zu gewähren.","id-ID":"SEKETIKA mulai menyalurkan fokusmu. Setelah fokus: mendapatkan shield yang menyerap satu instans damage dari sumber mana pun, reload lebih cepat, dan memasuki kondisi fokus agar musuh yang tumbang karena kamu kill atau beri damage memunculkan orb energi. Jika ditembak, orb ini akan memperbarui status fokusmu dan shield yang ada, atau memberikan satu shield lagi.","ko-KR":"즉시 집중을 시작합니다. 집중하면 모든 유형의 피해를 한 번 흡수하는 보호막을 얻고, 재장전이 빨라지며, 이 상태에서 적을 처치하거나 피해를 입힌 적이 쓰러지면 에너지 구슬이 생성됩니다. 구슬을 쏘면 집중 상태와 현재 보호막이 초기화되거나 보호막을 다시 얻습니다.","fr-FR":"Vous commencez INSTANTANÉMENT à vous concentrer. Une fois concentré : vous gagnez un bouclier absorbant une salve de dégâts de n''importe quelle source, vous rechargez plus vite et vous entrez dans un état fluide pendant lequel les ennemis que vous avez tués ou blessés génèrent un orbe d''énergie. Tirez sur cet orbe pour actualiser votre état fluide et votre bouclier existant, ou pour gagner un nouveau bouclier.","en-US":"INSTANTLY start channeling your focus. Once focused: gain a shield which absorbs one instance of damage from any source, reload more quickly, and enter a flow state during which downed enemies you kill or damage spawn an energy orb. Shooting this orb refreshes your flow state and your existing shield, or grants another.","pl-PL":"NATYCHMIAST zaczyna przygotowywać twoje skupienie. Po osiągnięciu skupienia: zapewnia ci tarczę, która wchłania jedno wystąpienie obrażeń z dowolnego źródła, pozwala ci przeładowywać szybciej i wprawia cię w stan skupienia, w czasie którego zabici lub zranieni przez ciebie przeciwnicy po pokonaniu pozostawiają po sobie kule energii. Strzelenie w tę kulę odnawia twój stan skupienia i obecną tarczę lub nakłada na ciebie nową tarczę.","pt-BR":"Comece INSTANTANEAMENTE a canalizar seu foco. Com o foco ativado: receba um escudo que absorve uma instância de dano de qualquer fonte, recarregue mais rápido e entre em um estado de fluxo. Inimigos que você abate ou a quem causa dano durante esse tempo geram um orbe de energia. Atirar nesse orbe renova seu estado de fluxo e seu escudo existente ou concede outro.","ru-RU":"Мгновенно инициирует фокусирование. Когда фокусирование завершено, агент получает щит, поглощающий одну порцию урона любого происхождения, перезаряжает оружие быстрее и входит в состояние потока, а противники, убитые при его участии, начинают оставлять энергетические сферы. Выстрелив в такую сферу, агент перезапускает состояние потока, а также имеющийся щит – либо получает его заново.","th-TH":"เริ่มร่ายเพื่อเข้าสู่โฟกัสทันที เมื่อเข้าสู่โฟกัสแล้ว จะได้รับโล่ซึ่งจะดูดซับความเสียหายใด ๆ ก็ตามได้ 1 ครั้ง รีโหลดได้เร็วขึ้น และเข้าสู่สถานะจดจ่อ ซึ่งในระหว่างนี้ ศัตรูที่ตายจากการโดนคุณฆ่าหรือสร้างความเสียหายจะทำให้ออร์บพลังงานปรากฏขึ้น การยิงออร์บนี้จะรีเฟรชสถานะจดจ่อและโล่ที่มีอยู่ของคุณ หรือมอบโล่ใหม่","tr-TR":"ANINDA odaklanmaya başla. Odaklanma tamamlandığında herhangi bir kaynaktan gelecek ilk hasarı engelleyen bir kalkan kazanırsın, silahını daha hızlı doldurursun ve öldürdüğün veya ölmeden önce senden hasar alan düşmanların enerji küresi düşürdüğü bir akış haline girersin. Bu küreye ateş ettiğinde akış halini ve var olan kalkanını yenilersin veya yeni bir kalkan kazanırsın.","vi-VN":"NGAY LẬP TỨC bắt đầu vận tập trung. Khi đã tập trung: nhận khiên hấp thụ 1 luồng sát thương từ bất kỳ nguồn nào, nạp đạn nhanh hơn, và bước vào trạng thái dòng chảy, trong đó mỗi kẻ địch bị bạn tiêu diệt hoặc gây sát thương lên sẽ tạo ra một quả cầu năng lượng. Bắn quả cầu này sẽ làm mới trạng thái dòng chảy và khiên sẵn có, hoặc cho thêm khiên.","zh-CN":"集中意念：获得一道护盾，可吸收一次任意来源的伤害，加快换弹速度，并进入心流状态。在此状态期间，受到你伤害的敌人会在被击败时生成一颗能量球。射击此球体可刷新当前存在的护盾和心流状态，或生成一道新护盾。","zh-TW":"立即開始凝神專注。專注完成後，獲得能吸收一次任何傷害的護盾，填彈速度變快，並進入殺戮心流狀態，此時對手被你擊殺、或受到你的傷害陣亡後會產生能量球。射擊此能量球即可重置殺戮心流狀態以及現有的護盾，或是產生新的護盾。"}'::jsonb, '"https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, 'Grenade', '{"es-MX":"Contingencia","ar-AE":"إجراء احتياطي","es-ES":"Contingencia","ja-JP":"コンティンジェンシー","it-IT":"Evenienza","de-DE":"Vorsichtsmaßnahme","id-ID":"Contingency","ko-KR":"대비책","fr-FR":"Contingence","en-US":"Contingency","pl-PL":"Plan Awaryjny","pt-BR":"Contingência","ru-RU":"Особая ситуация","th-TH":"Contingency","tr-TR":"B PLANI","vi-VN":"Ứng Biến","zh-CN":"绝对屏障","zh-TW":"應變"}'::jsonb, '{"es-MX":"EQUIPA para reunir energía prismática. DISPARA para impulsar hacia adelante un muro indestructible de energía que bloquea las balas. DISPARO SECUNDARIO para impulsar hacia adelante una versión más lenta del muro.","ar-AE":"تجهّز لتجميع الطاقة الموشورية. أطلق لدفع جدار طاقة غير قابل للتدمير إلى الأمام يتولى صد الرصاص. استخدم الإطلاق البديل للدفع بنسخة أبطأ من الجدار.","es-ES":"EQUIPA para reunir energía prismática. DISPARA para levantar un muro indestructible de energía que bloquea las balas. Utiliza el DISPARO ALTERNATIVO para desplegar una versión del muro más lenta.","ja-JP":"構えてプリズム状のエネルギーを溜める。「発射」で銃弾を防ぐ破壊不能な壁を前方に押し出す。「オルト射撃」でより遅い速度で壁を押し出す。","it-IT":"EQUIPAGGIA per incanalare energia prismatica. Usa il FUOCO per spingere in avanti un muro di energia indistruttibile che blocca i proiettili. Usa il FUOCO ALTERNATIVO per spingere in avanti il muro più lentamente.","de-DE":"AUSRÜSTEN, um prismatische Energie zu formen. FEUERE, um eine unzerstörbare Energiewand, die Kugeln abwehrt, nach vorn zu schicken. ALT. FEUERMODUS zum Aufbauen einer langsameren Version der Mauer.","id-ID":"EQUIP untuk merakit energi prismatik. Tekan FIRE untuk mendorong dinding energi yang tak bisa hancur untuk menghalangi peluru. Tekan ALT FIRE untuk mendorong tembok yang lebih lambat.","ko-KR":"장착하면 프리즘 에너지를 모읍니다. 발사하면 탄환을 막는 에너지 장벽을 앞으로 날립니다. 장벽은 파괴할 수 없습니다. 보조 공격 시 장벽을 느리게 날립니다.","fr-FR":"PRÉPAREZ une concentration d''énergie prismatique. Utilisez le TIR PRINCIPAL pour projeter un mur d''énergie indestructible qui bloque les balles. Utilisez le TIR SECONDAIRE pour projeter un mur plus lent.","en-US":"EQUIP to assemble prismatic energy. FIRE to push an indestructible wall of energy forward that blocks bullets. ALT FIRE to push out a slower version of the wall.","pl-PL":"UŻYJ, aby zebrać energię pryzmatyczną. STRZEL, by pchnąć niezniszczalną ścianę energii, która powstrzymuje pociski. ALT. STRZAŁ, by pchnąć wolniejszą wersję ściany.","pt-BR":"EQUIPE para reunir energia prismática. DISPARE para enviar à frente uma parede de energia indestrutível que bloqueia balas. Use o DISPARO ALTERNATIVO para enviar uma versão mais lenta da parede.","ru-RU":"Нажмите кнопку умения, чтобы собрать призматическую энергию. Нажмите ОГОНЬ, чтобы отправить вперед неразрушаемую энергетическую стену, блокирующую пули. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы стена двигалась медленнее.","th-TH":"ติดตั้งเพื่อรวบรวมพลังงานปริซึม กดยิงเพื่อดันม่านพลังงานที่ทำลายไม่ได้ไปข้างหน้าเพื่อบล็อกกระสุน กดโหมดยิงเสริมเพื่อส่งให้กำแพงเคลื่อนที่ออกไปช้าลง","tr-TR":"Prizmatik enerji biriktirmek için KUŞAN. Yok edilemeyen ve mermileri engelleyen bir enerji duvarını ileri doğru göndermek için ATEŞ ET. Duvarı ileri doğru daha yavaş göndermek için ALT. ATIŞ kullan.","vi-VN":"TRANG BỊ để triệu hồi năng lượng lăng trụ. NHẤN BẮN để tạo ra một bức tường năng lượng không thể phá hủy phía trước mặt, chặn mọi đường đạn. BẮN PHỤ để tạo ra một chiếc tường phiên bản chậm hơn.","zh-CN":"将能量聚合为棱晶形态。按【射击】向前推出一道可阻挡子弹的能量墙。按【辅助射击】可以较慢速度推出能量墙。","zh-TW":"點擊「裝備」即可凝聚稜光能量，接著點擊「攻擊」即可向前送出一道無法破壞的能量牆，阻擋子彈。點擊「輔助攻擊」送出一道速度較慢的牆。"}'::jsonb, '"https://media.valorant-api.com/agents/0e38b510-41a8-5780-5e8f-568b2a4f2d6c/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('0e38b510-41a8-5780-5e8f-568b2a4f2d6c'::uuid, 200000, '2023-10-31T13:00:00Z'::timestamp with time zone, '2023-11-29T22:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, '{"es-MX":"Clove","ar-AE":"كلوف","es-ES":"Clove","ja-JP":"クローヴ","it-IT":"Clove","de-DE":"Clove","id-ID":"Clove","ko-KR":"클로브","fr-FR":"Clove","en-US":"Clove","pl-PL":"Clove","pt-BR":"Clove","ru-RU":"Clove","th-TH":"Clove","tr-TR":"CLOVE","vi-VN":"Clove","zh-CN":"暮蝶","zh-TW":"珂樂芙"}'::jsonb, '{"es-MX":"Clove llega desde Escocia buscando pleito, y sus travesuras no paran ni en el calor de la batalla, ni en el frío de la muerte. Le joven inmortal confunde a los enemigos incluso desde el más allá, porque saben que en cualquier momento puede regresar al mundo de los vivos.","ar-AE":"تُلحق كلوف الاسكتلندية المشاكسة الأذى بالأعداء سواء فى حرارة القتال أو برودة الموت. وتُبقي المخلوقة الأزلية الشابة الأعداء في حيرة من أمرهم حتى عند موتها الذي لا يطول سوى برهة في المعتاد.","es-ES":"Le agente escocese Clove no para de liarla, tanto en el fragor de la batalla como en el frío abrazo de la muerte. Le joven inmortal trae de cabeza a sus enemigos incluso desde el más allá, porque saben que en cualquier momento podría volver al mundo de los vivos.","ja-JP":"スコットランド出身のトラブルメーカー「クローヴ」は、激しい戦闘の最中も、冷たい死を迎えたときすらも敵に悪戯を仕掛ける。若き不死の存在であるクローヴは、死の向こう側からでさえ敵に疑念を抱かせ翻弄する。生ける世界への帰還はいつもほんの一瞬のことだから。","it-IT":"L''agente scozzese combinaguai Clove crea scompiglio tra i nemici tanto nel fuoco della battaglia quanto nel gelo della morte. Quest''immortale tiene i nemici sulle spine anche dall''oltretomba, dalla quale può fare ritorno in ogni momento.","de-DE":"Clove aus Schottland ist gut darin, Gegner sowohl in der Hitze des Gefechts als auch angesichts der Kälte des Todes auf Trab zu halten. Clove ist unsterblich und kann selbst aus dem Grab heraus viel Unheil stiften und Gegner im Unklaren über die nächsten Schritte lassen.","id-ID":"Pembuat onar dari Skotlandia, Clove, membawa masalah bagi musuh di tengah panasnya pertempuran dan dinginnya kematian. Manusia abadi ini membuat musuhnya bertanya-tanya, bahkan soal kebangkitan setelah mati. Kembalinya dia ke dunia hanya tinggal menunggu waktu.","ko-KR":"스코틀랜드 출신 말썽꾸러기 클로브는 전투의 열기 속에서도, 싸늘한 죽음 속에서도 적을 괴롭힙니다. 젊은 불멸자인 클로브는 죽은 후에도 적에게 곧 살아 돌아올 거라는 불안감을 안겨 줍니다.","fr-FR":"Clove, l''intenable Écossais·e, déstabilise l''ennemi dans le feu de l''action comme le froid de la mort. Iel sème le trouble dans les rangs ennemis, même depuis sa tombe, car sa mort ne dure jamais très longtemps.","en-US":"Scottish troublemaker Clove makes mischief for enemies in both the heat of combat and the cold of death. The young immortal keeps foes guessing, even from beyond the grave, their return to the living only ever a moment away.","pl-PL":"Szkocku łobuzu Clove płata figle wrogom zarówno w ogniu walki, jak i w zimnych objęciach śmierci. Młodu nieśmiertelnu trzyma przeciwników w niepewności nawet zza grobu. Wróg nigdy nie wie, kiedy Clove wróci do świata żywych.","pt-BR":"Clove, ume encrenqueire da Escócia, vai desorientar os inimigos tanto no calor do combate quanto no frio da morte. Jovem e imortal, elu mantém os inimigos confusos até do além-túmulo: momentos após a morte, elu retorna à vida.","ru-RU":"Clove, родом из Шотландии, умеет навредить противникам и в пылу боя, и во хладе смерти. Врагам остается только гадать, когда же агент восстанет из могилы, – а это может случиться в любой момент.","th-TH":"Clove จอมก่อปัญหาชาวสก็อต จะสร้างความโกลาหลให้กับเหล่าศัตรูทั้งในระหว่างการต่อสู้\nอันดุเดือดและในยามที่หมดลมหายใจ เด็กอมตะ\nผู้นี้จะทำให้เหล่าศัตรูต้องคอยคาดเดา\nแม้ในโลกหลังความตาย เขาจะกลับมามีชีวิต\nหลังจากที่เวลาผ่านไปแค่ครู่เดียว","tr-TR":"İskoç ajan Clove muziplikleriyle hem çatışma sırasında hem de ölümden sonra sürekli ortalığı karıştırıyor. Ölüm nedir bilmeyen bu genç ajanın mezarından çıkıp gelerek düşmanlarının başına bela olması daima an meselesi.","vi-VN":"Chuyên gia gây rối đến từ Scotland, Clove \"quậy đục nước\" kẻ địch ngay giữa chiến trường nóng bỏng và cả trước cái chết lạnh lẽo. Kẻ bất tử trẻ tuổi luôn khiến kẻ địch phải đau đầu, kể cả khi đã bị vùi sâu xuống lòng đất, cậu ấy vẫn có thể tái sinh chỉ sau chốc lát.","zh-CN":"来自不列颠群岛北部的“暮蝶”擅长用自己的招牌恶作剧来捉弄敌人。即便在被击败后，这位年轻的永生者也能继续干扰敌人，甚至出其不意地返场再战。","zh-TW":"蘇格蘭裔搗蛋鬼珂樂芙遊走於戰鬥的激情和死亡的冷酷之間，總讓敵人捉摸不定。這位永生不朽的年輕人最愛將敵人耍得團團轉，即便身中數槍倒下，也可能隨時復活、就像沒事一樣。"}'::jsonb, 'Smonk', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/displayicon.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/displayicon.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/fullportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/fullportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/fullportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/killfeedportrait.png', 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/minimapportrait.png', null, 'https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/background.png', array['4b1d80ff', '0f1923ff', 'c347c7ff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, 'Grenade', '{"es-MX":"Tentempié","ar-AE":"جرعة منعشة","es-ES":"Chute de energía","ja-JP":"ピック・ミー・アップ","it-IT":"Ricostituente","de-DE":"Stärkungsmittel","id-ID":"Pick-me-up","ko-KR":"활력 회복","fr-FR":"Coup de boost","en-US":"Pick-me-up","pl-PL":"Na Zdrówko","pt-BR":"Revitalizar","ru-RU":"Подпитка","th-TH":"Pick-me-up","tr-TR":"DİNÇLEŞTİRİCİ ÖZÜT","vi-VN":"Hấp Thụ Sinh Lực","zh-CN":"虹吸","zh-TW":"精魂再生"}'::jsonb, '{"es-MX":"ACTIVA para absorber la fuerza vital de un enemigo caído al que Clove haya infligido daño o asesinado. Esto le otorga velocidad y vida de forma temporal.","ar-AE":"قم بتفعيل القدرة وامتص القوة من أحد الأعداء الذين سقطوا بعد أن تعرضوا للضرر أو القتل على يد كلوف، مما يكسبك تسارعًا وصحةً مؤقتة.","es-ES":"ACTIVA para absorber la fuerza vital de un enemigo caído al que Clove haya infligido daño o asesinado. Esto le otorga velocidad y vida de forma temporal.","ja-JP":"「発動」すると、クローヴがキルまたは事前にダメージを与えていた、倒れた敵から生命力を吸収する。移動速度が増し、一時的な増加体力を得る。","it-IT":"ATTIVA per assorbire la forza vitale di un nemico caduto che Clove ha danneggiato o ucciso, ottenendo velocità e salute temporanea.","de-DE":"AKTIVIERE, um die Lebenskraft von Gegnern zu absorbieren, die durch Clove getötet oder Schaden erfahren haben. Gewährt Tempo und vorübergehendes Leben.","id-ID":"AKTIFKAN untuk menyerap kekuatan musuh yang tumbang karena terkena damage atau kill dari Clove. Kekuatan ini memberikan haste dan health sementara.","ko-KR":"활성화 시 피해를 입히거나 처치한 적의 생명력을 흡수하여 이동 속도 증가와 일시적인 체력 증가 효과를 얻습니다.","fr-FR":"ACTIVEZ pour absorber la force vitale d''un ennemi tombé au combat que Clove a blessé ou tué, ce qui vous accélère et vous fait gagner des PV temporaires.","en-US":"ACTIVATE to absorb the life force of a fallen enemy that Clove damaged or killed, gaining haste and temporary health.","pl-PL":"AKTYWUJ, by wchłonąć siłę życiową wyeliminowanego wroga zranionego lub zabitego przez Clove i zyskać przyspieszenie oraz tymczasowe zdrowie.","pt-BR":"ATIVE para absorver a energia vital de um inimigo caído que sofreu dano ou foi abatido por Clove e receba aceleração e Vida temporárias.","ru-RU":"Нажмите кнопку умения, чтобы поглотить жизненную силу павшего противника, которого Clove удалось убить (или нанести урон). Это дает повышение скорости и временную прибавку к здоровью.","th-TH":"เปิดใช้งานเพื่อดูดซับพลังชีวิตของศัตรูที่ตายซึ่ง Clove เป็นคนสร้างความเสียหายหรือฆ่าในทันที เพิ่มความเร็วและพลังชีวิตชั่วคราว","tr-TR":"Clove''un öldürdüğü veya hasar vererek asist aldığı düşmanlardan yaşam enerjisi çekerek hız ve geçici can kazanmak için ETKİNLEŞTİR.","vi-VN":"KÍCH HOẠT để hấp thụ sinh lực của một kẻ địch đã hi sinh khi bị Clove gây sát thương hoặc hạ gục, được tăng tốc và nhận máu tạm thời.","zh-CN":"激活后，从被暮蝶击败或助攻的敌人身上吸收生命能量，获得加速和临时生命值。","zh-TW":"按下「啟動」可吸收珂樂芙擊殺或助攻之陣亡對手的生命能量，獲得加速與暫時生命值。"}'::jsonb, '"https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, 'Ability2', '{"es-MX":"Treta","ar-AE":"الحيلة","es-ES":"Treta","ja-JP":"ルース","it-IT":"Stratagemma","de-DE":"Täuschung","id-ID":"Ruse","ko-KR":"계략","fr-FR":"Ruse","en-US":"Ruse","pl-PL":"Zwód","pt-BR":"Artimanha","ru-RU":"Уловка","th-TH":"Ruse","tr-TR":"KATAKULLİ","vi-VN":"Bịp Bợm","zh-CN":"霞染","zh-TW":"瑰詭煙雲"}'::jsonb, '{"es-MX":"EQUIPA una vista del campo de batalla. DISPARA para marcar las ubicaciones en las que aparecerán las nubes de Clove. Usa el DISPARO SECUNDARIO para confirmar y lanzar nubes que bloquearán la visión en las zonas seleccionadas. Clove puede usar esta habilidad después de morir.","ar-AE":"تجهّز بنظرة على ساحة المعركة. أطلق لتحديد أماكن استقرار سُحُب كلوف. استخدم الإطلاق البديل للتأكيد، مما يؤدي إلى إطلاق السحب لحجب الرؤية في الأماكن المختارة. تستطيع كلوف استخدام هذه القدرة بعد الموت.","es-ES":"EQUIPA una vista del campo de batalla. DISPARA para fijar ubicaciones en las que aparecerán las nubes de Clove. Utiliza el DISPARO ALTERNATIVO para confirmar. Esto liberará nubes que bloquearán la visión en las zonas seleccionadas. Clove puede usar esta habilidad tras morir.","ja-JP":"マップを表示する。「発射」でクローヴの煙幕の発生地点を指定する。「オルト射撃」で位置を確定し、煙幕を発生させる。煙幕は指定した地点の視線を遮る。クローヴはデス後もこのスキルを使用できる。","it-IT":"EQUIPAGGIA una visuale del campo di battaglia. Usa il FUOCO per impostare i punti in cui si assesteranno le nuvole di Clove. Usa il FUOCO ALTERNATIVO per confermare e lanciare le nuvole, che bloccheranno la visione nelle aree selezionate. Clove può usare quest''abilità dopo la morte.","de-DE":"LEGE eine Schlachtfeldansicht AN. FEUERE, um festzulegen, an welchen Positionen die Rauchwolken von Clove entstehen soll. ALT. FEUERMODUS, um die Positionen zu bestätigen und Rauchwolken abzufeuern, die die Sicht im gewählten Bereich blockieren. Clove kann die Fähigkeit nach dem Tod einsetzen.","id-ID":"EQUIP tampilan battlefield. Tekan FIRE untuk mengatur lokasi pendaratan awan. Tekan ALT FIRE untuk mengonfirmasi dan meluncurkan awan. Awan ini dapat menghalangi pandangan lawan di area yang dipilih. Clove bisa menggunakan ability ini setelah mati.","ko-KR":"전장 시야를 장착합니다. 발사하면 연기가 발생할 위치를 지정합니다. 보조 공격 시 위치 확정 후 지정한 지역의 시야를 차단하는 연기를 보냅니다. 클로브는 사망 후에도 이 스킬을 사용할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''une vue du champ de bataille. TIREZ pour définir les endroits où poser les nuages de Clove. Utilisez le TIR SECONDAIRE pour confirmer, ce qui lance des nuages qui bloquent la vision dans les zones sélectionnées. Clove peut utiliser cette compétence après sa mort.","en-US":"EQUIP a view of the battlefield. FIRE to set the locations where Clove’s clouds will settle. ALT FIRE to confirm, launching clouds that block vision in the chosen areas. Clove can use this ability after death.","pl-PL":"UŻYJ, by wyświetlić mapę pola bitwy. STRZEL, by określić lokacje, w których zostaną umiejscowione chmury Clove. Zatwierdź wybór przyciskiem ALT. STRZAŁU, by wystrzelić chmury blokujące wizję na wybranych obszarach. Clove może używać tej umiejętności po śmierci.","pt-BR":"EQUIPE uma imagem do campo de batalha. DISPARE para marcar os locais onde você quer posicionar as nuvens de Clove. Use o DISPARO ALTERNATIVO para confirmar e lançar nuvens que bloqueiam a visão nas áreas selecionadas. Clove pode usar essa habilidade depois de morrer.","ru-RU":"Выбирает обзор поля боя. Нажмите кнопку ОГОНЬ, чтобы указать места на карте для облаков Clove. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы запустить несколько облаков, застилающих обзор в выбранной области. Clove может использовать это умение после смерти.","th-TH":"ติดตั้งมุมมองของสนามรบ กดยิงเพื่อกำหนดตำแหน่งที่เมฆของ Clove จะปล่อยออกมา กดโหมดยิงเสริมเพื่อยืนยันตำแหน่ง ปล่อยเมฆที่จะบดบังทัศนวิสัยในพื้นที่ที่กำหนด Clove ใช้สกิลนี้หลังจากตายแล้วได้","tr-TR":"Savaş meydanının haritasını KUŞAN. Clove''un duman bulutlarının düşeceği konumları belirlemek için ATEŞ ET. Seçili alanlarda görüş engelleyen duman bulutları oluşturmak için ALT. ATIŞ ile onayla. Clove bu yeteneği öldükten sonra da kullanabilir.","vi-VN":"TRANG BỊ 1 tầm nhìn của chiến trường. BẮN để chọn vị trí hạ xuống cho đám mây của Clove. BẮN PHỤ để xác nhận và phóng một đám mây để chắn tầm nhìn trong khu vực được chọn. Clove có thể sử dụng kỹ năng này sau khi hy sinh.","zh-CN":"装备战场地图。按【射击】选择烟雾的部署位置，按【辅助射击】以确认，在指定地点创造阻隔视线的云雾。暮蝶可以在被击败期间使用此技能。","zh-TW":"裝備一個戰場的鳥瞰圖。點擊「攻擊」，可指定放置煙幕的地點。點擊「輔助攻擊」進行確認，在指定區域產生一大片煙幕，阻擋視野。珂樂芙可在陣亡後施放此技能。"}'::jsonb, '"https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, 'Ultimate', '{"es-MX":"No Morí","ar-AE":"مراوغة الموت","es-ES":"No me voy","ja-JP":"ノット・デッド・イェット","it-IT":"Seconda occasione","de-DE":"Noch nicht tot","id-ID":"Not Dead Yet","ko-KR":"아직 안 죽었어","fr-FR":"Toujours debout","en-US":"Not Dead Yet","pl-PL":"Jeszcze Żyję","pt-BR":"Ainda Não Morri","ru-RU":"Рано помирать","th-TH":"Not Dead Yet","tr-TR":"DAHA ÖLMEDİK","vi-VN":"Bất Diệt","zh-CN":"化蝶","zh-TW":"續命開關"}'::jsonb, '{"es-MX":"Tras morir, ACTIVA para resucitar. Una vez que resucita, Clove debe conseguir un asesinato o una asistencia de daño dentro de un periodo de tiempo determinado o morirá. REACTIVA para cancelar antes de tiempo.","ar-AE":"بعد الموت، قم بالتفعيل للعودة إلى الحياة. بعد العودة إلى الحياة، يجب أن تحقق كلوف عملية قتل أو مساعدة في إلحاق الضرر ضمن فترة معينة كي تتجنب الموت. أعد التفعيل للإلغاء مبكرًا.","es-ES":"Tras morir, ACTIVA para resucitar. Al resucitar, Clove debe conseguir un asesinato o una asistencia de daño durante un periodo de tiempo determinado o morirá. REACTIVA para cancelar antes de tiempo.","ja-JP":"倒された後に「発動」すると復活する。復活後、一定時間内にキルを奪うかダメージアシストを行わなければ、クローヴはデスする。再発動すると早めにキャンセルする。","it-IT":"Dopo la morte, ATTIVA per risorgere. Dopo la risurrezione, Clove deve ottenere un''uccisione o un assist con danni entro un determinato periodo di tempo o morirà. RIATTIVA per annullare l''abilità in anticipo.","de-DE":"Nach dem Tod AKTIVIEREN zum Wiederbeleben. Nach der Wiederbelebung muss Clove innerhalb einer bestimmten Zeit einen Kill oder eine Schadensunterstützung erzielen, oder der Tod tritt erneut ein. REAKTIVIERE zum vorzeitigen Abbrechen.","id-ID":"Setelah mati, AKTIFKAN ability ini agar bisa hidup kembali. Setelah hidup kembali, Clove harus mendapatkan kill atau assist dengan damage dalam waktu yang ditentukan, atau dia akan mati. AKTIFKAN LAGI untuk membatalkan lebih awal.","ko-KR":"사망 후 활성화 시 부활합니다. 부활 후 일정 시간 내에 킬 또는 어시스트를 달성하지 않으면 사망합니다. 다시 활성화하면 일찍 취소합니다.","fr-FR":"Après votre mort, ACTIVEZ pour revenir à la vie. De retour parmi les vivants, vous avez un certain temps pour réussir une élimination ou une assistance blessante, sans quoi vous mourez. RÉACTIVEZ pour annuler prématurément.","en-US":"After dying, ACTIVATE to resurrect. Once resurrected, Clove must earn a kill or a damaging assist within a set time or they will die. REACTIVATE to cancel early.","pl-PL":"AKTYWUJ po śmierci, by wskrzesić postać. Po wskrzeszeniu Clove musi zdobyć zabójstwo lub asystę z zadaniem obrażeń w określonym czasie, bo inaczej zginie. REAKTYWUJ, by anulować wcześniej.","pt-BR":"Depois de morrer, ATIVE para ressuscitar. Depois de ressuscitar, Clove precisa obter um abate ou uma assistência de dano em um determinado período ou morre de vez. REATIVE para cancelar mais cedo.","ru-RU":"Нажмите кнопку умения для воскрешения. После воскрешения Clove нужно убить противника (или помочь убить его, нанеся урон) в пределах определенного времени, иначе наступит смерть. Нажмите кнопку умения повторно, чтобы отменить использование.","th-TH":"หลังจากตาย ให้เปิดใช้งานเพื่อคืนชีพ เมื่อคืนชีพแล้ว Clove จะต้องเก็บคิลหรือช่วยสร้างความเสียหายภายในเวลาที่กำหนด มิฉะนั้นเขาจะตาย เปิดใช้งานอีกครั้งเพื่อยกเลิกก่อนกำหนด","tr-TR":"Öldükten sonra hayata dönmek için ETKİNLEŞTİR. Clove hayata döndükten sonra belirli bir süre içerisinde bir skor veya hasar yoluyla asist almazsa ölür. Yeteneği erkenden iptal etmek için TEKRAR ETKİNLEŞTİR.","vi-VN":"Sau khi hi sinh, KÍCH HOẠT để hồi sinh. Sau khi hồi sinh, Clove phải có 1 mạng hạ gục hoặc có hỗ trợ sát thương trong một khoảng thời gian nhất định, nếu không sẽ hi sinh. TÁI KÍCH HOẠT để hủy sớm.","zh-CN":"被击败后，【激活】此技能以复活。复活后，暮蝶必须在限定时间内完成击败或助攻，否则将会回到被击败状态。【再次激活】可提前取消技能。","zh-TW":"陣亡後，按下「啟動」即可復活。復活之後，珂樂芙必須在一定時間內造成擊殺或助攻，否則便會再次陣亡。重施技能可提前取消技能效果。"}'::jsonb, '"https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, 'Ability1', '{"es-MX":"Carambola","ar-AE":"تطفّل","es-ES":"Tejemaneje","ja-JP":"メドル","it-IT":"Interferenza","de-DE":"Rumpfuschen","id-ID":"Meddle","ko-KR":"간섭","fr-FR":"Trouble-fête","en-US":"Meddle","pl-PL":"Zamęt","pt-BR":"Desvitalização","ru-RU":"Вмешательство","th-TH":"Meddle","tr-TR":"İŞGÜZAR","vi-VN":"Nhúng Chàm","zh-CN":"整蛊","zh-TW":"驚奇干涉"}'::jsonb, '{"es-MX":"EQUIPA un fragmento de esencia inmortal. DISPARA para lanzar el fragmento, que estalla tras un breve lapso de tiempo e inflige decrecimiento temporal a todos los objetivos alcanzados.","ar-AE":"تجهّز بجزء من جوهر الخلود. أطلق لرمي الجزء الذي ينفجر بعد فترة وجيزة من ارتطامه بالأرض ويوقع جميع الأهداف الواقعة في نطاقه مؤقتًا تحت تأثير التدهور.","es-ES":"EQUIPA un fragmento de esencia inmortal. DISPARA para lanzar el fragmento, que entrará en erupción tras un breve lapso de tiempo al tocar el suelo y aplicará declive de forma temporal a todos los objetivos que se encuentren en su interior.","ja-JP":"不死のエッセンスの欠片を構える。「発射」で欠片を投げる。欠片は床に着地後少ししてから爆発し、範囲内のすべての対象に一時的に「衰弱」効果を与える。","it-IT":"EQUIPAGGIA un frammento di essenza dell''immortalità. Usa il FUOCO per lanciare il frammento, che esplode qualche istante dopo essere atterrato e DETERIORA temporaneamente tutti i bersagli al suo interno.","de-DE":"LEGE ein Fragment der Unsterblichkeitsessenz AN. FEUERE, um das Fragment zu werfen. Nach dem Auftreffen auf dem Boden explodiert es nach einer kurzen Verzögerung und belegt sämtliche Ziele im Wirkungsradius mit „Verfall“.","id-ID":"EQUIP fragmen dari esensi keabadian. Tekan FIRE untuk melempar fragmen yang meledak setelah beberapa saat mendarat di lantai. Kemudian akan memberi efek Decay sementara pada semua target yang terperangkap di dalamnya.","ko-KR":"불멸의 정수 파편을 장착합니다. 발사하면 파편을 던집니다. 파편은 바닥에 닿으면 잠시 후 폭발하여 내부에 있는 모든 대상을 일시적으로 부패시킵니다.","fr-FR":"ÉQUIPEZ-vous d''un fragment d''essence d''immortalité. TIREZ pour lancer le fragment, lequel explose après un court délai en atterrissant au sol et désagrège temporairement toutes les cibles touchées.","en-US":"EQUIP a fragment of immortality essence. FIRE to throw the fragment, which upon landing on the floor, erupts after a short delay and temporarily Decays all targets caught inside.","pl-PL":"UŻYJ fragmentu esencji nieśmiertelności. STRZEL, by rzucić fragmentem, który po chwili od wylądowania na ziemi wybuchnie i spowoduje tymczasowy rozpad wszystkich celów w obszarze działania.","pt-BR":"EQUIPE um fragmento de Essência da Imortalidade. DISPARE para lançá-lo. Ao chegar no chão, ele detona após um breve intervalo e aplica temporariamente Deterioração a todos os alvos atingidos.","ru-RU":"Выбирает фрагмент эссенции бессмертия. Нажмите кнопку ОГОНЬ, чтобы бросить его. Коснувшись земли, он разрывается и временно наносит периодический урон всем целям в зоне поражения.","th-TH":"ติดตั้งเศษเสี้ยวแก่นอมตา กดยิงเพื่อขว้างเศษเสี้ยว ซึ่งเมื่อตกลงบนพื้น จะระเบิดหลังจากทิ้งช่วงสักครู่ และทำให้เป้าหมายทั้งหมดในบริเวณนั้นติดสถานะเสื่อมสลายชั่วคราว","tr-TR":"Bir ölümsüzlük özü parçası KUŞAN. Parçayı fırlatmak için ATEŞ ET. Fırlattığın parça yere değdikten sonra kısa bir gecikmenin ardından patlayarak etki alanında kalan tüm hedeflere geçici Çürüme uygular.","vi-VN":"TRANG BỊ 1 mảnh tinh hoa bất tử. BẮN để ném mảnh tinh hoa, khi chạm đất nó sẽ phát nổ thành từng mảnh nhỏ sau khoảng thời gian chờ ngắn và tạm thời làm Phân Rã mọi mục tiêu bên trong.","zh-CN":"装备一块不朽精华碎片。按【射击】将其掷出，落地后，碎片会在短暂延迟后爆炸，对范围内所有目标施加短时间的【腐坏】效果。","zh-TW":"裝備一塊永生精粹碎片。點擊「攻擊」即可向前拋擲，碎片落地隔一小段時間後爆發，對範圍內所有目標造成暫時「侵蝕」效果。"}'::jsonb, '"https://media.valorant-api.com/agents/1dbf2edd-4729-0984-3115-daa5eed44993/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('1dbf2edd-4729-0984-3115-daa5eed44993'::uuid, 200000, '2024-03-25T13:00:00Z'::timestamp with time zone, '2024-04-24T22:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('bb2a4828-46eb-8cd1-e765-15848195d751'::uuid, '{"es-MX":"Neon","ar-AE":"نيون","es-ES":"Neon","ja-JP":"ネオン","it-IT":"Neon","de-DE":"Neon","id-ID":"Neon","ko-KR":"네온","fr-FR":"Neon","en-US":"Neon","pl-PL":"Neon","pt-BR":"Neon","ru-RU":"Neon","th-TH":"NEON","tr-TR":"NEON","vi-VN":"Neon","zh-CN":"霓虹","zh-TW":"妮虹"}'::jsonb, '{"es-MX":"La agente filipina Neon avanza a velocidades impactantes, descargando ráfagas de energía bioeléctrica tan rápido como su cuerpo la genera. Se adelanta velozmente a sus enemigos para atraparlos desprevenidos y luego los fulmina más rápido que un rayo.","ar-AE":"تندفع العميلة الفلبينية نيون إلى الأمام بسرعة مذهلة، وتفرغ دفقات من أشعة الكهرباء الحيوية بسرعة توليد جسمها لها. وتسبق الجميع للإيقاع بالأعداء في غفلة من أمرهم، ثم تضربهم بسرعة تفوق سرعة البرق.","es-ES":"Neon, una agente filipina, se lanza hacia la batalla a una velocidad trepidante, disparando descargas bioeléctricas tan rápido como las genera su cuerpo. Se adelanta para pillar a sus enemigos desprevenidos y acabar con ellos más rápida que el rayo.","ja-JP":"フィリピン出身のエージェント、ネオンは驚異的なスピードで戦場を突き進み、生体電気を生み出して激しい電撃を解き放つ。彼女はそのスピードで敵の不意をつき、稲妻よりも速く相手を打ち倒す。","it-IT":"Neon, la scheggia delle Filippine, scatta a velocità supersoniche, emettendo scariche di bioelettricità generate dal suo corpo. Questo agente coglie i nemici di sorpresa con la sua rapidità e poi li colpisce più veloce di un fulmine.","de-DE":"Die philippinische Agentin Neon prescht blitzschnell nach vorn und entlädt Blitze aus bioelektrischer Strahlung, die ihr Körper mit einer ebensolchen Geschwindigkeit erzeugt. Sie stürmt vorwärts, um unvorbereitete Gegner zu überraschen und erledigt sie dann mit Lichtgeschwindigkeit.","id-ID":"Agen dari Filipina, Neon, melesat maju dengan kecepatan yang mencengangkan, menyemburkan pancaran bioelektrik secepat tubuhnya menghasilkannya. Dia berlari untuk mengejutkan musuh, lalu menyerang mereka lebih cepat dari kilat.","ko-KR":"필리핀 출신 요원 네온은 엄청난 속도로 달리며 몸에서 만들어낸 생체 전기를 빠르게 방출시킵니다. 네온은 빠르게 움직여 방심한 적을 기습하고, 번개보다 빠르게 제압합니다.","fr-FR":"Originaire des Philippines, Neon traverse le champ de bataille à une vitesse fulgurante, libérant de grosses décharges de radiance bioélectrique générées par son corps. Elle contourne les ennemis pour les prendre par surprise et les éliminer en un éclair.","en-US":"Filipino Agent Neon surges forward at shocking speeds, discharging bursts of bioelectric radiance as fast as her body generates it. She races ahead to catch enemies off guard then strikes them down quicker than lightning.","pl-PL":"Filipińska agentka Neon z niebotyczną prędkością pędzi naprzód, emitując impulsy bioelektrycznego blasku równie szybko, jak jej ciało je wytwarza. Mknie niczym wiatr, aby wziąć wrogów z zaskoczenia, po czym wykańcza ich szybciej niż błyskawica.","pt-BR":"Neon, nossa Agente filipina, avança em velocidades incríveis, descarregando surtos de radiância bioelétrica tão rapidamente quanto seu corpo consegue gerá-los. Ela corre à frente para pegar os inimigos de surpresa, abatendo-os mais rápido do que um raio.","ru-RU":"Филиппинка Neon способна невероятно быстро передвигаться благодаря биоэлектрическим импульсам, которые генерирует ее тело. Это позволяет ей заставать врагов врасплох и расправляться с ними быстрее молнии.","th-TH":"Neon เอเจนท์ชาวฟิลิปปินส์พุ่งไปข้างหน้าด้วยความเร็วที่น่าทึ่ง พร้อมปลดปล่อยระลอกไฟฟ้าชีวภาพได้เร็วพอ ๆ กับที่ร่างกายของเธอสร้างได้ เธอเคลื่อนที่อย่างรวดเร็วเพื่อจัดการศัตรูอย่างรวดเร็วแบบไม่ทันได้ตั้งตัว","tr-TR":"Filipinli Ajan Neon, şoke edici bir hızla öne atılır ve bedeninin ürettiği biyoelektrik dalgalarını düşmanların üstüne salar. Düşmanları gafil avlamak için yarışırcasına koşar ve hepsini yıldırım hızıyla indirir.","vi-VN":"Neon, một Đặc Vụ người Phillipines với kỹ năng phóng về phía trước với tốc độ chóng mặt, bắn ra các chùm bức xạ điện sinh học nhanh như chính cách cơ thể cô ấy tạo ra nó. Cô luôn xông lên trước để tìm kẻ thù khi chúng chưa kịp trở tay, để rồi hạ gục chúng trong chớp mắt.","zh-CN":"来自西太平洋群岛的“霓虹”拥有惊人的速度，可以在运动中产生和释放生物电能量。她擅长利用快速机动，以闪电般的效率把敌人打得措手不及。","zh-TW":"妮虹是來自菲律賓的特務，她的身體能產生帶有輻能的生物電流，讓她能一邊高速衝刺一邊釋放電擊。她擅長趁虛而入，然後以迅雷不及掩耳的速度擊倒敵人。"}'::jsonb, 'Sprinter', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/displayicon.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/displayicon.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/fullportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/fullportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/fullportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/killfeedportrait.png', 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/minimapportrait.png', null, 'https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/background.png', array['413476ff', '0f1923ff', '38328eff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('bb2a4828-46eb-8cd1-e765-15848195d751'::uuid, 'Ability2', '{"es-MX":"Velocidad Relámpago","ar-AE":"معدات السرعة","es-ES":"Cambio de marcha","ja-JP":"ハイギア","it-IT":"Partenza in quarta","de-DE":"Hochtourig","id-ID":"High Gear","ko-KR":"고속 기어","fr-FR":"Vitesse supérieure","en-US":"High Gear","pl-PL":"Wysoki Bieg","pt-BR":"Equipamento Voltaico","ru-RU":"Повышенная скорость","th-TH":"High Gear","tr-TR":"YÜKSEK DEVİR","vi-VN":"Gài Số Tiến","zh-CN":"充能疾驰","zh-TW":"極速快檔"}'::jsonb, '{"es-MX":"Canaliza INSTANTÁNEAMENTE el poder de Neon para aumentar su velocidad. Al cargarse, utiliza el DISPARO SECUNDARIO para activar un deslizamiento eléctrico. La carga del deslizamiento se reinicia cada dos asesinatos. Los asesinatos recargan el combustible. ","ar-AE":"وجّه قوة نيون فوريًا لزيادة السرعة. عند الشحن، اضغط على زر الإطلاق البديل لتفعيل اندفاع انزلاق كهربائي. تتم إعادة ضبط شحنة الانزلاق بعد كل عمليتي قتل. تتم إعادة شحن الوقود عند القتل. ","es-ES":"Canaliza INSTANTÁNEAMENTE el poder de Neon para aumentar su velocidad. Cuando esté cargado, utiliza el DISPARO ALTERNATIVO para activar un deslizamiento eléctrico. La carga del deslizamiento se reinicia cada dos asesinatos. El combustible se recarga al morir. ","ja-JP":"ネオンの力が解き放たれ、スピードが上昇する。「オルト射撃」でチャージを消費し、電気をまとって加速する。加速のチャージは敵を2回キルするたびにリセットされる。キルで燃料が回復する。 ","it-IT":"Canalizza ALL''ISTANTE l''energia di Neon per AUMENTARE LA VELOCITÀ. Quando l''abilità è carica, usa il FUOCO ALTERNATIVO per attivare uno scatto in scivolata elettrico. La carica della scivolata si ripristina ogni due uccisioni. Il carburante per la corsa si ricarica con le uccisioni. ","de-DE":"Kanalisiere SOFORT Neons Macht für erhöhte Geschwindigkeit. Wenn aufgeladen, löse mit ALT. FEUER einen elektrisierten Rutschen-Sprint aus. Die Rutschaufladung setzt sich alle zwei Kills zurück. Treibstoff lädt sich mit Kills wieder auf. ","id-ID":"LANGSUNG menyalurkan kekuatan Neon untuk Meningkatkan Kecepatan. Saat charge penuh, tekan ALT FIRE untuk memicu luncuran listrik. Charge luncuran direset tiap dua kill. Fuel di-recharge saat kill. ","ko-KR":"네온의 힘을 즉시 집중해 속도를 높입니다. 충전되면 보조 공격 시 전기 슬라이드를 발동합니다. 슬라이드 충전량은 2킬마다 초기화됩니다. 적 처치 시 배터리 게이지가 재충전됩니다. ","fr-FR":"Chargez INSTANTANÉMENT le pouvoir de Neon pour décupler sa vitesse. À la fin du chargement, utilisez le TIR SECONDAIRE pour faire une glissade électrique (considérée comme une ruée). Vous regagnez une charge de glissade toutes les deux éliminations. Le carburant se recharge en cas d''élimination. ","en-US":"INSTANTLY channel Neon’s power for Increased Speed. When charged, ALT FIRE to trigger an electric slide dash. Slide charge resets every two kills. Fuel recharges on kill. ","pl-PL":"NATYCHMIAST wykorzystaj moc Neon, aby znacząco przyspieszyć. Gdy ładunek jest dostępny, użyj ALT. STRZAŁU, aby wykonać doskok – elektryczny ślizg. Reset naładowania ślizgu następuje co dwa zabójstwa. Paliwo uzupełniane jest przy każdym zabójstwie. ","pt-BR":"INSTANTANEAMENTE canaliza o poder da Neon para receber velocidade aumentada. Ao atingir a carga máxima, use o DISPARO ALTERNATIVO para acionar um deslize elétrico. A carga de deslizamento é redefinida a cada dois abates. Abates recarregam o combustível. ","ru-RU":"Мгновенно накапливает заряд для повышения скорости. Находясь в заряженном состоянии, нажмите кнопку АЛЬТ. ОГОНЬ, чтобы проскользить. Заряд скольжения восстанавливается после каждых двух убийств. Топливо восполняется после убийства. ","th-TH":"ใช้พลังของ Neon เพื่อเพิ่มความเร็วทันที เมื่อมีชาร์จพอ จะสามารถกดโหมดยิงเสริมเพื่อพุ่งตัวสไลด์ด้วยพลังงานไฟฟ้า ชาร์จสำหรับการสไลด์จะรีเซ็ตทุก ๆ สองคิล เติมพลังงานสกิลเมื่อเก็บคิลได้ ","tr-TR":"Neon''u Hızlandırmak için ANINDA gücünü odakla. Yükü dolduğunda atılmak için ALT. ATIŞ''la elektrikli kayma hareketini etkinleştir. Her iki skorda bir kayma hareketinin yükü dolar. Skor aldığında yakıt yeniden dolar. ","vi-VN":"NGAY LẬP TỨC chuyển vận sức mạnh của Neon để Tăng Tốc Độ. Sau khi đã tụ đầy, BẮN PHỤ để kích hoạt một luồng trượt điện. Lượt sử dụng luồng trượt điện sẽ được làm mới sau mỗi 2 hạ gục. Nhiên liệu được nạp lại khi có mạng hạ gục. ","zh-CN":"引导霓虹的力量，立即提升移动速度。充能完毕时，按【辅助射击】即可发动闪电滑行。每击败两名敌人，可重置滑行的充能。击败敌人可补充燃料。 ","zh-TW":"立刻運用妮虹的能力提升速度。充能完成時，點擊「輔助攻擊」可發動帶電衝刺滑行。每擊殺兩名敵人可重置滑行充能數。擊殺時可補充燃料。 "}'::jsonb, '"https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('bb2a4828-46eb-8cd1-e765-15848195d751'::uuid, 'Ability1', '{"es-MX":"Electrorrebote","ar-AE":"صاعقة المرحّل","es-ES":"Proyectil electrizante","ja-JP":"リレーボルト","it-IT":"Saetta relè","de-DE":"Relaisblitz","id-ID":"Relay Bolt","ko-KR":"릴레이 볼트","fr-FR":"Éclair relais","en-US":"Relay Bolt","pl-PL":"Błyskawica Przekaźnikowa","pt-BR":"Ricochete Elétrico","ru-RU":"Прыгающий снаряд","th-TH":"Relay Bolt","tr-TR":"ELEKTRO OK","vi-VN":"Tia Chớp Nảy","zh-CN":"闪电弹球","zh-TW":"閃電傳導"}'::jsonb, '{"es-MX":"Lanza AL INSTANTE un rayo de energía que rebota una vez. Luego de golpear cada superficie, el rayo electrifica el terreno debajo, lo que provoca una explosión conmocionante.","ar-AE":"ارمِ بشكل فوري صاعقة طاقة ترتد مرة واحدة. عند إصابة كل سطح، تكهرب الصاعقة الأرض تحتها بصدمة ارتجاجية.","es-ES":"Lanza INSTANTÁNEAMENTE un rayo de energía que rebota una vez. Al golpear una superficie, el rayo electrifica el suelo de debajo con una explosión aturdidora.","ja-JP":"一度だけ跳ね返るエネルギーボルトを放つ。ボルトがオブジェクトの表面に触れるたび、その下にある地面は電気を帯び、スタンを与える爆発を起こす。","it-IT":"Lancia ALL''ISTANTE una saetta che rimbalza una volta. Quando colpisce una superficie, la saetta elettrizza il terreno sottostante con una scarica STORDENTE.","de-DE":"Schleudere SOFORT einen Energieblitz, der einmal abprallt. Wenn der Blitz auf eine Oberfläche trifft, elektrisiert er die Fläche unter dem Aufschlagspunkt mit einer erschütternden Explosion.","id-ID":"SEKETIKA melempar energy bolt yang memantul satu kali. Saat mengenai permukaan, bolt menyetrum tanah yang dikenainya dan meledak sehingga menghasilkan utilitas Concussive.","ko-KR":"한 번 튕기는 에너지 볼트를 즉시 투척합니다. 볼트는 표면에 맞을 때마다 지면에 전류를 흘려보내 뇌진탕을 일으킵니다.","fr-FR":"Lancez INSTANTANÉMENT un éclair d''énergie qui rebondit une fois. Chaque fois qu''il rencontre une surface, l''éclair électrifie le sol en dessous avec une explosion désorientante.","en-US":"INSTANTLY throw an energy bolt that bounces once. Upon hitting each surface, the bolt electrifies the ground below with a Concussive blast.","pl-PL":"NATYCHMIAST wyemituj błyskawicę energii, która odbije się jeden raz. Po uderzeniu w dowolną powierzchnię błyskawica naelektryzuje znajdujące się poniżej podłoże, wywołując ogłuszający wybuch.","pt-BR":"INSTANTANEAMENTE arremessa um raio de energia que ricocheteia uma vez. Ao atingir cada superfície, o raio eletrifica o chão abaixo dele com uma explosão Concussiva.","ru-RU":"Мгновенно бросает энергетический снаряд, который отскакивает от поверхности один раз. Когда снаряд касается поверхности, земля под ним электризуется, и происходит оглушающий взрыв.","th-TH":"ยิงคลื่นพลังงานออกไปทันที มันสามารถเด้งได้หนึ่งครั้ง เมื่อกระทบพื้นผิวแต่ละครั้ง ลูกดอกจะสร้างกระแสไฟฟ้าช็อตพื้นดินเบื้องล่าง ก่อให้เกิดแรงสะเทือน","tr-TR":"ANINDA bir enerji oku fırlat. Ok bir kere seker. Ok bir yüzeye çarptığında Sersemletici bir patlamayla altındaki zemine elektrik akımı verir.","vi-VN":"NGAY LẬP TỨC ném ra 1 tia năng lượng có thể nảy 1 lần. Mỗi lần tia này va chạm với bề mặt sẽ truyền điện xuống mặt đất và phát ra xung chấn để Làm Choáng đối thủ.","zh-CN":"立即掷出一个能量箭，可反弹一次。每次击中表面时，能量箭都会造成【震荡】冲击，同时使其下方的地面通电。","zh-TW":"立刻射出一道可反彈一次的能量閃電。閃電觸物時會漏電至下方地面，造成震波「暈眩」敵人。"}'::jsonb, '"https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('bb2a4828-46eb-8cd1-e765-15848195d751'::uuid, 'Grenade', '{"es-MX":"Carril Rápido","ar-AE":"المسلك السريع","es-ES":"Vía rápida","ja-JP":"ファストレーン","it-IT":"Corsia di sorpasso","de-DE":"Überholspur","id-ID":"Fast Lane","ko-KR":"추월 차선","fr-FR":"Voie rapide","en-US":"Fast Lane","pl-PL":"Pas Wysokiego Napięcia","pt-BR":"Via Expressa","ru-RU":"Защитный туннель","th-TH":"Fast Lane","tr-TR":"HIZ ŞERİDİ","vi-VN":"Năng Lượng Cao Thế","zh-CN":"高速通道","zh-TW":"加速電牆"}'::jsonb, '{"es-MX":"DISPARA dos líneas de energía por el suelo hacia adelante que se extienden por una corta distancia o hasta golpear contra una superficie. Las líneas se convierten en muros de electricidad estática que bloquean la visión.","ar-AE":"أطلق خطي طاقة اثنين إلى الأمام على الأرض، حيث يتسع نطاقهما لمسافة قصيرة أو حتى يصيبان أحد السطوح. ينتصب الخطان على شكل جدارين من الكهرباء الساكنة التي تحجب الرؤية.","es-ES":"DISPARA dos líneas de energía hacia delante por el suelo. Se desplazan una corta distancia o hasta chocar contra algún obstáculo. Entonces, se alzan para convertirse en muros de energía estática que bloquean la visión.","ja-JP":"「発射」で、短い距離またはオブジェクトの表面に当たるまで延びる2本のエネルギーラインを前方に送り出す。各ラインから帯電した壁が立ち上り、視界を妨げる。","it-IT":"Usa il FUOCO per proiettare in avanti sul terreno due archi elettrici che si estendono per una breve distanza o finché non colpiscono una superficie. Gli archi elettrici diventano muri di elettricità statica che bloccano la visione.","de-DE":"FEUERE zwei Energieströme auf den Boden, die sich ein kurzes Stück nach vorn bewegen oder bis sie auf ein Hindernis treffen. Die Ströme erheben sich zu Wänden aus statischer Elektrizität, die die Sicht blockieren.","id-ID":"Tekan FIRE untuk menembakkan dua garis energi di atas tanah. Garis membentang dalam jarak yang pendek atau sampai mengenai permukaan saja. Garis ini berubah menjadi dinding listrik statis yang menghalangi pandangan musuh.","ko-KR":"전방의 지면에 에너지로 이루어진 선 두 개를 발사합니다. 선은 짧게 뻗어나가거나 표면에 적중하면 멈춥니다. 선은 솟아나 정전기 벽이 되어 시야를 차단합니다.","fr-FR":"TIREZ deux lignes d''énergie dans le sol devant vous. Après avoir parcouru une courte distance ou touché une surface, elles créent des murs d''électricité statique qui bloquent la vision.","en-US":"FIRE two energy lines forward on the ground that extend a short distance or until they hit a surface. The lines rise into walls of static electricity that block vision.","pl-PL":"WYSTRZEL w ziemię przed siebie dwie linie energii, które zatrzymają się po pokonaniu niewielkiej odległości lub trafieniu w powierzchnię. Linie stają się ścianami elektryczności statycznej, które ograniczają wizję.","pt-BR":"DISPARE duas linhas de energia no chão à frente. As linhas se estendem por uma curta distância ou até atingirem uma superfície. Elas se tornam paredes de eletricidade estática que bloqueiam a visão.","ru-RU":"Нажмите кнопку ОГОНЬ, чтобы запустить вперед по земле две параллельных линии подачи энергии. Линии простираются на небольшое расстояние или до ближайшей поверхности, после чего образуют два энергетических барьера, которые блокируют обзор.","th-TH":"กดยิงเพื่อปล่อยเส้นพลังงานสองเส้นไปตามพื้น ซึ่งจะยืดไปเป็นระยะทางสั้น ๆ หรือจนกว่ามันจะไปโดนพื้นผิวใด ๆ เส้นพลังงานดังกล่าวจะพุ่งขึ้นมาเป็นกำแพงไฟฟ้าสถิตที่บดบังการมองเห็น","tr-TR":"Önüne doğru, kısa bir mesafe veya bir yüzeye çarpana kadar ilerleyen iki enerji hattı çıkarmak için ATEŞ ET. Bu enerji hatları, görüş engelleyen statik elektrik duvarlarına dönüşür.","vi-VN":"BẮN ra 2 dòng năng lượng tiến về phía trước trên mặt đất, kéo dài thêm 1 khoảng ngắn hoặc dừng lại khi chạm vào 1 bề mặt. Dòng năng lượng này sẽ dựng thành các bức tường tĩnh điện làm chắn tầm nhìn.","zh-CN":"向前发射两条能量线，它们随后会变成两道阻挡视线的静电墙。能量线只能向前延伸一小段距离，且会被墙面阻挡。","zh-TW":"朝前方地面「發射」兩條能量標線，行進短距離或觸物後停止，標線會升起靜電牆，阻擋視野。"}'::jsonb, '"https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('bb2a4828-46eb-8cd1-e765-15848195d751'::uuid, 'Ultimate', '{"es-MX":"Potencia Máxima","ar-AE":"السرعة المفرطة","es-ES":"Sobrecarga","ja-JP":"オーバードライブ","it-IT":"Sovraccarico","de-DE":"Spannungsspitze","id-ID":"Overdrive","ko-KR":"오버드라이브","fr-FR":"Ultra-vitesse","en-US":"Overdrive","pl-PL":"Nadbieg","pt-BR":"Sobrecarga","ru-RU":"На полную мощь","th-TH":"Overdrive","tr-TR":"ENERJİ PATLAMASI","vi-VN":"Quá Tải","zh-CN":"超限暴走","zh-TW":"電能超載"}'::jsonb, '{"es-MX":"Desata todo el poder y la velocidad de Neon por un tiempo corto, lo que regenera todo su combustible y una carga de su deslizamiento. DISPARA para canalizar todo su poder en un rayo mortal con gran precisión de movimiento. Los asesinatos reinician la duración del efecto. ","ar-AE":"أطلق عنان كامل قوة وسرعة نيون لفترة قصيرة، لتستعيد كامل وقودها وشحنة انزلاق. اضغط على زر الإطلاق لتحويل القوة إلى شعاع برق فتاك يتمتع بدقة حركة عالية. تعيد عمليات القتل ضبط مدة التأثير. ","es-ES":"Neon desata todo su poder y velocidad durante un breve periodo de tiempo, lo que le otorga todo su combustible y una carga de deslizamiento lateral. DISPARA para canalizar su poder en forma de un mortífero rayo que permite apuntar con precisión al moverse. Los asesinatos reinician la duración del efecto. ","ja-JP":"ネオンが全パワーを解き放ち、スピードを短時間上昇させる。ネオンの燃料と加速のチャージもすべて回復する。「発射」で、移動中も高い射撃精度を持つ強力な電撃ビームを放つ。キルすると効果の持続時間がリセットされる。 ","it-IT":"Scatena al massimo la velocità e l''energia di Neon per un breve periodo, recuperando tutto il suo carburante per la corsa e una carica della scivolata. Usa il FUOCO per canalizzare l''energia in un letale raggio elettrico che rimane preciso anche in movimento. Le uccisioni ripristinano la durata dell''effetto. ","de-DE":"Entfessle für kurze Zeit Neons volle Macht und Geschwindigkeit, womit sie ihren gesamten Treibstoff und eine Rutschenaufladung zurückerhält. FEUERE, um diese Macht in einen tödlichen Laserstrahl mit hoher Bewegungsgenauigkeit zu kanalisieren. Kills setzen die Effektdauer zurück. ","id-ID":"Melepaskan tenaga dan kecepatan penuh Neon selama beberapa saat, mendapatkan lagi semua fuel dan charge luncurannya. Tekan FIRE untuk menyalurkan kekuatan itu ke cahaya kilat yang mematikan dengan akurasi gerakan tinggi. Kill mereset durasi efek. ","ko-KR":"짧은 시간 동안 네온의 모든 힘과 속도를 해방하고, 배터리 게이지가 완전히 충전되고 슬라이드 충전을 1개 얻습니다. 발사하면 힘을 집중해 이동 정확도가 높은 치명적인 번개 광선을 만들어냅니다. 적을 처치하면 지속시간이 초기화됩니다. ","fr-FR":"Libérez toute la puissance et la vitesse de Neon pendant un court instant, ce qui lui rend tout son carburant et une charge de glissade. TIREZ pour canaliser son pouvoir en un rayon électrique mortel dont la précision reste élevée même en mouvement. Les éliminations réinitialisent la durée de cet effet. ","en-US":"Unleash Neon’s full power and speed for a short duration, regaining all her fuel and a slide charge. FIRE to channel the power into a deadly lightning beam with high movement accuracy. Kills reset the duration of the effect. ","pl-PL":"Na krótką chwilę wyzwól pełną moc i prędkość Neon, zapewniając jej całe paliwo oraz ładunek ślizgu. STRZEL, by przekształcić moc w zabójczą wiązkę błyskawicy o wysokiej precyzji ruchu. Zabójstwa resetują czas trwania efektu. ","pt-BR":"Neon libera todo o seu poder e velocidade por um curto período, recuperando todo o combustível e uma carga de deslizamento. DISPARE para canalizar esse poder em um raio elétrico letal com alta precisão de movimento. Abates reiniciam a duração do efeito. ","ru-RU":"В течение короткого времени Neon использует всю свою энергию и скорость, восполняя запас топлива и получая заряд скольжения. Нажмите кнопку ОГОНЬ, чтобы преобразовать энергию в смертоносный электрический луч высокой точности. Убийства обновляют длительность эффекта. ","th-TH":"ปลดปล่อยพลังและความเร็วของ Neon ออกมาเต็มพิกัดเป็นระยะเวลาสั้น ๆ โดยจะเติมพลังงานสกิลจนเต็ม และมอบชาร์จสำหรับการสไลด์หนึ่งชาร์จ กดยิงเพื่อรวมพลังงานเป็นลำแสงสายฟ้าที่มีความแม่นยำสูง การคิลจะรีเซ็ตระยะเวลาของเอฟเฟกต์ ","tr-TR":"Neon''un tüm gücünü ve hızını kısa bir süreliğine etkinleştirerek tüm yakıtını yenile ve bir kayma yükü kazan. Gücünü, hareket ederken isabetliliği yüksek olan ölümcül bir ışın saldırısına dönüştürmek için ATEŞ ET. Skor almak bu etkinin süresini yeniler. ","vi-VN":"Giải phóng sức mạnh và tốc độ tối đa của Neon trong một thời gian ngắn, hồi đầy nhiên liệu và cho một lượt sử dụng luồng trượt điện. BẮN để tụ sức mạnh thành 1 tia sét chết người với độ chính xác khi di chuyển cao. Mạng hạ gục sẽ làm mới thời gian tác dụng của hiệu ứng. ","zh-CN":"短时间内释放霓虹的全部力量与速度，补满燃料并获得一次滑行充能。按【射击】即可引导她的力量，发射一道高速且精准的闪电光束。击败敌人可重置效果持续时间。 ","zh-TW":"短時間內解放妮虹的全力和全速，補滿燃料及回復一次滑行充能。點擊「攻擊」，即可轉化體內能量，射出移動射擊準確度高的致命電光。擊殺可重置效果持續時間。 "}'::jsonb, '"https://media.valorant-api.com/agents/bb2a4828-46eb-8cd1-e765-15848195d751/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('7f94d92c-4234-0a36-9646-3a87eb8b5c89'::uuid, '{"es-MX":"Yoru","ar-AE":"يورو","es-ES":"Yoru","ja-JP":"ヨル","it-IT":"Yoru","de-DE":"Yoru","id-ID":"Yoru","ko-KR":"요루","fr-FR":"Yoru","en-US":"Yoru","pl-PL":"Yoru","pt-BR":"Yoru","ru-RU":"Yoru","th-TH":"Yoru","tr-TR":"YORU","vi-VN":"Yoru","zh-CN":"夜露","zh-TW":"夜戮"}'::jsonb, '{"es-MX":"El nativo de Japón, Yoru, abre agujeros a través de la realidad para infiltrarse en las líneas enemigas sin ser visto. Con engaños y agresividad por igual, sorprende a sus objetivos antes de que sepan dónde buscarlo.","ar-AE":"يُحدث يورو المتحدر من اليابان ثقوبًا في نسيج عالم الواقع ذاته ليتسلل وراء خطوط العدو متخفيًا. ومع اعتماده على ذات القدر من المكر والهجوم، يستطيع النيل من كل هدف قبل أن يدرك ما حلّ به.","es-ES":"Yoru, nacido en Japón, abre agujeros en el tejido de la realidad para infiltrarse tras las líneas enemigas sin ser visto. Utiliza el engaño y la agresividad por igual para acabar con sus objetivos antes de que sepan qué ha pasado.","ja-JP":"日本出身のヨルは、次元の狭間を渡る能力で敵陣の真っ只中に潜入できる。策略と攻撃性を合わせ持つ彼に狙われた標的は、その姿を認識する前に最期の瞬間を迎えることになる。","it-IT":"Yoru arriva dal Giappone per aprire squarci nella realtà e infiltrarsi furtivamente dietro le linee nemiche. Usando un mix di aggressività e sotterfugi, riesce ad avere la meglio su qualsiasi bersaglio prima ancora che si accorga della sua presenza.","de-DE":"Der Japaner Yoru reißt Löcher in die Realität, um unbeobachtet hinter die feindlichen Linien zu gelangen. Er setzt gleichermaßen auf Irreführung und Aggression und ist seinen Gegnern bereits einen Schritt voraus, bevor sie wissen, wie ihnen geschieht.","id-ID":"Agen asal Jepang, Yoru, melubangi realitas untuk menyusup ke wilayah musuh tanpa terlihat. Dengan bermodal tipuan dan agresi yang seimbang, dia menghabisi tiap target sebelum mereka sadar ke mana harus melihat.","ko-KR":"일본 출신의 요루는 현실에 구멍을 내어 적 진영으로 은밀히 침투합니다. 그는 공격성과 속임수를 활용해 적이 알아채기도 전에 임무를 완수합니다.","fr-FR":"Le Japonais Yoru perce des trous dans la réalité pour s''infiltrer derrière les lignes ennemies sans se faire repérer. En faisant preuve d''autant de ruse que d''agressivité, il prend ses cibles par surprise avant qu''elles n''aient le temps de se retourner.","en-US":"Japanese native Yoru rips holes straight through reality to infiltrate enemy lines unseen. Using deception and aggression in equal measure, he gets the drop on each target before they know where to look.","pl-PL":"Rodowity Japończyk Yoru wyrywa dziury w rzeczywistości, by niepostrzeżenie infiltrować linie wroga. Wykorzystując w równym stopniu podstęp i agresję, z zaskoczenia atakuje każdy kompletnie nieświadomy zagrożenia cel.","pt-BR":"Yoru, nativo do Japão, abre fendas na realidade para infiltrar as linhas inimigas sem ser visto. Ele usa tanto artimanhas quanto táticas agressivas, e os alvos são abatidos sem saber de onde o ataque veio.","ru-RU":"Уроженец Японии Yoru способен создавать разрывы в самой реальности, чтобы незаметно пробираться на вражескую территорию. Сила и хитрость позволяют ему заставать врагов врасплох – они даже не успеют понять, откуда пришла смерть.","th-TH":"Yoru หนุ่มญี่ปุ่นผู้สามารถแหวกมิติเพื่อเคลื่อนย้ายและแฝงตัวไปในกองทัพศัตรูได้อย่างแนบเนียน ด้วยเล่ห์เหลี่ยมและความดุดันที่มีมากพอกัน เขาสามารถกำจัดเป้าหมายได้ก่อนที่พวกมันจะทันตั้งตัวเสียอีก","tr-TR":"Japon Yoru, gerçeklikte açtığı geçitlerden geçerek düşman hattına sinsice sızıyor. Yanılsamalardan ve kaba kuvvetten eşit oranda faydalanarak hedeflerini göz açıp kapayıncaya kadar indiriyor.","vi-VN":"Đến từ Nhật Bản, Yoru có khả năng xé toang thực tại để xâm nhập vào hàng ngũ của địch mà không bị phát hiện. Với kỹ năng vừa đánh lừa vừa tấn công kẻ địch, con mồi của Yoru sẽ chẳng bao giờ biết được mình bị ai hạ gục.","zh-CN":"来自东亚的“夜露”能够直接撕裂现实空间，无声无息地渗透敌人的防线。他在战斗中喜欢虚实结合，在敌人尚未猜到他的位置时发动突然袭击。","zh-TW":"日本人夜戮可以撕裂現實世界的空間，潛入敵軍陣線而不被察覺。他同時運用欺敵和進攻策略先發制人，讓目標措手不及。"}'::jsonb, 'Stealth', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/displayicon.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/displayicon.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/fullportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/fullportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/fullportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/killfeedportrait.png', 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/minimapportrait.png', null, 'https://media.valorant-api.com/agents/7f94d92c-4234-0a36-9646-3a87eb8b5c89/background.png', array['222b67ff', '0f1923ff', '261e4fff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, '{"es-MX":"Waylay","ar-AE":"وايلاي","es-ES":"Waylay","ja-JP":"ウェイレイ","it-IT":"Waylay","de-DE":"Waylay","id-ID":"Waylay","ko-KR":"웨이레이","fr-FR":"Waylay","en-US":"Waylay","pl-PL":"Waylay","pt-BR":"Waylay","ru-RU":"Waylay","th-TH":"Waylay","tr-TR":"WAYLAY","vi-VN":"Waylay","zh-CN":"幻棱","zh-TW":"維蕾"}'::jsonb, '{"es-MX":"La radiante prismática Waylay de Tailandia se transforma en luz mientras se lanza a toda velocidad por el campo de batalla, abatiendo a sus objetivos con fragmentos de luz antes de volver a ponerse a salvo, todo en un abrir y cerrar de ojos.","ar-AE":"تتحول وايلاي التايلاندية المشعة الموشورية إلى ضوء حقيقي مع انطلاقها كالسهم عبر ساحة المعركة لتضرب أهدافها عبر شظايا الضوء قبل أن تعود إلى بر الأمان، وكل ذلك بلمح البصر.","es-ES":"La tailandesa Waylay es una prismática radiante capaz de transformarse en luz para desplazarse por el campo de batalla y eliminar a sus objetivos con fragmentos lumínicos antes de regresar a un lugar seguro en menos de lo que canta un gallo.","ja-JP":"プリズムの力を使いこなすタイ出身のウェイレイは、光そのものへと姿を変えて戦場を駆け抜け、光の欠片を貫き標的を倒す。そして一瞬のうちに安全な場所へと舞い戻るのだ。","it-IT":"Originaria della Thailandia, la radiante prismatica Waylay si trasforma in luce mentre sfreccia per il campo di battaglia, abbattendo i suoi bersagli con frammenti luminosi prima di tornare al sicuro in un batter d''occhio.","de-DE":"Die prismatisch strahlende Waylay aus Thailand verwandelt sich in Licht, wenn sie über das Schlachtfeld flitzt und ihre Ziele mit Lichtsplittern niederschlägt, bevor sie sich blitzschnell in Sicherheit bringt.","id-ID":"Waylay, agen Thailand yang berpijar prismatik, berubah menjadi cahaya saat ia melesat melintasi medan tempur. Ia menyerang targetnya melalui secercah cahaya dan langsung mengamankan diri dalam sekejap mata.","ko-KR":"프리즘처럼 빛나는 태국 출신 웨이레이는 빛으로 변신해 전장을 누비며 빛의 파편으로 적을 공격한 후 눈 깜짝할 사이에 다시 안전한 곳으로 돌아갑니다.","fr-FR":"Waylay, la prismatique radiante de Thaïlande, se transforme en particules de lumière pour filer sur le champ de bataille. Elle frappe ses cibles à l''aide d''éclats de lumière avant de se remettre à l''abri, le tout en un clin d''œil.","en-US":"Thailand''s prismatic radiant Waylay transforms into light itself as she darts across the battlefield, striking down her targets through shards of light before flitting back to safety, all in the blink of an eye.","pl-PL":"Pryzmatyczna promienista Waylay z Tajlandii przeistacza się w czyste światło i mknie przez pole bitwy, rażąc swoje cele odłamkami światła, a po wszystkim przemyka z powrotem w bezpieczne miejsce – wszystko to w mgnieniu oka.","pt-BR":"Waylay, a Radiante prismática da Tailândia, se transforma em pura luz e atravessa o campo de batalha abatendo os alvos com estilhaços luminosos antes de recuar. Tudo em um piscar de olhos.","ru-RU":"Сияющая Waylay из Таиланда превращается в сам свет, молниеносно перемещаясь по полю боя. Она поражает цели осколками света, а затем стремительно возвращается в безопасное место – и все это в мгновение ока.","th-TH":"Waylay ผู้เปล่งแสงสีรุ้งจากประเทศไทยจะกลายร่างเป็นแสงสว่างขณะพุ่งตัวไปทั่วสนามรบ และโจมตีเป้าหมายด้วยเศษเสี้ยวแห่งแสงก่อนจะกลับไปยังพื้นที่ปลอดภัยในชั่วพริบตา","tr-TR":"Taylandlı prizmatik radyant Waylay, bizzat ışığın kendisine dönüşüp savaş alanının bir ucundan diğer ucuna fırlar. Hedeflerini göz açıp kapayıncaya kadar ışık parçalarıyla alt eden Waylay daha onlar ne olduğunu anlamadan güvenli bir noktaya dönmüştür bile.","vi-VN":"Waylay - radiant với sức mạnh lăng kính tới từ Thái Lan - có khả năng biến thành ánh sáng để lao quanh chiến trường, tấn công mục tiêu bằng những mảnh vỡ ánh sáng trước khi bay trở lại nơi an toàn chỉ trong chớp mắt.","zh-CN":"来自暹罗湾北岸的“幻棱”是一名拥有棱晶能力的源能者，可以将自己变幻成光，在战场上穿梭自如，通过棱光碎片将敌人击倒后迅速撤退到安全区。眨眼之间，胜负已分。","zh-TW":"泰國的多彩光輝維蕾化身為光本身，在戰場上穿梭，透過光芒碎片擊倒目標後又迅速閃回安全之處，一切都發生在眨眼之間。"}'::jsonb, 'Terra', '2025-03-04T22:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/displayicon.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/displayicon.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/fullportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/fullportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/fullportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/killfeedportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/minimapportrait.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/homescreenpromotileimage.png', 'https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/background.png', array['482e61ff', '0f1923ff', '0f1923ff', '482e61ff'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, 'Ability2', '{"es-MX":"Refracción","ar-AE":"انكسار الضوء","es-ES":"Refracción","ja-JP":"リフラクト","it-IT":"Rifrazione","de-DE":"Refraktion","id-ID":"Refract","ko-KR":"굴절","fr-FR":"Réfraction","en-US":"Refract","pl-PL":"Refrakcja","pt-BR":"Refração","ru-RU":"Рефракция","th-TH":"Refract","tr-TR":"KIRILMA","vi-VN":"Khúc Xạ","zh-CN":"溯流回光","zh-TW":"折射"}'::jsonb, '{"es-MX":"Crea una baliza de luz en el suelo AL INSTANTE. REACTÍVALA para volver rápidamente a la baliza como una partícula de luz pura. Eres invulnerable mientras te transportas. Refracción se restablece cada dos asesinatos.","ar-AE":"أنشئ مصدر ضوء على الأرض فوريًا. أعد التفعيل للعودة بسرعة إلى مصدر الضوء على هيئة جزيء من الضوء النقي. تكون منيعًا أثناء انتقالك. تعيد قدرة انكسار الضوء شحنةً واحدةً بعد كل عمليتي قتل.","es-ES":"Coloca una baliza de luz INSTANTÁNEAMENTE en el suelo. REACTIVA la habilidad para volver rápidamente a la baliza en forma de partícula de luz. Eres invulnerable durante el desplazamiento. Refracción reinicia una carga cada dos asesinatos.","ja-JP":"床に光のビーコンを設置する。再発動すると純粋な光の粒子となり、ビーコンへ瞬時に移動する。移動中は無敵状態になる。「リフラクト」のチャージは敵を2回キルするたびにリセットされる。","it-IT":"Crea ALL''ISTANTE un segnalatore luminoso sul terreno. RIATTIVA per tornare velocemente al segnalatore sotto forma di particella di luce pura. Durante il viaggio, Waylay è invulnerabile. Recuperi una carica di Rifrazione ogni due uccisioni.","de-DE":"Erschaffe SOFORT ein Leuchtfeuer auf dem Boden. REAKTIVIERE, um als Partikel reinen Lichts zu deinem Leuchtfeuer zurückzukehren. Auf deiner Reise bist du unverwundbar. „Refraktion“ lädt eine Aufladung alle zwei Kills auf.","id-ID":"SEKETIKA menciptakan suar cahaya di lantai. AKTIFKAN ULANG untuk kembali ke suarmu sebagai setitik cahaya murni. Kamu kebal saat bergerak. Refract mereset charge tiap dua kill.","ko-KR":"즉시 바닥에 빛의 신호기를 생성합니다. 다시 활성화하면 순수한 빛의 입자가 되어 신호기로 돌아갑니다. 이동 중에는 무적 상태가 됩니다. 굴절 충전량은 2킬마다 하나 초기화됩니다.","fr-FR":"Produisez INSTANTANÉMENT une balise lumineuse au sol. RÉACTIVEZ pour revenir rapidement à votre balise sous forme d''une particule de lumière pure. Vous êtes invulnérable pendant ce déplacement. Vous regagnez une charge de Réfraction toutes les deux éliminations.","en-US":"INSTANTLY create a beacon of light on the floor. REACTIVATE to speed back to your beacon as a mote of pure light. You are invulnerable as you travel. Refract resets a charge every two kills.","pl-PL":"NATYCHMIAST tworzy promień światła na podłożu. AKTYWUJ PONOWNIE, aby wrócić do promienia jako drobina czystego światła. Podczas podróży nie można cię zranić. Refrakcja odświeża się co dwa zabójstwa.","pt-BR":"Cria INSTANTANEAMENTE um feixe de luz no chão. REATIVE para voltar rapidamente ao feixe como uma partícula de luz pura. Você fica invulnerável durante o deslocamento. Uma carga de Refração é restaurada a cada dois abates.","ru-RU":"Мгновенно создает на полу световой маячок. Нажмите кнопку умения повторно, чтобы перенестись к маячку в виде частицы света. Во время перемещения вы неуязвимы. Заряд \"Рефракции\" восстанавливается после каждых двух убийств.","th-TH":"สร้างแสงนำทางบนพื้นทันที เปิดใช้งานอีกครั้งเพื่อเปลี่ยนตัวเองเป็นอนุภาคแสงและเคลื่อนที่อย่างรวดเร็วกลับไปยังแสงนำทาง คุณจะไม่ได้รับความเสียหายใด ๆ ขณะเคลื่อนที่ Refract จะรีเซ็ตชาร์จทุก ๆ สองคิล","tr-TR":"ANINDA yere bir ışık huzmesi yerleştir. Saf ışığa dönüşüp hızlı bir şekilde ışık huzmesinin konumuna dönmek için TEKRAR ETKİNLEŞTİR. Saf ışığa dönüştüğünde hasar görmez olursun. Kırılma''nın yükü her iki skorda bir dolar.","vi-VN":"NGAY LẬP TỨC tạo ra một ngọn hải đăng trên mặt đất. TÁI KÍCH HOẠT để tốc biến về ngọn hải đăng dưới dạng hạt ánh sáng tinh khiết. Bạn trở nên bất khả xâm phạm khi dịch chuyển. Khúc Xạ được làm mới một lượt dùng sau mỗi 2 mạng hạ gục.","zh-CN":"立即在地面上形成一道光束。【再次激活】技能即可让自己化为一颗纯粹的光粒，迅速回到光束的所在位置。穿行时你不会受到伤害。【溯流回光】每击败两名敌人重置一次充能。","zh-TW":"立即在地面上生成一道光束。重施技能可化為光點，快速回到光束位置。移動期間會進入無敵狀態。每擊殺兩名敵人，折射即可重置1次充能。"}'::jsonb, '"https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, 'Grenade', '{"es-MX":"Saturación","ar-AE":"الإشباع البصري","es-ES":"Saturación","ja-JP":"サチュレート","it-IT":"Saturazione","de-DE":"Sättigung","id-ID":"Saturate","ko-KR":"포화","fr-FR":"Saturation","en-US":"Saturate","pl-PL":"Nasycenie","pt-BR":"Saturação","ru-RU":"Световое загрязнение","th-TH":"Saturate","tr-TR":"TUTULMA","vi-VN":"Bão Hòa","zh-CN":"光棱闪爆","zh-TW":"浸染"}'::jsonb, '{"es-MX":"EQUIPA un cúmulo de luz. DISPARA para lanzar el cúmulo, que al entrar en contacto con el suelo explota y Obstaculiza a los jugadores cercanos con una potente ralentización de movimientos y armas.","ar-AE":"تجهّز بعنقود ضوئي أطلق لرمي العنقود، والذي ينفجر عند ملامسة الأرض، مما يعيق اللاعبين القريبين بإبطاء قوي للحركة والسلاح.","es-ES":"EQUIPA un cúmulo de luz. DISPARA para lanzar el cúmulo de luz, que explota al entrar en contacto con el suelo, lo que entorpece a los jugadores cercanos con una poderosa ralentización de movimiento y de arma.","ja-JP":"光の塊を構える。「発射」で光の塊を投げる。光の塊は地面に接触すると爆発して、付近のプレイヤーの移動速度と武器操作速度を大きく下げて妨害する。","it-IT":"EQUIPAGGIA un ammasso di luce. Usa il FUOCO per lanciare l''ammasso che esplode a contatto con il suolo, INTRALCIANDO i giocatori vicini con un potente rallentamento ai movimenti e alle armi.","de-DE":"RÜSTE eine Lichtgranate AUS. FEUERE, um die Granate zu werfen. Sie explodiert beim Aufprall auf dem Boden und hindert Spieler in der Nähe mit einer erheblichen Bewegungs- und Waffenverlangsamung.","id-ID":"EQUIP sekumpulan cahaya. Tekan FIRE untuk melemparkan sekumpulan cahaya yang akan meledak saat menyentuh tanah. Cahaya itu akan memberikan efek Hinder pada pemain di sekitar, memperlambat gerakan dan senjata mereka secara drastis.","ko-KR":"빛의 덩어리를 장착합니다. 발사하면 빛의 덩어리를 던집니다. 빛의 덩어리는 지면에 닿으면 폭발하여 이동 속도와 무기를 둔화하는 강력한 효과로 주변 플레이어를 방해합니다.","fr-FR":"ÉQUIPEZ une masse de lumière. TIREZ pour lancer la masse, qui explose au contact du sol, entravant les joueurs à proximité avec un puissant ralentissement des déplacements et des armes.","en-US":"EQUIP a cluster of light. FIRE to throw the cluster, which upon contact with the ground explodes, Hindering nearby players with a powerful movement and weapon slow.","pl-PL":"WYPOSAŻ skupisko światła. STRZEL, by rzuć skupisko, które eksploduje po kontakcie z ziemią i ogranicza pobliskich graczy potężnym spowolnieniem ruchu i broni.","pt-BR":"EQUIPE um aglomerado de luz. DISPARE para lançar o aglomerado, que explode ao tocar no chão e Retém jogadores próximos com uma poderosa desaceleração de movimento e de armas.","ru-RU":"Выбирает сгусток света. Нажмите ОГОНЬ, чтобы бросить сгусток, который взрывается при контакте с землей и сдерживает ближайших игроков, заметно снижая их скорость использования оружия и передвижения.","th-TH":"ติดตั้งก้อนแสง กดยิงเพื่อขว้างก้อนแสง ซึ่งจะระเบิดเมื่อสัมผัสกับพื้น ขัดขวางการเคลื่อนที่และอาวุธของผู้เล่นในบริเวณใกล้เคียงให้ช้าลงอย่างมาก","tr-TR":"Bir ışık kümesi KUŞAN. Kümeyi fırlatmak için ATEŞ ET. Işık kümesi yere temas ettiği anda patlar ve yakındaki oyunculara Ağırlaştırma uygulayarak onları güçlü bir hareket ve silah yavaşlatmasına maruz bırakır.","vi-VN":"TRANG BỊ một chùm sáng. BẮN để phóng chùm sáng, phát nổ khi tiếp xúc với mặt đất, Cản Trở những người chơi xung quanh với hiệu ứng siêu làm chậm chuyển động và vũ khí của họ.","zh-CN":"装备一道光簇。按下【射击】投掷光簇，与地面接触时爆炸，【干扰】附近的玩家，使其受到大幅的移动和武器减速。","zh-TW":"裝備一枚聚合光彈。點擊「攻擊」即可拋出，光彈在接觸地面後爆炸，阻礙附近的玩家，大幅減緩其移動速度與武器射速。"}'::jsonb, '"https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, 'Ability1', '{"es-MX":"Velocidad de la Luz","ar-AE":"سرعة الضوء","es-ES":"Velocidad de la luz","ja-JP":"ライトスピード","it-IT":"Velocità della luce","de-DE":"Licht-\r\ngeschwindigkeit","id-ID":"Lightspeed","ko-KR":"광속","fr-FR":"Vitesse lumière","en-US":"Lightspeed","pl-PL":"Prędkość Światła","pt-BR":"Velocidade da Luz","ru-RU":"Скорость света","th-TH":"Lightspeed","tr-TR":"IŞIK HIZI","vi-VN":"Tốc Độ Ánh Sáng","zh-CN":"光速飞跃","zh-TW":"光速"}'::jsonb, '{"es-MX":"EQUIPA para prepararte para un impulso de velocidad. DISPARA para desplazarte hacia adelante dos veces. Usa el DISPARO SECUNDARIO para desplazarte una vez. Solo el primer desplazamiento puede moverte hacia arriba.","ar-AE":"تجهّز بالقدرة للاستعداد للاندفاع السريع. أطلق للاندفاع إلى الأمام مرتين. استخدم الإطلاق البديل للاندفاع مرة واحدة. وحدها اندفاعتك الأولى تستطيع رفعك إلى الأعلى.","es-ES":"EQUIPA para preparar una explosión de velocidad. DISPARA para deslizarte dos veces hacia delante. Utiliza el DISPARO ALTERNATIVO para deslizarte solo una vez. Solo puedes ascender con el primer deslizamiento.","ja-JP":"構えを取り、高速移動の準備をする。「発射」で前方に2回ダッシュする。「オルト射撃」で1回ダッシュする。1回目のダッシュのみ上昇することができる。","it-IT":"EQUIPAGGIA per prepararti a un aumento di velocità. Usa il FUOCO per scattare due volte in avanti. Usa il FUOCO ALTERNATIVO per scattare una volta. Solo il primo scatto può scagliarti verso l''alto.","de-DE":"AUSRÜSTEN, um dich auf einen Geschwindigkeitsschub vorzubereiten. FEUERE, um zweimal vorwärts zu sprinten. Mit ALT. FEUERMODUS sprintest du nur einmal. Nur dein erster Sprint kann dich nach oben bringen.","id-ID":"EQUIP untuk bergerak secepat kilat. Tekan FIRE untuk dash ke depan dua kali. Tekan ALT FIRE untuk dash sekali. Hanya dash pertama yang bisa membawamu ke atas.","ko-KR":"장착하면 속도를 올릴 준비를 합니다. 발사하면 앞으로 두 번 돌진합니다. 보조 공격 시 한 번 돌진합니다. 첫 돌진으로만 공중으로 뜰 수 있습니다.","fr-FR":"ÉQUIPEZ-vous pour préparer un pic de vitesse. Utilisez le TIR PRINCIPAL pour vous ruer en avant deux fois. Utilisez le TIR SECONDAIRE pour vous ruer une seule fois. Seule la première ruée peut vous faire monter en l''air.","en-US":"EQUIP to prepare for a burst of speed. FIRE to dash forward twice. ALT FIRE to dash once. Only your first dash can send you upward.","pl-PL":"WYPOSAŻ, aby przygotować się na przypływ szybkości. STRZEL, aby wykonać podwójny doskok w przód. ALT. STRZAŁ, aby wykonać pojedynczy doskok. Tylko pierwszy doskok może wyrzucić cię w górę.","pt-BR":"EQUIPE para se preparar para um impulso de velocidade. DISPARE para avançar duas vezes. Use o DISPARO ALTERNATIVO para avançar uma vez. Só o primeiro avanço faz você subir.","ru-RU":"Нажмите кнопку умения, чтобы приготовиться к ускорению. Нажмите кнопку ОГОНЬ, чтобы дважды совершить рывок вперед. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы сделать один рывок. Переместиться вверх можно только во время первого рывка.","th-TH":"ติดตั้งเพื่อเตรียมตัวให้พร้อมสำหรับความเร็วฉับพลัน กดยิงเพื่อพุ่งตัวไปข้างหน้าสองครั้ง กดโหมดยิงเสริมเพื่อพุ่งตัวหนึ่งครั้ง เฉพาะการพุ่งตัวครั้งแรกเท่านั้นที่จะส่งตัวคุณขึ้นไปข้างบน","tr-TR":"Hızla atılmaya hazırlanmak için KUŞAN. İki kere ileri atılmak için ATEŞ ET. Bir kere ileri atılmak için ALT. ATIŞ kullan. İlk atılmada yukarı yönlü hareket edebilirsin.","vi-VN":"TRANG BỊ để chuẩn bị tăng tốc. BẮN để lướt về phía trước 2 lần. BẮN PHỤ để lướt 1 lần. Chỉ lần lướt đầu tiên có thể đưa bạn lên cao.","zh-CN":"准备进行加速。按【射击】向前冲刺两次。按【辅助射击】向前冲刺一次。只有第一段冲刺能让你升空。","zh-TW":"裝備以準備加速。點擊「攻擊」向前衝刺兩次，點擊「輔助攻擊」衝刺一次。只有第一次衝刺時會向上躍起。"}'::jsonb, '"https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, 'Ultimate', '{"es-MX":"Ilusión Convergente","ar-AE":"تلاقي الدروب","es-ES":"Trayectorias convergentes","ja-JP":"コンバージェントパス","it-IT":"Percorsi convergenti","de-DE":"Konvergierende Pfade","id-ID":"Convergent Paths","ko-KR":"초점 교차","fr-FR":"Croisée des chemins","en-US":"Convergent Paths","pl-PL":"Zbieżne Ścieżki","pt-BR":"Caminhos Convergentes","ru-RU":"Схождение","th-TH":"Convergent Paths","tr-TR":"YAKINSAYAN IŞINLAR","vi-VN":"Đích Đến Cuối Cùng","zh-CN":"时光修罗场","zh-TW":"聚合之道"}'::jsonb, '{"es-MX":"EQUIPA para concentrar tu poder prismático. DISPARA para crear un espejismo tuyo que proyecta un haz de luz. Tras una pequeña demora, obtienes un potente aumento de velocidad y el haz se expande, obstaculizando a los demás jugadores de la zona.","ar-AE":"تجهّز لاستجماع قوّتك الموشورية. أطلق لإنشاء صورة طيفية عنك تلقي شعاعًا من الضوء. بعد فترة قصيرة، تكسبُ معزز سرعة قوي التأثير ويتوسع الشعاع، مما يؤدي إلى عرقلة اللاعبين الآخرين في المنطقة.","es-ES":"EQUIPA para concentrar tu poder prismático. DISPARA para crear un reflejo de ti misma que proyecta un rayo de luz. Tras un breve retardo, obtienes un poderoso aumento de velocidad y el rayo se expande, entorpeciendo al resto de jugadores en la zona.","ja-JP":"構えを取り、プリズムのパワーを集める。「発射」で自分の残像を作り出す。残像は光線を放つ。少し経つと自分の移動速度が大きく上昇して光線が拡大し、その範囲内のプレイヤーに行動妨害の効果を与える。","it-IT":"EQUIPAGGIA per concentrare il tuo potere prismatico. Usa il FUOCO per creare un''immagine residua di Waylay che proietta un fascio di luce. Dopo qualche istante, ottieni un forte aumento di velocità e il fascio di luce si espande, INTRALCIANDO gli altri giocatori nell''area.","de-DE":"AUSRÜSTEN, um deine prismatische Macht zu fokussieren. FEUERE, um ein Nachbild von dir zu erschaffen, das Lichtstrahlen aussendet. Nach einer kurzen Verzögerung erhältst du einen effektiven Geschwindigkeitsschub und der Strahl vergrößert sich, wodurch Spieler im Bereich gehemmt werden.","id-ID":"EQUIP untuk memfokuskan kekuatan prismatikmu. Tekan FIRE untuk menciptakan bayangan dirimu sendiri yang kemudian memancarkan cahaya. Setelah beberapa saat, kecepatanmu meningkat tajam dan cahaya meluas, menyebabkan pemain lain di area itu terkena Hinder.","ko-KR":"장착하면 프리즘의 힘을 집중합니다. 발사하면 빛줄기를 비추는 자신의 잔상을 만듭니다. 잠시 후 강력한 속도 상승 효과를 얻고 광선이 넓어져 해당 지역의 다른 플레이어를 방해합니다.","fr-FR":"ÉQUIPEZ pour concentrer votre pouvoir prismatique. TIREZ pour créer une image rémanente de vous-même qui projette un rayon de lumière. Après un court délai, vous gagnez une accélération puissante et le rayon s''élargit, ce qui entrave les autres joueurs dans la zone.","en-US":"EQUIP to focus your prismatic power. FIRE to create an afterimage of yourself that projects a beam of light. After a brief delay, you gain a powerful speed boost and the beam expands, Hindering other players in the area.","pl-PL":"WYPOSAŻ, aby skoncentrować moc pryzmatyczną. WYSTRZEL, aby stworzyć swoją poświatę, wystrzeliwującą promień światła. Po krótkim opóźnieniu zyskasz potężną premię szybkości, a promień się rozszerzy, ograniczając innych graczy w pobliżu.","pt-BR":"EQUIPE para focar seu poder prismático. DISPARE para criar uma imagem residual de si mesma que projeta um feixe de luz. Após um breve intervalo, você recebe um poderoso impulso de velocidade, e o feixe se expande e Retém outros jogadores na área.","ru-RU":"Нажмите кнопку умения, чтобы сфокусировать призматическую энергию. Нажмите кнопку ОГОНЬ, чтобы создать свою проекцию, которая излучает световой пучок. После небольшой задержки вы получаете мощный прирост скорости, а пучок расширяется, сдерживая других игроков в области поражения.","th-TH":"ติดตั้งเพื่อโฟกัสพลังงานปริซึม กดยิงเพื่อสร้างร่างเหมือนของตัวเองที่จะปล่อยลำแสงออกมา หลังเว้นช่วงไปเล็กน้อย คุณจะเคลื่อนที่เร็วขึ้นอย่างมากและลำแสงจะขยายใหญ่ขึ้น ขัดขวางผู้เล่นคนอื่น ๆ ในพื้นที่ให้เชื่องช้าลง","tr-TR":"Prizmatik gücünü odaklamak için KUŞAN. Işın demeti saçan bir kopyanı oluşturmak için ATEŞ ET. Kısa bir gecikmenin ardından büyük oranda hızlanırsın ve ışın demeti genişleyerek bölgedeki diğer oyunculara Ağırlaştırma uygular.","vi-VN":"TRANG BỊ để tập trung sức mạnh lăng kính của bạn. BẮN để tạo ra một hình ảnh phản chiếu của chính bạn, chiếu ra một luồng sáng. Sau một thời gian chờ ngắn, bạn được tăng mạnh tốc độ di chuyển và chùm tia sẽ lan rộng ra, Cản Trở những người chơi khác trong khu vực.","zh-CN":"装备并汇聚光棱能量。按【射击】创造一个自己的残像，放射一道光线。短暂延迟后你将获得大幅加速效果，同时光线开始扩张，干扰区域内的其他玩家。","zh-TW":"點擊「裝備」開始凝聚稜彩之力，點擊「攻擊」即可生成一個會發射光束的自身幻象。短暫延遲後，自身獲得強力速度加成，且光束範圍會隨之擴展，對範圍內的其他玩家造成阻礙效果。"}'::jsonb, '"https://media.valorant-api.com/agents/df1cb487-4902-002e-5c17-d28e83e78588/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_recruitments (agent, xp, start_time, end_time) values ('df1cb487-4902-002e-5c17-d28e83e78588'::uuid, 200000, '2025-03-05T22:00:00Z'::timestamp with time zone, '2025-04-02T21:00:00Z'::timestamp with time zone) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('569fdd95-4d10-43ab-ca70-79becc718b46'::uuid, '{"es-MX":"Sage","ar-AE":"سايج","es-ES":"Sage","ja-JP":"セージ","it-IT":"Sage","de-DE":"Sage","id-ID":"Sage","ko-KR":"세이지","fr-FR":"Sage","en-US":"Sage","pl-PL":"Sage","pt-BR":"Sage","ru-RU":"Sage","th-TH":"Sage","tr-TR":"SAGE","vi-VN":"Sage","zh-CN":"贤者","zh-TW":"聖祈"}'::jsonb, '{"es-MX":"Sage, el bastión de China, proporciona seguridad para sí misma y para su equipo en cualquier lugar. Gracias a su capacidad de revivir a sus compañeros caídos y evitar ataques poderosos, proporciona un lugar de protección en medio del caótico campo de batalla.","ar-AE":"توفر سايج، الحامية الصينية القوية، الأمان لنفسها ولأعضاء فريقها حيثما حلت. قدرتها على إنعاش الأصدقاء المسقطين وصد الهجمات العنيفة تجعل منها واحة من الأمان في قلب ميدان القتال المشتعل.","es-ES":"Originaria de China, Sage destaca a la hora de crear espacios seguros para su equipo allá donde va. Sus capacidades especiales para revivir a compañeros caídos en batalla y para mantener a raya los asaltos enemigos la convierten en la calma en mitad de la tormenta para su equipo.","ja-JP":"中国の守り手であるセージは、どこにいる時も仲間のために安全地帯を作り出すことができる。激しい攻撃を防ぎ、力尽きた戦友たちを蘇生する彼女は、過酷な戦場に一時の安らぎをもたらす存在なのだ。","it-IT":"Vero bastione della Cina, Sage genera sicurezza per se stessa e per i suoi alleati ovunque vada. È in grado di rianimare i compagni caduti e può prevenire gli assalti diretti, riuscendo così a fornire un porto sicuro anche sul campo di battaglia più infernale.","de-DE":"Die chinesische Wächterin Sage garantiert Sicherheit für sich und ihr Team, wohin auch immer sie geht. Dank ihrer einzigartigen Fähigkeit, gefallene Verbündete wiederzuerwecken und Angriffe abzuwehren, ist sie auf dem Schlachtfeld das Auge des Sturms.","id-ID":"Layaknya benteng pertahanan dari Cina, Sage memberikan rasa aman bagi dirinya dan timnya di mana pun dia berada. Bisa membangkitkan sekutu yang gugur dan menahan serangan sengit, dia menjadi sumber ketenangan di tengah kacaunya battlefield.","ko-KR":"중국에서 온 세이지는 어디에서든 자신과 아군이 안전할 수 있도록 능력을 발휘합니다. 쓰러진 아군을 부활시키거나 강력한 공격을 피할 수 있는 능력으로 지옥 같은 전장에서 고요한 중심이 되어 줍니다.","fr-FR":"Véritable pilier originaire de Chine, Sage assure sa sécurité et celle de son équipe où qu''elle aille. Elle peut réanimer ses alliés tombés au combat et repousser les assauts ennemis pour offrir des oasis de tranquillité sur un champ de bataille infernal.","en-US":"The bastion of China, Sage creates safety for herself and her team wherever she goes. Able to revive fallen friends and stave off forceful assaults, she provides a calm center to a hellish battlefield.","pl-PL":"Sage to istna chińska twierdza, która sprawia, że zarówno ona, jak i jej drużyna mogą czuć się bezpiecznie w każdym miejscu. Potrafi wskrzeszać poległych towarzyszy i odpierać potężne ataki, co czyni z niej ostoję spokoju na piekielnym polu walki.","pt-BR":"Como uma verdadeira fortaleza chinesa, Sage traz segurança para si mesma e para a equipe aonde quer que vá. Capaz de reviver aliados e rechaçar investidas agressivas, ela oferece um centro de calmaria em meio ao caos da batalha.","ru-RU":"Защитница Китая Sage обеспечивает безопасность команды в бою. Благодаря возможности воскрешать союзников и сдерживать натиск врага она создает оазис покоя на жутком поле боя.","th-TH":"Sage เปรียบเสมือนป้อมปราการของจีน เธอมอบความปลอดภัยแก่ตัวเองและเพื่อนร่วมทีมในทุกที่ที่เธอไปโดยอาศัยความสามารถในการชุบชีวิตเพื่อนร่วมทีมและการป้องกันการโจมตี เธอจึงเป็นศูนย์กลางของความสงบท่ามกลางสนามรบอันดุเดือด","tr-TR":"Çinli ve kapı gibi Sage gittiği her yerde kendisini ve takımını güvende tutar. Öldürülen silah arkadaşlarını hayata döndürme yeteneği ve agresif saldırıları bertaraf edebilmesiyle, cehennemvari savaş meydanında etrafına huzur verir.","vi-VN":"Đến từ Trung Quốc, Sage luôn đảm bảo cho mình và đồng đội được an toàn ở bất cứ nơi đâu cô đến. Với khả năng hồi sinh đồng đội đã ngã xuống và đẩy lùi những cuộc tấn công dữ dội, cô là hậu phương vững chắc cho đồng đội trong những trận giao tranh khốc liệt.","zh-CN":"“贤者”是华夏文明的后代，她可以用超能力阻滞敌方攻势、为队友提供保护和治疗，甚至还能复活队友。有她在的地方，就如同是腥风血雨中的一处避风港。","zh-TW":"來自中國的聖祈，是宛如銅牆鐵壁一般的存在，無論身在何處，除了自保之外，也能確保隊伍的安全。她可以復活不支倒地的友軍，並擊退來犯的敵軍，可說在槍林彈雨的煉獄中，建造一座令人安心的庇護所。"}'::jsonb, 'Thorne', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/displayicon.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/displayicon.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/fullportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/fullportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/fullportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/killfeedportrait.png', 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/minimapportrait.png', null, 'https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/background.png', array['1f5148ff', '0f1923ff', '102d23ff', '0f192300'], true, true, '5fc02f99-4091-4486-a531-98459a3e95e9'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('569fdd95-4d10-43ab-ca70-79becc718b46'::uuid, 'Ability1', '{"es-MX":"Orbe Ralentizador","ar-AE":"بلورة الإبطاء","es-ES":"Orbe de ralentización","ja-JP":"スロウオーブ","it-IT":"Cristallo rallentante","de-DE":"Verlangsamungs-\r\nsphäre","id-ID":"Slow Orb","ko-KR":"둔화 구슬","fr-FR":"Orbe de lenteur","en-US":"Slow Orb","pl-PL":"Spowalniająca Kula","pt-BR":"Orbe de Lentidão","ru-RU":"Сфера замедления","th-TH":"Slow Orb","tr-TR":"YAVAŞLATAN KÜRE","vi-VN":"Băng Cầu Rạn Vỡ","zh-CN":"薄冰","zh-TW":"緩速靈球"}'::jsonb, '{"es-MX":"EQUIPA un orbe de ralentización y DISPARA para lanzarlo. Este detonará al caer al suelo y creará un campo que permanecerá en la zona. El campo ralentiza y reduce la velocidad de deslizamiento de los jugadores que estén dentro.","ar-AE":"تجهّز بكرة إبطاء. أطلق لترمي كرة إبطاء إلى الأمام تنفجر عند هبوطها على الأرض وتنشئ مجالًا مستمرًا يتسبب في إبطاء اللاعبين الموجودين بداخله وتقليص سرعة اندفاعهم.","es-ES":"EQUIPA un orbe de ralentización. DISPARA para lanzar hacia adelante un orbe de ralentización que explota al aterrizar, lo que genera un campo persistente que ralentiza a los jugadores que se encuentren en su interior y reduce su velocidad de deslizamiento.","ja-JP":"スロウオーブを構える。「発射」でオーブを投げる。このオーブは地面に触れると破裂して遅延フィールドを作り出す。遅延フィールドは長時間持続し、その中にいるプレイヤーをスロウ状態にしてダッシュの速度を低下させる。","it-IT":"EQUIPAGGIA un cristallo rallentante. Usa il FUOCO per lanciare un cristallo rallentante che esplode all''atterraggio, creando un campo persistente che RALLENTA i giocatori al suo interno e ne riduce la velocità di scatto.","de-DE":"RÜSTE eine Verlangsamungskugel AUS. FEUERE, um eine Verlangsamungskugel nach vorn zu schleudern. Sie explodiert beim Aufprall und hinterlässt ein temporäres Feld, das die darin gefangenen Spieler verlangsamt und deren Sprintgeschwindigkeit verringert.","id-ID":"EQUIP slowing orb. Tekan FIRE untuk melempar slowing orb ke depan yang meledak saat mendarat. Orb menghasilkan area tahan lama yang memberikan utilitas Slow dan mengurangi kecepatan dash pemain yang terperangkap di dalamnya.","ko-KR":"둔화 구슬을 장착합니다. 발사하면 땅에 닿은 후 폭발하여 일정 시간 동안 둔화 영역을 생성하는 구슬을 던집니다. 둔화 영역에 있는 플레이어는 속도가 느려지고 돌진 속도가 감소합니다.","fr-FR":"ÉQUIPEZ-vous d''un orbe ralentissant. TIREZ pour lancer l''orbe devant vous. Lorsqu''il touche le sol, l''orbe explose et crée un champ persistant qui ralentit les joueurs qui s''y trouvent et qui réduit la vitesse de leurs ruées.","en-US":"EQUIP a slowing orb. FIRE to throw a slowing orb forward that detonates upon landing, creating a lingering field that Slows and reduces the dash speed of players caught inside of it.","pl-PL":"WYPOSAŻ spowalniającą kulę. STRZEL, by wypuścić przed siebie kulę spowalniającą, która po trafieniu eksploduje, tworząc długotrwałe pole spowalniające graczy w obszarze jego działania i zmniejszające ich szybkość doskoku.","pt-BR":"EQUIPE um orbe de lentidão. DISPARE para lançá-lo. O orbe detona ao pousar, criando um campo duradouro que Desacelera os jogadores dentro dele e reduz a velocidade de avanço.","ru-RU":"Выбирает замедляющую сферу. Нажмите кнопку ОГОНЬ, чтобы бросить замедляющую сферу вперед. После падения сфера создает поле, которое замедляет игроков и снижает скорость их рывков.","th-TH":"ติดตั้ง Slowing Orb กดยิงเพื่อโยน Slowing Orb ที่จะระเบิดเมื่อสัมผัสกับพื้น สร้างพื้นที่ที่จะทำให้ผู้เล่นที่ติดอยู่ข้างในติดสถานะสโลว์และความเร็วในการพุ่งตัวลดลง","tr-TR":"Bir yavaşlatma küresi KUŞAN. Yere temas ettiğinde patlayarak bir süre yerde kalan ve oluşturduğu alanda kalan oyuncuları ve oyuncuların atılma hızlarını Yavaşlatan bir yavaşlatma küresi göndermek için ATEŞ ET.","vi-VN":"TRANG BỊ 1 ngọc làm chậm. BẮN để quăng 1 ngọc làm chậm ra phía trước, sẽ phát nổ khi chạm đất và tạo ra một khu vực khiến đối phương trong phạm vi bị Làm Chậm và bị giảm tốc độ lướt.","zh-CN":"装备减速法球，按【射击】将其掷出，它会在落地时爆开，生成一片持续的【减速】领域，降低其中玩家的移动速度和冲刺速度。","zh-TW":"裝備一顆緩速靈球。點擊「攻擊」，將緩速靈球往前丟，觸地時立即引爆，製造一個持續力場，減緩範圍內玩家的移動和衝刺速度。"}'::jsonb, '"https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('569fdd95-4d10-43ab-ca70-79becc718b46'::uuid, 'Ability2', '{"es-MX":"Orbe Curativo","ar-AE":"البلورة الشافية","es-ES":"Orbe de sanación","ja-JP":"ヒーリングオーブ","it-IT":"Cristallo di guarigione","de-DE":"Heilsphäre","id-ID":"Healing Orb","ko-KR":"회복 구슬","fr-FR":"Orbe de soin","en-US":"Healing Orb","pl-PL":"Lecząca Kula","pt-BR":"Orbe Curativo","ru-RU":"Сфера лечения","th-TH":"Healing Orb","tr-TR":"CAN KÜRESİ","vi-VN":"Cầu Hồi Phục","zh-CN":"逢春","zh-TW":"治癒靈球"}'::jsonb, '{"es-MX":"EQUIPA un orbe curativo y DISPARA tras apuntar a un aliado herido para curarlo con el tiempo. Usa el DISPARO SECUNDARIO cuando Sage esté herida para curarla con el tiempo.","ar-AE":"تجهّز بكرة علاج. أطلقها في اتجاه مؤشر التصويب فوق حليف مصاب لتطبيق مفعول العلاج مع مرور الوقت عليه. استخدم الإطلاق البديل في حال تعرض سايج للإصابة لتفعيل العلاج الذاتي مع مرور الوقت.","es-ES":"EQUIPA un orbe de sanación. DISPARA con la mira sobre un aliado herido para curarlo durante un breve periodo. Utiliza el DISPARO ALTERNATIVO cuando Sage esté herida para que se cure a sí misma durante un breve periodo.","ja-JP":"ヒーリングオーブを構える。ダメージを受けた味方に狙いをつけてから「発射」で、その味方の HP を継続回復させる。セージ自身がダメージを受けている場合は、「オルト射撃」で自分の HP を継続回復させる。","it-IT":"EQUIPAGGIA un cristallo di guarigione. Usa il FUOCO mentre punti il tuo reticolo su un alleato danneggiato per attivare su di lui una GUARIGIONE NEL TEMPO. Usa il FUOCO ALTERNATIVO mentre Sage è danneggiata per attivare un''AUTOGUARIGIONE NEL TEMPO.","de-DE":"RÜSTE eine Heilungskugel AUS. FEUERE, während sich dein Fadenkreuz über einem verwundeten Verbündeten befindet, um ihm einen Heileffekt über Zeit zu verleihen. FEUERE IM ALTERNATIVEN MODUS, wenn Sage verwundet ist, um dir selbst einen Heileffekt über Zeit zu verleihen.","id-ID":"EQUIP healing orb. Tekan FIRE dengan menggunakan crosshair-mu pada sekutu yang terkena damage untuk mengaktifkan Heal-Over-Time pada mereka. Tekan ALT FIRE saat Sage terkena damage untuk mengaktifkan Heal-Over-Time untuk dirinya sendiri.","ko-KR":"회복 구슬을 장착합니다. 피해를 입은 아군을 조준한 후 발사하면 해당 아군이 서서히 체력을 회복합니다. 세이지가 피해를 입었을 때 보조 공격 시 자신의 체력을 서서히 회복합니다.","fr-FR":"ÉQUIPEZ-vous d''un orbe de soin. TIREZ en visant un allié blessé pour lui rendre des PV sur la durée. Si vous avez subi des dégâts, utilisez le TIR SECONDAIRE pour récupérer des PV sur la durée.","en-US":"EQUIP a healing orb. FIRE with your crosshairs over a damaged ally to activate a Heal-Over-Time on them. ALT FIRE while Sage is damaged to activate a self Heal-Over-Time.","pl-PL":"WYPOSAŻ leczącą kulę. STRZEL, celując w rannego sojusznika, by aktywować na nim efekt leczenia w czasie. Kiedy Sage jest ranna, ALT. STRZAŁ pozwala aktywować jej efekt leczenia w czasie na sobie.","pt-BR":"EQUIPE um orbe curativo. DISPARE com a mira sobre um aliado ferido para ativar uma Cura ao Longo do Tempo. Use o DISPARO ALTERNATIVO enquanto Sage estiver ferida para ativar uma Autocura ao Longo do Tempo.","ru-RU":"Выбирает сферу здоровья. При наведении на раненого союзника и нажатии кнопки ОГОНЬ активирует постепенное лечение. Если Sage ранена, то нажатие кнопки АЛЬТ. ОГОНЬ активирует постепенное самолечение.","th-TH":"ติดตั้ง Healing Orb กดยิงไปยังพันธมิตรที่บาดเจ็บด้วยเป้าเล็งของคุณเพื่อฮีลพวกเขาอย่างต่อเนื่อง กดโหมดยิงเสริมเมื่อ Sage ได้รับบาดเจ็บเพื่อเปิดใช้งานการฮีลตนเองอย่างต่อเนื่อง","tr-TR":"Bir iyileştirme küresi KUŞAN. Nişangâhını hasar almış bir silah arkadaşına doğrult ve onu Zaman İçinde İyileştirmek için ATEŞ ET. Sage hasar aldıysa, kendini Zaman İçinde İyileştirmek için ALT. ATIŞ kullan.","vi-VN":"TRANG BỊ 1 ngọc hồi phục. BẮN để chọn đồng minh bị thương trong hồng tâm và kích hoạt Hồi Phục Theo Thời Gian lên đồng minh đó. BẮN PHỤ để kích hoạt Hồi Phục Theo Thời Gian lên bản thân khi Sage bị thương.","zh-CN":"装备治疗法球。按【射击】并用准星对准受伤队友以持续对其进行【治疗】。当贤者受伤时，使用【辅助射击】来【治疗】自己。","zh-TW":"裝備一顆治癒靈球。以十字準星瞄準負傷友軍，點擊「攻擊」，發射治癒靈球，就能對其產生「持續治療」效果。當聖祈負傷時，點擊「輔助攻擊」，就能對自身發動「持續治療」效果。"}'::jsonb, '"https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('569fdd95-4d10-43ab-ca70-79becc718b46'::uuid, 'Grenade', '{"es-MX":"Orbe de Barrera","ar-AE":"بلورة الحاجز","es-ES":"Orbe barrera","ja-JP":"バリアオーブ","it-IT":"Muro di cristallo","de-DE":"Barrierensphäre","id-ID":"Barrier orb","ko-KR":"장벽 구슬","fr-FR":"Orbe barrière","en-US":"Barrier Orb","pl-PL":"Kula Bariery","pt-BR":"Orbe de Barreira","ru-RU":"Сфера барьера","th-TH":"Barrier Orb","tr-TR":"BARİYER KÜRESİ","vi-VN":"Tường Băng Bảo Hộ","zh-CN":"玉城","zh-TW":"屏障靈球"}'::jsonb, '{"es-MX":"EQUIPA un orbe de barrera. DISPARA para colocar un muro que se fortifica después de unos segundos. Usa el DISPARO SECUNDARIO para rotarlo antes de crearlo.","ar-AE":"تجهّز ببلورة الحاجز. إطلاقها ينشر جدارًا يصبح محصنًا بعد بضعة ثواني. الإطلاق البديل يدير المستهدف حول نفسه.","es-ES":"EQUIPA un orbe barrera. DISPARA para colocar una pared que se fortalece tras unos segundos. Utiliza el DISPARO ALTERNATIVO para rotarla antes de crearla.","ja-JP":"バリアオーブを構える。「発射」で数秒後に硬化する壁を生成する。「オルト射撃」で向きを変えることができる。","it-IT":"EQUIPAGGIA un cristallo che crea una barriera. Usa il FUOCO per posizionare un muro che si fortifica dopo pochi secondi. Usa il FUOCO ALTERNATIVO per ruotare l''indicatore.","de-DE":"RÜSTE eine Barrierensphäre AUS. FEUERE, um innerhalb weniger Sekunden eine Mauer zu errichten. Feuere im ALT. FEUERMODUS, um die Wand zu drehen.","id-ID":"EQUIP barrier orb. Tekan FIRE untuk menghasilkan dinding pelindung setelah beberapa detik. Tekan ALT FIRE untuk memutar penarget.","ko-KR":"장벽 구슬을 장착합니다. 발사하면 잠시 후 강화되는 장벽을 설치합니다. 보조 공격 시 장벽이 회전합니다.","fr-FR":"ÉQUIPEZ-vous d''un orbe barrière. TIRER permet de placer un mur qui se renforce après quelques secondes. Le TIR SECONDAIRE fait pivoter le cibleur.","en-US":"EQUIP a barrier orb. FIRE places a wall that fortifies after a few seconds. ALT FIRE rotates the targeter.","pl-PL":"WYPOSAŻ kulę bariery. STRZAŁ umieszcza ścianę, która umacnia się po paru sekundach. ALT. STRZAŁ obraca cel.","pt-BR":"EQUIPE um orbe de barreira. DISPARE para posicionar uma parede que é fortificada após alguns segundos. DISPARO ALTERNATIVO gira o marcador de alvo.","ru-RU":"Выбирает сферу барьера. Нажмите кнопку ОГОНЬ, чтобы создать стену, которая затвердеет через несколько секунд. Нажмите кнопку АЛЬТ. ОГОНЬ, чтобы повернуть стену перед установкой.","th-TH":"ติดตั้ง Barrier Orb กดยิงเพื่อวางกำแพงที่จะก่อตัว\nขึ้นหลังจากนั้นไม่กี่วินาที กดโหมดการยิงเสริมเพื่อหมุน","tr-TR":"Bir Bariyer Küresi KUŞAN. Birkaç saniye sonra güçlenen bir duvar yerleştirmek için ATEŞ ET. ALT. ATIŞ, hedefleyiciyi döndürür.","vi-VN":"TRANG BỊ 1 cầu bảo hộ. BẮN để tạo 1 bức tường kiên cố sau vài giây. BẮN PHỤ để đổi hướng nhắm mục tiêu.","zh-CN":"装备屏障法球，按【射击】来布置一道墙壁，【辅助射击】可旋转目标指示器。","zh-TW":"裝備一顆屏障靈球。點擊「攻擊」可豎立一道牆壁，牆體在數秒後會加固硬化。點擊「輔助攻擊」則可旋轉牆體方向。"}'::jsonb, '"https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('569fdd95-4d10-43ab-ca70-79becc718b46'::uuid, 'Ultimate', '{"es-MX":"Resurrección","ar-AE":"الإحياء","es-ES":"Resurrección","ja-JP":"リザレクション","it-IT":"Respiro vitale","de-DE":"Wiederbelebung","id-ID":"Resurrection","ko-KR":"부활","fr-FR":"Résurrection","en-US":"Resurrection","pl-PL":"Wskrzeszenie","pt-BR":"Ressurreição","ru-RU":"Воскрешение","th-TH":"Resurrection","tr-TR":"DİRİLİŞ","vi-VN":"Hồi Sinh","zh-CN":"再起","zh-TW":"起死回生"}'::jsonb, '{"es-MX":"EQUIPA una habilidad de resurrección y DISPARA mientras apuntas hacia un aliado muerto para comenzar a resucitarlo. Tras un breve periodo de canalización, el aliado volverá a la vida con su salud intacta.","ar-AE":"تجهّز بقدرة الإحياء. أطلق بعد وضع مؤشر التصويب على حليف مقتول لتبدأ في إحيائه. بعد فترة وجيزة سيعود الحليف إلى الحياة مع صحة كاملة.","es-ES":"EQUIPA una habilidad de resurrección. DISPARA con la mira sobre un aliado muerto para empezar a resucitarlo. Tras un breve periodo de canalización, el aliado resucitará con toda la vida.","ja-JP":"蘇生能力を使えるようにする。デスした味方に狙いをつけてから「発射」で蘇生を開始する。短時間の蘇生作業の後、その味方は HP をすべて回復した状態で復活する。","it-IT":"EQUIPAGGIA un''abilità di resurrezione. Usa il FUOCO mentre punti il tuo reticolo su un alleato morto per rianimarlo. Dopo una breve canalizzazione, tornerà in vita con la salute al massimo.","de-DE":"RÜSTE deine Wiederbelebungsfähigkeit AUS. FEUERE, während sich dein Fadenkreuz über einem toten Verbündeten befindet, um ihn wiederzubeleben. Nach einer kurzen Kanalisierung wird der Verbündete mit vollem Leben wiederbelebt.","id-ID":"EQUIP ability ini untuk menghidupkan sekutu. Tekan FIRE untuk menggunakan crosshair pada sekutu yang mati agar mereka hidup kembali. Setelah penyaluran singkat, sekutu akan hidup kembali dengan health yang penuh.","ko-KR":"부활 스킬을 장착합니다. 죽은 아군을 조준한 후 발사하면 해당 아군이 부활하기 시작합니다. 짧은 정신 집중이 끝나면 아군이 최대 체력으로 되살아납니다.","fr-FR":"ÉQUIPEZ-vous d''une compétence de résurrection. TIREZ en visant un allié mort pour le ramener à la vie. Après une courte canalisation, votre allié est ramené à la vie avec tous ses PV.","en-US":"EQUIP a resurrection ability. FIRE with your crosshairs placed over a dead ally to begin resurrecting them. After a brief channel, the ally will be brought back to life with full health.","pl-PL":"WYPOSAŻ umiejętność wskrzeszenia. STRZEL, celując w zabitego sojusznika, by rozpocząć jego wskrzeszanie. Po krótkiej chwili wróci on do życia z pełnym zdrowiem.","pt-BR":"EQUIPE uma habilidade de ressurreição. DISPARE com a mira sobre um aliado morto para começar a revivê-lo. Depois de uma breve canalização, o aliado voltará com a Vida completa.","ru-RU":"Выбирает воскрешающее умение. Наведите прицел на погибшего союзника и нажмите кнопку ОГОНЬ, чтобы начать воскрешение. После небольшой задержки цель вернется к жизни с полным запасом здоровья.","th-TH":"ติดตั้งสกิล Resurrection กดยิงและใช้เป้าเล็ง\nของคุณชี้ไปที่ร่างของพันธมิตรที่เสียชีวิตเพื่อ\nชุบชีวิตพวกเขา ภายในระยะเวลาสั้น ๆ \nพันธมิตรจะฟื้นกลับมามีพลังชีวิตที่สมบูรณ์","tr-TR":"Bir diriltme yeteneği KUŞAN. Nişangâhını dost bir cesede doğrult ve onu hayata döndürmek için ATEŞ ET. Silah arkadaşın kısa bir sürenin ardından tamamen iyileşmiş olarak hayata döner.","vi-VN":"TRANG BỊ 1 kỹ năng hồi sinh. BẮN để chọn đồng minh đã hy sinh trong hồng tâm để bắt đầu quá trình hồi sinh đồng minh đó. Sau một khoảng thời gian luyện kỹ năng ngắn, đồng đội sẽ hồi sinh với đầy máu.","zh-CN":"装备复活技能。瞄准一名倒下的队友按下【射击】，即可在短暂引导后使其满血复活。","zh-TW":"裝備一項復活技能。以十字準星瞄準陣亡友軍，點擊「攻擊」就能使其復活。短暫詠唱後，友軍即可滿血復活。"}'::jsonb, '"https://media.valorant-api.com/agents/569fdd95-4d10-43ab-ca70-79becc718b46/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('a3bfb853-43b2-7238-a4f1-ad90e9e46bcc'::uuid, '{"es-MX":"Reyna","ar-AE":"ريينا","es-ES":"Reyna","ja-JP":"レイナ","it-IT":"Reyna","de-DE":"Reyna","id-ID":"Reyna","ko-KR":"레이나","fr-FR":"Reyna","en-US":"Reyna","pl-PL":"Reyna","pt-BR":"Reyna","ru-RU":"Reyna","th-TH":"Reyna","tr-TR":"REYNA","vi-VN":"Reyna","zh-CN":"芮娜","zh-TW":"蕾娜"}'::jsonb, '{"es-MX":"Desde el corazón de México, Reyna llega para dominar los duelos y aumentar su poder con cada asesinato. Su letalidad solo está limitada por tu destreza al usarla, por lo que su eficacia dependerá mucho de ello. ","ar-AE":"مع نشوئها في قلب المكسيك، تهيمن ريينا على القتال الفردي، حيث تتفجر قدراتها مع كل عملية قتل تحرزها. ولا يفوق قدراتها سوى مهارتها الفطرية، مما يجعلها مقاتلة تعتمد بشدة على الأداء. ","es-ES":"Desde el corazón de México, Reyna llega para dominar los combates uno contra uno, y cada asesinato que consigue la hace más fuerte. Su potencial es prácticamente infinito, y la destreza individual es el único factor determinante de su éxito. ","ja-JP":"メキシコの中心部で鍛え上げられたレイナは一対一の状況で優位に立ち、敵を倒して命を食らう。その真の能力を開花できるかは、戦いのパフォーマンスによって大きく左右される。 ","it-IT":"Cresciuta nel cuore del Messico, Reyna domina i duelli uno contro uno, scatenandosi con ogni uccisione ottenuta. L''unico limite alle sue capacità è la sua abilità, che la rende fortemente dipendente dalle proprie prestazioni. ","de-DE":"Reyna wurde im Herzen Mexikos geschmiedet und dominiert den Einzelkampf, indem sie mit jedem Kill, den sie erzielt, auftrumpft. Allein ihr eigenes Können setzt ihren Fähigkeiten Grenzen, weshalb sie extrem abhängig von ihrer Leistung ist. ","id-ID":"Ditempa di jantung Meksiko, Reyna mendominasi single combat dan menjadi makin kuat seiring tiap kill yang berhasil diraih. Kepiawaiannya hanya terhambat keahlian mentahnya, membuatnya sangat bergantung pada performa. ","ko-KR":"멕시코 중심부에서 태어난 레이나는 일대일 전투에 탁월하며 적을 처치할 때마다 강력해집니다. 그녀의 능력은 온전히 전투 실력에만 좌우됩니다.","fr-FR":"Originaire du cœur du Mexique, Reyna est une experte des combats singuliers qui se renforce à chaque élimination qu''elle réussit. Son efficacité n''est limitée que par son habileté, ce qui la rend très dépendante de ses propres performances. ","en-US":"Forged in the heart of Mexico, Reyna dominates single combat, popping off with each kill she scores. Her capability is only limited by her raw skill, making her sharply dependent on performance. ","pl-PL":"Zahartowana w sercu Meksyku Reyna dominuje w walkach jeden na jeden, rozkręcając się z każdym zdobytym zabójstwem. Ograniczają ją wyłącznie jej własne umiejętności – im lepiej sobie radzi, tym staje się potężniejsza. ","pt-BR":"Criada no coração do México, Reyna domina o combate individual e se destaca a cada abate efetuado. Sua capacidade só é limitada pela própria perícia, o que a torna bastante dependente de desempenho. ","ru-RU":"Выросшая в самом сердце Мексики Reyna способна одолеть любого в бою один на один, и убийства придают ей сил. Ее мощь ограничена лишь мастерством и в значительной степени зависит от успехов в бою. ","th-TH":"หล่อหลอมขึ้นมาจากใจกลางเม็กซิโก Reyna เป็นที่หนึ่งในด้านการต่อสู้ตัวต่อตัว และยิ่งเก่งขึ้นทุกครั้งที่เก็บคิลได้ สิ่งเดียวที่เป็นขีดจำกัดความสามารถของเธอก็คือทักษะ ทำให้ประสิทธิภาพของเธอนั้นขึ้นอยู่กับฝีมือล้วน ๆ ","tr-TR":"Meksika''nın kalbinden kopup gelen Reyna, teke tek çatışmalarda düşmanını ezer ve aldığı her skorla daha da coşar. Yapabilecekleri tamamen saf beceri gerektirir ve onu ciddi şekilde performansa dayalı kılar. ","vi-VN":"Được tôi luyện ngay giữa trái tim của Mexico, Reyna luôn áp đảo trong các giao tranh đơn lẻ và trở nên mạnh mẽ hơn với mỗi đối thủ bị cô hạ gục. Sức mạnh của cô chỉ bị giới hạn bởi kỹ năng cá nhân, cũng là điều khiến cô bị lệ thuộc khá nhiều vào phong độ thi đấu của người chơi. ","zh-CN":"“芮娜”的威名铸就于马德雷山脉。虽然初始技能有所限制，但她能在狭路相逢的决斗中变得越来越强，直至觉醒强大的超能力，这使得她的实战表现格外重要。 ","zh-TW":"在墨西哥中心經過歷練的蕾娜，單打獨鬥的能力超強，每擊殺一名敵軍，都可以獲得所向無敵的增益效果。她是否能主宰戰場，除了取決於技巧熟練度，也仰賴賽局上的表現。 "}'::jsonb, 'Vampire', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/displayicon.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/displayicon.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/fullportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/fullportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/fullportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/killfeedportrait.png', 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/minimapportrait.png', null, 'https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/background.png', array['662d62ff', '0f1923ff', '2f2664ff', '0f192300'], false, false, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('a3bfb853-43b2-7238-a4f1-ad90e9e46bcc'::uuid, 'Ability1', '{"es-MX":"Devorar","ar-AE":"الافتراس","es-ES":"Devorar","ja-JP":"デバウアー","it-IT":"Divorare","de-DE":"Verzehren","id-ID":"Devour","ko-KR":"포식","fr-FR":"Dévoration","en-US":"Devour","pl-PL":"Pożarcie","pt-BR":"Devorar","ru-RU":"Поглощение","th-TH":"Devour","tr-TR":"SÖMÜR","vi-VN":"Nuốt chửng","zh-CN":"噬尽","zh-TW":"生靈吞噬"}'::jsonb, '{"es-MX":"Cosecha de Almas: Los enemigos que hayan muerto 3 seg después de recibir daño de Reyna, dejan orbes de almas que duran 3 seg.\r\nDevorar: Consume AL INSTANTE un orbe de alma y gana Vida Temporal rápidamente. Si LA EMPERATRIZ está activa, Devorar se lanzará de forma automática, no consumirá el orbe de almas y la curación recibida será permanente.","ar-AE":"حصد الروح: يؤدي موت الأعداء خلال 3 ثوانٍ من تلقي الضرر على يد ريينا إلى ترك كرات روح وراءهم تدوم لمدة 3 ثوان.\r\nالافتراس: تستهلك بصورة فورية كرة روح كي تكسب بسرعة صحة مؤقتة. إن كانت قدرة الإمبراطورة مُفعّلة، يتم إلقاء الافتراس تلقائيًا من دون استهلاك كرة الروح ويصبح العلاج دائمًا.","es-ES":"Cosecha de almas: Los enemigos asesinados que mueran en los 3 segundos siguientes a recibir daño de Reyna dejan tras de sí orbes de alma que duran 3 segundos.\r\nDevorar: Consume INSTANTÁNEAMENTE un orbe de alma, lo que otorga vida temporal rápidamente. Si EMPERATRIZ está activa, Devorar se lanzará de forma automática, no consumirá el orbe de alma y la curación será permanente.","ja-JP":"ソウルハーベスト:レイナからダメージを受けて3秒以内にデスした敵は、3秒間持続するソウルオーブを残す。\r\nデバウアー:ソウルオーブを1つ消費し、急速に一時的な増加体力を得る。「エンプレス」の発動中はデバウアーがソウルオーブを消費せずに自動的に使用され、回復の時間制限がなくなる。","it-IT":"Mietitura di anime: quando un nemico danneggiato da Reyna negli ultimi 3 secondi muore, lascia una sfera dell''anima che dura 3 secondi.\r\nDivorare: consumi ALL''ISTANTE una sfera dell''anima, ottenendo rapidamente salute temporanea. Se IMPERATRICE è attiva, Divorare verrà lanciata automaticamente senza consumare la sfera dell''anima, e la cura ottenuta sarà permanente.","de-DE":"Seelenernte: Gegner, die binnen 3 Sekunden sterben, nachdem sie von Reyna Schaden erlitten haben, lassen für 3 Sekunden Seelenkugeln zurück.\r\nVerzehren: Verbraucht SOFORT eine Seelenkugel, wodurch sie schnell temporäres Leben erhält. Ist „KAISERIN“ aktiv, wird „Verzehren“ automatisch gewirkt und keine Seelenkugel verbraucht. Die Heilung ist dauerhaft.","id-ID":"Soul Harvest: Musuh yang mati dalam 3 detik setelah menerima damage dari Reyna, meninggalkan Soul Orb yang bertahan 3 detik.\r\nDevour: SEKETIKA mengonsumsi Soul Orb di sekitar, mendapatkan Health Sementara dengan cepat. Jika EMPRESS aktif, Devour akan secara otomatis cast, tidak mengonsumsi Soul Orb, dan Healing-nya bersifat permanen.","ko-KR":"영혼 수확: 레이나에게 피해를 입고 3초 이내에 죽은 적은 3초 동안 유지되는 영혼 구슬을 남깁니다.\r\n포식: 즉시 영혼 구슬을 흡수하여 순식간에 일시적인 체력 증가 효과를 얻습니다. 여제 활성화 시 포식이 자동으로 사용되며 영혼 구슬을 흡수하지 않고, 영구적으로 체력이 회복됩니다.","fr-FR":"Récolte des âmes : les ennemis qui meurent dans les 3 sec après que Reyna les a blessés laissent des orbes d''âme qui durent 3 sec.\r\nDévoration : vous consommez INSTANTANÉMENT un orbe d''âme pour rapidement regagner des PV temporaires. Si IMPÉRATRICE est active, Dévoration se lance automatiquement, ne consomme pas d''orbe d''âme et rend des PV permanents.","en-US":"Soul Harvest: Enemies that die within 3 seconds of taking damage from Reyna leave behind Soul Orbs that last 3 seconds.\r\nDevour: INSTANTLY consume a soul orb, rapidly gaining Temporary Health. If EMPRESS is active then Devour automatically casts, does not consume the Soul Orb, and Healing is permanent.","pl-PL":"Żniwa Duszy: Wrogowie, którzy giną w ciągu 3 sek. od otrzymania obrażeń od Reyny, zostawiają po sobie pozostające na ziemi przez 3 sek. Kule Duszy.\r\nPożarcie: NATYCHMIAST pochłoń pobliską Kulę Duszy, by szybko zyskać tymczasowe zdrowie. Jeśli CESARZOWA jest aktywna, Pożarcie zostaje rzucone automatycznie, nie pochłania Kuli Duszy, a leczenie jest stałe.","pt-BR":"Colheita de Almas: inimigos abatidos até 3 segundos após sofrerem dano da Reyna deixam Orbes de Alma que duram 3s.\r\nDevorar: INSTANTANEAMENTE consome um Orbe de Alma e recebe Vida Temporária. Se IMPERATRIZ estiver ativa, Devorar é conjurada automaticamente, não consome o Orbe de Alma e a Cura é permanente.","ru-RU":"Сбор душ: когда противник умирает в течение 3 секунд после получения урона от Reyna, на 3 секунды появляется сфера души.\r\nПоглощение: мгновенно поглощает сферу души и временно увеличивает свое здоровье. Во время действия абсолютного умения поглощение срабатывает автоматически и не поглощает сферу, а прибавка к здоровью постоянна.","th-TH":"Soul Harvest: ศัตรูที่ตายภายใน 3 วินาทีหลังได้รับความเสียหายจาก Reyna จะทิ้ง Soul Orb ที่คงอยู่เป็นเวลา 3 วินาที\r\nDevour: ใช้ Soul Orb ในทันที และเพิ่มพลังชีวิตชั่วคราวอย่างรวดเร็ว หาก EMPRESS ทำงานอยู่ Devour จะร่ายอัตโนมัติโดยไม่ใช้ Soul Orb และการฮีลจะเป็นแบบถาวร","tr-TR":"Ruh Hasadı: Reyna''dan hasar aldıktan sonra 3 saniye içinde ölen düşmanlar, arkalarında 3 saniyeliğine Ruh Küreleri bırakır.\r\nSömür: ANINDA bir Ruh Küresi''ni tüket ve hızla geçici can kazan. İMPARATORİÇE etkinse Sömür otomatik olarak kullanılır, Ruh Küresi harcamaz ve iyileştirme kalıcı olur.","vi-VN":"Tụ Linh: Kẻ địch đã nhận sát thương từ Reyna trong vòng 3 giây trước khi bị tiêu diệt sẽ để lại Linh Ngọc trong 3 giây.\r\nNuốt Chửng: LẬP TỨC hấp thụ một linh ngọc ở gần để nhận siêu tốc Máu Tạm Thời. Nếu NỮ HOÀNG đang kích hoạt, Nuốt Chửng sẽ được tự động thi triển, không hấp thụ Linh Ngọc, và lượng Hồi Máu trở thành vĩnh viễn.","zh-CN":"狩魂：被芮娜造成伤害的3秒内被击败的敌人将留下魂珠，持续3秒。\r\n噬尽：立即吞噬一颗魂珠并迅速获得【临时生命值】。在【女皇旨令】激活时，噬尽将自动施放且不会消耗魂珠，治疗效果也将持续生效。","zh-TW":"靈魂收割：被蕾娜傷害後3秒內陣亡的敵人，會留下一個維持3秒鐘的魂體。\r\n生靈吞噬：立即消耗一個魂體，快速獲得暫時生命值。若已在女皇狀態下，將自動施放「生靈吞噬」、不消耗魂體，並治療效果改為永久。"}'::jsonb, '"https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('a3bfb853-43b2-7238-a4f1-ad90e9e46bcc'::uuid, 'Ability2', '{"es-MX":"Desechar","ar-AE":"الانعزال","es-ES":"Despreciar","ja-JP":"ディスミス","it-IT":"Negazione","de-DE":"Eliminieren","id-ID":"Dismiss","ko-KR":"무시","fr-FR":"Rebuffade","en-US":"Dismiss","pl-PL":"Drwina","pt-BR":"Dispensar","ru-RU":"Изгнание","th-TH":"Dismiss","tr-TR":"AZLET","vi-VN":"Vô ảnh","zh-CN":"逐散","zh-TW":"銷魂解形"}'::jsonb, '{"es-MX":"Consume AL INSTANTE un orbe de almas cercano para volverse intangible durante un tiempo breve. También se vuelve invisible si LA EMPERATRIZ está activa.","ar-AE":"استهلك بشكل فوري كرة روح قريبة كي تصبح غير قابل للمس لفترة وجيزة. إن كانت قدرة الإمبراطورة مفعلة، ستصبح أيضًا غير مرئي.","es-ES":"Consume INSTANTÁNEAMENTE un orbe de alma cercano y se vuelve intangible durante un breve periodo. Si EMPERATRIZ está activa, se vuelve también invisible.","ja-JP":"付近に存在するソウルオーブを 1 つ消費して、短時間だけ実体を持たない存在となる。「エンプレス」の発動中はさらに姿も見えなくなる。","it-IT":"Consumi ALL''ISTANTE una sfera dell''anima nelle vicinanze, diventando INTANGIBILE per una breve durata. Se IMPERATRICE è attiva, diventi anche INVISIBILE.","de-DE":"Verzehrt SOFORT eine nahe Seelenkugel und verleiht für kurze Zeit Unberührbarkeit. Wenn KAISERIN aktiv ist, wird Reyna zudem unsichtbar.","id-ID":"SEKETIKA mengonsumsi Soul Orb yang ada di sekitar dan membuat Reyna jadi tidak berwujud selama beberapa saat. Jika EMPRESS aktif, dia sekaligus akan tidak terlihat.","ko-KR":"즉시 근처에 있는 영혼 구슬을 흡수하여 짧은 시간 동안 무형 상태가 됩니다. 여제 활성화 시 추가로 투명 상태가 됩니다.","fr-FR":"Vous consommez INSTANTANÉMENT un orbe d''âme proche et devenez intangible pendant un court instant. Si IMPÉRATRICE est active, vous devenez également invisible.","en-US":"INSTANTLY consume a nearby Soul Orb, becoming Intangible for a short duration. If EMPRESS is active, also become Invisible.","pl-PL":"NATYCHMIAST pochłoń pobliską kulę duszy, która zapewni nieuchwytność przez krótki czas. Jeśli CESARZOWA jest aktywna, zapewnia także niewidzialność.","pt-BR":"INSTANTANEAMENTE consome um Orbe de Alma próximo, ficando Inatingível por um curto período. Também se torna Invisível se a habilidade IMPERATRIZ estiver ativa.","ru-RU":"Мгновенно поглощает находящуюся поблизости сферу души, что дает неуязвимость на 2 секунды. Во время действия умения \"Императрица\" также дает невидимость.","th-TH":"ใช้ Soul Orb ที่อยู่ใกล้เคียงในทันที และจะเข้าสู่สถานะไร้ตัวตนเป็นระยะเวลาสั้น ๆ หาก EMPRESS ทำงานอยู่ จะทำให้ล่องหนด้วย","tr-TR":"Yakınlardaki bir Ruh Küresi''ni ANINDA tüketerek kısa süreliğine Saydamlaş. İMPARATORİÇE etkinse, aynı zamanda Görünmez olursun.","vi-VN":"LẬP TỨC hấp thụ một Linh Ngọc ở gần để trở nên Phi Vật Chất trong một thời gian ngắn. Nếu NỮ HOÀNG đang kích hoạt, sẽ đồng thời trở nên Vô Hình.","zh-CN":"立即吞噬邻近的魂珠，在短时间内变得【无形】。在【女皇旨令】激活时，此技能还会使你【隐形】。","zh-TW":"立即消耗一個附近的魂體，並使自己短時間內進入「無形狀態」。若已在女皇狀態下，則同時變得「隱形」。"}'::jsonb, '"https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('a3bfb853-43b2-7238-a4f1-ad90e9e46bcc'::uuid, 'Grenade', '{"es-MX":"La Mirada","ar-AE":"النظرة الماكرة","es-ES":"Mirada lasciva","ja-JP":"リーア","it-IT":"Malizia","de-DE":"Starren","id-ID":"Leer","ko-KR":"눈총","fr-FR":"Œillade","en-US":"Leer","pl-PL":"Rzut Okiem","pt-BR":"Olhar Voraz","ru-RU":"Злобный взгляд","th-TH":"Leer","tr-TR":"KEM GÖZ","vi-VN":"Ánh Nhìn Hư Không","zh-CN":"睥睨","zh-TW":"邪媚凝視"}'::jsonb, '{"es-MX":"EQUIPA un ojo destructible y etéreo. ACTÍVALO para lanzarlo a una distancia corta y todos los enemigos que lo vean se ofuscarán.","ar-AE":"تجهّز بعين أثيرية قابلة للتدمير. قم بالتفعيل لإلقاء العين لمسافة قصيرة أمامك. تصيب العين جميع من ينظرون إليها من الأعداء بضعف النظر.","es-ES":"EQUIPA un ojo etéreo destructible. ACTÍVALA para lanzar el ojo hacia delante una corta distancia. El ojo limitará la visión de todos los enemigos que lo miren.","ja-JP":"破壊可能なエーテルの眼を構える。「発動」でこの眼を前方に向かって放つ。この眼は短い距離を進み、これを見たすべての敵は視界が悪化する。","it-IT":"EQUIPAGGIA un occhio etereo e distruttibile. ATTIVA per lanciare l''occhio davanti a te ad una breve distanza. L''occhio accecherà tutti i nemici che lo guardano.","de-DE":"RÜSTE ein ätherisches, zerstörbares Auge AUS. AKTIVIEREN, um das Auge eine kurze Strecke nach vorne zu werfen. Das Auge schränkt die Sicht von Gegnern, die es ansehen, ein.","id-ID":"EQUIP bola halus berbentuk mata yang bisa dihancurkan. AKTIFKAN untuk mengeluarkan bola tersebut dalam jarak pendek ke arah depan. Bola tersebut akan menerapkan utilitas Nearsight ke semua musuh.","ko-KR":"파괴 가능한 천상의 눈을 장착합니다. 활성화하면 눈을 짧게 앞으로 던집니다. 눈을 본 적은 모두 시야가 제한됩니다.","fr-FR":"ÉQUIPEZ-vous d''un œil éthéré destructible. ACTIVEZ pour lancer l''œil vers l''avant sur une courte distance. L''œil rend myopes tous les ennemis qui le regardent.","en-US":"EQUIP an ethereal, destructible eye. ACTIVATE to cast the eye a short distance forward. The eye will Nearsight all enemies who look at it.","pl-PL":"WYPOSAŻ eteryczne, zniszczalne oko. AKTYWUJ je, by rzucić oko przed siebie na niewielką odległość. Oko spowoduje krótkowzroczność u wszystkich przeciwników, którzy na nie spojrzą.","pt-BR":"EQUIPE um olho etéreo e destrutível. ATIVE para lançá-lo adiante a uma curta distância. O olho deixará com visão turva todos os inimigos que olharem para ele.","ru-RU":"Выбирает призрачный глаз. При активации бросает глаз на близкое расстояние. Глаз ограничивает обзор всех противников, которые посмотрят на него. Глаз можно уничтожить.","th-TH":"ติดตั้งดวงตาเพื่อทำลายการมองเห็น กดใช้งาน\nเพื่อปล่อยดวงตาออกไปข้างหน้าเป็นระยะทาง\nสั้น ๆ ศัตรูที่มองมันจะมองเห็นเป็นระยะทาง\nสั้น ๆ เท่านั้น","tr-TR":"Yok edilebilir, ruhtan bir göz KUŞAN. Gözü yakın mesafede ileri doğru kullanmak için ETKİNLEŞTİR. Göz, ona bakan tüm düşmanların Görüşünü Kısıtlar.","vi-VN":"TRANG BỊ 1 mắt hư không, có thể bị phá hủy. KÍCH HOẠT để sử dụng mắt hư không ở khoảng cách ngắn phía trước. Kẻ địch sẽ bị hạn chế tầm nhìn khi nhìn vào nó.","zh-CN":"装备一颗可被摧毁的虚灵之眼，【激活】将其向前掷出一段距离，使看见此眼球的敌人【视野收缩】。","zh-TW":"裝備一個可破壞的異界之眼。「啟動」後可投擲至前方不遠處，看見此眼的敵軍視野會受到限制。"}'::jsonb, '"https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('a3bfb853-43b2-7238-a4f1-ad90e9e46bcc'::uuid, 'Ultimate', '{"es-MX":"La Emperatriz","ar-AE":"الإمبراطورة","es-ES":"Emperatriz","ja-JP":"エンプレス","it-IT":"Imperatrice","de-DE":"Kaiserin","id-ID":"Empress","ko-KR":"여제","fr-FR":"Impératrice","en-US":"Empress","pl-PL":"Cesarzowa","pt-BR":"Imperatriz","ru-RU":"Императрица","th-TH":"Empress","tr-TR":"İMPARATORİÇE","vi-VN":"Nữ Hoàng","zh-CN":"女皇旨令","zh-TW":"無上女皇"}'::jsonb, '{"es-MX":"Entra al INSTANTE en un frenesí, lo que te da un Potenciador de combate que aumenta dramáticamente la velocidad de disparo, de equipamiento y de recarga. Recibe cargas infinitas de la habilidad Cosecha de Almas.","ar-AE":"ادخل فورًا في نوبة جنون، مما يكسبك محفز قتال يزيد سرعة إطلاق النار والتجهز وإعادة التلقيم على نحو كبير. اكسب عددًا لا ينتهي من قدرات حصد الأرواح.","es-ES":"Entra en un frenesí INSTANTÁNEO que otorga Estimulante de combate, lo que aumenta drásticamente la velocidad de disparo, de equipamiento y de recarga. Consigue cargas infinitas de habilidades de Cosecha de almas.","ja-JP":"狂乱状態となり、射撃と構え、リロードの速度が劇的に向上するバトルスティムを獲得する。ソウルハーベストの使用回数が無限になる。","it-IT":"Entri ALL''ISTANTE in uno stato di frenesia, ottenendo un effetto ENERGIZZANTE che aumenta notevolmente la velocità di fuoco, di equipaggiamento e di ricarica. Ottieni cariche infinite per le abilità Mietitura di anime.","de-DE":"Geht SOFORT in einen Kampfrausch über und erhält damit Kampf-Stim, die ihre Feuerrate, Ausrüstungs- und Nachladengeschwindigkeit enorm steigert. Erhält unendliche Ladungen der Seelenernte-Fähigkeiten.","id-ID":"SEKETIKA memasuki kondisi frenzy, lalu mendapatkan utilitas Combat Stim yang mempercepat tembakan, penggunaan, dan reload secara signifikan. Dapatkan charge tanpa batas untuk ability Soul Harvest. Saat musuh mati karena Reyna, atau mati dalam 3 detik setelah menerima damage dari Reyna, durasinya diperbarui.","ko-KR":"즉시 광란 상태가 되어 사격, 장착, 재장전 속도가 크게 증가하는 전투 자극제 효과를 얻습니다. 영혼 수확의 충전량을 무제한으로 얻습니다.","fr-FR":"Entrez INSTANTANÉMENT en furie et gagnez l''effet Stimulant de combat, ce qui augmente considérablement vos vitesses de tir, de changement d''arme et de rechargement. Vous gagnez une infinité de charges pour les compétences se servant de Récolte des âmes.","en-US":"INSTANTLY enter a frenzy, gaining a Combat Stim that increases firing, equip and reload speed dramatically. Gain infinite charges of Soul Harvest abilities.","pl-PL":"NATYCHMIAST wprowadza w szał, zapewniając stymulant bitewny, który znacznie zwiększa szybkość strzału, wyposażania i przeładowania. Zapewnia nieskończone ładunki umiejętności Żniwa Duszy.","pt-BR":"INSTANTANEAMENTE entra em estado de frenesi e recebe um Estimulante de Combate que aumenta drasticamente as velocidades de disparo, equipagem e recarga de munição. Ganha cargas infinitas das habilidades de Colheita de Almas.","ru-RU":"Мгновенно впадает в бешенство и получает боевой стимулятор, повышающий скорость стрельбы и обращения с оружием. Дает бесконечное количество зарядов \"Сбора душ\".","th-TH":"เข้าสู่สถานะบ้าคลั่งในทันที ได้รับบัฟ Combat Stim ที่จะเพิ่มความเร็วในการยิง ติดตั้ง และรีโหลดอย่างมาก ได้รับชาร์จไม่จำกัดสำหรับสกิล Soul Harvest","tr-TR":"ANINDA bir coşku haline geçerek atış, kuşanma ve doldurma hızını ciddi şekilde arttıran bir Kuvvetli Savaş edin. Ruh Hasadı yetenekleri için sonsuz yük kazanırsın.","vi-VN":"LẬP TỨC vào trạng thái điên cuồng, nhận Khuấy Động Giao Tranh, tăng nhanh tốc độ bắn, đổi súng và thay đạn. Nhận lượt dùng vô hạn các kỹ năng Tụ Linh.","zh-CN":"进入狂暴状态，获得【作战强化】效果，大幅度提升射击、装备与换弹速度，可以不限次数地使用【噬尽】技能。","zh-TW":"立即進入狂暴模式，獲得激發戰意，大幅提升射擊、裝備及填彈速度，並獲得無限靈魂收割能力。"}'::jsonb, '"https://media.valorant-api.com/agents/a3bfb853-43b2-7238-a4f1-ad90e9e46bcc/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('8e253930-4c05-31dd-1b6c-968525494517'::uuid, '{"es-MX":"Omen","ar-AE":"أومن","es-ES":"Omen","ja-JP":"オーメン","it-IT":"Omen","de-DE":"Omen","id-ID":"Omen","ko-KR":"오멘","fr-FR":"Omen","en-US":"Omen","pl-PL":"Omen","pt-BR":"Omen","ru-RU":"Omen","th-TH":"Omen","tr-TR":"OMEN","vi-VN":"Omen","zh-CN":"幽影","zh-TW":"歐門"}'::jsonb, '{"es-MX":"Omen, el espectro de un recuerdo, caza entre las sombras. Ciega a los enemigos, se teletransporta a través del campo de batalla y los infunde de paranoia mientras intentan descubrir de dónde vendrá su próximo ataque.","ar-AE":"يتربص شبح الذكريات أومن بفرائسه في جنح الظلام. حيث يعمي الأعداء ويتنقل بسرعة عبر الميدان لينشر الهلع بين أعدائه الذين يهرولون في الأنحاء محاولين اكتشاف مكان ضربته التالية.","es-ES":"Omen es un fantasma de tiempos pasados que acecha en las sombras. Es capaz de cegar al enemigo, teleportarse a través del campo de batalla y sembrar el caos y la paranoia mientras sus rivales se preguntan dónde atacará la próxima vez.","ja-JP":"記憶の幻影、オーメンは闇に潜んで敵を狩る。敵の視界を遮り、神出鬼没にテレポートすることで、次の一手を予測しようとする敵を徐々に疑心暗鬼へと誘うのだ。","it-IT":"Omen è uno spettro nato da un ricordo che caccia le sue prede nelle ombre. Acceca i nemici, si teletrasporta nel campo di battaglia e lascia che la paura si nutra dei suoi avversari, rosi dal dubbio di quale sarà la sua prossima vittima.","de-DE":"Omen ist das Phantom einer Erinnerung und jagt in den Schatten. Er kann Gegnern die Sicht nehmen und sich über die Karte teleportieren. Wenn die Gegner dann in Panik geraten und sein nächstes Ziel herausfinden wollen, schlägt er zu.","id-ID":"Sesosok hantu dalam pikiran, Omen berburu dalam bayangan. Dia memberikan utilitas Blind pada musuh, berteleportasi melintasi battlefield, lalu membiarkan paranoia menghantui saat musuh berusaha menerka di mana dia akan menyerang berikutnya.","ko-KR":"기억의 유령 오멘은 그림자 속에서 적들을 사냥합니다. 적들의 눈을 멀게 하고 전장 어느 곳이든 이동하며 피해망상을 일으키는 능력 때문에 상대는 다음 공격을 예측할 수 없어 혼란에 빠지게 됩니다.","fr-FR":"Spectre d''un souvenir, Omen chasse dans les ténèbres. Il aveugle les ennemis, se téléporte d''un bout à l''autre du champ de bataille et laisse la peur se répandre parmi ses adversaires qui se demandent qui sera sa prochaine victime.","en-US":"A phantom of a memory, Omen hunts in the shadows. He renders enemies blind, teleports across the field, then lets paranoia take hold as his foe scrambles to uncover where he might strike next.","pl-PL":"Omen, upiór wspomnień, poluje pośród cieni. Oślepia wrogów, teleportuje się po polu walki i pozwala, by nieświadomych miejsca kolejnego ataku nieprzyjaciół ogarnęła paranoja.","pt-BR":"Omen, uma lembrança fantasmagórica, caça nas sombras. Ele cega os inimigos, teleporta-se pelo campo e deixa a paranoia assumir o controle enquanto o adversário tenta descobrir de onde virá seu próximo ataque.","ru-RU":"Призрак из прошлого Omen наносит удары из тени. Он способен ослеплять врагов и незаметно перемещаться по полю боя, вселяя страх в сердца противников, тщетно пытающихся предугадать, откуда он нападет вновь.","th-TH":"Omen ออกล่าในเงามืด ดั่งปีศาจแห่งความทรงจำ เขาสามารถหายตัวข้ามสนาม ทำให้ศัตรูสูญเสียการมองเห็น แล้วปล่อยให้ความหวาดระแวงเข้าครอบงำศัตรู ก่อให้เกิดความกลัวว่าเมื่อไหร่ที่เขาจะลงมืออีกครั้ง","tr-TR":"Bir anının hayaleti olan Omen gölgelerin içinde avlanır. Düşmanlarını kör eder, savaş alanını boydan boya kat eder ve paranoyanın, onun ne taraftan saldıracağını anlamaya çalışan rakiplerinin damarlarında gezinmesini sağlar.","vi-VN":"Tựa như bóng ma của ký ức, Omen săn lùng trong bóng tối. Khả năng khống chế tầm nhìn và dịch chuyển tức thời của hắn khiến mọi đối thủ phải hoang mang tột độ vì có thể bị tấn công bất cứ lúc nào từ bất cứ nơi đâu.","zh-CN":"“幽影”是暗影中的狩猎者，关于他的过去只有一段模糊的记忆。他能传送到战场的任意位置，还能剥夺敌人的视野与理智，使其陷入草木皆兵的境地。","zh-TW":"歐門是個記憶中的魅影，在暗影裡巡獵。他能蒙蔽敵人雙眼、在地圖上神出鬼沒，使詭譎的氣氛籠罩全域，而他的敵人永遠在心慌意亂之中，試圖猜測他接下來會在哪裡現身。"}'::jsonb, 'Wraith', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/displayicon.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/displayicon.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/fullportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/fullportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/fullportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/killfeedportrait.png', 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/minimapportrait.png', null, 'https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/background.png', array['433178ff', '0f1923ff', '344673ff', '0f192300'], false, false, '4ee40330-ecdd-4f2f-98a8-eb1243428373'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('8e253930-4c05-31dd-1b6c-968525494517'::uuid, 'Ability1', '{"es-MX":"Paranoia","ar-AE":"بارانويا","es-ES":"Paranoia","ja-JP":"パラノイア","it-IT":"Paranoia","de-DE":"Paranoia","id-ID":"Paranoia","ko-KR":"피해망상","fr-FR":"Paranoïa","en-US":"Paranoia","pl-PL":"Paranoja","pt-BR":"Paranoia","ru-RU":"Паранойя","th-TH":"Paranoia","tr-TR":"PARANOYA","vi-VN":"Hoang Tưởng","zh-CN":"暗魇","zh-TW":"夢魘侵襲"}'::jsonb, '{"es-MX":"EQUIPA un orbe cegador. DISPARA para lanzarlo hacia adelante, lo que ofusca y ensordece a todos los jugadores a los que alcance durante un breve periodo. Este proyectil puede atravesar paredes.","ar-AE":"تجهّز ببلورة إعماء.  أطلق لرميها إلى الأمام، حيث تصيب كل من تلمسهم من اللاعبين بتأثير قصر النظر والصمم. يمكن لهذه القذيفة المرور عبر الجدران.","es-ES":"EQUIPA un orbe cegador.  DISPARA para lanzarlo hacia delante, lo que limita la visión y ensordece a todos los jugadores que toca durante un breve periodo. El proyectil puede atravesar paredes.","ja-JP":"ブラインドオーブを構える。「発射」でオーブを前方に発射する。このオーブは壁を貫通し、一時的に触れたすべてのプレイヤーの聴覚を奪い、視界を悪化させる。","it-IT":"EQUIPAGGIA una sfera d''ombra.  Usa il FUOCO per lanciarla in avanti, ANNEBBIANDO per un tempo limitato tutti i giocatori che incontra e ASSORDANDOLI. Questo proiettile può attraversare i muri.","de-DE":"RÜSTE eine Blendungskugel AUS. FEUERE, um sie nach vorn zu werfen. Alle Spieler, die sie berührt, haben kurzzeitig eingeschränkte Sicht und werden taub. Das Geschoss kann Mauern durchdringen.","id-ID":"EQUIP blinding orb. Tekan FIRE untuk melemparnya ke depan guna memberikan utilitas Nearsight dan Deafen pada semua pemain yang terkena. Proyektil ini bisa menembus dinding.","ko-KR":"실명 구슬을 장착합니다. 발사하면 앞으로 던져 구슬에 닿은 모든 플레이어의 시야와 청력을 약화시킵니다. 이 투사체는 벽을 통과할 수 있습니다.","fr-FR":"ÉQUIPEZ-vous d''un orbe aveuglant. TIREZ pour le lancer vers l''avant, ce qui rend myopes et assourdit brièvement tous les joueurs touchés. Ce projectile peut traverser les murs.","en-US":"EQUIP a blinding orb.  FIRE to throw it forward, briefly Nearsighting and Deafening all players it touches. This projectile can pass straight through walls.","pl-PL":"WYPOSAŻ oślepiającą kulę.  STRZEL, by wypuścić ją przed siebie, ograniczając chwilowo zasięg wizji i słyszenia wszystkich dotkniętych przez nią graczy. Pocisk ten może przenikać przez ściany.","pt-BR":"EQUIPE um orbe cegante. DISPARE para lançá-lo, causando Surdez e Visão Turva brevemente em todos os jogadores atingidos. O projétil atravessa paredes.","ru-RU":"Выбирает ослепляющую сферу. Нажмите кнопку ОГОНЬ, чтобы бросить ее вперед и ненадолго ограничить обзор и слух игроков, которых она коснется. Эта сфера может проходить сквозь стены.","th-TH":"ติดตั้ง Blinding Orb  กดยิงเพื่อขว้างออกไป จะจำกัดทัศนวิสัยและการได้ยินของผู้เล่นทุกคนที่สัมผัสกับมันเป็นเวลาสั้น ๆ ลูกกระสุนนี้สามารถทะลุผ่านกำแพง","tr-TR":"Kör edici bir küre KUŞAN. İleri fırlatmak için ATEŞ ET. Küre kısa süreliğine, dokunduğu düşmanların Görüşünü Kısıtlar ve onları Sağır eder. Bu yetenek doğrudan duvarlardan geçebilir.","vi-VN":"TRANG BỊ một ngọc hỏa mù.  BẮN để phóng ra phía trước, làm Giảm Tầm Nhìn và Khả Năng Nghe của người chơi bị trúng phải trong thời gian ngắn. Ngọc này có thể xuyên qua tường.","zh-CN":"装备致盲法球。按【射击】将其向前掷出，可使接触到的玩家短暂【致聋】和【视野收缩】。此投掷物可穿透墙体。","zh-TW":"裝備一個致盲彈。點擊「攻擊」，即可向前拋擲，暫時使被觸及的所有玩家「視野受限並喪失聽覺」。此彈體可貫穿牆壁。"}'::jsonb, '"https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('8e253930-4c05-31dd-1b6c-968525494517'::uuid, 'Ability2', '{"es-MX":"Manto Oscuro","ar-AE":"الغطاء المظلم","es-ES":"Velo tenebroso","ja-JP":"ダークカヴァー","it-IT":"Velo oscuro","de-DE":"Finsterer Schleier","id-ID":"Dark Cover","ko-KR":"어둠의 장막","fr-FR":"Voile sombre","en-US":"Dark Cover","pl-PL":"Mroczna Osłona","pt-BR":"Manto Sombrio","ru-RU":"Темный покров","th-TH":"Dark Cover","tr-TR":"KARANLIK ÖRTÜ","vi-VN":"Bóng Tối Bao Trùm","zh-CN":"黑瘴","zh-TW":"黑影籠罩"}'::jsonb, '{"es-MX":"EQUIPA un orbe de sombras y entra en un mundo desfasado para colocar y apuntar los orbes. PRESIONA el botón de la habilidad para lanzarlo hacia la ubicación marcada, creando una esfera de sombras duradera que bloquea visión. MANTÉN PRESIONADO EL DISPARO mientras apuntas para alejar el marcador aún más. MANTÉN PRESIONADO EL DISPARO SECUNDARIO mientras apuntas para acercar el marcador aún más. PRESIONA RECARGAR para cambiar a la vista normal.","ar-AE":"تجهّز بكرة ظلية لتدخل في نطاق منفصل عن الواقع لوضع وتوجيه الكرات. اضغط على زر القدرة لرمي البلورة الطيفية على البقعة المستهدفة، مما يكوّن قبة طيفية تحجب الرؤية وتدوم لفترة طويلة. تابع الضغط على زر الإطلاق أثناء التوجيه لتحريك المؤشر إلى مسافة أبعد. تابع الضغط على زر الإطلاق البديل أثناء التوجيه لتحريك المؤشر إلى مسافة أقرب. اضغط على زر إعادة التلقيم لتفعيل/تعطيل عرض الاستهداف العادي.","es-ES":"EQUIPA un orbe sombrío y te adentras en un mundo paralelo para colocarlo y marcar el objetivo de los orbes. PULSA la tecla de la habilidad para lanzar el orbe sombrío a la ubicación señalada, lo que genera una esfera sombría de larga duración que bloquea la visión. MANTÉN PULSADO el botón de disparar al apuntar para alejar el marcador. MANTÉN PULSADO el DISPARO ALTERNATIVO al apuntar para acercarlo. PULSA RECARGAR para cambiar al modo de apuntado normal.","ja-JP":"闇のオーブを構え、位相空間に入ってオーブを設置する。アビリティーキーを「押す」とマーカーの位置に闇のオーブを投げ、長時間視線を遮る球形の闇を作り出す。ターゲット中は「発射長押し」でマーカーが遠くに、「オルト射撃長押し」でマーカーが近くに移動する。また「リロード」キーで通常の照準視点に切り替わる。","it-IT":"EQUIPAGGIA una sfera oscura, entrando in uno stato che ti permette di piazzare le sfere in punti precisi. PREMI l''abilità per lanciare la sfera di oscurità nella posizione indicata, creando un globo d''ombra a lunga durata che blocca la visione. TIENI PREMUTO il FUOCO mentre miri per allontanare l''indicatore. TIENI PREMUTO il FUOCO ALTERNATIVO mentre miri per avvicinare l''indicatore. PREMI RICARICA per attivare o disattivare la visuale di mira normale.","de-DE":"RÜSTE eine Schattenkugel AUS, um eine Dimension zum Platzieren und Anvisieren der Kugel zu betreten. DRÜCKE die Fähigkeitstaste, um die Kugel zum Zielort zu schleudern, wo eine langanhaltende, sichtblockierende Sphäre entsteht. HALTE FEUERN GEDRÜCKT, um die Markierung von dir zu entfernen. HALTE ALT. FEUERN GEDRÜCKT, um die Markierung zu dir zu bewegen. DRÜCKE NACHLADEN für den normalen Zielmodus.","id-ID":"EQUIP shadow orb, masuki dunia transisi untuk menempatkan dan menarget orb. TEKAN tombol ability untuk melempar shadow orb ke lokasi yang ditandai, orb ini menciptakan area bayangan tahan lama yang menghalangi pandangan. HOLD FIRE untuk menjauhkan penanda, dan HOLD ALT FIRE untuk mendekatkan penanda. TEKAN RELOAD untuk beralih ke tampilan penargetan normal.","ko-KR":"그림자 구슬을 장착하고 다른 차원의 세계로 들어가 구슬을 조준합니다. 스킬 키를 누르면 표시한 위치에 그림자 구슬을 던져 한동안 시야를 차단하는 그림자 영역을 생성합니다. 발사를 길게 누르면 표시 위치를 더 멀리 옮깁니다. 보조 공격을 길게 누르면 표시 위치를 더 가까이 옮깁니다. 재장전을 누르면 기본 조준점을 끄고 켭니다.","fr-FR":"ÉQUIPEZ-vous d''un orbe d''ombre et entrez dans un monde déphasé afin d''y lancer des orbes. APPUYEZ sur la touche de la compétence pour lancer l''orbe à l''endroit marqué, ce qui crée une sphère d''ombre durable qui bloque la vision. MAINTENEZ LE TIR tout en visant pour éloigner le marqueur. MAINTENEZ LE TIR SECONDAIRE tout en visant pour rapprocher le marqueur. APPUYEZ sur RECHARGER pour repasser en visée normale.","en-US":"EQUIP a shadow orb, entering a phased world to place and target the orbs. PRESS the ability key to throw the shadow orb to the marked location, creating a long-lasting shadow sphere that blocks vision. HOLD FIRE while targeting to move the marker further away. HOLD ALT FIRE while targeting to move the marker closer. PRESS RELOAD to toggle normal targeting view.","pl-PL":"WYPOSAŻ mroczną kulę i wejdź w międzyświat, by wybrać położenie kuli i ją umieścić. NACIŚNIJ przycisk umiejętności, by wypuścić mroczną kulę w kierunku zaznaczonego miejsca, tworząc długotrwałą mroczną sferę ograniczającą wizję. PRZYTRZYMAJ STRZAŁ podczas namierzania, by oddalić znacznik. PRZYTRZYMAJ ALT. STRZAŁ podczas namierzania, by przybliżyć znacznik. NACIŚNIJ PRZEŁADOWANIE, by przełączyć zwykły widok namierzania.","pt-BR":"EQUIPE um orbe sombrio e entre em um universo distorcido para posicionar os orbes. PRESSIONE o botão de habilidade para lançar o orbe no local marcado, criando uma esfera de sombra duradoura que bloqueia a visão. SEGURE O DISPARO enquanto mira para afastar o marcador. SEGURE O DISPARO ALTERNATIVO enquanto mira para aproximar o marcador. PRESSIONE RECARREGAR para alternar para a visão de mira normal.","ru-RU":"Выбирает теневую сферу и переходит в иную реальность, чтобы установить сферы. Нажмите кнопку умения, чтобы бросить теневую сферу, которая расширяется в выбранной точке, ограничивая обзор. Чтобы увеличить дальность броска сферы, удерживайте кнопку ОГОНЬ. Чтобы уменьшить дальность броска, удерживайте кнопку АЛЬТ. ОГОНЬ. Нажмите кнопку ПЕРЕЗАРЯДКИ, чтобы переключиться на обычный режим прицеливания.","th-TH":"ติดตั้ง Shadow Orb เข้าสู่โลกวัฏภาคเพื่อวางและเล็งเป้า Orb กดสกิลเพื่อโยน Shadow Orb ไปยังตำแหน่งที่กำหนดไว้และสร้างเงาดำที่จะบดบังทัศนวิสัยอย่างยาวนาน กดยิงค้างไว้ในขณะที่เล็งเป้าหมายเพื่อย้ายเครื่องหมายให้ไกลออกไป กดโหมดยิงเสริมค้างไว้ในขณะที่เล็งเป้าหมายเพื่อย้ายเครื่องหมายให้ใกล้เข้ามา กดรีโหลดเพื่อสับเปลี่ยนเป็นมุมมองการเล็งแบบปกติ","tr-TR":"Bir gölge küresi KUŞAN, küreleri yerleştirmek ve hedef almak için soyut bir dünyaya adım at. Küreyi işaretlenen konuma fırlatarak görüş engelleyen uzun süreli bir gölge küresi oluşturmak için yetenek düğmesine BAS. Hedef alma esnasında işaretçiyi daha uzağa götürmek için ATEŞ DÜĞMESİNİ BASILI TUT. İşaretçiyi daha yakına getirmek için ALT. ATIŞ DÜĞMESİNİ BASILI TUT. Normal hedef almaya geçmek için DOLDURMA DÜĞMESİNE BAS.","vi-VN":"TRANG BỊ một ngọc bóng tối, du hành vào thế giới đa chiều để đặt và nhắm mục tiêu các viên ngọc. DÙNG phím kỹ năng để quăng ngọc bóng tối tới địa điểm đánh dấu, tạo một thể cầu bóng tối có thời gian tồn tại rất lâu để chắn tầm nhìn. GIỮ BẮN trong khi nhắm mục tiêu để di chuyển điểm đánh dấu ra xa. GIỮ BẮN PHỤ trong khi nhắm mục tiêu để di chuyển điểm đánh dấu lại gần. NẠP ĐẠN để bật/tắt nhắm mục tiêu thường.","zh-CN":"装备暗影法球，然后进入相位空间为法球选择目标。按【技能键】即可朝标记位置投掷暗影法球，创造一个长时间持续的暗影球体来遮挡视线。瞄准期间，【按住射击】可将标记移远，【按住辅助射击】可将标记移近。按【装填】即可切换至普通瞄准视野。","zh-TW":"裝備一顆暗影球，並進入戰慄境界來指定施放地點。按下「技能」，將暗影球丟至標記地點，製造出一個暗影穹頂，可阻擋視野且久不退散。瞄準時長按「攻擊」可將標記移動至遠處；長按「輔助技能」則能將標記移動至近處。按下「填彈」可切換為一般瞄準視角。"}'::jsonb, '"https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('8e253930-4c05-31dd-1b6c-968525494517'::uuid, 'Grenade', '{"es-MX":"Paso Encubierto","ar-AE":"السير عبر الظلال","es-ES":"Aparición tenebrosa","ja-JP":"シュラウドステップ","it-IT":"Passo velato","de-DE":"Vernebelte Schritte","id-ID":"Shrouded Step","ko-KR":"어둠의 발자국","fr-FR":"Voie des ombres","en-US":"Shrouded Step","pl-PL":"Krok w Mrok","pt-BR":"Passos Tenebrosos","ru-RU":"Скрытый шаг","th-TH":"Shrouded Step","tr-TR":"GİZLİ ADIM","vi-VN":"Biến Ảnh","zh-CN":"践影","zh-TW":"瞬步鬼影"}'::jsonb, '{"es-MX":"EQUIPA la habilidad Paso Encubierto y mira su indicador de alcance. DISPARA para comenzar una breve canalización y luego transpórtate hacia la ubicación marcada.","ar-AE":"تجهّز بقدرة السير عبر الظلال وراقب مؤشر مداها. أطلق لتبدأ عملية توجيه قصيرة ثم انتقل بسرعة إلى الموقع الموسوم.","es-ES":"EQUIPA una habilidad para caminar entre las sombras y ve su indicador de alcance. DISPARA para iniciar un breve periodo de canalización y después teleportarte a la ubicación señalada.","ja-JP":"シュラウドステップの体勢に入り、距離マーカーを表示する。「発射」で短い詠唱の後、マークの位置にテレポートする。","it-IT":"EQUIPAGGIA un''abilità che ti permette di muoverti furtivo tra le ombre e osserva il suo indicatore di gittata. Usa il FUOCO per entrare in una breve canalizzazione e teletrasportarti nella posizione indicata.","de-DE":"RÜSTE die Vernebelte-Schritte-Fähigkeit AUS und sieh dir ihre Reichweite an. FEUERE, um kurz zu kanalisieren und dich dann an die markierte Position zu teleportieren.","id-ID":"EQUIP ability Shrouded Step dan lihat indikator jangkauannya. Tekan FIRE untuk memulai channeling singkat, lalu teleportasi ke lokasi yang ditandai.","ko-KR":"어둠의 발자국 스킬을 장착하고 사거리를 표시합니다. 발사하면 짧은 정신 집중 후 표시한 위치로 순간이동합니다.","fr-FR":"ÉQUIPEZ-vous d''une compétence de marche dans les ombres accompagnée d''un indicateur de portée. TIREZ pour commencer une courte canalisation avant de vous téléporter vers l''endroit marqué.","en-US":"EQUIP a shrouded step ability and see its range indicator. FIRE to begin a brief channel, then teleport to the marked location.","pl-PL":"WYPOSAŻ umiejętność Krok w Mrok, by zobaczyć jej wskaźnik zasięgu. STRZEL, by rozpocząć krótkie ładowanie, po którym teleportujesz się do zaznaczonego miejsca.","pt-BR":"EQUIPE uma habilidade de Passos Tenebrosos para ver o indicador de alcance. DISPARE para começar uma breve canalização e, então, teleporte-se para o local marcado.","ru-RU":"Выбирает умение \"Скрытый шаг\" и показывает дальность его действия. Нажмите кнопку ОГОНЬ, чтобы после небольшой задержки телепортировать агента к выбранному месту. Противники услышат звук телепортации только от точки отправления.","th-TH":"ติดตั้งสกิล Shrouded Step และดูตัวบอกระยะ\nกดยิงเพื่อทำการร่ายสั้น ๆ จากนั้นเทเลพอร์ตไป\nยังตำแหน่งที่กำหนดไว้ ศัตรูสามารถได้ยิน\nเสียงจากตำแหน่งที่ออกเดินทางเท่านั้น","tr-TR":"Bir gizli adım yeteneği KUŞAN ve menzil göstergesini görüntüle. Kısa bir beklemenin ardından işaretli konuma ışınlanmak için ATEŞ ET.","vi-VN":"TRANG BỊ kỹ năng biến ảnh để hiển thị tầm phạm vi. BẮN để bắt đầu thời gian vận kỹ năng ngắn, sau đó dịch chuyển tức thời tới vị trí đã đánh dấu.","zh-CN":"装备【践影】技能，查看其范围指示器。按【射击】开始引导，然后传送至标记位置。","zh-TW":"裝備一項「瞬步鬼影」技能，可預視其傳送距離。點擊「攻擊」即開始詠唱，隨後可傳送至標記地點。"}'::jsonb, '"https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('8e253930-4c05-31dd-1b6c-968525494517'::uuid, 'Ultimate', '{"es-MX":"Desde las Sombras","ar-AE":"من طيات الظلام","es-ES":"Desde las sombras","ja-JP":"フロム・ザ・シャドウズ","it-IT":"Viandante spettrale","de-DE":"Aus den Schatten","id-ID":"From the Shadows","ko-KR":"그림자 습격","fr-FR":"Depuis les ombres","en-US":"From the Shadows","pl-PL":"Z Cieni","pt-BR":"Salto das Sombras","ru-RU":"Из тени","th-TH":"From the Shadows","tr-TR":"GÖLGELERİN İÇİNDEN","vi-VN":"Tan Vào Hư Vô","zh-CN":"离魂","zh-TW":"闇夜襲擊"}'::jsonb, '{"es-MX":"EQUIPA un mapa táctico. DISPARA para empezar a transportarte hacia la ubicación seleccionada. Mientras te transportas, Omen aparecerá como una sombra que podrá ser destruida por los enemigos para cancelar su transportación, o PRESIONA EQUIPAR para que Omen cancele su transportación.","ar-AE":"تجهّز بخريطة تكتيكية. أطلق لتبدأ الانتقال السريع إلى الموقع المنشود. أثناء الانتقال السريع، يظهر أومن كظل يمكن للأعداء تدميره مما يلغي عملية الانتقال السريع، أو اضغط التجهيز لكي يلغي أومن عملية الانتقال السريع.","es-ES":"EQUIPA un mapa táctico. DISPARA para empezar a teleportarte a la zona seleccionada. Mientras se teleporta, Omen aparecerá como una sombra que los enemigos pueden destruir para cancelar su teleportación. PULSA EQUIPAR para cancelar la teleportación.","ja-JP":"タクティカルマップを開き、「発射」で選択した地点にテレポートを開始する。テレポート中のオーメンは影の姿となり、この状態で敵に破壊されるとテレポートに失敗する。また発動中に再度押すとテレポートをキャンセルできる。","it-IT":"EQUIPAGGIA una mappa tattica. Usa il FUOCO per iniziare a teletrasportarti nel punto selezionato. Durante il teletrasporto, Omen apparirà nel punto di destinazione sotto forma di ombra, che potrà essere distrutta dagli avversari per impedirgli di completarlo. Puoi annullare l''operazione PREMENDO EQUIPAGGIA.","de-DE":"ÖFFNE eine taktische Karte. FEUERE, um deine Teleportation an den Zielort zu beginnen. Während der Teleportation erscheint Omen als Schatten, der von Gegnern zerstört werden kann, um die Teleportation abzubrechen. DRÜCKE AUSRÜSTEN, um die Teleportation abzubrechen.","id-ID":"EQUIP minimap. Tekan FIRE untuk teleportasi ke lokasi terpilih. Saat teleportasi, Omen muncul sebagai Shade yang bisa dihancurkan oleh musuh untuk membatalkan teleportasinya. Omen juga bisa membatalkan teleportasi lewat tombol TEKAN GUNAKAN.","ko-KR":"전술 지도를 장착합니다. 발사하면 선택한 위치로 순간이동을 시작합니다. 순간이동 중에는 오멘이 그림자로 나타나며 이때 적이 그림자를 파괴하면 순간이동이 취소됩니다. 장착을 누르면 오멘이 순간이동을 취소합니다.","fr-FR":"ÉQUIPEZ-vous d''une carte tactique. TIREZ pour commencer à vous téléporter vers l''endroit sélectionné. Pendant la téléportation, vous apparaissez sous forme d''ombre. Les ennemis peuvent détruire cette ombre pour annuler votre téléportation. APPUYEZ sur ÉQUIPER pour annuler votre téléportation.","en-US":"EQUIP a tactical map. FIRE to begin teleporting to the selected location. While teleporting, Omen will appear as a Shade that can be destroyed by an enemy to cancel his teleport, or PRESS EQUIP for Omen to cancel his teleport.","pl-PL":"WYPOSAŻ mapę taktyczną. STRZEL, by rozpocząć teleportację do wybranego miejsca. W trakcie teleportacji Omen będzie widoczny jako cień, który wrogowie mogą zniszczyć, by zapobiec jego teleportacji. NACIŚNIJ PRZYCISK WYPOSAŻENIA, by anulować teleportację.","pt-BR":"EQUIPE um mapa tático. DISPARE para começar a se teleportar ao local selecionado. Enquanto se teleporta, Omen aparecerá como um Vulto que pode ser destruído por qualquer inimigo para cancelar o teleporte, ou PRESSIONE EQUIPAR para cancelá-lo.","ru-RU":"Выбирает тактическую карту. Нажмите кнопку ОГОНЬ, чтобы начать телепортацию к выбранному месту. Во время телепортации Omen предстает в образе тени, которая может быть уничтожена врагом для отмены телепортации. Omen также может отменить телепортацию нажатием кнопки умения.","th-TH":"ติดตั้งแผนที่ยุทธวิธี กดยิงเพื่อเริ่มทำการ\nเทเลพอร์ตไปยังตำแหน่งที่กำหนดไว้ ระหว่าง\nการเทเลพอร์ต Omen จะปรากฏตัวเป็นร่างเงา\nซึ่งศัตรูสามารถทำลายได้เพื่อหยุดยั้งการ\nเทเลพอร์ต หรือ Omen สามารถกดปุ่มติดตั้ง\nอีกครั้งเพื่อยกเลิกการเทเลพอร์ต","tr-TR":"Bir taktik harita KUŞAN. Seçili konuma ışınlanmaya başlamak için ATEŞ ET. Omen, ışınlanma esnasında Gölge suretine bürünür ve düşmanları onu yok ederek ışınlanmayı iptal edebilir ya da Omen KUŞANMAYA BASARAK ışınlanmasını kendisi iptal edebilir.","vi-VN":"TRANG BỊ 1 bản đồ chiến thuật. BẮN để dịch chuyển tức thời tới vị trí chỉ định. Trong khi dịch chuyển tức thời, Omen sẽ biến thành một cái Bóng và có thể bị đối thủ tiêu diệt để loại bỏ quá trình dịch chuyển tức thời. TRANG BỊ chiêu cuối để Omen hủy dịch chuyển tức thời.","zh-CN":"装备战术地图。按【射击】传送至选定位置，传送期间幽影会变为一团阴影，敌人可通过摧毁阴影来强制取消传送，幽影也能按【装备】来取消传送。","zh-TW":"裝備一個戰術地圖。點擊「攻擊」，即可傳送至指定地點。詠唱技能時，歐門會以「暗影型態」在指定地點浮現，附近敵軍可將其摧毀來中止傳送。再按「裝備」則可讓歐門自行取消傳送。"}'::jsonb, '"https://media.valorant-api.com/agents/8e253930-4c05-31dd-1b6c-968525494517/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agents (uuid, display_name, description, developer_name, release_date, display_icon, display_icon_small, bust_portrait, full_portrait, full_portrait_v2, killfeed_portrait, minimap_portrait, home_screen_promo_title_image, background, background_gradient_colors, is_full_portrait_right_facing, is_base_content, role) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, '{"es-MX":"Jett","ar-AE":"جيت","es-ES":"Jett","ja-JP":"ジェット","it-IT":"Jett","de-DE":"Jett","id-ID":"Jett","ko-KR":"제트","fr-FR":"Jett","en-US":"Jett","pl-PL":"Jett","pt-BR":"Jett","ru-RU":"Jett","th-TH":"Jett","tr-TR":"JETT","vi-VN":"Jett","zh-CN":"捷风","zh-TW":"婕提"}'::jsonb, '{"es-MX":"Jett viene directamente de Corea del Sur. Su ágil y evasivo estilo de pelea le permite enfrentarse a riesgos que otros no pueden. Es imparable en todos los enfrentamientos y acaba con sus enemigos antes de que sepan qué los atacó.","ar-AE":"مع تمثيلها لبلدها الأصلي كوريا الجنوبية، تتمتع جيت بأسلوب قتالي رشيق شديد المراوغة يتيح لها القيام بمخاطرات لا يجرؤ أحد غيرها عليها. وهي تحقق السيطرة الكاملة في كل مناوشة وتسحق الأعداء حتى قبل أن يدركوا ما أصابهم.","es-ES":"Jett viene de Corea del Sur y su estilo de lucha ágil y evasivo le permite asumir grandes riesgos. En las refriegas, recorre el terreno en círculos y hace trizas a los enemigos con una rapidez espectacular.","ja-JP":"韓国出身のジェットは、俊敏で捉え難い戦闘スタイルを持ち、他の誰にも真似できないような危険な行動を取ることができる。交戦地帯の周囲を走り回り、敵が何が起こったのか理解するよりも早く切り刻んでしまうのだ。","it-IT":"Pronta a rappresentare la sua patria, la Corea del Sud, Jett ha uno stile di combattimento agile e sfuggente che le permette di affrontare rischi che nessun altro potrebbe correre. Aggira ogni scontro ed elimina i nemici prima ancora che possano rendersene conto.","de-DE":"Jett repräsentiert ihre Heimat Südkorea. Sie kämpft agil und weicht geschickt aus, weshalb sie Risiken eingehen kann wie niemand sonst. Sie umrundet Gefechte mit Leichtigkeit und schlitzt Gegner auf, bevor diese wissen, wie ihnen geschieht.","id-ID":"Mewakili negara asalnya, Korea Selatan, gaya bertarung Jett yang gesit dan banyak menghindar memungkinkannya mengambil risiko yang tidak bisa dilakukan orang lain. Dia berpindah secepat kilat saat bertarung, menebas musuh sebelum mereka menyadari apa yang terjadi.","ko-KR":"한국 출신으로 신속하고 은밀하게 움직이는 제트는 다른 사람이라면 엄두도 못 낼 위험한 일도 마다하지 않습니다. 교전이 벌어질 때면 어김없이 상대보다 뛰어난 능력을 통해 기습적으로 공격합니다.","fr-FR":"Représentante de sa patrie, la Corée du Sud, Jett dispose d''un style de combat basé sur l''agilité et l''esquive, ce qui lui permet de prendre des risques qu''elle seule peut se permettre de prendre. Elle tourne autour des affrontements et découpe ses ennemis avant même qu''ils ne s''en rendent compte.","en-US":"Representing her home country of South Korea, Jett''s agile and evasive fighting style lets her take risks no one else can. She runs circles around every skirmish, cutting enemies up before they even know what hit them.","pl-PL":"Zwinność i uniki Jett, reprezentującej Koreę Południową, pozwalają jej podejmować ryzyko, na jakie inni się nie decydują. Porusza się z niesamowitą szybkością, a jej wrogowie nie wiedzą, co ich trafiło.","pt-BR":"Representando a Coreia do Sul, sua terra natal, Jett tem um estilo de luta ágil e evasivo que permite que ela assuma riscos como ninguém. Ela corre em meio a qualquer confronto, cortando os inimigos antes mesmo que eles percebam quem ou o que os atingiu.","ru-RU":"Представляющая Южную Корею Jett быстра и неуловима и может позволить себе рисковать чаще других. В любой стычке она заходит с флангов и быстро уничтожает растерявшегося противника.","th-TH":"Jett คือตัวแทนจากเกาหลีใต้ บ้านเกิดของเธอ ด้วยรูปแบบการต่อสู้ที่คล่องตัวและสง่างาม ทำให้เธอเผชิญหน้ากับความเสี่ยงอย่างที่ไม่มีใครทำได้ เธอวิ่งไปรอบๆจุดปะทะ เชือดเฉือนศัตรูก่อนที่พวกเขาจะรู้ว่าถูกสิ่งใดโจมตี","tr-TR":"Anavatanı Güney Kore''yi temsil eden Jett''in çevik ve darbelerden kaçmaya dayalı dövüş tarzı, başkalarının alamadığı riskleri almasını sağlar. Her çatışmada üstünlüğünü belli eder ve rakipleri daha nerede olduğunu anlamadan onları kesip biçmeye başlar.","vi-VN":"Đến từ Hàn Quốc, với phong cách chiến đấu nhanh nhẹn và huyền ảo, Jett có thể thực hiện những pha tấn công liều lĩnh đến bất ngờ. Thoắt ẩn thoắt hiện trong các cuộc giao tranh, cô ra đòn chặn đứng đối thủ trước khi chúng kịp hiểu chuyện gì xảy ra.","zh-CN":"“捷风”是新罗人的后代，她灵活机动的战斗风格使她能够采取比常人更激进和冒险的策略。她可以在战场上肆意纵横，将敌人逐个击破，或是把他们打个措手不及。","zh-TW":"身為南韓代表，婕提身手矯捷，能使出他人所不能的精妙險招。交戰時她能把所有人耍得團團轉，以迅雷不及掩耳的速度秒殺敵人。"}'::jsonb, 'Wushu', '1970-01-01T00:00:00Z'::timestamp with time zone, 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/displayicon.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/displayicon.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/fullportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/fullportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/fullportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/killfeedportrait.png', 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/minimapportrait.png', null, 'https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/background.png', array['25607aff', '0f1923ff', '0f1923ff', '25607aff'], false, true, 'dbe8757e-9e92-4ed4-b39f-9dfc589691d4'::uuid) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, 'Ability1', '{"es-MX":"Ráfaga Ascendente","ar-AE":"التيار الصاعد","es-ES":"Vendaval","ja-JP":"アップドラフト","it-IT":"Corrente ascensionale","de-DE":"Aufwind","id-ID":"Updraft","ko-KR":"상승 기류","fr-FR":"Courant ascendant","en-US":"Updraft","pl-PL":"Prąd Wstępujący","pt-BR":"Corrente Ascendente","ru-RU":"Подъем","th-TH":"Updraft","tr-TR":"HAFİFLE","vi-VN":"Tùy Phong","zh-CN":"凌空","zh-TW":"乘風飛躍"}'::jsonb, '{"es-MX":"Propulsa a Jett AL INSTANTE hacia el aire.","ar-AE":"اندفاع فوري لجيت في الهواء.","es-ES":"Propulsa INSTANTÁNEAMENTE a Jett a mucha altura hacia arriba.","ja-JP":"ジェットを上に向かって飛ばす。","it-IT":"Lancia ALL''ISTANTE Jett in aria.","de-DE":"Katapultiere Jett SOFORT hoch in die Luft.","id-ID":"SEKETIKA melempar Jett tinggi ke udara.","ko-KR":"제트가 즉시 높이 날아오릅니다.","fr-FR":"Vous vous propulsez INSTANTANÉMENT dans les airs.","en-US":"INSTANTLY propel Jett high into the air.","pl-PL":"NATYCHMIAST wzleć Jett wysoko w górę.","pt-BR":"INSTANTANEAMENTE lança Jett bem alto no ar.","ru-RU":"Jett мгновенно взлетает в воздух.","th-TH":"พัดพา Jett ให้ลอยขึ้นไปบนอากาศทันที","tr-TR":"Jett''i ANINDA havaya doğru fırlat.","vi-VN":"Jett bật nhảy NGAY LẬP TỨC lên không trung.","zh-CN":"立即腾空直上，高高跃起。","zh-TW":"立刻讓婕提朝高空中風湧躍起。"}'::jsonb, '"https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/abilities/ability1/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, 'Ability2', '{"es-MX":"Impulso Ciclón","ar-AE":"الرياح الدافعة","es-ES":"Viento de cola","ja-JP":"テイルウィンド","it-IT":"Folata","de-DE":"Rückenwind","id-ID":"Tailwind","ko-KR":"순풍","fr-FR":"Vent arrière","en-US":"Tailwind","pl-PL":"Pomyślny Wiatr","pt-BR":"Brisa de Impulso","ru-RU":"Попутный ветер","th-TH":"Tailwind","tr-TR":"RÜZGÂR GİBİ","vi-VN":"Thuận Phong","zh-CN":"逐风","zh-TW":"順風式"}'::jsonb, '{"es-MX":"ACTIVA para preparar una ráfaga de viento durante un tiempo limitado. VUELVE A USAR el viento para propulsar a Jett en la dirección a la que se dirige. Si no se está moviendo, se impulsará hacia adelante. Las cargas de Impulso Ciclón se reinician cada dos asesinatos.","ar-AE":"قم بالتفعيل لتحضير عصفة رياح لفترة محدودة. أعد استخدام الرياح لدفع جيت في الاتجاه الذي تتحرك فيه. إن كانت جيت تقف ساكنة فسوف تندفع إلى الأمام. تتم إعادة ضبط شحنة الرياح الدافعة بعد كل عمليتي قتل.","es-ES":"ACTIVA para preparar una ráfaga de viento durante un tiempo limitado. VUELVE A USAR el viento para propulsar a Jett en la dirección en la que se esté moviendo. Si Jett está quieta, se propulsa hacia delante. La carga de Viento de cola se reinicia cada dos asesinatos.","ja-JP":"風を身にまとう。「再使用」することで、ジェットを現在の進行方向に向かって加速させる。立ち止まっている場合は前方に押し出す。「テイルウィンド」のチャージは2 キルごとにリセットされる。","it-IT":"ATTIVA per preparare una folata di vento che resta disponibile per un periodo limitato. USA DI NUOVO l''abilità per proiettare Jett nella direzione in cui si sta muovendo. Se Jett è ferma, verrà spinta in avanti. La carica di Folata si ripristina ogni due uccisioni.","de-DE":"AKTIVIEREN, um kurzzeitig eine Windböe vorzubereiten. ERNEUT VERWENDEN, um Jett in die Richtung sprinten zu lassen, in die sie sich bewegt. Falls Jett stillsteht, sprintet sie nach vorn. Die Ladung von „Rückenwind“ setzt sich alle zwei Kills zurück.","id-ID":"AKTIFKAN untuk menyiapkan embusan angin selama beberapa saat. GUNAKAN LAGI angin untuk melempar Jett ke arah dia bergerak. Jika Jett berdiri diam, dia akan terlempar ke depan. Charge Tailwind direset tiap dua kill.","ko-KR":"활성화 시 일정 시간 동안 돌풍을 준비합니다. 돌풍을 다시 사용하면 제트가 이동 방향으로 빠르게 이동합니다. 제트가 가만히 서 있을 경우에는 앞으로 빠르게 이동합니다. 순풍 충전량은 2킬마다 초기화됩니다.","fr-FR":"ACTIVEZ pour préparer une rafale de vent pendant une durée limitée. RÉUTILISEZ la compétence pour vous propulser dans la direction vers laquelle vous vous dirigez. Si vous êtes immobile, vous vous propulsez vers l''avant. Vous regagnez une charge de Vent arrière toutes les deux éliminations.","en-US":"ACTIVATE to prepare a gust of wind for a limited time. RE-USE the wind to propel Jett in the direction she is moving. If Jett is standing still, she propels forward. Tailwind charge resets every two kills.","pl-PL":"AKTYWUJ, aby przygotować podmuch wiatru na pewien czas. UŻYJ PONOWNIE wiatru, aby rozpędzić Jett w kierunku, w którym się porusza. Jeśli stoi nieruchomo, Jett popędzi przed siebie. Reset naładowania Pomyślnego Wiatru następuje co dwa zabójstwa.","pt-BR":"ATIVE para preparar uma rajada de vento por tempo limitado. REPITA a habilidade para lançar Jett na direção do movimento atual dela. Se estiver parada, Jett será lançada para a frente. A carga de Brisa de Impulso é redefinida a cada dois abates.","ru-RU":"Вызывает кратковременный порыв ветра. Используйте умение повторно, чтобы Jett совершила быстрый рывок в направлении движения. Если Jett стоит на месте, то она делает рывок вперед. Каждые два убийства восстанавливают заряд \"Попутного ветра\".","th-TH":"เปิดใช้งานเพื่อเตรียมเรียกพลังแห่งสายลมในช่วงเวลาหนึ่ง กดใช้อีกครั้งเพื่อให้ Jett ใช้สายลมพุ่งตัวไปในทิศทางการเคลื่อนที่ของเธอ หาก Jett ยืนอยู่กับที่ เธอจะพุ่งตัวไปข้างหน้า ชาร์จของ Tailwind จะรีเซ็ตทุก ๆ สองคิล","tr-TR":"Kısa süreliğine sert bir rüzgâr estirmeye hazırlanmak için ETKİNLEŞTİR. Jett''i hareket ettiği yönde fırlatmak için TEKRAR KULLAN. Jett hareketsiz durursa ileriye doğru atılır. Rüzgâr Gibi''nin yükü her iki skorda bir dolar.","vi-VN":"KÍCH HOẠT để hình thành 1 cơn gió mạnh có thể sử dụng trong một khoảng thời gian giới hạn. TÁI SỬ DỤNG cơn gió để phóng Jett về hướng đang di chuyển. Nếu Jett đang đứng yên, cô ấy sẽ phóng về phía trước. Lượt sử dụng Thuận Phong sẽ được làm mới sau mỗi 2 hạ gục.","zh-CN":"【激活】即可在限定时间内刮起阵风。【再次使用】该技能可朝移动方向突进。若站立不动，则向面朝的方向突进。每击败两名敌人，可重置【逐风】的充能。","zh-TW":"按下「啟動」可暫時準備一陣強風，「重施技能」可讓婕提朝移動的方向快速衝刺，若婕提立定不動，則會向前衝刺。每擊殺兩位敵人可重置順風式充能數。"}'::jsonb, '"https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/abilities/ability2/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, 'Grenade', '{"es-MX":"Nube Explosiva","ar-AE":"الانفجار السحابي","es-ES":"Borrasca","ja-JP":"クラウドバースト","it-IT":"Nuvola di fumo","de-DE":"Wolkenbruch","id-ID":"Cloudburst","ko-KR":"연막 폭발","fr-FR":"Averse","en-US":"Cloudburst","pl-PL":"Zasłona Chmur","pt-BR":"Erupção das Brumas","ru-RU":"Вихрь","th-TH":"Cloudburst","tr-TR":"DUMAN BULUTU","vi-VN":"Vân Nộ","zh-CN":"瞬云","zh-TW":"穿雲衝刺"}'::jsonb, '{"es-MX":"Lanza un proyectil AL INSTANTE que se convierte en una nube que bloquea la visión al impactar con alguna superficie. MANTÉN PRESIONADO el botón de la habilidad para cambiar la trayectoria del humo hacia donde apuntes.","ar-AE":"قم بالإلقاء الفوري لمقذوف يتمدد متحولًا إلى سحابة حاجبة للرؤية عند الارتطام بأي سطح. استمر في الضغط على مفتاح القدرة لكي تزحزح الدخان في اتجاه مؤشر تصويبك.","es-ES":"Lanza un proyectil INSTANTÁNEAMENTE que se expande en una nube la cual bloquea la visión de forma breve al impactar contra una superficie. MANTÉN PULSADO el botón de la habilidad para que el humo se curve en la dirección de la mira.","ja-JP":"煙玉を投げる。この玉は着弾すると煙を発生させ、しばらくの間視線を遮る。長押しでこの煙玉をクロスヘアの方向にカーブさせる。","it-IT":"Spara ALL''ISTANTE un proiettile che si espande brevemente in una nuvola che blocca la visione all''impatto con una superficie. TIENI PREMUTA l''abilità per curvare il fumo in direzione del tuo reticolo.","de-DE":"Schleudere SOFORT ein Projektil, das sich beim Aufprall auf einer Oberfläche zu einer Wolke ausdehnt, die kurz die Sicht versperrt. HALTE die Fähigkeiten-Taste gedrückt, um den Rauch in Richtung deines Fadenkreuzes zu biegen.","id-ID":"SEKETIKA melempar proyektil yang membesar menjadi awan. Awan tersebut sekilas menghalangi pandangan saat membentur permukaan. Tekan TAHAN pada tombol ability untuk membelokkan asap ke arah crosshair.","ko-KR":"표면에 닿아 충격을 받으면 구름으로 팽창해 잠시 시야를 가리는 투사체를 즉시 던집니다. 스킬 키를 길게 누르면 연기가 조준점 방향으로 휘어집니다.","fr-FR":"Lancez INSTANTANÉMENT un projectile. Lorsqu''il touche une surface, il libère un nuage qui bloque la vision pendant un court instant. MAINTENEZ la touche de la compétence pour courber la fumée dans la direction de votre réticule.","en-US":"INSTANTLY throw a projectile that expands into a brief vision-blocking cloud on impact with a surface. HOLD the ability key to curve the smoke in the direction of your crosshair.","pl-PL":"NATYCHMIAST wypuść pocisk, który rozszerza się do rozmiarów sporej chmury blokującej wizję w momencie trafienia. PRZYTRZYMAJ przycisk umiejętności, by zakręcić dym w stronę, w którą celujesz.","pt-BR":"INSTANTANEAMENTE lança um projétil que se expande numa breve nuvem que obscurece a visão ao bater numa superfície. SEGURE o botão da habilidade para curvar a fumaça na direção da sua mira.","ru-RU":"Мгновенно бросает снаряд, превращающийся в ненадолго закрывающее обзор облако при столкновении с поверхностью. Удерживайте кнопку умения, чтобы менять направление движения дыма с помощью прицела.","th-TH":"โยนลูกบอลควันออกไปทันที ซึ่งจะขยายตัว\nออกเป็นหมอกควันเพื่อบดบังวิสัยทัศน์เมื่อ\nกระทบกับพื้นผิว กดปุ่มสกิลค้างไว้เพื่อโยน\nควันโค้งไปตามทิศทางเป้าเล็งของคุณ","tr-TR":"ANINDA yaptığın atış, yüzeye çarptığında patlayarak kısa süreliğine görüş engelleyen bir sis bulutuna dönüşür. Duman bulutuna nişangâhın yönünde falso vermek için yetenek düğmesini BASILI TUT.","vi-VN":"NGAY LẬP TỨC phóng ra 1 cầu tinh vân khi va chạm vào bề mặt bất kỳ sẽ bung ra và biến thành đám khói chắn tầm nhìn. GIỮ phím kỹ năng để di chuyển đám khói về hướng ngắm hồng tâm.","zh-CN":"投掷一个发射物，其在触碰后可扩展成一朵能短暂阻挡视线的云雾。按住技能键能扭曲云雾至准星的方向。","zh-TW":"立刻丟出一枚彈體，觸物時會擴散成一朵雲霧，可暫時阻擋視野。長按「技能」能讓雲霧轉彎，使其移動至十字準星所指的方向。"}'::jsonb, '"https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/abilities/grenade/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, 'Ultimate', '{"es-MX":"Tormenta de Cuchillas","ar-AE":"عاصفة النصال","es-ES":"Tormenta de cuchillas","ja-JP":"ブレードストーム","it-IT":"Tempesta di lame","de-DE":"Klingensturm","id-ID":"Blade Storm","ko-KR":"칼날 폭풍","fr-FR":"Tempête de lames","en-US":"Blade Storm","pl-PL":"Burza Ostrzy","pt-BR":"Tormenta de Aço","ru-RU":"Буря клинков","th-TH":"Blade Storm","tr-TR":"KESKİN FIRTINA","vi-VN":"Bạo Vũ Cuồng Phong","zh-CN":"飓刃","zh-TW":"暴風旋刃"}'::jsonb, '{"es-MX":"EQUIPA un conjunto de cuchillas arrojadizas de gran precisión. DISPARA para lanzar una sola cuchilla y recárgalas al asesinar a un oponente. Usa el DISPARO SECUNDARIO para lanzar todas las cuchillas restantes; estas no se recargarán al asesinar a un oponente.","ar-AE":"تجهز بمجموعة من سكاكين الرمي المتميزة بدقة تصويب عالية. أطلق لرمي سكين واحدة مع إعادة شحن السكاكين عند تحقيق عملية قتل. استخدم الإطلاق البديل لرمي كل الخناجر المتبقية دون إعادة الشحن عند تحقيق عملية قتل.","es-ES":"EQUIPA un conjunto de cuchillos volantes de alta precisión. DISPARA para lanzar un único cuchillo y recarga los cuchillos con un asesinato. Utiliza el DISPARO ALTERNATIVO para lanzar todos los cuchillos restantes, pero no se recargan con un asesinato.","ja-JP":"精度の高い投げナイフを構え、「発射」で 1 本ずつ投げる。ナイフは敵をキルすると補充される。「オルト射撃」で現在残っているすべてのナイフを投げるが、敵をキルしてもナイフは補充されない。","it-IT":"EQUIPAGGIA un set di precisissimi pugnali da lancio. Usa il FUOCO per lanciare un singolo pugnale. Se Jett ottiene un''uccisione con il pugnale, la sua riserva di pugnali si ripristina. Usa il FUOCO ALTERNATIVO per lanciare tutti i pugnali rimasti, che però non si ripristinano con un''uccisione.","de-DE":"RÜSTE einige hochpräzise Wurfmesser AUS. FEUERE, um ein einziges Messer auf dein Ziel zu werfen. Bei einem Kill erhältst du alle Messer zurück. ALT. FEUERMODUS, um alle verbleibenden Klingen auf dein Ziel zu werfen. Bei einem Kill erhältst du keine Messer zurück.","id-ID":"EQUIP satu set pisau lempar dengan akurasi tinggi. Tekan FIRE untuk melempar satu pisau, dan recharge pisau saat melakukan kill. Tekan ALT FIRE untuk melempar sisa belati, tetapi tidak recharge saat melakukan kill.","ko-KR":"명중률이 높은 투척용 단검을 장착합니다. 발사하면 단검 하나를 던지며, 처치 시 단검을 충전합니다. 보조 공격 시 남은 단검을 전부 던집니다. 이 경우 처치 시 단검이 충전되지 않습니다.","fr-FR":"ÉQUIPEZ-vous d''un ensemble de couteaux de lancer extrêmement précis. TIREZ pour lancer un seul couteau (se recharge en cas d''élimination). Utilisez le TIR SECONDAIRE pour lancer tous les couteaux restants (ne se recharge pas).","en-US":"EQUIP a set of highly accurate throwing knives. FIRE to throw a single knife and recharge knives on a kill. ALT FIRE to throw all remaining daggers but does not recharge on a kill.","pl-PL":"WYPOSAŻ zestaw niezwykle precyzyjnych sztyletów do rzucania. STRZEL, by rzucić jednym sztyletem. Po zabiciu przeciwnika odnowisz wszystkie sztylety. ALT. STRZAŁ pozwala rzucić wszystkimi pozostałymi sztyletami w cel, ale nie odnawia sztyletów po zabiciu przeciwnika.","pt-BR":"EQUIPE um conjunto de facas de arremesso altamente precisas. DISPARE para lançar uma única faca contra o alvo. As facas são recarregadas ao matar um oponente. Use o DISPARO ALTERNATIVO para jogar todas as facas restantes contra o alvo, porém elas não são recarregadas ao matar um oponente.","ru-RU":"Вооружается набором кинжалов, которые всегда летят точно в цель. Нажмите кнопку ОГОНЬ, чтобы бросить один кинжал. При убийстве все кинжалы возвращаются. Нажав кнопку АЛЬТ. ОГОНЬ, вы бросите все кинжалы сразу, но они не вернутся при убийстве.","th-TH":"ติดตั้งชุดมีดสั้นสุดแม่นยำ กดยิงเพื่อขว้างมีดสั้นหนึ่งเล่มไปยังเป้าหมายและรีชาร์จมีดเมื่อฆ่าศัตรูได้ กดโหมดยิงเสริมเพื่อขว้างมีดสั้นที่เหลือทั้งหมด แต่จะไม่รีชาร์จเมื่อฆ่าศัตรูได้","tr-TR":"Oldukça isabetli fırlatma bıçakları KUŞAN. Hedefine tek bir bıçak fırlatmak için ATEŞ ET. Düşmanı öldürdüğünde yükü dolacak. Kalan tüm hançerleri hedefine fırlatmak için ALT. ATIŞ kullan. Bu saldırı düşmanı öldürdüğünde yük doldurmaz.","vi-VN":"TRANG BỊ 1 bộ dao găm ném xa có độ chuẩn xác cao. BẮN để ném 1 dao găm và hồi đầy lượt dùng mỗi khi hạ gục đối thủ. BẮN PHỤ để ném toàn bộ dao găm còn lại tới mục tiêu nhưng sẽ không hồi đầy lượt dùng nếu hạ gục đối thủ.","zh-CN":"装备一组飞刀，按【射击】向目标掷出一把飞刀，击败敌人即可重新充能所有飞刀。按【辅助射击】向你的目标抛掷所有剩余的飞刀，但这样做无法通过击败敌人获得充能。","zh-TW":"裝備一組高準度的飛刀。點擊「攻擊」即可射出一把飛刀，擊殺敵軍即可重填。點擊「輔助攻擊」，則可射出剩下的所有飛刀，但擊殺後不會重填。"}'::jsonb, '"https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/abilities/ultimate/displayicon.png"'::jsonb) on conflict do nothing;
insert into public.valo_agent_abilities (agent, slot, display_name, description, display_icon) values ('add6443a-41bd-e414-f6ad-e58d267f4e95'::uuid, 'Passive', '{"es-MX":"Viraje","ar-AE":"تحليق","es-ES":"Planeo","ja-JP":"ドリフト","it-IT":"Cadere con stile","de-DE":"Gleiten","id-ID":"Drift","ko-KR":"표류","fr-FR":"Vol","en-US":"Drift","pl-PL":"Noszenie","pt-BR":"Deriva","ru-RU":"Смещение","th-TH":"Drift","tr-TR":"SÜZÜL","vi-VN":"Lướt","zh-CN":"飘移","zh-TW":"飄風身法"}'::jsonb, '{"es-MX":"Puedes planear en el aire si mantienes presionado el botón de salto mientras caes.","ar-AE":"الاستمرار في الضغط على زر القفز أثناء السقوط يمكنك من التحليق في الهواء.","es-ES":"Mantener pulsado el botón de salto mientras caes te permite planear por los aires.","ja-JP":"落下中にジャンプボタン長押しで滑空することができる。","it-IT":"Tieni premuto il salto mentre cadi per planare.","de-DE":"Halte die Sprungtaste gedrückt, damit du beim Fallen durch die Luft gleitest.","id-ID":"Menahan tombol lompat saat Jett jatuh akan mengurangi kecepatan luncurnya.","ko-KR":"낙하 시 점프 버튼을 길게 누르면 활공합니다.","fr-FR":"Maintenir la touche de saut tout en tombant vous permet de planer.","en-US":"Holding the jump button while falling allows you to glide through the air.","pl-PL":"Przytrzymanie przycisku skoku podczas spadania pozwala ci szybować w powietrzu.","pt-BR":"Segurar o botão de pulo durante uma queda permite que você plane no ar.","ru-RU":"Зажав кнопку прыжка во время падения, можно медленно планировать вниз.","th-TH":"กดปุ่มกระโดดค้างไว้ขณะที่ตกลงมาจะช่วยให้คุณเหาะในอากาศได้","tr-TR":"Düşerken zıplama düğmesini basılı tutmak, havada süzülmeni sağlar.","vi-VN":"Giữ nút nhảy trong khi đang rơi sẽ giúp cho Jett lướt trên không.","zh-CN":"下落时按住【跳跃】可让你在空中滑翔。","zh-TW":"落地時按住跳躍按鈕，就可以在空中滑翔。"}'::jsonb, '"https://media.valorant-api.com/agents/add6443a-41bd-e414-f6ad-e58d267f4e95/abilities/passive/displayicon.png"'::jsonb) on conflict do nothing;
